// Shared draw helpers + reusable channel groups for the built-in marks.
import type { ChannelKind, DrawFn, MarkAnchor } from "../../ir/mark.js";
import { num, numOpt, str, styleOf, type Point } from "../../ir/pen.js";

// Reusable channel groups (paint = the modeled visual channels; arbitrary CSS is style).
// `title` rides along with paint: a per-mark hover tooltip (SVG <title> child), data-drivable
// like any channel — the profiling views hang query attribution off it.
export const fillPaint: Record<string, ChannelKind> = { fill: "color", stroke: "color", strokeWidth: "pixel", strokeDasharray: "text", opacity: "number", fillOpacity: "number", strokeOpacity: "number", title: "text" };
export const strokePaint: Record<string, ChannelKind> = { stroke: "color", strokeWidth: "pixel", strokeDasharray: "text", opacity: "number", strokeOpacity: "number", title: "text" };
// A rectangle accepts either offset (x,y,w,h) or interval (x,x2,y,y2); extentOf (C6) resolves which.
export const rectChannels: Record<string, ChannelKind> = { x: "positional-x", y: "positional-y", x2: "positional-x", y2: "positional-y", w: "pixel", h: "pixel", anchor: "shape", ...fillPaint };

// The box anchor: resolve the row's `anchor` binding against the mark's descriptor default, then
// return the top-left corner. `center` shifts (x, y) back by half the box (a pen-side pixel op —
// type-legal, the same shape as text's dx/dy nudge); `topleft` is the identity band layouts rely on.
export function anchorOffset(r: Parameters<DrawFn>[0], dflt: MarkAnchor, w: number, h: number): Point {
  const anchor = (str(r, "anchor") ?? dflt) as MarkAnchor;
  const x = num(r, "x"), y = num(r, "y");
  return anchor === "center" ? [x - w / 2, y - h / 2] : [x, y];
}

// A box mark's `anchor` is a GEOMETRY instruction (center vs corner), not the SVG `text-anchor`
// paint that `styleOf` reads it as for text marks. Drop it so a `<rect>`/`<image>` never carries a
// bogus `text-anchor="center"`.
export function boxStyle(r: Parameters<DrawFn>[0]) {
  const s = styleOf(r);
  s.textAnchor = undefined;
  return s;
}

// Shared draws. drawBox accepts BOTH box forms (triage §4): offset (x, y, w, h — anchor applies)
// and interval (x/x2, y/y2 — both edges absolute, anchor ignored on that axis). PRESENCE
// discriminates per axis and per row: a bound w of 0 stays a zero-width box; a row carrying both
// w AND x2 keeps the offset reading (w wins, matching extentOf's precedence). Aggregate marks
// expect a precomputed SVG path `d` and just emit it.
export const drawBox =
  (dflt: MarkAnchor): DrawFn =>
  (r, pen) => {
    const ix = numOpt(r, "w") === undefined && numOpt(r, "x2") !== undefined; // interval on x
    const iy = numOpt(r, "h") === undefined && numOpt(r, "y2") !== undefined; // interval on y
    const w = ix ? Math.abs(num(r, "x2") - num(r, "x")) : num(r, "w");
    const h = iy ? Math.abs(num(r, "y2") - num(r, "y")) : num(r, "h");
    const [ax, ay] = anchorOffset(r, dflt, w, h); // anchor applies to the OFFSET axes only
    const x = ix ? Math.min(num(r, "x"), num(r, "x2")) : ax;
    const y = iy ? Math.min(num(r, "y"), num(r, "y2")) : ay;
    pen.rect(x, y, w, h, boxStyle(r));
  };
// Stroke-only draws default their stroke to black (triage §4), mirroring drawPath's fill: "none"
// below: SVG inherits stroke: none, so an unbound stroke was an INVISIBLE mark with no error —
// the silent-invisible bug class. A bound stroke always wins.
export const strokedStyle = (r: Parameters<DrawFn>[0]) => {
  const s = styleOf(r);
  return { ...s, stroke: s.stroke ?? "#000" };
};
// An SVG <path> with no `fill` attribute paints solid black — the wrong default for a stroked
// polyline (line/path marks bind stroke, never fill). Default fill to "none" so an unfilled path
// is a stroke, not a filled blob; marks that want a fill (area) still provide one and override it.
export const drawPath: DrawFn = (r, pen) => {
  const s = strokedStyle(r);
  pen.path(str(r, "d") ?? "", { ...s, fill: s.fill ?? "none" });
};
export const drawSegment =
  (ax: string, ay: string, bx: string, by: string): DrawFn =>
  (r, pen) =>
    pen.line(num(r, ax), num(r, ay), num(r, bx, num(r, ax)), num(r, by, num(r, ay)), strokedStyle(r));

// arrow = a segment + a head at the tip. `headType` is categorical (triangle | barb | none),
// `headSize` is the head length in px. The head matches the stroke color.
export const drawArrow: DrawFn = (r, pen) => {
  const x1 = num(r, "x1");
  const y1 = num(r, "y1");
  const x2 = num(r, "x2");
  const y2 = num(r, "y2");
  const style = strokedStyle(r);
  pen.line(x1, y1, x2, y2, style);

  const type = str(r, "headType") ?? "triangle";
  if (type === "none") return;
  const size = num(r, "headSize", 8);
  const dir = Math.atan2(y2 - y1, x2 - x1);
  const corner = (spread: number): Point => [x2 + size * Math.cos(dir + Math.PI + spread), y2 + size * Math.sin(dir + Math.PI + spread)];

  if (type === "barb") {
    const a = corner(-Math.PI / 7);
    const b = corner(Math.PI / 7);
    pen.line(x2, y2, a[0], a[1], style);
    pen.line(x2, y2, b[0], b[1], style);
  } else {
    const color = style.stroke ?? "black"; // filled triangle (default)
    pen.polygon([[x2, y2], corner(-Math.PI / 8), corner(Math.PI / 8)], { fill: color, stroke: color });
  }
};

// hull: a per-row POLYGON mark. Its `path` channel carries the vertices a geometry resolver minted
// — either a JS array of already-placed [x,y] points (the js reduce) OR a WKT string like
// `POLYGON ((x y, …))` (the SQL push-down via ST_AsText). Drawn as a closed polygon (fill defaults
// to none like drawPath, so an unfilled hull is a stroked outline). A null/degenerate path (no
// matches, fewer than 3 vertices, or a non-polygon WKT — a ≤2-point hull is a POINT/LINESTRING) draws nothing.
const WKT_PAIR = /(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)/g;
const asPolygon = (v: unknown): Point[] | null => {
  if (typeof v === "string") {
    // a single-ring WKT (convex/bbox emit no holes): pull every "x y" coordinate pair in order.
    if (!v.startsWith("POLYGON")) return null; // POINT/LINESTRING (a degenerate ≤2-point hull) → nothing
    const pts: Point[] = [];
    for (const m of v.matchAll(WKT_PAIR)) pts.push([Number(m[1]), Number(m[2])]);
    // WKT closes the ring by REPEATING the first vertex; drop it so the vertex set matches the JS
    // reduce (the pen closes the polygon regardless) — SQL and JS hulls are then byte-identical.
    if (pts.length > 1 && pts[0][0] === pts[pts.length - 1][0] && pts[0][1] === pts[pts.length - 1][1]) pts.pop();
    return pts;
  }
  if (!Array.isArray(v)) return null;
  const pts: Point[] = [];
  for (const p of v) {
    if (!Array.isArray(p) || p.length < 2) return null;
    const x = Number(p[0]);
    const y = Number(p[1]);
    if (Number.isNaN(x) || Number.isNaN(y)) return null;
    pts.push([x, y]);
  }
  return pts;
};
export const drawHull: DrawFn = (r, pen) => {
  const pts = asPolygon(r.path);
  if (pts === null || pts.length < 3) return;
  const s = strokedStyle(r);
  pen.polygon(pts, { ...s, fill: s.fill ?? "none" });
};
