// The space arithmetic & coercion judgments (reorg §4.2, §6).
//
// This is today's binaryType() (ir/expr.ts — dimensional analysis on channel
// Exprs) lifted from Dimension to Space. The rule that keeps spatial semantics
// sound: mixed-space arithmetic is ILL-TYPED except through a registered coercion.
// "Only the affine flips relative→pixel" stops being a convention enforced by
// five files agreeing and becomes the definition of the affine — the unique
// registered coercion on that edge of the space lattice, exactly as
// materialize/inject are the unique coercions on the substrate axis.
//
// Ill-typed results are represented as `null` (no exceptions) so callers compose.
import type { Geom, Space } from "./attr.js";
import { area, dataSpace, isSpatial, len, pixelSpace, relativeSpace } from "./attr.js";

export type ArithOp = "+" | "-" | "*" | "/";

// ─────────────────────────────────────────────────────────────────────────────
// Geom-level arithmetic (within ONE spatial space). The affine dimensional
// analysis, on shapes: coord − coord = len; coord ± len = coord; len ± len = len
// (stack's cumsum); len × len = area. Axis is checked; cross-axis is ill-typed.
// "xy" (isotropic) matches any axis — the result takes the non-xy partner's axis.
function compatibleAxis(a: Geom, b: Geom): boolean {
  if (a.kind === "area" || b.kind === "area") return false;
  if (a.axis === "xy" || b.axis === "xy") return true;
  return a.axis === b.axis;
}
/** Resolve the result axis when two geoms combine: the non-xy partner's axis, or xy if both. */
function resolveAxis(a: Geom, b: Geom): "x" | "y" | "xy" {
  if (a.kind === "area" || b.kind === "area") return "x"; // shouldn't be called for area
  if (a.axis === "xy" && b.axis === "xy") return "xy";
  if (a.axis === "xy") return b.axis as "x" | "y" | "xy";
  return a.axis as "x" | "y" | "xy";
}

export function geomArith(op: ArithOp, a: Geom, b: Geom): Geom | null {
  if (op === "+" || op === "-") {
    if (a.kind === "coord" && b.kind === "coord") {
      if (!compatibleAxis(a, b)) return null; // cannot combine coords of different axes
      return op === "-" ? len(resolveAxis(a, b)) : null; // point − point = vector; point + point undefined
    }
    if (a.kind === "coord" && b.kind === "len") return compatibleAxis(a, b) ? { kind: "coord", axis: resolveAxis(a, b) as "x" | "y" } : null; // coord ± len = coord (inherits coord's concrete axis)
    if (a.kind === "len" && b.kind === "coord") {
      if (!compatibleAxis(a, b)) return null;
      return op === "+" ? { kind: "coord", axis: resolveAxis(a, b) as "x" | "y" } : null; // len + coord = coord; len − coord not a coordinate
    }
    if (a.kind === "len" && b.kind === "len") return compatibleAxis(a, b) ? len(resolveAxis(a, b)) : null; // stack cumsum
    return null; // anything with area under ±
  }
  if (op === "*") {
    if (a.kind === "len" && b.kind === "len") return area; // len × len = area
    return null; // coord/area products are ill-typed at the geom level
  }
  // "/" between two geoms → a dimensionless ratio; it drops out of spatial space.
  // Represented here as null (the result is data-space; the caller handles it).
  return null;
}

// ─────────────────────────────────────────────────────────────────────────────
// THE space judgment. The only cross-space rule is a registered coercion (applied
// by the planner, NOT here); so at the arithmetic level, mixed relative × pixel,
// data × domain, and anything × terminal are all ill-typed.
export function spaceArith(op: ArithOp, a: Space, b: Space): Space | null {
  // data ⊗ data → data (ordinary SQL/JS arithmetic)
  if (a.space === "data" && b.space === "data") return dataSpace;

  // same spatial space: delegate to geom; a null geom means the result left the
  // spatial world (e.g. len/len → ratio) — report data-space in that one case.
  if (a.space === "relative" && b.space === "relative") {
    const g = geomArith(op, a.geom, b.geom);
    if (g !== null) return relativeSpace(g);
    // "/" escapes the spatial world ONLY for len÷len (compatible axes) and area÷area —
    // a ratio of affine POSITIONS is not translation-invariant and stays ill-typed (B4).
    if (op === "/" && ((a.geom.kind === "len" && b.geom.kind === "len" && compatibleAxis(a.geom, b.geom)) || (a.geom.kind === "area" && b.geom.kind === "area"))) return dataSpace;
    return null;
  }
  if (a.space === "pixel" && b.space === "pixel") {
    const g = geomArith(op, a.geom, b.geom);
    if (g !== null) return pixelSpace(g);
    if (op === "/" && ((a.geom.kind === "len" && b.geom.kind === "len" && compatibleAxis(a.geom, b.geom)) || (a.geom.kind === "area" && b.geom.kind === "area"))) return dataSpace;
    return null;
  }

  // scaling a spatial value by a bare data factor (dimensionless) keeps the space:
  // relative len × 2 stays relative len. Multiplication/division only.
  if ((op === "*" || op === "/") && isSpatial(a) && b.space === "data") return a;
  if (op === "*" && a.space === "data" && isSpatial(b)) return b;

  // relative ⊗ pixel      — ILL-TYPED (only the affine coercion may cross)
  // data ⊗ domain         — ILL-TYPED as arithmetic (domains attach by fit-join)
  // anything ⊗ style|scene — ILL-TYPED (terminal spaces)
  return null;
}

// ─────────────────────────────────────────────────────────────────────────────
// THE affine coercion — the unique registered move on the relative→pixel edge.
// geom-preserving: the whole reason geom is shared between the two spatial spaces.
export function affineCoerce(a: Space): Space | null {
  return a.space === "relative" ? pixelSpace(a.geom) : null;
}

/** Does this edge demand the affine? A relative value feeding a pixel-typed slot. */
export function demandsAffine(have: Space, want: Space): boolean {
  return have.space === "relative" && want.space === "pixel";
}

// ─────────────────────────────────────────────────────────────────────────────
// The substrate axis — the SECOND coercion lattice, named the same way so the
// engine's two "crossing" mechanisms read as one idea. Substrate is orthogonal
// to space: any attr, in any space, is physically realized in sql or js.
export type Substrate = "sql" | "js";

/** materialize (sql→js) / inject (js→sql): identity on space, flips substrate.
 *  Idempotent when already in the target format. */
export function crossSubstrate(from: Substrate, to: Substrate): "materialize" | "inject" | "noop" {
  if (from === to) return "noop";
  return to === "js" ? "materialize" : "inject";
}
