// FK & cross-mark reference expressions + the via-family constructors
// (WUIR_IMPL §1.4; WUNOUNS §Foreign-key references). The reference *types* are the
// shared IR (the data layer's FK resolver consumes them); the Expr union (expr.ts)
// imports the *Expr forms. Expr-producing ctors (col/agg/boundRef/…) live in expr.ts
// to avoid an import cycle; predicate/path ctors live here.
import type { ExprType } from "./types.js";
import type { PlotId } from "../types/ids.js";
import type { Space } from "../types/attr.js";

export type JoinOp = "eq" | "lt" | "le" | "gt" | "ge" | "neq";
export type AggOp = "sum" | "avg" | "min" | "max" | "count";

/** A relation occurrence in a path (table | view | mark), with optional alias. */
export interface RelationBinding {
  relation: string;
  alias?: string;
}

/**
 * An attribute expression: a column of a specific relation occurrence. Operands of
 * a join predicate are AttrExprs — never a path-resolved BoundRefExpr (that would
 * nest a viaSpec inside a viaSpec).
 */
export type AttrExpr =
  | { kind: "local-column"; columnName: string }
  | TableRefExpr
  | { kind: "attr"; relation: RelationBinding; column: string };

export interface JoinCondition {
  op: JoinOp;
  left: AttrExpr;
  right: AttrExpr;
  /** A CROSS product (`on("*")`): every source row matches every target row. Resolves to a hop
   *  with zero key pairs → SQL `ON TRUE`; the operands are placeholders never emitted. Inherently
   *  multi-match, so it is only meaningful with a `{ resolve }` (e.g. one hull over ALL points). */
  cross?: true;
}

/** A named FK hop: advance from the current relation to `relation` through the unique FK
 *  between them (the resolver expands it to eq conditions against the catalog). */
export interface FKRef {
  kind: "fk";
  relation: string;
  alias?: string;
}

/** One step of a join path: an explicit predicate atom, a named FK hop, or a bare STRING — the
 *  same-column shorthand (`"id"` ≡ `on("id")` ≡ `eq("id", "id")`; `"*"` keeps on()'s declared
 *  cross join). String steps are AUTHORING sugar: resolveSpec normalizes every Path site in
 *  place (normalizePath), so downstream of resolve-once a string step never appears —
 *  assertResolvedPaths enforces it. */
export type PathStep = JoinCondition | FKRef | string;

/** THE join-path concept (CELL_KEY_VIA §3a): "relate this relation to that one, on these
 *  columns, possibly through intermediates" — every consumer (via, nest key, layout aux)
 *  accepts this ONE type; what varies is consumer policy (the nest key's eq gatekeeper),
 *  never the type. `null` ⇒ infer the unique FK, source ⇢ target. */
export type Path = PathStep[] | null;

/** A resolved path: ONE entry per hop; operands attr-qualified {relation, column}. */
export type ResolvedPath = JoinCondition[][];

/** Is this path step a named FK hop (vs an explicit predicate or string shorthand)?
 *  String-safe: JS's `in` throws on a string operand. */
export const isFKRef = (s: PathStep): s is FKRef => typeof s === "object" && s !== null && "kind" in s && (s as FKRef).kind === "fk";

/** Cross-TABLE column ref — a via whose referent is a raw TABLE (§8 Stage 2): same Path, same
 *  resolution vocabulary; the borrowed columns arrive in DATA space (pre-affine — free to feed a
 *  scale or place through the frame), where a plot referent's arrive placed (pixel). viaSpec
 *  null ⇒ infer the unique FK. `resolvedVia`/`resolve` mirror TableRefExpr. */
export interface BoundRefExpr {
  kind: "bound-ref";
  type: ExprType;
  tableName: string;
  columnName: string;
  viaSpec: Path;
  resolvedVia?: ResolvedPath;
  resolve?: ViaResolve;
}

/** A multi-match via's declared reduction (CELL_KEY_VIA §3b/§3c). A via whose path can match
 *  several referent rows must declare how the match set reduces to one value per mark —
 *  undeclared multiplicity is a build-time error, never a silent fan-out.
 *
 *  THE INPUT SCHEMA of a resolution is the same two-sided row every apply expression sees:
 *  `m` — the anchoring mark's row (constant within the group), and `f` — one matched row of
 *  the via relation (the referent's mark row). Three forms:
 *   - `fn` alone: an AggFn NAME from the ONE dual-substrate reduce vocabulary, over the picked
 *     referent column (validated at emission against the closed set);
 *   - `fn` + `arg`: the aggregate's argument is an EXPRESSION over (m, f) — a ScalarExpr built
 *     from the algebra's mcol/fcol vocabulary, auto-compiled to SQL (and mirrored in JS) by the
 *     shared lowering. Held as `unknown` here so the IR does not import the algebra layer; the
 *     emission types it at the boundary;
 *   - `js`: an OPAQUE reduce — `(matches, mark, cols?) => value`. `matches` is the mark's match
 *     set: FULL f-side rows (all referent attributes, intermediate-hop columns flattened in) —
 *     the developer references attributes directly. `mark` is the m-side row. `cols` echoes the
 *     resolution's declared `cols` (default: the borrowed column) so a COLUMN-GENERIC registered
 *     reducer (mode/range/extentUnion) knows what to reduce over; inline closures ignore it.
 *     Forces the reduce off the SQL substrate (the join materializes) — anything expressible as
 *     an aggregate over an (m,f) ScalarExpr should use `fn`+`arg`, which never leaves SQL.
 *     An INLINE function is the easy path but is NOT serializable (a closure cannot round-trip
 *     to JSON); a STRING names a reducer registered in `registries.reducers` — the serializable
 *     spelling. resolveSpec stamps `jsResolved` (resolve-once): downstream reads the function,
 *     the IR keeps the name. */
/** The opaque reduce: the match set (full f-side rows) + the m-side row → the value. `cols` is
 *  the declared column projection hint — inline closures may ignore it. */
export type ViaReduceFn = (matches: readonly Record<string, unknown>[], mark: Record<string, unknown>, cols?: readonly string[]) => unknown;

/** A REGISTERED resolver's descriptor (registries.reducers). A bare `js` reduce is the minimum;
 *  a resolver MAY also declare authoring defaults and a SQL implementation:
 *   - `defaultOutput` lets the bare-string form mint an output name (`resolve: "convex"` ≡
 *     `resolve: { <defaultOutput>: { js: "convex" } }`) — without it the single computed form is
 *     rejected (there is no name to pick by).
 *   - `defaultCols` is the input projection used when the resolution omits `cols` (convex reads
 *     the placed `x`/`y`).
 *   - `sql(xCol, yCol)` returns a per-group aggregate SQL EXPRESSION (WKT text) — the SQL-pushed
 *     implementation, chosen over `js` when its `requires` extension loads. `requires` names the
 *     DuckDB extension(s) the SQL impl needs; the backend INSTALL/LOADs them or throws. */
export interface ResolverSpec {
  js: ViaReduceFn;
  defaultOutput?: string;
  defaultCols?: readonly string[];
  sql?: (xCol: string, yCol: string) => string;
  requires?: readonly string[];
}

export interface ViaResolution {
  fn?: string;
  arg?: unknown; // ScalarExpr over (m, f) — typed at the algebra boundary
  order?: string;
  desc?: boolean;
  /** Inline fn (easy, NON-serializable escape hatch) or a registered reducer NAME (serializable). */
  js?: ViaReduceFn | string;
  /** Resolve-once product (never authored): the registry fn a string `js` names. */
  jsResolved?: ViaReduceFn;
  /** Resolve-once product (never authored): the SQL geometry impl a string `js` names, if the
   *  resolver declares one (a per-group WKT aggregate over the placed x/y). Preferred over the JS
   *  reduce for the bare-string form — SQL push-down; the JS form (`{ js: "name" }`) opts out. */
  sqlResolved?: (xCol: string, yCol: string) => string;
  /** Resolve-once product: DuckDB extension(s) the chosen SQL impl needs (loaded-or-throw). */
  requires?: readonly string[];
  /** Column projection hint passed to the reducer third — which attribute(s) to reduce over.
   *  Defaults to the borrowed column. Matches always carry ALL attributes regardless. */
  cols?: readonly string[];
  /** The computed output's declared Space (§8 Stage 4) — a pixel-valued reduction (a distance
   *  over placed positions) should say so. Defaults to data. Only the object form can carry
   *  one — the bare-function shorthand cannot, which is the reason the object form survives. */
  space?: Space;
}
/** One reduction for all borrowed columns, or a per-output map. A map value may be a BARE
 *  FUNCTION — shorthand for `{ js: fn }`: `{ resolve: { far: (matches, mark) => … } }`. */
export type ViaResolve = string | ViaResolution | Record<string, string | ViaResolution | ViaReduceFn>;

/** Cross-MARK column ref into another plot's solved channels (post-solve).
 *  `resolvedVia` is stamped by resolveSpec (attr-qualified, one entry per hop). */
export interface TableRefExpr {
  kind: "table-ref";
  type: ExprType;
  plotId: PlotId;
  attrName: string;
  viaSpec: Path;
  resolvedVia?: ResolvedPath;
  resolve?: ViaResolve;
}

// --- predicate / path constructors (Expr ctors live in expr.ts) ---

/** Desugar a string operand: "rel.col" → attr of `rel`; "col" → a local column. */
const attr = (a: string | AttrExpr): AttrExpr => {
  if (typeof a !== "string") return a;
  const dot = a.indexOf(".");
  return dot < 0
    ? { kind: "local-column", columnName: a }
    : { kind: "attr", relation: { relation: a.slice(0, dot) }, column: a.slice(dot + 1) };
};

const cond = (op: JoinOp) => (left: string | AttrExpr, right: string | AttrExpr): JoinCondition => ({ op, left: attr(left), right: attr(right) });

export const eq = cond("eq");
export const lt = cond("lt");
export const le = cond("le");
export const gt = cond("gt");
export const ge = cond("ge");
export const neq = cond("neq");

/** Named FK-hop constructor: `fk('islands')` — one PathStep through the unique FK to `relation`. */
export const fk = (relation: string): FKRef => ({ kind: "fk", relation });

/** Same-column eq shorthand: `on('island')` ≡ `eq('island', 'island')`. The wildcard `on('*')` is
 *  the CROSS product — every source row matches every target row (SQL `ON TRUE`); pair it with a
 *  `{ resolve }` to reduce the whole referent to one value per row (e.g. one hull over ALL points). */
export const on = (col: string): JoinCondition => (col === "*" ? { op: "eq", left: attr("*"), right: attr("*"), cross: true } : eq(col, col));
/** THE string-step eliminator: the same-column shorthand desugars through on() — the single
 *  semantic definition — so `"*"` keeps its cross meaning. The ONLY place strings leave a path. */
export const normalizeStep = (s: PathStep): JoinCondition | FKRef => (typeof s === "string" ? on(s) : s);

/** Normalize a whole path. Identity fast-path: a string-free path returns the SAME array object
 *  (idempotence + object-identity for consumers that compare paths). */
export function normalizePath(p: Path): Path {
  if (p === null || !p.some((s) => typeof s === "string")) return p;
  return p.map(normalizeStep);
}

/** An FK path through a sequence of relation (table) names — `path('friends','penguins','islands')`
 *  is `[fk('friends'), fk('penguins'), fk('islands')]`; the resolver treats a leading hop that names
 *  the SOURCE relation as the anchor (checked, then consumed). Interleave explicit predicates by
 *  building the array yourself: `[fk('penguins'), eq('island','island')]`. */
export function path(...relations: string[]): PathStep[] {
  return relations.map(fk);
}
