// Mark-table construction (WUPLAN C2): a Plot's IR → a mark-row SqlFragment carrying
// the identity columns (`dvl_plot`/`dvl_mark`; `dvl_cell` for nested marks — a follow-up)
// + the SOURCE columns its channels/layouts read. The spatial outputs (x/y/…) are
// filled downstream by the layouts (C4); the base table carries identity + data columns.
import type { RelationRef, SqlFragment } from "../../data/fragment.js";
import type { Column } from "../../data/schema.js";
import { leaves } from "../../ir/expr.js";
import { inputBinding } from "../../ir/layout.js";
import { isProducerSource, isRelationSource, isUnitSource, type Plot, type TableRef } from "../../ir/plot.js";
import type { Spec } from "../../ir/spec.js";
import { sanitizeOp } from "../../algebra/relation.js";
export function markTable(plot: Plot, spec: Spec, requiredColumns?: readonly string[]): SqlFragment {
  const selfRel = "src";

  const select: string[] = [`'${plot.id}' AS dvl_plot`, `(row_number() OVER () - 1) AS dvl_mark`];
  const columns: Column[] = [
    { name: "dvl_plot", type: "varchar" },
    { name: "dvl_mark", type: "int" },
  ];

  const local = referencedColumns(plot, spec);
  for (const [alias, ref] of local) {
    select.push(ref === alias ? `@${selfRel}."${ref}"` : `@${selfRel}."${ref}" AS "${alias}"`);
    columns.push({ name: alias, type: "unknown" });
  }
  // §2.4: columns no channel/layout of THIS plot reads, but a foreign op JOINS on — the
  // required-columns pass collected them from the emitted join edges (the ONE authority for
  // cross-relation survival). referencedColumns above owns only this plot's own data reads.
  for (const c of requiredColumns ?? []) {
    if (local.has(c)) continue;
    select.push(`@${selfRel}."${c}"`);
    columns.push({ name: c, type: "unknown" });
  }

  return {
    id: `${plot.id}:marks`,
    op: sanitizeOp(`${plot.id}:marks`), // valid SQL identifier for fold's CTE uniquification
    ctes: [{ name: "marks", body: `SELECT ${select.join(", ")} FROM @${selfRel}` }],
    result: "marks",
    inputs: { [selfRel]: sourceRef(plot.source) },
    outputs: { columns },
    cells: [],
  };
}

/** The SOURCE columns (or computed exprs) THIS plot's own channels/layouts read — its genuine
 * single responsibility. Cross-relation join keys (via / nest / σ / frame / hosted-children) are
 * NOT collected here: they ride on the `requiredColumns` the pass computes from the emitted ops. */
function referencedColumns(plot: Plot, spec: Spec): Map<string, string> {
  const out = new Map<string, string>();
  for (const expr of Object.values(plot.channels)) {
    if (expr.kind === "layout-output") {
      const layout = spec.layouts.get(expr.layout);
      if (layout) {
        // Post-affine layouts read from the placed marks (not the source table) — skip.
        const desc = layout.resolved?.operator; // resolve-once (undefined pre-resolve keeps this permissive, as the old optional registries did)
        if (desc?.requiresPixelInputs) continue;
        // A dvl_* member column is a MINTED base projection (`x(a+b)` → dvl_se_*), computed by the
        // plot's base-proj op — never sourced from the table (its input columns are collected below).
        for (const cols of Object.values(inputBinding(layout, plot.id))) for (const col of cols) if (!col.startsWith("dvl_")) out.set(col, col);
      }
    } else {
      // minted dvl_* columns (dvl_lift_* from the §3.3 lift) are PRODUCED by pipeline ops,
      // never present on the source table — same reserved-prefix rule as required-columns.
      for (const leaf of leaves(expr).data) if (leaf.kind === "local-column" && !leaf.columnName.startsWith("dvl_")) out.set(leaf.columnName, leaf.columnName);
    }
  }
  // Base projections (`x(col("a") + col("b"))`) are computed on the base; the SOURCE must supply the
  // columns their arithmetic reads (a, b), even though those never appear as a bare channel.
  for (const e of Object.values(plot.baseProjections ?? {})) {
    for (const leaf of leaves(e).data) if (leaf.kind === "local-column" && !leaf.columnName.startsWith("dvl_")) out.set(leaf.columnName, leaf.columnName);
  }
  return out;
}

function sourceRef(src: TableRef): RelationRef {
  if (typeof src === "string") return { base: src };
  if (isRelationSource(src) || isProducerSource(src)) throw new Error("marktable: a produced source (relation cell / producer) has no marktable — the compiler uses the cell directly");
  if (isUnitSource(src)) throw new Error("marktable: a UNIT source is rewritten to a values producer in mark() — it never reaches marktable");
  return src.asRelationRef();
}
