// Gather-scatter: union domain contributions, scatter to all members. The union ALGEBRA rides
// the payload (resolve-once — the compiler embedded the group's declared unionFn); this op just
// materially applies it. No registry, no domain-kind switch.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { jsRel, type JsRel } from "../../../algebra/relation.js";
import { applyTreatment } from "../../../operator/treatment.js";
import type { GatherScatterPayload } from "../../../plan/payloads.js";
export function gatherScatter(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload as unknown as Partial<GatherScatterPayload> & { kind: string };
  if (p.kind !== "gather-scatter") return;
  if (p.union === undefined) throw new Error("gather-scatter: payload carries no union operator — emit through planDomainGroups/emitGatherScatter");
  const members = op.reads.map((r) => store.read(r) as JsRel);
  const u = p.union.js(members);
  // §5a: the group's active treatment applies ONCE, post-union — explicit REPLACES the unioned
  // envelope (an override, not another member); zero extends the low edge.
  const union = applyTreatment(u, p.treatment);
  for (const w of op.writes) store.write(w, union, "assigned");
}
