// ordinal: one tick per category (reads the domain's category list).
import type { Scalar } from "../../data/schema.js";
import type { TickAlgo } from "../../operator/ticks.js";

export const ordinal: TickAlgo = {
  name: "ordinal",
  over: "domain",
  js({ params }) {
    const cats = (params.categories as readonly Scalar[] | undefined) ?? [];
    return cats.map((c, i) => ({ idx: i, value: c, label: String(c) }));
  },
};
