// The shared lowering: a TrainOp/ApplyOp (op.ts) -> a SqlFragment OR JS rows.
// Fragment ids here are LOCAL names ("fit", "apply") — the dispatch boundary owns global
// uniqueness by prefixing the invocation scope (exec.ts scopeFragments). This is the ONE place
// a substrate-agnostic operator description becomes physical — written once, reused by every
// operator. SQL augment reuses relation.ts's augmentBroadcast/augmentKeyed.
import type { SqlFragment } from "../data/fragment.js";
import type { Column, Row, Scalar, Schema, SqlType } from "../data/schema.js";
import { sqlLiteral } from "../data/dialect.js";
import type { OpBinding } from "./impl.js";
import { cellsOf, type Agg, type ApplyOp, type ScalarExpr, type TrainOp } from "./relop.js";
import { augmentBroadcast, augmentKeyed, mkFrag, type JsRel } from "./relation.js";
import { FUNCTIONS } from "./functions.js";

const sortKey = (a: Scalar, z: Scalar): number => (String(a ?? "") < String(z ?? "") ? -1 : String(a ?? "") > String(z ?? "") ? 1 : 0);

// ── ScalarExpr → SQL text (over mark alias `m`, fit alias `f`) ──
// Exported for the via-agg staging step (§3c): a resolution's `arg` is a ScalarExpr over the
// SAME two-sided (m, f) row, staged per matched row inside the via join before the reduce.
export function exprSql(e: ScalarExpr): string {
  switch (e.k) {
    case "lit":
      return sqlLiteral(e.v);
    case "col":
      return `${e.src === "fit" ? "f" : "m"}."${e.name}"`;
    case "bin":
      return `(${exprSql(e.l)} ${e.op} ${exprSql(e.r)})`;
    case "nullif0":
      return `NULLIF(${exprSql(e.x)}, 0)`;
    case "rank":
      return `(dense_rank() OVER (ORDER BY m."${e.col}") - 1)`;
    case "index":
      return `([${e.list.map((v) => sqlLiteral(v)).join(", ")}])[(${exprSql(e.idx)} % ${e.list.length}) + 1]`;
    case "rand":
      return `random()`;
    case "unary":
      // floor CASTs to a whole number so it can index an array (a quantized ramp); the rest are plain.
      return e.fn === "floor" ? `CAST(floor(${exprSql(e.x)}) AS BIGINT)` : `${e.fn}(${exprSql(e.x)})`;
    case "left":
      return `LEFT(CAST(${exprSql(e.str)} AS VARCHAR), CAST(${exprSql(e.n)} AS INTEGER))`;
    case "wsum": {
      const part = e.partition !== undefined ? `PARTITION BY m."${e.partition}"` : "";
      const ord = e.order !== undefined ? `ORDER BY m."${e.order}" ROWS UNBOUNDED PRECEDING` : ""; // order ⇒ running
      return `SUM(CAST(m."${e.col}" AS DOUBLE)) OVER (${[part, ord].filter(Boolean).join(" ")})`;
    }
    case "lead": {
      const part = e.partition !== undefined ? `PARTITION BY m."${e.partition}" ` : "";
      return `LEAD(m."${e.col}", ${e.offset ?? 1}) OVER (${part}ORDER BY m."${e.order}")`;
    }
    case "concat":
      return `(${e.parts.map(exprSql).join(" || ")})`; // SQL || — null-propagating
    case "round":
      return `round(CAST(${exprSql(e.x)} AS DOUBLE), ${e.digits})`;
    case "rownum":
      return `(row_number() OVER () - 1)`;
    case "cell":
      // a {ref} hole — emit() binds it per fixpoint iteration (the ref must be on the fragment's
      // cells list; lowerApplySql collects it via cellsOf).
      return `{${e.ref}}`;
    case "call": {
      const def = FUNCTIONS[e.fn];
      if (def === undefined) throw new Error(`exprSql: unknown function "${e.fn}"`);
      return def.sql(e.args.map(exprSql));
    }
  }
}

const wsig = (e: { col: string; partition?: string; order?: string }): string => `${e.col}|${e.partition ?? ""}|${e.order ?? ""}`;
const leadSig = (e: { col: string; order: string; partition?: string; offset?: number }): string => `lead:${e.col}|${e.partition ?? ""}|${e.order}|${e.offset ?? 1}`;

type EvalJs = (row: Row, fit: Row | null, ranks: Record<string, Map<Scalar, number>>, wsums: Record<string, Map<Row, number>>, cells?: Readonly<Record<string, Scalar>>, idx?: number) => Scalar;

// ── ScalarExpr → JS expression text (over `row`, `fit`, `ranks`) ──
function genJsExpr(e: ScalarExpr): string {
  switch (e.k) {
    case "lit":
      return JSON.stringify(e.v);
    case "col":
      return e.src === "fit" ? `(fit?.[${JSON.stringify(e.name)}] ?? null)` : `(row[${JSON.stringify(e.name)}] ?? null)`;
    case "bin": {
      const op =
        e.op === "+"
          ? "_ln + _rn"
          : e.op === "-"
            ? "_ln - _rn"
            : e.op === "*"
              ? "_ln * _rn"
              : e.op === "%"
                ? "_rn === 0 ? null : _ln % _rn"
                : "_rn === 0 ? null : _ln / _rn";
      return `(() => { const _l = ${genJsExpr(e.l)}; const _r = ${genJsExpr(e.r)}; if (_l === null || _r === null) return null; const _ln = Number(_l); const _rn = Number(_r); return ${op}; })()`;
    }
    case "nullif0":
      return `(() => { const _x = ${genJsExpr(e.x)}; return Number(_x) === 0 ? null : _x; })()`;
    case "rank":
      return `(ranks[${JSON.stringify(e.col)}]?.get(row[${JSON.stringify(e.col)}]) ?? 0)`;
    case "index":
      return `(() => { const _list = ${JSON.stringify([...e.list])}; const _i = Number(${genJsExpr(e.idx)}); const _n = _list.length; return _list[((_i % _n) + _n) % _n]; })()`;
    case "rand":
      return "Math.random()";
    case "unary": {
      const fn = e.fn === "ln" ? "Math.log" : e.fn === "floor" ? "Math.floor" : e.fn === "abs" ? "Math.abs" : "Math.sqrt";
      return `(() => { const _x = ${genJsExpr(e.x)}; return _x === null ? null : ${fn}(Number(_x)); })()`;
    }
    case "left":
      return `(() => { const _s = ${genJsExpr(e.str)}; const _n = ${genJsExpr(e.n)}; return _s === null ? null : String(_s).slice(0, Math.max(0, Number(_n))); })()`;
    case "wsum":
      return `(wsums[${JSON.stringify(wsig(e))}]?.get(row) ?? 0)`; // precomputed per-row window value
    case "lead":
      return `(wsums[${JSON.stringify(leadSig(e))}]?.get(row) ?? null)`; // precomputed successor; absent = partition tail → NULL
    case "concat":
      return `(() => { const _p = [${e.parts.map(genJsExpr).join(", ")}]; return _p.some((v) => v === null) ? null : _p.map(String).join(""); })()`;
    case "round":
      return `(() => { const _x = ${genJsExpr(e.x)}; if (_x === null) return null; const _m = 10 ** ${e.digits}; return Math.round(Number(_x) * _m) / _m; })()`;
    case "rownum":
      return `(idx ?? 0)`;
    case "cell":
      return `(cells?.[${JSON.stringify(e.ref)}] ?? null)`; // the store value, read once per lowering by the caller
    case "call": {
      const def = FUNCTIONS[e.fn];
      if (def === undefined) throw new Error(`genJsExpr: unknown function "${e.fn}"`);
      // null-guard the args, then splice the def's JS expression template over the arg refs —
      // dual-substrate parity with exprSql (the def.js text is the JS twin of def.sql).
      const args = e.args.map(genJsExpr);
      const refs = args.map((_, i) => `_a[${i}]`);
      return `(() => { const _a = [${args.join(", ")}]; return _a.some((v) => v === null || v === undefined) ? null : (${def.js(refs)}); })()`;
    }
  }
}

const compiledEvalJs = new WeakMap<ScalarExpr, EvalJs>();

export function compileEvalJs(e: ScalarExpr): EvalJs {
  let fn = compiledEvalJs.get(e);
  if (!fn) {
    fn = new Function("row", "fit", "ranks", "wsums", "cells", "idx", `return ${genJsExpr(e)};`) as EvalJs;
    compiledEvalJs.set(e, fn);
  }
  return fn;
}

// ── ScalarExpr → JS value (over a mark row + the fit row + precomputed rank maps) ──
function evalJs(e: ScalarExpr, row: Row, fit: Row | null, ranks: Record<string, Map<Scalar, number>>, wsums: Record<string, Map<Row, number>>, cells?: Readonly<Record<string, Scalar>>, idx?: number): Scalar {
  return compileEvalJs(e)(row, fit, ranks, wsums, cells, idx);
}

/** Precompute each window node's per-row value — the JS analogue of the SQL window functions.
 *  Keyed by the node's signature so genJsExpr can look it up: wsum (running/total SUM) and lead
 *  (the successor's value; a partition-tail row is ABSENT from the map ⇒ genJsExpr yields NULL). */
function windowSums(op: ApplyOp, rows: readonly Row[]): Record<string, Map<Row, number>> {
  const nodes = new Map<string, { col: string; partition?: string; order?: string }>();
  const leads = new Map<string, { col: string; order: string; partition?: string; offset?: number }>();
  const scan = (e: ScalarExpr): void => {
    if (e.k === "wsum") nodes.set(wsig(e), e);
    else if (e.k === "lead") leads.set(leadSig(e), e);
    else if (e.k === "bin") { scan(e.l); scan(e.r); }
    else if (e.k === "nullif0" || e.k === "unary" || e.k === "round") scan(e.x);
    else if (e.k === "index") scan(e.idx);
    else if (e.k === "left") { scan(e.str); scan(e.n); }
    else if (e.k === "concat") for (const p of e.parts) scan(p);
  };
  for (const e of Object.values(op.add)) scan(e);
  const out: Record<string, Map<Row, number>> = {};
  for (const [sig, e] of nodes) {
    const m = new Map<Row, number>();
    const parts = new Map<Scalar, Row[]>();
    for (const r of rows) { const k = (e.partition !== undefined ? r[e.partition] : "_all") as Scalar; const g = parts.get(k); if (g) g.push(r); else parts.set(k, [r]); }
    for (const group of parts.values()) {
      const total = group.reduce((sum, r) => sum + Number(r[e.col] ?? 0), 0);
      if (e.order === undefined) { for (const r of group) m.set(r, total); continue; }
      let acc = 0;
      for (const r of [...group].sort((a, z) => Number(a[e.order!] ?? 0) - Number(z[e.order!] ?? 0))) { acc += Number(r[e.col] ?? 0); m.set(r, acc); }
    }
    out[sig] = m;
  }
  for (const [sig, e] of leads) {
    const m = new Map<Row, number>();
    const parts = new Map<Scalar, Row[]>();
    for (const r of rows) { const k = (e.partition !== undefined ? r[e.partition] : "_all") as Scalar; const g = parts.get(k); if (g) g.push(r); else parts.set(k, [r]); }
    const off = e.offset ?? 1;
    for (const group of parts.values()) {
      const sorted = [...group].sort((a, z) => Number(a[e.order] ?? 0) - Number(z[e.order] ?? 0));
      for (let i = 0; i + off < sorted.length; i++) {
        const v = sorted[i + off][e.col];
        if (v !== null && v !== undefined) m.set(sorted[i], Number(v));
      }
    }
    out[sig] = m;
  }
  return out;
}

function rankMaps(op: ApplyOp, rows: readonly Row[]): Record<string, Map<Scalar, number>> {
  const cols = new Set<string>();
  const scan = (e: ScalarExpr): void => {
    if (e.k === "rank") cols.add(e.col);
    else if (e.k === "bin") {
      scan(e.l);
      scan(e.r);
    } else if (e.k === "nullif0" || e.k === "unary" || e.k === "round") scan(e.x);
    else if (e.k === "index") scan(e.idx);
    else if (e.k === "left") { scan(e.str); scan(e.n); }
    else if (e.k === "concat") for (const p of e.parts) scan(p);
  };
  for (const e of Object.values(op.add)) scan(e);
  const maps: Record<string, Map<Scalar, number>> = {};
  for (const col of cols) {
    const cats = [...new Set(rows.map((r) => r[col]))].sort(sortKey);
    maps[col] = new Map(cats.map((c, i) => [c, i] as const));
  }
  return maps;
}

// ── TRAIN ──
// ONE reduce, several consumers (scale train, extent bbox, path-agg) — the Agg vocabulary covers
// them all. The min/max/sum/count arms are the domain-training set and must stay byte-identical
// in their `col`-sugar form; the general base case aggregates an EXPRESSION (a.arg), so sum(x·w)
// or stringAgg(concat(…)) needs no staging column. The function set is a closed enum: every arm
// has a JS mirror and a declared carrier — scalar arithmetic ABOVE aggregates is reduce → derive.

/** The aggregate's argument as an expression — `col` is sugar for `mcol(col)`. Window leaves are
 *  ILLEGAL inside an aggregate argument (SQL rejects nested window-in-aggregate; the JS train path
 *  has no rank/wsum maps) — fail loudly at lowering, not with a cryptic backend error. */
function aggArg(a: Agg, b?: OpBinding): ScalarExpr {
  const arg = a.arg ?? { k: "col" as const, name: a.col!, src: "marks" as const };
  const scan = (e: ScalarExpr): void => {
    if (e.k === "rank" || e.k === "wsum" || e.k === "rownum" || e.k === "lead") throw new Error(`${b?.key ?? "reduce"}: window leaf "${e.k}" cannot appear inside an aggregate argument — derive it into a column first`);
    if (e.k === "bin") { scan(e.l); scan(e.r); }
    else if (e.k === "nullif0" || e.k === "unary" || e.k === "round") scan(e.x);
    else if (e.k === "index") scan(e.idx);
    else if (e.k === "left") { scan(e.str); scan(e.n); }
    else if (e.k === "concat") for (const p of e.parts) scan(p);
  };
  scan(arg);
  return arg;
}

const NUMERIC_AGG: Record<string, string> = { min: "min", max: "max", sum: "sum", avg: "avg", median: "median", stddev: "stddev", variance: "variance" };

const aggSql = (a: Agg, b?: OpBinding): string => {
  const x = exprSql(aggArg(a, b));
  if (a.fn === "countDistinct") return `count(DISTINCT ${x})`;
  if (a.fn === "count") return `count(${x})`;
  if (a.fn === "stringAgg") {
    const ord = a.order !== undefined ? ` ORDER BY m."${a.order}"${a.desc === true ? " DESC" : ""}` : "";
    return `string_agg(${x}, ${sqlLiteral(a.sep ?? ",")}${ord})`;
  }
  if (a.fn === "first" || a.fn === "last") {
    const ord = a.order !== undefined ? ` ORDER BY m."${a.order}"${a.desc === true ? " DESC" : ""}` : "";
    return `${a.fn}(${x}${ord})`;
  }
  if (a.fn === "anyValue") return `any_value(${x})`;
  return `${NUMERIC_AGG[a.fn]}(CAST(${x} AS DOUBLE))`;
};
const aggType = (a: Agg): SqlType =>
  a.fn === "countDistinct" || a.fn === "count" ? "int"
  : a.fn === "stringAgg" ? "varchar"
  : a.fn === "anyValue" || a.fn === "first" || a.fn === "last" ? "unknown" // passthrough carrier = the argument's
  : "double";

function aggJs(a: Agg, rows: readonly Row[], b?: OpBinding): Scalar {
  const ev = compileEvalJs(aggArg(a, b));
  const vals = rows.map((r, i) => ev(r, null, {}, {}, undefined, i));
  if (a.fn === "countDistinct") return new Set(vals).size;
  if (a.fn === "count") return vals.filter((v) => v !== null && v !== undefined).length; // SQL count(x): non-null
  // ORDER BY semantics mirror SQL: numeric when both values are numbers, else string.
  const cmp = (x: Scalar, z: Scalar): number => {
    const xn = Number(x), zn = Number(z);
    return Number.isFinite(xn) && Number.isFinite(zn) ? xn - zn : sortKey(x, z);
  };
  const ordered = (): Scalar[] => {
    if (a.fn !== "stringAgg" && a.fn !== "first" && a.fn !== "last") return [...vals];
    if (a.order === undefined) return [...vals];
    const dir = a.desc === true ? -1 : 1;
    return rows.map((r, i) => ({ v: vals[i], o: r[a.order!] as Scalar })).sort((x, z) => dir * cmp(x.o, z.o)).map((p) => p.v);
  };
  if (a.fn === "stringAgg") return ordered().map((v) => String(v ?? "")).join(a.sep ?? ",");
  if (a.fn === "first") { const o = ordered(); return (o[0] ?? null) as Scalar; }
  if (a.fn === "last") { const o = ordered(); return (o[o.length - 1] ?? null) as Scalar; }
  if (a.fn === "anyValue") return (vals[0] ?? null) as Scalar;
  const nums = vals.map(Number).filter(Number.isFinite);
  switch (a.fn) {
    case "sum": return nums.reduce((s, v) => s + v, 0);
    case "avg": return nums.length > 0 ? nums.reduce((s, v) => s + v, 0) / nums.length : null;
    case "median": {
      if (nums.length === 0) return null;
      const s = [...nums].sort((x, z) => x - z);
      const mid = s.length >> 1;
      return s.length % 2 === 1 ? s[mid] : (s[mid - 1] + s[mid]) / 2; // even n: interpolated (DuckDB numeric median)
    }
    case "stddev": case "variance": {
      if (nums.length < 2) return null; // sample statistics — DuckDB returns NULL for n < 2
      const mean = nums.reduce((s, v) => s + v, 0) / nums.length;
      const varSamp = nums.reduce((s, v) => s + (v - mean) ** 2, 0) / (nums.length - 1);
      return a.fn === "variance" ? varSamp : Math.sqrt(varSamp);
    }
    default: { // min | max
      let acc = a.fn === "min" ? Infinity : -Infinity;
      for (const v of nums) acc = a.fn === "min" ? Math.min(acc, v) : Math.max(acc, v);
      return acc;
    }
  }
}

// `by` (keyed execution): partition the fit by a key column — one fit row-group per key value
// (per-cell domains: by = "dvl_cell"). This is the NATIVE keyed path for every algebra-built train:
// vectorization is one GROUP BY / PARTITION BY in the shared lowering, written once for all of them.
// An ARRAY `by` is a composite group key (path-agg's series partition — possibly several ordinal
// columns); the single-string form is unchanged (its key column stays typed "int", the historical
// dvl_cell contract), composite keys type "unknown" (ordinal group columns carry their own types).
// `fragKey` names the emitted fragment ("fit" for the dispatch-scoped train path; a handler that
// writes fragments UNSCOPED must pass its own globally-unique key, as lowerApplySql callers do).
export function lowerTrainSql(op: TrainOp, marks: SqlFragment, b: OpBinding, byIn?: string | readonly string[], fragKey = "fit"): SqlFragment {
  if (Array.isArray(byIn)) {
    if (op.kind !== "aggregate") throw new Error(`${b.key}: a composite group key needs an aggregate train`);
    const keys = byIn as readonly string[];
    const keyCols: Schema = keys.map((k) => ({ name: k, type: "unknown" }));
    const keySel = keys.map((k) => `m."${k}" AS "${k}"`).join(", ");
    const sel = Object.entries(op.aggs).map(([out, a]) => `${aggSql(a, b)} AS "${out}"`).join(", ");
    const schema: Schema = Object.entries(op.aggs).map(([out, a]) => ({ name: out, type: aggType(a) }));
    if (keys.length === 0) return mkFrag(fragKey, `SELECT ${sel} FROM @marks AS m`, { marks: { fragment: marks } }, { columns: schema });
    return mkFrag(fragKey, `SELECT ${keySel}, ${sel} FROM @marks AS m GROUP BY ${keys.map((k) => `m."${k}"`).join(", ")}`, { marks: { fragment: marks } }, { columns: [...keyCols, ...schema] });
  }
  const by = byIn as string | undefined;
  const keyCol: Schema = by !== undefined ? [{ name: by, type: "int" }] : [];
  if (op.kind === "distinct") {
    if (op.indexed) {
      // keyed position table: each distinct value with its dense rank (value-sorted) + the count —
      // per key group when `by` (each cell ranks its own categories).
      const part = by !== undefined ? `PARTITION BY "${by}" ` : "";
      const inner = by !== undefined ? `SELECT DISTINCT m."${by}" AS "${by}", m."${op.col}" AS "${op.as}" FROM @marks AS m` : `SELECT DISTINCT m."${op.col}" AS "${op.as}" FROM @marks AS m`;
      const outerBy = by !== undefined ? `"${by}", ` : "";
      const body = `SELECT ${outerBy}"${op.as}", (dense_rank() OVER (${part}ORDER BY "${op.as}") - 1) AS idx, COUNT(*) OVER (${part.trim()}) AS n FROM (${inner})`;
      return mkFrag(fragKey, body, { marks: { fragment: marks } }, { columns: [...keyCol, { name: op.as, type: "varchar" }, { name: "idx", type: "int" }, { name: "n", type: "int" }] });
    }
    const cols = by !== undefined ? `m."${by}" AS "${by}", m."${op.col}" AS "${op.as}"` : `m."${op.col}" AS "${op.as}"`;
    return mkFrag(fragKey, `SELECT DISTINCT ${cols} FROM @marks AS m`, { marks: { fragment: marks } }, { columns: [...keyCol, { name: op.as, type: "varchar" }] });
  }
  const sel = Object.entries(op.aggs).map(([out, a]) => `${aggSql(a, b)} AS "${out}"`).join(", ");
  const schema: Schema = Object.entries(op.aggs).map(([out, a]) => ({ name: out, type: aggType(a) }));
  if (by !== undefined) {
    return mkFrag(fragKey, `SELECT m."${by}" AS "${by}", ${sel} FROM @marks AS m GROUP BY m."${by}"`, { marks: { fragment: marks } }, { columns: [...keyCol, ...schema] });
  }
  return mkFrag(fragKey, `SELECT ${sel} FROM @marks AS m`, { marks: { fragment: marks } }, { columns: schema });
}

export function lowerTrainJs(op: TrainOp, marks: JsRel, b: OpBinding, byIn?: string | readonly string[]): JsRel {
  if (Array.isArray(byIn)) {
    // composite group key — the JS mirror of the array-`by` SQL branch (GROUP BY several columns).
    if (op.kind !== "aggregate") throw new Error(`${b.key}: a composite group key needs an aggregate train`);
    const keys = byIn as readonly string[];
    if (keys.length === 0) return lowerTrainJs(op, marks, b);
    const groups = new Map<string, Row[]>();
    for (const r of marks.rows) {
      const k = keys.map((c) => String(r[c] ?? "")).join("\u0000"); // NUL-joined, the buildKeyed convention
      const g = groups.get(k);
      if (g === undefined) groups.set(k, [r as Row]);
      else g.push(r as Row);
    }
    const rows: Row[] = [];
    let schema: Schema = [];
    for (const g of [...groups.keys()].sort().map((k) => groups.get(k)!)) {
      const part = lowerTrainJs(op, { rows: g, schema: marks.schema }, b);
      schema = part.schema;
      const keyVals = Object.fromEntries(keys.map((c) => [c, g[0][c]]));
      for (const fr of part.rows) rows.push({ ...keyVals, ...fr });
    }
    return { rows, schema: [...keys.map((c) => ({ name: c, type: "unknown" as const })), ...schema] };
  }
  const by = byIn as string | undefined;
  if (by !== undefined) {
    // native keyed in JS: partition the rows, reuse the unkeyed logic per group, tag with the key.
    const groups = new Map<Scalar, Row[]>();
    for (const r of marks.rows) {
      const k = r[by] as Scalar;
      const g = groups.get(k);
      if (g === undefined) groups.set(k, [r as Row]);
      else g.push(r as Row);
    }
    const keys = [...groups.keys()].sort(sortKey);
    const rows: Row[] = [];
    let schema: Schema = [];
    for (const k of keys) {
      const part = lowerTrainJs(op, { rows: groups.get(k)!, schema: marks.schema }, b);
      schema = part.schema;
      for (const fr of part.rows) rows.push({ [by]: k, ...fr });
    }
    return { rows, schema: [{ name: by, type: "int" }, ...schema] };
  }
  if (op.kind === "distinct") {
    const cats = [...new Set(marks.rows.map((r) => r[op.col]))].sort(sortKey);
    if (op.indexed) {
      return { rows: cats.map((v, i) => ({ [op.as]: v, idx: i, n: cats.length })), schema: [{ name: op.as, type: "varchar" }, { name: "idx", type: "int" }, { name: "n", type: "int" }] };
    }
    return { rows: cats.map((v) => ({ [op.as]: v })), schema: [{ name: op.as, type: "varchar" }] };
  }
  const row: Record<string, Scalar> = {};
  const schema: Column[] = [];
  for (const [out, a] of Object.entries(op.aggs)) {
    row[out] = aggJs(a, marks.rows, b);
    schema.push({ name: out, type: aggType(a) });
  }
  return { rows: [row], schema };
}

// ── APPLY ──
function addSchema(op: ApplyOp): Schema {
  return Object.keys(op.add).map((out) => ({ name: out, type: op.outTypes?.[out] ?? "double" }));
}

export function lowerApplySql(op: ApplyOp, marks: SqlFragment, fit: SqlFragment | null, b: OpBinding, fragKey = "apply"): SqlFragment {
  const adds: Record<string, string> = {};
  for (const [out, e] of Object.entries(op.add)) adds[out] = exprSql(e);
  // every cell ref the adds read becomes a fragment cell — emit() binds the {ref} holes per iteration.
  const cells = [...new Set(Object.values(op.add).flatMap(cellsOf))];
  const replace = op.replace === true;
  if (op.fit === "none") return augmentBroadcast(fragKey, marks, adds, addSchema(op), null, cells, replace);
  if (op.fit === "broadcast") return augmentBroadcast(fragKey, marks, adds, addSchema(op), fit, cells, replace);
  if (fit === null) throw new Error(`${b.key}: keyed apply needs a fit`);
  return augmentKeyed(fragKey, marks, fit, op.fit.keyed, adds, addSchema(op), op.fit.kind ?? "JOIN", cells, replace);
}

export function lowerApplyJs(op: ApplyOp, marks: JsRel, fit: JsRel | null, _b: OpBinding, cells?: Readonly<Record<string, Scalar>>): JsRel {
  if (op.fit === "broadcast" && (fit === null || fit.rows.length === 0)) {
    throw new Error(`apply "${_b.key}": scale has no domain — scheduling error or missing train`);
  }
  const ranks = rankMaps(op, marks.rows);
  const wsums = windowSums(op, marks.rows);
  const bcast = op.fit === "broadcast" ? fit?.rows[0] ?? null : null;
  const keyed = typeof op.fit === "object" ? buildKeyed(op.fit.keyed, fit) : null;
  const rows = marks.rows.map((r, i) => {
    const fitRow = keyed !== null ? keyed.get(r) : bcast;
    const out: Record<string, Scalar> = { ...r };
    for (const [name, e] of Object.entries(op.add)) out[name] = evalJs(e, r, fitRow, ranks, wsums, cells, i);
    return out;
  });
  // replace: the value overwrite is in `out` already (assignment order); the schema replaces the
  // same-named column IN PLACE (mirroring composeSchema/SQL's SELECT * REPLACE) instead of appending.
  if (op.replace === true) {
    const adds = addSchema(op);
    const replaced = marks.schema.map((c) => adds.find((a) => a.name === c.name) ?? c);
    return { rows, schema: [...replaced, ...adds.filter((a) => !marks.schema.some((c) => c.name === a.name))] };
  }
  return { rows, schema: [...marks.schema, ...addSchema(op)] };
}

/** The keyed-fit lookup over ALL join pairs — the JS mirror of augmentKeyed's multi-pair ON
 *  (the composite [[dvl_cell,dvl_cell],[value,"value"]] and the single-pair case alike).
 *  Join values compare NORMALIZED (String): the two sides can carry one key with different
 *  types (DuckDB BigInt vs Number after materialization), matching SQL's coercing equality. */
function buildKeyed(on: ReadonlyArray<readonly [string, string] | readonly [string, string, string]>, fit: JsRel | null): { get(row: Row): Row | null } {
  if (on.some((p) => p[2] !== undefined && p[2] !== "eq")) throw new Error("keyed apply: the JS substrate supports eq join pairs only — a range-joined via must stay in SQL");
  const norm = (v: unknown): string => String(v ?? "");
  const keyOf = (r: Row, cols: readonly string[]): string => cols.map((c) => norm(r[c])).join("\u0000");
  const markCols = on.map(([m]) => m);
  const fitCols = on.map(([, f]) => f);
  const map = new Map<string, Row>((fit?.rows ?? []).map((fr) => [keyOf(fr, fitCols), fr] as const));
  return { get: (r) => map.get(keyOf(r, markCols)) ?? null };
}
