// fold() — collapse a fragment DAG into one query (WUDATA §3, WUDATA_IMPL §8).
//
// Post-order DFS: visit a fragment's inputs first (so producer CTEs are appended
// before consumers — a topological order), dedup shared producers (diamonds emit
// once), uniquify each fragment's local CTE names by its op id, rebind every
// @name (local-CTE-first, then inputs), and compose the result schema bottom-up
// (no SQL parsing). Cells are left intact for emit.
//
// DEDUP IS CONTENT-CHECKED (simplification §12 Phase 4b, "fragment identity"): an id is the
// NAME's claim to be one logical relation, and the name PROPOSES the merge — but content
// disposes. Two same-id nodes merge only when their bodies, outputs, and RESOLVED input
// bindings agree; a mismatch (a misnamed third-party fragment, an unseeded multi-invocation)
// degrades gracefully — both are emitted as distinct CTEs with uniquified labels and a
// once-per-id warning — instead of silently aliasing one body to the other or crashing.
// Correctness rides the OBJECT edges; the naming convention buys sharing and readable SQL.

import { composeSchema, type Schema } from "./schema.js";
import type { RelationName } from "./ids.js";
import { rewriteSql, type CteDef, type SqlFragment } from "./fragment.js";
import { defaultDialect, type Dialect } from "./dialect.js";

export interface FoldedQuery {
  readonly ctes: readonly CteDef[]; // flat, topologically ordered, uniquified
  readonly result: RelationName;
  readonly baseInputs: ReadonlySet<RelationName>;
  readonly schema: Schema;
  readonly cells: ReadonlySet<string>;
}

export function fold(
  top: SqlFragment,
  schemaOf: (r: RelationName) => Schema,
  dialect: Dialect = defaultDialect,
): FoldedQuery {
  const ctes: CteDef[] = [];
  const memoByObj = new Map<SqlFragment, { result: RelationName; schema: Schema }>();
  const memoById = new Map<string, { contentKey: string; res: { result: RelationName; schema: Schema } }>();
  const baseInputs = new Set<RelationName>();
  const cells = new Set<string>();
  const emittedNames = new Set<string>();

  function visit(f: SqlFragment): { result: RelationName; schema: Schema } {
    const seen = memoByObj.get(f);
    if (seen !== undefined) return seen; // same object — trivially the same relation

    // 1. resolve inputs first (post-order => producer CTEs land before ours). Resolving BEFORE
    // the id-dedup decision makes the content check sound: bindings compare by the inputs'
    // RESOLVED result names, which the object graph determined (children are memoized — cheap).
    const bind = new Map<string, RelationName>();
    const inSchema = new Map<string, Schema>();
    for (const [at, ref] of Object.entries(f.inputs)) {
      if ("base" in ref) {
        // Quote the base relation name for EMISSION (a name minted from a branch id/slug may
        // contain hyphens etc. — an illegal bare identifier); registration keeps the RAW name
        // (baseInputs) since the backend adapters quote on their own DDL. Fragment-result names
        // (the else branch) are already-uniquified safe CTE labels — left unquoted, matching emit.
        bind.set(at, dialect.ident(ref.base));
        baseInputs.add(ref.base);
        inSchema.set(at, schemaOf(ref.base));
      } else {
        const r = visit(ref.fragment);
        bind.set(at, r.result);
        inSchema.set(at, r.schema);
      }
    }

    // dedup: the id proposes, content disposes.
    const contentKey = JSON.stringify([f.result, f.ctes, [...bind.entries()].sort(), f.outputs]);
    const hit = memoById.get(f.id);
    if (hit !== undefined) {
      if (hit.contentKey === contentKey) {
        memoByObj.set(f, hit.res);
        return hit.res; // true diamond — one CTE serves both references
      }
      warnFragmentCollision(f.id); // degrade: emit as distinct (uniquified below), never alias
    }

    // 2. uniquify this fragment's own CTE names (counter-suffix on collision — a colliding or
    // sanitize-clashing id must not crash the render, only lose its shared label).
    const local = new Map<string, RelationName>();
    for (const c of f.ctes) {
      let uniq = `${f.op}__${c.name}`;
      for (let n = 2; emittedNames.has(uniq); n++) uniq = `${f.op}__${c.name}__${n}`;
      local.set(c.name, uniq);
    }

    // 3. rewrite @relation tokens (local-CTE first, then inputs); append in order.
    for (const c of f.ctes) {
      const body = rewriteSql(c.body, {
        rel: (name) => {
          const l = local.get(name);
          if (l !== undefined) return l;
          const b = bind.get(name);
          if (b !== undefined) return b;
          throw new Error(`unbound @${name} in op ${f.op}`);
        },
      });
      const uniq = local.get(c.name);
      if (uniq === undefined) throw new Error(`internal: missing local name for ${c.name}`);
      emittedNames.add(uniq);
      ctes.push({ name: uniq, body, recursive: c.recursive, columns: c.columns, usingKey: c.usingKey });
    }
    for (const cid of f.cells) cells.add(cid);

    // 4. compose output schema (no parsing).
    const resultName = local.get(f.result);
    if (resultName === undefined) {
      throw new Error(`result "${f.result}" is not a cte of op ${f.op}`);
    }
    const schema = composeSchema(f.outputs, inSchema);
    const res = { result: resultName, schema };
    memoByObj.set(f, res);
    if (memoById.get(f.id) === undefined) memoById.set(f.id, { contentKey, res });
    return res;
  }

  const top2 = visit(top);
  return { ctes, result: top2.result, baseInputs, schema: top2.schema, cells };
}

// once-per-id (per process): a misnamed fragment renders CORRECTLY with reduced sharing — the
// warning tells the author what to fix without failing their users' renders.
const warnedIds = new Set<string>();
function warnFragmentCollision(id: string): void {
  if (warnedIds.has(id)) return;
  warnedIds.add(id);
  console.warn(`dvl: fragment id "${id}" is bound to two different bodies in one query — sharing is disabled for it. One id names one relation: derive fragment ids from the binding key (b.key).`);
}
