// The non-scale layout operators + their registration. Same registration shape as scales:
// ONE Operator each, into the single operators registry (§12 Phase 5) — no module-globals.
import type { Registries } from "../../operator/registry.js";
import type { Operator } from "../../operator/operator.js";
import { bandX } from "./band-x.js";
import { bandY } from "./band-y.js";
import { barX } from "./bar-x.js";
import { barY } from "./bar-y.js";
import { eqX } from "./eq-x.js";
import { eqY } from "./eq-y.js";
import { dag } from "./dag.js";
import { force } from "./force.js";
import { gridStack } from "./grid-stack.js";
import { stackX } from "./stack-x.js";
import { stackY } from "./stack-y.js";
import { pitchX } from "./pitch-x.js";
import { pitchY } from "./pitch-y.js";
import { truncate } from "./truncate.js";
import { proportionalX } from "./proportional-x.js";
import { proportionalY } from "./proportional-y.js";
import { treemap } from "./treemap.js";
import { fitTextComponent } from "./fit-text.js";
import { routeComponent } from "./route.js";

export const layoutComponents: readonly Operator[] = [stackX, stackY, pitchX, pitchY, eqX, eqY, bandX, bandY, barX, barY, dag, force, gridStack, truncate, proportionalX, proportionalY, treemap, fitTextComponent, routeComponent];

export function registerLayouts(registries: Registries): void {
  for (const l of layoutComponents) registries.operators.register(l.name, l);
}
