// Cassowary arrange solver (kiwi.js) — same ArrangeSolver interface as propagation, but it OWNS its
// lowering of the strength-tagged Constraint[] (design/2026-07-17-sidestack-module.html §5.6).
//
// The one subtlety is the demand-loop idiom (WULAYOUT_IMPL §C6): a node's margin is a STRONG `=`
// DEFAULT that propagation TIGHTENS with a STRONG `≥` bound over the same edges, giving
// `hi − lo = max(default, bound)`. A simplex has no such tightening rule — a strong `=` and a strong
// `≥` at equal strength just fight. So Cassowary re-lowers a strong `=` (a tighten-able default) to
// WEAK; the strong `≥` bound then wins, reproducing `max(default, bound)` exactly. Every other
// strength passes through as tagged, so the soft subplot preferences (align = medium, equal-size =
// weak) that the propagation tier records-but-ignores are actually honored here — the reason to pick
// Cassowary at all. Finally, every owned variable gets a very-weak STAY so an otherwise unanchored
// relative system can't float to ±1e9 (kiwi leaves free variables unbounded without one).
import { Constraint as KiwiConstraint, Expression, Operator, Solver, Strength, Variable } from "kiwi.js";
import type { ArrangeSolver, Constraint, Param } from "../../ir/layout.js";
import type { CellRef } from "../../ir/cell.js";

const OP: Record<string, Operator> = { "=": Operator.Eq, ">=": Operator.Ge, "<=": Operator.Le };

/** Solver-owned re-lowering: a STRONG equality is a demand-loop DEFAULT → relax to WEAK so a strong
 *  `≥` bound over the same pair tightens it. Everything else keeps its tagged strength. */
function strengthOf(c: Constraint): number {
  if (c.op === "=" && c.strength === "strong") return Strength.weak;
  switch (c.strength) {
    case "required": return Strength.required;
    case "strong": return Strength.strong;
    case "medium": return Strength.medium;
    default: return Strength.weak;
  }
}

// Strictly weaker than any real preference (weak = create(0,0,1)) — an anchor, never a force.
const STAY = Strength.create(0, 0, 0.001);

export const cassowary: ArrangeSolver = (constraints, cells, owned = []) => {
  const solver = new Solver();
  const ownedSet = new Set<CellRef>(owned);
  const vars = new Map<CellRef, Variable>();
  const V = (ref: CellRef): Variable => {
    let v = vars.get(ref);
    if (v === undefined) { v = new Variable(String(ref)); vars.set(ref, v); }
    return v;
  };
  const param = (p: Param): number => {
    if (typeof p === "number") return p;
    const v = cells.read(p);
    return typeof v === "number" ? v : 0;
  };

  for (const c of constraints) {
    // owned edges → variables; non-owned fold to constants (skip if an input is unreadable — a demand
    // cell not yet measured; that constraint simply isn't active this sweep, as in propagation).
    let expr = new Expression(0);
    let ready = true;
    for (const t of c.terms) {
      const coef = param(t.coef);
      if (ownedSet.has(t.edge)) {
        expr = expr.plus(new Expression([coef, V(t.edge)])); // [coef, var] = coef·var (NOT `Expression(var, coef)`, which is var + coef)
      } else {
        const val = cells.read(t.edge);
        if (typeof val !== "number") { ready = false; break; }
        expr = expr.plus(coef * val);
      }
    }
    if (!ready) continue;
    expr = expr.plus(-param(c.constant));
    try {
      // kiwi Constraint is (expr, operator, rhs?, strength?) — rhs stays undefined (folded into expr).
      solver.addConstraint(new KiwiConstraint(expr, OP[c.op] ?? Operator.Eq, undefined, strengthOf(c)));
    } catch {
      // A non-required constraint kiwi rejects (a soft conflict) is dropped; a required one is a real bug.
      if (c.strength === "required") throw new Error(`cassowary: required constraint infeasible: ${c.label ?? "?"}`);
    }
  }

  // Anchor every owned variable with a very-weak STAY constraint `v = seed` (seeded at its current
  // value, else 0), so the system is fully determined: required/strong/weak facts all dominate this,
  // it only removes the free float. (Explicit weak constraints, not kiwi edit-variables — the latter's
  // suggest mechanism does not behave as a clean sub-weak stay.)
  for (const ref of owned) {
    const cur = cells.read(ref);
    const seed = typeof cur === "number" ? cur : 0;
    try {
      solver.addConstraint(new KiwiConstraint(new Expression([1, V(ref)]).plus(-seed), Operator.Eq, undefined, STAY));
    } catch { /* redundant — fine */ }
  }

  solver.updateVariables();
  for (const [ref, v] of vars) if (ownedSet.has(ref)) cells.write(ref, v.value() + 0, "assigned");
};
