// route: boundary attach for endpoint marks (box-model §5 rev. 2026-07-22) — a POST-AFFINE
// refine layout, fitText's class. Per row, each BOXED endpoint moves from its referent's center
// to the boundary point nearest the far end: the ray from this box's center toward the other
// endpoint's anchor, clipped where it exits the boundary. The metric is the referent's declared
// boundary shape (stamped per endpoint by desugarRouteInputs): "box" = L∞ (exit the rectangle),
// "ellipse" = L2 (exit the inscribed ellipse — a dot's ±r box clips at exactly r). Degenerate
// cases keep anchors, never NaN: a boxless endpoint stays verbatim; a zero-direction (self-loop)
// or overlapping/containing boxes (the clipped points would cross) keep both anchors.
//
// Inputs are the HIDDEN borrow channels desugarRouteInputs mints on the consuming plot
// (dvl_a<k>_x/y = the endpoint anchor, dvl_b<k>_* = the referent's box edges riding the same via
// join); outputs are the final endpoint channels (pick all four: x1, y1, x2, y2). Options:
//   shape / shape1 / shape2 — boundary metric override (default: the referent's boundaryShape);
//   pad — stand each clipped endpoint off its boundary by k px along the segment (arrowhead gap).
// js-only Exec (like fitText: division guards the relop vocabulary lacks); no domain — a
// geometric refinement, not a data mapping; nothing tickable.
import { jsImpl, type ExecCtx, type OpBinding } from "../../algebra/impl.js";
import type { PlanIO } from "../../operator/binding.js";
import { op } from "../../operator/operator.js";
import type { OpSpec } from "../../plan/opspec.js";
import type { JsRel } from "../../algebra/relation.js";
import type { Row, Scalar } from "../../data/schema.js";
import { coord, pixelSpace, type Space } from "../../types/attr.js";

/** The hidden input columns per endpoint k (1 = src, 2 = dst) — the names desugarRouteInputs
 *  mints and the natural-join default binds. */
export const routeCols = (k: 1 | 2) =>
  ({ ax: `dvl_a${k}_x`, ay: `dvl_a${k}_y`, x0: `dvl_b${k}_x0`, y0: `dvl_b${k}_y0`, x1: `dvl_b${k}_x1`, y1: `dvl_b${k}_y1` }) as const;

const INPUT_NAMES = [1, 2].flatMap((k) => Object.values(routeCols(k as 1 | 2)));

type Anchor = { cx: number; cy: number; hw: number; hh: number; boxed: boolean; shape: "box" | "ellipse" };

const numOf = (v: unknown): number | undefined => (typeof v === "number" && Number.isFinite(v) ? v : undefined);

/** The endpoint's anchor: its box center + half-extents when boxed, else the raw borrowed point. */
function anchorOf(row: Row, c: Record<keyof ReturnType<typeof routeCols>, string>, shape: "box" | "ellipse"): Anchor | undefined {
  const x = numOf(row[c.ax]), y = numOf(row[c.ay]);
  if (x === undefined || y === undefined) return undefined; // no endpoint at all — degenerate row
  const x0 = numOf(row[c.x0]), x1 = numOf(row[c.x1]), y0 = numOf(row[c.y0]), y1 = numOf(row[c.y1]);
  if (x0 !== undefined && x1 !== undefined && y0 !== undefined && y1 !== undefined) {
    return { cx: (x0 + x1) / 2, cy: (y0 + y1) / 2, hw: Math.abs(x1 - x0) / 2, hh: Math.abs(y1 - y0) / 2, boxed: true, shape };
  }
  return { cx: x, cy: y, hw: 0, hh: 0, boxed: false, shape: "box" };
}

/** Param t where the ray c + t·d exits the boundary; 0 for a point box (stay at center). */
function exitT(a: Anchor, dx: number, dy: number): number {
  const rx = a.hw > 0 ? Math.abs(dx) / a.hw : 0;
  const ry = a.hh > 0 ? Math.abs(dy) / a.hh : 0;
  // a zero half-extent means the boundary is flat on that axis: any travel on it exits at once —
  // unless the direction has no component there (rx/ry stays 0 and the other axis decides).
  const rxx = a.hw === 0 && dx !== 0 ? Infinity : rx;
  const ryy = a.hh === 0 && dy !== 0 ? Infinity : ry;
  const m = a.shape === "ellipse" ? Math.sqrt(rxx * rxx + ryy * ryy) : Math.max(rxx, ryy);
  return m > 0 && Number.isFinite(m) ? 1 / m : 0;
}

export const routeComponent = op({
  name: "route",
  // No domain: a geometric refinement over placed pixels — no trained fit, nothing tickable.
  inputs: { marks: INPUT_NAMES.map((name) => ({ name, type: "double" as const })) },
  output: { passthrough: "marks", add: [
    { name: "x1", type: "double" },
    { name: "y1", type: "double" },
    { name: "x2", type: "double" },
    { name: "y2", type: "double" },
  ] },
  outSpaces: {
    x1: pixelSpace(coord("x")),
    y1: pixelSpace(coord("y")),
    x2: pixelSpace(coord("x")),
    y2: pixelSpace(coord("y")),
  },
  // Pixel input contract ⇒ requiresPixelInputs (op() derives it): route defers post-affine, after
  // the via joins that mint its hidden borrow columns.
  inputSpaces: Object.fromEntries(INPUT_NAMES.map((n) => [n, pixelSpace(coord(n.endsWith("_x") || n.includes("_x0") || n.includes("_x1") ? "x" : "y"))])) satisfies Record<string, Space>,
  plan(io: PlanIO): OpSpec[] {
    // A standard "apply" op — the apply handler dispatches our js-only Exec (the framework
    // materializes SQL marks first). Same pattern as fitText.
    return [{
      id: `${io.id}:apply`,
      reads: io.marksIn !== undefined ? [io.marksIn] : [],
      writes: [io.marksOut],
      payload: { kind: "apply", algoName: "route", binding: io.binding },
    }];
  },
  exec: { js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, _ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    if (b.outputs.length !== 4) throw new Error(`route: pick all four endpoint outputs — .pick("x1", "y1", "x2", "y2") (got ${b.outputs.length})`);
    const [ox1, oy1, ox2, oy2] = b.outputs;
    // input columns: the first declared input rides the binding's `value` slot; the rest map by
    // their own names (identity project — finalizeLayout's natural-join default).
    const col = (name: string): string => (name === INPUT_NAMES[0] ? ((b.inputs.value as string | undefined) ?? name) : ((b.inputs[name] as string | undefined) ?? name));
    const named = (k: 1 | 2) => Object.fromEntries(Object.entries(routeCols(k)).map(([key, n]) => [key, col(n)])) as Record<keyof ReturnType<typeof routeCols>, string>;
    const c1 = named(1), c2 = named(2);
    const opts = (b.options ?? {}) as { shape?: "box" | "ellipse"; shape1?: "box" | "ellipse"; shape2?: "box" | "ellipse"; pad?: number };
    const s1 = opts.shape ?? opts.shape1 ?? "box";
    const s2 = opts.shape ?? opts.shape2 ?? "box";
    const pad = typeof opts.pad === "number" && opts.pad > 0 ? opts.pad : 0;

    const rows = marks.rows.map((row) => {
      const r = row as Row;
      const a1 = anchorOf(r, c1, s1), a2 = anchorOf(r, c2, s2);
      // no anchors at all (failed borrow): pass the raw borrowed values through untouched.
      if (a1 === undefined || a2 === undefined) return { ...r, [ox1]: r[c1.ax] ?? null, [oy1]: r[c1.ay] ?? null, [ox2]: r[c2.ax] ?? null, [oy2]: r[c2.ay] ?? null };
      const dx = a2.cx - a1.cx, dy = a2.cy - a1.cy;
      const len = Math.hypot(dx, dy);
      const centers = { ...r, [ox1]: a1.cx, [oy1]: a1.cy, [ox2]: a2.cx, [oy2]: a2.cy };
      if (len === 0) return centers; // self-loop — keep both anchors
      const t1 = a1.boxed ? exitT(a1, dx, dy) : 0;
      const t2 = a2.boxed ? exitT(a2, -dx, -dy) : 0;
      // pad (as a param fraction) applies only where a boundary was actually exited.
      const p1 = t1 + (a1.boxed ? pad / len : 0);
      const p2 = t2 + (a2.boxed ? pad / len : 0);
      // overlapping / containing boxes: the clipped points would cross — keep both anchors (centers)
      if (p1 + p2 >= 1) return centers;
      return {
        ...r,
        [ox1]: a1.cx + p1 * dx, [oy1]: a1.cy + p1 * dy,
        [ox2]: a2.cx - p2 * dx, [oy2]: a2.cy - p2 * dy,
      };
    });
    const schema = [...marks.schema];
    for (const o of b.outputs) if (!schema.some((c) => c.name === o)) schema.push({ name: o, type: "double" });
    return { substrate: "js", rows: rows as Readonly<Record<string, Scalar>>[], schema } as JsRel;
  }) },
});
