// stackX: weights → horizontal stacked segments. The x-mirror of stackY — but NOT a blind copy:
// stackY's y = cumsum/total works because the y range is inverted (the segment hangs DOWN from
// its running edge); on the uninverted x axis the START edge must be emitted explicitly:
// x = (cumsum − weight)/total, w = weight/total. Cumulative + total are WINDOWED sums (wsum).
// Inputs: weight (required), group (optional PARTITION), order (optional; default = weight).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, mcol, nullif0, wsum } from "../../algebra/relop.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const stackX = op({
  name: "stackX",
  inputs: { marks: [{ name: "weight", type: "double" }, { name: "group", type: "unknown" }, { name: "order", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), w: relativeSpace(len("x")) },
  inputSpaces: { weight: dataSpace },
  apply: (b): RelOp => {
    const [xo, wo] = b.outputs;
    const wt = inputCol(b, "value"); // primary input = the weight
    const partition = typeof b.inputs.group === "string" ? b.inputs.group : undefined;
    const order = typeof b.inputs.order === "string" ? b.inputs.order : wt; // default: stack by weight
    const cumsum = wsum(wt, { partition, order });
    const total = wsum(wt, { partition });
    return {
      kind: "derive",
      add: { [xo]: bin("/", bin("-", cumsum, mcol(wt)), nullif0(total)), [wo]: bin("/", mcol(wt), nullif0(total)) },
      outTypes: { [xo]: "double", [wo]: "double" },
    };
  },
});
