// The recording API (WUDEBUG §2). Code calls `span` (timing), `record` (a typed row
// into one of the explicit dvl_* tables, schema.ts), or `emit` (the catch-all event
// log). NULL_SINK is the default no-op so "debug off" has zero overhead and the calls
// can sit inert in the code. The real implementation is DuckDbSink (duckdb-sink.ts).
import type { Scalar } from "../data/schema.js";

/** A buffered row: scalars go to columns; objects/arrays are JSON-stringified on flush. */
export type DebugRow = Record<string, Scalar | object | undefined>;

export interface SpanAttrs {
  kind?: "pass" | "operator" | "iteration";
  pass?: string;
  iteration?: number;
  [k: string]: unknown;
}

export interface DebugSink {
  /** Configured verbosity threshold; rows whose table/level exceeds it are dropped. */
  readonly level: number;

  /** A timed unit of work → one `dvl_span` row. Handles sync and async bodies. */
  span<T>(name: string, attrs: SpanAttrs, body: () => T): T;

  /** The innermost open span, if any — how the backend tap attributes a `dvl_sql` row
   *  to the operator that issued it (a query always executes inside its op's span). */
  currentSpan?(): { id: string; name: string } | undefined;

  /** Append typed row(s) to a named structured table (run_id is stamped by the sink). */
  record(table: string, rows: DebugRow | DebugRow[]): void;

  /** Catch-all: record something new as (kind, subject, attrs) → `dvl_event`. */
  emit(kind: string, subject: string, attrs: Record<string, unknown>, level?: number): void;

  /** Start a run: ensure schema, allocate the global run_id, stamp subsequent rows. */
  beginRun(meta?: RunMeta): Promise<number>;

  /** Write buffered rows to the backend. */
  flush(): Promise<void>;
}

export interface RunMeta {
  label?: string;
  specHash?: string;
  root?: string;
  mode?: string;
}

/** Monotonic ms clock for span/query timings — sub-ms where the platform provides it,
 *  and immune to wall-clock adjustments. Rows store offsets from the run's t0. */
export const now: () => number =
  typeof globalThis.performance?.now === "function" ? () => globalThis.performance.now() : () => Date.now();

/** The default: records nothing. `span` still runs the body so control flow is intact. */
export const NULL_SINK: DebugSink = {
  level: -1,
  span: (_name, _attrs, body) => body(),
  record: () => {},
  emit: () => {},
  beginRun: async () => 0,
  flush: async () => {},
};
