// Expr → ScalarExpr: the channel-authoring language's data-leaf subset lowered to the ONE
// expression-lowering language (VIA_HARDENING §3.3 A1). ScalarExpr is dual-substrate by
// construction (algebra/lower.ts renders it to SQL and JS) — no new generator.
// Relational leaves (bound-ref / table-ref / agg) are JOINS, not scalars: liftViaExprs hoists
// them into their own channels before compile — a leftover leaf reaching here is a compiler bug.
import type { Expr } from "../../ir/expr.js";
import { bin, call, cell, lit, mcol, type ScalarExpr } from "../../algebra/relop.js";

export function toScalar(e: Expr): ScalarExpr {
  switch (e.kind) {
    case "literal": return lit(e.value, e.type.space);
    case "local-column": return mcol(e.columnName);
    case "binary": return bin(e.op, toScalar(e.left), toScalar(e.right));
    case "call": return call(e.fn, e.args.map(toScalar));
    case "var": return cell(e.cell);
    default:
      throw new Error(`toScalar: "${e.kind}" is a relational leaf — it must be lifted into its own step before scalar lowering (VIA_HARDENING §3.3 B1)`);
  }
}
