// intents — the SOLVER-AGNOSTIC layout intent IR (design/2026-07-17-layout-solve-semantics.html §10
// Step 8) and the two solver-OWNED lowerings. The band GEOMETRY (which intents a node's side-stack
// emits) lives in sidestack.arrangeIntents — this module only defines what an intent MEANS and how
// each solver encodes it.
//
// The problem it solves: the arranger + adornment lowerings used to emit constraints in ONE solver's
// idiom — propagation's "demand loop" (a STRONG `=` margin default TIGHTENED by a STRONG `≥`
// reservation over the same edge pair). A simplex (cassowary/kiwi) can't read that: to it a strong
// `=` and a strong `≥` are competing preferences with no tightening rule. So the arranger was married
// to propagation.
//
// The fix: lowerings stop emitting solver-specific `Constraint[]`. They emit a small, SOLVER-AGNOSTIC
// "intent" IR — what a placement MEANS, not how a given solver encodes it. Each solver OWNS its
// lowering from intents to native `Constraint[]`:
//   • propagation: `reserve` → strong `=` floor + strong `≥` bound  (today's demand-loop shape)
//   • cassowary:   `reserve` → required `≥` bound + WEAK floor       (smallest feasible gap)
// Both reach the same layout (pinned by solver-parity.test). Swapping solvers is choosing a lowering,
// nothing else.
//
// INVARIANT (experiment-pinned, layout-intent-fixpoint.mjs): SEALED inputs (the canvas `outer`) are
// PRE-WRITTEN to the store and NON-OWNED — never a `fix` intent. Propagation would propagate a `fix`,
// but cassowary reads non-owned cells as constants and would skip an unreadable one, floating the
// layout to NaN. So: sealed = pre-written non-owned; solver-written = owned; `fix` is ONLY for a cell
// that must be a solved variable pinned to a value.

import type { CellStore, CellRef } from "../ir/cell.js";
import type { Constraint } from "../ir/layout.js";
import { propagation } from "./solvers/propagation.js";
import { cassowary } from "./solvers/cassowary.js";

// ─────────────────────────────────────────────────────────────────────────────
// 1. The solver-agnostic layout INTENTS.
//    `fix` and `affine` are hard facts every solver handles the same way. `reserve` is the ONE intent
//    whose right encoding differs by solver — it bundles "gap ≥ Σdemand" with "keep the gap as small
//    as the margin floor allows," a margin+reservation as one semantic unit.
// ─────────────────────────────────────────────────────────────────────────────

export type Term = { coef: number; cell: CellRef };

export type Intent =
  | { kind: "fix"; cell: CellRef; value: number; note?: string } // cell = value (a solved variable pinned)
  | { kind: "affine"; terms: Term[]; equals: number; note?: string } // Σ coef·cell = equals (hard)
  | {
      kind: "reserve"; // (hi − lo) ≥ Σdemand + gap, AND (hi − lo) prefers `floor`, minimal otherwise
      hi: CellRef;
      lo: CellRef;
      demands: CellRef[];
      gap: number;
      floor: number;
      note?: string;
    }
  | {
      kind: "bound"; // span(hi, lo) must be at least `min`; MAXes with everything else on the pair.
                     // `lo` omitted ⇒ a 1-term bound (a template INSET cell). The fourth intent.
      hi: CellRef;
      lo?: CellRef;
      min: number | CellRef; // constant or a measured demand cell (written upward)
      note?: string;
    };

// ─────────────────────────────────────────────────────────────────────────────
// 2. The two solver-OWNED lowerings + the LayoutSolver interface over them.
//    Each translates the SAME intents into the constraint shape its solver can discharge, then
//    delegates to the existing ArrangeSolver. Adding a third solver = one more lowering here.
// ─────────────────────────────────────────────────────────────────────────────

export interface LayoutSolver {
  readonly name: string;
  solve(intents: readonly Intent[], store: CellStore, owned: readonly CellRef[]): void;
}

const toEdges = (terms: Term[]): Constraint["terms"] => terms.map((t) => ({ coef: t.coef, edge: t.cell }));
const gapTerms = (hi: CellRef, lo: CellRef): Constraint["terms"] => [{ coef: 1, edge: hi }, { coef: -1, edge: lo }];

/** PROPAGATION lowering — the demand-loop idiom, byte-for-byte the eager dock()/arrange shape: a
 *  STRONG `=` margin floor tightened by a STRONG `≥` reservation over the same edge pair. A `reserve`
 *  with no demands and zero gap is a pure margin (no `≥` bound) — an empty side yields exactly the
 *  lone strong margin equality, nothing extra. */
export function lowerForPropagation(intents: readonly Intent[]): Constraint[] {
  const cs: Constraint[] = [];
  for (const it of intents) {
    if (it.kind === "fix") cs.push({ terms: [{ coef: 1, edge: it.cell }], op: "=", constant: it.value, strength: "required", label: it.note });
    else if (it.kind === "affine") cs.push({ terms: toEdges(it.terms), op: "=", constant: it.equals, strength: "required", label: it.note });
    else if (it.kind === "bound") {
      const span = it.lo !== undefined ? gapTerms(it.hi, it.lo) : [{ coef: 1, edge: it.hi }];
      if (typeof it.min === "number") {
        cs.push({ terms: span, op: ">=", constant: it.min, strength: "strong", label: it.note });
      } else {
        cs.push({ terms: [...span, { coef: -1, edge: it.min }], op: ">=", constant: 0, strength: "strong", label: it.note });
      }
    } else { // reserve
      cs.push({ terms: gapTerms(it.hi, it.lo), op: "=", constant: it.floor, strength: "strong", label: `margin:${it.note ?? "reserve"}` });
      if (it.demands.length > 0 || it.gap !== 0) {
        cs.push({ terms: [...gapTerms(it.hi, it.lo), ...it.demands.map((d) => ({ coef: -1, edge: d }))], op: ">=", constant: it.gap, strength: "strong", label: it.note });
      }
    }
  }
  return cs;
}

/** CASSOWARY lowering — a REQUIRED `≥` bound + a WEAK `=` floor. The weak floor pulls the gutter down
 *  to the margin; the required bound stops it at Σdemand — the simplex's smallest feasible gap
 *  (largest content). Chains/centers stay required (rigid under any solver). The shipped
 *  solvers/cassowary.ts ArrangeSolver folds non-owned cells to store constants (an unreadable demand
 *  ⇒ that side simply isn't reserved yet — the first, unmeasured sweep) and anchors owned variables
 *  with sub-weak STAYs. */
export function lowerForCassowary(intents: readonly Intent[]): Constraint[] {
  const cs: Constraint[] = [];
  for (const it of intents) {
    if (it.kind === "fix") cs.push({ terms: [{ coef: 1, edge: it.cell }], op: "=", constant: it.value, strength: "required", label: it.note });
    else if (it.kind === "affine") cs.push({ terms: toEdges(it.terms), op: "=", constant: it.equals, strength: "required", label: it.note });
    else if (it.kind === "bound") {
      const span = it.lo !== undefined ? gapTerms(it.hi, it.lo) : [{ coef: 1, edge: it.hi }];
      if (typeof it.min === "number") {
        cs.push({ terms: span, op: ">=", constant: it.min, strength: "strong", label: it.note });
      } else {
        cs.push({ terms: [...span, { coef: -1, edge: it.min }], op: ">=", constant: 0, strength: "strong", label: it.note });
      }
    } else { // reserve
      if (it.demands.length > 0 || it.gap !== 0) {
        cs.push({ terms: [...gapTerms(it.hi, it.lo), ...it.demands.map((d) => ({ coef: -1, edge: d }))], op: ">=", constant: it.gap, strength: "required", label: it.note });
      }
      cs.push({ terms: gapTerms(it.hi, it.lo), op: "=", constant: it.floor, strength: "weak", label: `margin:${it.note ?? "reserve"}` });
    }
  }
  return cs;
}

/** Propagation's LayoutSolver: lower, then run the propagation ArrangeSolver. */
export const propagationSolver: LayoutSolver = {
  name: "propagation",
  solve(intents, store, owned) {
    propagation(lowerForPropagation(intents), store, owned);
  },
};

/** Cassowary's LayoutSolver: lower, then run the shipped kiwi ArrangeSolver. */
export const cassowarySolver: LayoutSolver = {
  name: "cassowary",
  solve(intents, store, owned) {
    cassowary(lowerForCassowary(intents), store, owned);
  },
};

export const LAYOUT_SOLVERS: Record<string, LayoutSolver> = { propagation: propagationSolver, cassowary: cassowarySolver };
