// truncate: replaces a string column with LEFT(col, K). An apply-only op() (no train, so no
// fit attaches). Not conceptually a scale — just a transform that fits the derive machinery.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { left, lit, mcol } from "../../algebra/relop.js";
import { dataSpace } from "../../types/attr.js";

export const truncate = op({
  name: "truncate",
  // No domain: a pure text transform, not a scale-shaped component — nothing tickable.
  inputs: { marks: [{ name: "value", type: "varchar" }] },
  output: { passthrough: "marks", add: [{ name: "value", type: "varchar" }] },
  outSpaces: { value: dataSpace }, // data→data: a truncated string is still a data value (§12.2)
  apply: (b): RelOp => {
    const k = Number(b.options?.k ?? -1);
    const col = mcol(inputCol(b, "value"));
    if (k < 0) {
      return { kind: "derive", add: { [b.outputs[0]]: col }, outTypes: { [b.outputs[0]]: "varchar" } };
    }
    return { kind: "derive", add: { [b.outputs[0]]: left(col, lit(k)) }, outTypes: { [b.outputs[0]]: "varchar" } };
  },
});
