// quantile: ticks at data quantiles (reads the DATA). js sorts + interpolates; sql pushes the
// computation into the DB via quantile_cont so large data never materializes.
import { mkFrag } from "../../algebra/relation.js";
import type { TickAlgo } from "../../operator/ticks.js";
import { clean, fmt, quantileProbs, quantileSorted } from "./_shared.js";

export const quantile: TickAlgo = {
  name: "quantile",
  over: "data",
  js({ rows }, ctx) {
    const xs = rows
      .map((r) => Number(r[ctx.column]))
      .filter(Number.isFinite)
      .sort((a, z) => a - z);
    return quantileProbs(ctx.count).map((p, i) => {
      const v = clean(quantileSorted(xs, p));
      return { idx: i, value: v, label: fmt(v) };
    });
  },
  sql(data, ctx) {
    const list = `[${quantileProbs(ctx.count).join(", ")}]`;
    return mkFrag(
      `ticks:${ctx.column}:quantile`,
      `SELECT (row_number() OVER () - 1) AS "idx", q AS "value", CAST(q AS VARCHAR) AS "label" FROM (SELECT unnest(quantile_cont(CAST(m."${ctx.column}" AS DOUBLE), ${list})) AS q FROM @data AS m) _u`,
      { data: { fragment: data } },
      { columns: [{ name: "idx", type: "int" }, { name: "value", type: "double" }, { name: "label", type: "varchar" }] },
    );
  },
};
