// Domain CONSTRUCTORS (§12 Phase 5c, the domain-owns-train design): the train is a required
// POSITIONAL argument — the fit IS the domain (WUAXIS), so a train cannot exist without the
// domain it derives. Forgetting the domain leaves the train nowhere to live (compile error);
// forgetting the train is a constructor arity error; defaults are inherited-or-overridden
// explicitly, never absent. mkScale/ScaleComponent are gone — every scale is ONE Operator
// built by op(), with the descriptor fields folded in.
import type { OpBinding } from "../../algebra/impl.js";
import type { RelOp } from "../../algebra/impl.js";
import type { TrainedDomain } from "../../operator/operator.js";
import { envelope, setUnion } from "../domains/index.js";

type Train = (b: OpBinding) => RelOp;
/** Per-scale overrides on a constructor's defaults — everything but the shape/train pair. */
type Over = Partial<Omit<TrainedDomain, "shape" | "train">>;

/** A CONTINUOUS trained domain: a 1-row fit ({lo,hi}-shaped) that CROSS JOINs to every mark
 *  (shape "broadcast"), envelope-unionable, nice-linear ticks and nice by default. */
export function continuous(train: Train, over?: Over): TrainedDomain {
  return { shape: "broadcast", train, union: "envelope", unionFn: envelope, ticks: "nice-linear", nice: "nice-linear", ordered: true, interpolable: true, ...over };
}

/** A CATEGORICAL trained domain: the N-row indexed category table (value, idx, n) JOINed on the
 *  value column (shape "keyed"), set-unionable, ordinal ticks, unordered by default. */
export function categorical(train: Train, over?: Over): TrainedDomain {
  return { shape: "keyed", train, union: "set-union", unionFn: setUnion, ticks: "ordinal", ordered: false, interpolable: false, ...over };
}
