// Kernel leaf ops: trivial, fixed-semantics handlers extracted from run.ts's inline switch.
// (values/unit moved into the relop source leaf — see ops/relop-op.ts.)
// Two families live here, and the distinction is load-bearing for the payload collapse (P4):
//   • cell-key IS relop-shaped (a nest-predicate join adding dvl_cell) — its target is a
//     join-derive relop (P4d data), after which the handler deletes.
//   • host-extent and verify are NOT relops and never migrate (P4g): they produce no relation.
//     host-extent is a scalar SINK in the solve/decision family — it materializes one host row,
//     places it into the content box, and writes pixel scalars to cells. A relop produces exactly
//     one relation; a "relop that writes cells" would break that invariant, so the honest
//     classification is reclassify, not collapse.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellRef, CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { jsRel, type Relation } from "../../../algebra/relation.js";
export async function hostExtentOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as { kind: string; row: number; x?: "relative" | "pixel"; y?: "relative" | "pixel"; w?: "relative" | "pixel"; h?: "relative" | "pixel" };
  const rel = store.read(op.reads[0]) as Relation;
  const rows = rel.substrate === "js" ? rel.rows : await ctx.run(rel.frag);
  const row = (rows[p.row] ?? {}) as Record<string, unknown>;
  const content = { left: Number(store.read(op.reads[1])), right: Number(store.read(op.reads[2])), top: Number(store.read(op.reads[3])), bottom: Number(store.read(op.reads[4])) };
  const place = (v: number, mode: "relative" | "pixel", lo: number, hi: number): number => (mode === "relative" ? lo + (hi - lo) * v : v);
  const out: number[] = [];
  if (p.x !== undefined) {
    const left = place(Number(row.x), p.x, content.left, content.right);
    out.push(left);
    if (p.w !== undefined) out.push(p.w === "relative" ? left + (content.right - content.left) * Number(row.w) : left + Number(row.w));
  }
  if (p.y !== undefined) {
    const top = place(Number(row.y), p.y, content.top, content.bottom);
    out.push(top);
    if (p.h !== undefined) out.push(p.h === "relative" ? top + (content.bottom - content.top) * Number(row.h) : top + Number(row.h));
  }
  out.forEach((v, i) => store.write(op.writes[i], v, "assigned"));
}

export function verifyOp(op: OpSpec, store: CellStore, ctx: RunCtx): void {
  const p = op.payload as { kind: string; nodeId: string };
  const inst = ctx.spec.nodes.get(p.nodeId)?.arrange;
  if (inst === undefined) throw new Error(`run: verify for node "${p.nodeId}" with no ArrangeInstance`);
  const val = (x: number | CellRef): number | undefined => (typeof x === "number" ? x : ((v) => (typeof v === "number" ? v : undefined))(store.read(x)));
  const rows: { label: string; residual: number }[] = [];
  for (const k of inst.constraints) {
    if (k.op === "=" || (k.strength !== "required" && k.strength !== "strong")) continue;
    let lhs = 0;
    let ready = true;
    for (const t of k.terms) {
      const v = val(t.edge);
      const co = val(t.coef);
      if (v === undefined || co === undefined) { ready = false; break; }
      lhs += co * v;
    }
    const c = val(k.constant);
    if (!ready || c === undefined) continue;
    const residual = k.op === ">=" ? lhs - c : c - lhs;
    if (residual < -0.5) rows.push({ label: k.label ?? "(unlabeled)", residual });
  }
  if (rows.length > 0) console.warn(`dvl: node "${p.nodeId}" violates ${rows.length} declared constraint(s): ${rows.map((r) => `${r.label} (${r.residual.toFixed(1)})`).join("; ")}`);
  store.write(op.writes[0], jsRel(rows, [{ name: "label", type: "varchar" }, { name: "residual", type: "double" }]), "assigned");
}
