// Scale-owned containment expansion (design/2026-07-21-scale-expansion.html §4).
// Two stages around the node walk:
//   allocScaleExpansion (BEFORE) — give every positional scale that serves an extent-bearing
//     author mark two RELATIVE-denominated expansion cells (demand, seeded 0 — the estimated
//     seeds that cut the SCC). An authored `expand` option allocs them SEALED (constants; no
//     loop, no measurement). `expand: 0 | false` opts out entirely.
//   emitScaleOverhang (AFTER) — one overhang op per live scale: reads its member plots' box
//     relations (the `box:` fork, dvl_x0/x1/y0/y1) + each member frame's content edges + the
//     expansion cells; writes the expansion cells. The frame affine reads those same cells,
//     which IS the cycle the scheduler fixpoints. One (e₀, e₁) per scale = the shared-scale
//     invariant: every member frame places through the same map (§3 scorecard).
import type { Spec } from "../../ir/spec.js";
import type { CellRef } from "../../ir/cell.js";
import type { LayoutInstance } from "../../ir/layout.js";
import type { LayoutId, PlotId } from "../../types/ids.js";
import type { OpSpec } from "../opspec.js";
import type { Plot } from "../../ir/plot.js";
import type { PlotBuild } from "../compile/context.js";
import { len, relativeSpace } from "../../types/attr.js";

/** Unwrap a channel-producing instance to its BASE scale: an apply-only wrapper carries its base
 *  instance's id as `options.wrappedId` (lower-axes) — the tick MUST place through the base's
 *  expansion cells or a tick at value V and a mark at value V land on different pixels (the
 *  false-axis bug, scale-expansion §8). LOUD on a dangling reference — the silent `?? inst`
 *  fallback here is exactly what turned a would-be compile error into a lying axis. */
export function baseInstanceOf(spec: Spec, id: LayoutId): LayoutInstance | undefined {
  const inst = spec.layouts.get(id);
  const wrappedId = inst?.options?.wrappedId;
  if (typeof wrappedId === "string") {
    const base = spec.layouts.get(wrappedId as LayoutId);
    if (base === undefined) throw new Error(`scale-expansion: "${id}" wraps unknown instance "${wrappedId}" — an apply-only wrapper must name its base scale's instance id`);
    return base;
  }
  return inst;
}

/** The base positional scale behind a channel expr (unwraps apply-only), or undefined. */
function baseScaleOf(spec: Spec, expr: Plot["channels"][string]): { inst: LayoutInstance; axis: "x" | "y" } | undefined {
  if (expr.kind !== "layout-output") return undefined;
  const sp = expr.type.space;
  if (sp.space !== "relative" || sp.geom.kind !== "coord") return undefined;
  const inst = baseInstanceOf(spec, expr.layout);
  return inst === undefined ? undefined : { inst, axis: sp.geom.axis };
}
/** Channels that give a mark real extent when BOUND. v1 participation gate: a mark drives
 *  expansion only when the author stated its size — an unbound dot's default r=3 halo may still
 *  bleed 3px (status quo everywhere), which keeps default-on from shifting every existing plot.
 *  `text` is the exception that proves the rule (box-text explainer): a label's extent IS its
 *  glyphs — the estimate (length·fontSize·0.6) exists whenever text is bound, no size channel
 *  needed. Only text marks declare a text-with-extentOf combination; a rect carrying a `text`
 *  column for fitText also passes, harmlessly — its extentOf reads box channels and an unbound
 *  box axis contributes a degenerate point. Origin-tagged labels (axes/legends) are excluded
 *  above, as ever. */
const EXTENT_CHANNELS = ["w", "h", "r", "x2", "y2", "text"];

/** A plot that can drive expansion: author-written, per-row, symbolic box, with a BOUND extent. */
export const participates = (plot: Plot): boolean =>
  plot.origin === undefined &&
  plot.resolvedMark?.extentOf !== undefined &&
  plot.resolvedMark.cardinality === "per-row" &&
  EXTENT_CHANNELS.some((ch) => plot.channels[ch] !== undefined);

/** Allocate expansion holes on every positional scale serving an extent-bearing author mark.
 *  Runs after resolveSpec (needs resolvedMark), before the node walk (the affine reads the cells). */
export function allocScaleExpansion(spec: Spec): void {
  for (const plot of spec.plots.values()) {
    if (!participates(plot)) continue;
    for (const expr of Object.values(plot.channels)) {
      const found = baseScaleOf(spec, expr);
      if (found === undefined || found.inst.expand !== undefined) continue;
      const { inst, axis } = found;
      const authored = inst.options?.expand;
      if (authored === 0 || authored === false) continue; // per-scale opt-out (D3)
      const space = relativeSpace(len(axis));
      if (typeof authored === "number" || Array.isArray(authored)) {
        // authored slack: constants (relative fractions of span), sealed — no measurement loop.
        const [lo, hi] = Array.isArray(authored) ? (authored as [number, number]) : [authored, authored];
        inst.expand = { lo: spec.cells.alloc("demand", lo, "scalar", space), hi: spec.cells.alloc("demand", hi, "scalar", space) };
        spec.cells.seal(inst.expand.lo);
        spec.cells.seal(inst.expand.hi);
      } else {
        inst.expand = { lo: spec.cells.alloc("demand", 0, "scalar", space), hi: spec.cells.alloc("demand", 0, "scalar", space) };
      }
    }
  }
}

/** Emit one overhang op per scale with LIVE (unsealed) expansion cells, aggregating every member
 *  frame's box relation against that frame's content edges. No member with a box ⇒ no op — the
 *  cells stay 0 and the affine's expansion arithmetic is exact identity. */
export function emitScaleOverhang(spec: Spec, builds: ReadonlyMap<PlotId, PlotBuild>, specs: OpSpec[]): void {
  // scale → axis + per-node box cells (a frame = the plot's node; content edges come from it)
  const perScale = new Map<LayoutId, { axis: "x" | "y"; frames: Map<string, CellRef[]> }>();
  for (const plot of spec.plots.values()) {
    if (!participates(plot)) continue;
    const boxed = builds.get(plot.id)?.boxed;
    if (boxed === undefined) continue;
    for (const expr of Object.values(plot.channels)) {
      const found = baseScaleOf(spec, expr);
      if (found === undefined || found.inst.expand === undefined) continue;
      if (spec.cells.get(found.inst.expand.lo).status === "sealed") continue; // authored constant
      let entry = perScale.get(found.inst.id);
      if (entry === undefined) perScale.set(found.inst.id, (entry = { axis: found.axis, frames: new Map() }));
      const frame = entry.frames.get(plot.node) ?? [];
      if (!frame.includes(boxed)) frame.push(boxed);
      entry.frames.set(plot.node, frame);
    }
  }
  for (const [scaleId, { axis, frames }] of perScale) {
    const expand = spec.layouts.get(scaleId)!.expand!;
    const frameSpecs = [...frames].map(([nodeId, boxes]) => {
      const cc = spec.nodes.get(nodeId)!.extent.content;
      // (lo, hi) in AFFINE order — the t=0 / t=1 endpoints (y flips: bottom is t=0).
      const [lo, hi] = axis === "x" ? [cc.left, cc.right] : [cc.bottom, cc.top];
      return { boxes, lo, hi };
    });
    specs.push({
      id: `${scaleId}:overhang`,
      reads: [...frameSpecs.flatMap((f) => [...f.boxes, f.lo, f.hi]), expand.lo, expand.hi],
      writes: [expand.lo, expand.hi],
      payload: { kind: "overhang", scale: scaleId, axis, expand, frames: frameSpecs },
    });
  }
}
