// The total attribute type system — carrier ⊥ space ⊥ geom (reorg §4.2).
//
// One column = one Attr. A relation's type is its attr list (TypedSchema). The
// three axes are INDEPENDENT along the two that vary freely (carrier, space) and
// DEPENDENT along the third (geom exists only inside the two spatial spaces), so
// illegal states — a data column with an axis, a style column with an area — are
// unrepresentable.
//
// This module is the type system, NOT its use: it defines the types and every
// operation on them (judgments, coercions, predicates). It imports only one
// frozen leaf (SqlType). See docs/2026-07-13-total-attr-type-system.html.
//
// GENERATIVE PRINCIPLE (design/DESIGN_PRINCIPLES_PROPOSAL.md §Method): a value's
// Space determines the COMPLETE, CLOSED set of operations legal on it. So the
// cases to support — in the compiler, the executor, AND the API surface — are
// found by enumerating the transitions the space algebra permits out of a space,
// not by accumulating features. E.g. a `data` value at a scale has exactly two
// out-transitions: data→domain (train) and data→relative (apply) — so `S('col')`
// and `S(datum)` are the whole surface, no third. When adding a Space or an
// operation, ask what the algebra makes total, not what a feature request wants.
import type { SqlType } from "../data/schema.js";

// ─────────────────────────────────────────────────────────────────────────────
// AXIS 1 — carrier: the physical representation. All DuckDB ever sees. Reused
// verbatim from the storage layer; re-exported so consumers name one home.
export type Carrier = SqlType;

// ─────────────────────────────────────────────────────────────────────────────
// AXIS 3 — geom: spatial shape. Present ONLY in the relative & pixel spaces, so
// it is nested inside those two Space variants (below), never a top-level field.
// Shared by both spatial spaces — which is exactly what makes the affine a
// space-flip that PRESERVES geom.
export type Axis = "x" | "y";
/** Axis for lengths: "x" | "y" for axis-specific, "xy" for isotropic (composes with either). */
export type LenAxis = "x" | "y" | "xy";
export type Geom =
  | { readonly kind: "coord"; readonly axis: Axis } // a point on an axis
  | { readonly kind: "len"; readonly axis: LenAxis } //   a length / vector along an axis (or isotropic)
  | { readonly kind: "area" }; //                      axis-free 2-D measure

// ─────────────────────────────────────────────────────────────────────────────
// AXIS 2 — space: the semantic world a value lives in; what the engine may DO
// with it. A tagged union so `switch (attr.type.space)` distinguishes at the top
// level and exhaustiveness is compiler-checked.
// Pen-consumed glyph parameters are terminal (reorg §10.1): anything the pen writes as a
// drawing attribute and the engine never transforms or composes lives here — including
// pixel-VALUED ones (fontSize, strokeWidth) and pixel-VERTEX geometry (a hull polygon: an
// array of already-placed [x,y] points the pen draws as-is). px-ness is a carrier fact, not a
// geom. Geom is earned by the affine/arithmetic, never by units; rotate stays terminal until a
// polar affine exists (a space is earned by an implemented mechanism, never anticipated).
export type StyleChannel = "color" | "shape" | "text" | "opacity" | "fontSize" | "rotate" | "strokeWidth" | "dash" | "geometry";
export type DomainShape = "envelope" | "categories";

export type Space =
  // source-table values + minted identity keys (dvl_plot/mark/cell) + derived
  // data relations (the tick table V, diagnostics). Trainable, joinable, the
  // loosest space and the default for a raw column.
  | { readonly space: "data" }
  // fitted metadata ABOUT a data column: an {lo,hi} envelope or an indexed
  // category table. Carries its subject (`over`) and family (`shape`); consumers
  // (ticks, apply joins) dispatch on shape.
  | { readonly space: "domain"; readonly over: string; readonly shape: DomainShape }
  // normalized-frame values in [0,1] — what produce-layouts emit. The affine's
  // INPUT. Carries a geom.
  | { readonly space: "relative"; readonly geom: Geom }
  // placed coordinates / lengths / extents / demands / measured sizes. The
  // affine's OUTPUT. Carries a geom.
  | { readonly space: "pixel"; readonly geom: Geom }
  // drawable non-spatial encodings the pen consumes untransformed. Terminal.
  | { readonly space: "style"; readonly channel: StyleChannel }
  // the artifact: materialized scene-graph rows / the SVG string. Terminal.
  | { readonly space: "scene" };

export type SpaceTag = Space["space"];

// ─────────────────────────────────────────────────────────────────────────────
// The Attr: one column's full type. carrier ⊥ space; geom rides inside space.
export interface Attr {
  readonly name: string;
  readonly carrier: Carrier; // physical
  readonly type: Space; //      semantic (engine metadata, never emitted to SQL)
}

/** A relation's type: its ordered attr list. Replaces Schema at engine seams. */
export type TypedSchema = readonly Attr[];

// ─────────────────────────────────────────────────────────────────────────────
// Constructors — the ONE place each Space variant is built, so callers never
// hand-assemble a tagged union (and a variant gaining a field breaks one site).
export const dataSpace: Space = { space: "data" };
export const sceneSpace: Space = { space: "scene" };
export const domainSpace = (over: string, shape: DomainShape): Space => ({ space: "domain", over, shape });
export const relativeSpace = (geom: Geom): Space => ({ space: "relative", geom });
export const pixelSpace = (geom: Geom): Space => ({ space: "pixel", geom });
export const styleSpace = (channel: StyleChannel): Space => ({ space: "style", channel });

export const coord = (axis: Axis): Geom => ({ kind: "coord", axis });
export const len = (axis: LenAxis): Geom => ({ kind: "len", axis });
export const area: Geom = { kind: "area" };

export const attr = (name: string, carrier: Carrier, type: Space = dataSpace): Attr => ({ name, carrier, type });

// ─────────────────────────────────────────────────────────────────────────────
// Predicates — the space vocabulary as questions. These replace the scattered
// `dim.mode === "pixel"` / SYSTEM_LAYOUTS-name checks the three encodings do today.
export const isData = (s: Space): boolean => s.space === "data";
export const isDomain = (s: Space): s is Extract<Space, { space: "domain" }> => s.space === "domain";
export const isRelative = (s: Space): s is Extract<Space, { space: "relative" }> => s.space === "relative";
export const isPixel = (s: Space): s is Extract<Space, { space: "pixel" }> => s.space === "pixel";
export const isStyle = (s: Space): s is Extract<Space, { space: "style" }> => s.space === "style";
export const isScene = (s: Space): boolean => s.space === "scene";

/** Spatial = carries a geom = participates in the affine. */
export const isSpatial = (s: Space): s is Extract<Space, { space: "relative" | "pixel" }> =>
  s.space === "relative" || s.space === "pixel";

/** Terminal = no further arithmetic or coercion is defined (the pen/sink consumes it). */
export const isTerminal = (s: Space): boolean => s.space === "style" || s.space === "scene";

/** The geom of a spatial space, else null. */
export const geomOf = (s: Space): Geom | null => (isSpatial(s) ? s.geom : null);

// ─────────────────────────────────────────────────────────────────────────────
// Structural equality — spaces are small immutable trees; used by judgment tests
// and (later) by validation to compare declared vs inferred.
export function geomEq(a: Geom, b: Geom): boolean {
  if (a.kind !== b.kind) return false;
  if (a.kind === "area") return true;
  return (a as { axis: string }).axis === (b as { axis: string }).axis;
}

export function spaceEq(a: Space, b: Space): boolean {
  if (a.space !== b.space) return false;
  switch (a.space) {
    case "data":
    case "scene":
      return true;
    case "domain":
      return a.over === (b as typeof a).over && a.shape === (b as typeof a).shape;
    case "relative":
    case "pixel":
      return geomEq(a.geom, (b as typeof a).geom);
    case "style":
      return a.channel === (b as typeof a).channel;
    default: {
      const _exhaustive: never = a;
      return _exhaustive;
    }
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// THE compatibility judgment: does a value in `actual` satisfy a slot expecting
// `expected`? Single source — validate.ts and satisfies() both import THIS.
// Fits = a coercion path exists (spatial pairs bridge via the affine; geoms must
// agree; len⟨xy⟩ is isotropic and composes with either axis).
export function fits(actual: Space, expected: Space): boolean {
  if (actual.space === "data") {
    if (expected.space === "data") return true;
    // a terminal style channel that carries a raw data column: `text` (the string) and
    // `geometry` (a polygon column — already-placed [x,y] vertices a hull reducer minted).
    if (expected.space === "style" && (expected.channel === "text" || expected.channel === "geometry")) return true;
    return false;
  }
  if (isSpatial(actual) && isSpatial(expected)) {
    const ag = actual.geom;
    const eg = expected.geom;
    if (ag.kind !== eg.kind) {
      if (ag.kind === "len" && eg.kind === "coord") return true;
      return false;
    }
    if (ag.kind === "area") return true;
    const aa = (ag as { axis: string }).axis;
    const ea = (eg as { axis: string }).axis;
    if (aa === ea) return true;
    if (aa === "xy" || ea === "xy") return true;
    return false;
  }
  if (isStyle(actual) && isStyle(expected)) {
    return actual.channel === expected.channel;
  }
  return spaceEq(actual, expected);
}

// ─────────────────────────────────────────────────────────────────────────────
// Human-readable rendering — for plan dumps / the debug harness. Legible without
// kind proliferation: the space says more than a payload kind ever did.
export function showGeom(g: Geom): string {
  return g.kind === "area" ? "area" : `${g.kind}⟨${g.axis}⟩`;
}
export function showSpace(s: Space): string {
  switch (s.space) {
    case "data":
      return "data";
    case "scene":
      return "scene";
    case "domain":
      return `domain(${s.over}:${s.shape})`;
    case "relative":
      return `relative ${showGeom(s.geom)}`;
    case "pixel":
      return `pixel ${showGeom(s.geom)}`;
    case "style":
      return `style:${s.channel}`;
    default: {
      const _exhaustive: never = s;
      return _exhaustive;
    }
  }
}
export function showAttr(a: Attr): string {
  return `${a.name}: ${a.carrier} @ ${showSpace(a.type)}`;
}
