// Strip lowering — a facet STRIP titles each subplot/panel with a text label, centered in the panel's
// step and sized by fitText, inside a reserved gutter band. Wired in compileSpec right after
// lowerLegends. Design mirror of an axis (WUAXIS): an adornment is ORDINARY PLOTS placed by the frame
// affine, PLUS the reservation machinery. See the explainer §strip for the marks-vs-adornment DELTA.
//
// A strip is the SIMPLEST adornment: no domain, no V synthesis (the panels `values` table is already
// the per-panel relation), no ticks. So it isolates exactly the adornment overhead over a plain mark:
//   (1) a per-panel CENTER (apply-only over the panels' x-layout, anchor "center" — same as an axis
//       tick lands on a band centre), (2) placement in a RESERVED gutter (a side-stack band on top),
//       (3) fitText sizing to the panel step box.
import type { Spec } from "../../ir/spec.js";
import type { Registries } from "../../operator/registry.js";
import type { Node, Side, PlotRect, AdornmentDirective } from "../../ir/node.js";
import type { Scale } from "../../ir/layout.js";
import type { LayoutOutputExpr, Expr } from "../../ir/expr.js";
import { col, layoutOutput, literal } from "../../ir/expr.js";
import { coord, len, pixelSpace, relativeSpace, styleSpace } from "../../types/attr.js";
import { placeToOrder } from "../../layout/sidestack.js";
import { boxCentre } from "../../layout/box-points.js";

const STRIP_HEIGHT = 18; // default reserved band thickness (px)
const STRIP_FONT = 11;   // fitText's max font size seed

export function lowerStrips(spec: Spec, registries: Registries): void {
  for (const node of spec.nodes.values()) {
    for (const dir of node.adornments) {
      if (dir.kind !== "strip") continue;
      createStrip(spec, registries, node, dir);
    }
  }
}

function createStrip(spec: Spec, _registries: Registries, node: Node, dir: AdornmentDirective & { kind: "strip" }): void {
  // The panels: the container plot (`node/panels`) over the virtual `values` table, and the layout it
  // binds on the strip axis (eqx/band → each panel's x + step). A strip needs that layout to CENTER.
  const panelsPlotId = `${node.id}/panels`;
  const panelsPlot = spec.plots.get(panelsPlotId);
  if (panelsPlot === undefined) return; // no panels on this node — nothing to strip
  const producer = panelsPlot.source; // { producer: `${node.id}/panels` }
  const side: Side = dir.placement ?? "top";
  const stripAxis: "x" | "y" = side === "left" || side === "right" ? "y" : "x";
  const cross: "x" | "y" = stripAxis === "x" ? "y" : "x";

  // the panels' layout on the strip axis (its x for a top/bottom strip) — the eqx/band that steps the
  // panels. Absent (panels not laid out on this axis) ⇒ can't center, skip.
  const stepCh = panelsPlot.channels[stripAxis] as LayoutOutputExpr | undefined;
  if (stepCh?.kind !== "layout-output") return;
  const stepLayoutId = stepCh.layout;
  const stepInst = spec.layouts.get(stepLayoutId) as Scale | undefined;
  if (stepInst === undefined) return;
  const labelCol = dir.labelCol; // the panels-table column holding each label's text

  const height = dir.height ?? STRIP_HEIGHT;
  const fontSize = dir.fontSize ?? STRIP_FONT;

  // (1) CENTRE: the panel centre is a typed DERIVATION over the panels' own step layout — x + w·½
  // (explainer §12.3), lifted into its own step by liftViaExprs (layout-output leaves). No producer
  // `anchor` option. Reusing the panels' OWN step layout means the centres are the SAME steps the
  // panels partition into — the alignment is structural, not coincidental. The derivation reads the
  // panels' bound step layout directly (which already keys on the panel index), so the strip's
  // position and its label can't diverge — no separate position key needed.
  const centerExpr: Expr = boxCentre(stepLayoutId, stripAxis);
  const stepW: Expr = layoutOutput(stepLayoutId, "w", { space: relativeSpace(len(stripAxis)), arity: "per-row" });

  // (3) fitText: fit the label to the panel STEP box (w = the relative step → pixels via the affine;
  // h = the strip band height). A REFINE layout — reads the placed mark's own text/w/h channels.
  const fitId = `${node.id}/strip-fit`;
  spec.layouts.set(fitId, {
    id: fitId, descriptor: "fitText",
    inputs: { marks: { relation: producer, project: { text: labelCol, w: "w", h: "h" } } },
    params: {},
    options: { maxFontSize: fontSize, minFontSize: 5 },
  });

  // the strip TEXT plot over the panels table. Placed by the frame affine like an axis label: a
  // relative coord on the strip axis (the panel centre) + the content edge on the cross axis, nudged
  // by a pixel dy into the reserved gutter. w = the panel step (for fitText); h = the band height.
  const relCoord = (a: "x" | "y") => relativeSpace(coord(a));
  const edgeT = side === "top" || side === "right" ? 1 : 0; // the content edge the strip hugs
  const dyPx = side === "top" ? -(height / 2) : side === "bottom" ? height / 2 : 0;
  const dxPx = side === "left" ? -(height / 2) : side === "right" ? height / 2 : 0;
  const channels: Record<string, Expr> = {
    [stripAxis]: centerExpr, // the panel centre (x + w/2)
    [cross]: literal(edgeT, relCoord(cross)),
    w: stepW, // the panel step (relative) → pixels via the affine → fitText box width
    h: literal(height, pixelSpace(len("y"))),
    text: col(labelCol, styleSpace("text")),
    fontSize: layoutOutput(fitId, "fontSize", { space: styleSpace("fontSize"), arity: "per-row" }),
    dx: literal(dxPx),
    dy: literal(dyPx),
    anchor: literal("middle"),
    baseline: literal("middle"),
    fill: literal("#333"),
  };
  const textPlotId = spec.ids.plot(node.id, `strip-${labelCol}`);
  spec.plots.set(textPlotId, { id: textPlotId, node: node.id, source: producer, markType: "text", channels, params: {}, origin: "strip" });
  node.plots.push(textPlotId);

  // (2) RESERVE a gutter band on `side` (fixed thickness — a title band, no measurement loop). Scalar
  // node: a side-stack band (SUMs with any axis on that side, Steps 1–4). Template: an inset reserve.
  if (node.insets === undefined) {
    const rect: PlotRect = {
      id: `strip-${labelCol}`, plots: [textPlotId],
      x: spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("x"))),
      y: spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("y"))),
      w: spec.cells.alloc("demand", 0, "scalar", pixelSpace(len("x"))),
      h: spec.cells.alloc("demand", 0, "scalar", pixelSpace(len("y"))),
    };
    (node.sideBands ??= []).push({ id: `strip-${labelCol}`, side, role: "strip-label", rect, fixedThickness: height, order: placeToOrder(dir.place), gap: dir.gap, pad: dir.pad });
  } else {
    const inset = node.insets[side];
    node.constraints.push({ terms: [{ coef: 1, edge: inset }], op: ">=", constant: height, strength: "strong", label: `strip:${side}` });
  }

  // group (styling/selection/debug), mirroring the axis/legend adornments.
  const groupId = spec.ids.group(node.id, `strip-${labelCol}`);
  node.groups.push({ id: groupId, role: "strip", plots: [textPlotId], annotates: { channel: labelCol } });
}
