// The Operator contract + the op() factory (ex dataflow/exec.ts part 3; §12 Phase 5c).
// An Operator IS its Exec (`sql`/`js` are the APPLY/main-step impls, spread directly) plus the
// declarative surface (inputs/output/outSpaces/inputSpaces/refs/domain/holes). One object, one
// registry entry. THE DOMAIN OWNS ITS TRAIN: the fit IS the domain (WUAXIS), so the train is the
// domain's DERIVATION and lives inside DomainSpec — "train without a domain" is unrepresentable.
import type { OutSchema, Row, Schema } from "../data/schema.js";
import type { LayoutHoles } from "../ir/layout.js"; // type-only: erases at runtime
import type { Space } from "../types/attr.js";
import type { JoinOp } from "../ir/refs.js";
import type { CellRef } from "../ir/cell.js";
import { buildApplyExec, buildTrainExec, inputCol, type DomainShape, type Exec, type Impl, type JsImpl, type OpBinding, type RelOp, type SqlImpl } from "../algebra/impl.js";
import type { PlanIO } from "./binding.js";
import { isActiveTreatment } from "./treatment.js";
import type { OpSpec } from "../plan/opspec.js";

/** Attach a non-enumerable toJSON so a resolved reference SELF-DESCRIBES in every stringify
 *  site (debug snapshots, graph dumps, error messages) as {"$<tag>": name}. Non-enumerable so
 *  SPREADS never copy a stale one — wrappers re-attach via reimpl/selfDescribe with their own
 *  name (dataflow/payloads.ts historically; the operator layer owns it now). */
export function selfDescribe<T extends object>(obj: T, tag: string, name: string): T {
  Object.defineProperty(obj, "toJSON", { value: () => ({ [tag]: name }), enumerable: false });
  return obj;
}

// ── DomainSpec: the domain OWNS its derivation (§12 Phase 5c, domain-owns-train) ──

/** The union algebra's implementation shape — the same dual-impl object the ir DomainDescriptor
 *  carries (resolve-once: components bind it at definition; no registry). */
export type DomainUnionFn = { readonly name: string; readonly js: (members: { rows: readonly Row[]; schema: Schema }[]) => { rows: Row[]; schema: Schema } };

/** A domain DERIVED from the data: the train IS the domain's derivation (WUAXIS: the fit is the
 *  domain), so it lives here — an operator cannot have a train without the domain it derives.
 *  Authored via the constructors (components/scales/types.ts continuous()/categorical()) whose
 *  required positional train argument makes "forgot the train" an arity error. */
export interface TrainedDomain {
  /** How the trained fit attaches to the marks — required: fits always attach somehow. */
  readonly shape: DomainShape;
  /** TRAIN — the reduction step (reduce/unique) that derives the domain, as a RelOp description. */
  readonly train: (b: OpBinding) => RelOp;
  /** Union operator NAME (serialization/identity). null = cannot share. */
  readonly union: string | null;
  /** The union IMPLEMENTATION — present iff `union` is non-null. */
  readonly unionFn?: DomainUnionFn;
  /** Default tick algo name for axes/legends (resolved from registries.tickAlgos). */
  readonly ticks: string;
  /** Nice function name. Absent = not niceable (derived treatment stays "data"). */
  readonly nice?: string;
  /** Values are comparable/ordered (affects legend/axis sort). */
  readonly ordered: boolean;
  /** Intermediate values can be produced (continuous). Affects out-of-domain handling. */
  readonly interpolable: boolean;
}

/** An ANNOTATION domain (threshold: authored breakpoints, no fit ever materializes) — shape and
 *  train are UNWRITABLE, not merely absent. A future explicit-domain operator is a third union
 *  member, not a migration. */
export interface StaticDomain {
  readonly shape?: never;
  readonly train?: never;
  readonly union?: string | null;
  readonly unionFn?: DomainUnionFn;
  readonly ticks: string;
  readonly nice?: string;
  readonly ordered: boolean;
  readonly interpolable: boolean;
}

export type DomainSpec = TrainedDomain | StaticDomain;

// ── Operator: the final unified component shape (§12 Phase 5) ────────────────

/** The ONE component contract: an Operator IS an Exec (`sql`/`js` = the APPLY/main-step impls)
 *  plus its declarative surface — the fields that used to live on a separate LayoutDescriptor.
 *  Registered once in `registries.operators`; the compiler reads `plan`, the executor dispatches
 *  the impls, api code reads inputs/output/outSpaces/domain/holes. */
export interface Operator extends Exec {
  readonly name: string;
  /** Input relations as data-layer Schemas (roles = column names); "marks" implicit. */
  readonly inputs: Record<string, Schema>;
  /** Augment-in-place output; composeSchema() yields the result schema. */
  readonly output: OutSchema;
  /** Output SPACE per added column — REQUIRED for every `output.add` column (registration
   *  error otherwise, decision §12.2). A Space for a fixed declaration; "binding" for the
   *  binding-polymorphic case (a positional scale's geom axis is the frame channel it serves —
   *  the INSTANCE stamps it at bind). Silence is never a declaration. */
  readonly outSpaces?: Record<string, OutSpaceDecl>;
  /** Input space requirements per named input column (W3/W4 checking). */
  readonly inputSpaces?: Record<string, Space>;
  /** Cross-input FK expectations a flat Schema can't hold (force: E.src/E.dst → marks.id). */
  readonly refs?: { from: string; to: string; op?: JoinOp }[];
  /** Structural replacement for the deleted phase flag (Stage 7b): an operator schedules
   *  post-affine iff its declared input contract REQUIRES pixel columns. */
  readonly requiresPixelInputs?: boolean;
  /** Inside a TEMPLATE this operator runs PER CELL by default (its edge keys on dvl_cell —
   *  one invocation per panel). Right for whole-set ARRANGEMENTS whose outputs are normalized
   *  over the rows they see (force, treemap): a global run squeezed into panels is almost never
   *  the intent. Scales keep the opposite default (shared domains); an authored `shared: true`
   *  on the instance opts back into one global run. */
  readonly perCell?: boolean;
  /** The structured domain, trained or static. A TrainedDomain carries the train fn — op()
   *  compiles it into `train` and derives `holes` from it. */
  readonly domain?: DomainSpec;
  /** TRAIN exec — COMPILED by op() from domain.train, never authored. Present ⇔ the domain is a
   *  TrainedDomain (the F3 invariant: needsFit ≡ train !== undefined). */
  readonly train?: Exec;
  /** The TickAlgo (by name) that synthesizes the `V` tick relation. */
  readonly ticks?: string;
  /** Default colour scheme NAME (AUTOLEGEND §6) for this scale when it serves a colour channel —
   *  sequential ("blues"/"viridis"/…) for continuous scales, categorical ("tableau10") for ordinal.
   *  resolveSpec resolves it (or an instance `options.scheme` override) to a palette. */
  readonly scheme?: string;
  /** Legend idiom this scale declares for a colour channel (AUTOLEGEND G2): "ramp" = a continuous
   *  gradient bar (band stack) — the interpolable families; absent = discrete swatches (ordinal,
   *  and DELIBERATELY quantize/threshold: a smooth ramp would lie about a binned encoding).
   *  lowerLegends' legendKind() is the ONE derivation site that reads this. */
  readonly legend?: "ramp";
  /** Emit this operator's SUBGRAPH. The graph builder calls this and nothing else. */
  readonly plan: (io: PlanIO) => OpSpec[];
  /** The under-defined cells an instance owns — DERIVED by op(): TrainedDomain ⇒ a domain hole. */
  readonly holes?: () => LayoutHoles;
}

// ── the default plan: the train/apply subgraph (absorbed from dataflow/plan.ts) ──
// This is NOT a universal "default" — it is specifically the shape a train/apply component
// reduces to: a scale, or a scale-shaped layout like eqx/band/col. The subgraph is
// [domain?, apply]: a domain (train) op iff the operator trains (needsFit ≡ domain is a
// TrainedDomain — the F3 invariant), then the apply op (AUGMENT the marks — marksOut = marksIn +
// this component's channel columns, attaching the fit iff one trains).
function trainApplyPlan(name: string, needsFit: boolean, io: PlanIO): OpSpec[] {
  const marksIn = io.marksIn; // a train/apply component TRANSFORMS marks — a source (no marksIn) can't be one
  if (marksIn === undefined) throw new Error(`${name}: a train/apply component needs input marks (PlanIO.marksIn)`);
  const by = io.key; // §C8: per-cell mode — partition train/apply by the key column (dvl_cell)
  const trainIn = io.trainIn ?? marksIn; // trains read the BASE (source columns) — never the augment chain
  // §C8 per-EDGE keyedness: a keyed apply's FIT edge is keyed too (the same-`by` train produced
  // it) — declared on the payload so the iterate path partitions BOTH edges, not just the marks
  // (exec.ts iteratePerGroup; a whole fit per group would mis-broadcast group 0's rows).
  const keyed = (fit: boolean): { keyedReads: readonly number[] } | Record<string, never> => (by !== undefined && fit ? { keyedReads: [0, 1] } : {});
  const apply = (reads: readonly CellRef[], fit?: CellRef): OpSpec => ({
    id: `${io.id}:apply`,
    reads,
    writes: [io.marksOut],
    payload: fit !== undefined ? { kind: "apply", algoName: name, binding: io.binding, fit, by, ...keyed(true) } : { kind: "apply", algoName: name, binding: io.binding, by },
  });
  const domainHole = io.holes.domain; // the trained-domain hole, if this component declared one — just a hole
  const contribution = io.holes.contribution; // present ⇒ a MEMBER of a shared scale (§C6 domain union)
  if (needsFit && domainHole !== undefined) {
    const fit = io.alloc("domain", "relation"); // SQL fit, CROSS-JOINed by apply; also materialized to `domain`
    if (contribution !== undefined) {
      // train THIS member's contribution; apply against the SHARED domain, filled by the framework's
      // gather-scatter op — the apply-only pattern (fit := the shared, already-resolved domain cell).
      // A shared group's ACTIVE treatment is applied by gather-scatter itself, post-union.
      return [
        { id: `${io.id}:domain`, reads: [trainIn], writes: [fit, contribution], payload: { kind: "domain", algoName: name, binding: io.binding, by } },
        apply([marksIn, domainHole], domainHole),
      ];
    }
    // §5a: an ACTIVE treatment (explicit/zero) must reach the MARKS, not just the axis — so the
    // apply consumes the treated, materialized domain cell (the same apply-only shape shared
    // scales use) instead of the raw SQL fit the untreated path cross-joins.
    if (isActiveTreatment(io.treatment)) {
      return [
        { id: `${io.id}:domain`, reads: [trainIn], writes: [fit, domainHole], payload: { kind: "domain", algoName: name, binding: io.binding, by, treatment: io.treatment } },
        apply([marksIn, domainHole], domainHole),
      ];
    }
    return [
      { id: `${io.id}:domain`, reads: [trainIn], writes: [fit, domainHole], payload: { kind: "domain", algoName: name, binding: io.binding, by } },
      apply([marksIn, fit], fit),
    ];
  }
  return [apply([marksIn])];
}

// ── output-space declarations (decision §12.2) ───────────────────────────────

/** Per-output space declaration. "binding" = binding-polymorphic: the space is instantiated
 *  per INSTANCE from the channel/frame it serves (positional scales, apply-only) — an explicit
 *  opt-out of a static declaration, never a silent default. */
export type OutSpaceDecl = Space | "binding";

/** The statically-declared Space of an output, if it has one ("binding" ⇒ undefined: the
 *  instance-stamped space, read from the bound channel expression, is authoritative). */
export const staticOutSpace = (d: OutSpaceDecl | undefined): Space | undefined => (d === undefined || d === "binding" ? undefined : d);

// ── op(): the universal operator factory ─────────────────────────────────────

/** What mkScale used to declare — the default single-value augment shape. */
const DEFAULT_INPUTS: Record<string, Schema> = { marks: [{ name: "value", type: "double" }] };
const DEFAULT_OUTPUT: OutSchema = { passthrough: "marks", add: [{ name: "value", type: "double" }] };

export function op(parts: {
  name: string;
  /** The structured domain. A trained fit is authored ONLY here — through the domain constructors
   *  (continuous/categorical, components/scales/types.ts) whose required train argument makes
   *  "train without a domain" unrepresentable. There is NO top-level train parameter. */
  domain?: DomainSpec;
  /** DECLARATIVE main step (derive) — compiled to dual keyed impls via the shared lowering. */
  apply?: (b: OpBinding) => RelOp;
  /** OPAQUE main step — the author's own Exec, passed through as-is. Without a custom `plan`,
   *  exactly one of apply/exec must be given: opaqueness is STATIC (§11.2 F2). With a custom
   *  plan, both may be absent (plan-only operators: vtable/unit/values/apply-only/grid-stack —
   *  their Exec side is empty). */
  exec?: Exec;
  ticks?: string;
  scheme?: string;
  legend?: "ramp";
  /** Custom graph topology; omitted = the train/apply subgraph (trainApplyPlan). */
  plan?: (io: PlanIO) => OpSpec[];
  /** Declarative surface (ex-LayoutDescriptor). Defaults = the mkScale shape. */
  inputs?: Record<string, Schema>;
  output?: OutSchema;
  outSpaces?: Record<string, OutSpaceDecl>;
  inputSpaces?: Record<string, Space>;
  refs?: { from: string; to: string; op?: JoinOp }[];
  perCell?: boolean;
}): Operator {
  if (parts.apply !== undefined && parts.exec !== undefined) throw new Error(`op("${parts.name}"): at most one of apply (declarative) / exec (opaque)`);
  if (parts.plan === undefined && parts.apply === undefined && parts.exec === undefined) throw new Error(`op("${parts.name}"): one of apply (declarative) / exec (opaque) required (or a custom plan for a plan-only operator)`);
  // RUNTIME BACKSTOP for untyped (plain-JS) callers — the DomainSpec union already makes these
  // unwritable in TS: a TrainedDomain requires shape+train together; a StaticDomain forbids both.
  const d = parts.domain;
  if (d?.train !== undefined && d.shape === undefined) throw new Error(`op("${parts.name}"): a trained domain must declare its fit shape ("broadcast" | "keyed") — author it via continuous()/categorical()`);
  if (d?.train === undefined && d?.shape !== undefined) throw new Error(`op("${parts.name}"): a static domain cannot carry a fit shape — shape belongs to the trained domain that uses it`);
  // UNDECLARED OUTPUT SPACE IS A REGISTRATION ERROR (decision §12.2): every added column
  // answers "what space is this?" at registration — verify-spaces is total only if this is.
  // Geom is earned by the affine/arithmetic, not by units (§10.1): a pen-consumed glyph
  // parameter (fontSize, rotate, …) is style⟨…⟩, never a decorative len⟨axis⟩.
  const outCols = "add" in (parts.output ?? DEFAULT_OUTPUT) ? ((parts.output ?? DEFAULT_OUTPUT) as { add: readonly { name: string }[] }).add.map((a) => a.name) : [];
  for (const c of outCols) {
    if (parts.outSpaces?.[c] === undefined)
      throw new Error(`op("${parts.name}"): output "${c}" has no declared space — add outSpaces.${c} (a Space, or "binding" for a binding-polymorphic output). A pen glyph parameter is style⟨…⟩, not a geom (reorg §10.1).`);
  }
  const trained = d?.train !== undefined; // needsFit ≡ the domain is a TrainedDomain (F3)
  const mainExec: Exec = parts.exec ?? (parts.apply !== undefined ? buildApplyExec(parts.apply, trained ? d!.shape : undefined) : {});
  // resolved refs SELF-DESCRIBE (§12 Phase 5a): every stringify site — debug snapshots, graph
  // dumps, error messages — serializes an embedded operator as {$op: name} via standard JSON.
  return selfDescribe<Operator>({
    name: parts.name,
    ...mainExec, // sql?/js? — the operator IS its Exec
    inputs: parts.inputs ?? DEFAULT_INPUTS,
    output: parts.output ?? DEFAULT_OUTPUT,
    outSpaces: parts.outSpaces,
    inputSpaces: parts.inputSpaces,
    refs: parts.refs,
    perCell: parts.perCell,
    requiresPixelInputs: parts.inputSpaces !== undefined && Object.values(parts.inputSpaces).some((s) => s.space === "pixel"),
    domain: parts.domain,
    train: trained ? buildTrainExec(d!.train!) : undefined,
    ticks: parts.ticks,
    scheme: parts.scheme,
    legend: parts.legend,
    plan: parts.plan ?? ((io: PlanIO) => trainApplyPlan(parts.name, trained, io)),
    holes: trained ? () => ({ domain: "relation" }) : undefined,
  }, "$op", parts.name);
}

/** Map every exec surface of an operator — sql, js, train.sql, train.js — through ONE transform
 *  (return undefined to drop an impl), optionally renaming. Object spread DROPS the non-enumerable
 *  toJSON, so wrapper registrations (a dekeyed/renamed external) go through here: reimpl
 *  re-attaches selfDescribe with the wrapper's (possibly new) name. */
export function reimpl(o: Operator, mapImpl: (impl: Impl) => Impl | undefined, name: string = o.name): Operator {
  const mapExec = (e: Exec): Exec => ({
    sql: e.sql !== undefined ? (mapImpl(e.sql) as SqlImpl | undefined) : undefined,
    js: e.js !== undefined ? (mapImpl(e.js) as JsImpl | undefined) : undefined,
  });
  return selfDescribe<Operator>({
    ...o,
    name,
    ...mapExec(o),
    train: o.train !== undefined ? mapExec(o.train) : undefined,
  }, "$op", name);
}
