// A DVL code editor — the ONE CodeMirror setup shared by the live playground (+page.svelte) and
// the documentation's live-example cards (documentation/assets/dvl-example.js, via the docs
// bundle). Both mount the same editor so they can never drift in behaviour or theme.
//
// Colours come entirely from CSS variables (--text/--text-dim/--hover + a --cm-*/--syn-* palette)
// defined by whatever surrounds the editor — the demo app's theme blocks, or the docs card CSS —
// so the editor matches its host by construction. basicSetup's default highlighter is
// light-tuned; ours (var-based) is layered at highest precedence to win on any background.
import { EditorView, keymap } from "@codemirror/view";
import { EditorState, Prec } from "@codemirror/state";
import { basicSetup } from "codemirror";
import { javascript } from "@codemirror/lang-javascript";
import { indentWithTab } from "@codemirror/commands";
import { HighlightStyle, syntaxHighlighting } from "@codemirror/language";
import { tags as tg } from "@lezer/highlight";

const cmTheme = EditorView.theme({
  "&": { color: "var(--text)", backgroundColor: "transparent", fontSize: "13px" },
  ".cm-content": { fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace", caretColor: "var(--cm-caret)" },
  ".cm-gutters": { backgroundColor: "transparent", color: "var(--text-dim)", border: "none" },
  ".cm-activeLine, .cm-activeLineGutter": { backgroundColor: "var(--hover)" },
  ".cm-selectionBackground, ::selection": { backgroundColor: "var(--cm-sel)" },
  ".cm-cursor": { borderLeftColor: "var(--cm-caret)" },
  "&.cm-focused": { outline: "none" },
});

const cmHighlight = HighlightStyle.define([
  { tag: tg.comment, color: "var(--syn-comment)", fontStyle: "italic" },
  { tag: [tg.keyword, tg.definitionKeyword, tg.moduleKeyword, tg.operatorKeyword], color: "var(--syn-keyword)" },
  { tag: [tg.function(tg.variableName), tg.function(tg.propertyName)], color: "var(--syn-func)" },
  { tag: [tg.string, tg.special(tg.string), tg.regexp], color: "var(--syn-string)" },
  { tag: [tg.number, tg.bool, tg.null, tg.atom], color: "var(--syn-number)" },
  { tag: [tg.className, tg.typeName, tg.namespace], color: "var(--syn-type)" },
  { tag: tg.propertyName, color: "var(--syn-prop)" },
  { tag: tg.variableName, color: "var(--syn-name)" },
  { tag: [tg.operator, tg.punctuation, tg.bracket, tg.separator], color: "var(--syn-punct)" },
  { tag: [tg.escape, tg.link, tg.url], color: "var(--syn-string)" },
  { tag: tg.invalid, color: "#e15759" },
]);

/** The DVL editor theme (var-driven; matches whatever host defines the --text/--syn-* vars). */
export const dvlEditorTheme = [cmTheme, Prec.highest(syntaxHighlighting(cmHighlight))];

export interface DvlEditorOpts {
  parent: HTMLElement;
  doc: string;
  /** Called (with the full document) on every user edit. */
  onChange?: (doc: string) => void;
}

/** Mount a DVL code editor: JS syntax, tab-indent, the shared theme, and a change callback. */
export function createDvlEditor(opts: DvlEditorOpts): EditorView {
  return new EditorView({
    state: EditorState.create({
      doc: opts.doc,
      extensions: [
        basicSetup,
        javascript(),
        keymap.of([indentWithTab]),
        ...dvlEditorTheme,
        EditorView.updateListener.of((u) => {
          if (u.docChanged && opts.onChange) opts.onChange(u.state.doc.toString());
        }),
      ],
    }),
    parent: opts.parent,
  });
}
