// fitText layout component: solves fontSize, rotate, and line wrapping for text constrained to boxes.
// Reads pixel-space w/h from placed marks (inputSpaces declares the requirement).
import type { OpBinding } from "../../algebra/impl.js";
import type { PlanIO } from "../../operator/binding.js";
import { jsImpl, type ExecCtx } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import type { OpSpec } from "../../plan/opspec.js";
import { fitText, type FitTextOptions } from "./fit-text-algo.js";
import { inputCol } from "../../algebra/impl.js";
import type { JsRel } from "../../algebra/relation.js";
import type { Scalar } from "../../data/schema.js";
import { len, pixelSpace, styleSpace, type Space } from "../../types/attr.js";

export const fitTextComponent = op({
  name: "fitText",
  // No domain: a text-fitting transform, not a data mapping — fontSize/rotate/lines are
  // solved per mark from pixel boxes (post-affine); no trained fit, nothing tickable.
  inputs: {
    marks: [
      { name: "text", type: "varchar" },
      { name: "w", type: "double" },
      { name: "h", type: "double" },
    ],
  },
  output: { passthrough: "marks", add: [
    { name: "fontSize", type: "double" },
    { name: "rotate", type: "double" },
    { name: "lines", type: "varchar" },
  ] },
  // Pen glyph parameters are TERMINAL (§10.1): fontSize is not a y-length — it is never
  // affine-placed and composes with nothing; its px-ness is a carrier fact. rotate would
  // compose in polar coordinates, but no polar affine exists, so it is terminal today.
  outSpaces: {
    fontSize: styleSpace("fontSize"),
    rotate: styleSpace("rotate"),
    lines: styleSpace("text"),
  },
  inputSpaces: { w: pixelSpace(len("x")), h: pixelSpace(len("y")) } satisfies Record<string, Space>,
  plan(io: PlanIO): OpSpec[] {
    // Emit a standard "apply" op — the apply handler dispatches our js-only Exec (the
    // framework materializes SQL marks first). Same pattern as force.
    return [{
      id: `${io.id}:apply`,
      reads: io.marksIn !== undefined ? [io.marksIn] : [],
      writes: [io.marksOut],
      payload: { kind: "apply", algoName: "fitText", binding: io.binding },
    }];
  },
  exec: { js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, _ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    const textCol = inputCol(b, "value");
    const wCol = b.inputs.w as string | undefined ?? "w";
    const hCol = b.inputs.h as string | undefined ?? "h";
    const opts = (b.options ?? {}) as Partial<FitTextOptions>;

    const measure = (text: string, fontSize: number) => text.length * fontSize * 0.6;

    const items = marks.rows.map(r => ({
      text: String(r[textCol] ?? ""),
      box: { w: Number(r[wCol] ?? 0), h: Number(r[hCol] ?? 0) },
    }));

    const results = fitText(items, { ...opts, measure });

    const rows = marks.rows.map((r, i) => {
      const out: Record<string, unknown> = { ...r };
      if (b.outputs[0]) out[b.outputs[0]] = results[i].fontSize;
      if (b.outputs[1]) out[b.outputs[1]] = results[i].rotate;
      if (b.outputs[2]) out[b.outputs[2]] = JSON.stringify(results[i].lines);
      return out;
    });
    const schema = [...marks.schema];
    if (b.outputs[0]) schema.push({ name: b.outputs[0], type: "double" });
    if (b.outputs[1]) schema.push({ name: b.outputs[1], type: "double" });
    if (b.outputs[2]) schema.push({ name: b.outputs[2], type: "varchar" });
    return { substrate: "js", rows: rows as Readonly<Record<string, Scalar>>[], schema } as JsRel;
  }) },
});
