// Schema types + composition / union-compatibility (WUDATA_IMPL §1, §7-§8).

export type Scalar = string | number | boolean | null;
/** Scalar-valued row (emit literals, scalar contexts). */
export type Row = Readonly<Record<string, Scalar>>;
/** JSON value: registered JS data may nest (e.g. loaded from JSON). */
export type Json = Scalar | readonly Json[] | { readonly [k: string]: Json };
/** A registered JS data row; values may be nested (arrays/objects). */
export type JsonRow = Readonly<Record<string, Json>>;
/** A raw backend query result row: values may be lists/structs, not just scalars. */
export type RawRow = Readonly<Record<string, unknown>>;

export type SqlType =
  | "int"
  | "double"
  | "varchar"
  | "bool"
  | "date"
  | "blob"
  | "json"
  | "list" // nested array, e.g. STRUCT(x,y)[] — used by the line/path mark's array_agg
  | "struct"
  | "unknown";

export interface Column {
  readonly name: string;
  readonly type: SqlType;
}
export type Schema = readonly Column[];

/**
 * A fragment's output schema, declared so the engine never parses SQL to learn
 * columns (WUDATA §3):
 *  - `passthrough` — all columns of the named `@input`, with `add` REPLACING
 *    same-named ones (in place) and appending the rest;
 *  - `columns` — an explicit list (aggregates, pivots, …).
 */
export type OutSchema =
  | { readonly passthrough: string; readonly add: Schema }
  | { readonly columns: Schema };

/**
 * Resolve a fragment's `OutSchema` against its bound inputs' schemas.
 * `inSchema` is keyed by the fragment's `@input` names.
 */
export function composeSchema(
  outputs: OutSchema,
  inSchema: ReadonlyMap<string, Schema>,
): Schema {
  if ("columns" in outputs) return outputs.columns;
  const base = inSchema.get(outputs.passthrough);
  if (base === undefined) {
    throw new Error(`passthrough input @${outputs.passthrough} has no schema`);
  }
  const result: Column[] = base.map((c) => ({ ...c }));
  for (const add of outputs.add) {
    const idx = result.findIndex((c) => c.name === add.name);
    if (idx >= 0) result[idx] = { ...add }; // REPLACE in place
    else result.push({ ...add });
  }
  return result;
}

/**
 * Union-compatibility check for binding a relation to a fragment input
 * (WUDATA §3 rule 4). Returns a provided→expected rename map, or `null` if
 * incompatible.
 *
 * Order: explicit override + by-name, else positional (same arity), else null.
 */
export function reconcile(
  provided: Schema,
  expected: Schema,
  explicit?: Readonly<Record<string, string>>,
): Record<string, string> | null {
  const providedNames = new Set(provided.map((c) => c.name));

  const byName: Record<string, string> = {};
  let allByName = true;
  for (const e of expected) {
    const src = explicit?.[e.name] ?? e.name;
    if (providedNames.has(src)) byName[src] = e.name;
    else {
      allByName = false;
      break;
    }
  }
  if (allByName) return byName;

  if (provided.length !== expected.length) return null;
  const positional: Record<string, string> = {};
  for (let i = 0; i < expected.length; i++) {
    positional[provided[i].name] = expected[i].name;
  }
  return positional;
}
