// W3: TypedSchema propagation + satisfies plan pass.
// Composes a TypedSchema along the relop chain per plot, checks inputSpaces via
// satisfies, and asserts no relative column survives past the affine.
// Runs always (D3 under D-A3: lax warns and counts, strict throws).
import type { CellRef } from "../../ir/cell.js";
import type { OpSpec } from "../opspec.js";
import type { RelopPayload } from "../payloads.js";
import type { Operator } from "../../operator/operator.js";
import type { TypedSchema } from "../../types/attr.js";
import { attr, dataSpace, domainSpace, type DomainShape, type Space } from "../../types/attr.js";
import { composeAttrs, requirementsOf, satisfies, unplacedSpatial } from "../../types/schema.js";
import { dvlSettings } from "../../config.js";
import type { Spec } from "../../ir/spec.js";
import { walk, type Expr } from "../../ir/expr.js";
import type { Path } from "../../ir/refs.js";

export interface PlanCheckViolation {
  readonly opId: string;
  readonly kind: "input-unsatisfied" | "unplaced-after-affine" | "illegal-consumption" | "alignment-conflict" | "draw-needs";
  readonly message: string;
}

/** Step 7 (WULAYOUT §1.3) — the floating-vs-aligned conflict. A coordinate channel bound through a
 *  positional SCALE is ALIGNED on its axis (it shares that scale's extent); a coordinate pinned to an
 *  absolute pixel LITERAL FLOATS. A box that binds the SAME axis both ways is over-determined: the
 *  absolute pin wins its pixels and breaks the alignment. Report each such plot+axis — an authoring
 *  smell to surface, not silently resolve. (Relative-coord literals are frame-aligned, not floating;
 *  lengths w/h are not coordinate pins; so a scale x with a fixed pixel w is fine.) */
export function checkAlignmentConflicts(spec: Spec): PlanCheckViolation[] {
  const out: PlanCheckViolation[] = [];
  for (const plot of spec.plots.values()) {
    const aligned: Record<"x" | "y", string[]> = { x: [], y: [] };
    const floating: Record<"x" | "y", string[]> = { x: [], y: [] };
    for (const [ch, expr] of Object.entries(plot.channels)) {
      const sp = (expr as { type?: { space?: Space } }).type?.space;
      if (sp === undefined || (sp.space !== "relative" && sp.space !== "pixel")) continue;
      if (sp.geom?.kind !== "coord") continue; // lengths (w/h) and non-coord channels don't pin position
      const axis = sp.geom.axis as "x" | "y";
      if (expr.kind === "layout-output") {
        const inst = spec.layouts.get((expr as { layout: string }).layout);
        if (inst?.domain !== undefined) aligned[axis].push(ch); // a trained positional scale → aligned
      } else if (expr.kind === "literal" && sp.space === "pixel") {
        floating[axis].push(ch); // an absolute pixel pin → floats
      }
    }
    for (const axis of ["x", "y"] as const) {
      if (aligned[axis].length > 0 && floating[axis].length > 0) {
        out.push({
          opId: plot.id,
          kind: "alignment-conflict",
          message: `plot "${plot.id}" binds axis ${axis} both to a scale (${aligned[axis].join(", ")} — aligned) and to an absolute pixel pin (${floating[axis].join(", ")} — floating); the pin breaks the alignment. Use one or the other on ${axis}.`,
        });
      }
    }
  }
  return out;
}

/** Resolver totality (VIA_HARDENING §1.3, closes CELL_KEY_VIA's recorded cut "the resolver is not
 *  yet total over Path sites"): after resolveSpec, EVERY reachable Path site must carry its stamp.
 *  A miss is a compiler wiring bug (a new Path site added without wiring it into resolvePaths) or
 *  an unsupported via position (a via nested inside arithmetic — VIA_HARDENING §3) — both must
 *  fail loud at build, never surface as a downstream lookup on an unresolved path. Always throws
 *  (an internal invariant, not a lax/strict user diagnostic).
 *
 *  The site inventory mirrors resolvePaths' contract (plan/resolve.ts):
 *    - template ChildRef.nest        → .resolved     (static hostRow children carry no path)
 *    - plot.nest / plot.frame        → .resolved
 *    - channel bound-ref/table-ref   → .resolvedVia  (walked into binary operands and agg refs,
 *                                                     where resolvePaths does NOT reach today)
 *    - layout aux input `on`         → .resolvedOn
 *  σ is a resolve-once PRODUCT (plot.sigma.paths are born resolved) — nothing to check. */
export function assertResolvedPaths(spec: Spec): void {
  const miss = (site: string): never => {
    throw new Error(
      `check-plan [unresolved-path]: ${site} has no resolved path after resolveSpec — ` +
      `a Path site not wired into resolvePaths (plan/resolve.ts), or a via in an unsupported ` +
      `position (nested in arithmetic — VIA_HARDENING §3)`,
    );
  };
  // String-step normalization is resolve-once's job (ir/refs.ts normalizePath, applied in place
  // by resolvePaths): downstream of resolveSpec, NO string step may survive on any raw path — a
  // survivor means a Path site was added without normalization wiring, the same bug class as a
  // missing stamp.
  const unnormalized = (p: Path | undefined, site: string): void => {
    if (p != null && p.some((s) => typeof s === "string")) {
      throw new Error(
        `check-plan [unnormalized-path]: ${site} still carries a bare-string step after resolveSpec — ` +
        `a Path site not wired into resolvePaths' in-place normalizePath (plan/resolve.ts)`,
      );
    }
  };
  const checkExpr = (e: Expr, site: string): void =>
    walk(e, (n) => {
      if ((n.kind === "bound-ref" || n.kind === "table-ref") && n.resolvedVia === undefined) miss(site);
      if (n.kind === "bound-ref" || n.kind === "table-ref") unnormalized(n.viaSpec, site);
      if (n.kind === "agg" && n.ref.resolvedVia === undefined) miss(site);
    });
  for (const node of spec.nodes.values()) {
    for (const c of node.children) {
      if (c.hostRow !== undefined || c.nest === null) continue;
      if (c.nest.resolved === undefined) miss(`nest(${c.node})`);
      unnormalized(c.nest.on, `nest(${c.node})`);
    }
  }
  for (const plot of spec.plots.values()) {
    if (plot.nest != null && plot.nest.resolved === undefined) miss(`nest(${plot.id})`);
    if (plot.nest != null) unnormalized(plot.nest.on, `nest(${plot.id})`);
    if (plot.frame !== undefined && plot.frame.resolved === undefined) miss(`frame(${plot.id})`);
    if (plot.frame !== undefined) unnormalized(plot.frame.on, `frame(${plot.id})`);
    for (const [ch, expr] of Object.entries(plot.channels)) checkExpr(expr, `via(${plot.id}.${ch})`);
  }
  for (const inst of spec.layouts.values()) {
    for (const [role, input] of Object.entries(inst.inputs ?? {})) {
      if (role === "marks") continue;
      if (input.on !== undefined && input.resolvedOn === undefined) miss(`layout(${inst.id}.${role})`);
      unnormalized(input.on, `layout(${inst.id}.${role})`);
    }
  }
}

/** Run the plan pass over a compiled set of OpSpecs.
 *  - For each relop: compose the output TypedSchema forward.
 *  - For each apply with a resolved algo that has inputSpaces: check satisfies.
 *  - After each affine: assert its own columns flipped.
 *  - At the render sink: assert no relative columns reach it (D-B1 consumption rule).
 *  Returns violations; under strict throws on the first. */
export function checkPlan(
  specs: readonly OpSpec[],
  spec: Spec,
  operators: { get(name: string): Operator; has(name: string): boolean },
): PlanCheckViolation[] {
  const violations: PlanCheckViolation[] = [];
  const fail = (v: PlanCheckViolation): void => {
    violations.push(v);
    if (dvlSettings.strict) throw new Error(`check-plan [${v.kind}]: ${v.message}`);
    console.warn(`check-plan [lax] [${v.kind}]: ${v.message}`);
  };

  // Step 7 — the floating-vs-aligned conflict (WULAYOUT §1.3), a per-plot check independent of the
  // op-graph schema walk below.
  for (const v of checkAlignmentConflicts(spec)) fail(v);

  // Track the TypedSchema per cell (marks cell → its current schema).
  const schemas = new Map<CellRef, TypedSchema>();

  for (const op of specs) {
    const p = op.payload as Record<string, unknown>;

    // Relop: compose outSpaces into the running schema.
    if (p.kind === "relop") {
      const rp = p as unknown as RelopPayload;
      const inputCell = op.reads[0] as CellRef | undefined;
      const inputSchema: TypedSchema = inputCell !== undefined ? (schemas.get(inputCell) ?? []) : [];
      const outCell = op.writes[0] as CellRef | undefined;
      if (outCell === undefined) continue;

      if (rp.source !== undefined) {
        // Source relop: output schema from outTypes + outSpaces (no input).
        const outputSchema: TypedSchema = Object.entries(rp.outTypes).map(([name, carrier]) =>
          attr(name, carrier, rp.outSpaces?.[name] ?? dataSpace),
        );
        schemas.set(outCell, outputSchema);
        continue;
      }

      // Derive/join relop: compose add columns onto input (composeAttrs replaces in-place on
      // name collision, which is exactly the replace-relop semantics).
      const addAttrs: TypedSchema = Object.entries(rp.outTypes).map(([name, carrier]) =>
        attr(name, carrier, rp.outSpaces?.[name] ?? dataSpace),
      );
      const result = composeAttrs(inputSchema, addAttrs);
      schemas.set(outCell, result);

      // An AFFINE is the relop whose outSpaces re-declare (via replace) previously-relative
      // columns as pixel — the typed question, never a tag match. The per-affine theorem is
      // local: THIS affine's own columns flipped (the x-affine legitimately leaves y-relative
      // columns for the y-affine; the terminal no-relative-survives assertion is the render
      // sink's, after the whole chain).
      if (rp.replace === true && rp.outSpaces !== undefined) {
        const flipped = Object.keys(rp.outSpaces).filter((name) => {
          const declared = rp.outSpaces![name];
          const before = inputSchema.find((a) => a.name === name);
          return declared.space === "pixel" && before?.type.space === "relative";
        });
        const stillRelative = flipped.filter((name) => result.find((a) => a.name === name)?.type.space === "relative");
        if (stillRelative.length > 0) {
          fail({
            opId: op.id,
            kind: "unplaced-after-affine",
            message: `${op.id}: affine's own column(s) still relative after placement: ${stillRelative.join(", ")}`,
          });
        }
      }
      continue;
    }

    // Apply/domain: propagate schema + check inputSpaces.
    if (p.kind === "apply" || p.kind === "domain") {
      const inputCell = op.reads[0] as CellRef | undefined;
      const inputSchema: TypedSchema = inputCell !== undefined ? (schemas.get(inputCell) ?? []) : [];
      const outCell = op.writes[0] as CellRef | undefined;

      // Check inputSpaces if the algo is resolved.
      const algoName = p.algoName as string | undefined;
      const algo = p.algo as Operator | undefined;
      const binding = p.binding as { inputs: Record<string, string>; outputs: string[] } | undefined;
      const resolved = algo ?? (algoName !== undefined ? operators.get(algoName) : undefined);
      if (resolved?.inputSpaces !== undefined && binding !== undefined) {
        const reqs = requirementsOf(resolved.inputSpaces, (role) => {
          const v = binding.inputs[role];
          return typeof v === "string" ? v : undefined;
        });
        const result = satisfies(inputSchema, reqs);
        if (!result.ok) {
          fail({
            opId: op.id,
            kind: "input-unsatisfied",
            message: `${op.id} (${algoName ?? "?"}): ${result.reason}`,
          });
        }
      }

      if (p.kind === "domain" && resolved?.domain !== undefined) {
        // W5: stamp domain-space on the fit cell(s). The fit's columns are domain-space
        // values "about" the bound input column. Shape maps: broadcast→envelope, keyed→categories.
        const domShape = resolved.domain.shape;
        const primaryRole = (resolved.inputs.marks ?? [])[0]?.name ?? "value";
        const over = binding !== undefined ? (binding.inputs[primaryRole] as string | undefined ?? "value") : "value";
        const spaceShape: DomainShape = domShape === "broadcast" ? "envelope" : "categories";
        const ds = domainSpace(over, spaceShape);
        const fitCols: TypedSchema = spaceShape === "envelope"
          ? [attr("lo", "double", ds), attr("hi", "double", ds)]
          : [attr("value", "unknown", ds), attr("idx", "int", ds), attr("n", "int", ds)];
        for (const wc of op.writes) schemas.set(wc, schemas.get(wc) ?? fitCols);
      } else if (outCell !== undefined && resolved?.outSpaces !== undefined) {
        // Propagate: apply produces passthrough + outSpaces columns.
        const spaces = resolved.outSpaces;
        const addAttrs: TypedSchema = Object.entries(spaces).map(([name, space]) => {
          const carrier = ("add" in resolved!.output)
            ? (resolved!.output.add.find((c: { name: string }) => c.name === name)?.type ?? "unknown")
            : "unknown";
          return attr(name, carrier, space as Space);
        });
        schemas.set(outCell, composeAttrs(inputSchema, addAttrs));
      } else if (outCell !== undefined) {
        // Unknown output shape: propagate input as-is.
        schemas.set(outCell, inputSchema);
      }
      continue;
    }

    // Marktable: output schema is unknown at plan time (the DB resolves it at runtime).
    // Start with empty — the first relop's outTypes/outSpaces will build it up.
    if (p.kind === "marktable") {
      const outCell = op.writes[0] as CellRef | undefined;
      if (outCell !== undefined) schemas.set(outCell, []);
      continue;
    }

    // Path-agg: output is opaque (aggregate) — just pass through what we know.
    if (p.kind === "path-agg") {
      const inputCell = op.reads[0] as CellRef | undefined;
      const outCell = op.writes[0] as CellRef | undefined;
      if (inputCell !== undefined && outCell !== undefined) {
        schemas.set(outCell, schemas.get(inputCell) ?? []);
      }
      continue;
    }
    // Via-agg (resolved multi-match borrow): passthrough + the attached channel columns — needed
    // so the schema chain survives to the render sink for the `needs` check below.
    if (p.kind === "via-agg") {
      const vp = p as unknown as { adds: Readonly<Record<string, unknown>>; outSpaces?: Readonly<Record<string, Space>> };
      const inputCell = op.reads[0] as CellRef | undefined;
      const outCell = op.writes[0] as CellRef | undefined;
      if (inputCell !== undefined && outCell !== undefined) {
        const addAttrs: TypedSchema = Object.keys(vp.adds).map((name) => attr(name, "unknown", vp.outSpaces?.[name] ?? dataSpace));
        schemas.set(outCell, composeAttrs(schemas.get(inputCell) ?? [], addAttrs));
      }
      continue;
    }

    // D-B1: the consumption rule at the render sink — a relative value reaching
    // the scene constructor is the canonical illegal consumption.
    if (p.kind === "render") {
      for (const r of op.reads) {
        const sch = schemas.get(r as CellRef);
        if (sch === undefined) continue;
        const rel = unplacedSpatial(sch);
        if (rel.length > 0) {
          fail({
            opId: op.id,
            kind: "illegal-consumption",
            message: `render consumes relative column(s) ${rel.map((a) => a.name).join(", ")} — un-affined placement reaching the scene sink`,
          });
        }
      }
      // The draw contract (triage §4): each plot's mark may declare `needs` — the columns its
      // draw reads (a string = required; an inner array = alternatives). The render payload
      // carries the plot↔marks-cell map, and here the FINAL schema is provably known, post every
      // lowering — compiler-minted columns (connect's pairs x1..y2, via borrows, solver fills)
      // count. Two principled exemptions:
      //  - a plot that HOSTS a child node may leave its box to the solver (extent holes never
      //    become marks columns);
      //  - origin-tagged adornments (axis/legend/strip marks) are framework-emitted over
      //    producer tables whose op kinds the schema walk doesn't all track — their draw inputs
      //    are correct by construction, and the check targets AUTHOR marks.
      const hostPlots = new Set<string>();
      for (const n of spec.nodes.values()) for (const c of n.children) hostPlots.add(c.hostPlot);
      const plotList = (p.plots as ReadonlyArray<{ plot: string; marks: CellRef }> | undefined) ?? [];
      for (const { plot: plotId, marks } of plotList) {
        const plot = spec.plots.get(plotId as Parameters<typeof spec.plots.get>[0]);
        const desc = plot?.resolvedMark;
        if (plot === undefined || desc?.needs === undefined || desc.draw === undefined) continue;
        if (plot.origin !== undefined) continue; // framework adornment
        if (hostPlots.has(plotId)) continue; // container host: box may be solver-owned
        const sch = schemas.get(marks);
        if (sch === undefined) continue; // untracked chain (hand-built plan) — nothing provable
        const names = new Set(sch.map((a) => a.name));
        for (const clause of desc.needs) {
          const alts = typeof clause === "string" ? [clause] : clause;
          if (alts.some((c) => names.has(c))) continue;
          fail({
            opId: op.id,
            kind: "draw-needs",
            message: `${desc.type} "${plotId}": draw needs ${alts.join(" or ")} — schema has ${[...names].filter((n) => !n.startsWith("dvl_")).join(", ") || "(no columns)"}`,
          });
        }
      }
      continue;
    }

    // Any other op (arrange, host-extent, etc.): skip schema propagation.
  }

  return violations;
}
