// uniform: `count` samples evenly spaced across the domain envelope [min, max] — t_i = i/(count−1),
// value = min + t·(max−min). The legend-ramp producer (AUTOLEGEND G2): the ramp's colour bands are
// uniform samples of the scale (count ~64), and its labels are the same algo at count 3 (min/mid/max),
// so bands and labels align by construction (both uniform in t). Contrast nice-linear, whose ticks are
// nice VALUES that neither cover the envelope nor space uniformly in t — right for axes, wrong for a
// pitch-placed ramp. This is the vtable's anticipated extension ("later a legend's swatches").
import type { Tick, TickAlgo } from "../../operator/ticks.js";
import { clean, fmt } from "./_shared.js";

export const uniform: TickAlgo = {
  name: "uniform",
  over: "domain",
  js({ params }, ctx) {
    const min = Number(params.min);
    const max = Number(params.max);
    if (!Number.isFinite(min) || !Number.isFinite(max) || min === max) return [{ idx: 0, value: clean(min), label: fmt(min) }];
    const n = Math.max(2, ctx.count);
    const out: Tick[] = [];
    for (let i = 0; i < n; i++) {
      const v = clean(min + (i / (n - 1)) * (max - min));
      out.push({ idx: i, value: v, label: fmt(v) });
    }
    return out;
  },
};
