// Built-in named via reducers (VIA_HARDENING §4.3): the SERIALIZABLE spelling of an opaque
// reduce — `resolve: { m: { js: 'mode' } }` names one of these instead of closing over an inline
// function. Inline functions stay the easy escape hatch; a NAME is what lets a spec round-trip
// to JSON (principle #8: the IR holds names, the runtime resolves through the registry).
//
// CONTRACT: (matches, mark, cols?) => value. `matches` = the mark's FULL f-side match rows (all
// referent attributes, hop columns flattened in); `cols` = the resolution's declared projection
// hint, defaulting to the borrowed column — how a column-generic reducer knows what to reduce.
// A registered reducer must not close over external state — it resolves by name on any client.
//
// SEED POLICY: only what the declarative vocabulary cannot express. Popular numeric aggregates
// (avg/sum/min/max/median/…) are AggFns (`fn`) and never leave SQL; aggregates over expressions
// are `fn`+`arg` (a ScalarExpr over the (m,f) row, compiled to BOTH substrates by algebra/lower);
// registering JS mirrors of those would invite authors onto the materializing path for nothing.
import type { Registries } from "../operator/registry.js";
import type { ViaReduceFn, ResolverSpec } from "../ir/refs.js";

type Rows = readonly Record<string, unknown>[];

const numsOf = (matches: Rows, col: string): number[] => {
  const out: number[] = [];
  for (const m of matches) {
    const v = m[col];
    if (v === null || v === undefined) continue;
    const n = Number(v);
    if (!Number.isNaN(n)) out.push(n);
  }
  return out;
};

const oneCol = (matches: Rows, cols: readonly string[] | undefined, name: string): string => {
  if (cols === undefined || cols.length !== 1) throw new Error(`reducer "${name}": needs exactly one column — declare it ({ js: '${name}', cols: ['col'] }) or pick a referent column`);
  void matches;
  return cols[0];
};

/** [lo, hi] per match: from a declared [loCol, hiCol] pair, or the min/max of one column. */
const extentsOf = (matches: Rows, cols: readonly string[] | undefined, name: string): [number, number][] => {
  if (cols !== undefined && cols.length === 2) {
    const out: [number, number][] = [];
    for (const m of matches) {
      const lo = Number(m[cols[0]]);
      const hi = Number(m[cols[1]]);
      if (!Number.isNaN(lo) && !Number.isNaN(hi)) out.push([lo, hi]);
    }
    return out;
  }
  const ns = numsOf(matches, oneCol(matches, cols, name));
  return ns.length === 0 ? [] : [[Math.min(...ns), Math.max(...ns)]];
};

// ── geometry reducers (design/2026-07-20-convexhull-resolver.html) ────────────────────────────
// A GEOMETRY reducer collapses a matched POINT set to ONE polygon: an array of [x,y] vertices in
// drawing order, closed by the hull mark. The points are the referent's PLACED (pixel) x/y — a via
// over a plot borrows solved positions — so the polygon is pixel-space, drawn as-is (no affine).
// JS-only by nature: a hull is not an AggFn, so it cannot leave SQL (SEED POLICY). SQL pushdown
// (ST_ConvexHull) is deferred — it needs the spatial extension + a geometry-aggregate emission
// path the closed AggFn lowering has no seam for (see the design doc's Deferred section).
type Pt = [number, number];

/** The [x,y] points of the matches, from the (xCol, yCol) hint (default the placed channels x/y). */
const pointsOf = (matches: Rows, cols: readonly string[] | undefined): Pt[] => {
  const xCol = cols !== undefined && cols.length === 2 ? cols[0] : "x";
  const yCol = cols !== undefined && cols.length === 2 ? cols[1] : "y";
  const out: Pt[] = [];
  for (const m of matches) {
    const x = Number(m[xCol]);
    const y = Number(m[yCol]);
    if (!Number.isNaN(x) && !Number.isNaN(y)) out.push([x, y]);
  }
  return out;
};

/** Andrew's monotone chain: sort by (x,y), build lower + upper hulls. O(n log n). Returns the
 *  hull vertices without the duplicated closing point (fewer than 3 unique points ⇒ as-is). */
const convexHull = (pts: Pt[]): Pt[] => {
  if (pts.length < 3) return pts;
  const p = [...pts].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
  const cross = (o: Pt, a: Pt, b: Pt): number => (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0]);
  const half = (src: Pt[]): Pt[] => {
    const h: Pt[] = [];
    for (const q of src) {
      while (h.length >= 2 && cross(h[h.length - 2], h[h.length - 1], q) <= 0) h.pop();
      h.push(q);
    }
    h.pop(); // drop the last (it starts the other half)
    return h;
  };
  return [...half(p), ...half([...p].reverse())];
};

export const builtinReducers: Record<string, ViaReduceFn> = {
  /** The most frequent value (ties: first seen). Not one SQL reduce. */
  mode: (matches, _mark, cols) => {
    const col = oneCol(matches, cols, "mode");
    const counts = new Map<unknown, number>();
    let best: unknown = null;
    let bestN = 0;
    for (const m of matches) {
      const v = m[col];
      if (v === null || v === undefined) continue;
      const n = (counts.get(v) ?? 0) + 1;
      counts.set(v, n);
      if (n > bestN) { best = v; bestN = n; }
    }
    return best;
  },
  /** max − min of the matched values. */
  range: (matches, _mark, cols) => {
    const ns = numsOf(matches, oneCol(matches, cols, "range"));
    return ns.length === 0 ? null : Math.max(...ns) - Math.min(...ns);
  },
  /** The union (bounding interval) of the matched extents → [lo, hi].
   *  cols: [loCol, hiCol] treats each match as an interval; one column takes its min/max. */
  extentUnion: (matches, _mark, cols) => {
    const es = extentsOf(matches, cols, "extentUnion");
    return es.length === 0 ? null : [Math.min(...es.map((e) => e[0])), Math.max(...es.map((e) => e[1]))];
  },
  /** The intersection of the matched extents → [lo, hi], or null when disjoint. */
  extentIntersect: (matches, _mark, cols) => {
    const es = extentsOf(matches, cols, "extentIntersect");
    if (es.length === 0) return null;
    const lo = Math.max(...es.map((e) => e[0]));
    const hi = Math.min(...es.map((e) => e[1]));
    return lo <= hi ? [lo, hi] : null;
  },
  /** The CONVEX HULL of the matched points → polygon vertices [[x,y], …]; null for < 1 point.
   *  cols: [xCol, yCol] (default the placed channels 'x','y'). Collinear/degenerate sets return
   *  their ≤2 points as-is (the hull mark draws a segment/point, never a bogus triangle). */
  convex: (matches, _mark, cols) => {
    const pts = pointsOf(matches, cols);
    return pts.length === 0 ? null : convexHull(pts);
  },
  /** The axis-aligned BOUNDING BOX of the matched points → 4 corners CCW; null for no points.
   *  cols: [xCol, yCol] (default 'x','y'). Needs no hull math — min/max on each axis. */
  bbox: (matches, _mark, cols) => {
    const pts = pointsOf(matches, cols);
    if (pts.length === 0) return null;
    const xs = pts.map((p) => p[0]);
    const ys = pts.map((p) => p[1]);
    const [x0, x1] = [Math.min(...xs), Math.max(...xs)];
    const [y0, y1] = [Math.min(...ys), Math.max(...ys)];
    return [[x0, y0], [x1, y0], [x1, y1], [x0, y1]];
  },
};

/** The registered RESOLVER descriptors: the JS reduce + authoring defaults + (convex) a SQL impl.
 *  Scalar reducers are bare `{ js }`; geometry resolvers carry `defaultOutput`/`defaultCols` (so the
 *  bare-string form `resolve: "convex"` has a name to mint and needs no `cols`). `convex` also
 *  carries a SQL implementation (DuckDB spatial `ST_ConvexHull`, emitting WKT) preferred for the
 *  bare form — push-down; the explicit `{ js: "convex" }` form opts back into the JS reduce. */
export const builtinResolvers: Record<string, ResolverSpec> = {
  mode: { js: builtinReducers.mode },
  range: { js: builtinReducers.range },
  extentUnion: { js: builtinReducers.extentUnion },
  extentIntersect: { js: builtinReducers.extentIntersect },
  convex: {
    js: builtinReducers.convex,
    defaultOutput: "path",
    defaultCols: ["x", "y"],
    // per-group WKT hull over the placed points; xCol/yCol arrive already alias-qualified (f."x").
    sql: (xCol, yCol) => `ST_AsText(ST_ConvexHull(ST_Collect(LIST(ST_Point(${xCol}, ${yCol})))))`,
    requires: ["spatial"],
  },
  bbox: { js: builtinReducers.bbox, defaultOutput: "path", defaultCols: ["x", "y"] },
};

export function registerReducers(r: Registries): void {
  for (const [name, spec] of Object.entries(builtinResolvers)) r.reducers.register(name, spec);
}
