// apply op: augment marks via the resolved Operator (§12 Phase 5: the old runApply fallback and
// the DVL_STRICT_EXEC guard are gone with optimizer/planner.ts — payload.algo is REQUIRED and IS
// the Exec: `sql`/`js` are the apply impls, spread directly on the operator).
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { ApplyPayload } from "../../../plan/payloads.js";
import { sqlRel, valuesFrag, type Relation } from "../../../algebra/relation.js";
import { chooseImpl, dispatch } from "../../../executor/dispatch.js";
export async function apply(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as ApplyPayload;
  if (p.kind !== "apply") return;
  const fit = p.fit !== undefined ? (store.read(p.fit) as Relation) : null;
  // resolve-once: the plan carries the RESOLVED operator (stamped by the compiler / embedded by
  // apply-only) — the executor never does a by-name lookup.
  const algo = p.algo;
  if (algo === undefined) throw new Error(`apply: payload for "${p.algoName}" carries no resolved operator — emit through the compiler (stampAlgo) or embed one`);
  const marks = store.read(op.reads[0]) as Relation;
  // The operator IS its Exec. OBEY the optimizer's static decision when stamped (§12 4c);
  // adaptive only on unplanned runs.
  const impl = p.substrate !== undefined ? algo[p.substrate]! : chooseImpl(algo, marks.substrate);
  const inputs = fit !== null ? [marks, fit] : [marks];
  // per-EDGE keyedness from the plan (only the compiler knows which reads are keyed); absent →
  // dispatch's iterate path refuses multi-input guessing (exec.ts).
  const keyedInputs = p.keyedReads !== undefined ? inputs.map((_, i) => p.keyedReads!.includes(i)) : undefined;
  let out = await dispatch(impl, inputs, p.binding, { run: ctx.run, key: p.by, keyedInputs });
  // UNPLANNED-path cross-back (§12 4c P4): when the optimizer stamped this op, crossings are
  // PLANNED in the graph (an explicit inject op) — never cross here. Without a stamp (direct
  // compileSpec→schedule runs — the optimizer-off reference path the equivalence suite needs),
  // preserve the legacy adaptive behavior.
  if (p.substrate === undefined && marks.substrate === "sql" && out.substrate === "js") out = sqlRel(valuesFrag(`${p.binding.key}:jsout`, out.rows, out.schema));
  store.write(op.writes[0], out, "assigned");
}
