// Force-directed layout as a single recursive DuckDB SQL query (P-total).
// Uses WITH RECURSIVE ... USING KEY(node) + recurring.* for an iterative
// attraction/repulsion/gravity simulation, then min-max normalizes to [pad, 1-pad].
import type { OpBinding } from "../../algebra/impl.js";
import { inputCol } from "../../algebra/impl.js";
import type { ExecCtx } from "../../algebra/impl.js";
import { sanitizeOp } from "../../algebra/relation.js";
import type { SqlFragment } from "../../data/fragment.js";

export function forceSql(inputs: readonly SqlFragment[], b: OpBinding, _ctx: ExecCtx): SqlFragment {
  const marks = inputs[0];
  const [xo, yo] = b.outputs;
  const idCol = inputCol(b, "value");
  const edgesTable = b.inputs.edges as string;
  // endpoint columns from the binding's RESOLVED refs (§8 Stage 1b) — same contract as the JS
  // impl; the fallback mirrors the operator's declaration for hand-built bindings.
  const refPairs = b.refs?.edges ?? [{ from: "src", to: "id" }, { from: "dst", to: "id" }];
  if (refPairs.length < 2) throw new Error(`force-sql "${b.key}": needs two edge endpoint refs (got ${refPairs.length})`);
  const [srcCol, dstCol] = [refPairs[0].from, refPairs[1].from];
  const key = `${b.key}:force-sql`;
  const op = sanitizeOp(key);

  const iterations = 80;
  const attraction = 0.08;
  const repulsion = 0.12;
  const gravity = 0.02;
  const temperature = 0.15;
  const pad = 0.05;
  const scale = 1 - 2 * pad;

  // All local CTE names are @-prefixed so the fold rewrites them on uniquification.
  // Self-references in the recursive body also use @ so they stay correct after fold.

  // edges is a DECLARED base input (@edges) — never a raw quoted table in the body, so the
  // runner registers it and fold resolves its schema, exactly like a marktable's source.
  // No edges relation ⇒ pure repulsion (the JS impl's contract): an empty undirected set.
  const hasEdges = typeof edgesTable === "string";
  const undirectedBody = hasEdges
    ? `SELECT "${srcCol}" AS src, "${dstCol}" AS dst FROM @edges UNION SELECT "${dstCol}", "${srcCol}" FROM @edges`
    : `SELECT NULL AS src, NULL AS dst WHERE FALSE`;

  const seedBody = `SELECT m."${idCol}" AS node,
    cos(2 * 3.141592653589793 * (row_number() OVER (ORDER BY m."${idCol}") - 1)
      / greatest(count(*) OVER (), 1))::DOUBLE AS x,
    sin(2 * 3.141592653589793 * (row_number() OVER (ORDER BY m."${idCol}") - 1)
      / greatest(count(*) OVER (), 1))::DOUBLE AS y
    FROM @marks AS m`;

  // The recursive body references itself as @fl and the keyed state as recurring.@fl.
  // After fold rewriting, both become the same uniquified CTE name.
  const forceBody = `SELECT 0, node, x, y FROM @seed
    UNION
    SELECT iter + 1, node,
      x + CASE WHEN force_norm = 0 THEN 0 ELSE fx / force_norm * least(force_norm, temp) END,
      y + CASE WHEN force_norm = 0 THEN 0 ELSE fy / force_norm * least(force_norm, temp) END
    FROM (
      SELECT p.iter, p.node, p.x, p.y,
        sum(${repulsion} * (p.x - q.x)
          / ((p.x - q.x)*(p.x - q.x) + (p.y - q.y)*(p.y - q.y) + 1e-6)
          + CASE WHEN e.src IS NOT NULL THEN ${attraction} * (q.x - p.x) ELSE 0 END
        ) - ${gravity} * p.x AS fx,
        sum(${repulsion} * (p.y - q.y)
          / ((p.x - q.x)*(p.x - q.x) + (p.y - q.y)*(p.y - q.y) + 1e-6)
          + CASE WHEN e.src IS NOT NULL THEN ${attraction} * (q.y - p.y) ELSE 0 END
        ) - ${gravity} * p.y AS fy,
        greatest(0.005, ${temperature} * (1.0 - p.iter::DOUBLE / ${iterations})) AS temp
      FROM @fl AS p
      CROSS JOIN recurring.@fl AS q
      LEFT JOIN @undirected_edges AS e ON e.src = p.node AND e.dst = q.node
      WHERE p.iter < ${iterations} AND p.node <> q.node
      GROUP BY p.iter, p.node, p.x, p.y
    ) AS frc
    CROSS JOIN LATERAL (SELECT sqrt(fx*fx + fy*fy) AS force_norm) AS mag`;

  const normBody = `SELECT m.*, norm.nx AS "${xo}", norm.ny AS "${yo}"
    FROM (
      SELECT node,
        CASE WHEN (mx - mn_x) = 0 THEN 0.5 ELSE ${pad} + ${scale} * ((x - mn_x) / (mx - mn_x)) END AS nx,
        CASE WHEN (my - mn_y) = 0 THEN 0.5 ELSE ${pad} + ${scale} * ((y - mn_y) / (my - mn_y)) END AS ny
      FROM (
        SELECT node, x, y,
          min(x) OVER () AS mn_x, max(x) OVER () AS mx,
          min(y) OVER () AS mn_y, max(y) OVER () AS my
        FROM @fl
      )
    ) AS norm
    JOIN @marks AS m ON m."${idCol}" = norm.node`;

  return {
    id: key,
    op,
    ctes: [
      { name: "undirected_edges", body: undirectedBody },
      { name: "seed", body: seedBody },
      { name: "fl", body: forceBody, recursive: true, columns: ["iter", "node", "x", "y"], usingKey: ["node"] },
      { name: "r", body: normBody },
    ],
    result: "r",
    inputs: hasEdges ? { marks: { fragment: marks }, edges: { base: edgesTable } } : { marks: { fragment: marks } },
    outputs: { passthrough: "marks", add: [{ name: xo, type: "double" }, { name: yo, type: "double" }] },
    cells: [],
  };
}
