// The apply-only wrapper scale (WUAXIS §apply-only). A CONSUMER that binds a WRAPPED scale to APPLY,
// reusing its already-trained domain — with NO train. Its `plan()` emits exactly one op, the apply,
// referencing the wrapped scale (by name, from `binding.options.wrapped`) and reading the SHARED domain
// from `holes.domain` (a cell it reads, never re-trains). So a tick mark can bind `apply-only(x)` exactly
// as a data mark binds `x`, and be placed by the frame scale WITHOUT training it: "don't train on V" is
// structural (no train branch), not a removal. It's a plan-time transform — the emitted op references the
// wrapped scale directly, so the wrapper has no run-time presence (§12 Phase 5: PLAN-ONLY — its own
// Exec side is empty; resolveSpec validates the wrapped reference is impl-bearing, S5).
import { op, type Operator } from "../../operator/operator.js";
import type { OpBinding } from "../../algebra/impl.js";
import type { PlanIO } from "../../operator/binding.js";
import type { OpSpec } from "../../plan/opspec.js";

/** Carry the wrapped scale on a binding for `apply-only` (the shared domain rides `holes.domain`). */
export function applyOnlyBinding(key: string, wrapped: string, outputs: readonly string[]): OpBinding {
  return { key, inputs: { value: "value" }, outputs, options: { wrapped } };
}

/** The `apply-only` operator — a channel binds an apply-only INSTANCE via `layoutOutput`, so it
 *  needs the declarative surface like any scale. It owns NO holes (it reuses the wrapped scale's
 *  domain) and declares no outKind (the coord axis/mode comes from the binding channel). */
export const applyOnly: Operator = op({
  name: "apply-only",
  outSpaces: { value: "binding" }, // the wrapped scale\'s space, per binding channel (§12.2)
  inputs: { marks: [{ name: "value", type: "double" }] },
  output: { passthrough: "marks", add: [{ name: "value", type: "double" }] },
  plan: (io: PlanIO): OpSpec[] => {
    const wrapped = io.binding.options?.wrapped as string | undefined;
    const domain = io.holes.domain; // the wrapped scale's domain cell, SHARED onto this instance
    if (wrapped === undefined || domain === undefined) throw new Error("apply-only: needs binding.options.wrapped + holes.domain");
    if (io.marksIn === undefined) throw new Error("apply-only: applies over input marks (PlanIO.marksIn)");
    // A multi-output wrapped scale (col: y,h; eqx: x,w) destructures b.outputs — pad the binding to the
    // wrapped ARITY: outputs[0] stays the bound channel (the coord); the extras are carried, unused.
    const arity = io.binding.options?.wrappedOutputs as readonly string[] | undefined;
    const outputs = arity !== undefined && arity.length > io.binding.outputs.length ? [...io.binding.outputs, ...arity.slice(io.binding.outputs.length)] : io.binding.outputs;
    const binding = { ...io.binding, outputs };
    // ONE apply op, referencing the wrapped scale + reusing its domain as the fit. No train, no hole.
    // §C8: a per-cell wrapped scale's domain is a KEYED table — thread the key so the apply JOINS
    // the fit on it (broadcasting a multi-row fit would cross every panel's ticks with every domain).
    // §C8 per-EDGE keyedness: the per-cell wrapped scale's domain is a KEYED table — both edges
    // partition when the executor iterates a non-keyed impl (exec.ts iteratePerGroup).
    const wrappedAlgo = io.binding.options?.wrappedAlgo; // resolved (and impl-validated) by resolveSpec (resolve-once)
    if (wrappedAlgo === undefined) throw new Error(`apply-only: wrapped scale "${wrapped}" is unresolved — call resolveSpec(spec, registries) after the lowerings`);
    return [{ id: `${io.id}:apply`, reads: [io.marksIn, domain], writes: [io.marksOut], payload: { kind: "apply", algoName: wrapped, algo: wrappedAlgo, binding, fit: domain, by: io.key, ...(io.key !== undefined ? { keyedReads: [0, 1] } : {}) } }];
  },
});
