// DomainTreatment execution (triage §5a). The domain CELL — the slot both the scale's apply and
// the axis's tick generator read — is written at exactly TWO places, and applyTreatment acts at
// both: the unshared train (ops/domain.ts, via the apply-only emission shape) and the shared
// union (dataflow/gather-scatter.ts). One pure, substrate-free function; same result whether the
// envelope came from SQL or JS.
//
//   explicit [lo, hi] — REPLACE the fitted envelope (an override, not a union member).
//   zero              — lo = min(lo, 0), the barY anchor generalized. No-op on categories.
//   data / nice / unbounded / undefined — identity. NICE STAYS IN THE TICK ALGO: treating it
//                       here would nice twice.
//
// Keyed (per-cell) domains carry their key columns beside lo/hi — the transform maps per row,
// so every cell's envelope is treated identically.
import type { DomainTreatment } from "../ir/layout.js";
import type { Row, Schema } from "../data/schema.js";
import { jsRel, type Relation } from "../algebra/relation.js";
/** Is this treatment one that CHANGES the domain (vs the passive defaults)? Active treatments
 *  also decide the emission shape: the apply must consume the treated cell (operator.ts). */
export const isActiveTreatment = (t: DomainTreatment | undefined): boolean =>
  t === "zero" || (typeof t === "object" && t !== null && "explicit" in t);

export function applyTreatment(domain: { rows: readonly Row[]; schema: Schema }, treatment: DomainTreatment | undefined): Relation {
  if (!isActiveTreatment(treatment)) return jsRel([...domain.rows], domain.schema);
  const hasEnvelope = domain.schema.some((c) => c.name === "lo") && domain.schema.some((c) => c.name === "hi");
  if (typeof treatment === "object" && "explicit" in treatment) {
    const [lo, hi] = treatment.explicit;
    if (!hasEnvelope) throw new Error(`domain treatment: explicit [${lo}, ${hi}] needs a numeric (lo/hi) domain — this scale's domain is categorical`);
    // no data rows (an empty relation still has an envelope under explicit) → synthesize one
    if (domain.rows.length === 0) return jsRel([{ lo, hi }], domain.schema);
    return jsRel(domain.rows.map((r) => ({ ...r, lo, hi })), domain.schema);
  }
  // zero: extend the low edge to the baseline; categories are untouched (a set has no baseline)
  if (!hasEnvelope) return jsRel([...domain.rows], domain.schema);
  return jsRel(domain.rows.map((r) => ({ ...r, lo: Math.min(Number(r.lo), 0) })), domain.schema);
}
