// Fuse consecutive relop augment ops into a single relop.
// Reduces intermediate relation copies when a pipeline adds several derived columns — the merged
// op adds them all in one pass through the shared lowering. (Was: literal/local-column →
// multi-augment; since the S4 collapse, every trivial derive is a `relop`, so fusion just unions
// the `add`/`outTypes` maps of a single-consumer chain.)
import type { OptRule, RuleCtx, RuleMatch } from "../rule.js";
import type { OpSpec } from "../../plan/opspec.js";
import type { Space } from "../../types/attr.js";
import type { RelopPayload } from "../../plan/payloads.js";
import type { ScalarExpr } from "../../algebra/relop.js";
import type { SqlType } from "../../data/schema.js";

/** Only the plain broadcast augment fuses. A source relop (values/unit) is a constant LEAF (no
 *  input relation; its `source` would be lost by the add-map union). A join-derive reads a second
 *  input, and a replace-derive overwrites columns — both change the fragment shape, so unioning
 *  their add maps into a neighbor would silently drop the join/overwrite. */
function fusible(op: OpSpec): boolean {
  if (op.payload.kind !== "relop") return false;
  const p = op.payload as { source?: unknown; join?: unknown; replace?: boolean };
  return p.source === undefined && p.join === undefined && p.replace !== true;
}
/** Mark-side columns an add expression READS (the m."col" references, including a window's
 *  partition/order/value columns). Fusion must not put a reader and its producer in one SELECT. */
function markColsOf(e: ScalarExpr): string[] {
  switch (e.k) {
    case "col": return e.src === "marks" ? [e.name] : [];
    case "rank": return [e.col];
    case "wsum": return [e.col, ...(e.partition !== undefined ? [e.partition] : []), ...(e.order !== undefined ? [e.order] : [])];
    case "lead": return [e.col, e.order, ...(e.partition !== undefined ? [e.partition] : [])];
    case "bin": return [...markColsOf(e.l), ...markColsOf(e.r)];
    case "nullif0": case "unary": case "round": return markColsOf(e.x);
    case "left": return [...markColsOf(e.str), ...markColsOf(e.n)];
    case "index": return markColsOf(e.idx);
    case "concat": return e.parts.flatMap(markColsOf);
    case "call": return e.args.flatMap(markColsOf);
    default: return []; // lit/rand/rownum/cell — no mark columns
  }
}

export const fuseLiterals: OptRule = {
  name: "fuse-literals",

  match(op: OpSpec, ctx: RuleCtx): RuleMatch | null {
    if (!fusible(op)) return null;
    // Only fuse the START of a chain (predecessor is not a fusible augment relop)
    const pred = ctx.graph.producer(op.reads[0]);
    if (pred && fusible(pred)) return null;

    // Walk forward: collect chain of relops with single-consumer edges. DEPENDENCY BREAK
    // (correctness): an op whose add exprs READ a column minted earlier in the chain cannot
    // share its producer's SELECT level (SQL cannot reference a same-level alias — the
    // connect literal-stroke bug: LEAD(...) OVER (PARTITION BY m."stroke") fused with
    // '…' AS "stroke"). The chain stops BEFORE the reader; it may anchor its own chain.
    const chain: OpSpec[] = [op];
    const minted = new Set(Object.keys((op.payload as unknown as RelopPayload).add));
    let cur = op;
    while (true) {
      const consumers = ctx.graph.consumers(cur.writes[0]);
      if (consumers.length !== 1) break;
      const next = consumers[0];
      if (!fusible(next)) break;
      const np = next.payload as unknown as RelopPayload;
      if (Object.values(np.add).some((e) => markColsOf(e).some((c) => minted.has(c)))) break;
      for (const c of Object.keys(np.add)) minted.add(c);
      chain.push(next);
      cur = next;
    }
    if (chain.length < 2) return null;
    return { anchor: chain[0], matched: chain };
  },

  apply(m: RuleMatch, ctx: RuleCtx): void {
    const chain = m.matched!;
    const first = chain[0];
    const last = chain[chain.length - 1];

    // Union every op's added columns into one relop (chain order = column order).
    const add: Record<string, ScalarExpr> = {};
    const outTypes: Record<string, SqlType> = {};
    const outSpaces: Record<string, Space> = {};
    for (const op of chain) {
      const p = op.payload as unknown as RelopPayload;
      Object.assign(add, p.add);
      Object.assign(outTypes, p.outTypes);
      Object.assign(outSpaces, p.outSpaces ?? {});
    }
    const fusedPayload: RelopPayload = { kind: "relop", key: (first.payload as unknown as RelopPayload).key, add, outTypes, outSpaces, tag: "fused" };

    const fused: OpSpec = {
      id: `${first.id}:fused`,
      reads: first.reads,
      writes: last.writes,
      payload: fusedPayload as unknown as OpSpec["payload"],
    };

    // Copy cell format from last op's output to the fused op's output
    const lastFmt = ctx.cellFormat(last.writes[0]);
    if (lastFmt) ctx.setCellFormat(fused.writes[0], lastFmt);

    ctx.graph.splice(first, chain.length, fused);
  },
};
