// Demand-weighted panel allocation: each panel gets its demand plus an equal share of surplus.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";

export function allocate(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload;
  if (p.kind !== "allocate") return;
  const nB = op.writes.length / 2;
  const N = nB + 1;
  const d = op.reads.slice(0, N).map((r) => Number(store.read(r)));
  const lo = Number(store.read(op.reads[N]));
  const hi = Number(store.read(op.reads[N + 1]));
  const W = hi - lo;
  const total = d.reduce((s, x) => s + x, 0);
  const widths = W > 0 && total > W ? d.map((x) => (x * W) / total) : d.map((x) => x + (W - total) / N);
  let cum = 0;
  for (let k = 0; k < nB; k++) {
    cum += widths[k];
    const f = W > 0 ? cum / W : (k + 1) / N;
    store.write(op.writes[2 * k], -(1 - f), "assigned");
    store.write(op.writes[2 * k + 1], -f, "assigned");
  }
}
