// The dataflow scheduler (C5). Operators read/write cells; the scheduler condenses the
// dependency graph into SCCs (Tarjan) and runs them two-level: an outer pass over the
// SCC-DAG in topological order, and for a cyclic SCC an inner fixpoint that re-runs its
// members until the scalar-cell residual ≤ ε, then seals. Substrate-agnostic — an
// operator's run() populates its write-cells via whatever impl the optimizer chose.
// See design/WUSCHED_IMPL.md.
import type { CellKind, CellRef, CellStore } from "../ir/cell.js";
import type { OperatorId } from "../data/ids.js";

export interface Runnable {
  readonly id: OperatorId;
  readonly reads: readonly CellRef[];
  readonly writes: readonly CellRef[];
  /** Populate `writes` (write status "assigned"); the scheduler seals. Async ok (SQL). */
  run(store: CellStore): void | Promise<void>;
}

import type { Controller } from "../ir/controller.js";

export interface ScheduleOpts {
  maxIters?: number; // inner-fixpoint cap (default 100)
  epsilon?: number; // residual convergence threshold in PIXELS (default 0.1 — below one device px,
  // and above the ~1e-6 reproducibility floor of DOM text measurement that drives the frame loop)
  strict?: boolean; // throw on non-convergence (default true); else warn + keep last "assigned"
  onWarn?: (msg: string) => void;
  controllers?: Controller[]; // post-sweep decision-makers for adjustable cells in cyclic SCCs
}

/** Run the operator graph to a fixpoint, sealing cells as their SCC converges. */
export async function schedule(
  ops: readonly Runnable[],
  store: CellStore,
  opts: ScheduleOpts = {},
): Promise<void> {
  const { maxIters = 100, epsilon = 0.1, strict = true, onWarn } = opts;

  // run an op, then stamp provenance on the cells it wrote
  const runOp = async (o: Runnable): Promise<void> => {
    await o.run(store);
    for (const w of o.writes) store.get(w).producer = o.id;
  };

  // Outer loop: SCCs in topological order (condense emits producers-first). ponytail: serial
  // for now — independent SCCs (antichains of the SCC-DAG) could run in parallel here once
  // scheduling cost matters; that's the only parallelism wanted, never within an SCC.
  for (const scc of condense(ops)) {
    // cyclic = a multi-op cycle, or a single op that reads a cell it writes (self-fixpoint)
    const cyclic = scc.length > 1 || scc[0].reads.some((r) => scc[0].writes.includes(r));

    if (!cyclic) {
      await runOp(scc[0]);
      for (const w of scc[0].writes) store.seal(w);
      continue;
    }

    const writes = scc.flatMap((o) => [...o.writes]);
    const ordered = seedOrder(store, scc); // seeds must CUT the cycle; the cut order = the first sweep

    // Inner fixpoint: members run SEQUENTIALLY — Gauss-Seidel, each reading values written
    // earlier this iteration (the seed-cut topological order, so iteration 1 reads only seeds or
    // already-written cells). Converges faster than Jacobi and stays deterministic; the fixed
    // point is order-independent, only the path differs. Consistency over within-SCC parallelism.
    // controllers whose cells overlap this SCC (run after ops each sweep)
    const sccCells = new Set(writes);
    const sccControllers = (opts.controllers ?? []).filter((c) => c.controls.some((cell) => sccCells.has(cell)));

    // Inner fixpoint with two stop conditions: (1) combined residual ≤ epsilon → a true fixpoint
    // within tolerance (seal, silent); (2) the residual sequence CONVERGES above tolerance — no
    // progress for STALL consecutive sweeps → a plateau or limit cycle; stop and report rather than
    // burn all maxIters. PROGRESS = a relation still changing (binary, resets the stall — it is
    // advancing toward its fixpoint) OR the scalar residual improving past its best-so-far by a
    // hair (IMPROVE ≪ epsilon, so a slow-but-genuine descent is never mistaken for a plateau).
    const STALL = 6, IMPROVE = 1e-9;
    let converged = false, plateaued = false;
    let bestScalar = Infinity, stall = 0, last = 0;
    for (let it = 0; it < maxIters; it++) {
      const snap = snapshotScalars(store, writes);
      for (const o of ordered) await runOp(o);
      for (const ctrl of sccControllers) ctrl.step({ store, iteration: it, violations: [] });
      const r = residual(store, writes, snap);
      last = r.max;
      if (r.max <= epsilon) { converged = true; break; }
      if (r.relChanged || r.scalar < bestScalar - IMPROVE) { if (r.scalar < bestScalar) bestScalar = r.scalar; stall = 0; }
      else if (++stall >= STALL) { plateaued = true; break; }
    }
    if (!converged) {
      const why = plateaued
        ? `residual converged to ${last.toFixed(3)}px (a plateau/limit cycle above the ${epsilon}px tolerance)`
        : `did not converge in ${maxIters} iterations (residual ${last.toFixed(3)}px, tolerance ${epsilon}px)`;
      const msg = `dataflow SCC {${scc.map((o) => o.id).join(", ")}}: ${why}`;
      if (strict) throw new Error(msg);
      onWarn?.(msg); // non-strict: cells stay "assigned" (never sealed) — a best-effort render
      continue;
    }
    for (const w of writes) store.seal(w);
  }
}

// ── residual over the SCC's cells (L∞ of per-iteration deltas) ────────────────
// TABLE-AWARE (§C8 7b prerequisite): scalar cells compare numerically; RELATION cells compare by a
// cheap structural FINGERPRINT (JSON of the value — a SqlFragment tree or a JsRel's rows are both
// plain data). A changed relation contributes 1 to the residual, so an SCC whose only moving state
// lives in table rows (per-cell chrome: a keyed V, demand columns) still iterates to a real
// fixpoint instead of "converging" on whatever the first sweep produced.
const SCALAR: CellKind = "scalar";

function snapshotScalars(store: CellStore, cells: readonly CellRef[]): Map<CellRef, number | string> {
  const m = new Map<CellRef, number | string>();
  for (const c of cells) {
    const cell = store.get(c);
    if (cell.kind === SCALAR) {
      if (typeof cell.value === "number") m.set(c, cell.value);
    } else if (cell.value !== undefined) {
      m.set(c, JSON.stringify(cell.value));
    }
  }
  return m;
}

/** The SCC residual, split so the fixpoint loop can tell PROGRESS from a PLATEAU:
 *  - `scalar`  = L∞ of per-sweep scalar deltas (a continuous magnitude — this is what "improves");
 *  - `relChanged` = did ANY relation cell's fingerprint change this sweep (a binary — a changing
 *    relation is still progressing toward its fixpoint, so it must RESET the stall, not trip it);
 *  - `max`     = the combined residual vs. the convergence tolerance (relation change counts as 1). */
function residual(store: CellStore, cells: readonly CellRef[], snap: Map<CellRef, number | string>): { max: number; scalar: number; relChanged: boolean } {
  let scalar = 0;
  let relChanged = false;
  for (const c of cells) {
    const cell = store.get(c);
    if (cell.kind === SCALAR) {
      if (typeof cell.value !== "number") continue;
      const prev = snap.get(c);
      const d = typeof prev !== "number" ? Math.abs(cell.value) : Math.abs(cell.value - prev);
      if (d > scalar) scalar = d;
    } else if (cell.value !== undefined) {
      const prev = snap.get(c);
      if (prev !== JSON.stringify(cell.value)) relChanged = true; // a changed relation = not converged
    }
  }
  return { max: Math.max(scalar, relChanged ? 1 : 0), scalar, relChanged };
}

// The seeds must CUT the cycle (WULAYOUT_IMPL §C6): drop dependency edges that flow through a
// currently-READABLE cell (a seed — estimated default, or already assigned); if the SCC is acyclic
// without them, that topological order is the first Gauss-Seidel sweep — every op reads only seeds
// or cells written earlier in the same iteration, so no read yields undefined/NaN. If a cycle
// survives the cut, it is genuinely unseeded: fail loudly (the old `requireSeeds` behavior).
function seedOrder(store: CellStore, scc: readonly Runnable[]): Runnable[] {
  const producerOf = new Map<CellRef, Runnable>();
  for (const o of scc) for (const w of o.writes) producerOf.set(w, o);
  // dependency edges o → producer, EXCLUDING reads satisfiable by a seed (readable now)
  const deps = new Map<Runnable, Runnable[]>();
  const unseeded = new Map<Runnable, CellRef[]>();
  for (const o of scc) {
    const ds: Runnable[] = [];
    for (const r of o.reads) {
      const p = producerOf.get(r);
      if (p === undefined || store.read(r) !== undefined) continue; // external, or seeded — no ordering need
      if (p === o) throw new Error(`cyclic cell ${r} has no seed value; bootstrap it (alloc with a default) before scheduling`);
      ds.push(p);
      unseeded.set(o, [...(unseeded.get(o) ?? []), r]);
    }
    deps.set(o, ds);
  }
  // Kahn topo over the cut graph — producers first; a leftover means the cut failed (unseeded cycle).
  const ordered: Runnable[] = [];
  const done = new Set<Runnable>();
  while (ordered.length < scc.length) {
    const ready = scc.find((o) => !done.has(o) && deps.get(o)!.every((d) => done.has(d)));
    if (ready === undefined) {
      const cells = scc.filter((o) => !done.has(o)).flatMap((o) => unseeded.get(o) ?? []);
      throw new Error(`cyclic cell${cells.length === 1 ? "" : "s"} ${cells.join(", ")} ha${cells.length === 1 ? "s" : "ve"} no seed value; bootstrap ${cells.length === 1 ? "it" : "one"} (alloc with a default) before scheduling`);
    }
    done.add(ready);
    ordered.push(ready);
  }
  return ordered;
}

// ── Tarjan SCC condensation ──────────────────────────────────────────────────
// Edges go reader → producer (an op depends on whoever writes the cells it reads), so
// Tarjan emits SCCs in dependency-first (topological) order — exactly the outer-loop order.
// Self-edges are dropped: a self-loop doesn't change SCC membership (the op is already its
// own component). A single-op self-fixpoint is still detected — by the reads∩writes check
// in schedule() — and driven by the inner fixpoint, exactly like a multi-op cycle.
function condense(ops: readonly Runnable[]): Runnable[][] {
  const producerOf = new Map<CellRef, Runnable>();
  for (const o of ops) for (const w of o.writes) producerOf.set(w, o);

  const succ = new Map<Runnable, Runnable[]>();
  for (const o of ops) {
    const outs = new Set<Runnable>();
    for (const r of o.reads) {
      const p = producerOf.get(r);
      if (p !== undefined && p !== o) outs.add(p);
    }
    succ.set(o, [...outs]);
  }

  let idx = 0;
  const index = new Map<Runnable, number>();
  const low = new Map<Runnable, number>();
  const onStack = new Set<Runnable>();
  const stack: Runnable[] = [];
  const out: Runnable[][] = [];

  const strong = (v: Runnable): void => {
    index.set(v, idx);
    low.set(v, idx);
    idx++;
    stack.push(v);
    onStack.add(v);
    for (const w of succ.get(v)!) {
      if (!index.has(w)) {
        strong(w);
        low.set(v, Math.min(low.get(v)!, low.get(w)!));
      } else if (onStack.has(w)) {
        low.set(v, Math.min(low.get(v)!, index.get(w)!));
      }
    }
    if (low.get(v) === index.get(v)) {
      const comp: Runnable[] = [];
      let w: Runnable;
      do {
        w = stack.pop()!;
        onStack.delete(w);
        comp.push(w);
      } while (w !== v);
      out.push(comp);
    }
  };

  for (const o of ops) if (!index.has(o)) strong(o);
  return out;
}
