// plot-measure op: compute the combined bounding box of placed marks from N plots.
// Two paths: DOM available → offscreen SVG + getBBox; no DOM → BboxPen heuristic.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { Relation } from "../../../algebra/relation.js";
import { BboxPen } from "../../../render/bbox-pen.js";
import { DVL_FONT_FAMILY } from "../../../ir/pen.js";

export async function plotMeasure(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as { kind: string; plots: readonly string[] };
  if (p.kind !== "plot-measure") return;

  let w = 0, h = 0;

  // Collect all rows across the PlotRect's plots
  const allRows: { rows: Record<string, unknown>[]; plotIdx: number }[] = [];
  for (let i = 0; i < op.reads.length; i++) {
    const rel = store.read(op.reads[i]) as Relation;
    if (rel === undefined) continue;
    const rows = rel.substrate === "js" ? rel.rows : await ctx.run(rel.frag);
    allRows.push({ rows: rows as Record<string, unknown>[], plotIdx: i });
  }

  // Detect keyed (per-cell) marks: if ANY row has dvl_cell, measure per-cell and take max.
  const hasCell = allRows.some(({ rows }) => rows.length > 0 && "dvl_cell" in rows[0]);

  if (hasCell) {
    // Group rows by dvl_cell, measure each group independently, take max w/h
    const cells = new Map<unknown, { rows: Record<string, unknown>[]; plotIdx: number }[]>();
    for (const { rows, plotIdx } of allRows) {
      for (const row of rows) {
        const key = row.dvl_cell;
        let group = cells.get(key);
        if (!group) { group = []; cells.set(key, group); }
        group.push({ rows: [row], plotIdx });
      }
    }
    for (const group of cells.values()) {
      const pen = new BboxPen();
      for (const { rows, plotIdx } of group) {
        const desc = ctx.spec.plots.get(p.plots[plotIdx])!.resolvedMark;
        if (desc === undefined) throw new Error(`plot-measure: plot "${p.plots[plotIdx]}" has an unresolved mark — call resolveSpec`);
        if (desc.draw) for (const row of rows) desc.draw(row as never, pen);
      }
      const bbox = pen.bbox();
      if (bbox) { w = Math.max(w, bbox.w); h = Math.max(h, bbox.h); }
    }
  } else if (typeof document !== "undefined") {
    // DOM path: render to offscreen SVG, measure via getBBox (pixel-accurate)
    const { SvgPen } = await import("../../../render/svg-pen.js");
    const pen = new SvgPen();
    for (const { rows, plotIdx } of allRows) {
      const desc = ctx.spec.plots.get(p.plots[plotIdx])!.resolvedMark;
        if (desc === undefined) throw new Error(`plot-measure: plot "${p.plots[plotIdx]}" has an unresolved mark — call resolveSpec`);
      if (desc.draw) for (const row of rows) desc.draw(row as never, pen);
    }
    const svg = pen.content();
    if (svg.length > 0) {
      const div = document.createElement("div");
      div.style.cssText = "position:absolute;left:-9999px;visibility:hidden";
      // Same font as the ROOT <svg> the render sink emits — the measuring context MUST resolve
      // the same glyph metrics as the display, or every reserved gutter lies (AUTOLEGEND_IMPL §8).
      div.innerHTML = `<svg xmlns="http://www.w3.org/2000/svg" font-family="${DVL_FONT_FAMILY}">${svg}</svg>`;
      document.body.appendChild(div);
      const bbox = div.querySelector("svg")!.getBBox();
      document.body.removeChild(div);
      w = bbox.width; h = bbox.height;
    }
  } else {
    // No-DOM path: BboxPen heuristic (shapes exact, text approximate)
    const pen = new BboxPen();
    for (const { rows, plotIdx } of allRows) {
      const desc = ctx.spec.plots.get(p.plots[plotIdx])!.resolvedMark;
        if (desc === undefined) throw new Error(`plot-measure: plot "${p.plots[plotIdx]}" has an unresolved mark — call resolveSpec`);
      if (desc.draw) for (const row of rows) desc.draw(row as never, pen);
    }
    const bbox = pen.bbox();
    if (bbox) { w = bbox.w; h = bbox.h; }
  }

  store.write(op.writes[0], w, "assigned");
  store.write(op.writes[1], h, "assigned");
}
