// The built IR tree — the container the authoring API (C1.3) populates, keyed by the
// path-based ids (allocated via IdGen). `validate` lives in C1.3 with the builder.
// (WUIR_IMPL §2.5.)
import { IdGen, type GroupId, type LayoutId, type NodeId, type PlotId } from "../types/ids.js";
import type { Group, Node } from "./node.js";
import type { Plot } from "./plot.js";
import type { LayoutInstance } from "./layout.js";
import { CellStore } from "./cell.js";
import type { Database } from "../data/database.js";

/** Canvas-level chart options (Observable Plot analogues), set once at `canvas(...)` and used as
 *  defaults during compile/render. Render-time `RenderOpts` override these per call. */
export interface CanvasOpts {
  /** Outer space between the canvas edge and the plot content — where axes/ticks/labels sit
   *  (Plot's `margin`; a number = all four sides). Feeds the root node's arrange margin. */
  margin?: number | { left?: number; right?: number; top?: number; bottom?: number };
  /** Inner data inset in px: pull marks off the frame edge (Plot's `inset`; a number = all four
   *  sides). Shrinks the [0,1]→pixel range; does not change the frame box. Mark-extent
   *  containment is NOT this knob — it is automatic per-scale expansion
   *  (design/2026-07-21-scale-expansion.html; opt out per scale with `expand: 0`). */
  inset?: number | { left?: number; right?: number; top?: number; bottom?: number };
  /** Canvas background color (Plot's `style.background`). */
  background?: string;
}

export interface Spec {
  root?: NodeId; // set once the root canvas node exists
  nodes: Map<NodeId, Node>;
  plots: Map<PlotId, Plot>;
  groups: Map<GroupId, Group>;
  layouts: Map<LayoutId, LayoutInstance>; // incl. scales/arranges
  cells: CellStore;
  ids: IdGen;
  db?: Database; // required for resolvability checks once C0 autoPath lands
  canvas?: CanvasOpts; // canvas-level chart options (§ Observable Plot analogues)
}

/** A fresh, empty spec with its own id allocator + cell store. */
export function newSpec(db?: Database, canvas?: CanvasOpts): Spec {
  return {
    nodes: new Map(),
    plots: new Map(),
    groups: new Map(),
    layouts: new Map(),
    cells: new CellStore(),
    ids: new IdGen(),
    db,
    canvas,
  };
}
