// Database — registration, schema cache, source versions, policy (WUDATA §1,
// WUDATA_IMPL §3). It is ALSO the root BRANCH: `db.branch(name?)` makes a child overlay
// where data-modeling steps register namespaced views (metadata-only, never UPDATE) and
// relation names resolve through the branch, falling through to the parent on a miss
// (design/2026-07-16-demo-core-tables.html §8). One abstraction — root and child are the
// same class; the base tables/FKs simply live on the root.

import type { Backend } from "./backend.js";
import type { Columnar } from "./backend.js";
import type { FKEdge } from "./fk.js";
import type { RelationName } from "./ids.js";
import type { RelationRef, SqlFragment } from "./fragment.js";
import type { Json, JsonRow, Schema, SqlType } from "./schema.js";
import { Table, type TableHost } from "./table.js";
import { emitSql } from "../algebra/relation.js";

export interface Warning {
  readonly kind: string;
  readonly message: string;
}

export interface DatabaseOptions {
  readonly backend: Backend;
  readonly mode?: "strict" | "non-strict";
  readonly onWarning?: (w: Warning) => void;
}

type Pending =
  | { readonly kind: "rows"; readonly rows: readonly JsonRow[] }
  | { readonly kind: "columnar"; readonly cols: Columnar }
  | { readonly kind: "view"; readonly sql: string };

/** A branch's recorded modeling step: the query object it denotes + the columns it exposes. */
interface ModelDef {
  readonly ref: RelationRef; // a SqlFragment (the CTE); base leaves recurse to real tables
  readonly schema: Schema; // the fragment's output columns (composed at record time)
  readonly key?: readonly string[];
}

let branchCounter = 0; // system branch ids ("br_1", …); a counter (not random) keeps runs reproducible.

/** A branch id is folded into backend relation names (`${id}__${identity}`), so it must be a legal
 *  bare SQL identifier — a caller-supplied name (e.g. a demo slug like "sized-panels") can carry
 *  hyphens or other punctuation. Map any non-word char to `_` and prefix a leading digit. This is
 *  defence-in-depth: fold now also quotes base names on emission, so a stray char no longer breaks
 *  SQL — but keeping ids as bare identifiers keeps the generated SQL and debug labels readable. */
function sanitizeBranchId(name: string): string {
  const cleaned = name.replace(/[^A-Za-z0-9_]/g, "_");
  return /^[0-9]/.test(cleaned) ? `_${cleaned}` : cleaned;
}

export class Database implements TableHost {
  #backend: Backend;
  readonly mode: "strict" | "non-strict";
  private readonly onWarning: (w: Warning) => void;
  private readonly schemas = new Map<RelationName, Schema>();
  private readonly versions = new Map<RelationName, number>();
  private readonly pending = new Map<RelationName, Pending>();

  // ── branch identity + overlay (§8) ──────────────────────────────────────────
  readonly id: string;
  readonly parent?: Database;
  /** logical relation name → the query object it denotes ON THIS BRANCH (a recorded modeling
   *  fragment). Unmapped names fall through to the parent, then to a base relation of that name. */
  private readonly modelMap = new Map<string, ModelDef>();
  /** logical name → a backend view/table this branch MATERIALIZED (namespaced) — the optional
   *  "other reasons" path (§8h); correctness never needs it, so it's separate from modelMap. */
  private readonly matMap = new Map<string, RelationName>();
  private readonly children = new Set<Database>();
  private readonly freshCounters = new Map<string, number>();
  private released = false;

  constructor(opts: DatabaseOptions & { id?: string; parent?: Database }) {
    this.#backend = opts.backend;
    this.mode = opts.mode ?? "non-strict";
    this.onWarning = opts.onWarning ?? (() => {});
    this.id = opts.id ?? "root";
    this.parent = opts.parent;
  }

  get backend(): Backend {
    return this.#backend;
  }

  /** Swap in a wrapping backend (the debug tap, debug/backend-tap.ts). Registration
   *  state, schema cache, and versions are untouched — the wrapper delegates. */
  installBackend(backend: Backend): void {
    this.#backend = backend;
  }

  // ── branch lifecycle (§8a/§8b) ───────────────────────────────────────────────

  /** A child branch: an empty overlay that falls through to this branch. Modeling steps on the
   *  child record query objects and never touch this branch. */
  branch(name?: string): Database {
    const id = name !== undefined ? sanitizeBranchId(name) : `br_${++branchCounter}`;
    const child = new Database({ backend: this.#backend, mode: this.mode, onWarning: this.onWarning, id, parent: this });
    this.children.add(child);
    return child;
  }

  /** Release this branch: mark it, and reclaim (drop any MATERIALIZED views/tables, detach) once
   *  it has no live children — a child holds its parent alive. Cascades up as children release.
   *  Modeling itself creates no backend objects (query objects fold inline), so reclamation only
   *  touches what `materialize()` created. */
  async release(): Promise<void> {
    this.released = true;
    await this.tryReclaim();
  }

  private reclaimed = false;
  private async tryReclaim(): Promise<void> {
    if (!this.released || this.parent === undefined) return; // root is never reclaimed
    for (const c of this.children) if (!c.reclaimed) return; // a live child still references us
    for (const backend of this.matMap.values()) {
      this.schemas.delete(backend);
      await this.#backend.dropView(backend).catch(() => {});
      await this.#backend.drop(backend).catch(() => {}); // materialize makes a TABLE; drop both forms
    }
    this.matMap.clear();
    this.modelMap.clear();
    this.reclaimed = true;
    this.parent.children.delete(this);
    await this.parent.tryReclaim(); // a released parent waiting on us can now reclaim too
  }

  /** Snapshot a modeled relation into a real backend table (§8h) — the escape hatch for a deep
   *  fragment stack in a hot loop. Namespaced, so it's reclaimed by release(); after this, the
   *  identity resolves to the table (a base leaf) instead of the inline fragment. */
  async materialize(identity: string): Promise<void> {
    const model = this.lookupModel(identity);
    if (model === undefined || !("fragment" in model.ref)) return; // nothing to snapshot
    const backend = `${this.id}__${identity}`;
    const sql = emitSql(model.ref.fragment, (n) => this.schemaOf(n), this.#backend.dialect);
    await this.#backend.materialize(backend, sql);
    this.matMap.set(identity, backend);
    this.schemas.set(backend, model.schema);
    // rebind the identity to the base table so future resolves skip the fragment.
    this.modelMap.set(identity, { ref: { base: backend }, schema: model.schema, key: model.key });
  }

  /** The raw-SQL escape hatch (design §6): register `sql` as a branch-scoped VIEW under this
   *  branch's namespace and return the bound Table. Unlike the query-object operators (which fold
   *  inline), derive persists a backend view — for modeling the structural operators don't cover
   *  (window→pixel geometry, exotic SQL). Still namespaced, so it's reclaimed on release; its SQL
   *  is on screen in the example (the point — no hidden boot view). Schema is introspected lazily.
   *  The SQL references relations by their plain names (base tables, or other branch identities —
   *  resolve their namespaced backend name if modeled). */
  derive(identity: string, sql: string): Table {
    const backend = this.parent === undefined ? identity : `${this.id}__${identity}`;
    // rewrite bare relation names that are branch-modeled into their backend names so the view
    // sees the modeled data (best-effort: only names this branch actually remapped).
    this.pending.set(backend, { kind: "view", sql });
    this.matMap.set(identity, backend); // reclaimed on release like a materialized relation
    this.modelMap.set(identity, { ref: { base: backend }, schema: [] }); // schema introspected on demand
    this.bumpVersion(backend);
    return new Table(identity, { kind: "view", relation: backend }, () => this.schemaOfIdentity(identity), this);
  }

  // ── TableHost (used by Table's modeling methods, §8c/§7) ─────────────────────

  private lookupModel(identity: string): ModelDef | undefined {
    for (let b: Database | undefined = this; b !== undefined; b = b.parent) {
      const hit = b.modelMap.get(identity);
      if (hit !== undefined) return hit;
    }
    return undefined;
  }

  /** Resolve a logical name to the relation it denotes: a recorded modeling fragment (falling
   *  through to parents), else a base relation of that name (root base tables / fromQuery). */
  resolveRef(identity: string): RelationRef {
    return this.lookupModel(identity)?.ref ?? { base: identity };
  }

  /** Current schema of a logical name — a recorded model's (live) schema, else the base
   *  relation's. Resolved fresh each call, so a Table handed out before a later modeling step
   *  still reports the up-to-date columns. */
  async schemaOfIdentity(identity: string): Promise<Schema> {
    const m = this.lookupModel(identity);
    if (m === undefined) return this.ensureSchema(identity);
    // a derive()'d view (base-leaf ref, no statically-composed schema) is introspected once.
    if (m.schema.length === 0 && "base" in m.ref) return this.ensureSchema(m.ref.base);
    return m.schema;
  }

  /** Record a modeling fragment under `identity` on this branch; returns the bound Table. The
   *  output schema is composed synchronously from the fragment's inputs (base leaves via the
   *  schema cache; upstream fragments via their recorded schema) — no backend round-trip. */
  recordModel(identity: string, frag: SqlFragment, opts?: { key?: readonly string[] }): Table {
    const schema = this.composeFragmentSchema(frag);
    this.modelMap.set(identity, { ref: { fragment: frag }, schema, key: opts?.key });
    const t = new Table(identity, { kind: "view", relation: identity }, () => this.schemaOfIdentity(identity), this);
    if (opts?.key) t.primaryKey = opts.key;
    return t;
  }

  /** Compose a modeling fragment's output columns from its inputs' schemas (§ schema.composeSchema).
   *  A base-leaf input reads the (already-loaded) schema cache; a fragment input reads the schema of
   *  its result CTE, which for our modeling fragments is the recorded upstream schema. */
  private composeFragmentSchema(frag: SqlFragment): Schema {
    const out = frag.outputs;
    if ("columns" in out) return out.columns;
    const inputSchema = (ref: RelationRef): Schema =>
      "base" in ref ? this.schemaOfModeled(ref.base) : this.composeFragmentSchema(ref.fragment);
    const base = inputSchema(frag.inputs[out.passthrough]);
    const result = base.map((c) => ({ ...c }));
    for (const add of out.add) {
      const i = result.findIndex((c) => c.name === add.name);
      if (i >= 0) result[i] = { ...add };
      else result.push({ ...add });
    }
    return result;
  }

  /** Schema of a base-leaf name for modeling composition: a recorded model's schema if the name is
   *  one of ours, else the loaded base-table schema. */
  private schemaOfModeled(name: RelationName): Schema {
    const m = this.lookupModel(name);
    if (m !== undefined) return m.schema;
    return this.schemaOf(name);
  }

  /** Sync column schema a ref denotes — for operators typing their outputs (groupby keys). */
  columnsOf(ref: RelationRef): Schema {
    try {
      return "base" in ref ? this.schemaOfModeled(ref.base) : this.composeFragmentSchema(ref.fragment);
    } catch {
      return [];
    }
  }

  /** A fresh, branch-unique identity for `base` — base, base2, base3, … */
  freshName(base: string): string {
    const taken = (id: string): boolean => this.lookupModel(id) !== undefined || this.schemas.has(id);
    if (!taken(base)) return base;
    let n = this.freshCounters.get(base) ?? 1;
    while (taken(`${base}${n + 1}`)) n++;
    n++;
    this.freshCounters.set(base, n);
    return `${base}${n}`;
  }

  // ── registration (sync handles; backend registration is lazy) ──────────────

  fromRows(name: string, rows: readonly JsonRow[]): Table {
    const schema = inferSchema(rows);
    this.schemas.set(name, schema);
    this.pending.set(name, { kind: "rows", rows });
    this.bumpVersion(name);
    return new Table(name, { kind: "js-rows", relation: name, rows }, () => this.ensureSchema(name), this);
  }

  fromColumnar(name: string, cols: Columnar): Table {
    this.schemas.set(name, inferColumnarSchema(cols));
    this.pending.set(name, { kind: "columnar", cols });
    this.bumpVersion(name);
    return new Table(name, { kind: "js-columnar", relation: name, cols }, () => this.ensureSchema(name), this);
  }

  /** An existing backend table/view; schema is introspected on demand. */
  table(name: string): Table {
    return new Table(name, { kind: "db-table", relation: name }, () => this.ensureSchema(name), this);
  }

  /** Opaque user SQL registered as a view; schema introspected on demand. */
  fromQuery(name: string, sql: string): Table {
    this.pending.set(name, { kind: "view", sql });
    this.bumpVersion(name);
    return new Table(name, { kind: "query", relation: name, sql }, () => this.ensureSchema(name), this);
  }

  // ── schema resolution ──────────────────────────────────────────────────────

  /** Sync schema lookup for fold; throws if not yet loaded. Falls through to the parent so a
   *  child branch sees base-table schemas without recaching them. */
  schemaOf(name: RelationName): Schema {
    for (let b: Database | undefined = this; b !== undefined; b = b.parent) {
      const s = b.schemas.get(name);
      if (s !== undefined) return s;
    }
    throw new Error(`schema for "${name}" not loaded; await ensureSchema("${name}") first`);
  }

  /** Resolve + cache a relation's schema (registers a pending view first). */
  async ensureSchema(name: RelationName): Promise<Schema> {
    for (let b: Database | undefined = this; b !== undefined; b = b.parent) {
      const cached = b.schemas.get(name);
      if (cached !== undefined) return cached;
    }
    await this.ensureRegistered(name);
    const s = await this.backend.introspectSchema(name);
    this.schemas.set(name, s);
    return s;
  }

  // ── lazy backend registration ──────────────────────────────────────────────

  /**
   * Push registered JS data into the backend so queries can actually run over it.
   * `fromRows`/`fromColumnar` stay sync (schema + an in-memory pending payload — spec
   * construction never touches the backend); this is the deliberate async step that
   * materializes that payload as a real backend table/view. Idempotent (clears pending);
   * omit `name` to flush ALL pending. The render pipeline also triggers this lazily per
   * query, so an explicit call is only needed to prep the DB or query it directly.
   */
  async register(name?: RelationName): Promise<void> {
    if (name !== undefined) return this.ensureRegistered(name);
    await Promise.all([...this.pending.keys()].map((n) => this.ensureRegistered(n)));
  }

  async ensureRegistered(name: RelationName): Promise<void> {
    // a base relation's pending entry may live on this branch or an ancestor (base tables are
    // registered on the root; a child resolving a base leaf must find it there).
    let b: Database | undefined = this;
    while (b !== undefined) {
      const p = b.pending.get(name);
      if (p !== undefined) {
        if (p.kind === "rows") await this.#backend.registerRows(name, p.rows);
        else if (p.kind === "columnar") await this.#backend.registerColumnar(name, p.cols);
        else await this.#backend.registerView(name, p.sql);
        b.pending.delete(name);
        return;
      }
      b = b.parent;
    }
  }

  // ── source versions (cache invalidation key input — WUDATA §6) ─────────────

  versionOf(name: RelationName): number {
    return this.versions.get(name) ?? 0;
  }
  bumpVersion(name: RelationName): void {
    this.versions.set(name, this.versionOf(name) + 1);
  }

  // ── the FK catalog (the graph paths resolve AGAINST — CELL_KEY_VIA §3a) ────

  #fkEdges: FKEdge[] = [];

  /** Declare an FK edge (sync — the resolve pass reads the catalog during compile). */
  declareFK(edge: FKEdge): void {
    this.#fkEdges.push(edge);
  }

  /** Load the backend's introspected FKs into the catalog (dedup by identity fields). */
  async loadFKs(): Promise<void> {
    const seen = new Set(this.#fkEdges.map((e) => JSON.stringify(e)));
    for (const e of await this.backend.introspectFKs()) {
      if (!seen.has(JSON.stringify(e))) this.#fkEdges.push(e);
    }
  }

  /** The FK catalog visible on this branch: this branch's edges plus every ancestor's. */
  get fks(): readonly FKEdge[] {
    const edges: FKEdge[] = [];
    for (let b: Database | undefined = this; b !== undefined; b = b.parent) edges.push(...b.#fkEdges);
    return edges;
  }

  // ── policy ─────────────────────────────────────────────────────────────────

  warn(w: Warning): void {
    if (this.mode === "strict") throw new Error(`[${w.kind}] ${w.message}`);
    this.onWarning(w);
  }
}

// ── schema inference from JS data ──────────────────────────────────────────────

export function inferSchema(rows: readonly JsonRow[]): Schema {
  if (rows.length === 0) {
    throw new Error("fromRows: cannot infer schema from 0 rows");
  }
  return Object.keys(rows[0]).map((name) => ({ name, type: inferColumnType(rows, name) }));
}

function inferColumnType(rows: readonly JsonRow[], col: string): SqlType {
  let sawNumber = false;
  let allInt = true;
  for (const r of rows) {
    const v: Json | undefined = r[col];
    if (v === null || v === undefined) continue;
    if (Array.isArray(v)) return "list"; // JSON-loaded nested column
    if (typeof v === "boolean") return "bool";
    if (typeof v === "string") return "varchar";
    if (typeof v === "object") return "struct"; // non-array object
    if (typeof v === "number") {
      sawNumber = true;
      if (!Number.isInteger(v)) allInt = false;
    }
  }
  if (sawNumber) return allInt ? "int" : "double";
  return "unknown";
}

function inferColumnarSchema(cols: Columnar): Schema {
  const keys = Object.keys(cols);
  const len = keys.length === 0 ? 0 : cols[keys[0]].length;
  const rows: JsonRow[] = [];
  for (let i = 0; i < Math.min(len, 64); i++) {
    const r: Record<string, Json> = {};
    for (const k of keys) r[k] = cols[k][i] as Json;
    rows.push(r);
  }
  return rows.length === 0 ? keys.map((name) => ({ name, type: "unknown" })) : inferSchema(rows);
}
