// stackV: fixed-pitch vertical bands — one band per row, ranked by an order column, band height
// INDEPENDENT of the parent extent. Contrast `stack` (percent-stack: segments cumulate per group
// and normalize to [0,1], so the frame STRETCHES them to fill the box). stackV is the legend-item
// layout: N swatches stacked at a constant pixel pitch, so the stack's height is intrinsic (N*pitch)
// rather than the box's.
//
// It is a pure windowed derive (rank) — no extent-cell reads — so it lowers to BOTH SQL and JS with
// no materialization. That is the point of gap #8 ("stackV SQL builder"): grid-stack packs 2-D by
// reading the content box (JS-only), whereas a 1-D fixed-pitch stack needs no box and stays in SQL.
//
// Outputs pixel-space offsets measured DOWN from the stack's own origin:
//   y = pad + rank·(pitch+gap)   — the band TOP edge (rect(y,h) semantics; a swatch centers at y+h/2)
//   h = pitch                     — the band height
// stackV reads no box origin; the consumer (a legend gutter plot) translates the whole stack into
// its box. `rank` is the 0-based dense rank of the order column — distinct values (the legend case)
// get consecutive bands; rows that tie on the order column share a band.
import { inputCol, type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, lit, rank } from "../../algebra/relop.js";
import { coord, dataSpace, len, pixelSpace } from "../../types/attr.js";

interface PitchOptions {
  readonly pitch?: number; // band height in pixels (default 16)
  readonly gap?: number; // extra gap between bands (default 0)
  readonly pad?: number; // offset of the first band from the origin (default 0)
}

export const pitchY = op({
  name: "pitchY",
  // No domain: fixed pixel pitch, no trained fit (like `stack`) — nothing tickable.
  inputs: { marks: [{ name: "order", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "y", type: "double" }, { name: "h", type: "double" }] },
  outSpaces: { y: pixelSpace(coord("y")), h: pixelSpace(len("y")) },
  inputSpaces: { order: dataSpace },
  apply: (b): RelOp => {
    const [yo, ho] = b.outputs;
    const o = (b.options ?? {}) as PitchOptions;
    const pitch = o.pitch ?? 16;
    const gap = o.gap ?? 0;
    const pad = o.pad ?? 0;
    const step = pitch + gap;
    // y = pad + rank·step (band top); h = pitch. rank(order) is 0-based (dense_rank − 1), so the
    // first item sits at `pad` and each subsequent band is one step lower.
    const y = bin("+", lit(pad), bin("*", rank(inputCol(b, "value")), lit(step)));
    return { kind: "derive", add: { [yo]: y, [ho]: lit(pitch) }, outTypes: { [yo]: "double", [ho]: "double" } };
  },
});
