// render op: the sink — materialize every plot's placed marks and draw the scene.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellRef, CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { materialize, type Relation } from "../../../algebra/relation.js";
import { render } from "../../../render/render.js";
import type { Frame, MarkOp, SceneRow } from "../../../render/scene.js";

export async function renderOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as { kind: string; plots: readonly { plot: string; marks: CellRef }[]; widthCell: CellRef; heightCell: CellRef; background?: string };
  if (p.kind !== "render") return;
  const markOps: MarkOp[] = [];
  for (const pl of p.plots) {
    const rel = store.read(pl.marks) as Relation;
    const { rows } = await materialize(rel, ctx.run);
    // Deterministic draw order (§12 Phase 4 P5): SQL row order is plan-shaped noise — planned
    // crossings change join shapes and with them the emitted order. Sorting by the mark key gives
    // a stable z-order contract and byte-identical output across plan shapes (measured blast
    // radius on the suite: zero). Rows without dvl_mark (producer relations) keep arrival order.
    const sorted = rows.length > 0 && rows.every((r) => r.dvl_mark !== undefined)
      ? [...rows].sort((a, z) => Number(a.dvl_cell ?? 0) - Number(z.dvl_cell ?? 0) || Number(a.dvl_mark) - Number(z.dvl_mark))
      : rows;
    markOps.push({ plot: pl.plot, markType: ctx.spec.plots.get(pl.plot)!.markType, rows: sorted as readonly SceneRow[] });
  }
  const width = Number(store.read(p.widthCell));
  const height = Number(store.read(p.heightCell));
  const frame: Frame = { id: ctx.spec.root ?? "", drawable: { x: 0, y: 0, w: width, h: height }, background: p.background };
  // resolve-once: mark descriptors come off the spec's resolved plots, never a registry.
  const marks = {
    get: (name: string) => {
      for (const pl of ctx.spec.plots.values()) if (pl.markType === name && pl.resolvedMark !== undefined) return pl.resolvedMark;
      throw new Error(`render: mark "${name}" has no resolved descriptor — call resolveSpec(spec, registries)`);
    },
  };
  store.write(op.writes[0], render({ width, height, frames: [frame], marks: markOps }, marks), "assigned");
}
