// The expression-tree walker: ScalarExpr → Space (P-total Stage 1).
//
// Given any ScalarExpr and a typing environment, computes the Space of the
// expression's result by applying the judgment (judgment.ts spaceArith)
// recursively over the P4 expression algebra. Returns null for ill-typed
// (mixed-space arithmetic). See §12 Stage 1 of the design doc.
import type { ScalarExpr } from "./relop.js";
import type { CellRef } from "../ir/cell.js";
import type { Space } from "../types/attr.js";
import { dataSpace, styleSpace } from "../types/attr.js";
import { spaceArith } from "../types/judgment.js";

/** A typing environment maps leaf names to spaces. */
export type SpaceEnv = {
  col(name: string, src: "marks" | "fit"): Space | null;
  cell(ref: CellRef): Space | null;
};

/** Compute the space a ScalarExpr produces under `env`.
 *  Returns null for ill-typed combinations (mixed-space arithmetic). */
export function spaceOf(e: ScalarExpr, env: SpaceEnv): Space | null {
  switch (e.k) {
    case "col":
      return env.col(e.name, e.src);
    case "cell":
      return env.cell(e.ref);
    case "bin": {
      const l = spaceOf(e.l, env);
      const r = spaceOf(e.r, env);
      if (l === null || r === null) return null;
      // Modulo is not a spatial operation — same-space passthrough when both match, else data
      // (the same rule as ir/expr.ts binaryType).
      if (e.op === "%") return l.space === r.space ? l : dataSpace;
      return spaceArith(e.op, l, r);
    }
    case "nullif0":
    case "unary":
    case "round":
      return spaceOf(e.x, env);
    case "lit":
      // An unspaced lit is a genuine data literal (SQL constants in derive expressions)
      return e.space ?? dataSpace;
    case "left":
    case "concat":
    case "rank":
    case "wsum":
    case "rownum":
    case "rand":
      return dataSpace;
    case "lead":
      // the successor's value of a marks column — same space as the column itself.
      return env.col(e.col, "marks");
    case "index":
      // §6: indexing a palette of COLOURS yields style⟨color⟩; a numeric/other list yields data.
      // This is what makes a colour scale's `index(ramp, …)` type as a colour, so verify-spaces
      // can tell a real colour output from a raw number dumped on a colour channel.
      return e.list.every((v) => typeof v === "string" && v.startsWith("#")) ? styleSpace("color") : dataSpace;
    case "call":
      // a registered function (math/string/stat) produces a DATA value by construction.
      return dataSpace;
  }
}
