// box-points — canonical POINTS of a 1-D box layout, as typed derivations (explainer §12.3).
//
// A positional box layout (band, eqx, col) is a pure producer of its box: a left/low edge `x` (or `y`)
// and a width/height `w` (or `h`), in relative space. The canonical points of that box — centre, far
// edge — are NOT producer options (`anchor:"center"` was a hack that smuggled a consumer's coordinate
// choice into the producer). They are DERIVATIONS over the two outputs the layout already emits:
//   centre = x + w·½      far = x + w        (the point at fraction t is x + t·w)
// These are well-typed (coord + len·scalar = coord) and, because their leaves are layout-outputs
// (relational), they LIFT into their own step via liftViaExprs — the same rule as any arithmetic over
// a layout output. The general `x + t·w` stays internal; consumers pick a named point (centre/far).
import { binary, layoutOutput, literal, type Expr } from "../ir/expr.js";
import { coord, len, relativeSpace } from "../types/attr.js";

/** The point at fraction `t` across a 1-D box layout's item along `axis` (0 = near edge, ½ = centre,
 *  1 = far edge): `x + t·w`, in relative coords. `xOut`/`wOut` name the layout's low-edge and extent
 *  outputs (default x/w; a vertical layout passes y/h). Lifted by liftViaExprs (layout-output leaves). */
export function boxPoint(layoutId: string, t: number, axis: "x" | "y" = "x", xOut = "x", wOut = "w"): Expr {
  const x = layoutOutput(layoutId, xOut, { space: relativeSpace(coord(axis)), arity: "per-row" });
  if (t === 0) return x; // the near edge — no arithmetic needed
  const w = layoutOutput(layoutId, wOut, { space: relativeSpace(len(axis)), arity: "per-row" });
  return binary("+", x, binary("*", w, literal(t)));
}

/** The CENTRE of a 1-D box layout's item along `axis` — `x + w·½`. The point an axis tick or a strip
 *  label sits on, replacing the `anchor:"center"` producer option. */
export function boxCentre(layoutId: string, axis: "x" | "y" = "x", xOut = "x", wOut = "w"): Expr {
  return boxPoint(layoutId, 0.5, axis, xOut, wOut);
}
