// The optimizer's side-map: physical format annotations on relation cells.
// Lives only during the optimizer pass — not stored on Cell (shared infra).
import type { CellRef } from "../ir/cell.js";
import type { Substrate } from "../algebra/relation.js";
export interface CellFormat {
  substrate: Substrate;
}

export class FormatMap {
  #map = new Map<CellRef, CellFormat>();
  get(ref: CellRef): CellFormat | undefined { return this.#map.get(ref); }
  set(ref: CellRef, fmt: CellFormat): void { this.#map.set(ref, fmt); }
}
