// Register framework-internal op handlers into registries.ops.
// Capabilities are declared at registration — the optimizer reads them from the registry.
import type { Registries, OpCapability } from "../../operator/registry.js";
import { gatherScatter } from "./dataflow/gather-scatter.js";
import { allocate } from "./arrange/allocate.js";
import { axisMerge } from "./arrange/axis-merge.js";
import { domain } from "./ops/domain.js";
import { apply } from "./ops/apply.js";
import { arrange } from "./ops/arrange.js";
import { renderOp } from "./ops/render-op.js";
import { marktableOp } from "./ops/marktable-op.js";
import { vtableOp } from "./ops/vtable-op.js";
import { pathAgg } from "./ops/path-agg.js";
import { plotMeasure } from "./ops/plot-measure.js";
import { overhang } from "./ops/overhang.js";
import { gridStackOp } from "../layouts/grid-stack.js";
import { materializeOp } from "./ops/materialize-op.js";
import { injectOp } from "./ops/inject-op.js";
import { hostExtentOp, verifyOp } from "./ops/kernel-leaves.js";
import { relopOp } from "./ops/relop-op.js";
import { viaAgg } from "./ops/via-agg.js";
import { reduceOp } from "./ops/reduce-op.js";
import { sigmaVerifyOp, unionAllOp } from "./ops/union-op.js";

const BOTH: readonly ("sql" | "js")[] = ["sql", "js"];
const SQL: readonly ("sql" | "js")[] = ["sql"];
const JS: readonly ("sql" | "js")[] = ["js"];
const NONE: readonly ("sql" | "js")[] = [];
const SCALAR: OpCapability = { canConsume: NONE, canProduce: NONE };
const SOURCE_SQL: OpCapability = { canConsume: NONE, canProduce: SQL };
const TRANSPARENT: OpCapability = { canConsume: BOTH, canProduce: BOTH };
const SINK: OpCapability = { canConsume: BOTH, canProduce: NONE };

export function registerInternalOps(r: Registries): void {
  // placement has NO handler (P4c + P4e): both affine boxes are relops — replace-derive over
  // lo + (hi−lo)·t, the scalar box reading extent cells (cell leaves), the keyed box joining the
  // host's placed marks (join-derive) — emitted by graph.ts, run by the shared lowering.
  // dataflow
  r.ops.register("gather-scatter", gatherScatter, TRANSPARENT);
  // arrange (scalar-only: reads/writes extent cells, not relations)
  r.ops.register("allocate", allocate, SCALAR);
  r.ops.register("axis-merge", axisMerge, SCALAR);
  // component-delegating ops
  r.ops.register("domain", domain, TRANSPARENT);
  r.ops.register("apply", apply, TRANSPARENT);
  r.ops.register("arrange", arrange, SCALAR);
  r.ops.register("render", renderOp, SINK);
  r.ops.register("marktable", marktableOp, SOURCE_SQL);
  r.ops.register("vtable", vtableOp, SOURCE_SQL);
  r.ops.register("path-agg", pathAgg, { canConsume: SQL, canProduce: SQL });
  // reduce (§8 Stage 3): the ONE grouped reduce as a standalone op — relation → relation, one
  // row per `by` value. via-agg's declarative path is a client; child-extent aggregation next.
  r.ops.register("reduce", reduceOp, { canConsume: BOTH, canProduce: BOTH });
  // σ (perCell explainer §7e): union-all realizes scope:'union' (one row per touching panel,
  // identity-deduped); sigma-verify is the conjoin's diagnostics twin (dropped rows as data).
  r.ops.register("union-all", unionAllOp, { canConsume: SQL, canProduce: SQL });
  r.ops.register("sigma-verify", sigmaVerifyOp, { canConsume: SQL, canProduce: SQL });
  // via-agg (§3b/§3c): a resolved multi-match via with an OPAQUE js reduction — the
  // (matches, mark) contract needs two-sided rows a single-input reduce cannot carry, so the
  // opaque form keeps its own handler; declarative resolutions lower as stage → reduce → attach.
  r.ops.register("via-agg", viaAgg, { canConsume: SQL, canProduce: BOTH });
  r.ops.register("plot-measure", plotMeasure, SINK);
  // overhang (§4.1): the containment loop's measure — reads the C6 box relations, writes the
  // data-inset demand cells the affine reads (the SCC the scheduler fixpoints). Scalar sink shape.
  r.ops.register("overhang", overhang, SINK);
  r.ops.register("grid-stack", gridStackOp, { canConsume: BOTH, canProduce: JS, fixedOutput: "js" });
  r.ops.register("materialize", materializeOp, { canConsume: SQL, canProduce: JS, fixedOutput: "js" });
  r.ops.register("inject", injectOp, { canConsume: JS, canProduce: SQL, fixedOutput: "sql" });
  // relop: the serializable algebra node — absorbs literal/local-column/multi-augment (augments)
  // AND values/unit (constant source leaves), executed by the shared lowering (lower.ts) instead
  // of a hand-rolled body per kind. A source relop has empty reads; substrate-chooser biases it to
  // SQL exactly as SOURCE_SQL did (TRANSPARENT + no relation inputs ⇒ same choice, verified).
  r.ops.register("relop", relopOp, TRANSPARENT);
  // kernel leaves (previously inline in run.ts switch). via + cell-key are GONE (P4d executed):
  // both are join relops emitted by graph.ts, run by the shared lowering.
  // host-extent is a SCALAR SINK (P4g reclassified): pixel scalars → cells, no relation out.
  // It is solve/decision-family, NOT relop-shaped — it stays out of the relop collapse by design.
  r.ops.register("host-extent", hostExtentOp, SINK);
  r.ops.register("verify", verifyOp, { canConsume: BOTH, canProduce: JS, fixedOutput: "js" });
}
