// The SVG pen — the concrete target encoding for the abstract ir/Pen. It is the SOLE
// place SVG syntax appears; marks draw via the Pen interface and never know the target.
import type { Pen, Point, Style } from "../ir/pen.js";

/** Accumulates SVG element strings; `content()` returns the inner markup. */
export class SvgPen implements Pen {
  #parts: string[] = [];

  /** Emit a shape element; a `title` style becomes a <title> child (the SVG-native
   *  hover tooltip / accessible name) instead of a self-closing tag. */
  #shape(tag: string, attrStr: string, s: Style): void {
    this.#parts.push(
      s.title === undefined || s.title === ""
        ? `<${tag}${attrStr}/>`
        : `<${tag}${attrStr}><title>${escapeXml(s.title)}</title></${tag}>`,
    );
  }

  circle(cx: number, cy: number, r: number, s: Style): void {
    this.#shape("circle", ` cx="${cx}" cy="${cy}" r="${r}"${attrs(s)}`, s);
  }
  ellipse(cx: number, cy: number, rx: number, ry: number, s: Style): void {
    this.#shape("ellipse", ` cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}"${attrs(s)}`, s);
  }
  rect(x: number, y: number, w: number, h: number, s: Style): void {
    this.#shape("rect", ` x="${x}" y="${y}" width="${w}" height="${h}"${attrs(s)}`, s);
  }
  line(x1: number, y1: number, x2: number, y2: number, s: Style): void {
    this.#shape("line", ` x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}"${attrs(s)}`, s);
  }
  polyline(points: readonly Point[], s: Style): void {
    this.#shape("polyline", ` points="${fmtPoints(points)}"${attrs(s)}`, s);
  }
  polygon(points: readonly Point[], s: Style): void {
    this.#shape("polygon", ` points="${fmtPoints(points)}"${attrs(s)}`, s);
  }
  path(d: string, s: Style): void {
    this.#shape("path", ` d="${d}"${attrs(s)}`, s);
  }
  text(t: string, x: number, y: number, s: Style): void {
    const rot = s.rotate != null && s.rotate !== 0 ? ` transform="rotate(${s.rotate}, ${x}, ${y})"` : "";
    this.#parts.push(`<text x="${x}" y="${y}"${rot}${attrs(s)}>${escapeXml(t)}</text>`);
  }
  textMultiline(lines: string[], x: number, y: number, s: Style): void {
    const lineH = (s.fontSize ?? 10) * 1.2;
    const rot = s.rotate != null && s.rotate !== 0 ? ` transform="rotate(${s.rotate}, ${x}, ${y})"` : "";
    const spans = lines.map((l, i) =>
      `<tspan x="${x}" ${i === 0 ? `y="${y}"` : `dy="${lineH}"`}>${escapeXml(l)}</tspan>`
    ).join("");
    this.#parts.push(`<text${rot}${attrs(s)}>${spans}</text>`);
  }
  image(x: number, y: number, w: number, h: number, href: string, s: Style): void {
    this.#parts.push(`<image x="${x}" y="${y}" width="${w}" height="${h}" href="${escapeAttr(href)}"${attrs(s)}/>`);
  }

  content(): string {
    return this.#parts.join("");
  }
}

function fmtPoints(points: readonly Point[]): string {
  return points.map(([x, y]) => `${x},${y}`).join(" ");
}

/** Canonical style → SVG presentation attributes (the default convention). */
function attrs(s: Style): string {
  const a: string[] = [];
  if (s.fill !== undefined) a.push(`fill="${s.fill}"`);
  if (s.stroke !== undefined) a.push(`stroke="${s.stroke}"`);
  if (s.strokeWidth !== undefined) a.push(`stroke-width="${s.strokeWidth}"`);
  if (s.strokeDasharray !== undefined) a.push(`stroke-dasharray="${s.strokeDasharray}"`);
  if (s.opacity !== undefined) a.push(`opacity="${s.opacity}"`);
  if (s.fillOpacity !== undefined) a.push(`fill-opacity="${s.fillOpacity}"`);
  if (s.strokeOpacity !== undefined) a.push(`stroke-opacity="${s.strokeOpacity}"`);
  if (s.fontSize !== undefined) a.push(`font-size="${s.fontSize}"`);
  if (s.fontFamily !== undefined) a.push(`font-family="${escapeAttr(s.fontFamily)}"`);
  if (s.textAnchor !== undefined) a.push(`text-anchor="${s.textAnchor}"`);
  if (s.dominantBaseline !== undefined) a.push(`dominant-baseline="${s.dominantBaseline}"`);
  return a.length > 0 ? " " + a.join(" ") : "";
}

function escapeXml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function escapeAttr(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;");
}
