// The executor's dispatcher: compile dataflow descriptions (OpSpec) into runnable operators the
// scheduler executes. Dispatches to registries.ops by payload.kind. (WUMODULES Phase 4.)
import type { Spec } from "../ir/spec.js";
import type { CellStore } from "../ir/cell.js";
import type { OpSpec } from "../plan/opspec.js";
import type { OpsRegistry } from "../operator/registry.js";
import type { MeasurementProvider } from "../ir/mark.js";
import type { RunFrag } from "../algebra/relation.js";
import type { DebugSink } from "../debug/sink.js";
import type { Runnable } from "./schedule.js";

/** What every op handler receives — the SLIM executor context (simplification §12 Phase 3):
 *  the spec (arrange/marktable/render read instances off it), a SQL runner, a measurement
 *  provider. NO registries — every name resolved once, upstream (resolveSpec / stampAlgo /
 *  creation-time binding). The kind→handler dispatch table is compileOps' own parameter, not
 *  ambient context; Phase 4's ResolvedOp deletes even that lookup. */
export interface RunCtx {
  readonly spec: Spec;
  readonly run: RunFrag;
  readonly measure: MeasurementProvider;
  /** Profiling sink (explainer §2a): runOp is the choke point EVERY operator flows
   *  through, so one span here times them all. Absent ⇒ zero overhead. */
  readonly debug?: DebugSink;
}

/** Compile dataflow descriptions into runnable operators (id/reads/writes + a run closure). */
export function compileOps(ops: readonly OpSpec[], ctx: RunCtx, dispatch: OpsRegistry): Runnable[] {
  return ops.map((op) => ({ id: op.id, reads: op.reads, writes: op.writes, run: (store: CellStore) => runOp(op, store, ctx, dispatch) }));
}

function runOp(op: OpSpec, store: CellStore, ctx: RunCtx, dispatch: OpsRegistry): void | Promise<void> {
  const kind = op.payload.kind;
  if (!dispatch.has(kind)) throw new Error(`run: unhandled op kind "${kind}" (not registered)`);
  const dbg = ctx.debug;
  if (dbg === undefined) return dispatch.get(kind)(op, store, ctx);
  // op.id is the structured identity the plan already mints (p0:linear_x:domain); the
  // payload tag carries purpose (path-hop, via-stage:x, …). No new naming scheme.
  const tag = (op.payload as { tag?: string }).tag;
  const ran = dbg.span(op.id, { kind: "operator", op_kind: kind, ...(tag !== undefined ? { tag } : {}) }, () => dispatch.get(kind)(op, store, ctx));
  // Record the ACTUAL substrate this op ran in (dvl_op_run, level 2 — self-gated): the substrate of
  // the relation it wrote IS which impl executed (sql/js), for EVERY op kind — the runtime truth the
  // "execute" graph view reads, complementing the optimizer's stamped choice on dvl_operator.
  if (dbg.level < 2) return ran;
  return Promise.resolve(ran).then(() => recordOpRun(op, store, dbg));
}

/** Record which substrate `op` produced — the substrate of its first relation output. Scalar-only
 *  ops (arrange/measure) write no relation, so they record nothing (they stay unattributed). */
function recordOpRun(op: OpSpec, store: CellStore, dbg: DebugSink): void {
  for (const w of op.writes) {
    let rel: unknown;
    try { rel = store.read(w); } catch { continue; }
    const sub = rel !== null && typeof rel === "object" && "substrate" in rel ? (rel as { substrate?: unknown }).substrate : undefined;
    if (sub === "sql" || sub === "js") {
      dbg.record("dvl_op_run", { operator_id: op.id, impl: sub });
      return;
    }
  }
}
