// ordinal: categorical → range[index]. Output range is a PARAM (color/shape/spatial), not
// baked-in color. Train builds an indexed category table; apply joins on it to get the rank.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { fcol, index } from "../../algebra/relop.js";
import { categorical } from "./types.js";
import { ordRange, ordType, out0 } from "./_shared.js";

export const ordinal = op({
  name: "ordinal",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: categorical((b): RelOp => ({ kind: "unique", col: inputCol(b, "value"), as: "value", indexed: true })),
  scheme: "tableau10", // categorical colour default (used when bound to a colour channel)
  apply: (b): RelOp => {
    const rng = ordRange(b);
    // idx from the trained fit (keyed join on value) → index into the palette
    return { kind: "derive", add: { [out0(b)]: index(rng, fcol("idx")) }, outTypes: { [out0(b)]: ordType(rng) } };
  },
  ticks: "ordinal",
});
