// The K-controller: reduces the label prefix length K when the legend's total height
// exceeds available space. Monotone descent → guaranteed convergence. Used by
// lowerLegends (Step 5) as a Controller registered on the fixpoint SCC.
import type { CellRef, CellStore } from "../../ir/cell.js";
import type { Controller, ControllerCtx } from "../../ir/controller.js";

export interface KControllerOpts {
  kCell: CellRef;
  contentTop: CellRef;
  contentBottom: CellRef;
  n: number;       // number of legend items (category count)
  itemH: number;   // item height in pixels
  pad: number;     // vertical padding
  minK: number;    // floor — never reduce below this
}

export function mkKController(opts: KControllerOpts): Controller {
  const { kCell, contentTop, contentBottom, n, itemH, pad, minK } = opts;
  return {
    name: "legend-K",
    controls: [kCell],
    step(ctx: ControllerCtx): boolean {
      const top = Number(ctx.store.read(contentTop) ?? 0);
      const bot = Number(ctx.store.read(contentBottom) ?? 0);
      const availH = Math.abs(bot - top);
      const totalH = n * itemH + 2 * pad;

      if (totalH <= availH) return true; // fits — converged

      const k = Number(ctx.store.read(kCell));
      if (k !== -1 && k <= minK) return true; // floor reached — accept

      // reduce K: first call from -1 → 12; subsequent calls decrement by 2
      const newK = k === -1 ? 12 : Math.max(minK, k - 2);
      ctx.store.write(kCell, newK, "assigned");
      return false; // changed — iterate
    },
  };
}
