// pitchX: fixed-pitch horizontal bands — one band per row, ranked by an order column, band width
// INDEPENDENT of the parent extent. The x-mirror of pitchY: N swatches laid out at a constant pixel
// pitch (a horizontal legend / toolbar row). Pure windowed derive (rank) — lowers to BOTH SQL and JS.
//   x = pad + rank·(pitch+gap)   — the band LEFT edge
//   w = pitch                     — the band width
import { inputCol, type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, lit, rank } from "../../algebra/relop.js";
import { coord, dataSpace, len, pixelSpace } from "../../types/attr.js";

interface PitchOptions {
  readonly pitch?: number; // band width in pixels (default 16)
  readonly gap?: number; // extra gap between bands (default 0)
  readonly pad?: number; // offset of the first band from the origin (default 0)
}

export const pitchX = op({
  name: "pitchX",
  inputs: { marks: [{ name: "order", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: pixelSpace(coord("x")), w: pixelSpace(len("x")) },
  inputSpaces: { order: dataSpace },
  apply: (b): RelOp => {
    const [xo, wo] = b.outputs;
    const o = (b.options ?? {}) as PitchOptions;
    const pitch = o.pitch ?? 16;
    const gap = o.gap ?? 0;
    const pad = o.pad ?? 0;
    const step = pitch + gap;
    const x = bin("+", lit(pad), bin("*", rank(inputCol(b, "value")), lit(step)));
    return { kind: "derive", add: { [xo]: x, [wo]: lit(pitch) }, outTypes: { [xo]: "double", [wo]: "double" } };
  },
});
