// Hierarchical structural ids + allocation (WUIR_IMPL §1.1; WUDESIGN §Identity).
// Paths so an id encodes its place in the hierarchy and stays stable under edits
// elsewhere. The per-row dvl_* columns are a separate tier (data layer).

export type NodeId = string; // "n0", "n0/c1"
export type PlotId = string; // "n0/p2"
export type GroupId = string; // "n0/ax-y"
export type LayoutId = string; // "n0/p2/lin-x"  (a scale carries a LayoutId)

/**
 * Deterministic id allocation, scoped per parent. Construction order fixes ids; a
 * caller-supplied `key` pins a plot segment so reordering siblings elsewhere does
 * not shift it (WUIR_IMPL §1.1 stability rule).
 */
export class IdGen {
  #roots = 0;
  #children = new Map<NodeId, number>();
  #plots = new Map<NodeId, number>();

  /** A node: top-level when `parent` is omitted, else a nested child of `parent`. */
  node(parent?: NodeId): NodeId {
    if (parent === undefined) return `n${this.#roots++}`;
    return this.child(parent);
  }

  /** A nested child node of `parent` (faceting / nesting). */
  child(parent: NodeId): NodeId {
    const n = this.#children.get(parent) ?? 0;
    this.#children.set(parent, n + 1);
    return `${parent}/c${n}`;
  }

  /** A plot in `node`; `key` pins the segment for stability across edits. */
  plot(node: NodeId, key?: string): PlotId {
    if (key !== undefined) return `${node}/${key}`;
    const n = this.#plots.get(node) ?? 0;
    this.#plots.set(node, n + 1);
    return `${node}/p${n}`;
  }

  /** A semantic group (axis/legend) in `node`; `role` is the segment, e.g. "ax-y". */
  group(node: NodeId, role: string): GroupId {
    return `${node}/${role}`;
  }

  /** A layout/scale scoped to a plot or node; `kind` is the segment, e.g. "lin-x". */
  layout(scope: PlotId | NodeId, kind: string): LayoutId {
    return `${scope}/${kind}`;
  }
}
