// Shared helpers for positional components — scales AND non-scale layouts (eqx/stack/force) that
// map an output into a range. The range/palette interpreters live here, not in the op-algebra.
import type { Scalar, SqlType } from "../../data/schema.js";
import type { OpBinding, RelOp } from "../../algebra/impl.js";
import { bin, floor, index, lit, type ScalarExpr } from "../../algebra/relop.js";
/** A categorical palette (tableau10-ish) — the fallback when no scheme is resolved. */
export const CATEGORICAL_PALETTE = ["#4e79a7", "#f28e2b", "#e15759", "#76b7b2", "#59a14f", "#edc949", "#af7aa1", "#ff9da7", "#9c755f", "#bab0ab"];
/** A sequential fallback ramp (defensive — resolveSpec normally stamps options.schemeColors). */
const SEQUENTIAL_FALLBACK = ["#f7fbff", "#c6dbef", "#6baed6", "#2171b5", "#08306b"];

export const out0 = (b: OpBinding): string => b.outputs[0];

/** Does this binding serve a colour channel (style⟨color⟩)? Then a scale emits a COLOUR, not a
 *  number — AUTOLEGEND §6, the Plot `registry.get(key)===color` decision made per binding. */
export const isColorOut = (b: OpBinding): boolean => {
  const s = b.outSpace;
  return s !== undefined && s.space === "style" && s.channel === "color";
};

/** The resolved colour palette for a colour binding (resolveSpec stamped it from the scheme name). */
export const colorRamp = (b: OpBinding): readonly string[] => {
  const c = b.options?.schemeColors;
  return Array.isArray(c) && c.length > 0 ? (c as readonly string[]) : SEQUENTIAL_FALLBACK;
};

/** A continuous scale's normalized t∈[0,1] → its output. Colour channel: index the 256-step ramp
 *  (`index(ramp, floor(t·(N-1)))`) — smooth, dual-substrate, no colour-interp primitive. Otherwise
 *  the relative t (the frame affine places positional; number channels read t directly). */
export function scaledOut(b: OpBinding, t: ScalarExpr): RelOp {
  const o = out0(b);
  if (isColorOut(b)) {
    const ramp = colorRamp(b);
    return { kind: "derive", add: { [o]: index(ramp, floor(bin("*", t, lit(ramp.length - 1)))) }, outTypes: { [o]: "varchar" } };
  }
  return { kind: "derive", add: { [o]: t }, outTypes: { [o]: "double" } };
}

// A positional output's pixel range is gone from the operator binding (NORMALIZED: apply emits relative
// [0,1]; the frame affine owns the box). `options.range` now carries only a non-positional PALETTE.
export const ordRange = (b: OpBinding): readonly Scalar[] => {
  const r = b.options?.range;
  if (Array.isArray(r)) return r as readonly Scalar[]; // explicit author override wins
  if (isColorOut(b)) return colorRamp(b); // resolved categorical scheme (tableau10 default)
  return CATEGORICAL_PALETTE;
};

export const ordType = (rng: readonly Scalar[]): SqlType => (typeof rng[0] === "number" ? "double" : "varchar");
