// The via argument grammar, shared by BOTH receivers (§8 Stage 2): PlotBuilder.via (a plot
// referent — borrow PLACED values) and Table.via (a table referent — borrow DATA values). One
// verb, one steps/resolve grammar; the receiver decides only what the f-side IS.
import type { FKRef, PathStep, ViaReduceFn, ViaResolve, ViaResolution } from "../ir/refs.js";
import type { Space } from "../types/attr.js";

/** PathStep admits bare strings (the same-column shorthand, ir/refs.ts) — parse passes them
 *  through untouched; resolveSpec desugars every Path site once (normalizePath). */
export type ViaArgs = [...PathStep[], PathStep | { resolve: ViaResolve }];

export interface ParsedVia {
  steps: PathStep[];
  /** Map keys whose resolution is COMPUTED (arg/js/bare fn) — each DECLARES a new output name. */
  computedNames: string[];
  /** The (normalized: bare fn → { js }) resolution for an output name. */
  resolveFor(name: string): ViaResolve | undefined;
  /** A computed output's declared Space, if the resolution carries one. */
  declaredSpace(name: string): Space | undefined;
}

const isComputed = (r: unknown): boolean => typeof r === "function" || (typeof r === "object" && r !== null && ("arg" in r || "js" in r));

/** Split trailing options off the steps, validate the single/computed combination, and expose
 *  normalized per-output resolutions. A COMPUTED resolution mints a NEW derived quantity outside
 *  the referent's output namespace, so it must be DECLARED under a fresh output name — the map
 *  key is its declaration site (§3c); the single form is rejected because there would be no
 *  well-defined name to pick it by. */
export function parseViaArgs(site: string, args: ViaArgs): ParsedVia {
  const last = args[args.length - 1];
  // a string is always a STEP, never options (also: JS's `in` throws on a string operand).
  const hasOpts = last !== undefined && typeof last !== "string" && !("op" in last) && !("kind" in last && (last as FKRef).kind === "fk");
  const steps = (hasOpts ? args.slice(0, -1) : args) as PathStep[];
  const resolve = hasOpts ? (last as { resolve: ViaResolve }).resolve : undefined;
  const isSingle = typeof resolve === "string" || typeof resolve === "function" || (typeof resolve === "object" && resolve !== null && ("fn" in resolve || "js" in resolve || "arg" in resolve));
  if (isSingle && isComputed(resolve)) {
    throw new Error(`${site}: a computed resolution (arg/js) defines a NEW output — name it in the map form: { resolve: { spend: { fn, arg } } } or { resolve: { far: (matches, mark) => … } }, then pick by that name`);
  }
  const resolveMap = !isSingle && typeof resolve === "object" && resolve !== null ? (resolve as Record<string, ViaResolve | ViaReduceFn>) : undefined;
  const computedNames = resolveMap !== undefined ? Object.keys(resolveMap).filter((k) => isComputed(resolveMap[k])) : [];
  const norm = (r: ViaResolve | ViaReduceFn | undefined): ViaResolve | undefined => (typeof r === "function" ? { js: r } : r);
  return {
    steps,
    computedNames,
    resolveFor: (name) => norm(resolve === undefined || isSingle ? resolve : resolveMap![name]),
    declaredSpace(name) {
      const r = norm(resolveMap?.[name]);
      return typeof r === "object" && r !== null ? (r as ViaResolution).space : undefined;
    },
  };
}
