// The propagation arrange solver (C6, WULAYOUT_IMPL §C6 — "ship propagation first"). It resolves
// REQUIRED EQUALITIES by fixpoint: repeatedly find a constraint with exactly one unknown edge,
// solve it, seal it, repeat. That covers the split/grid/inset shapes whose constraint graph is a
// propagation DAG (each unknown determined by knowns) — no simplex. Strong/weak preferences and
// inequalities are Cassowary's job; this solver leaves them for that swap-in.
// A constraint's coef/const may be a CELL (a read-only PARAMETER, §C6): resolved at solve time, so a
// cell-weighted term is linear THIS sweep (the fixpoint closes the loop). A parameter that reads
// undefined (unbound / an unsolved owned cell) makes the constraint not-yet-ready — deferred, as an
// unknown edge is.
import type { ArrangeSolver, Param } from "../../ir/layout.js";
import type { CellRef } from "../../ir/cell.js";

const asNumber = (v: unknown): number | undefined => (typeof v === "number" ? v : undefined);

export const propagation: ArrangeSolver = (constraints, cells, owned = []) => {
  // `owned` cells are RECOMPUTED this call (the calling op's writes): their stale values are invisible
  // until re-solved, so an SCC re-run re-derives them from the current inputs (Gauss-Seidel).
  const ownedSet = new Set<CellRef>(owned);
  const solved = new Map<CellRef, number>(); // owned cells solved THIS call
  const val = (edge: CellRef): number | undefined => solved.get(edge) ?? (ownedSet.has(edge) ? undefined : asNumber(cells.read(edge)));
  // a PARAMETER (coef / constant): a literal, or a cell read as a solver INPUT — never an unknown.
  const param = (p: Param): number | undefined => (typeof p === "number" ? p : val(p));

  // The naive tier's ONE softness rule (WULAYOUT_IMPL §C6 demand loop): a STRONG 2-term ±1 equality
  // is a DEFAULT (a margin inset), TIGHTENED by every `≥` lower bound over the same edge pair whose
  // remaining terms are readable (a measured demand cell, a constant reservation), then propagated as
  // required. Everything else soft/inequality is left for Cassowary, which replaces this rule wholesale.
  const pairOf = (c: (typeof constraints)[number]): string | undefined => {
    if (c.terms.length < 2) return undefined;
    const [t0, t1] = c.terms;
    if (t0.coef === 1 && t1.coef === -1) return `${t0.edge}|${t1.edge}`;
    if (t0.coef === -1 && t1.coef === 1) return `${t1.edge}|${t0.edge}`;
    return undefined;
  };
  const bounds = new Map<string, number>(); // pair → the tightest readable lower bound
  const cellBounds = new Map<CellRef, number>(); // single cell → its tightest readable lower bound
  for (const c of constraints) {
    if (c.op !== ">=") continue;
    // single-cell bound (a TEMPLATE gutter, §C8: `inset − demand ≥ 0`): first term +1·cell, every
    // remaining term readable ⇒ cell ≥ constant − Σ rest. Tightens the strong 1-TERM inset default
    // exactly as the pair bound tightens a scalar margin equality.
    if (c.terms[0]?.coef === 1) {
      let kk = param(c.constant);
      if (kk !== undefined) {
        let ok = true;
        for (const t of c.terms.slice(1)) {
          const v = val(t.edge);
          const co = param(t.coef);
          if (v === undefined || co === undefined) { ok = false; break; }
          kk -= co * v;
        }
        if (ok) cellBounds.set(c.terms[0].edge, Math.max(cellBounds.get(c.terms[0].edge) ?? -Infinity, kk));
      }
    }
    const key = pairOf(c);
    if (key === undefined) continue;
    let k = param(c.constant); // pair ≥ constant − Σ coef·val(other terms)
    if (k === undefined) continue;
    let readable = true;
    for (const t of c.terms.slice(2)) {
      const v = val(t.edge);
      const co = param(t.coef);
      if (v === undefined || co === undefined) {
        readable = false;
        break;
      }
      k -= co * v;
    }
    if (readable) bounds.set(key, Math.max(bounds.get(key) ?? -Infinity, k));
  }

  let pending = constraints.flatMap((c) => {
    if (c.op !== "=") return [];
    if (c.strength === "required") return [c];
    if (c.strength === "strong" && c.terms.length === 2) {
      const b = bounds.get(pairOf(c) ?? "");
      const base = param(c.constant);
      return [b !== undefined && base !== undefined && b > base ? { ...c, constant: b } : c]; // the tightened default
    }
    if (c.strength === "strong" && c.terms.length === 1 && c.terms[0].coef === 1) {
      // a strong 1-term DEFAULT (a template's `inset = margin`, §C8) tightened by its cell bounds.
      const b = cellBounds.get(c.terms[0].edge);
      const base = param(c.constant);
      return [b !== undefined && base !== undefined && b > base ? { ...c, constant: b } : c];
    }
    return []; // other soft equalities await Cassowary
  });

  let progress = true;
  while (progress && pending.length > 0) {
    progress = false;
    const next: typeof pending = [];
    for (const c of pending) {
      const unknown = c.terms.filter((t) => val(t.edge) === undefined);
      // ready iff exactly one unknown EDGE and every parameter (coef/constant) resolves this sweep.
      const k = param(c.constant);
      const paramsReady = k !== undefined && c.terms.every((t) => param(t.coef) !== undefined);
      if (unknown.length === 1 && paramsReady) {
        const u = unknown[0];
        const rest = c.terms.reduce((s, t) => (t === u ? s : s + (param(t.coef) as number) * (val(t.edge) as number)), 0);
        const v = (k - rest) / (param(u.coef) as number);
        cells.write(u.edge, v, "assigned"); // the OPERATOR contract: run() assigns, the scheduler seals
        solved.set(u.edge, v);
        progress = true;
      } else if (unknown.length > 1 || (unknown.length === 1 && !paramsReady)) {
        next.push(c); // not yet resolvable — a later round may free an edge or a parameter cell
      }
      // 0 unknowns ⇒ already determined (consistency-checking soft/over-constrained cases is Cassowary's)
    }
    if (progress) pending = next;
    else break; // no edge freed this round — a param cell may still be pending; the fixpoint retries the op
  }
  // pending left ⇒ under-constrained by propagation alone (≥2 unknowns, or a param cell not yet produced)
  // — a genuine solver case (Cassowary) or a later fixpoint sweep. Silent; the scheduler's empty-cell
  // check surfaces anything that never resolves.
};
