// DuckDB-Wasm backend adapter (WUDATA §1, WUDATA_IMPL §2).
//
// The library stays free of @duckdb/duckdb-wasm imports: the adapter is built over
// a minimal structural connection (`DuckDBConn`) the app supplies — `exec` wraps
// the real AsyncDuckDBConnection (query + Arrow→rows), and an optional
// `insertColumnar` provides the zero-copy fast path. Most of the Backend is just
// dialect-SQL generation over `exec`, which keeps it testable without a live DB.

import type { Backend, Columnar, Prepared, TableStats } from "./backend.js";
import { defaultDialect, type Dialect } from "./dialect.js";
import type { FKEdge } from "./fk.js";
import type { RelationName } from "./ids.js";
import type { Json, JsonRow, RawRow, Row, Scalar, Schema, SqlType } from "./schema.js";

export interface DuckDBConn {
  /** Execute SQL, returning rows as plain objects (Arrow→rows done by the app). */
  exec(sql: string, params?: readonly Scalar[]): Promise<readonly RawRow[]>;
  /** Optional zero-copy columnar ingestion (Arrow/typed arrays). */
  insertColumnar?(name: string, cols: Columnar): Promise<void> | void;
  /** Optional JSON ingestion for nested rows (DuckDB parses the nesting). */
  insertJSON?(name: string, rows: readonly JsonRow[]): Promise<void> | void;
}

export class DuckDBBackend implements Backend {
  readonly dialect: Dialect;
  private readonly conn: DuckDBConn;
  readonly #loadedExtensions = new Set<string>();

  constructor(conn: DuckDBConn, dialect: Dialect = defaultDialect) {
    this.conn = conn;
    this.dialect = dialect;
  }

  run(sql: string, params?: readonly Scalar[]): Promise<readonly RawRow[]> {
    return this.conn.exec(sql, params);
  }

  /** INSTALL + LOAD each DuckDB extension once (memoized). A load failure THROWS — a geometry
   *  resolver that declared it (convex → spatial) has no silent JS fallback; the caller must fix
   *  the environment (network for INSTALL, or a bundled extension) or use the JS escape hatch. */
  async ensureExtensions(names: readonly string[]): Promise<void> {
    for (const name of names) {
      if (this.#loadedExtensions.has(name)) continue;
      try {
        await this.conn.exec(`INSTALL ${name};`);
        await this.conn.exec(`LOAD ${name};`);
      } catch (e) {
        throw new Error(`DuckDB extension "${name}" could not be loaded (INSTALL/LOAD failed): ${e instanceof Error ? e.message : String(e)}. It is required by a SQL-pushed operator; provide network access for INSTALL, bundle the extension, or use the JS resolver form ({ js: (matches, mark) => … }).`);
      }
      this.#loadedExtensions.add(name);
    }
  }

  async prepare(sql: string): Promise<Prepared> {
    const conn = this.conn;
    // A conn impl may cache prepared statements keyed by sql for the perf win.
    return {
      run: (params: readonly Scalar[]) => conn.exec(sql, params),
      close: () => {},
    };
  }

  async registerRows(name: RelationName, rows: readonly JsonRow[]): Promise<void> {
    const d = this.dialect;
    if (rows.length === 0) {
      await this.conn.exec(`CREATE OR REPLACE TABLE ${d.ident(name)} AS SELECT NULL WHERE 1 = 0`);
      return;
    }
    const cols = Object.keys(rows[0]);

    // Nested values (JSON-loaded data) can't go through scalar VALUES literals;
    // let DuckDB parse them via JSON ingestion.
    if (rows.some((r) => cols.some((c) => isNested(r[c])))) {
      if (this.conn.insertJSON === undefined) {
        throw new Error(
          `registerRows("${name}"): nested values need a JSON-ingestion conn (conn.insertJSON); flat rows use VALUES`,
        );
      }
      await this.conn.insertJSON(name, rows);
      return;
    }

    const values = rows
      .map((r) => `(${cols.map((c) => d.literal((r[c] ?? null) as Scalar)).join(", ")})`)
      .join(", ");
    const colList = cols.map((c) => d.ident(c)).join(", ");
    await this.conn.exec(
      `CREATE OR REPLACE TABLE ${d.ident(name)} AS SELECT * FROM (VALUES ${values}) AS _t(${colList})`,
    );
  }

  async registerColumnar(name: RelationName, cols: Columnar): Promise<void> {
    if (this.conn.insertColumnar !== undefined) {
      await this.conn.insertColumnar(name, cols); // zero-copy path
      return;
    }
    // Fallback: pivot columns → rows, then register.
    const keys = Object.keys(cols);
    const len = keys.length === 0 ? 0 : cols[keys[0]].length;
    const rows: Row[] = [];
    for (let i = 0; i < len; i++) {
      const r: Record<string, Scalar> = {};
      for (const k of keys) r[k] = cols[k][i] as Scalar;
      rows.push(r);
    }
    await this.registerRows(name, rows);
  }

  async registerView(name: RelationName, sql: string): Promise<void> {
    await this.conn.exec(`CREATE OR REPLACE VIEW ${this.dialect.ident(name)} AS (${sql})`);
  }

  async materialize(name: RelationName, sql: string, params?: readonly Scalar[]): Promise<TableStats> {
    const d = this.dialect;
    await this.conn.exec(`CREATE OR REPLACE TABLE ${d.ident(name)} AS ${sql}`, params);
    const stat = (
      await this.conn.exec(
        `SELECT estimated_size AS bytes, (SELECT count(*) FROM ${d.ident(name)}) AS rows ` +
          `FROM duckdb_tables() WHERE table_name = ${d.literal(name)}`,
      )
    )[0];
    return {
      rowCount: Number(stat?.["rows"] ?? 0),
      byteSize: Number(stat?.["bytes"] ?? 0),
    };
  }

  async drop(name: RelationName): Promise<void> {
    await this.conn.exec(`DROP TABLE IF EXISTS ${this.dialect.ident(name)}`);
  }

  async dropView(name: RelationName): Promise<void> {
    await this.conn.exec(`DROP VIEW IF EXISTS ${this.dialect.ident(name)}`);
  }

  async introspectSchema(name: RelationName): Promise<Schema> {
    const rows = await this.conn.exec(`DESCRIBE ${this.dialect.ident(name)}`);
    return rows.map((r) => ({
      name: String(r["column_name"]),
      type: mapDuckType(String(r["column_type"])),
    }));
  }

  async introspectFKs(): Promise<readonly FKEdge[]> {
    const rows = await this.conn.exec(
      `SELECT table_name, constraint_column_names, referenced_table, referenced_column_names ` +
        `FROM duckdb_constraints() WHERE constraint_type = 'FOREIGN KEY'`,
    );
    return rows.map((r) => ({
      fromTable: String(r["table_name"]),
      fromCols: asStringArray(r["constraint_column_names"]),
      toTable: String(r["referenced_table"]),
      toCols: asStringArray(r["referenced_column_names"]),
    }));
  }
}

export function mapDuckType(t: string): SqlType {
  const u = t.toUpperCase();
  // nested first: "INTEGER[]" / "STRUCT(...)[]" contain scalar substrings.
  if (u.endsWith("[]") || /\bLIST\b|\bARRAY\b/.test(u)) return "list";
  if (/\bSTRUCT\b|\bMAP\b|\bROW\b/.test(u)) return "struct";
  if (/JSON/.test(u)) return "json";
  if (/DOUBLE|FLOAT|REAL|DECIMAL|NUMERIC/.test(u)) return "double";
  if (/BOOL/.test(u)) return "bool";
  if (/DATE|TIME|TIMESTAMP/.test(u)) return "date";
  if (/CHAR|TEXT|STRING|VARCHAR/.test(u)) return "varchar";
  if (/BLOB|BYTEA|BINARY/.test(u)) return "blob";
  if (/INT\b|INTEGER|HUGEINT|BIGINT|SMALLINT|TINYINT/.test(u)) return "int";
  return "unknown";
}

function isNested(v: Json | undefined): boolean {
  return v !== null && typeof v === "object"; // array or object
}

function asStringArray(v: unknown): readonly string[] {
  if (Array.isArray(v)) return v.map((x) => String(x));
  if (typeof v === "string") {
    const trimmed = v.replace(/^[[{]|[\]}]$/g, "");
    return trimmed.length === 0 ? [] : trimmed.split(",").map((s) => s.trim().replace(/^['"]|['"]$/g, ""));
  }
  return [];
}
