// dag (layered DAG): the compute-graph placement extracted from debug/graph-svg.ts —
// Sugiyama-lite. Three steps: (1) LAYER by longest path from the roots (a node sits one
// layer below its deepest parent; back-edges in a cycle count 0 — never infinite), (2) ORDER
// each layer by the barycenter of its parents' positions in the layer above (one downward
// sweep — crossing reduction without the full iterative Sugiyama), (3) CENTER each layer's
// row around x = 0.5 with a uniform step scaled to the widest layer.
//
// Same contract shape as force: marks + an aux `edges` relation (src → dst FKs onto marks.id),
// NORMALIZED relative x/y out (the frame affine places them). Flow is top-down: roots at
// y = pad, deepest layer at y = 1 − pad. js-only Exec (an ordering algorithm over the whole
// node set — like fitText, there is no meaningful SQL form).
import { inputCol, jsImpl, type ExecCtx, type OpBinding } from "../../algebra/impl.js";
import { type PlanIO } from "../../operator/binding.js";
import { op } from "../../operator/operator.js";
import { mkFrag, type JsRel } from "../../algebra/relation.js";
import type { OpSpec } from "../../plan/opspec.js";
import { coord, dataSpace, relativeSpace } from "../../types/attr.js";

/** One directed edge, by node id. */
export interface DagEdge {
  src: string;
  dst: string;
}

/** The pure core, shared with debug/graph-svg.ts: layer + order a DAG.
 *  Returns the layers in flow order, each an ORDERED list of node ids.
 *  Edges touching unknown ids are ignored; a cycle's back-edge contributes layer 0. */
export function layerDag(ids: readonly string[], edges: readonly DagEdge[]): string[][] {
  const known = new Set(ids);
  const radj = new Map<string, Set<string>>(ids.map((id) => [id, new Set()]));
  for (const e of edges) {
    if (known.has(e.src) && known.has(e.dst) && e.src !== e.dst) radj.get(e.dst)!.add(e.src);
  }

  // (1) longest-path layering, memoized; `visiting` breaks cycles (back-edge → 0).
  const layer = new Map<string, number>();
  const visiting = new Set<string>();
  const layerOf = (id: string): number => {
    const memo = layer.get(id);
    if (memo !== undefined) return memo;
    if (visiting.has(id)) return 0;
    visiting.add(id);
    const parents = radj.get(id)!;
    const l = parents.size === 0 ? 0 : Math.max(...[...parents].map(layerOf)) + 1;
    visiting.delete(id);
    layer.set(id, l);
    return l;
  };
  for (const id of ids) layerOf(id);

  const byLayer: string[][] = [];
  for (const id of ids) {
    const l = layer.get(id)!;
    (byLayer[l] ?? (byLayer[l] = [])).push(id); // input order = initial order within the layer
  }
  // A cycle can leave a hole (its members memoize mid-visit at shifted depths) — compact, so
  // consumers can rely on contiguous, non-empty layers.
  const layers = byLayer.filter((row) => row !== undefined && row.length > 0);

  // (2) one downward barycenter sweep: order layer l by the mean position of parents in l−1.
  for (let l = 1; l < layers.length; l++) {
    const prevPos = new Map(layers[l - 1].map((id, i) => [id, i]));
    const bary = (id: string): number => {
      const ps = [...radj.get(id)!].filter((p) => prevPos.has(p));
      return ps.length === 0 ? 0 : ps.reduce((s, p) => s + prevPos.get(p)!, 0) / ps.length;
    };
    layers[l].sort((a, b) => bary(a) - bary(b));
  }
  return layers;
}

export const dag = op({
  name: "dag",
  // No domain: no train — self-contained placement (like force). Positions carry no
  // data-space meaning, so there is nothing an axis could tick.
  inputs: { marks: [{ name: "id", type: "int" }], edges: [{ name: "src", type: "int" }, { name: "dst", type: "int" }] },
  refs: [{ from: "edges.src", to: "marks.id" }, { from: "edges.dst", to: "marks.id" }],
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "y", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), y: relativeSpace(coord("y")) },
  inputSpaces: { id: dataSpace },
  // In a template, dag runs PER CELL by default: one layered graph per panel.
  perCell: true,
  // ONE ordinary apply op (custom plan, same as force): reads the marks, writes the augmented
  // marks; the edges aux relation rides binding.inputs. io.key rides payload.by when templated.
  plan: (io: PlanIO): OpSpec[] => {
    if (io.marksIn === undefined) throw new Error("dag: applies over input marks (PlanIO.marksIn)");
    return [{ id: `${io.id}:apply`, reads: [io.marksIn], writes: [io.marksOut], payload: { kind: "apply", algoName: "dag", binding: io.binding, ...(io.key !== undefined && { by: io.key }) } }];
  },
  exec: { js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    const [xo, yo] = b.outputs;
    const idCol = inputCol(b, "value"); // the marks id column (the primary input)
    const edgesRef = b.inputs.edges;

    // endpoint columns come from the binding's RESOLVED refs (instance `on` override or the
    // declaration above); the fallback mirrors the declaration for hand-built bindings.
    const refPairs = b.refs?.edges ?? [{ from: "src", to: "id" }, { from: "dst", to: "id" }];
    if (refPairs.length < 2) throw new Error(`dag "${b.key}": needs two edge endpoint refs (got ${refPairs.length})`);
    const [srcCol, dstCol] = [refPairs[0].from, refPairs[1].from];

    // materialize the aux edges relation (a base table today; empty ⇒ every node is a root).
    const edgeRows: readonly Record<string, unknown>[] =
      typeof edgesRef === "string" ? await ctx.run(mkFrag(`${b.key}:edges`, "SELECT * FROM @e AS m", { e: { base: edgesRef } }, { columns: [{ name: srcCol, type: "unknown" }, { name: dstCol, type: "unknown" }] })) : [];

    // normalize ids to STRINGS on both sides (BigInt vs Number vs VARCHAR — one key space).
    const ids = marks.rows.map((r) => String(r[idCol]));
    const edges: DagEdge[] = edgeRows.map((e) => ({ src: String(e[srcCol]), dst: String(e[dstCol]) }));

    const layers = layerDag(ids, edges);

    // (3) NORMALIZED positions in [pad, 1−pad]: y = the layer — roots at y = 1−pad, which the
    // frame affine (y-up, chart convention) renders at the TOP, so flow reads top→down. x = the
    // node's slot in its layer's row, rows centered on 0.5 with ONE step shared across layers
    // (the widest layer spans the full width — uniform density, matching the debug renderer's
    // centered variable-width rows under uniform node size).
    const pad = 0.05;
    const maxLayer = layers.length - 1;
    const widest = Math.max(...layers.map((row) => row.length));
    const step = widest > 1 ? (1 - 2 * pad) / (widest - 1) : 0;
    const pos = new Map<string, { x: number; y: number }>();
    layers.forEach((row, l) => {
      const y = maxLayer === 0 ? 0.5 : 1 - pad - (1 - 2 * pad) * (l / maxLayer);
      row.forEach((id, i) => pos.set(id, { x: 0.5 + (i - (row.length - 1) / 2) * step, y }));
    });

    return {
      rows: marks.rows.map((r, i) => ({ ...r, [xo]: pos.get(ids[i])!.x, [yo]: pos.get(ids[i])!.y })),
      schema: [...marks.schema, { name: xo, type: "double" }, { name: yo, type: "double" }],
    };
  }) },
});
