// nice-linear: ticks at nice round values across the domain [min, max] (reads the domain).
import type { Tick, TickAlgo } from "../../operator/ticks.js";
import { clean, fmt, niceStep } from "./_shared.js";

export const niceLinear: TickAlgo = {
  name: "nice-linear",
  over: "domain",
  js({ params }, ctx) {
    const min = Number(params.min);
    const max = Number(params.max);
    const count = ctx.count;
    if (!Number.isFinite(min) || !Number.isFinite(max) || min === max) return [{ idx: 0, value: clean(min), label: fmt(min) }];
    const step = niceStep(min, max, count);
    const out: Tick[] = [];
    let i = 0;
    for (let v = Math.ceil(min / step) * step; v <= max + step * 1e-9; v += step) {
      const r = clean(v);
      out.push({ idx: i++, value: r, label: fmt(r) });
    }
    return out;
  },
};
