import { emitVerify, fillChildExtentHoles } from "../layout/arrange.js";
import { validate } from "../api/validate.js";
import { compileNode } from "../plan/compile/node.js";
import { emitGatherScatter, planDomainGroups } from "../plan/compile/domains.js";
import { type PlotBuild, type RenderOpts, type TemplateCtx } from "../plan/compile/context.js";
import { emitAxisMerge, lowerAxes } from "../plan/passes/lower-axes.js";
import { lowerLegends } from "../plan/passes/lower-legends.js";
import { lowerStrips } from "../plan/passes/lower-strips.js";
import { allocScaleExpansion, emitScaleOverhang } from "../plan/passes/scale-expansion.js";
