export type { RenderOpts } from "../plan/compile/context.js";

/** Normalize an Observable-Plot-style `number | {per-side}` to four sides. */
function sides(v: number | { left?: number; right?: number; top?: number; bottom?: number } | undefined): { left: number; right: number; top: number; bottom: number } | undefined {
  if (v === undefined) return undefined;
  if (typeof v === "number") return { left: v, right: v, top: v, bottom: v };
  return { left: v.left ?? 0, right: v.right ?? 0, top: v.top ?? 0, bottom: v.bottom ?? 0 };
}

/** Fold canvas-level options (defaults) under a render-time RenderOpts (overrides). Only fills
 *  fields the caller left unset; `margin`/`inset` are normalized from Plot's number|per-side form. */
function mergeCanvasOpts(canvas: CanvasOpts | undefined, opts: RenderOpts): RenderOpts {
  if (canvas === undefined) return opts;
  return {
    ...opts,
    margin: opts.margin ?? sides(canvas.margin),
    inset: opts.inset ?? sides(canvas.inset),
    background: opts.background ?? canvas.background,
  };
}

/** The compiled vis: the logical op graph (arrange + plot pipelines + the render sink) + the sink cell. */
export interface CompiledVis {
  specs: OpSpec[];
  svgCell: CellRef;
  /** Index into `specs` where global passes begin (gather-scatter, axis-merge, verify, render). */
  globalStart: number;
  /** Legend/adornment controllers (k-controller shrink, …) threaded to the scheduler. */
  controllers: Controller[];
}

/** Compile the WHOLE vis: lower axes to plots (idempotent), walk the node tree (a node, then its
 *  nested children) compiling each, then describe the render sink over every plot's final marks.
 *  Pure planning — descriptions only; the scheduler decides when everything (arrange included) runs. */
export function compileSpec(spec: Spec, registries: Registries, opts: RenderOpts = {}): CompiledVis {
  // Canvas-level chart options (set at canvas(...)) are the DEFAULTS; a render-time RenderOpts
  // overrides them per call. Merge once here so downstream passes read a single effective opts.
  opts = mergeCanvasOpts(spec.canvas, opts);
  // Profiling (explainer §2c): the pass list is static, so wrapping each call IS the
  // compile-side instrumentation — record at pass boundaries, never mid-pass (WUDEBUG §3).
  const dbg = opts.debug ?? NULL_SINK;
  const pass = <T>(name: string, body: () => T): T => dbg.span(name, { kind: "pass", pass: name } as SpanAttrs, body);
  // §1/§4: arm the author-facing checks. FIRST pass, before any lowering: at this point the spec
  // holds exactly the AUTHOR's plots — the axis/legend/strip plots minted below are framework
  // output and never held to author rules. Default = throw (an unknown channel is a build error,
  // never a silently-dropped channel and a blank plot); `strict: false` demotes to warnings.
  pass("validate", () => validate(spec, registries, opts.strict === false ? (w) => console.warn(`dvl validate: ${w.message}`) : undefined));
  pass("lower-axes", () => lowerAxes(spec, registries, { tickCount: opts.tickCount, strict: opts.strict })); // axes → plots (idempotent)
  const { controllers } = pass("lower-legends", () => lowerLegends(spec, registries)); // legends → ordinary plots over V (AUTOLEGEND §0 G0); before resolveSpec so the minted instances/plots resolve
  pass("lower-strips", () => lowerStrips(spec, registries)); // facet strips → text over the panels table + a reserved band (mirror of an axis)
  pass("lift-via-exprs", () => liftViaExprs(spec)); // §3.3 B1: relational leaves out of arithmetic — BEFORE resolve, so minted channels get stamped (idempotent)
  pass("resolve", () => resolveSpec(spec, registries, { strictMultiplicity: opts.strictMultiplicity })); // resolve-once (§2.3): AFTER spec-mutating lowerings, BEFORE any compile — downstream never touches a registry
  pass("assert-resolved-paths", () => assertResolvedPaths(spec)); // resolver totality (VIA_HARDENING §1.3): every Path site is stamped, or throw naming the site
  // Containment expansion (scale-expansion §4): positional scales serving extent-bearing author
  // marks get relative slack cells BEFORE the walk (the affine lerps through them); the overhang
  // measure that writes them is emitted AFTER the walk, once every member's box relation exists.
  pass("scale-expansion", () => allocScaleExpansion(spec));
  const specs: OpSpec[] = [];
  const plots: { plot: PlotId; marks: CellRef }[] = [];
  // §C6 gather-scatter: domain sharing is planned ONCE over the whole spec (identity groups span
  // nodes — sibling subplots binding the same quantity); each compileNode collects its members'
  // contributions into this shared plan, and the group ops are emitted after the walk.
  const domains = planDomainGroups(spec);
  const builds = new Map<PlotId, PlotBuild>(); // host lookups for TEMPLATE children (§C8)
  const visit = (nodeId: NodeId, template?: TemplateCtx): void => {
    const node = spec.nodes.get(nodeId);
    if (node === undefined) return;
    const built = compileNode(spec, nodeId, opts, domains, template);
    specs.push(...built.specs);
    for (const p of built.plots) {
      plots.push({ plot: p.pid, marks: p.marks });
      builds.set(p.pid, p);
    }
    for (const c of node.children) {
      // a data-driven child (§C8, no hostRow) compiles as a TEMPLATE: pass the HOST plot's cells
      // (base for the cell-key join; placed marks = the box relation) + the nest's default join.
      if (c.hostRow === undefined) {
        const host = builds.get(c.hostPlot);
        if (host === undefined) throw new Error(`compileSpec: template child "${c.node}" hosted by uncompiled plot "${c.hostPlot}"`);
        // §C8 ruling: a box-less host is NOT auto-placed — authors specify channel mappings
        // (synthesizing them is a future recommender/optimizer's job). Fail clearly at compile
        // instead of opaquely in SQL (the keyed affine would find no box columns to join).
        const hostChannels = spec.plots.get(c.hostPlot)!.channels;
        const missing = ["x", "y", "w", "h"].filter((ch) => hostChannels[ch] === undefined);
        if (missing.length > 0) throw new Error(`compileSpec: host plot "${c.hostPlot}" of template child "${c.node}" has no box channel(s) ${missing.join(", ")} — bind a layout (e.g. band over the nest key) or literals to place the panels`);
        const resolved = c.nest?.resolved ?? [];
        // §C8 7b: per-cell tick counts read each panel's own box — lowering set `countFrom` on the
        // template's V instances; only compile knows the host's placed-marks CELL, so inject it here
        // (before the child compiles — its producer plans read these options).
        // Capability-based: any instance under this child with `countFrom` needs the boxes cell,
        // regardless of descriptor name (today only vtable, but the signal is the option, not the name).
        for (const inst of spec.layouts.values()) {
          if (inst.id.startsWith(`${c.node}/`) && inst.options?.countFrom !== undefined) {
            inst.options = { ...inst.options, boxes: host.marks };
          }
        }
        visit(c.node, { hostBase: host.base, hostMarks: host.marks, resolved });
      } else {
        visit(c.node);
      }
    }
  };
  if (spec.root !== undefined) pass("compile-nodes", () => visit(spec.root!));
  // LATE-BOUND plot references (perCell explainer §7e F2): a top-level frame layer (or via)
  // may reference a plot compiled AFTER it — its referent lives in a child node the walk
  // reaches later. compilePlot emits placeholder reads; patch them now every plot is built.
  for (let i = 0; i < specs.length; i++) {
    const sp = specs[i];
    let changed = false;
    const reads = sp.reads.map((r) => {
      if (r.startsWith("$plot-keyed:")) {
        const pid = r.slice("$plot-keyed:".length) as PlotId;
        const b = builds.get(pid);
        if (b?.keyed === undefined) throw new Error(`compileSpec: frame references plot "${pid}", which carries no dvl_cell (not nested under a template)`);
        changed = true;
        return b.keyed;
      }
      if (r.startsWith("$plot-boxed:")) {
        const pid = r.slice("$plot-boxed:".length) as PlotId;
        const b = builds.get(pid);
        if (b?.boxed === undefined) throw new Error(`compileSpec: a box borrow references plot "${pid}" but its box fork was never emitted — desugarRouteInputs must set needsBox at bind (compiler bug)`);
        changed = true;
        return b.boxed;
      }
      if (r.startsWith("$ref:")) {
        const pid = r.slice("$ref:".length) as PlotId;
        const b = builds.get(pid);
        if (b === undefined) throw new Error(`compileSpec: via references unknown plot "${pid}"`);
        changed = true;
        return b.marks;
      }
      return r;
    });
    if (changed) specs[i] = { ...sp, reads };
  }
  pass("overhang", () => emitScaleOverhang(spec, builds, specs)); // scale-expansion §4: one measure op per live scale
  const globalStart = specs.length;
  pass("gather-scatter", () => emitGatherScatter(spec, domains, specs)); // one op per shared group: contributions → every member's domain
  pass("axis-merge", () => emitAxisMerge(spec, domains, specs)); // §C6: sibling axes over one quantity — aligned ⇒ one axis speaks for all
  pass("extent-holes", () => fillChildExtentHoles(spec, specs, domains)); // §C6/§C8: unwritten child extents → declare + realize (row/column inferred from sharing)
  pass("verify", () => emitVerify(spec, specs)); // §C6: check the hard declarations post-solve — violations become diagnostics DATA
  pass("required-columns", () => propagateRequiredColumns(specs)); // §2.4: stamp each mark table with the columns foreign join
  // edges demand of it — the single authority for cross-relation column survival. Runs after every
  // op is emitted, before the optimizer (downstream) can fuse/DCE columns away.

  const root = spec.nodes.get(spec.root ?? "");
  if (root === undefined) throw new Error("compileSpec: spec has no root node");
  const svgCell = spec.cells.alloc("sink", undefined, "scalar", sceneSpace);
  // the render sink — an ordinary DESCRIPTION: gated on every plot's final marks + the canvas cells.
  specs.push({
    id: "render",
    reads: [...plots.map((p) => p.marks), root.extent.outer.right, root.extent.outer.bottom],
    writes: [svgCell],
    payload: { kind: "render", plots, widthCell: root.extent.outer.right, heightCell: root.extent.outer.bottom, background: opts.background },
  });
  // W2/W3: verify declared outSpaces against inference; check plan-level space invariants.
  // Wired lax (D-W): B2 trust boundary and orient-undefined lens are open — strict enforcement
  // deferred until those are resolved; lax warns and counts, never silent.
  const prevStrict = dvlSettings.strict;
  dvlSettings.strict = false;
  pass("check-plan", () => {
    verifyRelopSpaces(specs, spec.cells);
    checkPlan(specs, spec, registries.operators);
  });
  dvlSettings.strict = prevStrict;

  return { specs, svgCell, globalStart, controllers };
}

// The `plotId` arg is retained for signature compatibility; renderSpec renders the WHOLE spec.
/** The driver: compile the vis, lower to runnables, schedule, read the sink. */
export async function renderSpec(spec: Spec, registries: Registries, plotId: PlotId, db: Database, opts: RenderOpts = {}): Promise<string> {
  void plotId;
  // Profiling (explainer §2): one run per render; the sink buffers in JS during the run
  // and flushes after the sink cell is read, so recording never perturbs the measurement.
  const dbg = opts.debug ?? NULL_SINK;
  if (dbg.level >= 0) await dbg.beginRun({ root: spec.root, mode: "render" });
  const { specs: compiled, svgCell, controllers } = dbg.span("compile", { kind: "pass", pass: "compile" }, () => compileSpec(spec, registries, opts));
  // The dataflow log (dvl_operator/dvl_op_io) is recorded at EVERY phase — same schema, keyed by
  // `pass`, differing only by which graph it is (design/2026-07-22 §1). Pre-optimize (compile) has
  // no substrate stamp (impl NULL); post-optimize + execute carry payload.substrate. record()
  // self-gates on the sink level (dvl_operator is level 1), so all three are free with debug off.
  recordGraph(compiled, "compile", dbg, registries);
  // Phase 4a (simplification §12): the optimizer runs on every render. Advisory-first — handlers
  // still adapt at run time; 4c makes the substrate choices binding.
  const specs = dbg.span("optimize", { kind: "pass", pass: "optimize" }, () => optimize(compiled, spec.cells as never, registries.ops));
  recordGraph(specs, "optimize", dbg, registries);
  // The fragment runner binds {ref} holes from the LIVE cell store at emit time — the cell-leaf
  // (P4a) fixpoint contract: a fragment's structure is stable across iterations; the affine's
  // extent values re-bind on every run. Reading lazily (at emit, not closure creation) is the point.
  const cellEnv = {
    get: (id: string) => {
      const v = spec.cells.read(id);
      return v === undefined ? undefined : { kind: "literal" as const, value: v as Scalar }; // undefined ⇒ emit throws "unbound cell" — loud, not NULL
    },
  };
  const run = (frag: SqlFragment): Promise<readonly Record<string, unknown>[]> => runRelation(db, frag, cellEnv);
  const measure = typeof globalThis.OffscreenCanvas !== "undefined"
    ? canvasMeasureProvider()
    : registries.measures.get("estimate");
  // Extension pre-pass: a SQL-pushed operator (a geometry resolver → ST_ConvexHull) declares the
  // DuckDB extension(s) it needs on its via-agg payload. Load them ONCE before executing — a load
  // failure throws here (loud), never a silent JS fallback. Collected across all via-agg ops.
  const required = new Set<string>();
  for (const op of specs) {
    if (op.payload.kind !== "via-agg") continue;
    // OpPayload is an open bag ({kind, [k]:unknown}), so `kind` doesn't discriminate — assert the
    // via-agg shape we just matched by kind, once, into a named const.
    const payload = op.payload as unknown as ViaAggPayload;
    for (const a of Object.values(payload.adds)) {
      for (const ext of a.requires ?? []) required.add(ext);
    }
  }
  if (required.size > 0) {
    if (db.backend.ensureExtensions === undefined) throw new Error(`this backend cannot load DuckDB extensions (${[...required].join(", ")}) required by a SQL-pushed resolver — use the JS resolver form ({ js: (matches, mark) => … })`);
    await dbg.span("extensions", { kind: "pass", pass: "extensions" }, () => db.backend.ensureExtensions!([...required]));
  }
  await dbg.span("execute", { kind: "pass", pass: "execute" }, () =>
    schedule(compileOps(specs, { spec, run, measure, debug: opts.debug }, registries.ops), spec.cells, { controllers }));
  recordGraph(specs, "execute", dbg, registries); // the graph as executed (structurally = optimize; dvl_op_run now has runtime impl)
  if (dbg.level >= 1) recordFragmentGraph(spec.cells, "fragments", dbg); // the SQL-fragment DAG (finer than ops)
  if (dbg.level >= 0) await dbg.flush();
  return spec.cells.read(svgCell) as string;
}

function canvasMeasureProvider(): MeasurementProvider {
  const canvas = new OffscreenCanvas(1, 1);
  const ctx2d = canvas.getContext("2d") as OffscreenCanvasRenderingContext2D;
  return {
    name: "canvas",
    textExtent(text, font) {
      ctx2d.font = `${font.weight ?? 400} ${font.size}px ${font.family}`;
      const m = ctx2d.measureText(text);
      return { w: m.width, h: font.size };
    },
  };
}
