// The cell store behind solver VarExprs and data-scalar holes: alloc / read / write /
// seal with status. The scheduler (executor/schedule.ts, C5) drives the status
// transitions by SCC convergence + residual. A per-row channel value's definedness is a
// SEPARATE, data-level notion — not a cell.
import type { CellId, OperatorId } from "../data/ids.js";
import type { Scalar } from "../data/schema.js";
import { dvlSettings } from "../config.js";
import type { Space } from "../types/attr.js";

export type CellRef = CellId;
export type CellStatus = "unbound" | "estimated" | "assigned" | "sealed";
export type CellKind = "scalar" | "relation";
export type CellRole = "extent" | "demand" | "param" | "range" | "domain" | "channel" | "marks" | "ticks" | "sink" | "indicator"; // indicator = a DECISION cell (§C6): axis presence, written by a decision op
export type CellValue = Scalar | object; // object = a compile-layer Relation, held opaquely

export interface Cell {
  readonly id: CellId;
  // scalar: a number/Scalar (carries the fixpoint residual). relation: a Relation held
  // opaquely as `object`, so ir doesn't import compile — the scheduler casts it back.
  readonly kind: CellKind;
  readonly role: CellRole;
  status: CellStatus;
  value?: CellValue;
  producer?: OperatorId; // provenance: the operator that wrote it (stamped by the scheduler)
}

export class CellStore {
  #cells = new Map<CellId, Cell>();
  #defaults = new Map<CellId, Scalar>();
  #spaces = new Map<CellId, Space>();
  #n = 0;
  #untypedCount = 0;

  /** Allocate a cell; with a default it starts `estimated`, else `unbound`.
   *  `space` declares the semantic world; omitting it for a scalar in strict mode
   *  increments the untyped-cell counter (W1 ratchet). */
  alloc(role: CellRole, def?: Scalar, kind: CellKind = "scalar", space?: Space): CellRef {
    const id = `c${this.#n++}`;
    this.#cells.set(id, { id, role, kind, status: def === undefined ? "unbound" : "estimated", value: def });
    if (def !== undefined) this.#defaults.set(id, def);
    if (space !== undefined) {
      this.#spaces.set(id, space);
    } else if (kind === "scalar") {
      this.#untypedCount++;
    }
    return id;
  }

  /** Number of scalar cells allocated without an explicit space (W1 ratchet). */
  get untypedCount(): number { return this.#untypedCount; }

  get(id: CellRef): Cell {
    const c = this.#cells.get(id);
    if (c === undefined) throw new Error(`unknown cell ${id}`);
    return c;
  }

  /** Best available value: sealed/assigned/estimated value, else the default. */
  read(id: CellRef): CellValue | undefined {
    const c = this.get(id);
    return c.status === "unbound" ? this.#defaults.get(id) : c.value;
  }

  write(id: CellRef, value: CellValue, status: CellStatus): void {
    const c = this.get(id);
    c.value = value;
    c.status = status;
  }

  /** Mark final: a literal, an acyclic op's output, or a converged SCC. Sealed = constant. */
  seal(id: CellRef): void {
    this.get(id).status = "sealed";
  }

  /** The declared space of a cell (W1). Null = never declared — the caller decides
   *  whether that is acceptable (fail fast under strict via spaceFallbacks.note). */
  cellSpace(id: CellRef): Space | null {
    return this.#spaces.get(id) ?? null;
  }

  /** Every allocated cell — for debug/introspection (walking relation cells' fragment DAGs). */
  values(): IterableIterator<Cell> {
    return this.#cells.values();
  }
}
