// The tick components + their registration into a canvas's `registries.tickAlgos`.
import type { Registries } from "../../operator/registry.js";
import type { TickAlgo } from "../../operator/ticks.js";
import { niceLinear } from "./nice-linear.js";
import { ordinal } from "./ordinal.js";
import { quantile } from "./quantile.js";
import { uniform } from "./uniform.js";

export const tickComponents: readonly TickAlgo[] = [niceLinear, ordinal, quantile, uniform];

export function registerTicks(registries: Registries): void {
  for (const t of tickComponents) registries.tickAlgos.register(t.name, t);
}

// resolved refs self-describe (§12 Phase 5a): an embedded tick algo serializes as {$tick: name}.
import { selfDescribe } from "../../operator/operator.js";
for (const t of tickComponents) selfDescribe(t, "$tick", t.name);
