// Per-entity serializers (WUDEBUG §2, §6): walk a Spec at a given pass and record one
// row per entity into the explicit dvl_* tables. This is where the structured-table
// schemas are actually produced; the sink stays a generic typed-row writer. Covers the
// IR entities (node/plot/channel/expr/layout/scale/cell/arrange/constraint) + the scene
// frames (recordScene) + the dataflow graph (recordGraph → dvl_operator/dvl_op_io). The
// per-iteration traces (cell_trace/span/op_run) need the executor hook and stay deferred.
import type { Expr } from "../ir/expr.js";
import { resolutionOf } from "../ir/expr.js";
import type { Cell, CellStore } from "../ir/cell.js";
import type { Extent } from "../ir/node.js";
import type { ArrangeInstance, LayoutInstance, Scale } from "../ir/layout.js";
import { isProducerSource, isRelationSource, isUnitSource, type Plot, type TableRef } from "../ir/plot.js";
import type { Spec } from "../ir/spec.js";
import { showSpace } from "../types/attr.js";
import type { Frame } from "../render/scene.js";
import type { OpSpec } from "../plan/opspec.js";
import type { SqlFragment } from "../data/fragment.js";
import type { Registries } from "../operator/registry.js";
import { operatorMeta } from "./graph-meta.js";
import type { DebugRow, DebugSink } from "./sink.js";

type CellOwner = { kind: string; id: string };

/** Snapshot the whole spec at `pass` into the structured tables. */
export function recordSnapshot(spec: Spec, pass: string, sink: DebugSink): void {
  const parentOf = new Map<string, { parent: string; host: string }>();
  for (const n of spec.nodes.values())
    for (const c of n.children) parentOf.set(c.node, { parent: n.id, host: c.hostPlot });

  const cells = new Map<string, CellOwner>();

  for (const n of spec.nodes.values()) {
    const pr = parentOf.get(n.id);
    sink.record("dvl_node", {
      pass, node_id: n.id, parent_node: pr?.parent, host_plot: pr?.host,
      ...extentCols(n.extent), origin: undefined,
    });
    for (const c of extentCellIds(n.extent)) cells.set(c, { kind: "node", id: n.id });
    if (n.arrange !== undefined) recordArrange(sink, n.arrange, pass);
  }

  for (const p of spec.plots.values()) {
    sink.record("dvl_plot", {
      pass, plot_id: p.id, node_id: p.node, source: srcName(p.source), mark_type: p.markType,
      nest_kind: p.nest != null ? (p.nest.on === null ? "inferred" : "path") : undefined, z_index: p.params.zIndex, clip: p.params.clip, origin: undefined,
    });
    for (const [channel, expr] of Object.entries(p.channels)) {
      const rootId = `${p.id}#${channel}`;
      sink.record("dvl_channel", {
        pass, plot_id: p.id, channel, expr_id: rootId,
        value_dim: showSpace(expr.type.space), value_arity: expr.type.arity, resolution: resolutionOf(expr),
        origin: undefined,
      });
      recordExpr(sink, expr, rootId, undefined, pass, cells);
    }
  }

  for (const l of spec.layouts.values()) {
    sink.record("dvl_layout", {
      pass, layout_id: l.id, descriptor: l.descriptor, scope: undefined, params: l.params, origin: undefined,
    });
    if (isScale(l)) {
      sink.record("dvl_scale", {
        pass, layout_id: l.id, kind: l.descriptor, side: l.side, shared: l.shared,
        domain_cell: l.domain, domain_spec: treatmentStr(l), ticks_algorithm: l.ticks?.algorithm,
        members: l.members, // frame-scoped scale: the plots it serves (NORMALIZED: no range cells)
      });
      if (l.domain) cells.set(l.domain, { kind: "scale", id: l.id });
    }
  }

  for (const [cellId, owner] of cells) {
    const c = tryGetCell(spec, cellId);
    if (c === undefined) continue;
    const numeric = c.kind === "scalar" && typeof c.value === "number";
    sink.record("dvl_cell", {
      pass, cell_id: cellId, role: c.role, kind: c.kind, status: c.status,
      value: numeric ? (c.value as number) : undefined,
      value_text: c.kind === "relation" ? "<relation>" : numeric || c.value == null ? undefined : String(c.value),
      producer: c.producer, owner_kind: owner.kind, owner_id: owner.id,
    });
  }
}

/** Record the scene-graph frames (the final render pass). */
export function recordScene(frames: readonly Frame[], sink: DebugSink): void {
  for (const f of frames)
    sink.record("dvl_frame", {
      frame_id: f.id, owner_kind: "frame", owner_id: f.id,
      x: f.drawable.x, y: f.drawable.y, w: f.drawable.w, h: f.drawable.h,
      clip: f.clip, background: f.background,
    });
}

/** Record a built dataflow graph (OpSpec[]) → dvl_operator + dvl_op_io. Pure: the caller passes
 *  the graph (from compileNode); op→op edges derive by joining a writer's out to a reader's in.
 *  `impl` = the optimizer's stamped substrate decision (payload.substrate, §12 Phase 4c) —
 *  present on post-optimize graphs, NULL on pre-optimize ones. `registries` enriches each row with
 *  op_class / has_sql / has_js / trainable / in_schema / out_schema (graph-meta.ts). Still a leaf:
 *  Registries is a type-only import. */
export function recordGraph(specs: readonly OpSpec[], pass: string, sink: DebugSink, registries: Registries): void {
  for (const s of specs) {
    const meta = operatorMeta(s, registries);
    sink.record("dvl_operator", { pass, operator_id: s.id, kind: s.payload.kind, impl: (s.payload as { substrate?: string }).substrate, op_class: meta.op_class, has_sql: meta.has_sql, has_js: meta.has_js, trainable: meta.trainable, in_schema: meta.in_schema, out_schema: meta.out_schema, payload: s.payload });
    for (const r of s.reads) sink.record("dvl_op_io", { pass, operator_id: s.id, direction: "in", ref_kind: "cell", ref_id: r });
    for (const w of s.writes) sink.record("dvl_op_io", { pass, operator_id: s.id, direction: "out", ref_kind: "cell", ref_id: w });
  }
}

/** Record the SQL-FRAGMENT DAG into the SAME dvl_operator/dvl_op_io shape under `pass` — so the
 *  graph tab reads it like any other pass. Walks every relation cell's SqlFragment tree: one node
 *  per fragment (op → CTE) + an edge per input (input fragment/base → this fragment). A js relation
 *  cell is a materialized leaf (no fragment structure) — recorded as a js-coloured leaf node, so
 *  the sql/js split shows. Edges use the op→op join shape: each node emits an `out` on its own id;
 *  a consumer emits an `in` on each input's id (out ⋈ in on ref_id ⇒ input → consumer). */
export function recordFragmentGraph(cells: CellStore, pass: string, sink: DebugSink): void {
  const seen = new Set<string>();
  const node = (id: string, kind: string, opClass: string, impl: string): void => {
    if (seen.has(id)) return;
    seen.add(id);
    sink.record("dvl_operator", { pass, operator_id: id, kind, op_class: opClass, impl });
    sink.record("dvl_op_io", { pass, operator_id: id, direction: "out", ref_kind: "frag", ref_id: id });
  };
  const walk = (f: SqlFragment): void => {
    const first = !seen.has(f.id);
    node(f.id, f.op, "fragment", "sql");
    if (!first) return; // its input edges are already recorded
    for (const ref of Object.values(f.inputs)) {
      if ("base" in ref) {
        node(ref.base, "base", "base", "sql");
        sink.record("dvl_op_io", { pass, operator_id: f.id, direction: "in", ref_kind: "frag", ref_id: ref.base });
      } else {
        sink.record("dvl_op_io", { pass, operator_id: f.id, direction: "in", ref_kind: "frag", ref_id: ref.fragment.id });
        walk(ref.fragment);
      }
    }
  };
  for (const c of cells.values()) {
    if (c.kind !== "relation" || c.value === undefined) continue;
    const rel = c.value as { substrate?: string; frag?: SqlFragment };
    if (rel.substrate === "sql" && rel.frag !== undefined) walk(rel.frag);
    else if (rel.substrate === "js") node(`js:${c.id}`, "js-rows", "js", "js");
  }
}

function recordArrange(sink: DebugSink, a: ArrangeInstance, pass: string): void {
  sink.record("dvl_arrange", { pass, arrange_id: a.id, scope_node: a.scope, objective: a.objective, solver: a.solver });
  a.constraints.forEach((c, i) => {
    const cid = `${a.id}/c${i}`;
    sink.record("dvl_constraint", { pass, constraint_id: cid, node_id: a.scope, op: c.op, constant: c.constant, strength: c.strength });
    for (const t of c.terms) sink.record("dvl_constraint_term", { pass, constraint_id: cid, edge_cell: t.edge, coef: t.coef });
  });
}

function recordExpr(sink: DebugSink, e: Expr, exprId: string, parent: string | undefined, pass: string, cells: Map<string, CellOwner>): void {
  const row: DebugRow = {
    pass, expr_id: exprId, parent_expr: parent, kind: e.kind,
    value_dim: showSpace(e.type.space), value_arity: e.type.arity, resolution: resolutionOf(e),
    literal_value: undefined, column_name: undefined, layout_id: undefined, output: undefined,
    op: undefined, cell_id: undefined, var_role: undefined, ref_table: undefined, ref_plot: undefined, attr_name: undefined,
  };
  switch (e.kind) {
    case "literal": row.literal_value = String(e.value); break;
    case "local-column": row.column_name = e.columnName; break;
    case "layout-output": row.layout_id = e.layout; row.output = e.output; break;
    case "binary": row.op = e.op; break;
    case "var": row.cell_id = e.cell; row.var_role = e.role; cells.set(e.cell, { kind: "expr", id: exprId }); break;
    case "bound-ref": row.ref_table = e.tableName; row.attr_name = e.columnName; break;
    case "table-ref": row.ref_plot = e.plotId; row.attr_name = e.attrName; break;
    case "agg": row.op = e.op; row.ref_plot = e.ref.plotId; row.attr_name = e.ref.attrName; break;
    case "call": row.op = e.fn; break;
  }
  sink.record("dvl_expr", row);
  if (e.kind === "binary") {
    recordExpr(sink, e.left, `${exprId}/l`, exprId, pass, cells);
    recordExpr(sink, e.right, `${exprId}/r`, exprId, pass, cells);
  } else if (e.kind === "call") {
    e.args.forEach((a, i) => recordExpr(sink, a, `${exprId}/${i}`, exprId, pass, cells));
  }
}

// ── helpers ────────────────────────────────────────────────────────────────────
function isScale(l: LayoutInstance): l is Scale {
  return "treatment" in l; // scales carry a domain treatment; plain layouts don't
}
function srcName(src: TableRef): string {
  if (typeof src === "string") return src;
  if (isRelationSource(src)) return "<relation>";
  if (isProducerSource(src)) return `<producer:${src.producer}>`;
  if (isUnitSource(src)) return `<unit:${src.value}>`;
  return src.name;
}
function treatmentStr(s: Scale): string | undefined {
  const ds = s.treatment;
  if (ds === undefined) return undefined;
  return typeof ds === "object" ? JSON.stringify(ds) : ds;
}
function extentCols(e: Extent): DebugRow {
  return {
    ext_outer_l: e.outer.left, ext_outer_r: e.outer.right, ext_outer_t: e.outer.top, ext_outer_b: e.outer.bottom,
    ext_content_l: e.content.left, ext_content_r: e.content.right, ext_content_t: e.content.top, ext_content_b: e.content.bottom,
  };
}
function extentCellIds(e: Extent): string[] {
  return [e.outer.left, e.outer.right, e.outer.top, e.outer.bottom, e.content.left, e.content.right, e.content.top, e.content.bottom];
}
function tryGetCell(spec: Spec, id: string): Cell | undefined {
  try {
    return spec.cells.get(id);
  } catch {
    return undefined;
  }
}
