// SqlFragment — the foldable SQL unit / query object (WUDATA §3, WUDATA_IMPL §7).

import type { OutSchema } from "./schema.js";
import type { CellId, FragmentId, OperatorId, RelationName } from "./ids.js";

export interface CteDef {
  readonly name: string; // LOCAL name within the fragment; uniquified on fold
  readonly body: string; // references relations as @name and cells as {name} ONLY
  readonly recursive?: boolean;
  /** Explicit CTE column list — `name(col, …) AS (…)`. Structured (not baked into a header
   *  string) because fold uniquifies `name`; the renderer re-attaches these after the new name. */
  readonly columns?: readonly string[];
  /** DuckDB iterative-recursion key — `USING KEY (col, …)` after the column list. */
  readonly usingKey?: readonly string[];
}

/** A fragment input: a base relation (leaf) or another fragment (fold target). */
export type RelationRef =
  | { readonly base: RelationName }
  | { readonly fragment: SqlFragment };

export interface SqlFragment {
  readonly id: FragmentId; // identity for dedup in fold (unique per operator)
  readonly op: OperatorId; // CTE-name uniquification prefix
  readonly ctes: readonly CteDef[]; // local names, in dependency order
  readonly result: string; // the local cte exposed as this fragment's relation
  readonly inputs: Readonly<Record<string, RelationRef>>; // @name -> leaf | fragment
  readonly outputs: OutSchema;
  readonly cells: readonly CellId[]; // {name} holes referenced in the bodies
}

const REL_RE = /@([A-Za-z_][A-Za-z0-9_]*)/y;
const CELL_RE = /\{([A-Za-z_][A-Za-z0-9_]*)\}/y;

/**
 * Quote-aware token substitution over a CTE body (WUDATA_IMPL §9). Rewrites
 * `@name` (relations) and/or `{name}` (cells) using the provided handlers, while
 * copying single-quoted string literals and double-quoted identifiers verbatim
 * (so `@`/`{` inside them are never touched). Not a SQL parser.
 */
export function rewriteSql(
  body: string,
  opts: { rel?: (name: string) => string; cell?: (name: string) => string },
): string {
  let out = "";
  let i = 0;
  const len = body.length;
  while (i < len) {
    const ch = body[i];

    // Skip quoted regions (string literal ' or quoted identifier ").
    if (ch === "'" || ch === '"') {
      const quote = ch;
      out += ch;
      i++;
      while (i < len) {
        const c = body[i];
        out += c;
        i++;
        if (c === quote) {
          if (body[i] === quote) {
            out += quote; // doubled-quote escape -> stay inside
            i++;
            continue;
          }
          break; // closing quote
        }
      }
      continue;
    }

    if (ch === "@" && opts.rel) {
      REL_RE.lastIndex = i;
      const m = REL_RE.exec(body);
      if (m !== null) {
        out += opts.rel(m[1]);
        i += m[0].length;
        continue;
      }
    }

    if (ch === "{" && opts.cell) {
      CELL_RE.lastIndex = i;
      const m = CELL_RE.exec(body);
      if (m !== null) {
        out += opts.cell(m[1]);
        i += m[0].length;
        continue;
      }
    }

    out += ch;
    i++;
  }
  return out;
}
