// grid-stack: pack items into a box by stacking row- or column-major.
// Outputs absolute pixel boxes (x, y, w, h). Derives cols/rows from the
// available extent at execution. Component-owned JS impl; reads extent
// cells directly (same mechanism as `affine`).
import type { CellRef, CellStore } from "../../ir/cell.js";
import type { MeasurementProvider } from "../../ir/mark.js";
import type { OpBinding } from "../../algebra/impl.js";
import type { PlanIO } from "../../operator/binding.js";
import { op } from "../../operator/operator.js";
import { jsRel, materialize, type JsRel } from "../../algebra/relation.js";
import type { OpSpec } from "../../plan/opspec.js";
import type { RunCtx } from "../../executor/run.js";
import { coord, len, pixelSpace } from "../../types/attr.js";
import { DVL_FONT_FAMILY } from "../../ir/pen.js";

export interface GridStackOpts {
  contentEdges: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
  /** For a DOCKED legend, the own-axis anchor (the gutter edge the legend hugs) reads THESE fixed
   *  outer-extent edges instead of the content box. The content box shrinks by the legend's own
   *  reserved gutter, so anchoring to it makes the legend chase its own reservation — a feedback
   *  loop with `arrange` that never converges under precise (sub-pixel) text metrics (the browser).
   *  Pinning the own-axis anchor to the FIXED outer edge cuts that edge; the cross-axis + wrap still
   *  read the content box (that's a different gutter, no self-feedback). Absent ⇒ old behaviour. */
  outerEdges?: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
  /** Step 3: a DOCKED legend that registered as a side-stack BAND anchors its own-axis (the gutter
   *  normal) to the band's SOLVED top-left corner instead of the content/outer edge. The band's x/y
   *  are chained OUTSIDE any co-located axis, so the legend no longer overlaps it — and because the
   *  band position derives from `outer − measured reservation` (not the shrinking content box), the
   *  own-axis anchor is stable across the measure↔arrange fixpoint (this subsumes the `outerEdges`
   *  convergence patch). The CROSS axis + wrap still read the content box. Absent ⇒ old behaviour. */
  bandAnchor?: { x: CellRef; y: CellRef };
  itemW: number;
  itemH: number;
  pad?: number;
  major?: "column" | "row";
  side?: "left" | "right" | "top" | "bottom"; // which gutter the legend occupies (determines anchor)
  /** G3: an INSIDE overlay — anchor the grid in this content-box corner instead of a gutter.
   *  Consumes no layout space (no dock reservation exists); `side` is ignored when set. */
  inside?: "top-left" | "top-right" | "bottom-left" | "bottom-right";
  /** G4: measure the item width from the REAL text extents at execution — `itemW` above becomes
   *  the seed / no-measure fallback. `base` = the non-text width (swatch + gaps); `k` mirrors the
   *  truncate layout's static prefix (G6 hook: becomes a kCell read when the controller goes live). */
  label?: { column: string; fontSize: number; family?: string; base: number; k?: number };
  /** Glyph anchor INSIDE each item box (AUTOLEGEND_IMPL §8): the emitted x/y are the box
   *  origin plus this inset, so a circle centered at (x, y) or a middle-baselined text sits
   *  within the box instead of straddling its top-left corner. Default {0, 0} (box origin). */
  inset?: { x: number; y: number };
}

// PLAN-ONLY operator (§12 Phase 5): its op kind ("grid-stack") has a dedicated handler
// (gridStackOp below — its op reads extent CELLS, which Exec can't express) — the operator's
// own Exec side is empty.
export const gridStack = op({
  name: "grid-stack",
  // No domain: no train — absolute pixel boxes packed row/column-major from the extent
  // cells at execution. Pure placement in gutter space; no data domain, nothing tickable.
  inputs: { marks: [{ name: "value", type: "unknown" }] },
  output: { passthrough: "marks", add: [
    { name: "x", type: "double" }, { name: "y", type: "double" },
    { name: "w", type: "double" }, { name: "h", type: "double" },
  ]},
  outSpaces: {
    x: pixelSpace(coord("x")),
    y: pixelSpace(coord("y")),
    w: pixelSpace(len("x")),
    h: pixelSpace(len("y")),
  },
  plan: (io: PlanIO): OpSpec[] => {
    if (io.marksIn === undefined) throw new Error("grid-stack needs input marks");
    const opts = io.binding.options as unknown as GridStackOpts;
    const cc = opts.contentEdges;
    const oo = opts.outerEdges;
    const ba = opts.bandAnchor;
    return [{
      id: `${io.id}:grid-stack`,
      reads: [io.marksIn, cc.left, cc.right, cc.top, cc.bottom, ...(oo ? [oo.left, oo.right, oo.top, oo.bottom] : []), ...(ba ? [ba.x, ba.y] : [])],
      writes: [io.marksOut],
      payload: { kind: "grid-stack", key: io.id, binding: io.binding },
    }];
  },
});

/** Execute grid-stack: read extent cells, compute absolute pixel boxes for each item.
 *  Called from run.ts's op dispatch (same pattern as the "affine" case). */
export function runGridStack(
  marks: JsRel,
  b: OpBinding,
  readCell: (ref: CellRef) => number,
  measure?: MeasurementProvider,
): JsRel {
  const opts = b.options as unknown as GridStackOpts;
  const cc = opts.contentEdges;
  const left = readCell(cc.left);
  const right = readCell(cc.right);
  const top = readCell(cc.top);
  const bottom = readCell(cc.bottom);
  // The own-axis anchor reads the FIXED outer edge when given (docked legend) — see GridStackOpts.
  const oo = opts.outerEdges;
  const oLeft = oo ? readCell(oo.left) : left;
  const oRight = oo ? readCell(oo.right) : right;
  const oTop = oo ? readCell(oo.top) : top;
  const oBottom = oo ? readCell(oo.bottom) : bottom;
  const side = opts.side ?? "right";
  // G4: the pitch is MEASURED from the rows' actual (truncated) labels — the option is only the
  // seed/fallback. Measuring at the point of use keeps pitch and packing consistent per sweep;
  // the demand loop (plot-measure → arrange) converges the gutter around it.
  const itemW = opts.label !== undefined && measure !== undefined
    ? opts.label.base + marks.rows.reduce((w, r) => {
        const raw = String(r[opts.label!.column] ?? "");
        const t = opts.label!.k !== undefined && opts.label!.k >= 0 ? raw.slice(0, opts.label!.k) : raw;
        return Math.max(w, measure.textExtent(t, { size: opts.label!.fontSize, family: opts.label!.family ?? DVL_FONT_FAMILY }).w);
      }, 0)
    : opts.itemW;
  const itemH = opts.itemH;
  const pad = opts.pad ?? 4;

  // Default major axis: left/right → column (stack vertically); top/bottom → row (stack horizontally)
  const inside = opts.inside;
  const major = opts.major ?? (!inside && (side === "top" || side === "bottom") ? "row" : "column");
  const n = marks.rows.length;

  // avail extents are anchor-independent, so cols/rows resolve BEFORE the anchor — the top/left
  // gutters need the full grid size to grow AWAY from the content (a second row of a top legend
  // must climb further up, not descend onto the plot). An INSIDE overlay is bounded by the
  // content box on both axes.
  const availW = inside !== undefined || side === "top" || side === "bottom" ? right - left : Infinity;
  const availH = inside !== undefined || side === "left" || side === "right" ? bottom - top : Infinity;
  let cols: number, rows: number;
  if (major === "column") {
    rows = availH === Infinity ? n : Math.max(1, Math.floor((availH - 2 * pad) / itemH));
    cols = Math.ceil(n / rows);
  } else {
    cols = availW === Infinity ? n : Math.max(1, Math.floor((availW - 2 * pad) / itemW));
    rows = Math.ceil(n / cols);
  }
  // Anchors that place the WHOLE grid before an edge need its OCCUPIED size — `rows`/`cols` are
  // capacity in the wrap dimension (e.g. column-major rows = how many FIT, not how many exist).
  const occRows = major === "column" ? Math.min(rows, n) : rows;
  const occCols = major === "column" ? cols : Math.min(cols, n);

  // Anchor = the grid's top-left corner. Docked: in the gutter the side names — left/top place
  // the WHOLE grid (occCols·itemW / occRows·itemH) outside the content edge; right/bottom start
  // just past it. INSIDE (G3): an overlay in the named content-box corner, consuming no layout
  // space and emitting no constraints — the grid sits wholly within the content edges.
  let anchorX: number, anchorY: number;
  if (inside !== undefined) {
    anchorX = inside.includes("right") ? right - pad - occCols * itemW : left + pad;
    anchorY = inside.includes("bottom") ? bottom - pad - occRows * itemH : top + pad;
  } else {
    switch (side) {
      case "right":
        anchorX = right + pad;
        anchorY = top + pad;
        break;
      case "left":
        anchorX = left - pad - occCols * itemW;
        anchorY = top + pad;
        break;
      case "top":
        anchorX = left + pad;
        anchorY = top - pad - occRows * itemH;
        break;
      case "bottom":
        anchorX = left + pad;
        anchorY = bottom + pad;
        break;
    }
    // Step 3 — a legend registered as a side-stack BAND anchors its OWN-AXIS to the band's solved
    // top-left corner (chained OUTSIDE any co-located axis). Stable across the fixpoint (the band
    // position derives from outer − measured reservation, not the shrinking content box) and it no
    // longer overlaps the axis. Cross-axis anchor + wrap stay on the content box.
    const ba = opts.bandAnchor;
    if (ba) {
      if (side === "left" || side === "right") anchorX = readCell(ba.x);
      else anchorY = readCell(ba.y);
    } else if (oo) {
      // Legacy (ramp legends): pin the OWN-AXIS anchor to the FIXED outer edge instead of the
      // shrinking content edge — same converged position, no self-chase. Superseded by bandAnchor.
      if (side === "right") anchorX = oRight - pad - occCols * itemW;
      else if (side === "left") anchorX = oLeft + pad;
      else if (side === "top") anchorY = oTop + pad;
      else if (side === "bottom") anchorY = oBottom - pad - occRows * itemH;
    }
  }
  // b.outputs only has the channels the plot actually binds (may be just x,y — not w,h).
  // Use fixed names for the grid columns; unbound ones still appear in the relation for passthrough.
  const xo = b.outputs[0] ?? "x";
  const yo = b.outputs[1] ?? "y";
  const wo = b.outputs[2] ?? "w";
  const ho = b.outputs[3] ?? "h";
  const inX = opts.inset?.x ?? 0;
  const inY = opts.inset?.y ?? 0;

  return {
    rows: marks.rows.map((r, i) => ({
      ...r,
      [xo]: anchorX + (major === "column" ? Math.floor(i / rows) : i % cols) * itemW + inX,
      [yo]: anchorY + (major === "column" ? i % rows : Math.floor(i / cols)) * itemH + inY,
      [wo]: itemW,
      [ho]: itemH,
    })),
    schema: [...marks.schema,
      { name: xo, type: "double" }, { name: yo, type: "double" },
      { name: wo, type: "double" }, { name: ho, type: "double" }],
  };
}

export async function gridStackOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload;
  if (p.kind !== "grid-stack") return;
  const marks = await materialize(store.read(op.reads[0]) as any, ctx.run);
  const readCell = (ref: CellRef): number => Number(store.read(ref));
  const out = runGridStack(marks, p.binding as OpBinding, readCell, ctx.measure);
  store.write(op.writes[0], jsRel(out.rows, out.schema), "assigned");
}
