// Per-operator metadata for the recorded graph (design/2026-07-22-debug-graph-inspector.html §1).
// A LEAF: type-only imports (OpSpec, Registries, Operator) so debug/snapshot stays dependency-free
// of the executor/optimizer. The authoritative source for impls + I/O schema is the operator
// DESCRIPTOR in registries.operators (looked up by payload.algoName) — NOT the serialized payload,
// whose embedded Exec closures toJSON to {$op: name}. Framework ops (no descriptor) fall back to
// the handler capability in registries.ops.
import type { OpSpec } from "../plan/opspec.js";
import type { Registries } from "../operator/registry.js";

export type OpClass = "scale" | "layout" | "mark" | "framework";

export interface OpMeta {
  op_class: OpClass;
  has_sql: boolean;
  has_js: boolean;
  trainable: boolean;
  /** declared input roles → columns, as JSON (registered ops only). */
  in_schema?: string;
  /** declared output (passthrough + added columns), as JSON (registered ops only). */
  out_schema?: string;
}

// Op kinds that materialize a mark/render table (not a registered layout/scale, not pure framework).
const MARK_KINDS = new Set(["marktable", "vtable", "render"]);

/** Classify + describe one operator. `payload.algoName` names the registered operator for
 *  apply/domain ops; a registered descriptor with a domain (or ticks) is scale-family, else layout.
 *  Everything else is a framework/mark op typed by its handler capability. */
export function operatorMeta(op: OpSpec, registries: Registries): OpMeta {
  const payload = op.payload as { kind: string; algoName?: unknown };
  const kind = payload.kind;
  const algoName = typeof payload.algoName === "string" ? payload.algoName : undefined;

  if (algoName !== undefined && registries.operators.has(algoName)) {
    const o = registries.operators.get(algoName);
    return {
      op_class: o.domain !== undefined || o.ticks !== undefined ? "scale" : "layout",
      has_sql: o.sql !== undefined,
      has_js: o.js !== undefined,
      trainable: o.train !== undefined,
      in_schema: JSON.stringify(o.inputs),
      out_schema: JSON.stringify(o.output),
    };
  }

  const cap = registries.ops.has(kind) ? registries.ops.capability(kind) : { canProduce: [] as readonly ("sql" | "js")[] };
  return {
    op_class: MARK_KINDS.has(kind) ? "mark" : "framework",
    has_sql: cap.canProduce.includes("sql"),
    has_js: cap.canProduce.includes("js"),
    trainable: false,
  };
}
