// one row per (customer, product, year) sale — the FACT table. Deterministic pseudo-data.
export const ORDERS: { id: number; cust_id: number; product_id: number; qty: number; year: number }[] = [];
{
  let oid = 0;
  for (let c = 0; c < CUSTOMERS.length; c++) for (let p = 0; p < PRODUCTS.length; p++) {
    if ((c * 7 + p * 3) % 4 === 0) continue; // sparse — not every customer buys every product
    ORDERS.push({ id: oid++, cust_id: c, product_id: p, qty: ((c + p * 2) % 6) + 1, year: 2007 + ((c + p) % 3) });
  }
}

