// reduce: the ONE grouped reduce as a standalone op (§8 Stage 3) — relation in, relation out,
// one row per `by` value. The declarative adds are a thin wrap of the shared lowering
// (lowerTrainSql / lowerTrainJs — the same code every scale train and path-agg runs); an opaque
// `js` add materializes the input and reduces each group's rows in JS. via-agg's declarative
// path is a client (plot.ts emits stage join → reduce by dvl_mark → keyed attach); child-extent
// aggregation (by: dvl_cell) is the anticipated next one — no group key is baked in here.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { ReducePayload } from "../../../plan/payloads.js";
import type { OpBinding } from "../../../algebra/impl.js";
import type { Row, Scalar } from "../../../data/schema.js";
import type { Agg, AggFn } from "../../../algebra/relop.js";
import { lowerTrainJs, lowerTrainSql } from "../../../algebra/lower.js";
import { jsRel, materialize, sqlRel, type Relation } from "../../../algebra/relation.js";

export const AGG_FNS = new Set<AggFn>(["min", "max", "sum", "avg", "median", "stddev", "variance", "count", "countDistinct", "first", "last", "stringAgg", "anyValue"]);

type Add = ReducePayload["adds"][string];

function toAgg(key: string, name: string, a: Add): Agg {
  if (a.fn === undefined || !AGG_FNS.has(a.fn as AggFn)) {
    throw new Error(`reduce "${key}": unknown fn "${a.fn}" for "${name}" — use an AggFn (${[...AGG_FNS].join("/")}) or a js reduce`);
  }
  return { fn: a.fn, ...(a.arg !== undefined ? { arg: a.arg } : { col: a.col ?? name }), ...(a.order !== undefined && { order: a.order, desc: a.desc }) } as Agg;
}

export async function reduceOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as ReducePayload;
  const input = store.read(op.reads[0]) as Relation;
  const b = { key: p.key, inputs: {}, outputs: Object.keys(p.adds) } as unknown as OpBinding;
  const hasJs = Object.values(p.adds).some((a) => a.js !== undefined);

  if (!hasJs) {
    const aggs = Object.fromEntries(Object.entries(p.adds).map(([n, a]) => [n, toAgg(p.key, n, a)]));
    if (input.substrate === "sql") {
      store.write(op.writes[0], sqlRel(lowerTrainSql({ kind: "aggregate", aggs }, input.frag, b, p.by, p.key)), "assigned");
    } else {
      const out = lowerTrainJs({ kind: "aggregate", aggs }, { rows: input.rows, schema: input.schema }, b, p.by);
      store.write(op.writes[0], jsRel(out.rows, out.schema), "assigned");
    }
    return;
  }

  // opaque js adds: materialize, group by the key, reduce each group's rows in JS (declarative
  // adds riding the same reduce run through the ONE reduce's JS mirror per group).
  const { rows, schema } = input.substrate === "js" ? { rows: input.rows, schema: input.schema } : await materialize(input, ctx.run);
  const keys = typeof p.by === "string" ? [p.by] : [...p.by];
  const groups = new Map<string, Row[]>();
  for (const r of rows) {
    const k = keys.map((c) => String((r as Row)[c] ?? "")).join("�");
    const g = groups.get(k);
    if (g === undefined) groups.set(k, [r as Row]);
    else g.push(r as Row);
  }
  const out: Row[] = [];
  for (const g of groups.values()) {
    const row: Record<string, Scalar> = Object.fromEntries(keys.map((c) => [c, g[0][c] as Scalar]));
    for (const [name, a] of Object.entries(p.adds)) {
      if (a.js !== undefined) {
        row[name] = a.js(g) as Scalar;
        continue;
      }
      row[name] = lowerTrainJs({ kind: "aggregate", aggs: { [name]: toAgg(p.key, name, a) } }, { rows: g, schema }, b).rows[0][name] as Scalar;
    }
    out.push(row);
  }
  const outSchema = [...keys.map((c) => ({ name: c, type: "unknown" as const })), ...Object.keys(p.adds).map((n) => ({ name: n, type: "unknown" as const }))];
  store.write(op.writes[0], jsRel(out, outSchema), "assigned");
}
