// By-name registries — the serializability keystone (WUIR_IMPL §2.4). The IR
// references closures by name; the runtime resolves through these. No spec object
// holds a closure, so JSON-from-IR is nearly free (WUDESIGN option A).
import type { MarkDescriptor, MeasurementProvider } from "../ir/mark.js";
import type { ArrangeSolver, Objective } from "../ir/layout.js";
import type { ResolverSpec } from "../ir/refs.js";
import type { Operator } from "./operator.js"; // type-only: erases at runtime, so ir stays a runtime leaf
import type { TickAlgo } from "./ticks.js";
// DomainUnion and DomainNice use opaque relation types to keep ir/ a leaf.
// The actual JsRel/SqlFragment types live in dataflow/relation; these are
// compatible structural types that avoid the import.
import type { Row, Schema } from "../data/schema.js";

/** A domain union operator — combines N domain contributions into one.
 *  Dual JS/SQL implementations; the executor picks substrate. */
export interface DomainUnion {
  name: string;
  js: (members: { rows: readonly Row[]; schema: Schema }[]) => { rows: Row[]; schema: Schema };
  sql?: (members: unknown[]) => unknown; // SqlFragment[] → SqlFragment (opaque at ir level)
}

/** A domain nice function — extends domain to clean boundaries.
 *  Dual JS/SQL implementations. */
export interface DomainNice {
  name: string;
  js: (domain: { rows: readonly Row[]; schema: Schema }) => { rows: Row[]; schema: Schema };
  sql?: (domain: unknown) => unknown;
}

/** An op handler: the registered execution logic for one payload kind.
 *  The type is generic over the context to avoid circular deps (ir/ → executor/). The executor
 *  narrows it to `(op: OpSpec, store: CellStore, ctx: RunCtx)` at registration. */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export type OpHandler = (op: any, store: any, ctx: any) => void | Promise<void>;

/** Substrate capabilities declared at registration time. */
export interface OpCapability {
  readonly canConsume: readonly ("sql" | "js")[];
  readonly canProduce: readonly ("sql" | "js")[];
  readonly fixedOutput?: "sql" | "js";
}

/** An op registration: handler + declared capabilities. */
export interface OpRegistration {
  readonly handler: OpHandler;
  readonly capability: OpCapability;
}

export class Registry<T> {
  #items = new Map<string, T>();

  register(name: string, item: T): void {
    if (this.#items.has(name)) throw new Error(`already registered: ${name}`);
    this.#items.set(name, item);
  }

  get(name: string): T {
    const item = this.#items.get(name);
    if (item === undefined) throw new Error(`not registered: ${name}`);
    return item;
  }

  has(name: string): boolean {
    return this.#items.has(name);
  }
}

const DUAL: OpCapability = { canConsume: ["sql", "js"], canProduce: ["sql", "js"] };

/** Specialized registry for ops: stores handler + capability together. */
export class OpsRegistry {
  #handlers = new Map<string, OpHandler>();
  #caps = new Map<string, OpCapability>();

  register(name: string, handler: OpHandler, capability: OpCapability = DUAL): void {
    if (this.#handlers.has(name)) throw new Error(`already registered: ${name}`);
    this.#handlers.set(name, handler);
    this.#caps.set(name, capability);
  }

  get(name: string): OpHandler {
    const h = this.#handlers.get(name);
    if (h === undefined) throw new Error(`not registered: ${name}`);
    return h;
  }

  has(name: string): boolean { return this.#handlers.has(name); }

  keys(): IterableIterator<string> { return this.#handlers.keys(); }

  capability(name: string): OpCapability {
    return this.#caps.get(name) ?? DUAL;
  }
}

export interface Registries {
  marks: Registry<MarkDescriptor>;
  /** The ONE component registry (§12 Phase 5): an Operator carries its Execs AND its declarative
   *  surface (ex-LayoutDescriptor) — the old layouts/layoutAlgos twin registration is gone. */
  operators: Registry<Operator>;
  tickAlgos: Registry<TickAlgo>; // off the old module-global
  arrangeSolvers: Registry<ArrangeSolver>; // C6
  objectives: Registry<Objective>; // C6 default
  renderTargets: Registry<unknown>; // C3
  measures: Registry<MeasurementProvider>; // C7 default
  ops: OpsRegistry; // execution dispatch + capability, keyed by payload.kind
  /** Named via resolvers (§4.3): `resolve: { m: { js: 'mode' } }` or the bare `resolve: 'convex'`
   *  names one of these — the SERIALIZABLE spelling of a reduce (an inline closure can't round-trip).
   *  A ResolverSpec carries the JS reduce + optional authoring defaults and a SQL impl. */
  reducers: Registry<ResolverSpec>;
  /** Named colour palettes (AUTOLEGEND §6): categorical arrays + 256-step sampled ramps. A colour
   *  scale's `scheme` name resolves through this — the serializable spelling of a palette. */
  schemes: Registry<readonly string[]>;
}

/** Bare registries — `components/index.ts` `defaultRegistries()` seeds them with the built-ins
 *  (marks, scales, layouts, ticks). Keeping the seeding there keeps `ir/` a leaf. */
export function emptyRegistries(): Registries {
  return {
    marks: new Registry<MarkDescriptor>(),
    operators: new Registry<Operator>(),
    tickAlgos: new Registry<TickAlgo>(),
    arrangeSolvers: new Registry<ArrangeSolver>(),
    objectives: new Registry<Objective>(),
    renderTargets: new Registry<unknown>(),
    measures: new Registry<MeasurementProvider>(),
    ops: new OpsRegistry(),
    reducers: new Registry<ResolverSpec>(),
    schemes: new Registry<readonly string[]>(),
  };
}
