// Tick generation — the `V(idx, value, label)` table a scale exposes; axes are tick/text
// marks over V. Two flavors (WULAYOUT_IMPL): PARAMS-ONLY (`generate`, over the trained
// scalars — substrate-portable, the engine serializes it) and DATA-DEPENDENT (`sql`/`js`,
// over the data relation — a `train` whose output is a relation). `sql` returns a
// `SqlFragment` (V as a relation), never a string. The substrate choice is in genTicks.
import type { SqlFragment } from "../data/fragment.js";
import type { Row, Scalar, Schema } from "../data/schema.js";
import type { Params } from "../algebra/impl.js";
import { jsRel, sqlRel, valuesFrag, type Relation, type RunFrag, type Substrate } from "../algebra/relation.js";
export interface Tick {
  readonly idx: number;
  readonly value: Scalar;
  readonly label: string;
}

export interface TickCtx {
  readonly column: string;
  readonly count: number;
}

/** What a tick algo reads to build V — one consistent input. `over: "domain"` algos use
 *  `params` (the trained min/max/categories); `over: "data"` algos use `rows` (materialized data). */
export interface TickInput {
  readonly params: Params;
  readonly rows: readonly Row[];
}

export interface TickAlgo {
  readonly name: string;
  /** Input source — the consistent replacement for the old generate-vs-sql/js split. */
  readonly over: "domain" | "data";
  /** V (ticks) from the input, in JS — every tick algo provides this. */
  js(input: TickInput, ctx: TickCtx): Tick[];
  /** Optional SQL push-down (data algos): V as a relation over the data fragment. */
  sql?(data: SqlFragment, ctx: TickCtx): SqlFragment;
}

/** Tick → row, for serializing V into a relation (columns idx/value/label). */
export const tickRows = (ticks: readonly Tick[]): Row[] => ticks.map((t) => ({ idx: t.idx, value: t.value, label: t.label }));
const vSchema = (ticks: readonly Tick[]): Schema => [
  { name: "idx", type: "int" },
  { name: "value", type: ticks.length > 0 && typeof ticks[0].value === "number" ? "double" : "varchar" },
  { name: "label", type: "varchar" },
];

// The built-in tick algos (nice-linear / ordinal / quantile) live in components/ticks and
// are registered into a canvas's `registries.tickAlgos` by defaultRegistries().

/** Params-only convenience (axis code uses genTicks for the general/data-dependent case).
 *  Takes the resolved algo — symmetric with train/apply; the caller resolves it by name. */
export function ticksOf(algo: TickAlgo, params: Params, opts?: Readonly<Record<string, unknown>>): Tick[] {
  if (algo.over !== "domain") throw new Error(`tick algo "${algo.name}" reads data — use genTicks`);
  return algo.js({ params, rows: [] }, { column: "", count: Number(opts?.count ?? 5) });
}

/** Produce V as a Relation in substrate `want` (WULAYOUT_IMPL §ticks). Params-only algos
 *  compute in JS and serialize either way; data-dependent algos run their SQL/JS producer. */
export async function genTicks(algo: TickAlgo, params: Params, ctx: TickCtx, data: Relation, want: Substrate, run: RunFrag): Promise<Relation> {
  const serialize = (ticks: readonly Tick[]): Relation =>
    want === "sql" ? sqlRel(valuesFrag(`ticks:${ctx.column}`, tickRows(ticks), vSchema(ticks))) : jsRel(tickRows(ticks), vSchema(ticks));

  if (algo.over === "domain") return serialize(algo.js({ params, rows: [] }, ctx));

  // data-dependent: push the computation into SQL if the algo offers it, else materialize + JS
  if (want === "sql" && algo.sql !== undefined) {
    const frag = data.substrate === "sql" ? data.frag : valuesFrag(`ticks:${ctx.column}:data`, data.rows, data.schema);
    return sqlRel(algo.sql(frag, ctx));
  }
  const rows = await asRows(data, run);
  return serialize(algo.js({ params, rows }, ctx));
}

async function asRows(data: Relation, run: RunFrag): Promise<readonly Row[]> {
  if (data.substrate === "js") return data.rows;
  return (await run(data.frag)) as readonly Row[];
}
