// domain op: train a scale's fit via the resolved Operator (§12 Phase 5: the old runTrain
// fallback and the DVL_STRICT_EXEC guard are gone with optimizer/planner.ts — payload.algo is
// REQUIRED; the train Exec is `algo.train`, compiled by op() from the TrainedDomain). The second
// write (the materialized JS copy into the domain hole) is this op's OWN semantics —
// axes/legends/gather-scatter read the domain as rows — not part of the train impl.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { DomainPayload } from "../../../plan/payloads.js";
import { jsRel, materialize, type Relation } from "../../../algebra/relation.js";
import { type Exec } from "../../../algebra/impl.js";
import { applyTreatment } from "../../../operator/treatment.js";
import { chooseImpl, dispatch } from "../../../executor/dispatch.js";
export async function domain(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as DomainPayload;
  if (p.kind !== "domain") return;
  const algo = p.algo;
  if (algo === undefined) throw new Error(`domain: payload for "${p.algoName}" carries no resolved operator — emit through the compiler (stampAlgo)`);
  const train: Exec | undefined = algo.train;
  if (train === undefined) throw new Error(`domain: operator "${p.algoName}" has no train Exec — a domain op requires an operator with a TrainedDomain`);
  const marks = store.read(op.reads[0]) as Relation;
  const impl = p.substrate !== undefined ? train[p.substrate]! : chooseImpl(train, marks.substrate);
  const fit = await dispatch(impl, [marks], p.binding, { run: ctx.run, key: p.by });
  store.write(op.writes[0], fit, "assigned");
  const m = await materialize(fit, ctx.run);
  // §5a: an ACTIVE treatment (explicit/zero) transforms the envelope before the hole write; the
  // emission shape (operator.ts) guarantees the APPLY consumes this same treated cell, so marks
  // and ticks read one envelope. The raw fit (writes[0]) stays untouched for side products.
  store.write(op.writes[1], applyTreatment(m, p.treatment), "assigned");
}
