// arrange (C6, WULAYOUT_IMPL §C6) — the box model as an OPERATOR in the dataflow, one per node.
// `arrangeNode` builds the node's ArrangeInstance (required equalities over its extent cells +
// the node's raw component-emitted constraints) onto `Node.arrange` and returns the OpSpec that
// solves it: reads = the node's OUTER edges, writes = its CONTENT edges + each child's OUTER edges.
// The root's outer is sealed at authoring (the canvas literal), so the scheduler orders the
// down-pass parent-before-child purely off the declared cells; run.ts resolves the solver by NAME
// (Registries.arrangeSolvers — `propagation` today) and runs it over the store.
// ponytail: the child inset is a FIXED corner box — a placeholder standing in for the per-row
// nest-join (each host mark row → its own child extent), which is the next increment. Demand
// (up-pass) + absorbsBelow + a Cassowary solver ride the same ArrangeInstance interface later.
import type { NodeId } from "../types/ids.js";
import { dvlSettings } from "../config.js";
import { propagation } from "./solvers/propagation.js";
import { cassowary } from "./solvers/cassowary.js";
import type { CellRef } from "../ir/cell.js";
import type { ArrangeInstance, Constraint } from "../ir/layout.js";
import type { Node } from "../ir/node.js";
import { arrangeIntents, ownedCells, shedToFit, type ShedItem } from "./sidestack.js";
import { lowerForCassowary, lowerForPropagation } from "./intents.js";
import type { Spec } from "../ir/spec.js";
import type { OpSpec } from "../plan/opspec.js";
import type { DomainGroups } from "../plan/compile/domains.js";
import { coord, dataSpace, pixelSpace } from "../types/attr.js";

export interface Margin {
  left: number;
  right: number;
  top: number;
  bottom: number;
}

export const DEFAULT_MARGIN: Margin = { left: 0, right: 0, top: 0, bottom: 0 };
export const NESTED_MARGIN: Margin = { left: 30, right: 8, top: 8, bottom: 22 };

/** `cell = (1-f)·lo + f·hi` — a proportional position between two edges. */
const lerp = (cell: CellRef, lo: CellRef, hi: CellRef, f: number): Constraint => ({ terms: [{ coef: 1, edge: cell }, { coef: -(1 - f), edge: lo }, { coef: -f, edge: hi }], op: "=", constant: 0, strength: "required" });

/** Build the node's ArrangeInstance (onto `node.arrange`) + the operator description that solves it.
 *  Constraints: content = outer inset by the margin (STRONG defaults — the solver tightens them by the
 *  node's `≥` bounds, WULAYOUT_IMPL §C6) + the node's RAW component constraints. The op READS any
 *  non-extent cells those constraints reference (measured demand), so the scheduler orders
 *  measure → arrange. Children are NOT placed here — a child's outer is its host MARK's placed box,
 *  extracted by the `host-extent` op (containers are marks; §C6).  */
/** The node's minimum plot area (mirrors lower-axes MIN_PLOT) — the space shedding must preserve. */
const SHED_MIN_PLOT = 40;

/** Priority shedding (Step 5). For a SCALAR node whose outer extent is known at build time (the root
 *  canvas), decide per side which sheddable bands to drop so the plot keeps at least SHED_MIN_PLOT.
 *  Sheds by setting each dropped band's `indicator` cell to 0 — the existing vtable gate then empties
 *  its V (no marks + zero measured thickness), so its reservation naturally goes to 0 through the
 *  ordinary measure→arrange loop. Decided ONCE here on stable SEED thicknesses + the sealed outer, so
 *  it cannot oscillate across sweeps (§5 anti-oscillation: a coarse, one-way decision). Non-root nodes
 *  (unknown outer at compile) are skipped — their gutters are bounded by the demand-floor diagnostic. */
function applyShedding(spec: Spec, node: Node): void {
  const bands = node.sideBands;
  if (bands === undefined || node.insets !== undefined) return;
  const o = node.extent.outer;
  const rd = (c: CellRef): number | undefined => { const v = spec.cells.read(c); return typeof v === "number" ? v : undefined; };
  const oL = rd(o.left), oR = rd(o.right), oT = rd(o.top), oB = rd(o.bottom);
  if (oL === undefined || oR === undefined || oT === undefined || oB === undefined) return; // outer not known (non-root)
  const W = oR - oL, H = oB - oT;
  const thick = (b: (typeof bands)[number]): number => {
    const isH = b.side === "left" || b.side === "right";
    return rd(isH ? b.rect.w : b.rect.h) ?? 0;
  };
  const OPP = { left: "right", right: "left", top: "bottom", bottom: "top" } as const;
  for (const side of ["left", "right", "top", "bottom"] as const) {
    const onSide = bands.filter((b) => b.side === side);
    if (!onSide.some((b) => b.shed !== undefined)) continue;
    const normal = side === "left" || side === "right" ? W : H;
    const oppTotal = bands.filter((b) => b.side === OPP[side]).reduce((s, b) => s + thick(b), 0);
    const nonShed = onSide.filter((b) => b.shed === undefined).reduce((s, b) => s + thick(b), 0);
    const budget = normal - SHED_MIN_PLOT - nonShed - oppTotal;
    const sheddable: ShedItem[] = onSide.filter((b) => b.shed !== undefined).map((b) => ({ id: b.id, priority: b.shed!.priority, thickness: thick(b) }));
    const drop = shedToFit(sheddable, budget);
    for (const b of onSide) if (drop.has(b.id) && b.shed?.indicator !== undefined) spec.cells.write(b.shed.indicator, 0, "assigned");
  }
}

export function arrangeNode(spec: Spec, nodeId: NodeId, margin: Margin): OpSpec {
  const node = spec.nodes.get(nodeId);
  if (node === undefined) throw new Error(`arrangeNode: no node "${nodeId}"`);
  applyShedding(spec, node); // Step 5: gate over-budget sheddable bands before building the stack
  const o = node.extent.outer;
  const c = node.extent.content;

  // THE INTENT PATH (Step 8, completed): the node's margins + ALIGNED bands (Steps 1–4) are built as
  // solver-agnostic Intent[] by sidestack.arrangeIntents — per side ONE `reserve` (margin floor +
  // summed band demand; co-located adornments SUM) plus the rigid chain/center affines. The solver is
  // picked FIRST (only node.constraints can carry the soft strengths that force cassowary), then its
  // OWN lowering encodes the reserves — arrangeNode never names a strength for them. Each band's x/y
  // is solver-OWNED; the reservation references its measured w/h (a read). Perpendicular end-spacer
  // `≥` floors stay in node.constraints and still MAX in via propagation's bound rule.
  const bands = node.sideBands ?? [];
  const solver = pickSolver(node.constraints);
  const intents = arrangeIntents(spec.cells, node.extent, margin, bands);
  const cons: Constraint[] = [
    ...(solver === "cassowary" ? lowerForCassowary(intents) : lowerForPropagation(intents)),
    ...node.constraints,
  ];
  const writes: CellRef[] = [c.left, c.right, c.top, c.bottom, ...ownedCells(bands)];

  // reads = the outer box + every non-extent cell the constraints reference (demand cells) — the
  // dependency that puts this op after the node's measure op in the schedule.
  const own = new Set<CellRef>([o.left, o.right, o.top, o.bottom, ...writes]);
  const reads: CellRef[] = [o.left, o.right, o.top, o.bottom];
  for (const k of cons) for (const t of k.terms) if (!own.has(t.edge) && !reads.includes(t.edge)) reads.push(t.edge);

  // RE-SEED the node's demand estimate to include the margin defaults (§C6): demand.w/h is the TRUE
  // minimum footprint — actual insets are max(default, measured gutter). The measure op overwrites
  // with per-side-floored values; a node with nothing to measure keeps this margin-inclusive seed,
  // so measured and unmeasured siblings stay commensurable in the row allocation. Guarded by the
  // first-arrange check (node.arrange unset) — a re-compile must not bump the seed again.
  if (node.arrange === undefined && node.demand !== undefined) {
    const w = spec.cells.read(node.demand.w);
    const h = spec.cells.read(node.demand.h);
    if (typeof w === "number") spec.cells.write(node.demand.w, w + margin.left + margin.right, "estimated");
    if (typeof h === "number") spec.cells.write(node.demand.h, h + margin.top + margin.bottom, "estimated");
  }
  const instance: ArrangeInstance = { id: `${nodeId}/arrange`, scope: nodeId, constraints: cons, objective: "none", solver, resolvedSolver: SOLVERS[solver as keyof typeof SOLVERS], margin };
  node.arrange = instance;
  return { id: `${nodeId}:arrange`, reads, writes, payload: { kind: "arrange", nodeId } };
}

/** The TEMPLATE variant (§C8): a data-driven child has no scalar outer extent — its outer IS the
 *  host's box relation — so its arrange solves INSET cells instead; the keyed affine then places
 *  into `box ⊖ insets` per cell. Gutter constraints have inset form (`inset − demand ≥ 0`, pushed
 *  by lowering onto node.constraints): the STRONG inset defaults below are tightened by those
 *  measured bounds (propagation's 1-term rule) — the exact analogue of a scalar node's margins. */
export function arrangeTemplate(spec: Spec, nodeId: NodeId, margin: Margin): OpSpec {
  const node = spec.nodes.get(nodeId);
  if (node === undefined) throw new Error(`arrangeTemplate: no node "${nodeId}"`);
  node.insets ??= { left: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("x"))), right: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("x"))), top: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("y"))), bottom: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("y"))) };
  // STRONG defaults (§C8 incr 3): axis gutters (`inset − demand ≥ 0`, pushed by lowering onto
  // node.constraints) TIGHTEN these — the same rule that tightens a scalar node's margin equalities.
  const one = (edge: CellRef, k: number, side: string): Constraint => ({ terms: [{ coef: 1, edge }], op: "=", constant: k, strength: "strong", label: `inset:${side}` });
  const cons: Constraint[] = [
    one(node.insets.left, margin.left, "left"),
    one(node.insets.right, margin.right, "right"),
    one(node.insets.top, margin.top, "top"),
    one(node.insets.bottom, margin.bottom, "bottom"),
    ...node.constraints,
  ];
  const writes = [node.insets.left, node.insets.right, node.insets.top, node.insets.bottom];
  const own = new Set<CellRef>(writes);
  const reads: CellRef[] = [];
  for (const k of node.constraints) for (const t of k.terms) if (!own.has(t.edge) && !reads.includes(t.edge)) reads.push(t.edge);
  // demand re-seed, margin-inclusive — same commensurability rule as arrangeNode (guarded).
  if (node.arrange === undefined && node.demand !== undefined) {
    const w = spec.cells.read(node.demand.w);
    const h = spec.cells.read(node.demand.h);
    if (typeof w === "number") spec.cells.write(node.demand.w, w + margin.left + margin.right, "estimated");
    if (typeof h === "number") spec.cells.write(node.demand.h, h + margin.top + margin.bottom, "estimated");
  }
  const solver = pickSolver(cons);
  node.arrange = { id: `${nodeId}/arrange`, scope: nodeId, constraints: cons, objective: "none", solver, resolvedSolver: SOLVERS[solver as keyof typeof SOLVERS], margin };
  return { id: `${nodeId}:arrange`, reads, writes, payload: { kind: "arrange", nodeId } };
}

/** Pick the solver. `dvlSettings.arrangeSolver` forces one for every node; "auto" (default) upgrades
 *  to Cassowary only when a medium/weak constraint is present — propagation handles required+strong
 *  (equalities + tightening bounds), Cassowary the soft trade-offs propagation can't resolve. */
export function pickSolver(cons: readonly Constraint[]): string {
  const forced = dvlSettings.arrangeSolver;
  if (forced === "propagation" || forced === "cassowary") return forced;
  for (const c of cons) {
    if (c.strength === "medium" || c.strength === "weak") return "cassowary";
  }
  return "propagation";
}
// resolve-once: the creator binds the solver FUNCTION alongside its name (pickSolver's choice is
// static — a registry lookup added nothing); the arrange op reads resolvedSolver, never a registry.
const SOLVERS = { propagation, cassowary } as const;

/** `sum(±1·edge) ≥ k`, labeled — a DECLARED placement fact for the solver/verifier. */
const ge = (terms: Constraint["terms"], k: number, strength: Constraint["strength"], label: string): Constraint => ({ terms, op: ">=", constant: k, strength, label });

/** The ARRANGEMENT of fully-holed siblings (WULAYOUT_IMPL §C6/§C8): row (partition x, span+share y)
 *  vs column (partition y, span+share x), INFERRED from which scale the siblings share. A shared
 *  scale wants to be ALIGNED, so the panels partition along the OTHER axis: shared-y ⇒ side by side
 *  (one y-axis, separate x); shared-x ⇒ stacked (one x-axis, separate y). Read off the domain groups
 *  (sharing is compile-pinned today, like the gather-scatter partition); the discrete solver
 *  generalizes this to a decision cell + grids later. Ambiguous (both/neither shared) ⇒ row. */
function inferPartitionAxis(spec: Spec, arranged: readonly { node: NodeId }[], domains: DomainGroups): "x" | "y" {
  if (arranged.length < 2) return "x";
  const arrangedNodes = new Set(arranged.map((ch) => ch.node));
  let sharesX = false;
  let sharesY = false;
  for (const g of domains.groups) {
    const dim = spec.layouts.get(g.ids[0])?.dim;
    const hit = new Set<NodeId>();
    for (const id of g.ids) for (const m of spec.layouts.get(id)?.members ?? []) {
      const pn = spec.plots.get(m.plot)?.node;
      if (pn !== undefined && arrangedNodes.has(pn)) hit.add(pn);
    }
    if (hit.size >= 2) {
      if (dim === "x") sharesX = true;
      else if (dim === "y") sharesY = true;
    }
  }
  if (sharesX && !sharesY) return "y"; // shared x → align x → stack (column)
  return "x"; // shared y, both, or neither → side by side (row)
}

/** The under-determination stage (WULAYOUT_IMPL §C6 holes → the solver), in two layers:
 *
 *  DECLARE — the general placement facts ANY realization must satisfy, pushed onto the instance for
 *  the solver (Cassowary consumes them; the verify op checks them post-solve):
 *    · containment (required): every child ⊆ the parent content;
 *    · demand-min (strong): a child at least its measured footprint (the demand CELLS as terms);
 *    · ordering (required): the chosen arrangement linearizes non-overlap along the partition axis;
 *    · alignment (medium) + equal-size (weak): soft preferences, RECORDED for Cassowary — the naive
 *      tier ignores them.
 *
 *  REALIZE — the naive tier's closed form: FULLY-HOLED siblings (no layout bound) partition along the
 *  inferred axis (row/column, demand-weighted) and span the other; a partially-placed child's stray
 *  holes pin/span to their content edge. One solution to the declarations, not the source of truth. */
export function fillChildExtentHoles(spec: Spec, specs: OpSpec[], domains: DomainGroups): void {
  const written = new Set<CellRef>();
  for (const op of specs) for (const w of op.writes) written.add(w);

  for (const node of spec.nodes.values()) {
    if (node.children.length === 0 || node.arrange === undefined) continue;
    const c = node.extent.content;
    const extra: Constraint[] = [];
    const holes: CellRef[] = [];
    const readsExtra: CellRef[] = []; // non-owned cells the new constraints reference (child demands)
    const cover = (cell: CellRef, lo: CellRef, hi: CellRef, f: number): void => {
      extra.push(lerp(cell, lo, hi, f));
      holes.push(cell);
    };

    // DECLARE — for EVERY child (holed or host-extent'd alike: an inset that overflows is a caught
    // violation, not a silent one).
    for (const ch of node.children) {
      if (ch.hostRow === undefined) continue; // a TEMPLATE child (§C8): no scalar extents — its containment is per-cell (relational verify, later)
      const childNode = spec.nodes.get(ch.node);
      if (childNode === undefined) continue;
      const co = childNode.extent.outer;
      extra.push(
        ge([{ coef: 1, edge: co.left }, { coef: -1, edge: c.left }], 0, "required", `contain:${ch.node}:left`),
        ge([{ coef: 1, edge: c.right }, { coef: -1, edge: co.right }], 0, "required", `contain:${ch.node}:right`),
        ge([{ coef: 1, edge: co.top }, { coef: -1, edge: c.top }], 0, "required", `contain:${ch.node}:top`),
        ge([{ coef: 1, edge: c.bottom }, { coef: -1, edge: co.bottom }], 0, "required", `contain:${ch.node}:bottom`),
      );
      if (childNode.demand !== undefined) {
        extra.push(
          ge([{ coef: 1, edge: co.right }, { coef: -1, edge: co.left }, { coef: -1, edge: childNode.demand.w }], 0, "strong", `min-w:${ch.node}`),
          ge([{ coef: 1, edge: co.bottom }, { coef: -1, edge: co.top }, { coef: -1, edge: childNode.demand.h }], 0, "strong", `min-h:${ch.node}`),
        );
        readsExtra.push(childNode.demand.w, childNode.demand.h);
      }
    }

    // The ARRANGED set: FULLY-HOLED children (no layout bound at all → all four edges unwritten).
    // Their arrangement is INFERRED from sharing; a partially-placed child (host-extent wrote some
    // edges) drops to the stray-pin pass below (its holed edges span, unchanged).
    const fullyHoled = node.children.filter((ch) => {
      if (ch.hostRow === undefined) return false; // template children (§C8) have no scalar extents to arrange
      const co = spec.nodes.get(ch.node)?.extent.outer;
      return co !== undefined && !written.has(co.left) && !written.has(co.right) && !written.has(co.top) && !written.has(co.bottom);
    });
    const P = inferPartitionAxis(spec, fullyHoled, domains); // "x" = row, "y" = column
    // partition-axis (P) + span-axis (S) accessors over the content box and a child's outer box.
    const cLoP = P === "x" ? c.left : c.top;
    const cHiP = P === "x" ? c.right : c.bottom;
    const cLoS = P === "x" ? c.top : c.left;
    const cHiS = P === "x" ? c.bottom : c.right;
    const loP = (co: Node["extent"]["outer"]): CellRef => (P === "x" ? co.left : co.top);
    const hiP = (co: Node["extent"]["outer"]): CellRef => (P === "x" ? co.right : co.bottom);
    const loS = (co: Node["extent"]["outer"]): CellRef => (P === "x" ? co.top : co.left);
    const hiS = (co: Node["extent"]["outer"]): CellRef => (P === "x" ? co.bottom : co.right);
    const demandP = (cn: Node): CellRef => (P === "x" ? cn.demand!.w : cn.demand!.h);

    // REALIZE the partition DEMAND-WEIGHTED (§C6): the interior boundary fractions are CELL
    // COEFFICIENTS written by an `allocate` decision op — each panel gets its demand plus an equal
    // share of the surplus, so panels with differing gutters (an axis-merge survivor beside merged
    // interiors) end EQUAL in PLOT area. Shares SEEDED with the equal split (the seed IS the pre-6a
    // behavior, and it cuts the allocate↔arrange cycle). Cells hold −(1−f), −f (signed lerp coefs).
    const shares: CellRef[] = [];
    const N = fullyHoled.length;
    for (let k = 1; k < N; k++) {
      shares.push(spec.cells.alloc("param", -(1 - k / N), "scalar", dataSpace), spec.cells.alloc("param", -(k / N), "scalar", dataSpace));
    }
    const boundary = (cell: CellRef, k: number): void => {
      extra.push({ terms: [{ coef: 1, edge: cell }, { coef: shares[2 * (k - 1)], edge: cLoP }, { coef: shares[2 * (k - 1) + 1], edge: cHiP }], op: "=", constant: 0, strength: "required" });
      holes.push(cell);
    };

    fullyHoled.forEach((ch, i) => {
      const co = spec.nodes.get(ch.node)!.extent.outer;
      if (i > 0) {
        const prev = spec.nodes.get(fullyHoled[i - 1].node)!.extent.outer;
        const first = spec.nodes.get(fullyHoled[0].node)!.extent.outer;
        // ordering along P (required non-overlap); alignment along S + equal-size along P are soft.
        extra.push(ge([{ coef: 1, edge: loP(co) }, { coef: -1, edge: hiP(prev) }], 0, "required", `order:${fullyHoled[i - 1].node}|${ch.node}`));
        extra.push({ terms: [{ coef: 1, edge: loS(co) }, { coef: -1, edge: loS(first) }], op: "=", constant: 0, strength: "medium", label: `align-lo:${ch.node}` });
        extra.push({ terms: [{ coef: 1, edge: hiS(co) }, { coef: -1, edge: hiS(first) }], op: "=", constant: 0, strength: "medium", label: `align-hi:${ch.node}` });
        extra.push({ terms: [{ coef: 1, edge: hiP(co) }, { coef: -1, edge: loP(co) }, { coef: -1, edge: hiP(first) }, { coef: 1, edge: loP(first) }], op: "=", constant: 0, strength: "weak", label: `equal-size:${ch.node}` });
      }
      // partition along P (outer boundaries structural f = 0,1; interiors take the shares); span S.
      if (i === 0) cover(loP(co), cLoP, cHiP, 0);
      else boundary(loP(co), i);
      if (i === N - 1) cover(hiP(co), cLoP, cHiP, 1);
      else boundary(hiP(co), i + 1);
      cover(loS(co), cLoS, cHiS, 0);
      cover(hiS(co), cLoS, cHiS, 1);
    });
    if (N >= 2) {
      // the allocation DECISION op: reads the partition demands + the content P-span, writes shares.
      // Dim-agnostic executor: it just returns signed lerp coefs for whichever cells it is handed.
      specs.push({
        id: `${node.id}:allocate`,
        reads: [...fullyHoled.map((ch) => demandP(spec.nodes.get(ch.node)!)), cLoP, cHiP],
        writes: shares,
        payload: { kind: "allocate", nodeId: node.id },
      });
      readsExtra.push(...shares);
    }
    // stray-pin pass: a PARTIALLY-placed child's remaining holes span/pin to their content edge.
    for (const ch of node.children) {
      if (ch.hostRow === undefined || fullyHoled.includes(ch)) continue;
      const co = spec.nodes.get(ch.node)?.extent.outer;
      if (co === undefined) continue;
      if (!written.has(co.top) && !holes.includes(co.top)) cover(co.top, c.top, c.bottom, 0);
      if (!written.has(co.bottom) && !holes.includes(co.bottom)) cover(co.bottom, c.top, c.bottom, 1);
      if (!written.has(co.left) && !holes.includes(co.left)) cover(co.left, c.left, c.right, 0);
      if (!written.has(co.right) && !holes.includes(co.right)) cover(co.right, c.left, c.right, 1);
    }
    if (extra.length === 0) continue;

    node.arrange.constraints.push(...extra); // the instance data run.ts solves (and verify checks)
    const i = specs.findIndex((op) => op.id === `${node.id}:arrange`);
    if (i < 0) throw new Error(`fillChildExtentHoles: no arrange op for node "${node.id}"`);
    const reads = [...specs[i].reads, ...readsExtra.filter((r) => !specs[i].reads.includes(r) && !specs[i].writes.includes(r))];
    specs[i] = { ...specs[i], reads, writes: [...specs[i].writes, ...holes] }; // the solver now owns the holes
    for (const h of holes) written.add(h);
  }
}

/** Emit one `verify` op per arranged node (WULAYOUT_IMPL §C6): reads every cell its instance's HARD
 *  inequalities reference, evaluates them POST-SOLVE (its reads put it after the whole SCC), writes
 *  the violations to `node.diagnostics`. The naive realizer can satisfy or miss the declarations —
 *  either way the answer is DATA, not a silent lie; Cassowary later makes violations solvable. */
export function emitVerify(spec: Spec, specs: OpSpec[]): void {
  for (const node of spec.nodes.values()) {
    if (node.arrange === undefined) continue;
    const checks = node.arrange.constraints.filter((k) => k.op !== "=" && (k.strength === "required" || k.strength === "strong"));
    if (checks.length === 0) continue;
    const cells = new Set<CellRef>();
    for (const k of checks) {
      for (const t of k.terms) {
        cells.add(t.edge);
        if (typeof t.coef !== "number") cells.add(t.coef);
      }
      if (typeof k.constant !== "number") cells.add(k.constant);
    }
    node.diagnostics = spec.cells.alloc("sink", undefined, "relation");
    specs.push({ id: `${node.id}:verify`, reads: [...cells], writes: [node.diagnostics], payload: { kind: "verify", nodeId: node.id } });
  }
}
