// The dataflow graph: ops + cell-mediated topology index.
// Owns the plan array and maintains producer/consumers maps.
import type { CellRef } from "../ir/cell.js";
import type { OpSpec } from "../plan/opspec.js";

export class DataflowGraph {
  #ops: OpSpec[];
  #producerOf = new Map<CellRef, OpSpec>();
  #consumersOf = new Map<CellRef, OpSpec[]>();

  constructor(ops: OpSpec[]) {
    this.#ops = [...ops];
    this.#rebuild();
  }

  get ops(): readonly OpSpec[] { return this.#ops; }

  producer(cell: CellRef): OpSpec | undefined { return this.#producerOf.get(cell); }

  consumers(cell: CellRef): readonly OpSpec[] { return this.#consumersOf.get(cell) ?? []; }

  splice(anchor: OpSpec, deleteCount: number, ...newOps: OpSpec[]): void {
    const idx = this.#ops.indexOf(anchor);
    if (idx === -1) throw new Error("splice: anchor not in graph");
    this.#ops.splice(idx, deleteCount, ...newOps);
    this.#rebuild();
  }

  #rebuild(): void {
    this.#producerOf.clear();
    this.#consumersOf.clear();
    for (const op of this.#ops) {
      for (const w of op.writes) this.#producerOf.set(w, op);
      for (const r of op.reads) {
        const list = this.#consumersOf.get(r);
        if (list) list.push(op);
        else this.#consumersOf.set(r, [op]);
      }
    }
  }
}
