// Mark descriptors (extension point, registry-resolved by name) + the channel-kind
// vocabulary that is the channel-style boundary (WUIR_IMPL §2.1). A mark OWNS its
// `draw` (row -> pen primitives) -- adding a mark type is `defineMark({..., draw})`, never
// editing the renderer. `extentOf` is a SLOT filled by C6 (box model).
import type { ExprType, FontSpec } from "./types.js";
import type { ScalarExpr } from "../algebra/relop.js";
import type { Pen } from "./pen.js";
import type { Row } from "../data/schema.js";
import { coord, dataSpace, len, pixelSpace, relativeSpace, styleSpace, type LenAxis, type Space } from "../types/attr.js";
import { spaceFallbacks } from "../config.js";

/** The role a channel plays -- the modeled, declared set (everything else is opaque style).
 *  "pixel" means SPATIAL pixel (composes with positions: dx/dy nudges, w/h extents) — a
 *  pen-consumed glyph parameter (fontSize/rotate) is a style kind instead (§10.1: geom is
 *  earned by the affine/arithmetic, never by units). */
export type ChannelKind = "positional-x" | "positional-y" | "pixel" | "number" | "color" | "shape" | "text" | "fontSize" | "rotate" | "geometry";

const SPACE_OF_KIND: Record<ChannelKind, Space> = {
  "positional-x": relativeSpace(coord("x")),
  "positional-y": relativeSpace(coord("y")),
  pixel: pixelSpace(len("x")), // default axis; overridden per-channel by pixelAxes
  number: dataSpace,
  color: styleSpace("color"),
  shape: styleSpace("shape"),
  text: styleSpace("text"),
  fontSize: styleSpace("fontSize"), // px-valued but TERMINAL — the pen writes font-size (§10.1)
  rotate: styleSpace("rotate"), //     an angle; terminal until a polar affine exists (§10.1)
  geometry: styleSpace("geometry"), // a polygon: already-placed [x,y] vertices the pen draws as-is
};

/** The Space for a channel kind (kind-level, before per-channel axis refinement). */
export function spaceOfKind(k: ChannelKind): Space {
  return SPACE_OF_KIND[k];
}
// ── The default-wrapper table (triage §5b) ──────────────────────────────────────────────────
/** What a BARE value on a channel means. "lit" = a data value (placed through the axis's scale,
 *  widens its domain); "px" = a screen-pixel value (placed as-is); "value" = the value itself
 *  (color/text/… are not space-ambiguous). One readable table beside SPACE_OF_KIND — "what does
 *  `w: 12` mean" is answered here, not by tracing code paths. An explicit wrapper (`lit(v)` /
 *  `px(v)`) always wins over the default. */
export type DefaultWrap = "lit" | "px" | "value";
const WRAP_OF_KIND: Record<ChannelKind, DefaultWrap> = {
  "positional-x": "lit",
  "positional-y": "lit",
  pixel: "px",
  number: "value",
  color: "value",
  shape: "value",
  text: "value",
  fontSize: "value",
  rotate: "value",
  geometry: "value",
};
/** A channel's default wrapper: the mark's per-channel override, else the kind default. */
export function wrapOf(mark: { channels: Record<string, ChannelKind>; defaultWrap?: Record<string, DefaultWrap> }, channel: string): DefaultWrap {
  const kind = mark.channels[channel];
  return mark.defaultWrap?.[channel] ?? (kind !== undefined ? WRAP_OF_KIND[kind] : "value");
}

/** The required ExprType for a channel of this kind (per-row; literals broadcast). */
export function exprTypeOfKind(k: ChannelKind): ExprType {
  return { space: SPACE_OF_KIND[k], arity: "per-row" };
}

// --- C6 slot placeholder (extent / box model) ---
/** Where a box mark's positional (x, y) sits relative to its drawn box. `center` (the kind
 *  default) places the box centered on (x, y); `topleft` places (x, y) at the box's corner — the
 *  convention band layouts depend on (they hand out corner + size). Widen to the 9-point grid
 *  (`top`, `bottomright`, …) later without redesign. Single-sourced on the descriptor so `draw`
 *  and C6's `extentOf` read ONE default. */
export type MarkAnchor = "center" | "topleft";
/** What `extentOf` sees: which channels the plot BOUND (unbound channels have no column in the
 *  placed relation — an edge must not reference them), and the resolved anchor (the plot's literal
 *  binding or the descriptor default; data-driven anchors are rejected upstream, LOUD). For TEXT
 *  marks the anchor literal is the text-anchor vocabulary (start/middle/end) riding the same
 *  slot, and `baseline` carries the vertical alignment literal (top/middle/bottom) when bound —
 *  read them through `bound.has(...)` first, since the MarkAnchor default is box-mark language. */
export interface ExtentCtx { bound: ReadonlySet<string>; anchor: MarkAnchor; baseline?: string; }
/** Per-axis box edges as relop ScalarExprs over the mark's PLACED columns (post-affine pixels).
 *  left/right = min/max x edge; top/bottom = min/max y edge (pixel y grows downward). An axis with
 *  no bound positional channel stays absent — the mark contributes no box on that axis. */
export interface ExtentEdges { left?: ScalarExpr; right?: ScalarExpr; top?: ScalarExpr; bottom?: ScalarExpr; }
export interface MeasurementProvider {
  name: string;
  textExtent(text: string, font: FontSpec): { w: number; h: number };
}

/** A mark's row -> primitive renderer. The pen abstracts the target (SVG/canvas/...). */
export type DrawFn = (row: Row, pen: Pen) => void;

export interface MarkDescriptor {
  type: string;
  channels: Record<string, ChannelKind>; // the DECLARED set is the channel-style boundary
  spatial: { x: string[]; y: string[] }; // positional channels per dimension, first = primary
  pixelAxes?: Record<string, LenAxis>; // per-channel axis for "pixel" channels (W4b)
  /** Per-channel override of the kind-level default wrapper (WRAP_OF_KIND); rarely needed. */
  defaultWrap?: Record<string, DefaultWrap>;
  expectedType(channel: string): ExprType;
  containerEligible: boolean;
  cardinality: "per-row" | "aggregate" | "pairs"; // 1:1 | N rows -> 1 path (line/area) | 1:1 + LEAD successor (connect; SEQUENCE_MARKS §2)
  anchorDefault?: MarkAnchor; // box marks only: the default reference point when no `anchor` channel binding (C6-read)
  /** How a connector should treat this mark's box when clipping an endpoint to its boundary
   *  (§5.1): `"box"` (default) = the L∞ edges as stated; `"ellipse"` = the inscribed ellipse —
   *  a dot's ±r box is really a circle, so clipping in the L2 metric lands EXACTLY r from center. */
  boundaryShape?: "box" | "ellipse";
  draw?: DrawFn; // how this mark turns a row into scene elements (undefined => not renderable yet)
  extentOf?(ctx: ExtentCtx): ExtentEdges; // C6: the symbolic per-row box (lowered as the `box:` relop)
  /** draw's INPUT SCHEMA (triage §4): the columns draw reads to paint anything, as a conjunction
   *  of clauses — a string is a required column; an inner array is alternatives (at least one).
   *  Stated in draw's namespace (post-lowering COLUMNS, not author channels — connect's are the
   *  pairs-minted x1..y2). Checked generically at the render sink (checkPlan), where the final
   *  schema is provably known; requiredness = the column EXISTS (per-row NULLs stay legal — e.g.
   *  connect's degenerate tail). OPTIONAL: a mark that declares nothing gets no check. */
  needs?: readonly (string | readonly string[])[];
}

export function defineMark(spec: { type: string; channels: Record<string, ChannelKind>; pixelAxes?: Record<string, LenAxis>; defaultWrap?: Record<string, DefaultWrap>; containerEligible?: boolean; cardinality?: "per-row" | "aggregate" | "pairs"; anchorDefault?: MarkAnchor; boundaryShape?: "box" | "ellipse"; draw?: DrawFn; extentOf?: (ctx: ExtentCtx) => ExtentEdges; needs?: readonly (string | readonly string[])[] }): MarkDescriptor {
  const { channels, pixelAxes } = spec;
  const spatial: { x: string[]; y: string[] } = { x: [], y: [] };
  for (const [ch, kind] of Object.entries(channels)) {
    if (kind === "positional-x") spatial.x.push(ch);
    else if (kind === "positional-y") spatial.y.push(ch);
  }
  return {
    type: spec.type,
    channels,
    spatial,
    pixelAxes,
    defaultWrap: spec.defaultWrap,
    containerEligible: spec.containerEligible ?? false,
    cardinality: spec.cardinality ?? "per-row",
    anchorDefault: spec.anchorDefault,
    boundaryShape: spec.boundaryShape,
    draw: spec.draw,
    extentOf: spec.extentOf,
    needs: spec.needs,
    expectedType(channel) {
      const k = channels[channel];
      if (k === undefined) throw new Error(`mark "${spec.type}" has no channel "${channel}"`);
      if (k === "pixel") {
        const declared = pixelAxes?.[channel];
        if (declared === undefined) { spaceFallbacks.note(`defineMark:${spec.type}.${channel}`); }
        const axis: LenAxis = declared ?? "xy";
        return { space: pixelSpace(len(axis)), arity: "per-row" };
      }
      return exprTypeOfKind(k);
    },
  };
}
