// The built-in marks — common AFFINE marks across Vega-Lite, Observable Plot, and dvl-legacy.
// They're all one-liners over `defineMark`, so they're grouped here (the complexity is the
// shared draws in _draw.ts). Non-affine (arc/pie polar, geoshape) are deferred to the
// non-affine coordinate work; composites (error-bar/band) lower to several primitive marks.
import { defineMark, type ExtentCtx, type ExtentEdges, type MarkDescriptor } from "../../ir/mark.js";
import { num, numOpt, str, styleOf, DEFAULT_FONT_FAMILY } from "../../ir/pen.js";
import { bin, call, lit, mcol, unary, type ScalarExpr } from "../../algebra/relop.js";
import { drawArrow, drawBox, drawHull, drawPath, drawSegment, fillPaint, anchorOffset, boxStyle, rectChannels, strokePaint, strokedStyle } from "./_draw.js";

// --- extentOf (C6): the symbolic per-row box, closed-form for the arithmetic marks. ---
// least/greatest without widening the relop vocabulary: (a+b∓|a−b|)/2.
const least = (a: ScalarExpr, b: ScalarExpr): ScalarExpr => bin("/", bin("-", bin("+", a, b), unary("abs", bin("-", a, b))), lit(2));
const greatest = (a: ScalarExpr, b: ScalarExpr): ScalarExpr => bin("/", bin("+", bin("+", a, b), unary("abs", bin("-", a, b))), lit(2));
const half = (c: string): ScalarExpr => bin("/", mcol(c), lit(2));
// One axis of a box mark: offset form (pos + len, anchor-aware), interval form (pos/pos2), or a
// degenerate point (pos only). An unbound primary position ⇒ no edges on that axis (the placed
// relation has no column to reference — e.g. the synthetic panels host rect binds nothing).
function boxAxis(ctx: ExtentCtx, pos: string, len: string, pos2: string): [ScalarExpr, ScalarExpr] | undefined {
  if (!ctx.bound.has(pos)) return undefined;
  const p = mcol(pos);
  if (ctx.bound.has(len)) {
    return ctx.anchor === "center"
      ? [bin("-", p, half(len)), bin("+", p, half(len))]
      : [p, bin("+", p, mcol(len))];
  }
  if (ctx.bound.has(pos2)) return [least(p, mcol(pos2)), greatest(p, mcol(pos2))];
  return [p, p];
}
function boxEdges(ctx: ExtentCtx): ExtentEdges {
  const e: ExtentEdges = {};
  const x = boxAxis(ctx, "x", "w", "x2");
  if (x !== undefined) [e.left, e.right] = x;
  const y = boxAxis(ctx, "y", "h", "y2");
  if (y !== undefined) [e.top, e.bottom] = y;
  return e;
}
// dot: centered by nature; radius default 3 matches the draw default (pipeline sees what the pen draws).
function dotEdges(ctx: ExtentCtx): ExtentEdges {
  const e: ExtentEdges = {};
  const r = ctx.bound.has("r") ? mcol("r") : lit(3);
  if (ctx.bound.has("x")) { e.left = bin("-", mcol("x"), r); e.right = bin("+", mcol("x"), r); }
  if (ctx.bound.has("y")) { e.top = bin("-", mcol("y"), r); e.bottom = bin("+", mcol("y"), r); }
  return e;
}
// text (box-text explainer, 2026-07-22): the two-arm extent.
// BOX arm — a bound w/h IS that axis's extent ([x, x+w], exact; anchor only places glyphs
// INSIDE the box). GLYPH arm — no box on the axis: estimate from the character-width heuristic
// the no-DOM measuring pen already trusts (w ≈ length(text)·fontSize·0.6, h ≈ fontSize·1.2),
// hung off the anchor/baseline literals. The estimate depends on text/fontSize only — never the
// current scale range — so the expansion fixpoint converges exactly as it does for dot's r.
// NOTE ctx.anchor carries TEXT's literal (start/middle/end) when bound; the MarkAnchor default
// is box-mark language, so read it through bound.has() first.
function textEdges(ctx: ExtentCtx): ExtentEdges {
  const e: ExtentEdges = {};
  const fs: ScalarExpr = ctx.bound.has("fontSize") ? mcol("fontSize") : lit(10);
  if (ctx.bound.has("x")) {
    const x = ctx.bound.has("dx") ? bin("+", mcol("x"), mcol("dx")) : mcol("x");
    if (ctx.bound.has("w")) {
      [e.left, e.right] = [x, bin("+", x, mcol("w"))]; // the box IS the extent
    } else {
      const w = bin("*", bin("*", call("length", [mcol("text")]), fs), lit(0.6));
      const anchor = ctx.bound.has("anchor") ? String(ctx.anchor) : "start";
      if (anchor === "middle") [e.left, e.right] = [bin("-", x, bin("/", w, lit(2))), bin("+", x, bin("/", w, lit(2)))];
      else if (anchor === "end") [e.left, e.right] = [bin("-", x, w), x];
      else [e.left, e.right] = [x, bin("+", x, w)];
    }
  }
  if (ctx.bound.has("y")) {
    const y = ctx.bound.has("dy") ? bin("+", mcol("y"), mcol("dy")) : mcol("y");
    if (ctx.bound.has("h")) {
      [e.top, e.bottom] = [y, bin("+", y, mcol("h"))];
    } else {
      const h = bin("*", fs, lit(1.2));
      const baseline = ctx.bound.has("baseline") ? (ctx.baseline ?? "alphabetic") : "alphabetic";
      if (baseline === "middle") [e.top, e.bottom] = [bin("-", y, bin("/", h, lit(2))), bin("+", y, bin("/", h, lit(2)))];
      else if (baseline === "top") [e.top, e.bottom] = [y, bin("+", y, h)];
      else [e.top, e.bottom] = [bin("-", y, h), y]; // alphabetic/bottom: glyphs sit above the point
    }
  }
  return e;
}

export const markComponents: readonly MarkDescriptor[] = [
  // points (VL point/circle/square; Plot dot)
  defineMark({ type: "dot", channels: { x: "positional-x", y: "positional-y", r: "pixel", shape: "shape", ...fillPaint }, pixelAxes: { r: "xy", strokeWidth: "xy" }, boundaryShape: "ellipse", extentOf: dotEdges, needs: ["x", "y"], draw: (r, pen) => pen.circle(num(r, "x"), num(r, "y"), num(r, "r", 3), styleOf(r)) }),
  // rectangles — container-eligible hosts for nesting/faceting (VL bar/rect; Plot bar/rect/cell)
  defineMark({ type: "rect", containerEligible: true, channels: rectChannels, pixelAxes: { w: "x", h: "y", strokeWidth: "xy" }, anchorDefault: "topleft", extentOf: boxEdges, needs: ["x", "y", ["w", "x2"], ["h", "y2"]], draw: drawBox("topleft") }),
  defineMark({ type: "bar", containerEligible: true, channels: rectChannels, pixelAxes: { w: "x", h: "y", strokeWidth: "xy" }, anchorDefault: "topleft", extentOf: boxEdges, needs: ["x", "y", ["w", "x2"], ["h", "y2"]], draw: drawBox("topleft") }),
  // cell: the heatmap tile — a positioned box that FILLS its band(s). Like Observable Plot's cell,
  // it takes w/h from the layout it sits in (bandX × bandY), or explicit sizes; unbound w/h fall
  // back to 0 (a leaf tile nested in a container gets its box from the host instead).
  defineMark({ type: "cell", containerEligible: true, channels: { x: "positional-x", y: "positional-y", w: "pixel", h: "pixel", anchor: "shape", ...fillPaint }, pixelAxes: { w: "x", h: "y", strokeWidth: "xy" }, anchorDefault: "topleft", extentOf: boxEdges, needs: ["x", "y", "w", "h"], draw: drawBox("topleft") }),
  // paths (N points -> 1 path: cardinality "aggregate"; the array_agg -> `d` is path-agg). `order`
  // is the SEQUENCE channel (SEQUENCE_MARKS §3.1) — the column the points sort by; default x.
  defineMark({ type: "line", cardinality: "aggregate", channels: { x: "positional-x", y: "positional-y", order: "number", ...strokePaint }, pixelAxes: { strokeWidth: "xy" }, draw: drawPath }),
  // path: the aggregate PRIMITIVE — an ordered point set -> ONE open polyline (line = path; a
  // trajectory/spiral binds `order` explicitly since x is not monotone).
  defineMark({ type: "path", cardinality: "aggregate", channels: { x: "positional-x", y: "positional-y", order: "number", ...strokePaint }, pixelAxes: { strokeWidth: "xy" }, draw: drawPath }),
  defineMark({ type: "area", cardinality: "aggregate", channels: { x: "positional-x", y: "positional-y", x2: "positional-x", y2: "positional-y", order: "number", ...fillPaint }, pixelAxes: { strokeWidth: "xy" }, draw: drawPath }),
  // connect: the PAIR sibling (SEQUENCE_MARKS §4) — each point borrows its successor's coords via
  // a LEAD window (1:1; the partition tail is degenerate/invisible); drawn like a link segment.
  defineMark({ type: "connect", cardinality: "pairs", channels: { x: "positional-x", y: "positional-y", order: "number", ...strokePaint }, pixelAxes: { strokeWidth: "xy" }, needs: ["x1", "y1", "x2", "y2"], draw: drawSegment("x1", "y1", "x2", "y2") }),
  // hull: a per-row POLYGON around a matched point set. Its `path` channel carries the vertices a
  // GEOMETRY reducer minted (convex/bbox) over a via into a point plot — `pts.via(on('species'),
  // { resolve: { path: { js: 'convex' } } }).pick('path')` — already-placed pixel [x,y], drawn as-is
  // (design/2026-07-20-convexhull-resolver.html). Strokes AND fills, so it takes the full paint set.
  defineMark({ type: "hull", channels: { path: "geometry", ...fillPaint }, pixelAxes: { strokeWidth: "xy" }, needs: ["path"], draw: drawHull }),
  // segments / connectors (Plot rule/link/arrow/vector; VL rule)
  defineMark({ type: "rule", channels: { x: "positional-x", y: "positional-y", x2: "positional-x", y2: "positional-y", ...strokePaint }, pixelAxes: { strokeWidth: "xy" }, needs: ["x", "y", ["x2", "y2"]], draw: drawSegment("x", "y", "x2", "y2") }),
  defineMark({ type: "link", channels: { x1: "positional-x", y1: "positional-y", x2: "positional-x", y2: "positional-y", ...strokePaint }, pixelAxes: { strokeWidth: "xy" }, needs: ["x1", "y1", ["x2", "y2"]], draw: drawSegment("x1", "y1", "x2", "y2") }),
  // bezier: link's curved sibling — the same x1,y1 → x2,y2 endpoint contract (borrowed via
  // `via().pick`, exactly like link), drawn as ONE cubic Bézier per row. Curve options:
  //   curvature — signed perpendicular bow as a FRACTION of the chord length (default 0.25;
  //     negative bends the other way; 0 = a straight segment; peak deviation ≈ ¾·curvature·chord).
  //   cx1/cy1/cx2/cy2 — explicit control points, ordinary POSITIONAL channels (scale-bindable,
  //     borrowable). When all four are bound they win over curvature (flow maps, edge bundling).
  defineMark({
    type: "bezier",
    channels: { x1: "positional-x", y1: "positional-y", x2: "positional-x", y2: "positional-y", cx1: "positional-x", cy1: "positional-y", cx2: "positional-x", cy2: "positional-y", curvature: "number", ...strokePaint },
    pixelAxes: { strokeWidth: "xy" },
    needs: ["x1", "y1", "x2", "y2"],
    draw: (r, pen) => {
      const x1 = num(r, "x1"), y1 = num(r, "y1");
      const x2 = num(r, "x2", x1), y2 = num(r, "y2", y1);
      let cx1 = numOpt(r, "cx1"), cy1 = numOpt(r, "cy1"), cx2 = numOpt(r, "cx2"), cy2 = numOpt(r, "cy2");
      if (cx1 === undefined || cy1 === undefined || cx2 === undefined || cy2 === undefined) {
        const dx = x2 - x1, dy = y2 - y1;
        const chord = Math.hypot(dx, dy);
        if (chord === 0) return; // degenerate (missing/self endpoint) — nothing to draw, like link's collapsed segment
        const k = num(r, "curvature", 0.25) * chord;
        const nx = (-dy / chord) * k, ny = (dx / chord) * k; // unit normal × bow
        cx1 = x1 + dx / 3 + nx; cy1 = y1 + dy / 3 + ny;
        cx2 = x1 + (2 * dx) / 3 + nx; cy2 = y1 + (2 * dy) / 3 + ny;
      }
      // stroke-only connector (like link/path): default stroke to black so an unbound stroke is
      // visible, not the silent-invisible bug class; fill:"none" keeps a bare <path> from filling.
      const s = strokedStyle(r);
      pen.path(`M${x1},${y1} C${cx1},${cy1} ${cx2},${cy2} ${x2},${y2}`, { ...s, fill: s.fill ?? "none" });
    },
  }),
  defineMark({ type: "arrow", channels: { x1: "positional-x", y1: "positional-y", x2: "positional-x", y2: "positional-y", headType: "shape", headSize: "pixel", ...strokePaint }, pixelAxes: { headSize: "xy", strokeWidth: "xy" }, needs: ["x1", "y1", ["x2", "y2"]], draw: drawArrow }),
  defineMark({
    type: "vector",
    channels: { x: "positional-x", y: "positional-y", length: "pixel", angle: "number", ...strokePaint },
    pixelAxes: { length: "xy", strokeWidth: "xy" },
    needs: ["x", "y", "length"],
    // ponytail: angle in radians, 0 = +x
    draw: (r, pen) => {
      const x = num(r, "x");
      const y = num(r, "y");
      const len = num(r, "length");
      const a = num(r, "angle");
      pen.line(x, y, x + len * Math.cos(a), y + len * Math.sin(a), styleOf(r));
    },
  }),
  // tick orientation: "vertical" (x-axis, extends in y) | "horizontal" (y-axis, extends in x).
  // ponytail: signs assume bottom/left axis placement; C7 flips them for top/right.
  defineMark({
    type: "tick",
    channels: { x: "positional-x", y: "positional-y", len: "pixel", orient: "shape", ...strokePaint },
    pixelAxes: { len: "xy", strokeWidth: "xy" },
    needs: ["x", "y"],
    draw: (r, pen) => {
      const x = num(r, "x");
      const y = num(r, "y");
      const len = num(r, "len", 4);
      if (str(r, "orient") === "horizontal") pen.line(x, y, x - len, y, styleOf(r));
      else pen.line(x, y, x, y + len, styleOf(r));
    },
  }),
  // text & image (VL/Plot text, image). dx/dy: PIXEL nudges the draw applies after placement
  // (an axis label sits `labelPad` px off its baseline -- WUAXIS §createAxis); anchor -> text-anchor.
  // BOX-PLACEABLE (box-text explainer): optional w/h channels — when a box is bound,
  // anchor/baseline align the glyph point WITHIN it (middle → x + w/2 …); no box = today's
  // point semantics, so axis/legend labels are untouched. dx/dy nudge AFTER box alignment.
  defineMark({
    type: "text",
    channels: { x: "positional-x", y: "positional-y", w: "pixel", h: "pixel", dx: "pixel", dy: "pixel", text: "text", anchor: "shape", baseline: "shape", fontSize: "fontSize", rotate: "rotate", fill: "color", opacity: "number" },
    pixelAxes: { w: "x", h: "y", dx: "x", dy: "y" },
    needs: ["x", "y", "text"],
    extentOf: textEdges,
    draw: (r, pen) => {
      // box alignment per axis (presence discriminates, like drawBox): the anchor point moves
      // inside the bound box; the paint attributes (text-anchor/dominant-baseline) stay as
      // authored, so glyphs hang off the computed point exactly as before.
      const w = numOpt(r, "w"), h = numOpt(r, "h");
      const anchor = str(r, "anchor");
      const baseline = str(r, "baseline");
      const ax = w === undefined ? num(r, "x") : anchor === "middle" ? num(r, "x") + w / 2 : anchor === "end" ? num(r, "x") + w : num(r, "x");
      const ay = h === undefined ? num(r, "y") : baseline === "middle" ? num(r, "y") + h / 2 : baseline === "bottom" ? num(r, "y") + h : num(r, "y");
      const x = ax + num(r, "dx", 0), y = ay + num(r, "dy", 0);
      const style = styleOf(r);
      style.fontFamily ??= DEFAULT_FONT_FAMILY; // pin the font so measure (getBBox) == render metrics
      const linesRaw = r.lines;
      const lines: string[] = typeof linesRaw === "string" ? JSON.parse(linesRaw) : null;
      if (lines && lines.length > 1 && pen.textMultiline) pen.textMultiline(lines, x, y, style);
      else pen.text(lines?.[0] ?? str(r, "text") ?? "", x, y, style);
    },
  }),
  // image: an <image href> box sized w*h (src = the URL/data-URI). opacity rides the style. Anchor
  // defaults to CENTER (glyph usage — the box is centered on (x, y)); pass anchor:"topleft" for a
  // corner-placed box (e.g. an image dropped into a band layout's solved rect).
  defineMark({ type: "image", channels: { x: "positional-x", y: "positional-y", w: "pixel", h: "pixel", anchor: "shape", src: "text", opacity: "number" }, pixelAxes: { w: "x", h: "y" }, anchorDefault: "center", extentOf: boxEdges, needs: ["x", "y", "w", "h", "src"], draw: (r, pen) => { const w = num(r, "w", 0), h = num(r, "h", 0); const [x, y] = anchorOffset(r, "center", w, h); pen.image(x, y, w, h, str(r, "src") ?? "", boxStyle(r)); } }),
];
