// Axis lowering (WUAXIS §2/§5): an axis is ORDINARY PLOTS over V — a rule (baseline), tick marks,
// and text labels — binding the frame scale APPLY-ONLY. `lowerAxes` runs once per spec at compile
// entry: `assignSides` resolves each frame scale's side (a DISCRETE assignment — a continuous solver
// has no notion of "left"; pins claim first, then the primary side, sides exclusive), then
// `createAxis` builds pure IR per placed scale: a `vtable` producer instance (domain → V), an
// `apply-only` instance (place V by the frame scale WITHOUT re-training), and the three plots.
// The compiler (graph.compileNode) then processes them like any plot — it never learns what a tick is.
import type { NodeId } from "../../types/ids.js";
import { col, layoutOutput, literal, type Expr } from "../../ir/expr.js";
import type { AxisOptions, AxisTitleOptions, Constraint, Scale } from "../../ir/layout.js";
import { coord, dataSpace, len, pixelSpace, relativeSpace, type Space } from "../../types/attr.js";
import type { CellRef } from "../../ir/cell.js";
import { templateNodeIds, type Node, type PlotRect } from "../../ir/node.js";
import type { Plot } from "../../ir/plot.js";
import type { Spec } from "../../ir/spec.js";
import type { Registries } from "../../operator/registry.js";
import { dock, type DockTarget } from "./layout-api.js";
import { placeToOrder, type NodeBand } from "../../layout/sidestack.js";
import { hostBindingMode } from "./binding-mode.js";
import type { OpSpec } from "../opspec.js";
import type { DomainGroups } from "../compile/domains.js";

export interface LowerOpts {
  tickCount?: number; // default tick count when neither the axis config nor the scale says
  strict?: boolean; // unplaceable axis (three on one dim, pin collision): throw instead of warn+skip
}

type Side = "top" | "right" | "bottom" | "left";
const SIDES: Record<"x" | "y", readonly Side[]> = { x: ["bottom", "top"], y: ["left", "right"] }; // primary side first

// per-side geometry: the box edge as a relative coord, the tick's signed length, the label nudge.
const EDGE_T: Record<Side, number> = { bottom: 0, left: 0, top: 1, right: 1 };
// axis-styling DEFAULTS — every one is author-overridable per axis via AxisOptions (tickLength,
// fontSize); the nudges DERIVE from them, so an override moves labels and gutters coherently.
const TICK_LEN = 5;
const FONT_SIZE = 10; // the label fontSize; also the demand cell's SEED estimate for an x-axis's label height
const EST_LABEL_W = 30; // the demand cell's SEED estimate for a y-axis's label width — MEASUREMENT replaces it
// label nudge per side: below-axis labels drop by tick + font (+1 breathing px); all others sit
// tick + 3 off the edge; y labels center vertically at ~0.3·font.
const labelFor = (side: Side, tickLen: number, fontSize: number): { dx: number; dy: number; anchor: string } => {
  const near = tickLen + 3;
  const vCenter = Math.round(fontSize * 0.3);
  switch (side) {
    case "bottom":
      return { dx: 0, dy: tickLen + fontSize + 1, anchor: "middle" };
    case "top":
      return { dx: 0, dy: -near, anchor: "middle" };
    case "left":
      return { dx: -near, dy: vCenter, anchor: "end" };
    case "right":
      return { dx: near, dy: vCenter, anchor: "start" };
  }
};


/** A node's minimum content area (its demand beyond the gutters) — the seed for `Node.demand`. */
export const MIN_PLOT = 40;

/** Lower every node's axes to plots (idempotent — a node lowers once). */
export function lowerAxes(spec: Spec, registries: Registries, opts: LowerOpts = {}): void {
  const templates = templateNodeIds(spec.nodes.values());
  for (const node of spec.nodes.values()) {
    if (node.axesLowered) continue;
    node.axesLowered = true;
    // the node's min-footprint demand cells (§C6 up-pass): the measure op fills them; seeded so a
    // future consumer (demand-driven container size — C8/Cassowary) can read pre-measure.
    node.demand = { w: spec.cells.alloc("demand", MIN_PLOT, "scalar", pixelSpace(len("x"))), h: spec.cells.alloc("demand", MIN_PLOT, "scalar", pixelSpace(len("y"))) };
    // §C8 incr 3 — TEMPLATE axes: a template's axes are ordinary axis plots whose bases BROADCAST
    // across the cells (V × host marks via an empty-predicate cell-key) and whose gutters constrain
    // the INSET cells (allocated here — lowering precedes compile; arrangeTemplate reuses them).
    const isTemplate = templates.has(node.id);
    if (isTemplate) {
      node.insets ??= { left: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("x"))), right: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("x"))), top: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("y"))), bottom: spec.cells.alloc("extent", undefined, "scalar", pixelSpace(coord("y"))) };
    }
    const candidates = axisCandidates(node, spec);
    // `.axis(dim, opts)` directives (recorded on the node) MERGE onto the matching frame scales —
    // the directive wins over the scale-level `axis:` config; `placement` pins the side.
    for (const d of node.adornments) {
      if (d.kind !== "axis") continue;
      const { kind: _k, axis: dim, placement, style: _s, ...axisOpts } = d;
      for (const s of candidates) {
        if (s.dim !== dim || s.axis === false) continue;
        s.axis = { ...(s.axis ?? {}), ...axisOpts };
        if (placement !== undefined) s.side = placement;
      }
    }
    assignSides(candidates, opts.strict ?? false);
    for (const scale of candidates) {
      if (scale.side === undefined) continue; // unplaced (assignSides warned / strict threw)
      createAxis(spec, registries, node, scale, opts, isTemplate);
    }
  }
}

/** Which producers get an axis on this node: its frame scales, plus any plot-bound POSITIONAL layout
 *  instance with a trained domain (eqx, col — "scale" is a ROLE: a ticked positional producer earns an
 *  axis whether or not it is frame-scoped). Suppressed (`axis:false`) and domain-less ones drop out. */
function axisCandidates(node: Node, spec: Spec): Scale[] {
  const out: Scale[] = [];
  const seen = new Set<string>();
  const add = (s: Scale, dim: "x" | "y"): void => {
    if (seen.has(s.id)) return;
    seen.add(s.id);
    if (s.axis === false || s.domain === undefined) return;
    s.dim ??= dim;
    out.push(s);
  };
  for (const sid of node.frame.scales) {
    const s = spec.layouts.get(sid) as Scale;
    add(s, s.dim ?? "x");
  }
  for (const pid of node.plots) {
    const plot = spec.plots.get(pid);
    if (plot === undefined) continue;
    // a CONTAINER plot (its marks host child nodes — a subplot/facet container) gets no axis: its
    // positional layout (eqx/col over the panels) ARRANGES panels, it is not a data encoding, so a
    // plot-style baseline under the panels is noise (WULAYOUT_IMPL §C8). Panel labels are a facet
    // header, a separate adornment. Leaf data plots (a bar's band x) host nothing → axis kept.
    if (node.children.some((cr) => cr.hostPlot === pid)) continue;
    for (const [ch, expr] of Object.entries(plot.channels)) {
      if (expr.kind !== "layout-output" || (ch !== "x" && ch !== "y")) continue;
      const sp = expr.type.space;
      if (sp.space !== "relative" && sp.space !== "pixel") continue;
      if (sp.geom.kind !== "coord") continue;
      add(spec.layouts.get(expr.layout) as Scale, sp.geom.axis);
    }
  }
  return out;
}

/** DISCRETE side assignment (WUAXIS §5): pins claim their side first, then unpinned scales take the
 *  first free side of their dim (primary preferred). A dim's sides are exclusive — an unplaceable
 *  axis (no free side) warns and stays sideless (its MARKS still render: the normalized frame places
 *  coords via the affine, no side needed — only the AXIS is skipped), or throws under `strict`. */
export function assignSides(candidates: readonly Scale[], strict: boolean): void {
  for (const dim of ["x", "y"] as const) {
    const scales = candidates.filter((s) => s.dim === dim);
    const taken = new Set<Side>();
    const claim = (s: Scale, want: Side | undefined): void => {
      const side = want !== undefined && !taken.has(want) ? want : SIDES[dim].find((c) => !taken.has(c));
      if (side === undefined) {
        const msg = `dvl: no free ${dim}-side for scale "${s.id}" (${scales.length} ${dim}-scales, ${SIDES[dim].length} sides) — its axis is not drawn`;
        if (strict) throw new Error(msg);
        console.warn(msg);
        s.side = undefined;
        return;
      }
      if (want !== undefined && side !== want) console.warn(`dvl: ${dim}-${want} is taken; placing "${s.id}" at ${dim}-${side}`);
      taken.add(side);
      s.side = side;
    };
    for (const s of scales) if (s.side !== undefined) claim(s, s.side); // pins first
    for (const s of scales) if (s.side === undefined) claim(s, undefined); // then preference order
  }
}

/** Reserve a side's SPACER — the outer→content inset on that side — as `≥ k` [strong]. Handles both a
 *  scalar node (extent outer/content, a 2-term inset) and a template node (a 1-term inset cell). The `≥`
 *  TIGHTENS the side's strong margin default (arrange's propagation keeps the binding bound), so several
 *  reservations on one side compose as their MAX, never their sum: a parallel axis gutter and a
 *  perpendicular end-spacer coexist on the same side with no double-counting. */
function reserveSpacer(node: Node, side: Side, k: number, label: string): void {
  if (node.insets) {
    node.constraints.push({ terms: [{ coef: 1, edge: node.insets[side] }], op: ">=", constant: k, strength: "strong", label });
  } else {
    const o = node.extent.outer, c = node.extent.content;
    const [hi, lo]: [CellRef, CellRef] = side === "left" ? [c.left, o.left] : side === "right" ? [o.right, c.right] : side === "top" ? [c.top, o.top] : [o.bottom, c.bottom];
    node.constraints.push({ terms: [{ coef: 1, edge: hi }, { coef: -1, edge: lo }], op: ">=", constant: k, strength: "strong", label });
  }
}

/** Register a stacked band on a SCALAR node's side (Steps 1/2): axes join a per-node side-stack so
 *  co-located adornments SUM (not MAX). Template nodes have no scalar extent — they keep the inset
 *  `dock`/`reserveSpacer` path (unchanged). */
function pushBand(node: Node, band: NodeBand): void {
  (node.sideBands ??= []).push(band);
}

/** Build ONE axis as pure IR (WUAXIS §2): the V producer + the apply-only wrapper + rule/tick/text
 *  plots appended to `node.plots`. The compiler places them like any plot (apply → affine). */
function createAxis(spec: Spec, registries: Registries, node: Node, scale: Scale, opts: LowerOpts, template = false): void {
  const axis = scale.dim!;
  const cross = axis === "x" ? "y" : "x";
  const side = scale.side as Side;
  const orient = axis === "x" ? "vertical" : "horizontal";
  const lenSign = side === "top" || side === "right" ? -1 : 1; // ticks extend INTO the margin
  // axis constants are OPTIONS (author-overridable per axis); the constants above are the defaults.
  const cfg = scale.axis === false ? undefined : scale.axis;
  const tickLen = pxNum(cfg?.tickLength, "axis tickLength") ?? TICK_LEN;
  const fontSize = pxNum(cfg?.fontSize, "axis fontSize") ?? FONT_SIZE;
  const label = labelFor(side, tickLen, fontSize);
  const stroke = "#888888";
  const key = scale.id.split("/").pop()!; // "x" | "y" | "x2" … — the axis's plot-id segment

  const relCoord = (a: "x" | "y"): Space => relativeSpace(coord(a));
  const edge = (a: "x" | "y"): Expr => literal(EDGE_T[side], relCoord(a));

  // ticks + labels need a tick algo (the scale's, or the axis config's override).
  const ticks = resolveTicks(scale, registries, opts);

  // A TICKED axis gets a PRESENCE cell (§C6 axis-merge): seeded 1 (drawn); the merge decision op
  // recomputes it from solved sibling alignment. Its V/unit producers READ it — 0 ⇒ empty relations
  // ⇒ no marks AND (via measure over empty V) zero demand: the whole axis vanishes through ordinary
  // dataflow. A rule-only axis has no labels to merge; it keeps the node's shared ungated unit.
  let unitId: string;
  if (ticks === undefined) {
    unitId = ensureUnit(spec, node.id);
  } else {
    const indicator = spec.cells.alloc("indicator", 1, "scalar", dataSpace);
    scale.indicator = indicator;
    unitId = `${scale.id}/unit`;
    spec.layouts.set(unitId, { id: unitId, descriptor: "unit", inputs: {}, params: {}, options: { indicator } });
  }

  // the baseline rule: a 1-row `unit` base, all-literal relative coords on the SOLVED side's edge.
  const ruleChannels: Record<string, Expr> =
    axis === "x"
      ? { x: literal(0, relCoord("x")), x2: literal(1, relCoord("x")), y: edge("y"), y2: edge("y"), stroke: literal(stroke) }
      : { x: edge("x"), x2: edge("x"), y: literal(1, relCoord("y")), y2: literal(0, relCoord("y")), stroke: literal(stroke) };
  // ponytail: rule uses ungated unit — it's a spatial boundary, not a scale readout
  addPlot(spec, node, `ax-${key}-rule`, "rule", { producer: ensureUnit(spec, node.id) }, ruleChannels);

  if (ticks === undefined) {
    // rule-only axis: constant footprint, no measurement. Template: keep the inset reserveSpacer.
    // Scalar: register a FIXED-thickness band so it SUMs with any co-located adornment (Step 2).
    if (node.insets) {
      reserveSpacer(node, side, tickLen, `gutter:${side}`);
    } else {
      const ruleRect: PlotRect = {
        id: `ax-${key}-rule`, plots: [],
        x: spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("x"))),
        y: spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("y"))),
        w: spec.cells.alloc("demand", tickLen, "scalar", pixelSpace(len("x"))),
        h: spec.cells.alloc("demand", tickLen, "scalar", pixelSpace(len("y"))),
      };
      pushBand(node, { id: `ax-${key}-rule`, side, role: "axis", rect: ruleRect, fixedThickness: tickLen, order: placeToOrder(cfg?.place), gap: cfg?.gap, pad: cfg?.pad });
    }
    return;
  }

  // §5: shared axis detection — determines whether plots/constraints go on parent or self.
  // Pixel-pinned hosts have no scale to share — per-panel only.
  const hostMode = hostBindingMode(spec, registries, node, axis);
  const hoistable = hostMode !== null && hostMode !== "pixel";
  const hoisted = template && scale.shared !== false && hoistable;

  // the V producer: domain → V(idx, value, label); options ride binding.options into the vtable op.
  // An UNPINNED count is derived from the axis LENGTH at execution — the op reads the content-edge
  // cells, closing the §C6 cycle (content → count → V → demand → margin → content).
  const cc = node.extent.content;
  const extentPair: readonly [CellRef, CellRef] = axis === "x" ? [cc.left, cc.right] : [cc.bottom, cc.top];
  // TEMPLATE counts (§C8 7b): ALL template axes are per-cell (rendering always on child).
  // Per-panel tick count derived from each panel's box (inset on hoisted side = 0 → full panel width).
  const count = template ? (ticks.count ?? opts.tickCount) : ticks.count;
  const perCell = template && scale.shared === false;
  const ins = node.insets;
  const tmplOpts = (template && ins !== undefined)
    ? { by: "dvl_cell", countFrom: axis, insetLo: axis === "x" ? ins.left : ins.top, insetHi: axis === "x" ? ins.right : ins.bottom }
    : {};
  const vId = `${scale.id}/V`;
  spec.layouts.set(vId, { id: vId, descriptor: "vtable", inputs: {}, params: {}, domain: scale.domain, options: { tickAlgo: ticks.algo, count, indicator: scale.indicator, ...tmplOpts, ...(!template && count === undefined ? { extent: extentPair } : {}) } });

  // ── the axis TITLE config resolves FIRST: its extent joins the demand seeds, its plot id joins the
  // measured PlotRect (the plot-measure op then reserves for tick + label + title together).
  const title = resolveTitle(spec, scale, cfg);
  const titleExtra = title !== undefined ? title.fontSize + TITLE_GAP : 0;

  // §5 + the demand loop: the axis is a PlotRect whose w/h are filled by the plot-measure op.
  const estPad = tickLen + Math.abs(axis === "x" ? label.dy : label.dx);
  const axisW = spec.cells.alloc("demand", estPad + EST_LABEL_W + (axis === "y" ? titleExtra : 0), "scalar", pixelSpace(len("x")));
  const axisH = spec.cells.alloc("demand", estPad + fontSize + (axis === "x" ? titleExtra : 0), "scalar", pixelSpace(len("y")));
  const axisX = spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("x")));
  const axisY = spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("y")));
  const tickPlotId = spec.ids.plot(node.id, `ax-${key}-tick`);
  const textPlotId = spec.ids.plot(node.id, `ax-${key}-text`);
  const axisPlotIds = title !== undefined ? [tickPlotId, textPlotId, spec.ids.plot(node.id, `ax-${key}-title`)] : [tickPlotId, textPlotId];
  if (hoisted) {
    // Shared axis: plots stay on CHILD (keyed-affine → C4 satisfied).
    // Dock on PARENT with seeded demand (no PlotRect — avoids cross-node measure cycle).
    // The demand cells keep their seeded estimates; no dynamic measurement for hoisted axes
    // (the child→parent→child cycle would prevent convergence).
    const parentNode = spec.nodes.get(node.parent!)!;
    const axisRect: PlotRect = { id: `ax-${key}`, plots: axisPlotIds, x: axisX, y: axisY, w: axisW, h: axisH };
    parentNode.constraints.push(...dock(axisRect, { extent: parentNode.extent }, side));
    // Child inset on the shared side = 0 (parent's dock handles space).
    if (node.insets) {
      node.constraints.push({ terms: [{ coef: 1, edge: node.insets[side] }], op: "=", constant: 0, strength: "strong", label: `shared-zero:${side}` });
    }
  } else {
    // Per-panel axis: PlotRect on self (measured). Template (insets): dock on self, unchanged.
    // Scalar: register as a side-stack band so co-located adornments SUM (Step 2). Both reduce to
    // exactly today's single reservation when the axis is alone on its side.
    const axisRect: PlotRect = { id: `ax-${key}`, plots: axisPlotIds, x: axisX, y: axisY, w: axisW, h: axisH };
    node.plotRects ??= [];
    node.plotRects.push(axisRect);
    if (node.insets) {
      const target: DockTarget = { insets: node.insets };
      node.constraints.push(...dock(axisRect, target, side));
    } else {
      // Sheddable (Step 5): under space pressure the tick+label band drops (indicator → 0 hides its
      // V → empty marks + zero measured thickness), leaving the ungated rule. priority 2 (a future
      // finer split would shed labels p1 before ticks p2; this band bundles both).
      pushBand(node, { id: `ax-${key}`, side, role: "axis", rect: axisRect, order: placeToOrder(cfg?.place), gap: cfg?.gap, pad: cfg?.pad, shed: { priority: 2, indicator: scale.indicator } });
    }
  }

  // END-SPACERS (the perpendicular gutter). A tick label is CENTERED on its tick (labelFor: a left axis
  // sets dy≈0.3·fontSize with anchor "end"; an x axis anchors "middle"). The axis's EXTREME ticks land
  // exactly on the content edges (domain max → content.top/right, min → content.bottom/left), so ~half a
  // label overhangs PERPENDICULAR to the axis's own gutter — above content.top for a y axis, right of
  // content.right for an x axis. `dock()` reserves only the PARALLEL side (rect.w for left/right, rect.h
  // for top/bottom); the perpendicular overhang was unreserved, which let the top y-label clip the canvas
  // (design/2026-07-16-yaxis-label-clip.html §9). Reserve it on both perpendicular sides — WORST CASE:
  // half the label BOX in that dimension (a y axis overhangs by half its uniform HEIGHT = fontSize/2,
  // EXACT; an x axis by half its label WIDTH, estimated as EST_LABEL_W/2 since exact width needs the
  // extreme label measured). The MAX-tightening in reserveSpacer means a side already covered by a real
  // axis gutter (e.g. bottom, under the x-axis) ignores the smaller end-spacer — no double-counting.
  const [perpLo, perpHi]: [Side, Side] = axis === "y" ? ["top", "bottom"] : ["left", "right"];
  const perpHalf = axis === "y" ? Math.ceil(fontSize / 2) : Math.ceil(EST_LABEL_W / 2);
  const perpNode = hoisted ? spec.nodes.get(node.parent!)! : node;
  reserveSpacer(perpNode, perpLo, perpHalf, `endspacer:${key}:${perpLo}`);
  reserveSpacer(perpNode, perpHi, perpHalf, `endspacer:${key}:${perpHi}`);

  // the apply-only wrapper: place V.value by the frame scale WITHOUT training it (WUAXIS §apply-only).
  // A multi-output wrapped scale (col: y,h) destructures b.outputs, so the wrapper carries the wrapped
  // ARITY — the tick binds outputs[0] (the coord); the extra columns are carried, unused.
  const wrappedDesc = registries.operators.get(scale.descriptor);
  const wrappedOutputs = wrappedDesc.outSpaces !== undefined ? Object.keys(wrappedDesc.outSpaces) : "add" in wrappedDesc.output ? wrappedDesc.output.add.map((a) => a.name) : ["value"];
  const aoId = `${scale.id}/apply-only`;
  spec.layouts.set(aoId, {
    id: aoId,
    descriptor: "apply-only",
    inputs: { marks: { relation: { producer: vId }, project: { value: "value" } } },
    params: {},
    ...(perCell ? { shared: false } : {}), // §C8: a per-cell scale's wrapper applies against the KEYED fit (join on the key)
    domain: scale.domain, // SHARE the scale's domain — read as the fit, never re-trained
    // anchor: an axis places a tick at the CENTER of its value's extent — a width-producing scale
    // (band) emits (idx+0.5)/n under this option; zero-extent (point) scales ignore it. The wrapped
    // scale's OWN options (band padding/align) ride along so ticks land at the SAME centers as bars.
    // `wrapped` is the REGISTRY name (apply-only's plan resolves algoName against it); `wrappedId`
    // is the base INSTANCE — geometry passes (scale expansion) unwrap through it so a tick at value
    // V and a mark at value V place through the SAME map (the false-axis bug, scale-expansion §8).
    options: { ...scale.options, wrapped: scale.descriptor, wrappedId: scale.id, wrappedOutputs, anchor: "center" },
  });
  const posCh = (): Expr => layoutOutput(aoId, "value", { space: relCoord(axis), arity: "per-row" });

  // Plots always on CHILD — keyed-affine ensures per-panel frame (C4).
  addPlot(spec, node, `ax-${key}-tick`, "tick", { producer: vId }, {
    [axis]: posCh(), [cross]: edge(cross), len: literal(tickLen * lenSign), orient: literal(orient), stroke: literal(stroke),
  });
  addPlot(spec, node, `ax-${key}-text`, "text", { producer: vId }, {
    [axis]: posCh(), [cross]: edge(cross), text: col("label"), anchor: literal(label.anchor),
    dx: literal(label.dx), dy: literal(label.dy), fill: literal("#333333"), fontSize: literal(fontSize),
  });

  // ── the axis TITLE (WUAXIS §title): one more ordinary text plot over the axis's GATED unit (it
  // vanishes with the axis under axis-merge). Placed like a farther-out tick label: midpoint of the
  // axis in relative space + a pixel dx/dy that CLEARS the tick labels (screen coords, y DOWN):
  //   bottom — labels' baseline sits (tickLen + fontSize + 1) BELOW the content edge; the title's
  //            baseline drops one more title-line + gap below that;
  //   top    — labels' baseline sits (tickLen + 3) ABOVE the edge, glyphs ascend ≈ fontSize higher;
  //            the title's baseline clears both (its own ascent extends further up);
  //   left   — labels extend ≈ EST_LABEL_W left of their (tickLen + 3) anchor; the title anchors
  //            beyond that, ROTATED -90 (baseline vertical, ascent extending LEFT — reads upward);
  //   right  — mirror of left, rotated +90.
  // The title plot rides the axis's measured PlotRect, so the gutter reserves for it automatically.
  if (title !== undefined) {
    const near = tickLen + 3;
    const off =
      side === "bottom" ? { dx: 0, dy: tickLen + fontSize + 1 + TITLE_GAP + title.fontSize }
      : side === "top" ? { dx: 0, dy: -(near + fontSize + TITLE_GAP) }
      : side === "left" ? { dx: -(near + EST_LABEL_W + TITLE_GAP), dy: 0 }
      : { dx: near + EST_LABEL_W + TITLE_GAP, dy: 0 };
    const rotate = title.rotate ?? (axis === "y" ? (side === "left" ? -90 : 90) : 0);
    addPlot(spec, node, `ax-${key}-title`, "text", { producer: unitId }, {
      [axis]: literal(0.5, relCoord(axis)), [cross]: edge(cross),
      text: literal(title.text), anchor: literal(title.anchor),
      dx: literal(off.dx + title.dx), dy: literal(off.dy + title.dy),
      fill: literal(title.fill), fontSize: literal(title.fontSize),
      ...(rotate !== 0 ? { rotate: literal(rotate) } : {}),
      ...(title.opacity !== undefined ? { opacity: literal(title.opacity) } : {}),
      ...(title.baseline !== undefined ? { baseline: literal(title.baseline) } : {}),
    });
  }
}

// ── the axis title: config → resolved text + styling ────────────────────────
const TITLE_FONT = 11; // default title font size (1pt over tick labels)
const TITLE_GAP = 4; // px between the tick labels' extent and the title

/** LOUD numeric guard (the legend-placement rule: silent typos cost a debugging session). The title
 *  offsets and demand seeds are ARITHMETIC over these values — a CSS-style string ("20pt") would
 *  string-concatenate into garbage geometry, so any non-number throws, naming the fix. */
function pxNum(v: unknown, what: string): number | undefined {
  if (v === undefined) return undefined;
  if (typeof v === "number" && Number.isFinite(v)) return v;
  throw new Error(`dvl: ${what} must be a number in px, got ${JSON.stringify(v)} — write fontSize: 20, not "20pt"`);
}

interface ResolvedTitle { text: string; fontSize: number; fill: string; opacity?: number; dx: number; dy: number; rotate?: number; anchor: string; baseline?: string }

/** Resolve the axis's `title` config: `true` derives the text, a string IS the text, the object
 *  form adds the text mark's normal styling options. No config (or no derivable text) → no title. */
function resolveTitle(spec: Spec, scale: Scale, cfg: AxisOptions | undefined): ResolvedTitle | undefined {
  const t = cfg?.title;
  if (t === undefined || t === false) return undefined;
  const o: AxisTitleOptions = t === true ? {} : typeof t === "string" ? { text: t } : t;
  const text = o.text ?? deriveTitle(spec, scale);
  if (text === undefined || text.length === 0) return undefined;
  return {
    text,
    fontSize: pxNum(o.fontSize, "axis title fontSize") ?? TITLE_FONT,
    fill: o.fill ?? o.color ?? "#333333",
    opacity: pxNum(o.opacity, "axis title opacity"),
    dx: pxNum(o.dx, "axis title dx") ?? 0,
    dy: pxNum(o.dy, "axis title dy") ?? 0,
    rotate: pxNum(o.rotate, "axis title rotate"),
    anchor: o.anchor ?? "middle",
    baseline: o.baseline,
  };
}

/** Default title text: the scale's FIRST member's column; an expr-bound member (minted `dvl_se_*`)
 *  prints the AUTHORED expression from the plot's base projections (x(a+b) titles as "a + b"). */
function deriveTitle(spec: Spec, scale: Scale): string | undefined {
  const m = scale.members?.[0];
  if (m === undefined) return undefined;
  if (m.column.startsWith("dvl_se_")) {
    const e = spec.plots.get(m.plot)?.baseProjections?.[m.column];
    if (e !== undefined) return exprLabel(e);
  }
  return m.column;
}

/** Tiny Expr pretty-printer for derived titles: column names, literals, infix binaries. */
function exprLabel(e: Expr): string {
  switch (e.kind) {
    case "local-column": return e.columnName;
    case "literal": return String(e.value);
    case "binary": return `${exprLabel(e.left)} ${e.op} ${exprLabel(e.right)}`;
    case "call": return `${e.fn}(${e.args.map(exprLabel).join(", ")})`;
    case "agg": return e.op;
    default: return "expr";
  }
}

/** The axis's tick algo + count: the axis config overrides the scale's declared algo; no algo ⇒ no
 *  ticks. Count `undefined` = UNPINNED — derived from the axis length at execution (the §C6 cycle). */
function resolveTicks(scale: Scale, registries: Registries, opts: LowerOpts): { algo: string; count?: number } | undefined {
  const cfg: AxisOptions["ticks"] = scale.axis === false ? undefined : scale.axis?.ticks;
  // Operator-level `ticks` ONLY (no domain.ticks fallback here): an operator that declares no
  // ticks (eqx) keeps its RULE-ONLY axis — the domain-level ticks default serves legends
  // (lower-legends resolveTickAlgo), where every scale must produce swatch labels.
  const declared = registries.operators.has(scale.descriptor) ? registries.operators.get(scale.descriptor).ticks : undefined;
  const algo = (typeof cfg === "object" ? cfg.algorithm : undefined) ?? declared;
  if (algo === undefined) return undefined; // a scale with no tick algo (or none registered) → rule-only axis
  const count = (typeof cfg === "number" ? cfg : cfg?.count) ?? opts.tickCount; // undefined = extent-driven
  return { algo, count };
}

/** The node's shared 1-row `unit` producer instance (lazy — one per node). */
function ensureUnit(spec: Spec, nodeId: NodeId): string {
  const id = `${nodeId}/unit`;
  if (!spec.layouts.has(id)) spec.layouts.set(id, { id, descriptor: "unit", inputs: {}, params: {} });
  return id;
}

/** Append an axis plot: ordinary IR — a Plot in spec.plots + node.plots (WUAXIS: an axis IS plots). */
function addPlot(spec: Spec, node: Node, key: string, markType: string, source: Plot["source"], channels: Record<string, Expr>): void {
  const id = spec.ids.plot(node.id, key);
  spec.plots.set(id, { id, node: node.id, source, markType, channels, params: {}, origin: "axis" });
  node.plots.push(id);
}

/** Emit the axis-merge DECISION op per shared group of SIBLING axes (WULAYOUT_IMPL §C6): a
 *  post-solve decision — it reads the siblings' SOLVED content edges; if they ALIGN on the shared
 *  dim, one axis speaks for all (the leftmost keeps a y axis, the bottom-most an x axis) and the
 *  interior indicators go to 0. Not aligned ⇒ all stay 1. The op recomputes each fixpoint sweep;
 *  indicators are SEEDED 1 (drawn), so the first sweep runs with every axis present. No hysteresis
 *  in the naive tier: alignment is tested on ABSOLUTE content cells, so row siblings can never
 *  x-align (their bands differ by construction) — the two dims' merges are geometrically exclusive.
 *  Damping becomes binding only when a solver can RE-ALIGN panels in response to a merge. */
export function emitAxisMerge(spec: Spec, domains: DomainGroups, specs: OpSpec[]): void {
  for (const g of domains.groups) {
    const insts = g.ids.map((id) => spec.layouts.get(id)!).filter((s) => s.indicator !== undefined && s.members !== undefined);
    // merging economizes a SHARED gutter, which only SAME-SIDE axes occupy — sides are EXPLICIT
    // (assigned/pinned at lowering, never assumed): subgroup by side; mixed sides never merge.
    const bySide = new Map<Side, Scale[]>();
    for (const s of insts as Scale[]) {
      if (s.side === undefined) continue;
      bySide.set(s.side, [...(bySide.get(s.side) ?? []), s]);
    }
    for (const [side, sided] of bySide) {
      if (sided.length < 2) continue;
      const dim = sided[0].dim as "x" | "y";
      // each axis's node via its first member plot; merge applies to SIBLINGS only (one shared parent)
      const nodes = sided.map((s) => spec.nodes.get(spec.plots.get(s.members![0].plot)!.node)!);
      const parents = nodes.map((n) => [...spec.nodes.values()].find((p) => p.children.some((c) => c.node === n.id))?.id);
      if (parents[0] === undefined || new Set(parents).size !== 1) continue; // root scales / non-siblings: no merge
      const ids = sided.map((s) => s.id);
      const reads = nodes.flatMap((n) => {
        const c = n.extent.content;
        // per sibling [alignLo, alignHi, pick]: align on the shared dim's content edges; the pick
        // edge is the SIDE's own edge — the survivor is the axis at the row/column's OUTER rim
        // (left side → leftmost, right → rightmost, bottom → bottom-most, top → topmost).
        const align = dim === "y" ? [c.top, c.bottom] : [c.left, c.right];
        const pick = side === "left" ? c.left : side === "right" ? c.right : side === "top" ? c.top : c.bottom;
        return [...align, pick];
      });
      specs.push({
        id: `${ids.join("+")}:axis-merge`,
        reads,
        writes: sided.map((s) => s.indicator!),
        payload: { kind: "axis-merge", key: `${ids.join("+")}:merge`, dim, side },
      });
    }
  }
}
