// The execution atoms + the RelOp lowering (algebra layer; ex dataflow/exec.ts part 1).
// An Impl is the atom of execution — a substrate-tagged function you can inspect
// (`impl.substrate`, `impl.keyed`). An Exec holds up to two impls (one per substrate). A RelOp
// is the AUTHORING description a component writes; buildTrainExec/buildApplyExec compile it into
// Execs via the shared lowering, so each operator describes its computation once, substrate-free.
// Also home to the impl INVOCATION CONTEXT (OpBinding — what every impl receives): the algebra
// defines what its atoms consume; the operator layer builds bindings, the executor dispatches.
import type { SqlFragment } from "../data/fragment.js";
import type { Scalar, SqlType } from "../data/schema.js";
import type { Agg, ApplyOp, FitMode, ScalarExpr, TrainOp } from "./relop.js";
import { lowerApplyJs, lowerApplySql, lowerTrainJs, lowerTrainSql } from "./lower.js";
import type { JsRel, RunFrag } from "./relation.js";
import type { Space } from "../types/attr.js";

/** Trained "fit" as scalars (a materialized 1-row fit) — what tick generators read. */
export type Params = Readonly<Record<string, Scalar | readonly Scalar[]>>;

/** A layout input bound to a role: a COLUMN of the marks (by name), or an aux RELATION
 *  (force's `edges`). The column case is the overload that makes "a column is a relation". */
export type RelInput = string | JsRel | { readonly frag: SqlFragment };

export interface OpBinding {
  readonly key: string; // unique id prefix for this op's fragments (e.g. "n0/p0:x")
  readonly inputs: Readonly<Record<string, RelInput>>; // role → marks column | aux relation
  readonly outputs: readonly string[]; // output column(s): scale→[ch]; band→[x,w]; force→[x,y]
  // An output's RANGE — pixels for positional outputs, a palette for color — is component
  // context, not op-algebra. It rides in `options.range`, interpreted by the component (see
  // components/scales/_shared `range`/`ordRange`). ponytail: still a literal here; C6 sources it
  // from the host node's extent-edge cells (instance `range: [CellRef,CellRef]`).
  readonly options?: Readonly<Record<string, unknown>>; // component context (range, tick count, …)
  /** Per aux role: the RESOLVED join pairs (aux column ⇢ marks column) — from the instance's
   *  `on` override, else the operator's declared `refs`. Impls read these instead of hardcoding
   *  column names (§8 Stage 1b — force's src/dst stops being a convention). */
  readonly refs?: Readonly<Record<string, ReadonlyArray<{ readonly from: string; readonly to: string }>>>;
  /** The stamped output SPACE of the primary output (`outputs[0]`) — how a binding-polymorphic
   *  apply knows which range to emit (AUTOLEGEND §6): a style⟨color⟩ output → a colour, else the
   *  positional/number value. Set by the compiler from the bound channel's expression. */
  readonly outSpace?: Space;
}

/** The marks column a role binds (scales bind columns; aux-relation inputs are read elsewhere). */
export function inputCol(b: OpBinding, role: string): string {
  const v = b.inputs[role];
  if (typeof v !== "string") throw new Error(`binding role "${role}" of "${b.key}" is an aux relation, not a column`);
  return v;
}


// ── ExecCtx: what the framework hands every impl beyond inputs + binding ─────
// (§11.2 F1 — the design doc's bare `(inputs, b)` signature is insufficient.)

export interface ExecCtx {
  /** Execute a SQL fragment — JS impls that read aux relations (force's `edges`) need it. */
  readonly run: RunFrag;
  /** §C8 partition column when this edge is keyed. A keyed impl consumes it (GROUP BY /
   *  per-group loop); a non-keyed impl never sees it — dispatch() iterates outside. */
  readonly key?: string;
  /** Per-EDGE keyedness, parallel to the call's inputs (§2.7: a partition key is a property of
   *  the data flowing through each edge, not of the invocation). Consulted only when dispatch
   *  iterates a non-keyed impl: flagged inputs are FILTERED to each group's key value (a per-cell
   *  fit); unflagged inputs pass WHOLE (a global aux relation). Comes from the plan
   *  (payload.keyedReads) — the compiler knows which reads are keyed because it emitted the keyed
   *  train that produced them. Absent: a single input defaults to [true] (the marks edge); a
   *  multi-input iterate REFUSES to guess and throws — a silent default would mis-broadcast a
   *  keyed fit (every group reading group 0's rows). */
  readonly keyedInputs?: readonly boolean[];
}

// ── Impl / Exec: the physical execution primitive ────────────────────────────

export type SqlImplFn = (inputs: readonly SqlFragment[], b: OpBinding, ctx: ExecCtx) => SqlFragment;
export type JsImplFn = (inputs: readonly JsRel[], b: OpBinding, ctx: ExecCtx) => JsRel | Promise<JsRel>;

/** A concrete substrate implementation — self-describing via properties: `substrate` says what
 *  inputs it expects and produces; `keyed` says it handles a partitioned edge internally. */
export type SqlImpl = SqlImplFn & { readonly substrate: "sql"; readonly keyed?: boolean };
export type JsImpl = JsImplFn & { readonly substrate: "js"; readonly keyed?: boolean };
export type Impl = SqlImpl | JsImpl;

/** The execution interface — one or both substrate implementations. The optimizer (Phase 4)
 *  picks one; until then chooseImpl() picks at run time from the data's substrate. */
export interface Exec {
  readonly sql?: SqlImpl;
  readonly js?: JsImpl;
}

export const sqlImpl = (fn: SqlImplFn, keyed = false): SqlImpl => Object.assign(fn, { substrate: "sql" as const, keyed });
export const jsImpl = (fn: JsImplFn, keyed = false): JsImpl => Object.assign(fn, { substrate: "js" as const, keyed });

// ── RelOp: the unified operation description (authoring input, §2.8) ─────────

export type RelOp =
  | { readonly kind: "reduce"; readonly aggs: Readonly<Record<string, Agg>> } // N→1 row (min/max/count/sum)
  | { readonly kind: "unique"; readonly col: string; readonly as: string; readonly indexed?: boolean } // N→M distinct rows
  // derive carries NO fit field (§11.2 F3): how a trained fit attaches to the marks
  // (broadcast vs keyed join) is the FRAMEWORK's decision — see fitMode().
  | { readonly kind: "derive"; readonly add: Readonly<Record<string, ScalarExpr>>; readonly outTypes?: Readonly<Record<string, SqlType>> }
  | { readonly kind: "opaque"; readonly exec: Exec }; // arbitrary (force, affine, …) — authored via op({ exec })

/** How a trained fit consumes: broadcast = 1-row fit CROSS JOINed to all marks;
 *  keyed = N-row fit JOINed on the value column. Lives on the OPERATOR (its domain's shape),
 *  never on the operation description. */
export type DomainShape = "broadcast" | "keyed";

/** The fit-attachment mode — derived from the operator's domain shape × the edge key, never
 *  authored on the op. Validated against every component (§11.2 F3): keyed domains all join
 *  [[bound value column, "value"]]; a §C8 key turns broadcast into a join on the key; a keyed
 *  domain × a cell key COMPOSES into the two-pair join [[key,key],[value,"value"]] — each
 *  partition's marks match their own cell's category rows (per-cell band/ordinal/point). */
export function fitMode(shape: DomainShape | undefined, b: OpBinding, key: string | undefined, haveFit: boolean): FitMode {
  if (!haveFit || shape === undefined) return "none";
  if (shape === "keyed") {
    return key !== undefined
      ? { keyed: [[key, key], [inputCol(b, "value"), "value"]] }
      : { keyed: [[inputCol(b, "value"), "value"]] };
  }
  return key !== undefined ? { keyed: [[key, key]] } : "broadcast";
}

// ── One lowering per substrate (§2.9): RelOp → SqlFragment | JsRel ───────────
// The old-algebra ops (TrainOp/ApplyOp) are the INTERNAL carrier only (dataflow/op.ts) — the
// authoring surface is RelOp; the old train/apply description path is gone (Phase 5).

const toTrainOp = (r: RelOp): TrainOp => {
  if (r.kind === "reduce") return { kind: "aggregate", aggs: r.aggs };
  if (r.kind === "unique") return { kind: "distinct", col: r.col, as: r.as, indexed: r.indexed };
  throw new Error(`RelOp kind "${r.kind}" cannot lower as a train`);
};
const toApplyOp = (r: RelOp, fit: FitMode): ApplyOp => {
  if (r.kind !== "derive") throw new Error(`RelOp kind "${r.kind}" cannot lower as an apply`);
  return { kind: "augment", add: r.add, fit, outTypes: r.outTypes };
};

/** Lower any RelOp to SQL. inputs = [main, fit?]; `fit` (framework-derived, see fitMode) only
 *  applies to derive. Opaque delegates to the author's impl. */
export function lowerSql(op: RelOp, inputs: readonly SqlFragment[], b: OpBinding, ctx: ExecCtx, fit: FitMode = "none"): SqlFragment {
  switch (op.kind) {
    case "reduce":
    case "unique":
      return lowerTrainSql(toTrainOp(op), inputs[0], b, ctx.key);
    case "derive":
      return lowerApplySql(toApplyOp(op, fit), inputs[0], inputs[1] ?? null, b);
    case "opaque": {
      if (op.exec.sql === undefined) throw new Error(`${b.key}: opaque op has no SQL impl`);
      return op.exec.sql(inputs, b, ctx);
    }
  }
}

/** Lower any RelOp to JS. Same contract as lowerSql. */
export function lowerJs(op: RelOp, inputs: readonly JsRel[], b: OpBinding, ctx: ExecCtx, fit: FitMode = "none"): JsRel | Promise<JsRel> {
  switch (op.kind) {
    case "reduce":
    case "unique":
      return lowerTrainJs(toTrainOp(op), inputs[0], b, ctx.key);
    case "derive":
      return lowerApplyJs(toApplyOp(op, fit), inputs[0], inputs[1] ?? null, b);
    case "opaque": {
      if (op.exec.js === undefined) throw new Error(`${b.key}: opaque op has no JS impl`);
      return op.exec.js(inputs, b, ctx);
    }
  }
}

// ── buildExec: compile a declarative RelOp fn into a dual-substrate Exec ─────

/** TRAIN exec: dual impls, keyed natively — the shared lowering vectorizes (GROUP BY / partition). */
export function buildTrainExec(descFn: (b: OpBinding) => RelOp): Exec {
  return {
    sql: sqlImpl((inputs, b, ctx) => lowerSql(descFn(b), inputs, b, ctx), true),
    js: jsImpl((inputs, b, ctx) => lowerJs(descFn(b), inputs, b, ctx), true),
  };
}

/** APPLY exec: inputs = [marks, fit?]; the join mode comes from the operator's domain shape ×
 *  the edge key — never from the op description. */
export function buildApplyExec(descFn: (b: OpBinding) => RelOp, shape: DomainShape | undefined): Exec {
  return {
    sql: sqlImpl((inputs, b, ctx) => lowerSql(descFn(b), inputs, b, ctx, fitMode(shape, b, ctx.key, inputs.length > 1)), true),
    js: jsImpl((inputs, b, ctx) => lowerJs(descFn(b), inputs, b, ctx, fitMode(shape, b, ctx.key, inputs.length > 1)), true),
  };
}

