// The optimizer driver: run rule phases over the dataflow graph.
import type { CellStore } from "../ir/cell.js";
import type { OpCapability, OpsRegistry } from "../operator/registry.js";
import type { AnyOperatorPayload, RelopPayload } from "../plan/payloads.js";
import type { OpSpec } from "../plan/opspec.js";
import { DataflowGraph } from "./dataflow-graph.js";
import { FormatMap } from "./cell-format.js";
import { substrateChooser } from "./rules/substrate-chooser.js";
import { insertCrossings } from "./rules/insert-crossings.js";
import { fuseLiterals } from "./rules/fuse-literals.js";
import { deadCodeElim } from "./rules/dead-code-elim.js";
import type { OptPhase, RuleCtx } from "./rule.js";

// One rule APPLICATION consumes one iteration (the driver restarts the pass after a fire), so a
// phase's budget must cover ~one application per op — with maxIters 1 the substrate/crossing
// phases were inert no-ops (§12 Phase 4 P1), and arming them with structural capability under a
// starved budget produced HALF-PLANNED graphs that mis-executed. Budgets scale with plan size;
// stampDecisions' invariant (P2) backstops exhaustion by failing loudly.
const MAX_TOTAL_ITERS = 50_000;
const PHASE_ITERS = 10_000;

const phases: OptPhase[] = [
  { name: "substrate-chooser", rules: [substrateChooser], maxIters: PHASE_ITERS },
  { name: "insert-crossings", rules: [insertCrossings], maxIters: PHASE_ITERS },
  { name: "fusion-dce", rules: [fuseLiterals, deadCodeElim], maxIters: PHASE_ITERS },
];

/** Structural capability (§12 Phase 4b): impl presence = capability. Iteration is
 *  substrate-preserving (dispatch runs a non-keyed impl's correlated definition in the impl's
 *  OWN substrate), so keyed edges need no special case. TYPED payload reads (§12 5a, S3):
 *  a payload field rename here is a compile error, not a silent optimizer degrade. */
function structuralCapability(op: OpSpec): OpCapability | undefined {
  const pl = op.payload as unknown as AnyOperatorPayload;
  // a JOIN-DERIVE relop (via/cell-key: a second keyed input) is a relational join — SQL only.
  // The plain augment relop stays TRANSPARENT (the registry entry, dual-substrate — a registry
  // `call` lowers on either side like any built-in); the capability narrows structurally from the
  // payload, not via a new registered kind.
  if (pl.kind === "relop" && (op.payload as unknown as RelopPayload).join !== undefined) {
    return { canConsume: ["sql"], canProduce: ["sql"], fixedOutput: "sql" };
  }
  // the operator IS the apply exec (sql/js spread on); the train exec is algo.train (§12 5c)
  const exec = pl.kind === "apply" ? pl.algo : pl.kind === "domain" ? pl.algo?.train : undefined;
  if (exec === undefined) return undefined;
  const subs: ("sql" | "js")[] = [...(exec.sql !== undefined ? ["sql" as const] : []), ...(exec.js !== undefined ? ["js" as const] : [])];
  if (subs.length === 0) return undefined;
  return { canConsume: subs, canProduce: subs, fixedOutput: subs.length === 1 ? subs[0] : undefined };
}

export function optimize(plan: OpSpec[], cells: CellStore, ops: OpsRegistry): OpSpec[] {
  const graph = new DataflowGraph(plan);
  const formats = new FormatMap();

  const ctx: RuleCtx = {
    graph,
    cellFormat: (ref) => formats.get(ref),
    setCellFormat: (ref, fmt) => formats.set(ref, fmt),
    allocCell: (role, kind) => cells.alloc(role, undefined, kind),
    cellRole: (ref) => cells.get(ref).role,
    capability: (kind) => ops.capability(kind),
    opCapability: (op) => structuralCapability(op) ?? ops.capability(op.payload.kind),
  };

  // §12 Phase 4c: after chooser + crossings every apply/domain edge is consumable — stamp the
  // DECISION (payload.substrate) so the executor OBEYS instead of re-deciding. Iteration is
  // substrate-preserving, so the stamp covers iterating ops too (it says which substrate the
  // iteration runs in). P2 invariant: a planned input format without a matching impl means
  // insert-crossings is incomplete — a half-planned graph mis-executes silently; fail loudly.
  const stampDecisions = (): void => {
    for (const op of graph.ops) {
      const pl = op.payload as unknown as AnyOperatorPayload;
      const exec = pl.kind === "apply" ? pl.algo : pl.kind === "domain" ? pl.algo?.train : undefined;
      if (exec === undefined) continue;
      const fmt = formats.get(op.reads[0])?.substrate;
      if (fmt === undefined) continue; // un-formatted input (unplanned edge) — leave adaptive
      if ((fmt === "sql" ? exec.sql : exec.js) === undefined) throw new Error(`optimize: "${op.id}" input planned as ${fmt} but the exec has no ${fmt} impl — insert-crossings incomplete`);
      (op as { payload: unknown }).payload = { ...op.payload, substrate: fmt };
    }
  };

  let totalIters = 0;
  for (const phase of phases) {
    const cap = phase.maxIters ?? 10;
    let changed = true;
    let iters = 0;
    while (changed && iters < cap && totalIters < MAX_TOTAL_ITERS) {
      changed = false;
      iters++;
      totalIters++;
      // Snapshot per pass; break on first mutation to restart with fresh state
      const snapshot = [...graph.ops];
      for (const op of snapshot) {
        if (!graph.ops.includes(op)) continue; // stale after a prior rule fired this pass
        let fired = false;
        for (const rule of phase.rules) {
          const m = rule.match(op, ctx);
          if (m !== null) {
            rule.apply(m, ctx);
            changed = true;
            fired = true;
            break; // restart rule scan for this op (it may have been replaced)
          }
        }
        if (fired) break; // restart the pass with a fresh snapshot
      }
    }
  }
  stampDecisions();
  return [...graph.ops];
}
