// The scalar FUNCTION REGISTRY (cexpr §functions): named unary/binary functions the channel and
// ScalarExpr templates parse into a `call` node. Each entry is DUAL-SUBSTRATE by construction —
// `sql` and `js` are both expression-TEXT templates over the already-lowered argument texts,
// exactly like the built-in `unary` codegen (which inlines `sqrt(x)` / `Math.sqrt(x)`). So a
// `call` lowers transparently on either substrate with NO optimizer special-casing: it is just
// another member of the ScalarExpr union, like `sqrt`. Results are DATA space.
//
// To add a function: give it a DuckDB SQL form and a JS expression form. A function with no clean
// dual form (e.g. erf — no DuckDB scalar) does not belong here; keep the registry honest.
import type { SqlType } from "../data/schema.js";

export interface FnDef {
  readonly arity: 1 | 2;
  readonly type: SqlType; // result carrier (double for math, varchar/int for string)
  /** SQL text from the lowered argument texts (DuckDB scalar). */
  readonly sql: (a: readonly string[]) => string;
  /** JS expression text from the lowered argument texts — the arg refs are null-guarded upstream. */
  readonly js: (a: readonly string[]) => string;
}

// a DuckDB scalar called by name: `name(a0, a1, …)`
const sqlFn = (name: string) => (a: readonly string[]): string => `${name}(${a.join(", ")})`;
// a Math unary: `Math.fn(Number(x))`
const m1 = (name: string) => (a: readonly string[]): string => `Math.${name}(Number(${a[0]}))`;
// a Math binary: `Math.fn(Number(x), Number(y))`
const m2 = (name: string) => (a: readonly string[]): string => `Math.${name}(Number(${a[0]}), Number(${a[1]}))`;

export const FUNCTIONS: Record<string, FnDef> = {
  // ── unary math (DuckDB scalar name = the SQL form; Math.* = the JS form) ──
  sqrt: { arity: 1, type: "double", sql: sqlFn("sqrt"), js: m1("sqrt") },
  cbrt: { arity: 1, type: "double", sql: sqlFn("cbrt"), js: m1("cbrt") },
  exp: { arity: 1, type: "double", sql: sqlFn("exp"), js: m1("exp") },
  ln: { arity: 1, type: "double", sql: sqlFn("ln"), js: m1("log") },
  log10: { arity: 1, type: "double", sql: sqlFn("log10"), js: m1("log10") },
  log2: { arity: 1, type: "double", sql: sqlFn("log2"), js: m1("log2") },
  abs: { arity: 1, type: "double", sql: sqlFn("abs"), js: m1("abs") },
  floor: { arity: 1, type: "double", sql: sqlFn("floor"), js: m1("floor") },
  ceil: { arity: 1, type: "double", sql: sqlFn("ceil"), js: m1("ceil") },
  round: { arity: 1, type: "double", sql: (a) => `round(${a[0]})`, js: m1("round") },
  trunc: { arity: 1, type: "double", sql: sqlFn("trunc"), js: m1("trunc") },
  sign: { arity: 1, type: "double", sql: sqlFn("sign"), js: m1("sign") },
  sin: { arity: 1, type: "double", sql: sqlFn("sin"), js: m1("sin") },
  cos: { arity: 1, type: "double", sql: sqlFn("cos"), js: m1("cos") },
  tan: { arity: 1, type: "double", sql: sqlFn("tan"), js: m1("tan") },
  asin: { arity: 1, type: "double", sql: sqlFn("asin"), js: m1("asin") },
  acos: { arity: 1, type: "double", sql: sqlFn("acos"), js: m1("acos") },
  atan: { arity: 1, type: "double", sql: sqlFn("atan"), js: m1("atan") },
  degrees: { arity: 1, type: "double", sql: sqlFn("degrees"), js: (a) => `(Number(${a[0]}) * 180 / Math.PI)` },
  radians: { arity: 1, type: "double", sql: sqlFn("radians"), js: (a) => `(Number(${a[0]}) * Math.PI / 180)` },

  // ── binary math ──
  pow: { arity: 2, type: "double", sql: sqlFn("pow"), js: m2("pow") },
  atan2: { arity: 2, type: "double", sql: sqlFn("atan2"), js: m2("atan2") },
  log: { arity: 2, type: "double", sql: (a) => `log(${a[0]}, ${a[1]})`, js: (a) => `(Math.log(Number(${a[1]})) / Math.log(Number(${a[0]})))` }, // log base a0 of a1
  mod: { arity: 2, type: "double", sql: (a) => `(${a[0]} % ${a[1]})`, js: (a) => `(Number(${a[1]}) === 0 ? null : Number(${a[0]}) % Number(${a[1]}))` },
  min: { arity: 2, type: "double", sql: (a) => `least(${a[0]}, ${a[1]})`, js: m2("min") },
  max: { arity: 2, type: "double", sql: (a) => `greatest(${a[0]}, ${a[1]})`, js: m2("max") },
  hypot: { arity: 2, type: "double", sql: (a) => `sqrt(${a[0]} * ${a[0]} + ${a[1]} * ${a[1]})`, js: m2("hypot") },

  // ── unary string ──
  upper: { arity: 1, type: "varchar", sql: sqlFn("upper"), js: (a) => `String(${a[0]}).toUpperCase()` },
  lower: { arity: 1, type: "varchar", sql: sqlFn("lower"), js: (a) => `String(${a[0]}).toLowerCase()` },
  trim: { arity: 1, type: "varchar", sql: sqlFn("trim"), js: (a) => `String(${a[0]}).trim()` },
  ltrim: { arity: 1, type: "varchar", sql: sqlFn("ltrim"), js: (a) => `String(${a[0]}).replace(/^\\s+/, "")` },
  rtrim: { arity: 1, type: "varchar", sql: sqlFn("rtrim"), js: (a) => `String(${a[0]}).replace(/\\s+$/, "")` },
  length: { arity: 1, type: "int", sql: sqlFn("length"), js: (a) => `String(${a[0]}).length` },
  reverse: { arity: 1, type: "varchar", sql: sqlFn("reverse"), js: (a) => `[...String(${a[0]})].reverse().join("")` },

  // ── binary string ──
  repeat: { arity: 2, type: "varchar", sql: sqlFn("repeat"), js: (a) => `String(${a[0]}).repeat(Math.max(0, Math.trunc(Number(${a[1]}))))` },
  concat2: { arity: 2, type: "varchar", sql: (a) => `(${a[0]} || ${a[1]})`, js: (a) => `(String(${a[0]}) + String(${a[1]}))` },
};
