// sidestack — the side-stack arranger (design doc §7): the registration vocabulary (roles, ranks,
// orders, bands) and THE aligned-band geometry, emitted as solver-agnostic Intent[] (intents.ts owns
// the lowerings; the solver choice picks the reserve encoding).
//
// One source of truth: `arrangeIntents(store, extent, margin, bands)` builds a node's whole box
// model — per side ONE `reserve` intent (margin floor + summed band demand + gaps) and per band the
// rigid `affine` chain/center — from its registered `NodeBand`s. The real path (arrange.arrangeNode)
// and the standalone `SideArranger` harness below both call it; there is no second copy of the
// chain/center/reserve shapes anywhere.
//
// The decoupling invariant (the whole point): a caller registers `{ side, role, rank?, order?,
// attach? }` and never references another item. Ordering lives in the shared SIDE_ORDER table and
// per-item overrides; geometry lives in one resolver. Registration order does not matter.

import { CellStore, type CellRef } from "../ir/cell.js";
import type { Constraint, ArrangeSolver } from "../ir/layout.js";
import type { Extent, PlotRect, Side } from "../ir/node.js";
import { propagation } from "./solvers/propagation.js";
import { lowerForPropagation, type Intent } from "./intents.js";

// ── public vocabulary ────────────────────────────────────────────────────────

export type Attach = "stack" | "flush";
export type Anchor = "start" | "middle" | "end";
/** INNER padding (§12.4) — space inside a band, between its edges and its drawn content. A number
 *  pads all four sides; the object form names ABSOLUTE sides (a top strip: `top` toward the canvas,
 *  `bottom` between the text and the plot). Orthogonal to `gap` (OUTER — between this band and its
 *  neighbour): the CSS margin/padding pair. */
export type BandPad = number | { top?: number; right?: number; bottom?: number; left?: number };
/** Author override. Maps onto a rank (and, for "innermost", a zero gap). `{ after: role }` is the
 *  rare relative-to-role escape hatch — resolved centrally by the arranger, never by a component. */
export type Order = "innermost" | "outer" | number | { after: string };

/** Shared ordering policy — like CSS z-index defaults. A component reads only SIDE_ORDER[itsRole];
 *  it never inspects another item. New adornment kinds add a row here + register a band. */
export const SIDE_ORDER: Record<string, number> = {
  axis: 10, // ticks + tick labels, hug the frame
  "axis-name": 20, // outside the ticks
  "strip-label": 20, // (top) above each panel
  subtitle: 28,
  title: 30, // outermost furniture on top
  caption: 30, // outermost on bottom
  legend: 40,
};
export const DEFAULT_RANK = 50;

export interface Margin {
  left: number;
  right: number;
  top: number;
  bottom: number;
}
export const ZERO_MARGIN: Margin = { left: 0, right: 0, top: 0, bottom: 0 };

const SIDES: readonly Side[] = ["left", "right", "top", "bottom"];
const cmp = (a: string, b: string): number => (a < b ? -1 : a > b ? 1 : 0);

// ── the band (a node's registered adornment) ─────────────────────────────────

/** A stacked band registered on a node (an axis gutter, a legend, a title, a strip): its side + role
 *  + ordering, plus the EXISTING PlotRect cells (w/h filled by the node's plot-measure op, x/y solved
 *  by arrange). `fixedThickness` pre-writes the reserved dimension for a band with NO measurement
 *  (a rule-only axis, a strip). */
export interface NodeBand {
  id: string;
  side: Side;
  role: string;
  rect: PlotRect;
  /** Explicit rank (smaller = nearer the plot). Default: SIDE_ORDER[role] ?? DEFAULT_RANK. */
  rank?: number;
  /** Author override; takes precedence over rank. */
  order?: Order;
  /** Gap before this band along the stack normal (px). Default 0. */
  gap?: number;
  /** "stack" (default) accumulates outward and reserves space; "flush" pins to the plot edge and
   *  reserves nothing (an overlay — grid lines, a rule that must sit ON the frame). */
  attach?: Attach;
  /** Cross-axis alignment along the side. Default "middle". */
  anchor?: Anchor;
  fixedThickness?: number;
  /** Inner padding (§12.4): inflates the reserved thickness by the normal components and insets the
   *  band's content from the cross-axis span ends. Default 0. */
  pad?: BandPad;
  /** Priority shedding (Step 5): a SHEDDABLE band drops (its sub-plots hidden via `indicator` → 0)
   *  under space pressure, lowest priority first. Absent ⇒ non-sheddable (e.g. an axis rule). */
  shed?: { priority: number; indicator?: CellRef };
}

/** Resolve a band's ORDER override into an effective rank/gap/after. `innermost` → rank −∞ + zero
 *  gap; `outer` → +∞; a number sets the rank directly; `{after: role}` is resolved centrally at
 *  chain time. */
export function resolveOrder(input: Pick<NodeBand, "role" | "rank" | "order" | "gap" | "attach">): { rankEff: number; gapEff: number; attachEff: Attach; after?: string } {
  const rankBase = input.rank ?? SIDE_ORDER[input.role] ?? DEFAULT_RANK;
  let rankEff = rankBase;
  let gapEff = input.gap ?? 0;
  let after: string | undefined;
  const o = input.order;
  if (o === "innermost") { rankEff = -Infinity; gapEff = 0; }
  else if (o === "outer") { rankEff = Infinity; }
  else if (typeof o === "number") { rankEff = o; }
  else if (o && typeof o === "object") { after = o.after; }
  return { rankEff, gapEff, attachEff: input.attach ?? "stack", after };
}

/** Map a builder `place` override (Step 4) onto the arranger's `Order`. `inside` hugs the plot
 *  (innermost), `outside` pushes to the outermost slot; unset defers to the role's SIDE_ORDER rank. */
export function placeToOrder(place?: "inside" | "outside"): Order | undefined {
  return place === "inside" ? "innermost" : place === "outside" ? "outer" : undefined;
}

// ── the geometry: a node's bands → solver-agnostic Intent[] ──────────────────

type ResolvedBand = NodeBand & ReturnType<typeof resolveOrder> & { padEff: SidePad };

/** A band's pad, resolved onto its side's axes: `inner`/`outer` along the reservation normal (inner =
 *  toward the plot), `crossLo`/`crossHi` along the side (lo = left for a horizontal side, top for a
 *  vertical one). */
interface SidePad { inner: number; outer: number; crossLo: number; crossHi: number }

function resolvePad(side: Side, pad: BandPad | undefined): SidePad {
  if (pad === undefined) return { inner: 0, outer: 0, crossLo: 0, crossHi: 0 };
  const p = typeof pad === "number" ? { top: pad, right: pad, bottom: pad, left: pad } : { top: pad.top ?? 0, right: pad.right ?? 0, bottom: pad.bottom ?? 0, left: pad.left ?? 0 };
  switch (side) {
    case "bottom": return { inner: p.top, outer: p.bottom, crossLo: p.left, crossHi: p.right };
    case "top": return { inner: p.bottom, outer: p.top, crossLo: p.left, crossHi: p.right };
    case "left": return { inner: p.right, outer: p.left, crossLo: p.top, crossHi: p.bottom };
    case "right": return { inner: p.left, outer: p.right, crossLo: p.top, crossHi: p.bottom };
  }
}

/** Which extent edges a side's reservation spans (hi − lo grows the gutter), matching dock()'s
 *  [hi, lo] orientation so the propagation demand-loop recognizes it. `edge` is the CONTENT edge
 *  bands chain from. */
function sideEdges(e: Extent, side: Side): { hi: CellRef; lo: CellRef; edge: CellRef } {
  switch (side) {
    case "left": return { hi: e.content.left, lo: e.outer.left, edge: e.content.left };
    case "right": return { hi: e.outer.right, lo: e.content.right, edge: e.content.right };
    case "top": return { hi: e.content.top, lo: e.outer.top, edge: e.content.top };
    case "bottom": return { hi: e.outer.bottom, lo: e.content.bottom, edge: e.content.bottom };
  }
}

/** The cells the solver must OWN for these bands (each band's x/y position). The content edges are
 *  owned by the arranging caller; the outer edges are sealed inputs (never owned). */
export function ownedCells(bands: readonly NodeBand[]): CellRef[] {
  return bands.flatMap((b) => [b.rect.x, b.rect.y]);
}

/** Build a node's whole side-stack as Intent[]. Per side: ONE `reserve` intent (floor = margin,
 *  demands = the stack's band thicknesses, gap = Σ gaps) — this single intent is BOTH the strong
 *  margin equality AND the summed `≥` reservation (co-located bands SUM; the node's separate
 *  end-spacer `≥` floors still MAX in via propagation's bound rule). Per band: `affine` intents
 *  chaining it outward from the content edge and centering it on the cross axis (rigid, required —
 *  solver-agnostic). `attach:'flush'` bands pin to the content edge and reserve nothing.
 *  `fixedThickness` bands get their reserved dimension pre-written now (a sealed input). */
export function arrangeIntents(store: CellStore, extent: Extent, margin: Margin, bands: readonly NodeBand[]): Intent[] {
  const out: Intent[] = [];
  const resolved: ResolvedBand[] = bands.map((b) => {
    if (b.fixedThickness !== undefined) {
      const isH = b.side === "left" || b.side === "right";
      store.write(isH ? b.rect.w : b.rect.h, b.fixedThickness, "assigned");
    }
    return { ...b, ...resolveOrder(b), padEff: resolvePad(b.side, b.pad) };
  });

  for (const side of SIDES) {
    const { hi, lo, edge } = sideEdges(extent, side);
    const isH = side === "left" || side === "right";
    const mine = resolved.filter((b) => b.side === side);

    // {after: role} → sit just outside the outermost band of that role.
    const rankOf = (it: ResolvedBand): number => {
      if (it.after === undefined) return it.rankEff;
      const anchor = Math.max(...mine.filter((x) => x.role === it.after && x.after === undefined).map((x) => x.rankEff), -Infinity);
      return anchor === -Infinity ? it.rankEff : anchor + 0.5;
    };
    const stack = mine.filter((b) => b.attachEff === "stack").sort((a, b) => rankOf(a) - rankOf(b) || cmp(a.role, b.role) || cmp(a.id, b.id));
    const flush = mine.filter((b) => b.attachEff === "flush");

    // (a) the reserve intent — margin floor + summed band demand. ALWAYS emitted (even an empty side
    //     gets its margin floor); the lowering drops the ≥ bound when there is nothing to reserve.
    //     A band's normal pad (§12.4) inflates the reservation: reserved = thickness + pad_in + pad_out.
    out.push({
      kind: "reserve",
      hi, lo,
      demands: stack.map((b) => (isH ? b.rect.w : b.rect.h)),
      gap: stack.reduce((s, b) => s + b.gapEff + b.padEff.inner + b.padEff.outer, 0),
      floor: margin[side],
      note: `reserve:${side}`,
    });

    // (b) chain + center as affine intents (rigid required equalities — solver-agnostic).
    let prev: ResolvedBand | undefined;
    for (const b of stack) {
      out.push(chainIntent(side, b, prev, edge));
      out.push(centerIntent(side, b, extent));
      prev = b;
    }

    // (c) flush bands overlay the plot edge; reserve nothing.
    for (const b of flush) {
      out.push(flushIntent(side, b, edge));
      out.push(centerIntent(side, b, extent));
    }
  }
  return out;
}

/** Chain a band outward from the content edge (innermost) or the previous band's outer edge. The
 *  offset before a band's content is its gap + its own inner pad (+ the previous band's outer pad);
 *  the outermost band's outer pad is covered by the reservation sum. */
function chainIntent(side: Side, b: ResolvedBand, prev: ResolvedBand | undefined, edge: CellRef): Intent {
  const r = b.rect;
  const g = b.gapEff + b.padEff.inner + (prev?.padEff.outer ?? 0);
  if (prev === undefined) {
    // innermost: touch the content edge (+ gap), on the outward side.
    switch (side) {
      case "bottom": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: -1, cell: edge }], equals: g, note: `chain0:${r.id}` };
      case "right": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: -1, cell: edge }], equals: g, note: `chain0:${r.id}` };
      case "top": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: 1, cell: r.h }, { coef: -1, cell: edge }], equals: -g, note: `chain0:${r.id}` };
      case "left": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: 1, cell: r.w }, { coef: -1, cell: edge }], equals: -g, note: `chain0:${r.id}` };
    }
  }
  const p = prev!.rect;
  switch (side) {
    case "bottom": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: -1, cell: p.y }, { coef: -1, cell: p.h }], equals: g, note: `chain:${r.id}` };
    case "right": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: -1, cell: p.x }, { coef: -1, cell: p.w }], equals: g, note: `chain:${r.id}` };
    case "top": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: 1, cell: r.h }, { coef: -1, cell: p.y }], equals: -g, note: `chain:${r.id}` };
    case "left": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: 1, cell: r.w }, { coef: -1, cell: p.x }], equals: -g, note: `chain:${r.id}` };
  }
}

/** Pin a flush band to the content edge (an overlay — no gap, no reservation). */
function flushIntent(side: Side, b: ResolvedBand, edge: CellRef): Intent {
  const r = b.rect;
  switch (side) {
    case "bottom": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: -1, cell: edge }], equals: 0, note: `flush:${r.id}` };
    case "right": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: -1, cell: edge }], equals: 0, note: `flush:${r.id}` };
    case "top": return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: 1, cell: r.h }, { coef: -1, cell: edge }], equals: 0, note: `flush:${r.id}` };
    case "left": return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: 1, cell: r.w }, { coef: -1, cell: edge }], equals: 0, note: `flush:${r.id}` };
  }
}

/** Center/anchor a band on the free (cross) axis of its side. The cross pad (§12.4) insets the
 *  anchor targets from the content span ends: [lo + pad, hi − pad]. */
function centerIntent(side: Side, b: ResolvedBand, extent: Extent): Intent {
  const r = b.rect;
  const c = extent.content;
  const anchor = b.anchor ?? "middle";
  const { crossLo, crossHi } = b.padEff;
  if (side === "top" || side === "bottom") {
    if (anchor === "start") return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: -1, cell: c.left }], equals: crossLo, note: `anchor:${r.id}` };
    if (anchor === "end") return { kind: "affine", terms: [{ coef: 1, cell: r.x }, { coef: 1, cell: r.w }, { coef: -1, cell: c.right }], equals: -crossHi, note: `anchor:${r.id}` };
    return { kind: "affine", terms: [{ coef: 2, cell: r.x }, { coef: 1, cell: r.w }, { coef: -1, cell: c.left }, { coef: -1, cell: c.right }], equals: crossLo - crossHi, note: `anchor:${r.id}` };
  }
  if (anchor === "start") return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: -1, cell: c.top }], equals: crossLo, note: `anchor:${r.id}` };
  if (anchor === "end") return { kind: "affine", terms: [{ coef: 1, cell: r.y }, { coef: 1, cell: r.h }, { coef: -1, cell: c.bottom }], equals: -crossHi, note: `anchor:${r.id}` };
  return { kind: "affine", terms: [{ coef: 2, cell: r.y }, { coef: 1, cell: r.h }, { coef: -1, cell: c.top }, { coef: -1, cell: c.bottom }], equals: crossLo - crossHi, note: `anchor:${r.id}` };
}

// ── priority shedding (Step 5) ───────────────────────────────────────────────

/** One sheddable candidate for `shedToFit`: its id, shed priority (lower = shed FIRST), and the
 *  thickness it would reserve if kept. */
export interface ShedItem { id: string; priority: number; thickness: number }

/** Priority shedding (Step 5, validated by experiments/layout-shed.mjs). Given the sheddable items on
 *  one side and the space `budget` they must fit within, return the ids to SHED: drop the lowest
 *  priority first until the kept items' total thickness ≤ budget. Non-sheddable items are NOT passed
 *  in (they always reserve). Pure + deterministic (ties break on larger thickness, then id) so the
 *  decision is STABLE across sweeps — the anti-oscillation requirement (§5): a coarse, one-way call. */
export function shedToFit(items: readonly ShedItem[], budget: number): Set<string> {
  const shed = new Set<string>();
  let total = items.reduce((s, it) => s + it.thickness, 0);
  if (total <= budget) return shed;
  const order = [...items].sort((a, b) => a.priority - b.priority || b.thickness - a.thickness || cmp(a.id, b.id));
  for (const it of order) {
    if (total <= budget) break;
    shed.add(it.id);
    total -= it.thickness;
  }
  return shed;
}

// ── the standalone harness (tests / probes) ──────────────────────────────────

export interface Frame {
  store: CellStore;
  extent: Extent;
  margin: Margin;
}

/** A scalar node: outer sealed to [0,0,W,H] (the sealed canvas), content cells left for the solver. */
export function scalarFrame(store: CellStore, width: number, height: number, margin: Partial<Margin> = {}): Frame {
  const seal = (v: number): CellRef => {
    const c = store.alloc("extent");
    store.write(c, v, "sealed");
    return c;
  };
  const free = (): CellRef => store.alloc("extent"); // unbound → solver assigns
  const extent: Extent = {
    outer: { left: seal(0), top: seal(0), right: seal(width), bottom: seal(height) },
    content: { left: free(), right: free(), top: free(), bottom: free() },
  };
  return { store, extent, margin: { ...ZERO_MARGIN, ...margin } };
}

/** Registration input for the harness: a NodeBand minus the rect (allocated by `add`), plus optional
 *  hand-written dimensions simulating plot-measure. */
export interface SideItemInput extends Omit<NodeBand, "rect"> {
  /** Measured size along the side NORMAL (the thickness that gets reserved): height for top/bottom,
   *  width for left/right. Omit to leave the cell for a later `measure()`. */
  thickness?: number;
  /** Measured size along the side (for centering): width for top/bottom, height for left/right. */
  length?: number;
}

/** A thin harness over `arrangeIntents` + `lowerForPropagation` — the same geometry the real
 *  arrangeNode wires, driven by hand (tests, probes). It adds nothing: registration allocates the
 *  rect, `constraints()` lowers the node's intents, `solve()` runs an ArrangeSolver. */
export class SideArranger {
  private bands: NodeBand[] = [];
  constructor(readonly frame: Frame) {}

  /** Register an adornment on a side. Returns the allocated rect (the caller reads its solved
   *  x/y/w/h). This is the WHOLE contract a lowering sees — it never touches other items. */
  add(input: SideItemInput): PlotRect {
    const s = this.frame.store;
    const rect: PlotRect = { id: input.id, plots: [], x: s.alloc("extent"), y: s.alloc("extent"), w: s.alloc("demand"), h: s.alloc("demand") };
    const isH = input.side === "left" || input.side === "right";
    // thickness = the reserved dimension (w for L/R, h for T/B); length = the cross dimension.
    if (input.thickness !== undefined) s.write(isH ? rect.w : rect.h, input.thickness, "assigned");
    if (input.length !== undefined) s.write(isH ? rect.h : rect.w, input.length, "assigned");
    const { thickness: _t, length: _l, ...band } = input;
    this.bands.push({ ...band, rect });
    return rect;
  }

  /** Simulate plot-measure writing a rect's dimensions after the fact (drives the fixpoint tests). */
  measure(rect: PlotRect, dims: { thickness?: number; length?: number }): void {
    const it = this.bands.find((b) => b.rect === rect);
    if (it === undefined) throw new Error(`measure: unknown rect ${rect.id}`);
    const isH = it.side === "left" || it.side === "right";
    if (dims.thickness !== undefined) this.frame.store.write(isH ? rect.w : rect.h, dims.thickness, "assigned");
    if (dims.length !== undefined) this.frame.store.write(isH ? rect.h : rect.w, dims.length, "assigned");
  }

  /** The node's whole arrangement as solver-agnostic intents. */
  intents(): Intent[] {
    return arrangeIntents(this.frame.store, this.frame.extent, this.frame.margin, this.bands);
  }

  /** The propagation-shaped constraint set (margins + reservation Σ + chain + center). */
  constraints(): Constraint[] {
    return lowerForPropagation(this.intents());
  }

  /** The cells this arranger WRITES (content edges + each rect's position). */
  owned(): CellRef[] {
    const c = this.frame.extent.content;
    return [c.left, c.right, c.top, c.bottom, ...ownedCells(this.bands)];
  }

  /** Emit constraints and run a solver over the frame's cell store (default: propagation). */
  solve(solver: ArrangeSolver = propagation): void {
    solver(this.constraints(), this.frame.store, this.owned());
  }

  /** Read a rect's solved box as numbers (test/inspection convenience). `+ 0` normalizes -0 → 0. */
  box(rect: PlotRect): { x: number; y: number; w: number; h: number } {
    const n = (c: CellRef): number => {
      const v = this.frame.store.read(c);
      return typeof v === "number" ? v + 0 : NaN;
    };
    return { x: n(rect.x), y: n(rect.y), w: n(rect.w), h: n(rect.h) };
  }

  /** Read a content edge (e.g. how far the reservation pushed it in). */
  content(edge: "left" | "right" | "top" | "bottom"): number {
    const v = this.frame.store.read(this.frame.extent.content[edge]);
    return typeof v === "number" ? v + 0 : NaN;
  }
}
