// log: domain {lo,hi} (1-row fit) → relative t = (ln v − ln lo)/(ln hi − ln lo). Same train as
// linear (min/max); the apply interpolates in LOG space. Assumes a positive domain (ln of a
// non-positive value is NULL — the mark drops, as with any out-of-domain point).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, ln, mcol, nullif0 } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

export const log = op({
  name: "log",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } })),
  scheme: "blues",
  legend: "ramp",
  apply: (b): RelOp => {
    const c = inputCol(b, "value");
    // relative t ∈ [0,1] in log space; scaledOut emits t or a ramp colour.
    return scaledOut(b, bin("/", bin("-", ln(mcol(c)), ln(fcol("lo"))), nullif0(bin("-", ln(fcol("hi")), ln(fcol("lo"))))));
  },
  ticks: "nice-linear", // ponytail: linear-spaced ticks in log space; log-nice (1,2,5·10ᵏ) when someone needs it
});
