// Table.via — the cross-TABLE referent (§8 Stage 2): the SAME verb as PlotBuilder.via, on a
// Table handle. One mechanism, different Space interpretation: a plot referent's positional
// channels arrive PLACED (pixel, post-affine); a table referent's columns arrive in DATA space
// (pre-affine — free to feed a scale, train a domain, or place through the frame). The type
// carries the difference, not the verb.
//
// Installed by PROTOTYPE AUGMENTATION from the api layer: data/ stays below ir/ (Table never
// imports the Expr layer); importing api/builder installs the method. The output list cannot be
// validated against the table's columns at author time (the schema resolves async) — pick stays
// unchecked here and the execution binder error is the backstop. No `dvl_cell` output: a raw
// table has no cell to borrow (the Level-2 pick is plot-referent only).
import { Table } from "../data/table.js";
import { boundRef } from "../ir/expr.js";
import { dataSpace, type Space } from "../types/attr.js";
import { producer, type Producer } from "./refs.js";
import { parseViaArgs, type ViaArgs } from "./via-common.js";

declare module "../data/table.js" {
  interface Table {
    /** A cross-table reference producer: borrow this table's columns onto the consuming plot's
     *  marks over a join path — predicates and fk() hops, with the §3b/§3c resolve grammar. */
    via(...args: ViaArgs): Producer;
  }
}

Table.prototype.via = function (this: Table, ...args: ViaArgs): Producer {
  const v = parseViaArgs(`via(${this.name})`, args);
  const tableName = this.name;
  return producer(v.computedNames, (name) => {
    // computed outputs declare their space (§3c); a plain column borrow is DATA by definition —
    // it is the table's raw value, upstream of any scale or placement.
    const declared = v.computedNames.includes(name) ? v.declaredSpace(name) : undefined;
    const space: Space = declared !== undefined ? declared : dataSpace;
    return boundRef(tableName, name, v.steps, { space, arity: "per-row" }, v.resolveFor(name));
  });
};

export {}; // module side-effect: importing installs Table.via
