// via-agg: a resolved MULTI-MATCH via (CELL_KEY_VIA §3b/§3c) — train/apply in miniature.
// A non-single-match via join (any predicate op; each mark may match a SET of referent rows)
// with a declared per-channel reduction. reads: [marks (attach target), joinBase (marks walked
// through the intermediate hops; = marks on a single-hop path), referent].
//
// THE INPUT SCHEMA of a resolution is the apply expression's two-sided row (§3c): alias `m` =
// one joinBase row, alias `f` = one matched referent row. Aggregate-of-expression reduces to
// aggregate-over-staged-values, so both declarative forms stage per matched row INSIDE the join
// (where both aliases exist) and then run the ONE shared reduce grouped by mark identity —
// exprSql/compileEvalJs give the SQL text and the JS mirror of the same staging expression.
//
// Two lowerings:
//   SQL (every resolution declarative): join-stage → lowerTrainSql(by dvl_mark) → keyed attach.
//     Three fragments, all existing forms; never leaves the database.
//   JS (any opaque `js` resolution): the match set MATERIALIZES — one f-row array per mark —
//     and the reduce runs in JS ((matches, mark) => value for opaque channels; the same staged
//     values + lowerTrainJs for declarative channels riding the same via() call). The output
//     relation leaves SQL (jsRel), exactly like any materialize crossing.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { ViaAggPayload } from "../../../plan/payloads.js";
import type { OpBinding } from "../../../algebra/impl.js";
import type { Row, Scalar } from "../../../data/schema.js";
import type { ViaReduceFn } from "../../../ir/refs.js";
import { cellsOf, fcol, type Agg, type AggFn, type ApplyOp, type ScalarExpr } from "../../../algebra/relop.js";
import { compileEvalJs, exprSql, lowerApplySql, lowerTrainJs, lowerTrainSql } from "../../../algebra/lower.js";
import { jsRel, materialize, mkFrag, sqlRel, type Relation } from "../../../algebra/relation.js";

const SQL_OP: Record<string, string> = { eq: "=", lt: "<", le: "<=", gt: ">", ge: ">=", neq: "<>" };
const AGG_FNS = new Set<AggFn>(["min", "max", "sum", "avg", "median", "stddev", "variance", "count", "countDistinct", "first", "last", "stringAgg", "anyValue"]);

type Add = ViaAggPayload["adds"][string];

const stagedExpr = (a: Add): ScalarExpr => (a.arg as ScalarExpr | undefined) ?? fcol(a.attr);

/** The executable reduce of a js resolution: the inline fn, or the resolve-once product of a
 *  registered NAME (stamped by resolveSpec — reaching execution unstamped is a wiring bug). */
function jsFnOf(key: string, ch: string, a: Add): ViaReduceFn {
  if (typeof a.js === "function") return a.js;
  if (a.jsResolved !== undefined) return a.jsResolved;
  throw new Error(`via-agg "${key}": reducer "${String(a.js)}" for "${ch}" is unresolved — call resolveSpec(spec, registries) (a string js names a registries.reducers entry)`);
}

function checkFn(key: string, ch: string, a: Add): void {
  if (a.sqlResolved !== undefined || a.jsResolved !== undefined) return; // a named resolver (sql/js), resolve-once stamped
  if (typeof a.js === "function") return; // inline js reduce
  if (a.fn === undefined || !AGG_FNS.has(a.fn as AggFn)) {
    throw new Error(`via-agg "${key}": unknown resolution "${a.fn}" for "${ch}" — use an AggFn (${[...AGG_FNS].join("/")}) or a js reduce`);
  }
}

/** The (xCol, yCol) a geometry resolver reduces over — its declared `cols` (defaulted to the
 *  placed x/y by resolveSpec's defaultCols), alias-qualified onto the referent side. */
const geomCols = (a: Add): [string, string] => {
  const c = a.cols ?? [];
  return [`f."${c[0] ?? "x"}"`, `f."${c[1] ?? "y"}"`];
};

export async function viaAgg(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as ViaAggPayload;
  const marks = store.read(op.reads[0]) as Relation;
  const joinBase = store.read(op.reads[1]) as Relation;
  const ref = store.read(op.reads[2]) as Relation;
  if (marks.substrate !== "sql" || joinBase.substrate !== "sql" || ref.substrate !== "sql") {
    throw new Error(`via-agg "${p.key}": join-derive needs SQL inputs (marks=${marks.substrate}, ref=${ref.substrate})`);
  }
  for (const [ch, a] of Object.entries(p.adds)) checkFn(p.key, ch, a);
  // a CROSS via (on("*")) resolves to zero key pairs — the join is unconditional (ON TRUE).
  const cond = p.on.length > 0 ? p.on.map(([m, f, o]) => `m."${m}" ${SQL_OP[o] ?? "="} f."${f}"`).join(" AND ") : "TRUE";
  // ROUTING: a sql-geom add (a named resolver with a SQL impl, e.g. convex) pushes to SQL — it does
  // NOT force materialization. A js-opaque add (an inline fn, or a named resolver with no SQL impl)
  // does. So `hasJs` counts only js-opaque adds; sql-geom adds take the geometry branch below.
  const geomAdds = Object.entries(p.adds).filter(([, a]) => a.sqlResolved !== undefined);
  const hasJs = Object.values(p.adds).some((a) => a.js !== undefined && a.sqlResolved === undefined);
  const b = { key: p.key, inputs: {}, outputs: Object.keys(p.adds) } as unknown as OpBinding;

  if (geomAdds.length > 0 && !hasJs) {
    // ── SQL GEOMETRY path: a per-group WKT aggregate (convex hull, …) pushed to the database.
    // The resolver's sql(xCol,yCol) IS the aggregate expression; GROUP BY the mark identity, then
    // attach by dvl_mark (LEFT JOIN — a mark with no match keeps its row, null geometry).
    if (geomAdds.length !== Object.keys(p.adds).length) {
      throw new Error(`via-agg "${p.key}": a geometry resolution (${geomAdds.map(([ch]) => ch).join(", ")}) cannot share one via() with other reductions — split them into separate via() calls`);
    }
    const sel = [`m."dvl_mark" AS dvl_mark`, ...geomAdds.map(([ch, a]) => `${a.sqlResolved!(...geomCols(a))} AS "${ch}"`)];
    const reduced = mkFrag(
      `${p.key}:geom`,
      `SELECT ${sel.join(", ")} FROM @marks AS m JOIN @ref AS f ON ${cond} GROUP BY m."dvl_mark"`,
      { marks: { fragment: joinBase.frag }, ref: { fragment: ref.frag } },
      { columns: [{ name: "dvl_mark", type: "int" }, ...geomAdds.map(([ch]) => ({ name: ch, type: "varchar" as const }))] },
    );
    const applyOp: ApplyOp = {
      kind: "augment",
      add: Object.fromEntries(geomAdds.map(([ch]) => [ch, fcol(ch)])),
      fit: { keyed: [["dvl_mark", "dvl_mark"]], kind: "LEFT JOIN" },
      outTypes: Object.fromEntries(geomAdds.map(([ch]) => [ch, "varchar" as const])),
    };
    store.write(op.writes[0], sqlRel(lowerApplySql(applyOp, marks.frag, reduced, b, p.key)), "assigned");
    return;
  }
  if (!hasJs) {
    // ── SQL path: stage per matched row (both aliases live), reduce, attach ──
    const sel: string[] = [`m."dvl_mark" AS dvl_mark`];
    const aggs: Record<string, Agg> = {};
    const cells = [...new Set(Object.values(p.adds).flatMap((a) => (a.arg !== undefined ? cellsOf(a.arg as ScalarExpr) : [])))];
    for (const [ch, a] of Object.entries(p.adds)) {
      sel.push(`${exprSql(stagedExpr(a))} AS "dvl_v_${ch}"`);
      if (a.order !== undefined) sel.push(`f."${a.order}" AS "dvl_o_${ch}"`);
      aggs[ch] = { fn: a.fn, col: `dvl_v_${ch}`, ...(a.order !== undefined && { order: `dvl_o_${ch}`, desc: a.desc }) } as Agg;
    }
    const joined = mkFrag(
      `${p.key}:join`,
      `SELECT ${sel.join(", ")} FROM @marks AS m JOIN @ref AS f ON ${cond}`,
      { marks: { fragment: joinBase.frag }, ref: { fragment: ref.frag } },
      { columns: [{ name: "dvl_mark", type: "int" }] },
      cells,
    );
    const reduced = lowerTrainSql({ kind: "aggregate", aggs }, joined, b, "dvl_mark", `${p.key}:agg`);
    const applyOp: ApplyOp = {
      kind: "augment",
      add: Object.fromEntries(Object.keys(p.adds).map((ch) => [ch, fcol(ch)])),
      fit: { keyed: [["dvl_mark", "dvl_mark"]], kind: "LEFT JOIN" }, // marks with NO match keep their row (null value)
      outTypes: Object.fromEntries(Object.keys(p.adds).map((ch) => [ch, "double" as const])),
    };
    store.write(op.writes[0], sqlRel(lowerApplySql(applyOp, marks.frag, reduced, b, p.key)), "assigned");
    return;
  }

  // ── JS path: materialize the match sets, reduce per mark in JS ──
  // matches: FULL f-side rows per mark, with intermediate-hop columns FLATTENED IN (§4.3 "cut f"):
  // a multi-hop walk mints dvl_h_* columns on the m side; projecting them into each match row
  // makes (matches, mark) complete — the reducer sees per-match hop values, not just the group's.
  const mRows = await materialize(joinBase, ctx.run);
  const hopCols = mRows.schema.map((c) => c.name).filter((n) => n.startsWith("dvl_h_"));
  const hopSel = hopCols.map((h) => `m."${h}"`).join(", ");
  const joinRows = (await ctx.run(
    mkFrag(`${p.key}:join`, `SELECT m."dvl_mark" AS dvl_via_group${hopSel.length > 0 ? `, ${hopSel}` : ""}, f.* FROM @marks AS m JOIN @ref AS f ON ${cond}`, { marks: { fragment: joinBase.frag }, ref: { fragment: ref.frag } }, { columns: [] }),
  )) as readonly Record<string, unknown>[];
  const matchesByMark = new Map<string, Record<string, unknown>[]>();
  for (const r of joinRows) {
    const { dvl_via_group, ...f } = r;
    const k = String(dvl_via_group);
    const g = matchesByMark.get(k);
    if (g === undefined) matchesByMark.set(k, [f]);
    else g.push(f);
  }
  // the m-side row: joinBase carries the mark + hopped columns (one row per mark on a
  // single-match walk; the first row stands for the group otherwise).
  const mByMark = new Map<string, Row>();
  for (const r of mRows.rows) {
    const k = String(r["dvl_mark"]);
    if (!mByMark.has(k)) mByMark.set(k, r);
  }
  const marksRows = await materialize(marks, ctx.run);
  const out = marksRows.rows.map((mr) => {
    const k = String(mr["dvl_mark"]);
    const matches = matchesByMark.get(k) ?? [];
    const mSide = mByMark.get(k) ?? mr;
    const row: Record<string, Scalar> = { ...mr } as Record<string, Scalar>;
    for (const [ch, a] of Object.entries(p.adds)) {
      if (a.js !== undefined) {
        // cols: the declared projection hint, defaulting to the borrowed column — how a
        // column-generic REGISTERED reducer (mode/range/extentUnion) knows what to reduce over.
        row[ch] = (matches.length > 0 ? jsFnOf(p.key, ch, a)(matches, mSide, a.cols ?? [a.attr]) : null) as Scalar;
        continue;
      }
      // declarative channel riding the same via(): stage per match with the SAME two-sided
      // expression (row = m side, fit = f side), then the ONE reduce's JS mirror.
      const ev = compileEvalJs(stagedExpr(a));
      const staged = matches.map((f) => ({ dvl_v: ev(mSide, f as Row, {}, {}), ...(a.order !== undefined && { dvl_o: (f as Row)[a.order] }) }));
      if (staged.length === 0) {
        row[ch] = null;
        continue;
      }
      const agg = { fn: a.fn, col: "dvl_v", ...(a.order !== undefined && { order: "dvl_o", desc: a.desc }) } as Agg;
      row[ch] = lowerTrainJs({ kind: "aggregate", aggs: { [ch]: agg } }, { rows: staged as Row[], schema: [] }, b).rows[0][ch] as Scalar;
    }
    return row;
  });
  const addSchema = Object.keys(p.adds).map((ch) => ({ name: ch, type: "unknown" as const }));
  store.write(op.writes[0], jsRel(out, [...marksRows.schema, ...addSchema]), "assigned");
}
