// barX (value → horizontal bar, x-axis): a value → a horizontal bar from the baseline (range.lo =
// the left edge) out to the value. Outputs x (the bar's LEFT edge — the domain's lo, relative 0)
// + w (its width out to the value) — the x-mirror of barY; pick('x','w') binds both. Trains
// min/max like a linear scale and carries `nice-linear` ticks so the x axis is labelled.
//
// NOT a blind copy of barY's apply: barY emits y = t, h = t and lands on the baseline only
// because the y range is INVERTED (top = bottom + (top−bottom)·t, then +|span|·t cancels back to
// the bottom). On the uninverted x axis that same shape draws [v, 2v] — the bar hangs off its own
// far edge and bleeds up to 100% of the span (the §triage barX limit-cycle). Here the rect's
// left edge is the constant relative 0 (the domain's lo) and w carries the value.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, mcol, nullif0, unary } from "../../algebra/relop.js";
import { continuous } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const barX = op({
  name: "barX",
  domain: continuous((b): RelOp => {
    const v = mcol(inputCol(b, "value"));
    const zero = b.options?.zero === true;
    return { kind: "reduce", aggs: {
      lo: zero ? { fn: "min", arg: bin("/", bin("-", v, unary("abs", v)), lit(2)) } : { fn: "min", col: inputCol(b, "value") },
      hi: zero ? { fn: "max", arg: bin("/", bin("+", v, unary("abs", v)), lit(2)) } : { fn: "max", col: inputCol(b, "value") },
    } };
  }, { union: null, unionFn: undefined, nice: undefined }),
  inputs: { marks: [{ name: "value", type: "double" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), w: relativeSpace(len("x")) },
  inputSpaces: { value: dataSpace },
  apply: (b): RelOp => {
    const [xo, wo] = b.outputs;
    const ratio = bin("/", bin("-", mcol(inputCol(b, "value")), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo"))));
    return { kind: "derive", add: { [xo]: lit(0), [wo]: ratio }, outTypes: { [xo]: "double", [wo]: "double" } };
  },
  ticks: "nice-linear",
});
