// linear: domain {lo,hi} (1-row fit) → pixel range, linear interpolation.
// Authored via the unified op() factory (dataflow/exec, simplification §2.12): RelOp descriptions
// in, ONE Operator out (§12 Phase 5 — the descriptor fields are folded into the operator; the
// train lives INSIDE the domain, whose shape derives the broadcast fit attachment — exec.ts
// fitMode; the apply carries NO fit field).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, mcol, nullif0 } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

export const linear = op({
  name: "linear",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } })),
  // §6: continuous colour default is a sequential ramp; ignored unless bound to a colour channel.
  scheme: "blues",
  legend: "ramp", // continuous colour legend = a gradient band stack (G2); ONE derivation site reads this
  apply: (b): RelOp => {
    const c = inputCol(b, "value");
    // NORMALIZED: relative t = (value − lo) / NULLIF(hi − lo, 0) ∈ [0,1]. scaledOut emits t for a
    // positional/number channel (frame affine maps t → pixels) or a colour from the ramp for style⟨color⟩.
    const ratio = bin("/", bin("-", mcol(c), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo"))));
    return scaledOut(b, ratio);
  },
  ticks: "nice-linear",
});
