// Resolve-once (simplification §2.3, §12 Phase 3): the ONLY registry consumer downstream of spec
// construction. Walks the spec and attaches resolved component objects everywhere a name was
// recorded, so the compiler and executor never do by-name lookups. Must run AFTER every
// spec-mutating lowering (lowerAxes, lowerLegends when wired) — they CREATE instances (axis V
// producers, apply-only wrappers) that need resolution too. Idempotent: re-running skips
// already-resolved entries, so standalone compiles and repeated compileSpec calls are safe.
//
// The name→object references this resolves (the §11.2 F6 inventory):
//   1. LayoutInstance.descriptor        → resolved.operator (the ONE Operator, §12 Phase 5)
//   2. options.wrapped (apply-only)     → options.wrappedAlgo — the wrapped scale's Operator
//   3. options.tickAlgo (vtable)        → options.tickAlgoResolved — the TickAlgo object
//   4. Plot.markType                    → resolvedMark — the MarkDescriptor
//   (Node.arrange.solver resolves at CREATION — arrangeNode runs during compile, after this
//    step, and its pickSolver choice is static; see dataflow/arrange.ts SOLVERS.)
import type { Spec } from "../ir/spec.js";
import type { Registries } from "../operator/registry.js";
import type { FKEdge } from "../data/fk.js";
import { isFKRef, normalizePath, normalizeStep, type AttrExpr, type JoinCondition, type Path, type ResolvedPath, type ViaResolution, type ViaResolve } from "../ir/refs.js";
import { isProducerSource, isRelationSource, type TableRef } from "../ir/plot.js";
import { Table } from "../data/table.js";
import { warnOnce } from "../config.js";

export interface ResolveOpts {
  /** §4.3: flip UNKNOWN-multiplicity vias (no key knowledge either way) from permissive to a
   *  build error unless a resolution is declared — total judgment once FKs are catalogued. */
  strictMultiplicity?: boolean;
}

export function resolveSpec(spec: Spec, registries: Registries, opts: ResolveOpts = {}): void {
  for (const inst of spec.layouts.values()) {
    if (inst.resolved === undefined) {
      inst.resolved = { operator: registries.operators.get(inst.descriptor) };
    }
    const wrapped = inst.options?.wrapped;
    if (typeof wrapped === "string" && inst.options?.wrappedAlgo === undefined && registries.operators.has(wrapped)) {
      // S5 VALIDATION at the resolve boundary: an apply-only wrapper hands the wrapped operator
      // straight to the executor as an apply payload's algo — plan and impls are orthogonal
      // capabilities, so a plan-only operator (no sql/js) can be REGISTERED but cannot be APPLIED.
      const wop = registries.operators.get(wrapped);
      if (wop.sql === undefined && wop.js === undefined) {
        throw new Error(`resolveSpec: instance "${inst.id}" wraps "${wrapped}" (options.wrapped), but that operator has no sql/js implementation — a plan-only operator cannot be applied`);
      }
      inst.options = { ...inst.options, wrappedAlgo: wop };
    }
    const tick = inst.options?.tickAlgo;
    if (typeof tick === "string" && inst.options?.tickAlgoResolved === undefined && registries.tickAlgos.has(tick)) {
      inst.options = { ...inst.options, tickAlgoResolved: registries.tickAlgos.get(tick) };
    }
    // §6: a colour scale's palette — the instance `scheme` override, else the WRAPPED operator's
    // default (an apply-only wrapper must render the same palette as the scale it pictures —
    // AUTOLEGEND_IMPL §8's swatch-mismatch finding), else the operator's own default — resolved
    // once to an array. THE single scheme-inference site: the apply reads `options.schemeColors`
    // (never the registry); only used when the instance serves a style⟨color⟩ channel.
    if (inst.resolved !== undefined && inst.options?.schemeColors === undefined) {
      const wrappedScheme = (inst.options?.wrappedAlgo as { scheme?: string } | undefined)?.scheme;
      const schemeName = (typeof inst.options?.scheme === "string" ? inst.options.scheme : undefined) ?? wrappedScheme ?? inst.resolved.operator.scheme;
      if (schemeName !== undefined && registries.schemes.has(schemeName)) {
        inst.options = { ...inst.options, schemeColors: registries.schemes.get(schemeName) };
      }
    }
  }
  for (const plot of spec.plots.values()) {
    if (plot.resolvedMark === undefined) plot.resolvedMark = registries.marks.get(plot.markType);
    // §4.3: a STRING `js` NAMES a registered resolver — resolve-once from its descriptor (the IR
    // keeps the name, so the spec stays serializable; downstream reads the stamped products). An
    // INLINE function `js` is already executable (JS-only) and is skipped. A named resolver with a
    // SQL impl stamps `sqlResolved`+`requires` too — via-agg PREFERS SQL (push-down); a named
    // resolver's `defaultCols` fills an omitted `cols` (convex reads placed x/y).
    for (const [ch, expr] of Object.entries(plot.channels)) {
      if (expr.kind !== "table-ref" && expr.kind !== "bound-ref") continue;
      for (const res of resolutionsOf(expr.resolve)) {
        if (typeof res.js !== "string" || res.jsResolved !== undefined) continue;
        if (!registries.reducers.has(res.js)) {
          throw new Error(`via(${plot.id}.${ch}): unknown resolver "${res.js}" — register it (registries.reducers.register) or pass the function inline ({ js: (matches, mark) => … })`);
        }
        const spec = registries.reducers.get(res.js);
        res.jsResolved = spec.js;
        if (res.cols === undefined && spec.defaultCols !== undefined) res.cols = spec.defaultCols;
        if (spec.sql !== undefined) {
          res.sqlResolved = spec.sql;
          if (spec.requires !== undefined) res.requires = spec.requires;
        }
      }
    }
  }
  resolvePaths(spec, opts);
}

/** Every ViaResolution object reachable from a `resolve` value (single object or per-output map —
 *  bare fn / string values carry no js name to resolve). */
function resolutionsOf(resolve: ViaResolve | undefined): ViaResolution[] {
  if (resolve === undefined || typeof resolve === "string" || typeof resolve === "function") return [];
  if ("fn" in resolve || "js" in resolve || "arg" in resolve) return [resolve as ViaResolution];
  return Object.values(resolve).filter((v): v is ViaResolution => typeof v === "object" && v !== null);
}

// ── join-path resolution (CELL_KEY_VIA §3a): ONE resolver for every Path site ──────────────

/** The (source, target) context a Path resolves in. Names may be null (a producer/cell-backed
 *  relation has no catalog name) — explicit predicates still resolve; FK/null forms need names. */
export interface PathContext {
  source: string | null;
  target: string | null;
  fks: readonly FKEdge[];
  /** Error prefix naming the resolving site. */
  site: string;
}

const attrOf = (rel: string, column: string): AttrExpr => ({ kind: "attr", relation: { relation: rel }, column });

/** Qualify a condition's bare-column operands: left ⇒ the hop's source, right ⇒ its target. */
function qualify(c: JoinCondition, leftRel: string | null, rightRel: string | null): JoinCondition {
  const q = (a: JoinCondition["left"], rel: string | null): AttrExpr =>
    a.kind === "local-column" && rel !== null ? attrOf(rel, a.columnName) : (a as AttrExpr);
  // spread preserves `cross` (a cross hop carries no real columns — pairs() drops it downstream).
  return { ...c, left: q(c.left, leftRel), right: q(c.right, rightRel) };
}

/** The FK edges connecting two relations (either direction). */
const fkBetween = (fks: readonly FKEdge[], a: string, b: string): FKEdge[] =>
  fks.filter((e) => (e.fromTable === a && e.toTable === b) || (e.fromTable === b && e.toTable === a));

/** Expand one FK edge into eq conditions, oriented so `left` is `current`'s side. */
function fkConditions(e: FKEdge, current: string): JoinCondition[] {
  const forward = e.fromTable === current; // current holds the FK columns
  const leftCols = forward ? e.fromCols : e.toCols;
  const rightCols = forward ? e.toCols : e.fromCols;
  const rightRel = forward ? e.toTable : e.fromTable;
  return leftCols.map((lc, i) => ({ op: "eq" as const, left: attrOf(current, lc), right: attrOf(rightRel, rightCols[i]) }));
}

/** Resolve one FK hop, current ⇢ next; zero or several candidate edges is an error naming them. */
function fkHop(fks: readonly FKEdge[], current: string, next: string, site: string): JoinCondition[] {
  const edges = fkBetween(fks, current, next);
  if (edges.length === 0) throw new Error(`${site}: no FK between "${current}" and "${next}" — declare one (db.declareFK) or give explicit predicates`);
  if (edges.length > 1) throw new Error(`${site}: ${edges.length} FKs between "${current}" and "${next}" (${edges.map((e) => `${e.fromTable}(${e.fromCols.join(",")})→${e.toTable}`).join("; ")}) — name the columns explicitly`);
  return fkConditions(edges[0], current);
}

/** THE path resolver: raw Path → ResolvedPath (one entry per hop, operands attr-qualified where
 *  relations are known). `null` infers the unique source⇄target FK; an FKRef hop expands against
 *  the catalog; a RUN of consecutive explicit predicates is ONE (possibly composite-key) hop —
 *  a mid-path explicit hop must attr-qualify its right operand ("rel.col") so the walk knows
 *  where it lands; the last hop lands on the target by construction. */
export function resolvePath(p: Path, ctx: PathContext): ResolvedPath {
  p = normalizePath(p); // totality over the widened PathStep: a direct caller may pass string steps
  if (p === null) {
    if (ctx.source === null || ctx.target === null) throw new Error(`${ctx.site}: cannot infer an FK — the ${ctx.source === null ? "source" : "target"} relation has no catalog name; give explicit predicates`);
    return [fkHop(ctx.fks, ctx.source, ctx.target, ctx.site)];
  }
  const hops: ResolvedPath = [];
  let current = ctx.source;
  let i = 0;
  // a leading fk() naming the SOURCE relation is the anchor — checked, then consumed
  if (p.length > 1 && isFKRef(p[0]) && p[0].relation === current) i = 1;
  while (i < p.length) {
    const step = p[i];
    if (isFKRef(step)) {
      if (current === null) throw new Error(`${ctx.site}: fk("${step.relation}") needs a named source relation to resolve from`);
      hops.push(fkHop(ctx.fks, current, step.relation, ctx.site));
      current = step.relation;
      i++;
      continue;
    }
    // a run of consecutive explicit predicates = ONE hop
    const run: JoinCondition[] = [];
    while (i < p.length && !isFKRef(p[i])) {
      run.push(p[i] as JoinCondition);
      i++;
    }
    const last = i >= p.length;
    // where does this hop land? an attr-qualified right operand says; else the target (last hop only)
    const declared = [...new Set(run.map((c) => (c.right.kind === "attr" ? c.right.relation.relation : null)).filter((r): r is string => r !== null))];
    if (declared.length > 1) throw new Error(`${ctx.site}: one hop's predicates land on several relations (${declared.join(", ")})`);
    const next = declared[0] ?? (last ? ctx.target : null);
    if (!last && next === null) throw new Error(`${ctx.site}: a mid-path predicate hop must qualify its right operand ("rel.col")`);
    hops.push(run.map((c) => qualify(c, current, next)));
    current = next;
  }
  if (ctx.target !== null && current !== null && current !== ctx.target) {
    throw new Error(`${ctx.site}: the path ends at "${current}", expected "${ctx.target}"`);
  }
  return hops;
}

/** Every distinct FK path from `from` to `to`, as resolved hops (σ needs ALL routes where
 *  resolvePath resolves ONE declared route). BFS over the catalog; an edge is traversable in
 *  EITHER direction; no edge reused and no relation revisited within a path (cycles are never
 *  partition keys); depth ≤ maxDepth hops — deeper is a modeling smell, the caller's error asks
 *  for an explicit `on`. Deterministic: sorted by (hop count, canonical string) and deduped. */
export function enumerateFKPaths(from: string, to: string, fks: readonly FKEdge[], maxDepth = 3): ResolvedPath[] {
  if (from === to) return [];
  const out: ResolvedPath[] = [];
  const walk = (current: string, hops: ResolvedPath, usedEdges: ReadonlySet<number>, visited: ReadonlySet<string>): void => {
    if (hops.length >= maxDepth) return;
    fks.forEach((e, i) => {
      if (usedEdges.has(i)) return;
      const next = e.fromTable === current ? e.toTable : e.toTable === current ? e.fromTable : null;
      if (next === null || visited.has(next)) return;
      const hop = fkConditions(e, current);
      const nextHops = [...hops, hop];
      if (next === to) {
        out.push(nextHops);
        return;
      }
      walk(next, nextHops, new Set([...usedEdges, i]), new Set([...visited, next]));
    });
  };
  walk(from, [], new Set(), new Set([from]));
  const canon = (p: ResolvedPath): string =>
    p.flatMap((hop) => hop.map((c) => `${c.left.kind === "attr" ? c.left.relation.relation : "?"}.${c.left.kind === "attr" ? c.left.column : "?"}=${c.right.kind === "attr" ? c.right.relation.relation : "?"}.${c.right.kind === "attr" ? c.right.column : "?"}`)).join("|");
  const seen = new Set<string>();
  return out
    .sort((a, b) => a.length - b.length || (canon(a) < canon(b) ? -1 : 1))
    .filter((p) => {
      const k = canon(p);
      if (seen.has(k)) return false;
      seen.add(k);
      return true;
    });
}

/** The relation a raw Path lands on, when statable: the last step's fk() target or the last
 *  explicit condition's attr-qualified right relation. Null when unqualified (a bare string
 *  step desugars to an unqualified same-column eq, so it also yields null). */
function pathTargetName(p: Path): string | null {
  if (p === null || p.length === 0) return null;
  const last = normalizeStep(p[p.length - 1]);
  if (isFKRef(last)) return last.relation;
  return last.right.kind === "attr" ? last.right.relation.relation : null;
}

/** A source's catalog name (a producer/cell-backed source has none). */
export function relationName(src: TableRef | undefined): string | null {
  if (src === undefined) return null;
  if (typeof src === "string") return src;
  if (src instanceof Table) return src.name;
  return null; // producer / relation-cell sources
}

/** One hop's match multiplicity (§3b). Provably SINGLE when it lands on a KEY of its right
 *  relation — the FK catalog's to-side columns are keys by definition, so an eq hop whose right
 *  columns cover some key of that relation matches at most one row. Any non-eq predicate is
 *  provably MULTI (it selects a set). Everything else is UNKNOWN — an unnamed relation, or a
 *  relation the catalog holds no key for; with a fully-declared catalog UNKNOWN disappears and
 *  the judgment is total. */
export function hopMultiplicity(hop: readonly JoinCondition[], fks: readonly FKEdge[]): "single" | "multi" | "unknown" {
  if (hop.some((c) => c.op !== "eq")) return "multi";
  const rels = [...new Set(hop.map((c) => (c.right.kind === "attr" ? c.right.relation.relation : null)))];
  if (rels.length !== 1 || rels[0] === null) return "unknown";
  const rightCols = hop.map((c) => (c.right.kind === "attr" ? c.right.column : c.right.kind === "local-column" ? c.right.columnName : ""));
  const keys = fks.filter((e) => e.toTable === rels[0]).map((e) => e.toCols);
  if (keys.length === 0) return "unknown";
  return keys.some((k) => k.every((c) => rightCols.includes(c))) ? "single" : "multi";
}

/** A whole path's multiplicity: multi dominates, then unknown; single only when EVERY hop is. */
export function pathMultiplicity(resolved: ResolvedPath, fks: readonly FKEdge[]): "single" | "multi" | "unknown" {
  let out: "single" | "multi" | "unknown" = "single";
  for (const hop of resolved) {
    const m = hopMultiplicity(hop, fks);
    if (m === "multi") return "multi";
    if (m === "unknown") out = "unknown";
  }
  return out;
}

/** Every resolved nest condition must be eq — dvl_cell is a partition key (§3a rule 4). */
function gateNestEq(resolved: ResolvedPath, site: string): void {
  for (const hop of resolved) for (const c of hop) {
    if (c.op !== "eq") throw new Error(`${site}: a nest key must resolve to all-eq conditions (got ${c.op}) — non-eq joins are for vias, with a declared resolution`);
  }
}

/** Resolve every Path site on the spec (idempotent — skips already-stamped entries):
 *  each template ChildRef's nest, each plot's own nest override, each channel's via ref,
 *  each layer's frame assignment, and the derived σ of nested layers (§7e S2). */
function resolvePaths(spec: Spec, opts: ResolveOpts = {}): void {
  const fks = spec.db?.fks ?? [];
  // template-child index: node → its host/child relation names (frame + σ read it)
  const templates = new Map<string, { hostRel: string | null; childRel: string | null }>();
  for (const node of spec.nodes.values()) {
    for (const c of node.children) {
      if (c.hostRow !== undefined) continue;
      const hostRel = relationName(spec.plots.get(c.hostPlot)?.source);
      const child = spec.nodes.get(c.node);
      const childRel = relationName(child !== undefined && child.plots.length > 0 ? spec.plots.get(child.plots[0])?.source : undefined);
      templates.set(c.node, { hostRel, childRel });
      if (c.nest === null || c.nest.resolved !== undefined) continue;
      const site = `nest(${c.node})`;
      c.nest.on = normalizePath(c.nest.on); // string shorthand → eq(col, col), in place (zero strings post-resolve)
      c.nest.resolved = resolvePath(c.nest.on, { source: childRel, target: hostRel, fks, site });
      gateNestEq(c.nest.resolved, site);
    }
  }
  // FRAME assignments (§7e F2): owner semantics — the layer's panel is its referent's dvl_cell.
  for (const plot of spec.plots.values()) {
    if (plot.scope !== undefined && !templates.has(plot.node)) {
      throw new Error(`scope(${plot.id}): 'scope' is what NESTING means — it is meaningless on a top-level layer (nest the layer, or drop the opt)`);
    }
    const fr = plot.frame;
    if (fr === undefined || fr.resolved !== undefined) continue;
    fr.on = normalizePath(fr.on); // BEFORE pathTargetName below reads it
    const site = `frame(${plot.id})`;
    if (templates.has(plot.node)) throw new Error(`${site}: a NESTED layer's panel comes from the partition (σ) — drop frame:, or author the layer top-level`);
    if (fr.plot === undefined) {
      // the sugar form (bare predicate/path): find the co-nested plot over the path's target
      const target = pathTargetName(fr.on);
      if (target === null) throw new Error(`${site}: cannot tell which relation the path lands on — qualify the right operand ("rel.col") or pass the via handle`);
      const candidates = [...spec.plots.values()].filter((p) => p.id !== plot.id && templates.has(p.node) && relationName(p.source) === target);
      if (candidates.length !== 1) throw new Error(`${site}: ${candidates.length} co-nested plots over "${target}" — pass the via handle`);
      fr.plot = candidates[0].id;
    }
    const refRel = relationName(spec.plots.get(fr.plot)?.source);
    fr.resolved = resolvePath(fr.on, { source: relationName(plot.source), target: refRel, fks, site });
    gateNestEq(fr.resolved, site);
    if (pathMultiplicity(fr.resolved, fks) !== "single") {
      throw new Error(`${site}: a frame is ONE panel — the path must be provably single-match end to end (declare the FKs it walks)`);
    }
  }
  // σ derivation (§7e S2): a nested layer whose source is NOT the nest table reaches the host
  // through the FK catalog — its partition is DERIVED, one path per distinct FK route, conjoin
  // by default ('union' admits any route). The legacy cell pick suppresses σ (deprecation path).
  for (const [nodeId, t] of templates) {
    const child = spec.nodes.get(nodeId);
    if (child === undefined) continue;
    for (const pid of child.plots) {
      const p = spec.plots.get(pid);
      if (p === undefined || p.sigma !== undefined || p.nest != null) continue;
      if (isProducerSource(p.source) || isRelationSource(p.source)) continue; // broadcast / cell-backed
      const srcRel = relationName(p.source);
      if (srcRel === null || srcRel === t.childRel || t.hostRel === null) continue; // the nest key covers it
      const legacy = p.channels["cell"];
      if (legacy !== undefined && legacy.kind === "table-ref" && legacy.attrName === "dvl_cell") {
        warnOnce(`${pid}:cell-pick`, `pick({ cell: 'dvl_cell' }) is deprecated — author the layer TOP-LEVEL with opts.frame (perCell explainer §7d)`);
        continue; // today's owner spelling keeps today's borrow compile path
      }
      const site = `sigma(${pid})`;
      const paths = enumerateFKPaths(srcRel, t.hostRel, fks);
      if (paths.length === 0) throw new Error(`${site}: no FK route from "${srcRel}" to "${t.hostRel}" — declareFK the hops or give an explicit on`);
      for (const path of paths) gateNestEq(path, site);
      p.sigma = { paths, mode: p.scope ?? "panel" };
    }
  }
  for (const plot of spec.plots.values()) {
    if (plot.nest != null && plot.nest.resolved === undefined) {
      const hostPlot = [...spec.nodes.values()].flatMap((n) => n.children).find((c) => c.node === plot.node)?.hostPlot;
      const hostRel = relationName(hostPlot !== undefined ? spec.plots.get(hostPlot)?.source : undefined);
      const site = `nest(${plot.id})`;
      plot.nest.on = normalizePath(plot.nest.on);
      plot.nest.resolved = resolvePath(plot.nest.on, { source: relationName(plot.source), target: hostRel, fks, site });
      gateNestEq(plot.nest.resolved, site);
    }
    for (const [ch, expr] of Object.entries(plot.channels)) {
      if ((expr.kind !== "table-ref" && expr.kind !== "bound-ref") || expr.resolvedVia !== undefined) continue;
      // a via's target relation: the referent PLOT's source, or the referenced TABLE itself
      // (a bound ref names it directly, so the target is always known).
      const refRel = expr.kind === "table-ref" ? relationName(spec.plots.get(expr.plotId)?.source) : expr.tableName;
      const site = `via(${plot.id}.${ch})`;
      expr.viaSpec = normalizePath(expr.viaSpec);
      expr.resolvedVia = resolvePath(expr.viaSpec, { source: relationName(plot.source), target: refRel, fks, site });
      // §3b multiplicity: a PROVABLY multi-match via (a non-eq predicate, or an eq hop the
      // catalog can show does NOT land on a key) must declare its resolution — undeclared
      // multiplicity is a build-time error, never a silent fan-out. UNKNOWN hops (no key
      // knowledge) pass: without a populated catalog the judgment cannot be total.
      // §8 Stage 6: the Level-2 cell borrow is a FRAME assignment — the whole path must be
      // provably single-match (an unpopulated catalog degrades to this error: declare the FKs).
      // Checked BEFORE the generic multi judgment: "declare a resolution" would be wrong advice
      // for a frame key (an aggregated cell id is meaningless).
      if (expr.kind === "table-ref" && ch === "cell" && expr.attrName === "dvl_cell" && pathMultiplicity(expr.resolvedVia, fks) !== "single") {
        throw new Error(`${site}: a cell borrow must be provably single-match end to end — declare the FKs it walks (db.declareFK) so every hop lands on a key`);
      }
      const mult = pathMultiplicity(expr.resolvedVia, fks);
      if (mult === "multi" && expr.resolve === undefined) {
        throw new Error(`${site}: this via join can match several referent rows — declare how it reduces (via(..., { resolve: 'avg' | { ${ch}: 'last' } }))`);
      }
      // §4.3: UNKNOWN (no key knowledge either way) is permissive by default — the judgment
      // cannot be total on an unpopulated catalog. strictMultiplicity makes it total: prove
      // single-match (declare the FKs) or declare a resolution.
      if (opts.strictMultiplicity === true && mult === "unknown" && expr.resolve === undefined) {
        throw new Error(`${site}: cannot prove this via join is single-match (strictMultiplicity) — declare the FKs it walks (db.declareFK) or declare a resolution (via(..., { resolve: … }))`);
      }
    }
    // layout aux inputs: each declared `on` resolves against (aux relation ⇢ marks relation) —
    // the SAME resolver as every Path site (§3a rule 2); the resolved pairs reach the impl
    // through the binding (OpBinding.refs).
    for (const inst of spec.layouts.values()) {
      for (const [role, input] of Object.entries(inst.inputs ?? {})) {
        if (role === "marks" || input.on === undefined || input.resolvedOn !== undefined) continue;
        input.on = normalizePath(input.on) ?? undefined;
        const auxRel = typeof input.relation === "string" ? input.relation : relationName(input.relation);
        const marksRel = relationName(inst.inputs.marks?.relation);
        input.resolvedOn = resolvePath(input.on ?? null, { source: auxRel, target: marksRel, fks, site: `layout(${inst.id}.${role})` });
      }
    }
  }
}
