// Plot (the atom: one data table → one mark table) + params + nest spec
// (WUIR_IMPL §2.1; WUNOUNS §Plot).
import type { LayoutId, NodeId, PlotId } from "../types/ids.js";
import type { ExtentEdges, MarkAnchor, MarkDescriptor } from "./mark.js";
import type { Expr } from "./expr.js";
import type { Path, ResolvedPath } from "./refs.js";
import type { CellRef } from "./cell.js";
import type { Table } from "../data/table.js";

/** A reference to a data source: a relation NAME (resolved by the Database), a Table, a PRODUCED
 *  relation cell (WUAXIS §V-as-a-source), or a PRODUCER instance's output relation — the
 *  source-position sibling of a channel's `layoutOutput(id, col)`: a channel picks an instance's
 *  output COLUMN, a source takes its output RELATION. For the cell case the plot's base IS that
 *  cell; for the producer case the compiler runs the instance's `plan` once (emit-once per node)
 *  and the base is its output cell (WUAXIS §4). No `marktable` either way. */
/** A single-row, single-column source — the authoring constant `UNIT` (value 1) / `UNIT(v)`. The
 *  builder rewrites it to a synthesized `values` producer in `mark()` BEFORE it reaches the IR, so
 *  no compile/render consumer ever sees it; it lives in the union only to type the `mark(source)`
 *  boundary. Its lone column is `value`. */
export interface UnitSource {
  readonly __unit: "unit-source";
  readonly value: number | string | boolean;
}

export type TableRef = string | Table | { relation: CellRef } | { producer: LayoutId } | UnitSource;

/** Is this source a produced relation cell (vs a table name / Table)? */
export const isRelationSource = (s: TableRef): s is { relation: CellRef } => typeof s === "object" && s !== null && "relation" in s;

/** Is this source a producer instance's output relation (a SOURCE instance — vtable, unit)? */
export const isProducerSource = (s: TableRef): s is { producer: LayoutId } => typeof s === "object" && s !== null && "producer" in s;

/** Is this source the `UNIT` authoring constant (rewritten to a `values` producer in mark())?
 *  Bare `UNIT` is a CALLABLE (typeof "function") carrying the sentinel props; `UNIT(v)` is a
 *  plain object — admit both. */
export const isUnitSource = (s: TableRef): s is UnitSource =>
  (typeof s === "object" || typeof s === "function") && s !== null && "__unit" in s && s.__unit === "unit-source";

/** A stable identity key for a source (§C6): quantity identity is TABLE-SCOPED — each table's
 *  column is a distinct quantity; equivalence across tables is authored, never assumed by name. */
export const sourceKey = (s: TableRef): string =>
  typeof s === "string" ? `t:${s}` : "producer" in s ? `p:${s.producer}` : "relation" in s ? `c:${s.relation}` : `tbl:${(s as { name?: string }).name ?? "?"}`;

/** CHANNEL-SPACE box-model adjustments (WUDESIGN §box model / §seam); types only — C6. */
export interface SpatialAdjustments {
  padding?: Expr | { top?: Expr; right?: Expr; bottom?: Expr; left?: Expr }; // len
  rotation?: Expr; // angle
  align?: "left" | "center" | "right"; // anchor → coord
  baseline?: "top" | "middle" | "bottom";
  dx?: Expr; // len
  dy?: Expr; // len
}

export interface PlotParams {
  adjust?: SpatialAdjustments;
  style?: Record<string, Expr>; // OPAQUE CSS pass-through (open set), forwarded raw
  clip?: boolean;
  zIndex?: number;
}

/** The nest key as a Path (CELL_KEY_VIA §3): `on` is the raw authored path (null ⇒ infer the
 *  unique child⇄host FK); `resolved` is stamped by resolveSpec — attr-qualified eq conditions,
 *  ONE entry per hop (multi-hop = chained join relops at compile). The nest key is the single
 *  consumer gated to all-eq resolved conditions (dvl_cell is a partition key). */
export type NestJoinSpec = { on: Path; resolved?: ResolvedPath } | null; // null nest slot ⇒ no nest

export interface Plot {
  id: PlotId;
  node: NodeId;
  source: TableRef;
  markType: string; // registry key → MarkDescriptor
  /** Resolve-once: the mark descriptor, attached by resolveSpec — compiler/executor read this. */
  resolvedMark?: MarkDescriptor;
  /** Who minted this plot: absent = author-written. Lowerings tag theirs so geometry passes can
   *  distinguish DATA marks from adornments — e.g. the overhang loop (§4.1) must never enroll an
   *  axis label that legitimately lives outside the content box. A typed tag, not an id-prefix
   *  heuristic. */
  origin?: "axis" | "legend" | "strip";
  /** Compile product (never authored): a box consumer (the `route` layout's endpoint borrows,
   *  box-model §5 rev.) references this plot's box edges, so its `box:` fork must be emitted even
   *  when no expansion loop is live — set at bind time (desugarRouteInputs), read by the plot
   *  compiler's box gate. */
  needsBox?: true;
  channels: Record<string, Expr>;
  /** Data-space columns computed on the plot's BASE relation (before the augment chain), so both a
   *  scale's TRAIN (which reads the base) and its APPLY see them. This is how a scale over a derived
   *  quantity — `x(col("a") + col("b"))` — is realized: the arithmetic is a base projection, and the
   *  scale binds the minted column like any other. Materialized once, ahead of `pipelineBase`. */
  baseProjections?: Record<string, Expr>;
  params: PlotParams;
  nest?: NestJoinSpec;
  /** The FRAME ASSIGNMENT (owner semantics — perCell explainer §7d): the row's panel is its
   *  referent's dvl_cell, reached over `on`. `plot` is the referent when authored from a via
   *  handle; a bare predicate leaves it for resolveSpec to find. Same raw+stamped shape as nest. */
  frame?: { plot?: PlotId; on: Path; resolved?: ResolvedPath };
  /** σ extension mode for a nested layer over a multi-path relation (§7d). Default 'panel'. */
  scope?: "panel" | "union";
  /** Resolve-once product (never authored): the derived partition paths of a nested layer whose
   *  source reaches the host through the FK catalog (σ — one entry per distinct path). */
  sigma?: { paths: ResolvedPath[]; mode: "panel" | "union" };
  /** Compile product (σ conjoin only): the relation of rows the partition DROPPED — the
   *  sigma-verify diagnostics twin's output (violations are data, never silent). */
  sigmaDropped?: CellRef;
}

/** A plot's symbolic box edges under its RESOLVED anchor (the literal binding or the descriptor
 *  default) — the one shared computation behind the `box:` fork emission (box-model §4) and the
 *  `route` layout's endpoint borrows (§5 rev.). `desc` defaults to the resolve-once descriptor;
 *  pre-resolve callers (bind-time desugars) pass the registry descriptor explicitly. Data-driven
 *  anchors are a LOUD error, not silent wrong geometry. */
export function boxEdgesOf(plot: Plot, desc: MarkDescriptor | undefined = plot.resolvedMark): ExtentEdges | undefined {
  if (desc?.extentOf === undefined) return undefined;
  const aExpr = plot.channels["anchor"];
  if (aExpr !== undefined && aExpr.kind !== "literal") throw new Error(`compilePlot: plot "${plot.id}" binds a data-driven anchor — the box model needs a literal anchor (per-row anchors are not supported yet)`);
  const anchor = (aExpr !== undefined && aExpr.kind === "literal" ? String(aExpr.value) : desc.anchorDefault ?? "center") as MarkAnchor;
  // text's vertical alignment literal (box-text explainer): same literal-only rule as anchor.
  const bExpr = plot.channels["baseline"];
  if (bExpr !== undefined && bExpr.kind !== "literal") throw new Error(`compilePlot: plot "${plot.id}" binds a data-driven baseline — the box model needs a literal baseline (per-row baselines are not supported yet)`);
  const baseline = bExpr !== undefined && bExpr.kind === "literal" ? String(bExpr.value) : undefined;
  return desc.extentOf({ bound: new Set(Object.keys(plot.channels)), anchor, baseline });
}
