// Domain union operators + nice functions — bound DIRECTLY onto DomainDescriptors at component
// definition (resolve-once); the old domainUnions/domainNice registries are gone (never read).
// Each provides dual JS/SQL implementations (same substrate-choice pattern as train/apply).
import type { Row, Schema } from "../../data/schema.js";
import type { DomainNice, DomainUnion, Registries } from "../../operator/registry.js";
type Rel = { rows: readonly Row[]; schema: Schema };

// ── Union operators ──────────────────────────────────────────────────────────

/** Envelope union: min of mins, max of maxes. For continuous domains (1-row {lo, hi}). */
export const envelope: DomainUnion = {
  name: "envelope",
  js: (members: Rel[]): { rows: Row[]; schema: Schema } => {
    const lo = Math.min(...members.map((m) => Number(m.rows[0]?.lo ?? Infinity)));
    const hi = Math.max(...members.map((m) => Number(m.rows[0]?.hi ?? -Infinity)));
    return { rows: [{ lo, hi }], schema: [{ name: "lo", type: "double" }, { name: "hi", type: "double" }] };
  },
  // ponytail: SQL impl deferred — the current gather-scatter runs JS-only (materialize + union).
  // When the optimizer pushes gather-scatter into SQL, add:
  // sql: (members) => mkFrag(..., "SELECT MIN(lo) AS lo, MAX(hi) AS hi FROM (...UNION ALL...)", ...)
};

/** Set union: dedup by value, re-rank. For discrete domains (N-row indexed {value, idx, n}). */
export const setUnion: DomainUnion = {
  name: "set-union",
  js: (members: Rel[]): { rows: Row[]; schema: Schema } => {
    const indexed = members.some((m) => m.rows[0] !== undefined && "idx" in (m.rows[0] as Record<string, unknown>));
    const seen = new Set<string>();
    const key = (r: Record<string, unknown>): string => (indexed ? JSON.stringify(r.value ?? r.category) : JSON.stringify(r));
    let rows = members.flatMap((m) => [...m.rows]).filter((r) => { const k = key(r as Record<string, unknown>); if (seen.has(k)) return false; seen.add(k); return true; });
    if (indexed) {
      const val = (r: Record<string, unknown>): string => String(r.value ?? r.category);
      rows = [...rows].sort((a, b) => (val(a as Record<string, unknown>) < val(b as Record<string, unknown>) ? -1 : 1)).map((r, i, all) => ({ ...(r as Record<string, unknown>), idx: i, n: all.length }));
    }
    return { rows, schema: members[0]?.schema ?? [] };
  },
};

/** Quantile union: merge sorted value arrays, dedup, re-sort. For quantile domains (N-row {value}). */
export const quantileUnion: DomainUnion = {
  name: "quantile-union",
  js: (members: Rel[]): { rows: Row[]; schema: Schema } => {
    const seen = new Set<number>();
    const values: number[] = [];
    for (const m of members) {
      for (const r of m.rows) {
        const v = Number((r as Record<string, unknown>).value);
        if (!seen.has(v)) { seen.add(v); values.push(v); }
      }
    }
    values.sort((a, b) => a - b);
    return { rows: values.map((v) => ({ value: v })), schema: [{ name: "value", type: "double" }] };
  },
};

// ── Nice functions ───────────────────────────────────────────────────────────

/** Nice-linear: extend lo/hi to clean step boundaries (same logic as nice-linear tick algo). */
export const niceLinear: DomainNice = {
  name: "nice-linear",
  js: (domain: Rel): { rows: Row[]; schema: Schema } => {
    const lo = Number(domain.rows[0]?.lo ?? 0);
    const hi = Number(domain.rows[0]?.hi ?? 0);
    if (lo === hi) return { rows: [{ lo: lo - 1, hi: hi + 1 }], schema: domain.schema };
    const span = hi - lo;
    const step = Math.pow(10, Math.floor(Math.log10(span))) / 2;
    const nlo = Math.floor(lo / step) * step;
    const nhi = Math.ceil(hi / step) * step;
    return { rows: [{ lo: nlo, hi: nhi }], schema: domain.schema };
  },
};

// ── Registration ─────────────────────────────────────────────────────────────

// resolved refs self-describe (§12 Phase 5a): an embedded union serializes as {$union: name}.
import { selfDescribe } from "../../operator/operator.js";
for (const u of [envelope, setUnion, quantileUnion]) selfDescribe(u, "$union", u.name);
