// Axis-merge: among aligned siblings, keep the outermost axis, suppress the rest.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";

export function axisMerge(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload;
  if (p.kind !== "axis-merge") return;
  const K = op.writes.length;
  const at = (i: number, j: number): number => Number(store.read(op.reads[i * 3 + j]));
  const EPS = 0.5;
  let aligned = true;
  for (let i = 1; i < K; i++) aligned = aligned && Math.abs(at(i, 0) - at(0, 0)) < EPS && Math.abs(at(i, 1) - at(0, 1)) < EPS;
  const outermost = p.side === "left" || p.side === "top" ? (a: number, b: number): boolean => a < b : (a: number, b: number): boolean => a > b;
  let keep = 0;
  if (aligned) for (let i = 1; i < K; i++) if (outermost(at(i, 2), at(keep, 2))) keep = i;
  for (let i = 0; i < K; i++) store.write(op.writes[i], !aligned || i === keep ? 1 : 0, "assigned");
}
