// Table — the uniform interface over a backing; resolves to a base relation OR a query
// object (WUDATA §2, WUDATA_IMPL §4). A Table also carries the BRANCH it lives on and its
// logical IDENTITY (the name an author uses); `asRelationRef` resolves that identity through
// the branch (design/2026-07-16-demo-core-tables.html §8).
//
// KEY MODEL: a data-modeling step (copy/normalize/…) does NOT persist a backend view. It
// records a QUERY OBJECT — a SqlFragment (a CTE) whose inputs point at its dependencies —
// so the path from a modeled table back to the base tables folds into ONE query at execution
// (fold recurses fragment inputs; base leaves are the only names that hit the backend). Views
// are created only for OTHER reasons (materialize a hot loop; surface SQL in the Data tab),
// not to make modeling work. This is why branch modeling needs no view lifecycle to be correct.

import type { RelationName } from "./ids.js";
import type { Columnar } from "./backend.js";
import type { JsonRow, Schema, SqlType } from "./schema.js";
import type { RelationRef, SqlFragment } from "./fragment.js";

// ── aggregate vocabulary (for groupby/rollup) ─────────────────────────────────
/** An aggregate argument: a bare column name (quoted) or a raw SQL expression. */
export type AggArg = string | { readonly sql: string };
/** An aggregate: `count()`, `sum(col)`, `avg({sql:'qty*price'})`, … */
export interface Agg {
  readonly fn: "count" | "sum" | "avg" | "min" | "max" | "median";
  readonly arg?: AggArg;
}
export const count = (): Agg => ({ fn: "count" });
export const sum = (arg: AggArg): Agg => ({ fn: "sum", arg });
export const avg = (arg: AggArg): Agg => ({ fn: "avg", arg });
export const min = (arg: AggArg): Agg => ({ fn: "min", arg });
export const max = (arg: AggArg): Agg => ({ fn: "max", arg });
export const median = (arg: AggArg): Agg => ({ fn: "median", arg });

export type Backing =
  | { readonly kind: "db-table" | "view"; readonly relation: RelationName }
  | { readonly kind: "query"; readonly relation: RelationName; readonly sql: string }
  | { readonly kind: "js-rows"; readonly relation: RelationName; readonly rows: readonly JsonRow[] }
  | { readonly kind: "js-columnar"; readonly relation: RelationName; readonly cols: Columnar }
  | { readonly kind: "derived"; readonly producer: () => SqlFragment };

/** The subset of Branch a Table needs — resolving its identity to a relation ref, recording a
 *  modeling step, and declaring FKs. (Structural, to avoid a Table→Database import cycle.) */
export interface TableHost {
  /** Resolve a logical name to the relation it denotes on this branch: a modeling fragment the
   *  branch recorded, or (falling through to parents) a base relation name. */
  resolveRef(identity: string): RelationRef;
  /** The CURRENT schema of a logical name on this branch (a modeling step may have rewritten it
   *  after a Table object was handed out — so schema is resolved live, not captured). */
  schemaOfIdentity(identity: string): Promise<Schema>;
  /** Record a modeling fragment under `identity` on this branch, returning the bound Table.
   *  `build(input)` gets the resolved ref of the CURRENT identity (its prior definition) and
   *  returns the new fragment + its output schema description. */
  recordModel(identity: string, frag: SqlFragment, opts?: { key?: readonly string[] }): Table;
  /** A branch-unique fresh identity for `base` (base, base2, …). */
  freshName(base: string): string;
  /** The (best-effort, synchronous) column schema a relation ref denotes — for operators that
   *  need to type their output columns (e.g. groupby keys). Base tables must be schema-loaded
   *  (they are, after fromRows/register); returns [] if unknown. */
  columnsOf(ref: RelationRef): Schema;
  /** Declare an FK on this branch (normalize auto-declares its FK). */
  declareFK(edge: { fromTable: string; fromCols: readonly string[]; toTable: string; toCols: readonly string[] }): void;
}

let fragSeq = 0; // fragment-id counter (unique per modeling step; not random — reproducible).

export class Table {
  readonly name: string;
  readonly backing: Backing;
  primaryKey?: readonly string[];
  private readonly resolveSchema: () => Promise<Schema>;
  /** The branch this Table lives on (undefined for a bare Table not bound to a branch). */
  readonly host?: TableHost;

  constructor(name: string, backing: Backing, resolveSchema: () => Promise<Schema>, host?: TableHost) {
    this.name = name;
    this.backing = backing;
    this.resolveSchema = resolveSchema;
    this.host = host;
  }

  /** The relation's column schema (cached by the Database). */
  schema(): Promise<Schema> {
    return this.resolveSchema();
  }

  /** Resolve to a fold leaf (base relation) or a fragment (derived / branch-modeled backing).
   *  A branch-bound Table resolves its logical name through the branch — a modeled `penguins`
   *  yields the recorded fragment transparently (no spec rewrite; §8d/§8e). */
  asRelationRef(): RelationRef {
    if (this.backing.kind === "derived") return { fragment: this.backing.producer() };
    if (this.host !== undefined) return this.host.resolveRef(this.name);
    return { base: this.backing.relation };
  }

  // ── modeling operators (branch-scoped, query objects, metadata-only) — §7, §8c ──

  /** A working copy: a fresh identity you can reshape in place without shadowing the original.
   *  A pass-through fragment over the source; folds away to nothing at execution. */
  copy(name?: string): Table {
    const host = this.requireHost("copy");
    const id = name ?? host.freshName(`${this.name}_copy`);
    const src = host.resolveRef(this.name);
    const frag = passFragment(`copy_${id}_${fragSeq++}`, src);
    return host.recordModel(id, frag);
  }

  /** Decompose `col` into its own keyed dimension relation and rewrite THIS table to carry
   *  `<col>_id` (an FK to the dimension). Returns the dimension Table; records a new fragment for
   *  this Table's identity so references see the FK column (§7). `opts.bin` buckets a continuous
   *  column into `bin` equal-width buckets before distinct-ing. */
  normalize(col: string, opts?: { bin?: number }): Table {
    const host = this.requireHost("normalize");
    const src = host.resolveRef(this.name);
    const dimId = host.freshName(col);

    // the dimension: distinct (or binned) values with a dense, deterministic surrogate key.
    const valueExpr = opts?.bin
      ? `width_bucket(m.${qi(col)}, (SELECT min(${qi(col)}) FROM @src), (SELECT max(${qi(col)}) FROM @src), ${opts.bin})`
      : `m.${qi(col)}`;
    const dimFrag: SqlFragment = {
      id: `norm_dim_${dimId}_${fragSeq++}`,
      op: `norm_dim_${sanitize(dimId)}`,
      ctes: [{
        name: "d",
        body: `SELECT (row_number() OVER (ORDER BY v) - 1) AS id, v AS ${qi(col)} ` +
          `FROM (SELECT DISTINCT ${valueExpr} AS v FROM @src AS m)`,
      }],
      result: "d",
      inputs: { src },
      outputs: { columns: [{ name: "id", type: "int" }, { name: col, type: "unknown" }] },
      cells: [],
    };
    const dim = host.recordModel(dimId, dimFrag, { key: ["id"] });

    // rewrite THIS table's fragment: same rows + the FK column joining to the dimension.
    const fkCol = `${col}_id`;
    const mainFrag: SqlFragment = {
      id: `norm_main_${this.name}_${fragSeq++}`,
      op: `norm_main_${sanitize(this.name)}`,
      ctes: [{
        name: "r",
        body: `SELECT m.*, d.id AS ${qi(fkCol)} FROM @src AS m JOIN @dim AS d USING (${qi(col)})`,
      }],
      result: "r",
      inputs: { src, dim: dim.asRelationRef() },
      outputs: { passthrough: "src", add: [{ name: fkCol, type: "int" }] },
      cells: [],
    };
    host.recordModel(this.name, mainFrag);

    // declare the FK so via(fk(col)) / nest(on: fk(col)) traverse it with no extra wiring.
    host.declareFK({ fromTable: this.name, fromCols: [fkCol], toTable: dimId, toCols: ["id"] });
    return dim;
  }

  /** Aggregate to one row per distinct combination of `keys`, computing each named aggregate.
   *  The output is the key columns + one column per agg (`groupby(['species'], {n: count()})`). */
  groupby(keys: readonly string[], aggs: Record<string, Agg>, name?: string): Table {
    const host = this.requireHost("groupby");
    const src = host.resolveRef(this.name);
    const id = name ?? host.freshName(`${this.name}_by_${keys.join("_") || "all"}`);
    const keySel = keys.map((k) => `m.${qi(k)}`);
    const aggSel = Object.entries(aggs).map(([out, a]) => `${aggSql(a)} AS ${qi(out)}`);
    const groupBy = keys.length > 0 ? ` GROUP BY ${keys.map((k) => `m.${qi(k)}`).join(", ")}` : "";
    // type the key columns from the source schema (so scales over them get a real type, not
    // "unknown" — which breaks literal emission downstream); aggs get their result type.
    const srcCols = new Map(host.columnsOf(src).map((c) => [c.name, c.type]));
    const cols: Schema = [
      ...keys.map((k) => ({ name: k, type: srcCols.get(k) ?? ("unknown" as SqlType) })),
      ...Object.entries(aggs).map(([out, a]) => ({ name: out, type: aggType(a) })),
    ];
    const frag: SqlFragment = {
      id: `groupby_${id}_${fragSeq++}`,
      op: `groupby_${sanitize(id)}`,
      ctes: [{ name: "r", body: `SELECT ${[...keySel, ...aggSel].join(", ")} FROM @src AS m${groupBy}` }],
      result: "r",
      inputs: { src },
      outputs: { columns: cols },
      cells: [],
    };
    return host.recordModel(id, frag, { key: keys.length > 0 ? keys : undefined });
  }

  /** Add a dense `rank` column (1-based) per `partition`, ordered by `order` (a column, or
   *  `{col, desc}`). No partition = one global ranking. Keeps all rows + the rank column. */
  rank(order: RankOrder, opts?: { partition?: readonly string[]; as?: string; name?: string }): Table {
    const host = this.requireHost("rank");
    const src = host.resolveRef(this.name);
    const id = opts?.name ?? host.freshName(`${this.name}_ranked`);
    const rankCol = opts?.as ?? "rank";
    const over = windowOver(opts?.partition, order);
    const frag: SqlFragment = {
      id: `rank_${id}_${fragSeq++}`,
      op: `rank_${sanitize(id)}`,
      ctes: [{ name: "r", body: `SELECT m.*, rank() OVER (${over}) AS ${qi(rankCol)} FROM @src AS m` }],
      result: "r",
      inputs: { src },
      outputs: { passthrough: "src", add: [{ name: rankCol, type: "int" }] },
      cells: [],
    };
    return host.recordModel(id, frag, { key: this.primaryKey });
  }

  /** The top-`n` rows per `partition` by `order` (a rank-then-filter). Fewer rows out. */
  top(n: number, order: RankOrder, opts?: { partition?: readonly string[]; name?: string }): Table {
    const host = this.requireHost("top");
    const src = host.resolveRef(this.name);
    const id = opts?.name ?? host.freshName(`${this.name}_top${n}`);
    const over = windowOver(opts?.partition, order);
    const frag: SqlFragment = {
      id: `top_${id}_${fragSeq++}`,
      op: `top_${sanitize(id)}`,
      // row_number (not rank) so exactly n survive per group even with ties.
      ctes: [{ name: "r", body: `SELECT * EXCLUDE (dvl_rn) FROM (SELECT m.*, row_number() OVER (${over}) AS dvl_rn FROM @src AS m) WHERE dvl_rn <= ${Math.floor(n)}` }],
      result: "r",
      inputs: { src },
      outputs: { passthrough: "src", add: [] },
      cells: [],
    };
    return host.recordModel(id, frag, { key: this.primaryKey });
  }

  /** Inner-join another table on `on` (a column present in both, or `{left, right}`), keeping
   *  this table's columns plus the other's non-key columns. FK traversal for modeling (contrast
   *  via(), which borrows PLACED marks post-solve — this joins DATA pre-render). */
  join(other: Table, on: string | { left: string; right: string }, name?: string): Table {
    const host = this.requireHost("join");
    const src = host.resolveRef(this.name);
    const oref = other.host !== undefined ? other.host.resolveRef(other.name) : other.asRelationRef();
    const id = name ?? host.freshName(`${this.name}_x_${other.name}`);
    const cond = typeof on === "string"
      ? `USING (${qi(on)})`
      : `ON m.${qi(on.left)} = o.${qi(on.right)}`;
    // SELECT m.*, o.* EXCLUDE the join column (USING already coalesces it) — DuckDB's o.* keeps
    // the other side's columns; a name clash on non-key columns is a user error (documented).
    const oProj = typeof on === "string" ? `o.* EXCLUDE (${qi(on)})` : "o.*";
    const frag: SqlFragment = {
      id: `join_${id}_${fragSeq++}`,
      op: `join_${sanitize(id)}`,
      ctes: [{ name: "r", body: `SELECT m.*, ${oProj} FROM @src AS m JOIN @other AS o ${cond}` }],
      result: "r",
      inputs: { src, other: oref },
      // columns can't be composed statically without both schemas; declare passthrough of THIS
      // side + a best-effort of the other's (resolved live by the branch at recordModel).
      outputs: { passthrough: "src", add: [] },
      cells: [],
      // dep: the join reads the other table's columns via o.* — no static add; schema is refreshed
      // from the backend on first ensureSchema (the branch composes passthrough, then introspection
      // corrects it if the view is materialized). For render, the marktable projects by name so the
      // borrowed columns must exist — they do, at the SQL level.
    };
    return host.recordModel(id, frag);
  }

  /** Roll a measure up across a join then aggregate to `key` — `t.join(other,on).groupby([key],aggs)`
   *  in one call, the common "denormalize then summarize" step. */
  rollup(other: Table, on: string | { left: string; right: string }, key: string, aggs: Record<string, Agg>, name?: string): Table {
    return this.join(other, on).groupby([key], aggs, name);
  }

  /** Stack the wide columns `cols` into long (name, value) rows — Observable Plot / SQL UNPIVOT.
   *  Each input row becomes `cols.length` rows. `into`/`value` name the two new columns. */
  unpivot(cols: readonly string[], opts?: { into?: string; value?: string; name?: string }): Table {
    const host = this.requireHost("unpivot");
    const src = host.resolveRef(this.name);
    const id = opts?.name ?? host.freshName(`${this.name}_long`);
    const into = opts?.into ?? "key";
    const value = opts?.value ?? "value";
    const frag: SqlFragment = {
      id: `unpivot_${id}_${fragSeq++}`,
      op: `unpivot_${sanitize(id)}`,
      ctes: [{ name: "r", body: `UNPIVOT @src ON ${cols.map(qi).join(", ")} INTO NAME ${qi(into)} VALUE ${qi(value)}` }],
      result: "r",
      inputs: { src },
      // the non-unpivoted columns pass through + the two new ones; the exact passthrough set needs
      // the source schema, so declare add-only and let introspection fill the rest.
      outputs: { passthrough: "src", add: [{ name: into, type: "varchar" }, { name: value, type: "unknown" }] },
      cells: [],
    };
    return host.recordModel(id, frag, { key: [into] });
  }

  /** Add a stable 1-based surrogate key column — the tuple identity parallel-coords / links need
   *  (a via joins on it). Deterministic order so the key is reproducible. */
  withKey(as = "id", name?: string): Table {
    const host = this.requireHost("withKey");
    const src = host.resolveRef(this.name);
    const id = name ?? host.freshName(this.name);
    const frag: SqlFragment = {
      id: `withkey_${id}_${fragSeq++}`,
      op: `withkey_${sanitize(id)}`,
      ctes: [{ name: "r", body: `SELECT (row_number() OVER ()) AS ${qi(as)}, m.* FROM @src AS m` }],
      result: "r",
      inputs: { src },
      outputs: { passthrough: "src", add: [{ name: as, type: "int" }] },
      cells: [],
    };
    const t = host.recordModel(id, frag, { key: [as] });
    return t;
  }

  /** Keep only rows matching `predicate` — a raw SQL boolean over the row (columns are bare
   *  names, e.g. `"species <> 'Gentoo'"`). Same columns out, fewer rows. */
  filter(predicate: string, name?: string): Table {
    const host = this.requireHost("filter");
    const src = host.resolveRef(this.name);
    const id = name ?? host.freshName(`${this.name}_filtered`);
    const frag: SqlFragment = {
      id: `filter_${id}_${fragSeq++}`,
      op: `filter_${sanitize(id)}`,
      ctes: [{ name: "r", body: `SELECT * FROM @src WHERE (${predicate})` }],
      result: "r",
      inputs: { src },
      outputs: { passthrough: "src", add: [] },
      cells: [],
    };
    return host.recordModel(id, frag, { key: this.primaryKey });
  }

  private requireHost(op: string): TableHost {
    if (this.host === undefined) throw new Error(`Table.${op}: this table is not bound to a branch (create it via db.table/fromRows/…)`);
    return this.host;
  }
}

/** Order spec for rank/top: a column name (ascending), or `{col, desc}`. */
export type RankOrder = string | { col: string; desc?: boolean };

function windowOver(partition: readonly string[] | undefined, order: RankOrder): string {
  const part = partition && partition.length > 0 ? `PARTITION BY ${partition.map(qi).join(", ")} ` : "";
  const o = typeof order === "string" ? { col: order } : order;
  return `${part}ORDER BY ${qi(o.col)}${o.desc ? " DESC" : ""}`;
}

function aggSql(a: Agg): string {
  if (a.fn === "count") return "count(*)";
  const arg = a.arg === undefined ? "*" : typeof a.arg === "string" ? `m.${qi(a.arg)}` : a.arg.sql;
  return `${a.fn}(${arg})`;
}

function aggType(a: Agg): SqlType {
  if (a.fn === "count") return "int";
  return "double"; // sum/avg/min/max/median — double is the safe umbrella for the demo
}

/** A pass-through fragment: `SELECT * FROM @src`, passthrough schema. Folds away (its CTE just
 *  aliases the input), so `copy` costs nothing at execution — it exists for identity, not data. */
function passFragment(id: string, src: RelationRef): SqlFragment {
  return {
    id,
    op: sanitize(id),
    ctes: [{ name: "r", body: `SELECT * FROM @src` }],
    result: "r",
    inputs: { src },
    outputs: { passthrough: "src", add: [] },
    cells: [],
  };
}

/** Quote an identifier for the modeling SQL. */
function qi(name: string): string {
  return `"${name.replace(/"/g, '""')}"`;
}

/** A valid SQL-identifier prefix for fold's CTE uniquification (mirrors relation.ts sanitizeOp). */
function sanitize(s: string): string {
  return s.replace(/[^A-Za-z0-9_]/g, "_");
}
