// dispatch: the ONE executor entry for any Impl (ex dataflow/exec.ts part 2).
// Runs one impl over cell-store relations — prepares inputs per substrate (materialize for JS,
// VALUES-serialize for SQL) and iterates per group when the edge is keyed but the impl is not
// (§C8's correlated definition). Substrate choice is transitional (chooseImpl) until the
// optimizer's static pick.
import type { SqlFragment } from "../data/fragment.js";
import type { Scalar } from "../data/schema.js";
import { sqlLiteral } from "../data/dialect.js";
import type { Exec, ExecCtx, Impl, OpBinding, SqlImpl } from "../algebra/impl.js";
import { jsRel, materialize, mkFrag, sanitizeOp, sqlRel, valuesFrag, type JsRel, type Relation } from "../algebra/relation.js";

// ── dispatch: the ONE executor entry for any Impl ────────────────────────────

/** TRANSITIONAL runtime substrate choice — stay in the data's substrate if the exec supports it,
 *  else take what exists. Phase 4 replaces this with the optimizer's static pick. */
export function chooseImpl(exec: Exec, dataAt: "sql" | "js"): Impl {
  if (dataAt === "sql" && exec.sql) return exec.sql;
  if (dataAt === "js" && exec.js) return exec.js;
  const impl = exec.sql ?? exec.js;
  if (impl === undefined) throw new Error("exec provides neither a SQL nor a JS implementation");
  return impl;
}

/** Run one impl over cell-store relations. Prepares inputs per `impl.substrate` (materialize for
 *  JS, VALUES-serialize for SQL — the run-time crossings, planned statically in Phase 4) and
 *  iterates per group when the edge is keyed but the impl is not (§C8's correlated definition). */
export async function dispatch(impl: Impl, inputs: readonly Relation[], b: OpBinding, ctx: ExecCtx): Promise<Relation> {
  // Iteration is SUBSTRATE-PRESERVING (§12 Phase 4b P3): a keyed edge over a non-keyed impl runs
  // the correlated definition in the impl's OWN substrate — SQL data never leaves the database
  // just because the impl doesn't claim the key.
  if (ctx.key !== undefined && impl.keyed !== true) {
    return impl.substrate === "sql" ? iteratePerGroupSql(impl, inputs, b, ctx) : iteratePerGroup(impl, inputs, b, ctx);
  }
  if (impl.substrate === "sql") {
    const prepared = inputs.map((r, i) => (r.substrate === "sql" ? r.frag : valuesFrag(`${b.key}:in${i}`, r.rows, r.schema)));
    return sqlRel(scopeFragments(impl(prepared, b, ctx), b.key, new Set(prepared)));
  }
  const prepared = await Promise.all(inputs.map((r) => materialize(r, ctx.run)));
  const out = await impl(prepared, b, ctx);
  return jsRel(out.rows, out.schema);
}

/** FRAMEWORK-owned fragment scoping (§12 Phase 5e, identity-ladder Level 3): walk the impl's
 *  returned tree down to the input fragments the framework handed in (OBJECT identity — those are
 *  not ours to rename) and prefix every NEW node's id with the invocation scope. A third-party
 *  impl can then use LOCAL names (mkFrag("fit")) and is collision-proof by construction —
 *  cross-component id collisions become unwritable; iteration's seed-varying is automatic (each
 *  group's scope differs). Every impl-side id is LOCAL
 *  (lower.ts names "fit"/"apply"); the scope prefix is unconditional. */
function scopeFragments(f: SqlFragment, scope: string, stop: ReadonlySet<SqlFragment>): SqlFragment {
  const memo = new Map<SqlFragment, SqlFragment>();
  const walk = (n: SqlFragment): SqlFragment => {
    if (stop.has(n)) return n; // a framework-supplied input — its identity is its own
    const hit = memo.get(n);
    if (hit !== undefined) return hit;
    const inputs: Record<string, (typeof n.inputs)[string]> = {};
    for (const [k, ref] of Object.entries(n.inputs)) inputs[k] = "base" in ref ? ref : { fragment: walk(ref.fragment) };
    const scoped: SqlFragment = { ...n, id: `${scope}/${n.id}`, op: sanitizeOp(`${scope}/${n.id}`), inputs };
    memo.set(n, scoped);
    return scoped;
  };
  return walk(f);
}

/** §C8 keyed execution, the DEFINITION (the correlated form): partition every KEYED input by the
 *  key (ctx.keyedInputs — per-edge, groups driven by inputs[0]), invoke the scalar impl once per
 *  group — the impl never learns keys exist — tag each result row with its key, union all.
 *  Keyed impls are optimizations that must agree with this. Unflagged inputs pass whole (global
 *  aux relations); a keyed input with no rows for a group filters to empty — the correct scalar
 *  view. Key values compare NORMALIZED (String) across inputs: different relations materialize
 *  the same key with different carriers (DuckDB BigInt vs Number). */
function iterFlags(inputs: readonly unknown[], b: OpBinding, ctx: ExecCtx): readonly boolean[] {
  const flags = ctx.keyedInputs ?? (inputs.length === 1 ? [true] : undefined);
  if (flags === undefined) throw new Error(`${b.key}: iterating a multi-input op over key "${ctx.key}" needs per-edge keyedness (payload.keyedReads) — refusing to guess which inputs partition`);
  if (flags[0] !== true) throw new Error(`${b.key}: iterate-per-group is driven by inputs[0]'s key values — inputs[0] must be keyed`);
  return flags;
}

async function iteratePerGroup(impl: Impl, inputs: readonly Relation[], b: OpBinding, ctx: ExecCtx): Promise<Relation> {
  const by = ctx.key!;
  const flags = iterFlags(inputs, b, ctx);
  const norm = (v: unknown): string => String(v ?? "");
  const mats = await Promise.all(inputs.map((r, i) => (flags[i] === true ? materialize(r, ctx.run) : Promise.resolve(undefined))));
  const m = mats[0]!;
  const groups = new Map<string, { key: unknown; rows: Record<string, unknown>[] }>();
  for (const r of m.rows) {
    const k = norm(r[by]);
    const g = groups.get(k);
    if (g === undefined) groups.set(k, { key: r[by], rows: [r] });
    else g.rows.push(r);
  }
  const keys = [...groups.keys()].sort();
  const rows: Record<string, unknown>[] = [];
  let schema: JsRel["schema"] = [];
  for (const k of keys) {
    const g = groups.get(k)!;
    const groupInputs = inputs.map((rel, i): Relation => {
      if (flags[i] !== true) return rel; // global edge — the whole relation, every group
      if (i === 0) return jsRel(g.rows as JsRel["rows"], m.schema);
      const mi = mats[i]!;
      return jsRel(mi.rows.filter((r) => norm(r[by]) === k) as JsRel["rows"], mi.schema);
    });
    const out = await dispatch(impl, groupInputs, b, { run: ctx.run }); // the scalar call — no key
    const outJs = await materialize(out, ctx.run);
    schema = outJs.schema;
    for (const fr of outJs.rows) rows.push({ [by]: g.key, ...fr });
  }
  return jsRel(rows as JsRel["rows"], [{ name: by, type: "int" }, ...schema.filter((c) => c.name !== by)]);
}

/** The SQL flavor of the definition (§12 Phase 4b P3): ONE small query fetches the distinct key
 *  values (only the key column crosses the boundary), then per key the impl composes over
 *  key-filtered fragments — seed-varied binding (`${b.key}:g${i}`), so every id the impl derives
 *  reflects the group (the fragment-identity principle; fold's dedup then shares only the
 *  underlying unfiltered inputs) — and the group fragments UNION ALL into one relation. Data
 *  stays in the database; wall-clock is one keys roundtrip + one composed query. */
async function iteratePerGroupSql(impl: SqlImpl, inputs: readonly Relation[], b: OpBinding, ctx: ExecCtx): Promise<Relation> {
  const by = ctx.key!;
  const flags = iterFlags(inputs, b, ctx);
  const frags = inputs.map((r, i) => (r.substrate === "sql" ? r.frag : valuesFrag(`${b.key}:in${i}`, r.rows, r.schema)));
  // the distinct keys — the ONLY materialization; sorted for deterministic group order.
  const keyRows = await ctx.run(mkFrag(`${b.key}:keys`, `SELECT DISTINCT m."${by}" AS k FROM @m AS m`, { m: { fragment: frags[0] } }, { columns: [{ name: "k", type: "unknown" }] }));
  const keys = keyRows.map((r) => (typeof r.k === "bigint" ? Number(r.k) : (r.k as Scalar))).sort((a, z) => (String(a ?? "") < String(z ?? "") ? -1 : String(a ?? "") > String(z ?? "") ? 1 : 0));
  if (keys.length === 0) return sqlRel(mkFrag(`${b.key}:iter`, `SELECT NULL AS "${by}" WHERE 1 = 0`, {}, { columns: [{ name: by, type: "int" }] }));
  const parts = keys.map((k, i) => {
    const gb: OpBinding = { ...b, key: `${b.key}:g${i}` }; // seed-varied: every derived id names its group
    const groupInputs = frags.map((f, j) =>
      flags[j] === true
        ? mkFrag(`${gb.key}:flt${j}`, `SELECT * FROM @src WHERE "${by}" = ${sqlLiteral(k)}`, { src: { fragment: f } }, { passthrough: "src", add: [] })
        : f); // global edge — the whole relation, every group
    return { k, out: scopeFragments(impl(groupInputs, gb, { run: ctx.run }), gb.key, new Set(groupInputs)) }; // the scalar call — no key
  });
  // Tag with the key iff the impl's output doesn't already carry it (an apply passes marks
  // through — key present; a train reduces to fresh columns — key absent). Resolved structurally
  // from the declared outputs chain; an undecidable chain is a loud error, not a guess.
  const carries = fragHasColumn(parts[0].out, by);
  if (carries === undefined) throw new Error(`${b.key}: cannot tell whether the iterated output carries "${by}" — declare the impl's outputs as {columns} (or passthrough a fragment that does)`);
  const inputsMap: Record<string, { fragment: SqlFragment }> = {};
  const selects = parts.map((pt, i) => {
    inputsMap[`g${i}`] = { fragment: pt.out };
    return carries ? `SELECT * FROM @g${i}` : `SELECT g.*, ${sqlLiteral(pt.k)} AS "${by}" FROM @g${i} AS g`;
  });
  const outputs = carries ? ({ passthrough: "g0", add: [] } as const) : ({ passthrough: "g0", add: [{ name: by, type: "int" as const }] } as const);
  return sqlRel(mkFrag(`${b.key}:iter`, selects.join(" UNION ALL "), inputsMap, outputs));
}

/** Whether a fragment's declared output carries a column — resolved through passthrough chains.
 *  undefined = the chain roots in a base table before deciding (callers fail loudly). */
function fragHasColumn(f: SqlFragment, name: string): boolean | undefined {
  const o = f.outputs;
  if ("columns" in o) return o.columns.some((c) => c.name === name);
  if (o.add !== undefined && o.add.some((c) => c.name === name)) return true;
  const src = f.inputs[o.passthrough];
  if (src === undefined) return undefined;
  return "fragment" in src ? fragHasColumn(src.fragment, name) : undefined;
}

