// marktable op: build a plot's base mark-row relation.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { markTable } from "../../../plan/compile/marktable.js";
import { sqlRel } from "../../../algebra/relation.js";
export function marktableOp(op: OpSpec, store: CellStore, ctx: RunCtx): void {
  const p = op.payload as { kind: string; plotId: string; requiredColumns?: readonly string[] };
  if (p.kind !== "marktable") return;
  store.write(op.writes[0], sqlRel(markTable(ctx.spec.plots.get(p.plotId)!, ctx.spec, p.requiredColumns)), "assigned");
}
