// barY (value → vertical bar, y-axis): a value → a vertical bar from the baseline (range.lo = the bottom edge) up to
// the value. Outputs y (the bar top) + h (its height down to the baseline) — multi-output like eqx,
// but on the y axis over an interval; pick('y','h') binds both. Trains min/max like a linear scale
// and carries `nice-linear` ticks so the y axis is labelled. This is the abstraction-following bar:
// eqx gives {x,w}, col gives {y,h}, and one rect draws the bar.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, mcol, nullif0, unary } from "../../algebra/relop.js";
import { continuous } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const barY = op({
  name: "barY",
  // union: null preserves today's non-sharing (planDomainGroups keys on union non-null); the
  // unionFn drops with it. col's fit algebra IS linear's {lo,hi}, so an envelope-union upgrade is
  // semantically legal — but deliberately deferred until it has its own sharing test. No `nice`
  // (override nice: undefined) → the derived treatment stays "data". Ticks keep nice-linear.
  //
  // { zero: true } anchors the domain at the baseline: lo = least(min, 0), hi = greatest(max, 0)
  // — otherwise the min-value bar has height 0 (the domain is the data extent). least/greatest
  // live inside the aggregate as (v ∓ |v|)/2, so the fit stays one reduce and the ticks (which
  // read the same {lo,hi}) label the zero-based axis by construction.
  domain: continuous((b): RelOp => {
    const v = mcol(inputCol(b, "value"));
    const zero = b.options?.zero === true;
    return { kind: "reduce", aggs: {
      lo: zero ? { fn: "min", arg: bin("/", bin("-", v, unary("abs", v)), lit(2)) } : { fn: "min", col: inputCol(b, "value") },
      hi: zero ? { fn: "max", arg: bin("/", bin("+", v, unary("abs", v)), lit(2)) } : { fn: "max", col: inputCol(b, "value") },
    } };
  }, { union: null, unionFn: undefined, nice: undefined }),
  inputs: { marks: [{ name: "value", type: "double" }] },
  output: { passthrough: "marks", add: [{ name: "y", type: "double" }, { name: "h", type: "double" }] },
  outSpaces: { y: relativeSpace(coord("y")), h: relativeSpace(len("y")) },
  inputSpaces: { value: dataSpace },
  apply: (b): RelOp => {
    // NORMALIZED: y = relative t (bar top), h = the SAME t as a len (the baseline is t=0). The frame
    // affine maps y as a coord (offset+scale) and h as a len (scale only, |span|·t) into the y box.
    const [yo, ho] = b.outputs;
    const ratio = bin("/", bin("-", mcol(inputCol(b, "value")), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo"))));
    return { kind: "derive", add: { [yo]: ratio, [ho]: ratio }, outTypes: { [yo]: "double", [ho]: "double" } };
  },
  ticks: "nice-linear",
});
