// Tagged template for ScalarExpr trees. Turns arithmetic strings into nested op.ts ASTs.
//
// Usage:
//   expr`${lit(4)} + ${rank("x")} * ${lit(16)}`
//   expr`${mcol("value")} - ${fcol("lo")} / ${fcol("hi")} - ${fcol("lo")}`
//   expr`floor(${mcol("idx")} / ${lit(cols)})`
//   expr`f.price * f.qty`            // dotted refs: m.col ⇒ mcol, f.col ⇒ fcol (§3c resolutions)
//   expr`(f.x - m.x) * (f.x - m.x)`  // the two-sided (m, f) row, no interpolation needed
//
// Interpolated values (${...}) must be ScalarExpr nodes — they're spliced in as leaves.
// Bare dotted identifiers reference the two-sided row: `m.<col>` is the mark side (mcol),
// `f.<col>` the fit/referent side (fcol) — the same aliases the SQL lowering emits.
// Supported operators: + - * / (standard precedence). Parentheses for grouping.
// Supported unary functions: floor, ln, abs, sqrt, nullif0.
// Bare numbers in the template string become lit() automatically.
import { bin, fcol, lit, mcol, unary, nullif0, call, type ScalarExpr } from "./relop.js";
import { FUNCTIONS } from "./functions.js";

type BinOp = "+" | "-" | "*" | "/";

const PREC: Record<string, number> = { "+": 1, "-": 1, "*": 2, "/": 2 };
const UNARIES = new Set(["floor", "ln", "abs", "sqrt", "nullif0"]); // legacy dedicated ScalarExpr nodes

type Token =
  | { kind: "expr"; value: ScalarExpr }
  | { kind: "num"; value: number }
  | { kind: "op"; value: BinOp }
  | { kind: "fn"; value: string }
  | { kind: "(" }
  | { kind: ")" }
  | { kind: "," };

function tokenize(strings: TemplateStringsArray, exprs: ScalarExpr[]): Token[] {
  const tokens: Token[] = [];
  for (let i = 0; i < strings.length; i++) {
    const s = strings[i];
    let j = 0;
    while (j < s.length) {
      const ch = s[j];
      if (ch === " " || ch === "\t" || ch === "\n") { j++; continue; }
      if (ch === "(") { tokens.push({ kind: "(" }); j++; continue; }
      if (ch === ")") { tokens.push({ kind: ")" }); j++; continue; }
      if (ch === ",") { tokens.push({ kind: "," }); j++; continue; }
      if (ch === "+" || ch === "-" || ch === "*" || ch === "/") {
        // minus as unary: only if at start or after ( or after another op
        if (ch === "-" && (tokens.length === 0 || tokens[tokens.length - 1].kind === "(" || tokens[tokens.length - 1].kind === "op")) {
          // negative number literal
          let end = j + 1;
          while (end < s.length && (s[end] >= "0" && s[end] <= "9" || s[end] === ".")) end++;
          if (end > j + 1) {
            tokens.push({ kind: "num", value: parseFloat(s.slice(j, end)) });
            j = end;
            continue;
          }
        }
        tokens.push({ kind: "op", value: ch as BinOp });
        j++;
        continue;
      }
      if ((ch >= "0" && ch <= "9") || ch === ".") {
        let end = j;
        while (end < s.length && (s[end] >= "0" && s[end] <= "9" || s[end] === ".")) end++;
        tokens.push({ kind: "num", value: parseFloat(s.slice(j, end)) });
        j = end;
        continue;
      }
      if (ch >= "a" && ch <= "z" || ch >= "A" && ch <= "Z" || ch === "_") {
        let end = j;
        while (end < s.length && (s[end] >= "a" && s[end] <= "z" || s[end] >= "A" && s[end] <= "Z" || s[end] >= "0" && s[end] <= "9" || s[end] === "_")) end++;
        const word = s.slice(j, end);
        // dotted two-sided refs: m.<col> ⇒ mcol, f.<col> ⇒ fcol — the (m, f) row of §3c
        if ((word === "m" || word === "f") && s[end] === ".") {
          let ce = end + 1;
          while (ce < s.length && (s[ce] >= "a" && s[ce] <= "z" || s[ce] >= "A" && s[ce] <= "Z" || s[ce] >= "0" && s[ce] <= "9" || s[ce] === "_")) ce++;
          if (ce === end + 1) throw new Error(`expr template: expected a column name after "${word}."`);
          const col = s.slice(end + 1, ce);
          tokens.push({ kind: "expr", value: word === "m" ? mcol(col) : fcol(col) });
          j = ce;
          continue;
        }
        if (UNARIES.has(word) || FUNCTIONS[word] !== undefined) { tokens.push({ kind: "fn", value: word }); }
        else throw new Error(`expr template: unknown identifier "${word}" (use m.<col> / f.<col>, a registered function, or interpolation)`);
        j = end;
        continue;
      }
      throw new Error(`expr template: unexpected char '${ch}'`);
    }
    if (i < exprs.length) {
      tokens.push({ kind: "expr", value: exprs[i] });
    }
  }
  return tokens;
}

// Pratt parser
function parse(tokens: Token[]): ScalarExpr {
  let pos = 0;
  const peek = (): Token | undefined => tokens[pos];
  const advance = (): Token => tokens[pos++];

  function atom(): ScalarExpr {
    const t = peek();
    if (!t) throw new Error("expr template: unexpected end of expression");
    if (t.kind === "expr") { advance(); return t.value; }
    if (t.kind === "num") { advance(); return lit(t.value); }
    if (t.kind === "(") {
      advance();
      const inner = parseExpr(0);
      const cl = advance();
      if (!cl || cl.kind !== ")") throw new Error("expr template: expected ')'");
      return inner;
    }
    if (t.kind === "fn") {
      const fn = t.value;
      advance();
      const lp = advance();
      if (!lp || lp.kind !== "(") throw new Error(`expr template: expected '(' after ${fn}`);
      const args: ScalarExpr[] = [parseExpr(0)];
      while (peek()?.kind === ",") { advance(); args.push(parseExpr(0)); }
      const rp = advance();
      if (!rp || rp.kind !== ")") throw new Error(`expr template: expected ')' after ${fn}(...`);
      // legacy dedicated nodes keep their shape (hot paths, existing ASTs); the rest are registry calls
      if (fn === "nullif0") return nullif0(args[0]);
      if (fn === "floor" || fn === "ln" || fn === "abs" || fn === "sqrt") return unary(fn, args[0]);
      const def = FUNCTIONS[fn];
      if (def === undefined) throw new Error(`expr template: unknown function "${fn}"`);
      if (def.arity !== args.length) throw new Error(`expr template: "${fn}" takes ${def.arity} argument(s), got ${args.length}`);
      return call(fn, args);
    }
    throw new Error(`expr template: unexpected token ${JSON.stringify(t)}`);
  }

  function parseExpr(minPrec: number): ScalarExpr {
    let left = atom();
    while (true) {
      const t = peek();
      if (!t || t.kind !== "op") break;
      const prec = PREC[t.value];
      if (prec <= minPrec) break;
      advance();
      const right = parseExpr(prec); // right-to-left for same prec (left assoc: use prec instead of prec)
      left = bin(t.value, left, right);
    }
    return left;
  }

  const result = parseExpr(0);
  if (pos < tokens.length) throw new Error(`expr template: unexpected tokens after expression at position ${pos}`);
  return result;
}

/**
 * Tagged template literal for building ScalarExpr trees.
 *
 * Interpolated values must be ScalarExpr nodes (use lit(), mcol(), fcol(), rank(), etc).
 * Bare numbers in the string are auto-wrapped in lit().
 * Operators: + - * / with standard precedence. Parentheses for grouping.
 * Functions: floor(), ln(), abs(), sqrt(), nullif0().
 *
 * @example
 * // pad + idx * pitch
 * expr`${lit(4)} + ${rank("idx")} * ${lit(16)}`
 *
 * // (value - lo) / nullif0(hi - lo)
 * expr`(${mcol("value")} - ${fcol("lo")}) / nullif0(${fcol("hi")} - ${fcol("lo")})`
 */
export function expr(strings: TemplateStringsArray, ...values: ScalarExpr[]): ScalarExpr {
  return parse(tokenize(strings, values));
}
