// bandY: categorical → y + height — the horizontal-bar's y layout (VL's band scale on the y axis).
// The y-mirror of bandX; binds via pick('y','h'). THE FIT IS THE DOMAIN: train produces the keyed
// (value, idx, n) category table and apply is a keyed join — y = idx/n (band top edge), h = 1/n.
// Ticks: `ordinal` — one per category, anchored at each band's center (anchor === "center").
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, nullif0 } from "../../algebra/relop.js";
import { categorical } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const bandY = op({
  name: "bandY",
  domain: categorical((b): RelOp => ({ kind: "unique", col: inputCol(b, "value"), as: "value", indexed: true }), { ordered: true }),
  inputs: { marks: [{ name: "value", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "y", type: "double" }, { name: "h", type: "double" }] },
  outSpaces: { y: relativeSpace(coord("y")), h: relativeSpace(len("y")) },
  inputSpaces: { value: dataSpace },
  apply: (b): RelOp => {
    const [yo, ho] = b.outputs;
    const opt = (name: string, dflt: number): number => (b.options?.[name] !== undefined ? Number(b.options[name]) : b.options?.padding !== undefined ? Number(b.options.padding) : dflt);
    const pi = opt("paddingInner", 0);
    const po = opt("paddingOuter", 0);
    const align = b.options?.align !== undefined ? Number(b.options.align) : 0.5;
    const center = b.options?.anchor === "center";
    const denom = nullif0(bin("+", bin("-", fcol("n"), lit(pi)), lit(2 * po)));
    const off = 2 * po * align + (center ? (1 - pi) / 2 : 0);
    return {
      kind: "derive",
      add: { [yo]: bin("/", bin("+", lit(off), fcol("idx")), denom), [ho]: bin("/", lit(1 - pi), denom) },
      outTypes: { [yo]: "double", [ho]: "double" },
    };
  },
  ticks: "ordinal",
});
