// Node / group / adornment-directive / extent (WUIR_IMPL §2.3; WUNOUNS §Structural).
// Adornments are RECORDED here as directives; lowering to groups-of-plots is C7.
import type { GroupId, LayoutId, NodeId, PlotId } from "../types/ids.js";
import type { ArrangeInstance, AxisOptions, Constraint } from "./layout.js";
import type { NestJoinSpec } from "./plot.js";
import type { CellRef } from "./cell.js";
import type { Expr } from "./expr.js";
import type { BandPad, NodeBand } from "../layout/sidestack.js"; // type-only (erased) — no runtime cycle

export type Side = "top" | "right" | "bottom" | "left";
export type LegendPlacement = Side | "inside";
export type BindingMode = "derived" | "mapped" | "pixel";

/** The box: outer extent + content region (outer inset by padding). Cells solved by C6. */
export interface Extent {
  outer: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
  content: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
}

/** A semantic bundle of plots (axis/legend/…); the shared-axis rule derives elsewhere. */
export interface Group {
  id: GroupId;
  role: string; // OPEN tag (selection/styling/debug), not dispatched on
  plots: PlotId[];
  annotates?: { layout?: LayoutId; channel?: string };
}

/** The TEMPLATE nodes of a spec-like: data-driven children (no hostRow — §C8). */
export function templateNodeIds(nodes: Iterable<Node>): Set<NodeId> {
  const out = new Set<NodeId>();
  for (const n of nodes) for (const c of n.children) if (c.hostRow === undefined) out.add(c.node);
  return out;
}

export type AdornmentDirective =
  // The axis directive carries the full AxisOptions (title, ticks, tickLength, fontSize, …) —
  // lowerAxes merges it into the matching frame scale's recorded config (directive wins).
  | ({ kind: "axis"; axis: "x" | "y"; placement?: Side; style?: Record<string, Expr> } & AxisOptions)
  | { kind: "legend"; channel: string; placement?: LegendPlacement; style?: Record<string, Expr> }
  // A facet STRIP: one text label per subplot/panel, centered in the panel's step, sized by fitText.
  // `labelCol` = the panels-table column holding each label. Reserves a gutter band on `placement`.
  | { kind: "strip"; labelCol: string; placement?: Side; height?: number; fontSize?: number; place?: "inside" | "outside"; gap?: number; pad?: BandPad };

/** A bounded variable the solver can adjust within [min, max]. */
export interface AdjustableParam {
  cell: CellRef;
  min: number;
  preferred: number;
  max: number;
}

/** A sub-plot the controller can hide under space pressure. */
export interface OptionalPlot {
  plot: PlotId;
  indicator: CellRef; // 0 = hidden, 1 = shown
  priority: number; // lower = shed first
}

/** Every adornment is a PlotRect: measured size + solver-positioned + adaptability profile.
 *  This is the ONLY layout primitive. It subsumes the old PlotMeasureRequest. */
export interface PlotRect {
  id: string;
  plots: PlotId[]; // sub-plots whose combined bbox fills w/h (measurement target)
  x: CellRef; // left edge — solver writes
  y: CellRef; // top edge — solver writes
  w: CellRef; // width — plot-measure fills (or author pins)
  h: CellRef; // height — plot-measure fills (or author pins)
  adjustable?: AdjustableParam[];
  optional?: OptionalPlot[];
}

export interface Node {
  id: NodeId;
  plots: PlotId[];
  groups: Group[];
  adornments: AdornmentDirective[];
  constraints: Constraint[]; // component-emitted (an axis's gutter, …) — consumed by the node's arrange op
  /** ALIGNED bands on this node's sides (axes, legends, titles) — registered by lowering, resolved
   *  into a SINGLE summed reservation + chain + center per side by `arrangeNode` (via
   *  `nodeSideStack`). Co-located bands SUM (WULAYOUT §alignment); separate `≥` floors in
   *  `constraints` (perpendicular end-spacers) still MAX in. Scalar nodes only (Steps 1–4). */
  sideBands?: NodeBand[];
  plotRects?: PlotRect[]; // adornment rectangles — measured + positioned by the constraint system
  /** Parent node ID (undefined for root). Set by the builder when the child is created. */
  parent?: NodeId;
  demand?: { w: CellRef; h: CellRef }; // min footprint (measure op writes; consumer = demand-driven container size, C8/Cassowary)
  arrange?: ArrangeInstance; // built/solved by C6
  diagnostics?: CellRef; // the verify op's report (§C6): violated hard declarations, post-solve
  /** TEMPLATE nodes only (§C8): the node has no scalar outer extent (its outer IS the host's box
   *  relation); its arrange solves these INSET cells instead, and the keyed affine reads
   *  `box ⊖ insets`. Template-uniform by design (panels vary only in data). */
  insets?: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
  // A child node is hosted by a plot's MARKS. `hostRow` = the implicit FK key of a STATIC child:
  // virtual/host row k ↔ all rows of the child's data (WULAYOUT_IMPL §C6 subplot model) — the
  // degenerate `dvl_cell = k`. A DATA-DRIVEN child (§C8) has NO hostRow: the child is a TEMPLATE
  // whose single pipeline spans ALL host rows, keyed by the `nest` join (dvl_cell from the cell-key
  // op). hostRow undefined ⇔ template.
  children: { node: NodeId; hostPlot: PlotId; nest: NestJoinSpec; hostRow?: number }[];
  extent: Extent;
  frame: { scales: LayoutId[] }; // the shared coordinate frame (shared-axis rule)
  axesLowered?: boolean; // lowerAxes ran (idempotence marker — axes lower to plots ONCE)
}
