// Domain-union planning (§C6): group shared/coupled scale instances, emit the
// gather-scatter op that unions member contributions into the shared domain cell
// (ex dataflow/graph.ts). Pure planning over the spec's layout instances.
import type { Spec } from "../../ir/spec.js";
import { sourceKey } from "../../ir/plot.js";
import type { LayoutInstance } from "../../ir/layout.js";
import type { Operator } from "../../operator/operator.js";
import type { CellRef } from "../../ir/cell.js";
import type { OpSpec } from "../opspec.js";
import type { LayoutId, NodeId } from "../../types/ids.js";
import { opOf } from "./context.js";
import { isActiveTreatment } from "../../operator/treatment.js";
import { warnOnce } from "../../config.js";

/** The domain-sharing plan (gather-scatter).
 *
 *  WHO may share — three rules, in precedence order:
 *  1. AUTHORED pins win: `shared: false` never groups; one ScaleSpec OBJECT reused across binds is
 *     the authored equivalence (`equiv` tag) and groups unconditionally — set, not solved. A MARK's
 *     coupled positional channels (x/x2 — an interval's ends, registered by the mark's channel
 *     KINDS) tag their per-channel instances into the same equivalence at bind: one quantity-axis,
 *     unioned domains, the primary channel's axis speaking for the group.
 *  2. Derived identity is TABLE-SCOPED: `(dim, descriptor, table, column)` — each table's column is
 *     a DISTINCT quantity; a shared column NAME across tables means nothing (equivalence is
 *     authored, never assumed).
 *  3. Derived scope is SIBLINGS under one parent — the same scope the parent's solver can actually
 *     ALIGN (sharing is only useful where alignment is possible). Scales and axes are not
 *     conflated: one quantity may drive axes in many nodes without those nodes sharing a domain.
 *     Cross-subtree merging is a later OPTIMIZER's call; the abstraction stays simple.
 *
 *  WHAT may share — the domain must be an algebra WITH A UNION: min-max (envelope) or distinct
 *  (set union). A domain kind with no union operation (quantile) NEVER shares — it is not coerced;
 *  a multi-member instance over such a kind warns (its members would otherwise last-write).
 *
 *  A shared group's members each train into a CONTRIBUTION cell (collected during compile) and one
 *  gather-scatter op per group unions them into every instance's effective domain. The partition is
 *  otherwise PINNED at compile; a solver-written partition cell later merges the per-group ops into
 *  one op whose grouping is a read. */
type UnionOp = NonNullable<Operator["domain"]>["unionFn"];

export interface DomainGroups {
  contributions: Map<LayoutId, CellRef[]>; // collector: a shared instance → its members' contribution cells
  groups: { ids: LayoutId[]; union: NonNullable<UnionOp> }[];
}

/** The union IMPLEMENTATION of an operator's domain, iff it DECLARES one (domain.union
 *  non-null). Keys on the declared intent — quantize (min-max fit, union: null) is correctly
 *  unshareable. */
const unionOf = (o: Operator): NonNullable<UnionOp> | undefined =>
  o.domain?.union != null ? o.domain.unionFn : undefined;

export function planDomainGroups(spec: Spec): DomainGroups {
  const parent = new Map<NodeId, NodeId>();
  for (const n of spec.nodes.values()) for (const ch of n.children) parent.set(ch.node, n.id);
  const nodeOf = (inst: LayoutInstance): NodeId => spec.plots.get(inst.members![0].plot)!.node;

  const byKey = new Map<string, LayoutId[]>();
  for (const inst of spec.layouts.values()) {
    if (inst.domain === undefined || inst.dim === undefined || inst.members === undefined || inst.members.length === 0) continue;
    if (inst.shared === false) continue; // authored opt-out PINS: own domain, whatever identity says
    const nid = nodeOf(inst);
    const multiMember = new Set(inst.members.map((m) => m.plot)).size > 1;
    const uk = unionOf(opOf(inst));
    if (uk === undefined) {
      // no union algebra ⇒ not shareable. A single-member instance is simply direct-path; a
      // multi-member one has no correct semantics (K trains, one cell) — warn loudly.
      if (multiMember) console.warn(`dvl: scale "${inst.id}" spans plots but its domain kind has no union operation — domains cannot be shared (last writer wins)`);
      continue;
    }
    // authored equivalence (`equiv` present ⇔ the author reused one ScaleSpec object) groups
    // unconditionally; derived identity groups within the SIBLING scope (instances under one
    // parent — where the parent's solver can align them). Root/parentless instances group only
    // with themselves (the within-node multi-member case).
    const par = parent.get(nid);
    const key =
      inst.equiv !== undefined
        ? `eq:${inst.equiv}`
        : par !== undefined
          ? `sib:${par}:${inst.dim}:${inst.descriptor}:${sourceKey(inst.members[0].source)}:${inst.members[0].column}`
          : `self:${inst.id}`;
    byKey.set(key, [...(byKey.get(key) ?? []), inst.id]);
  }

  const contributions = new Map<LayoutId, CellRef[]>();
  const groups: DomainGroups["groups"] = [];
  for (const ids of byKey.values()) {
    const memberPlots = new Set(ids.flatMap((id) => (spec.layouts.get(id)!.members ?? []).map((m) => m.plot)));
    if (ids.length === 1 && memberPlots.size === 1) continue; // unshared — the direct train/apply path
    for (const id of ids) contributions.set(id, []);
    groups.push({ ids, union: unionOf(opOf(spec.layouts.get(ids[0])!))! });
  }
  return { contributions, groups };
}

/** Emit one gather-scatter op per shared group: reads every member's contribution, writes the SAME
 *  union to EVERY instance's effective-domain cell. Called by compileSpec AFTER the whole walk (a
 *  group's contributions span nodes). Skips groups not fully collected (a standalone compileNode
 *  compiled only its own node — the rest is compileSpec's job). */
export function emitGatherScatter(spec: Spec, domains: DomainGroups, specs: OpSpec[]): void {
  for (const g of domains.groups) {
    if (g.ids.some((id) => (domains.contributions.get(id) ?? []).length === 0)) continue;
    // §5a: the group's ACTIVE treatment (explicit/zero) — the treatment rides the scale
    // instance, so it applies ONCE per group, post-union. First declaring member wins; two
    // members declaring DIFFERENT active treatments is an authoring smell, warned once.
    const actives = g.ids
      .map((id) => spec.layouts.get(id)?.treatment)
      .filter((t): t is NonNullable<typeof t> => isActiveTreatment(t));
    const treatment = actives[0];
    if (actives.length > 1 && actives.some((t) => JSON.stringify(t) !== JSON.stringify(treatment))) {
      warnOnce(`${g.ids.join("+")}:treatment`, `shared scales ${g.ids.join(", ")} declare DIFFERENT domain treatments — keeping the first (${JSON.stringify(treatment)})`);
    }
    specs.push({
      id: `${g.ids.join("+")}:gather-scatter`,
      reads: g.ids.flatMap((id) => domains.contributions.get(id)!),
      writes: g.ids.map((id) => spec.layouts.get(id)!.domain!),
      payload: { kind: "gather-scatter", key: `${g.ids.join("+")}:union`, union: g.union, ...(treatment !== undefined ? { treatment } : {}) },
    });
  }
}
