// eqY (equi-height): distribute the distinct keys evenly across the range → y + height. The y-mirror
// of eqX (the row-facet driver). Same shape as the band scale (rank → step), promoted to a layout.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, rank } from "../../algebra/relop.js";
import { continuous } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const eqY = op({
  name: "eqY",
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { n: { fn: "countDistinct", col: inputCol(b, "value") } } }), { union: null, unionFn: undefined, nice: undefined, ticks: "ordinal", interpolable: false }),
  inputs: { marks: [{ name: "key", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "y", type: "double" }, { name: "h", type: "double" }] },
  outSpaces: { y: relativeSpace(coord("y")), h: relativeSpace(len("y")) },
  inputSpaces: { key: dataSpace },
  apply: (b): RelOp => {
    const [yo, ho] = b.outputs;
    const invN = bin("/", lit(1), fcol("n")); // 1/n — normalized step
    return { kind: "derive", add: { [yo]: bin("*", rank(inputCol(b, "value")), invN), [ho]: invN }, outTypes: { [yo]: "double", [ho]: "double" } };
  },
});
