// The SOURCE producers (WUAXIS §3): plan-only Operators with no input marks, referenced from a
// plot's base via the `{ producer: LayoutId }` source. The compiler runs their `plan` once per node
// (emit-once) and the plot's base is the output cell.
//
//   • `vtable` — domain → V (the tick relation idx/value/label) via a registered tick algo. Producing
//     V is the OPEN `tickAlgos` registry: a new way to produce V (temporal ticks, a formatter, later a
//     legend's swatches) is just another registered tick algo — no new machinery. The instance's
//     `options` ({ tickAlgo, count }) ride binding.options into the emitted op.
//   • `unit` — ONE all-defaults row: the singleton base for a plot whose channels are all literals
//     (an axis's baseline rule).
import type { CellRef } from "../../ir/cell.js";
import { op, type Operator } from "../../operator/operator.js";
import type { PlanIO } from "../../operator/binding.js";
import type { OpSpec } from "../../plan/opspec.js";

export const vtable: Operator = op({
  name: "vtable",
  inputs: {}, // a SOURCE: no input marks — it reads its domain hole
  output: { columns: [{ name: "idx", type: "int" }, { name: "value", type: "double" }, { name: "label", type: "varchar" }] },
  plan: (io: PlanIO): OpSpec[] => {
    const domain = io.holes.domain; // the trained domain cell this V ticks — SHARED from the scale
    if (domain === undefined) throw new Error("vtable: needs holes.domain (the trained domain to tick)");
    const o = io.binding.options ?? {};
    if (typeof o.tickAlgo !== "string") throw new Error("vtable: needs options.tickAlgo (a registered tick algo name)");
    const tickAlgoResolved = o.tickAlgoResolved; // resolved by resolveSpec (resolve-once)
    if (tickAlgoResolved === undefined) throw new Error(`vtable: tick algo "${o.tickAlgo}" is unresolved — call resolveSpec(spec, registries) after the lowerings`);
    // count: the author's pin, else DERIVED from the axis length — the op then READS the extent
    // content-edge cells, closing the §C6 cycle (content → count → V → demand → margin → content).
    const count = o.count === undefined ? undefined : Number(o.count);
    const extent = count === undefined ? (o.extent as readonly [CellRef, CellRef] | undefined) : undefined;
    // per-cell counts (§C8 7b): `countFrom` names the box dimension; the count derives from EACH
    // panel's box ⊖ insets at execution. `boxes` (the host's placed marks) is a compile artifact —
    // compileSpec injects it into these options before the plan runs.
    const countFrom = o.countFrom as "x" | "y" | undefined;
    const boxes = o.boxes as CellRef | undefined;
    const insetLo = o.insetLo as CellRef | undefined;
    const insetHi = o.insetHi as CellRef | undefined;
    if (count === undefined && extent === undefined && countFrom === undefined) throw new Error("vtable: needs options.count (a pin), options.extent (content-edge cells), or options.countFrom (per-cell, §C8)");
    if (countFrom !== undefined && (boxes === undefined || insetLo === undefined || insetHi === undefined)) throw new Error("vtable: per-cell counts need options.boxes (injected by compileSpec) + insetLo/insetHi");
    // the axis PRESENCE cell (§C6 axis-merge), read at execution: 0 ⇒ V is EMPTY — the axis's marks
    // and its measured demand then vanish through ordinary dataflow, nothing is unwired.
    const indicator = o.indicator as CellRef | undefined;
    // `by` (§C8 per-cell tick content): ticks generate PER CELL — a keyed domain contributes each
    // cell its own rows; a shared (1-row) domain broadcasts to every cell, at that cell's count.
    const by = o.by as string | undefined;
    return [{ id: `${io.id}:vtable`, reads: [domain, ...(extent ?? []), ...(countFrom !== undefined ? [boxes!, insetLo!, insetHi!] : []), ...(indicator !== undefined ? [indicator] : [])], writes: [io.marksOut], payload: { kind: "vtable", tickAlgo: o.tickAlgo, algo: tickAlgoResolved, column: String(o.column ?? "value"), count, extent, indicator, by, countFrom, boxes, insetLo, insetHi } }];
  },
});

/** A CONSTANT relation from the instance's `options.rows` — the per-node virtual table each
 *  `subplot()` call appends a row to (WULAYOUT_IMPL §C6 subplot syntax model). */
export const values: Operator = op({
  name: "values",
  inputs: {},
  output: { columns: [] }, // columns come from the instance's rows (constant, authoring-time data)
  plan: (io: PlanIO): OpSpec[] => {
    const rows = io.binding.options?.rows;
    if (!Array.isArray(rows) || rows.length === 0) throw new Error("values: needs options.rows (a non-empty constant row set)");
    // A constant leaf relation — a relop source (no input relation, no ScalarExpr).
    return [{ id: `${io.id}:values`, reads: [], writes: [io.marksOut], payload: { kind: "relop", key: io.id, add: {}, outTypes: {}, source: { rows: rows as Record<string, unknown>[] }, tag: "values" } }];
  },
});

export const unit: Operator = op({
  name: "unit",
  inputs: {},
  output: { columns: [{ name: "dvl_mark", type: "int" }] },
  plan: (io: PlanIO): OpSpec[] => {
    // a GATED unit (an axis's baseline rides its axis's presence, §C6 axis-merge): 0 ⇒ 0 rows.
    // The unit relation is a relop source with empty rows; the indicator becomes the `gate` cell.
    const indicator = io.binding.options?.indicator as CellRef | undefined;
    return [{ id: `${io.id}:unit`, reads: indicator !== undefined ? [indicator] : [], writes: [io.marksOut], payload: { kind: "relop", key: io.id, add: {}, outTypes: {}, source: { rows: [], gate: indicator }, tag: "unit" } }];
  },
});
