// overhang op (design/2026-07-21-scale-expansion.html §4): the containment loop's measure,
// scoped to ONE positional scale. Scans every member frame's box columns (the C6 `box:` fork,
// dvl_<axis>0/1) for the extreme edges, compares them to that frame's content endpoints, and
// corrects the scale's RELATIVE expansion cells with a SIGNED slack update: overflow grows the
// slack, room shrinks it, so the fixpoint is "the worst mark edge exactly touches the frame".
// Corrections are taken per frame and MAXed — the tightest member frame binds, which is the
// shared-scale invariant (one map per scale, every frame comparable). The frame affine reads the
// same cells, so this op closes the measure→expand→affine cycle the scheduler runs as an SCC.
// Infeasible (needed slack ≥ span) clamps proportionally and warns LOUDLY — a stable best-effort
// fixpoint instead of an oscillation.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { Relation } from "../../../algebra/relation.js";
import type { OverhangPayload } from "../../../plan/payloads.js";

export async function overhang(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as OverhangPayload;
  if (p.kind !== "overhang") return;

  const rd = (c: string): number => { const v = store.read(c); return typeof v === "number" ? v : 0; };
  const e0 = rd(p.expand.lo), e1 = rd(p.expand.hi);
  const a0 = `dvl_${p.axis}0`, a1 = `dvl_${p.axis}1`; // min / max pixel edge columns for this axis

  // Per frame: the extreme box edges vs the frame's t=0 / t=1 endpoints, as a corrected candidate
  // (e + overhang/span, floored at 0). A frame with no contributing rows proposes nothing.
  let best0 = -Infinity, best1 = -Infinity, minSpan = Infinity;
  for (const f of p.frames) {
    let minE = Infinity, maxE = -Infinity;
    for (const ref of f.boxes) {
      const rel = store.read(ref) as Relation | undefined;
      if (rel === undefined) continue;
      const rows = (rel.substrate === "js" ? rel.rows : await ctx.run(rel.frag)) as Record<string, unknown>[];
      for (const row of rows) {
        const lo = row[a0], hi = row[a1];
        if (typeof lo === "number" && Number.isFinite(lo) && lo < minE) minE = lo;
        if (typeof hi === "number" && Number.isFinite(hi) && hi > maxE) maxE = hi;
      }
    }
    if (minE === Infinity && maxE === -Infinity) continue;
    const cLo = rd(f.lo), cHi = rd(f.hi); // AFFINE order: cLo is the t=0 endpoint (y: the bottom)
    const span = Math.abs(cHi - cLo);
    if (span <= 0) continue;
    minSpan = Math.min(minSpan, span);
    // overflow past each ENDPOINT, direction-aware: when the axis flips (y: cHi < cLo), the t=0
    // endpoint is the numerically LARGER edge, so overflow there is maxE − cLo.
    const flipped = cHi < cLo;
    const overLo = flipped ? maxE - cLo : cLo - minE;
    const overHi = flipped ? cHi - minE : maxE - cHi;
    if (minE !== Infinity || maxE !== -Infinity) {
      best0 = Math.max(best0, Math.max(0, e0 + overLo / span));
      best1 = Math.max(best1, Math.max(0, e1 + overHi / span));
    }
  }
  if (best0 === -Infinity && best1 === -Infinity) return; // no measurements anywhere — leave the cells

  let n0 = best0 === -Infinity ? e0 : best0;
  let n1 = best1 === -Infinity ? e1 : best1;
  // Clamp: total slack must leave ≥ 1px of span in the TIGHTEST frame (e₀ + e₁ ≤ 1 − 1/minSpan).
  const cap = 1 - 1 / Math.max(minSpan, 2);
  if (n0 + n1 > cap && n0 + n1 > 0) {
    const f = cap / (n0 + n1);
    console.warn(`[dvl] overhang(${p.scale}): ${p.axis}-axis mark extents need ${((n0 + n1) * 100).toFixed(0)}% of the span as slack (span ${minSpan.toFixed(0)}px) — expansion clamped, marks will bleed`);
    n0 *= f; n1 *= f;
  }
  store.write(p.expand.lo, n0, "assigned");
  store.write(p.expand.hi, n1, "assigned");
}
