// INTERNAL-ONLY (§12 Phase 5): TrainOp/ApplyOp/FitMode are the internal carrier between op()'s
// RelOp descriptions and the shared lowering (dataflow/lower.ts) — no component authors them
// anymore. They stay exported only because lower.ts/exec.ts consume them; treat them as private.
// The relational-op algebra a layout/scale operator EMITS — substrate-agnostic descriptions
// of what to compute, not how (WULAYOUT_IMPL, C4 logical/physical split). The operator never
// builds a SqlFragment or JS rows; it returns a TrainOp / ApplyOp, and the shared lowering
// (lower.ts) realizes it as SQL or JS while the scheduler picks substrate (and may fuse).
import type { Scalar, SqlType } from "../data/schema.js";
import type { CellRef } from "../ir/cell.js";
import type { Space } from "../types/attr.js";

/** A scalar value over a mark row + the fit row — lowered to SQL text or a JS evaluator. */
export type ScalarExpr =
  | { readonly k: "lit"; readonly v: Scalar; readonly space?: Space }
  | { readonly k: "col"; readonly name: string; readonly src: "marks" | "fit" }
  | { readonly k: "bin"; readonly op: "+" | "-" | "*" | "/" | "%"; readonly l: ScalarExpr; readonly r: ScalarExpr }
  | { readonly k: "nullif0"; readonly x: ScalarExpr } // NULLIF(x, 0) — null-propagating divide guard
  | { readonly k: "rank"; readonly col: string } // dense_rank() over (order by marks.col) − 1
  // wsum: a windowed SUM over the marks — SUM(col) OVER (PARTITION BY partition [ORDER BY order]).
  // With `order` it is a RUNNING (cumulative) sum; without, the whole-partition total. The same
  // window family as `rank` (a bare formula leaf) — stack's cumulative/total pair.
  | { readonly k: "wsum"; readonly col: string; readonly partition?: string; readonly order?: string }
  // lead: the SUCCESSOR row's value — LEAD(col, offset) OVER (PARTITION BY partition ORDER BY order).
  // The window family's third member (rank, wsum — same partition/order shape, dual lowering).
  // NULL at each partition's tail (no successor): the consumer decides (drawSegment collapses a
  // missing endpoint to a degenerate, invisible segment — SEQUENCE_MARKS §4).
  | { readonly k: "lead"; readonly col: string; readonly order: string; readonly partition?: string; readonly offset?: number }
  | { readonly k: "index"; readonly list: readonly Scalar[]; readonly idx: ScalarExpr } // list[idx mod len]
  | { readonly k: "unary"; readonly fn: "ln" | "floor" | "abs" | "sqrt"; readonly x: ScalarExpr } // a scalar math fn — one more leaf of the formula vocabulary
  | { readonly k: "left"; readonly str: ScalarExpr; readonly n: ScalarExpr } // LEFT(str, n) — string truncation
  | { readonly k: "rand" } // a uniform [0,1) sample (SQL random() / JS Math.random()) — for stub layouts
  | { readonly k: "concat"; readonly parts: readonly ScalarExpr[] } // string concatenation (SQL ||) — null-propagating
  | { readonly k: "round"; readonly x: ScalarExpr; readonly digits: number } // round(x, digits) — fixed-precision numeric
  | { readonly k: "rownum" } // the row's 0-based position — (row_number() OVER () − 1) / the JS row index
  // cell: a scalar read from the cell store AT EMIT TIME — the value stays a {ref} hole that
  // emit() binds per fixpoint iteration (never a literal baked into static SQL text). This is how
  // an expression names a runtime value (the affine's lo/hi extent cells) without leaving the algebra.
  | { readonly k: "cell"; readonly ref: CellRef }
  // call: a REGISTERED function (algebra/functions.ts) over N args — the extensible unary/binary
  // vocabulary (math/string/stat). Dual-substrate when the def has a SQL form; JS-only otherwise
  // (the optimizer forces its relop to JS). Result is data-space by construction.
  | { readonly k: "call"; readonly fn: string; readonly args: readonly ScalarExpr[] };

// expression builders (keep call sites terse)
export const lit = (v: Scalar, space?: Space): ScalarExpr => (space === undefined ? { k: "lit", v } : { k: "lit", v, space });
export const mcol = (name: string): ScalarExpr => ({ k: "col", name, src: "marks" });
export const fcol = (name: string): ScalarExpr => ({ k: "col", name, src: "fit" });
export const bin = (op: "+" | "-" | "*" | "/" | "%", l: ScalarExpr, r: ScalarExpr): ScalarExpr => ({ k: "bin", op, l, r });
export const nullif0 = (x: ScalarExpr): ScalarExpr => ({ k: "nullif0", x });
export const rank = (col: string): ScalarExpr => ({ k: "rank", col });
export const index = (list: readonly Scalar[], idx: ScalarExpr): ScalarExpr => ({ k: "index", list, idx });
export const rand = (): ScalarExpr => ({ k: "rand" });
export const unary = (fn: "ln" | "floor" | "abs" | "sqrt", x: ScalarExpr): ScalarExpr => ({ k: "unary", fn, x });
export const ln = (x: ScalarExpr): ScalarExpr => unary("ln", x);
export const floor = (x: ScalarExpr): ScalarExpr => unary("floor", x);
export const left = (str: ScalarExpr, n: ScalarExpr): ScalarExpr => ({ k: "left", str, n });
export const wsum = (col: string, opts: { partition?: string; order?: string } = {}): ScalarExpr => ({ k: "wsum", col, partition: opts.partition, order: opts.order });
export const lead = (col: string, opts: { order: string; partition?: string; offset?: number }): ScalarExpr => ({ k: "lead", col, order: opts.order, partition: opts.partition, offset: opts.offset });
export const concat = (...parts: ScalarExpr[]): ScalarExpr => ({ k: "concat", parts });
export const round = (x: ScalarExpr, digits: number): ScalarExpr => ({ k: "round", x, digits });
export const rownum = (): ScalarExpr => ({ k: "rownum" });
export const cell = (ref: CellRef): ScalarExpr => ({ k: "cell", ref });
export const call = (fn: string, args: readonly ScalarExpr[]): ScalarExpr => ({ k: "call", fn, args });

/** All cell refs an expression reads — the collection walk that lets a lowering register the
 *  refs on its fragment (`mkFrag(..., cells)`) so emit() knows to bind them. */
export function cellsOf(e: ScalarExpr): CellRef[] {
  switch (e.k) {
    case "cell": return [e.ref];
    case "bin": return [...cellsOf(e.l), ...cellsOf(e.r)];
    case "nullif0": case "unary": return cellsOf(e.x);
    case "left": return [...cellsOf(e.str), ...cellsOf(e.n)];
    case "index": return cellsOf(e.idx);
    case "concat": return e.parts.flatMap(cellsOf);
    case "round": return cellsOf(e.x);
    case "call": return e.args.flatMap(cellsOf);
    default: return []; // lit/col/rank/wsum/rand/rownum — no cells
  }
}

/** TRAIN — how to reduce the marks into a fit relation. There is ONE reduce; its consumers wear
 *  different names (scale train, extent bbox, path-agg) and differ only in output space +
 *  downstream protocol — so the Agg vocabulary covers all of them, not just domain fitting.
 *
 *  The base case is an aggregate over an EXPRESSION: `arg` is any ScalarExpr, so sum(x·w) or
 *  stringAgg(concat(x, ",", y)) needs no staging column. `col` is the sugar form (≡ arg: mcol(col))
 *  kept for the dominant call shape. The FUNCTION set stays a closed enum — every arm must carry a
 *  JS mirror (aggJs) and a declared output carrier (aggType), which an open fn string cannot; and
 *  scalar arithmetic ABOVE aggregates (hi − lo) is deliberately not here: reduce → derive already
 *  composes it. Window leaves (rank/wsum/rownum) are illegal inside an aggregate argument. */
export type AggFn =
  | "min" | "max" | "sum" | "avg" | "median" | "stddev" | "variance" // numeric (CAST to DOUBLE)
  | "count" | "countDistinct" // counts (int)
  | "first" | "last" // positional (optionally ordered)
  | "stringAgg" // ordered string aggregation
  | "anyValue"; // grouped passthrough — a value constant within each group survives the reduce
type AggArg =
  | { readonly col: string; readonly arg?: never } // sugar: aggregate a bare marks column
  | { readonly arg: ScalarExpr; readonly col?: never }; // the general base case: aggregate an expression
export type Agg = AggArg &
  (
    | { readonly fn: "min" | "max" | "sum" | "avg" | "median" | "stddev" | "variance" | "count" | "countDistinct" | "anyValue" }
    // string_agg(arg, sep ORDER BY order [DESC]) — path-agg's `d` assembly.
    | { readonly fn: "stringAgg"; readonly order?: string; readonly desc?: boolean; readonly sep?: string }
    // first/last value, deterministic when `order` is given.
    | { readonly fn: "first" | "last"; readonly order?: string; readonly desc?: boolean }
  );
export type TrainOp =
  | { readonly kind: "aggregate"; readonly aggs: Readonly<Record<string, Agg>> } // → a 1-row fit
  // distinct → an N-row fit (one per value). `indexed` adds each value's ORDER STATISTICS —
  // `idx` (dense rank, value-sorted, 0-based) + `n` (the category count) — making the fit a KEYED
  // position table: the fit IS the domain, so an axis's apply-only re-run works by construction
  // (band; WUAXIS §apply-only — the wrapper hands the DOMAIN over as the fit).
  | { readonly kind: "distinct"; readonly col: string; readonly as: string; readonly indexed?: boolean };

/** How the fit attaches to the marks in `apply`. `kind` widens the keyed join (LEFT JOIN keeps
 *  marks with no matching fit row); absent = inner JOIN, the historical default. A pair's
 *  optional THIRD element is the predicate op (default eq) — a multi-match via's stage join
 *  (§3b) joins on lt/gt/…; the JS keyed path supports eq only (buildKeyed throws otherwise). */
export type KeyedPair = readonly [string, string] | readonly [string, string, string]; // 3rd = predicate op (eq default; validated at lowering)
export type FitMode = "none" | "broadcast" | { readonly keyed: ReadonlyArray<KeyedPair>; readonly kind?: "JOIN" | "LEFT JOIN" };

/** APPLY — augment the marks with `add` columns (key-preserving), attaching the fit. */
export interface ApplyOp {
  readonly kind: "augment";
  readonly add: Readonly<Record<string, ScalarExpr>>;
  readonly fit: FitMode;
  readonly outTypes?: Readonly<Record<string, SqlType>>; // schema hint for the added columns
  /** Added cols OVERWRITE same-named input cols (SELECT * REPLACE) — DECLARED, never inferred
   *  from a name collision: an accidental collision must stay an error, not a silent overwrite. */
  readonly replace?: boolean;
}
