// Browser DuckDB-Wasm adapter. `wasmConn` adapts an already-connected
// AsyncDuckDBConnection to the DuckDBConn seam; `createBrowserDuckDB` is a convenience
// bootstrap over the jsDelivr CDN bundles. (Node uses duckdb-node.ts instead.)
import * as duckdb from "@duckdb/duckdb-wasm";
import type { DuckDBConn } from "./duckdb-backend.js";
import { arrowToRows } from "./duckdb-rows.js";
import type { RawRow } from "./schema.js";

/** Adapt a connected AsyncDuckDBConnection (the app owns instantiation) to DuckDBConn. */
export function wasmConn(connection: duckdb.AsyncDuckDBConnection): DuckDBConn {
  return {
    // ponytail: params unused — Milestone A inlines literals; route via prepare() when cells land
    exec: async (sql: string): Promise<readonly RawRow[]> => arrowToRows(await connection.query(sql)),
  };
}

export interface BrowserDuckDB {
  db: duckdb.AsyncDuckDB;
  connection: duckdb.AsyncDuckDBConnection;
  conn: DuckDBConn;
  close(): Promise<void>;
}

/** Convenience bootstrap: instantiate DuckDB-Wasm from the jsDelivr CDN bundles. The
 * worker is loaded via a blob shim because a cross-origin CDN URL can't go straight
 * into `new Worker(url)`. */
export async function createBrowserDuckDB(): Promise<BrowserDuckDB> {
  const bundle = await duckdb.selectBundle(duckdb.getJsDelivrBundles());
  const workerUrl = URL.createObjectURL(new Blob([`importScripts("${bundle.mainWorker}");`], { type: "text/javascript" }));
  const worker = new Worker(workerUrl);
  const db = new duckdb.AsyncDuckDB(new duckdb.ConsoleLogger(), worker);
  await db.instantiate(bundle.mainModule, bundle.pthreadWorker);
  URL.revokeObjectURL(workerUrl);
  const connection = await db.connect();
  return {
    db,
    connection,
    conn: wasmConn(connection),
    close: async () => {
      await connection.close();
      await db.terminate();
      worker.terminate();
    },
  };
}
