// union-all: N same-shaped relations → one (σ's union mode, perCell explainer §7e S3) — plus
// sigma-verify, the diagnostics twin of a σ agreement join (§7e S4). Both are SQL-only, like
// every join-derive: the planner keeps σ edges in the database.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { SigmaVerifyPayload, UnionAllPayload } from "../../../plan/payloads.js";
import { fragColumns, mkFrag, sqlRel, type Relation } from "../../../algebra/relation.js";

const q = (c: string): string => `"${c}"`;

export function unionAllOp(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload as unknown as UnionAllPayload;
  const rels = op.reads.map((r) => store.read(r) as Relation);
  if (rels.some((r) => r.substrate !== "sql")) throw new Error(`union-all "${p.key}": needs SQL inputs — the planner must keep σ edges in the database`);
  const frags = rels.map((r) => (r.substrate === "sql" ? r.frag : (undefined as never)));
  // project every branch to the SHARED columns (intersection, branch-0 order): σ-internal hop
  // columns differ per branch and must neither break UNION arity nor leak into the output.
  const colSets = frags.map((f) => fragColumns(f));
  const common = [...colSets[0]].filter((c) => colSets.every((s) => s.has(c)));
  if (common.length === 0) throw new Error(`union-all "${p.key}": the branches share no columns`);
  const inputs: Record<string, { fragment: (typeof frags)[number] }> = {};
  const selects = frags.map((f, i) => {
    inputs[`g${i}`] = { fragment: f };
    return `SELECT ${common.map(q).join(", ")} FROM @g${i}`;
  });
  const unioned = selects.join(" UNION ALL ");
  const body = p.dedupBy !== undefined && p.dedupBy.length > 0
    ? `SELECT * FROM (${unioned}) t QUALIFY row_number() OVER (PARTITION BY ${p.dedupBy.map(q).join(", ")}) = 1`
    : unioned;
  store.write(op.writes[0], sqlRel(mkFrag(p.key, body, inputs, { columns: common.map((c) => ({ name: c, type: "unknown" as const })) })), "assigned");
}

/** The rows a σ conjoin DROPPED: LEFT JOIN the agreement pairs, keep the null-matches. */
export function sigmaVerifyOp(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload as unknown as SigmaVerifyPayload;
  const marks = store.read(op.reads[0]) as Relation;
  const host = store.read(op.reads[1]) as Relation;
  if (marks.substrate !== "sql" || host.substrate !== "sql") throw new Error(`sigma-verify "${p.key}": needs SQL inputs`);
  const cond = p.on.map(([m, h]) => `m.${q(m)} = h.${q(h)}`).join(" AND ");
  const body = `SELECT m.*, '${p.key}' AS dvl_reason FROM @marks AS m LEFT JOIN @host AS h ON ${cond} WHERE h."dvl_mark" IS NULL`;
  store.write(op.writes[0], sqlRel(mkFrag(p.key, body, { marks: { fragment: marks.frag }, host: { fragment: host.frag } }, { passthrough: "marks", add: [{ name: "dvl_reason", type: "varchar" }] })), "assigned");
}
