// inject op: js→sql crossing. Emit a VALUES fragment from JS rows.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { sqlRel, valuesFrag, type Relation } from "../../../algebra/relation.js";
export function injectOp(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const rel = store.read(op.reads[0]) as Relation;
  if (rel.substrate === "sql") {
    store.write(op.writes[0], rel, "assigned");
    return;
  }
  store.write(op.writes[0], sqlRel(valuesFrag((op.payload as { kind: string; key: string }).key, rel.rows, rel.schema)), "assigned");
}
