// NOTE(§12.1 residual): binding-mode no longer gates the AFFINE — the plot compiler inserts
// the affine at the relative→pixel space mismatch on each channel expression (plan/compile/
// plot.ts + layout/frame.ts). What remains here is the axis/legend DOCKING classification
// (pixel/derived/mapped hosts hoist differently, lower-axes/lower-legends). Post-refactor
// candidate: restate docking as a space question and delete this module.
import type { Spec } from "../../ir/spec.js";
import type { Node, BindingMode } from "../../ir/node.js";
import type { Expr, LayoutOutputExpr } from "../../ir/expr.js";
import type { Registries } from "../../operator/registry.js";
import { attr, isSpatial } from "../../types/attr.js";
import { isDerived } from "../../types/schema.js";
import { staticOutSpace } from "../../operator/operator.js";
/** Derive the host's binding mode for `axis` from the host plot's channel expressions.
 *  Returns null when the node has no host (root or unparented). */
export function hostBindingMode(spec: Spec, registries: Registries, node: Node, axis: "x" | "y"): BindingMode | null {
  const parent = node.parent ? spec.nodes.get(node.parent) : undefined;
  if (!parent) return null;
  const childRef = parent.children.find(c => c.node === node.id);
  if (!childRef) return null;
  const hostPlot = spec.plots.get(childRef.hostPlot);
  if (!hostPlot) return null;

  // Space-based channel discovery: find every channel whose Expr's space is spatial on this axis.
  // This naturally picks up x2 on the x-axis, y2 on the y-axis — the channel name is irrelevant,
  // only the declared space on the Expr matters.
  const exprs = Object.entries(hostPlot.channels)
    .filter(([_, e]) => { const sp = e.type.space; return isSpatial(sp) && sp.geom.kind !== "area" && sp.geom.axis === axis; })
    .map(([_, e]) => e);
  if (exprs.length === 0) return "derived";

  // Pixel-pinned = the expression's space IS pixel (a positional literal, px.* column, or a
  // pixel-emitting layout like grid-stack — all carry pixel space on the expr since Stage 4).
  const isPixelExpr = (e: Expr) => e.type.space.space === "pixel";
  if (exprs.every(isPixelExpr)) return "pixel";

  // DERIVED = every layout-bound channel comes from a produce-layout: an operator whose DECLARED
  // outSpaces contain a STATIC relative column (isDerived — the structural replacement for the
  // old SYSTEM_LAYOUTS name list). Scales declare "binding" (§12.2 — the instance stamps their
  // space per frame channel), so scale-mapped hosts fall through to "mapped".
  const layouts = exprs
    .filter((e): e is LayoutOutputExpr => e.kind === "layout-output")
    .map(e => spec.layouts.get(e.layout));
  const derivesLayout = (descriptor: string): boolean => {
    if (!registries.operators.has(descriptor)) return false;
    const outSpaces = registries.operators.get(descriptor).outSpaces;
    if (outSpaces === undefined) return false;
    const statics = Object.entries(outSpaces).flatMap(([name, d]) => { const s = staticOutSpace(d); return s !== undefined ? [attr(name, "unknown", s)] : []; });
    return isDerived(statics);
  };
  if (layouts.length > 0 && layouts.every(l => l !== undefined && derivesLayout(l.descriptor)))
    return "derived";

  return "mapped";
}
