// DVL global settings — ONE mutable object, read at use sites (never captured), so a developer
// can flip a flag once (`dvlSettings.strict = false`) and it applies everywhere immediately.
// Keep this dependency-free: it is imported from every layer.

export interface DvlSettings {
  /** Strict mode (default ON): boundary code that would otherwise silently degrade — an
   *  unconvertible database value coerced to 0, and similar lossy fallbacks — throws instead.
   *  Turn off only when availability matters more than exactness. */
  strict: boolean;

  /** Which arrange solver to bind (WULAYOUT_IMPL §C6). "auto" (default): propagation for a
   *  required+strong system, Cassowary once a medium/weak preference is present at build time.
   *  Force "propagation" or "cassowary" to bind that solver for EVERY node — Cassowary additionally
   *  honors the soft subplot preferences (align, equal-size) the propagation tier ignores. The two
   *  agree on the hard result (each owns its lowering of the strength-tagged constraints). */
  arrangeSolver: "auto" | "propagation" | "cassowary";
}

export const dvlSettings: DvlSettings = {
  strict: true,
  arrangeSolver: "auto",
};

/** One-time warnings, keyed by site: behavior that is CORRECT but worth surfacing once — e.g.
 *  a via borrow shadowing a same-named mark column (the referent's value wins). Never throws. */
const warned = new Set<string>();
export function warnOnce(site: string, message: string): void {
  if (warned.has(site)) return;
  warned.add(site);
  console.warn(`dvl [${site}]: ${message}`);
}

export const spaceFallbacks = {
  count: 0,
  note(site: string): void {
    this.count++;
    if (dvlSettings.strict) throw new Error(`space-fallback [${site}]: a space was needed but not declared`);
  },
};
