// The single assembly point (WUMODULES): bare registries seeded with every built-in component.
// Keeping the seeding here (not in ir/) keeps ir a leaf.
import { emptyRegistries, type Registries } from "../operator/registry.js";
import type { MeasurementProvider } from "../ir/mark.js";
import { propagation } from "../layout/solvers/propagation.js";
import { cassowary } from "../layout/solvers/cassowary.js";
import { unit, values, vtable } from "./internal/vtable.js";

/** The naive measurement provider (WULAYOUT_IMPL §C6 demand loop): a width heuristic — a real
 *  (canvas/DOM) provider registers under its own name and swaps in without touching the ops. */
const estimate: MeasurementProvider = {
  name: "estimate",
  textExtent: (text, font) => ({ w: 0.6 * font.size * text.length, h: font.size }),
};
import { registerLayouts } from "./layouts/index.js";
import { markComponents } from "./marks/index.js";
import { registerScales } from "./scales/index.js";
import { registerTicks } from "./ticks/index.js";
import { registerInternalOps } from "./internal/index.js";
import { registerReducers } from "./reducers.js";
import { registerSchemes } from "./schemes.js";

export function defaultRegistries(): Registries {
  const r = emptyRegistries();
  for (const m of markComponents) r.marks.register(m.type, m);
  registerScales(r);
  registerLayouts(r);
  registerTicks(r);
  r.operators.register(vtable.name, vtable); // the SOURCE producers (WUAXIS §3)
  r.operators.register(unit.name, unit);
  r.operators.register(values.name, values);
  r.arrangeSolvers.register("propagation", propagation); // C6 default (fast path: required + strong)
  r.arrangeSolvers.register("cassowary", cassowary); // full solver (medium/weak + inequalities)
  r.measures.register(estimate.name, estimate); // C6 demand loop — the naive label-extent provider
  registerInternalOps(r);
  registerReducers(r); // named opaque via reducers (§4.3) — the serializable js spelling
  registerSchemes(r); // named colour palettes (§6) — categorical + sampled ramps
  return r;
}
