// sqrt: continuous → [0,1] via square-root transform. Same domain as linear (min-max
// envelope, niceable), different normalization formula.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, mcol, nullif0, unary } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

export const sqrt = op({
  name: "sqrt",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } })),
  scheme: "blues",
  legend: "ramp",
  apply: (b): RelOp => {
    // t = (sqrt(value) - sqrt(lo)) / (sqrt(hi) - sqrt(lo)); scaledOut emits t or a ramp colour.
    const sv = unary("sqrt", mcol(inputCol(b, "value")));
    const slo = unary("sqrt", fcol("lo"));
    const shi = unary("sqrt", fcol("hi"));
    return scaledOut(b, bin("/", bin("-", sv, slo), nullif0(bin("-", shi, slo))));
  },
  ticks: "nice-linear",
});
