// W2, TOTAL since decision §12.2: every relop's added column must carry a declared
// space, and the declaration must match spaceOf inference where the judgment can see
// (marks-col + cell + literal leaves). Fit-col reads are the documented residual: this
// pass has no fit schema (the running TypedSchema is check-plan's, W3), so equality on
// expressions reading the fit is deferred there — presence is still required.
// Under strict mode, violations throw; ill-typed expressions always throw.
import type { CellStore } from "../../ir/cell.js";
import type { OpSpec } from "../opspec.js";
import type { RelopPayload } from "../payloads.js";
import type { ScalarExpr } from "../../algebra/relop.js";
import type { SpaceEnv } from "../../algebra/space-of.js";
import { spaceOf } from "../../algebra/space-of.js";
import { dataSpace, spaceEq, showSpace, type Space } from "../../types/attr.js";
import { dvlSettings } from "../../config.js";

export interface SpaceViolation {
  readonly opId: string;
  readonly column: string;
  /** null = the column has NO declaration (a §12.2 violation in itself). */
  readonly declared: Space | null;
  readonly inferred: Space | null;
}

/** Does the expression read any fit column? (Equality is uncheckable here for those —
 *  the fit's schema lives in check-plan's running TypedSchema, not in this pass.) */
function readsFit(e: ScalarExpr): boolean {
  switch (e.k) {
    case "col": return e.src === "fit";
    case "bin": return readsFit(e.l) || readsFit(e.r);
    case "nullif0": case "unary": case "round": return readsFit(e.x);
    case "left": return readsFit(e.str) || readsFit(e.n);
    case "index": return readsFit(e.idx);
    case "concat": return e.parts.some(readsFit);
    default: return false; // lit/cell/rank/wsum/rownum/rand — no fit reads
  }
}

/** Verify every relop's outSpaces: PRESENCE for every added column (total, §12.2),
 *  plus declared-vs-inferred equality where the judgment can infer.
 *  Returns violations found; under strict, throws on the first. */
export function verifyRelopSpaces(specs: readonly OpSpec[], cells: CellStore): SpaceViolation[] {
  const violations: SpaceViolation[] = [];
  const env: SpaceEnv = {
    col(_name, _src) { return dataSpace; },
    cell(ref) { return cells.cellSpace(ref); },
  };

  for (const op of specs) {
    if (op.payload.kind !== "relop") continue;
    const p = op.payload as unknown as RelopPayload;
    if (p.source !== undefined) continue; // source relops (values/unit) have no expressions to check

    for (const [col, expr] of Object.entries(p.add)) {
      const declared = p.outSpaces?.[col];
      if (declared === undefined) {
        // TOTALITY (§12.2): an added column with no declared space is itself a violation —
        // silence was the demo-blank bug's shape; it is never a declaration.
        const v: SpaceViolation = { opId: op.id, column: col, declared: null, inferred: null };
        violations.push(v);
        if (dvlSettings.strict) throw new Error(`verify-spaces: ${op.id} adds column "${col}" with no declared space (§12.2 — every relop output declares)`);
        continue;
      }
      if (readsFit(expr)) continue; // equality deferred to check-plan's running TypedSchema (W3)
      const inferred = spaceOf(expr, env);
      if (inferred === null) {
        const v: SpaceViolation = { opId: op.id, column: col, declared, inferred: null };
        violations.push(v);
        if (dvlSettings.strict) throw new Error(`verify-spaces: ${op.id} column "${col}" is ill-typed under the judgment`);
        continue;
      }
      // §6 colour validation: a style⟨color⟩ output whose value is NOT a colour (a raw number on a
      // colour channel — the old `fill: linear` type-lie, or a numeric literal) is ALWAYS an error,
      // never a lax warning. A colour scale emits `index(palette,…)` → style⟨color⟩; this fires only
      // on a genuine non-colour value the judgment can see (fit-reading exprs defer to check-plan).
      if (declared.space === "style" && declared.channel === "color" && !(inferred.space === "style" && inferred.channel === "color")) {
        throw new Error(`verify-spaces: ${op.id} column "${col}" is a colour channel but computes ${showSpace(inferred)} — bind a colour scale (value → colour), not a raw number`);
      }
      if (!spaceEq(declared, inferred)) {
        const v: SpaceViolation = { opId: op.id, column: col, declared, inferred };
        violations.push(v);
        if (dvlSettings.strict) {
          throw new Error(`verify-spaces: ${op.id} column "${col}" declares ${showSpace(declared)} but computes ${showSpace(inferred)}`);
        }
      }
    }
  }
  return violations;
}
