// THE frame affine — the unique relative→pixel coercion (reorg §9 layout/frame.ts; §12.1).
// Inserted by the plot compiler as a crossing at the relative→pixel space mismatch: one pass
// per (plot, axis) over the collected mismatch columns (coord = offset+scale, len = scale-only),
// reading the extent side cells. Placement is generic — any relative coord/len column is placed
// here, regardless of which producer emitted it. A TEMPLATE plot places per CELL; a scalar or
// parent-level plot uses the node's content edges. Both boxes are ONE relop shape —
// replace-derive (P4b) over lo + (hi−lo)·t, differing only in where lo/hi COME FROM: the scalar
// box reads the node's extent cells (P4a cell leaves, bound per fixpoint iteration); the keyed
// box derives them from the host's placed row (P4d join on dvl_cell = host.dvl_mark; fcol = the
// joined alias) inset by the node's inset cells.
import type { SqlType } from "../data/schema.js";
import type { PlotId } from "../types/ids.js";
import { bin, cell, fcol, lit, mcol, unary, type ScalarExpr } from "../algebra/relop.js";
import { coord, len, pixelSpace, type Space } from "../types/attr.js";
import type { CellRef, CellStore } from "../ir/cell.js";
import type { OpSpec } from "../plan/opspec.js";
import type { TemplateCtx } from "../plan/compile/context.js";

/** A relative column awaiting placement, tagged with its producing scale's expansion cells
 *  (scale-expansion §4). A column with `exp` lerps the slack-compressed box
 *  [lo + span·e₀, hi − span·e₁]; a column without (relative literals — axis rules/baselines,
 *  authored frame fractions) lerps the frame box itself. */
export interface PlacedCol { name: string; exp?: { lo: CellRef; hi: CellRef }; }

const affineRelop = (key: string, tag: string, axis: "x" | "y", cols: { coords: PlacedCol[]; lens: PlacedCol[] }, lo: ScalarExpr, hi: ScalarExpr): { add: Record<string, ScalarExpr>; outTypes: Record<string, SqlType>; outSpaces: Record<string, Space>; key: string; tag: string; kind: "relop"; replace: true } => {
    const span = bin("-", hi, lo);
    // The column's own box: the frame box, compressed by its scale's expansion cells when present.
    // t′ = e₀ + t·(1−e₀−e₁) realized as lo′ = lo + span·e₀, hi′ = hi − span·e₁ — sign-correct on
    // the flipped y axis because span carries the direction.
    const boxOf = (c: PlacedCol): { lo: ScalarExpr; hi: ScalarExpr; span: ScalarExpr } => {
      if (c.exp === undefined) return { lo, hi, span };
      const loC = bin("+", lo, bin("*", span, cell(c.exp.lo)));
      const hiC = bin("-", hi, bin("*", span, cell(c.exp.hi)));
      return { lo: loC, hi: hiC, span: bin("-", hiC, loC) };
    };
    const add: Record<string, ScalarExpr> = {};
    const outTypes: Record<string, SqlType> = {};
    // The affine IS the relative→pixel coercion: its outSpaces re-declare (via replace) the placed
    // columns as pixel. THIS declaration — never the tag string — is how a plan pass finds affines
    // (the typed question: which relops flip relative→pixel).
    const outSpaces: Record<string, Space> = {};
    for (const c of cols.coords) { const b = boxOf(c); add[c.name] = bin("+", b.lo, bin("*", b.span, mcol(c.name))); outTypes[c.name] = "double"; outSpaces[c.name] = pixelSpace(coord(axis)); }
    for (const l of cols.lens) { const b = boxOf(l); add[l.name] = bin("*", unary("abs", b.span), mcol(l.name)); outTypes[l.name] = "double"; outSpaces[l.name] = pixelSpace(len(axis)); }
    return { kind: "relop", key, add, outTypes, outSpaces, replace: true, tag };
  };

/** The expansion cells a column set reads (dedup) — they join the op's `reads` so the scheduler
 *  sees the overhang→affine cycle; emit() binds the {ref} holes per sweep, as with extent cells. */
const expReads = (cols: { coords: PlacedCol[]; lens: PlacedCol[] }): CellRef[] => {
  const out = new Set<CellRef>();
  for (const c of [...cols.coords, ...cols.lens]) if (c.exp !== undefined) { out.add(c.exp.lo); out.add(c.exp.hi); }
  return [...out];
};

/** Emit the per-(plot,axis) affine crossings over the collected relative columns; returns the
 *  final placed-marks cell. Called by the plot compiler at the space mismatch (§12.1). */
export function emitFrameAffines(args: {
  plotId: PlotId;
  relByAxis: ReadonlyMap<"x" | "y", { coords: PlacedCol[]; lens: PlacedCol[] }>;
  template: TemplateCtx | undefined;
  insets: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef } | undefined;
  cc: { left: CellRef; right: CellRef; top: CellRef; bottom: CellRef };
  store: CellStore;
  specs: OpSpec[];
  marks: CellRef;
  /** Inner data inset (px), root-level only — shrinks the relative→pixel range so marks sit off
   *  the frame edge (Plot's `inset`; the canvas option). Frame-level and literal by design; the
   *  mark-extent slack is per-scale expansion on the COLUMNS, never this. */
  dataInset?: { left: number; right: number; top: number; bottom: number };
}): CellRef {
  const { plotId, relByAxis, template, cc, store, specs, dataInset } = args;
  let marks = args.marks;
  for (const [axis, cols] of relByAxis) {
    const placed = store.alloc("marks", undefined, "relation");
    if (template !== undefined) {
      // P4e: the keyed box — each row lerps into its OWN cell's box (host placed marks ⋈ dvl_cell).
      // x: [h.x + insetLo, h.x + h.w − insetHi]; y flips: [h.y + h.h − insetLo, h.y + insetHi].
      const ins = args.insets!;
      const [insetLo, insetHi] = axis === "x" ? [ins.left, ins.right] : [ins.bottom, ins.top];
      const [lo, hi] = axis === "x"
        ? [bin("+", fcol("x"), cell(insetLo)), bin("-", bin("+", fcol("x"), fcol("w")), cell(insetHi))]
        : [bin("-", bin("+", fcol("y"), fcol("h")), cell(insetLo)), bin("+", fcol("y"), cell(insetHi))];
      specs.push({
        id: `${plotId}:affine:${axis}`,
        reads: [marks, template.hostMarks, insetLo, insetHi, ...expReads(cols)],
        writes: [placed],
        payload: { ...affineRelop(`${plotId}:aff:${axis}`, `affine-k:${axis}`, axis, cols, lo, hi), join: { input: "host", on: [["dvl_cell", "dvl_mark"]] } },
      });
    } else {
      // P4c: the scalar box — lo/hi are the node's content-edge cells; span = hi − lo stays INLINE
      // in the algebra (no staging cell). The extent cells stay in `reads` for scheduling but their
      // VALUES never bake into folded SQL — emit() binds the {ref} holes per fixpoint iteration.
      const [loC, hiC] = axis === "x" ? ([cc.left, cc.right] as const) : ([cc.bottom, cc.top] as const);
      // Data inset (px): x → [left+insL, right−insR]; y flips → [bottom−insB, top+insT].
      const [insLo, insHi] = axis === "x" ? [dataInset?.left ?? 0, dataInset?.right ?? 0] : [dataInset?.bottom ?? 0, dataInset?.top ?? 0];
      const lo = insLo !== 0 ? bin(axis === "x" ? "+" : "-", cell(loC), lit(insLo)) : cell(loC);
      const hi = insHi !== 0 ? bin(axis === "x" ? "-" : "+", cell(hiC), lit(insHi)) : cell(hiC);
      specs.push({ id: `${plotId}:affine:${axis}`, reads: [marks, loC, hiC, ...expReads(cols)], writes: [placed], payload: affineRelop(`${plotId}:aff:${axis}`, `affine:${axis}`, axis, cols, lo, hi) });
    }
    marks = placed;
  }
  return marks;
}
