// Walk a scene graph → SVG. Each mark's geometry comes from its OWN `draw`; this just walks,
// groups, and supplies the SvgPen. Adding a mark type never touches this file. The lookup is
// STRUCTURAL ({ get(name) }) — a Registry<MarkDescriptor> satisfies it, and so does the
// resolve-once map render-op builds from the spec's resolvedMark descriptors.
//
// ⚠️ PROVISIONAL — minimal C3 scaffold (see render/index.ts).
import type { MarkDescriptor } from "../ir/mark.js";
import { DVL_FONT_FAMILY } from "../ir/pen.js";
import type { SceneGraph } from "./scene.js";
import { SvgPen } from "./svg-pen.js";

export function render(scene: SceneGraph, marks: { get(name: string): MarkDescriptor }): string {
  const parts: string[] = [];

  for (const f of scene.frames) {
    if (f.background !== undefined) {
      parts.push(`<rect x="${f.drawable.x}" y="${f.drawable.y}" width="${f.drawable.w}" height="${f.drawable.h}" fill="${f.background}"/>`);
    }
  }

  for (const m of scene.marks) {
    const desc = marks.get(m.markType); // throws "not registered: X" for unknown marks
    if (desc.draw === undefined) throw new Error(`render: mark "${m.markType}" has no draw (not renderable yet)`);
    const pen = new SvgPen();
    for (const row of m.rows) desc.draw(row, pen);
    parts.push(`<g data-dvl-plot="${m.plot}">${pen.content()}</g>`);
  }

  // font-family on the ROOT: the output is self-contained — glyph metrics no longer depend on
  // whatever page the SVG lands in, so plot-measure's offscreen bboxes match the display exactly.
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${scene.width}" height="${scene.height}" font-family="${DVL_FONT_FAMILY}">${parts.join("")}</svg>`;
}
