// stack: weights → stacked segments. Each mark occupies [cumsum−weight, cumsum] of its GROUP's
// total, normalized to [0,1] (the frame maps t → pixels): y (segment TOP) = cumsum/total,
// h (height) = weight/total. A percent-stack per group; with no group, one stack of all rows
// (which is also the absolute stack). Cumulative + total are WINDOWED sums (wsum) — the same
// window family as rank, no new abstraction; the axis-agnostic `col`/`eqx` shape.
//
// Inputs: weight (required), group (optional PARTITION — the x category the bars stack within),
// order (optional stacking order; default = weight, largest last). All are marks columns:
//   stack({ weight: "value", group: "category", order: "series" }).pick("y", "h")
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, mcol, nullif0, wsum } from "../../algebra/relop.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const stackY = op({
  name: "stackY",
  // No domain: no trained fit (apply-only) — output is within-group relative shares in [0,1].
  // A percent axis over it would need an explicit unit-domain feature, not a declaration.
  inputs: { marks: [{ name: "weight", type: "double" }, { name: "group", type: "unknown" }, { name: "order", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "y", type: "double" }, { name: "h", type: "double" }] },
  outSpaces: { y: relativeSpace(coord("y")), h: relativeSpace(len("y")) },
  inputSpaces: { weight: dataSpace },
  apply: (b): RelOp => {
    const [yo, ho] = b.outputs;
    const w = inputCol(b, "value"); // primary input = the weight
    const partition = typeof b.inputs.group === "string" ? b.inputs.group : undefined;
    const order = typeof b.inputs.order === "string" ? b.inputs.order : w; // default: stack by weight
    const cumsum = wsum(w, { partition, order }); // running total up to & incl. this row
    const total = wsum(w, { partition }); // the group's full sum (the normalizer)
    return {
      kind: "derive",
      add: { [yo]: bin("/", cumsum, nullif0(total)), [ho]: bin("/", mcol(w), nullif0(total)) },
      outTypes: { [yo]: "double", [ho]: "double" },
    };
  },
});
