// Authoring helpers (WUIR_IMPL §3.2): `pick` (project a producer's named outputs into
// a splattable channel map) and `parseInputs` (the layout-input sugar ladder). The
// fluent builder (api/builder.ts, next) consumes both.
import { Table } from "../data/table.js";
import type { Expr } from "../ir/expr.js";
import type { Schema } from "../data/schema.js";
import type { TableRef } from "../ir/plot.js";
import type { Path, ResolvedPath } from "../ir/refs.js";

/** The slice of an operator's declaration the input sugar ladder needs: its name
 *  (for error messages) + its declared input roles (role → Schema). */
export interface InputsDecl {
  name: string;
  inputs: Record<string, Schema>;
}

// --- producers + pick ---

/** Anything with named outputs: a layout/scale instance, or a cross-mark via-ref. */
export interface Producer {
  readonly outputs: readonly string[];
  /** The channel-value Expr for a named output. */
  out(name: string): Expr;
  /** Project outputs into a channel map — identity `pick("x","y")`, rename `pick({x1:"x"})`, or
   *  `pick("*")` / bare `pick()` for ALL outputs (each under its own name). */
  pick(first?: "*" | string | Record<string, string>, ...rest: string[]): Record<string, Expr>;
}

/** A PLOT-referent via producer that EXPOSES its declaration — what `frame:` consumes (§7d of
 *  the perCell explainer): the referent plot and the authored join path. Table.via stays a
 *  plain Producer — a table referent has no cell, so it is statically invalid as a frame. */
export interface ViaHandle extends Producer {
  readonly via: { readonly plot: string; readonly on: Path };
}

/** Build a Producer from its output names + an output→Expr function (adds `pick`). `wildcard`
 *  is the set `pick("*")`/bare `pick()` expands to (defaults to all `outputs`; a via passes its
 *  borrowable set MINUS the internal dvl_cell). */
export function producer(outputs: readonly string[], out: (name: string) => Expr, wildcard: readonly string[] = outputs): Producer {
  return {
    outputs,
    out,
    pick(first, ...rest) {
      const result: Record<string, Expr> = {};
      if (first === undefined || first === "*") {
        for (const name of wildcard) result[name] = out(name);
      } else if (typeof first === "object") {
        for (const [channel, source] of Object.entries(first)) result[channel] = out(source);
      } else {
        for (const name of [first, ...rest]) result[name] = out(name);
      }
      return result;
    },
  };
}

// --- the layout-input sugar ladder ---

export interface InputBinding {
  relation: TableRef;
  project?: Record<string, string | Expr>; // reconcile rename (string) or computed (Expr)
  on?: Path; // override the operator's declared `refs` (aux ⇢ marks) — resolved by resolveSpec
  resolvedOn?: ResolvedPath; // stamped by resolveSpec; compile reads pairs off this
}

const isRelation = (v: unknown): v is TableRef => typeof v === "string" || v instanceof Table;

/**
 * Resolve the authoring arg against a descriptor's declared roles into a per-role
 * binding (WUIR_IMPL §3.2). `marks` binds to `marksRelation` (the host plot's source).
 * Predicate→relation inference for the single-aux predicate sugar (`force({from,to})`)
 * is deferred to the builder/resolve step; here the aux relation is explicit.
 */
export function parseInputs(desc: InputsDecl, arg: unknown, marksRelation: TableRef): Record<string, InputBinding> {
  const roles = Object.keys(desc.inputs);
  const aux = roles.filter((r) => r !== "marks");
  const marksCols = (desc.inputs.marks ?? []).map((c) => c.name);

  // NO argument: the marks binding alone, unprojected — finalizeLayout's natural-join default
  // then binds each declared input by its own name (a refine layout reading the mark's channels:
  // fitText() consumes the text/w/h the mark draws). Aux roles have no such default.
  if (arg === undefined) {
    if (aux.length > 0) throw new Error(`${desc.name}: missing input (an aux role has no natural-join default)`);
    return marksCols.length > 0 ? { marks: { relation: marksRelation } } : {};
  }

  // positional: a string / string[] of marks columns (marks-only layouts), or a bare aux relation
  if (typeof arg === "string" || (Array.isArray(arg) && arg.every((a) => typeof a === "string"))) {
    const cols = typeof arg === "string" ? [arg] : (arg as string[]);
    if (aux.length === 0) {
      const project: Record<string, string> = {};
      cols.forEach((c, i) => {
        const target = marksCols[i];
        if (target === undefined) throw new Error(`${desc.name}: too many positional inputs`);
        project[target] = c;
      });
      return { marks: { relation: marksRelation, project } };
    }
    if (aux.length === 1 && typeof arg === "string") return withMarks(aux[0], { relation: arg }, marksRelation, marksCols);
    throw new Error(`${desc.name}: ambiguous positional input`);
  }

  // a Table instance → the sole aux relation
  if (arg instanceof Table) {
    if (aux.length === 1) return withMarks(aux[0], { relation: arg }, marksRelation, marksCols);
    throw new Error(`${desc.name}: a bare relation needs exactly one aux role`);
  }

  if (typeof arg === "object" && arg !== null) {
    const a = arg as Record<string, unknown>;
    const keys = Object.keys(a);

    // full / multi-relation form: keys are relation roles
    if (keys.length > 0 && keys.every((k) => roles.includes(k))) {
      const inputs: Record<string, InputBinding> = {};
      for (const k of keys) inputs[k] = asBinding(a[k], k === "marks" ? marksRelation : undefined);
      if (!("marks" in a) && marksCols.length > 0) inputs.marks = { relation: marksRelation };
      return inputs;
    }

    // marks-only project sugar: keys are marks columns
    if (aux.length === 0 && keys.every((k) => marksCols.includes(k))) {
      return { marks: { relation: marksRelation, project: a as Record<string, string | Expr> } };
    }

    throw new Error(`${desc.name}: unknown role or column in {${keys.join(", ")}}`);
  }

  throw new Error(`${desc.name}: invalid input argument`);
}

/** Add an implicit `marks` binding (the host plot's source) alongside an aux binding. */
function withMarks(auxRole: string, aux: InputBinding, marksRelation: TableRef, marksCols: readonly string[]): Record<string, InputBinding> {
  const out: Record<string, InputBinding> = { [auxRole]: aux };
  if (marksCols.length > 0) out.marks = { relation: marksRelation };
  return out;
}

function asBinding(v: unknown, fallbackRelation?: TableRef): InputBinding {
  if (isRelation(v)) return { relation: v };
  if (typeof v === "object" && v !== null && "relation" in v) return v as InputBinding;
  if (fallbackRelation !== undefined) return { relation: fallbackRelation, project: v as Record<string, string | Expr> };
  throw new Error(`input binding needs a relation`);
}
