// The Expr union (the channel-value language) + constructors + type/resolution
// derivation + traversal (WUIR_IMPL §1.3). Every node carries its logical
// ExprType; resolution is derived (a leaf scan). Affine dimensional analysis lives
// in binaryType — delegating to spaceArith (types/judgment.ts).
import type { Scalar } from "../data/schema.js";
import type { ExprType } from "./types.js";
import { dataSpace, type Space } from "../types/attr.js";
import { spaceArith, type ArithOp } from "../types/judgment.js";
import { showSpace } from "../types/attr.js";
import type { LayoutId } from "../types/ids.js";
import type { CellRef, CellRole } from "./cell.js";
import type { AggOp, BoundRefExpr, Path, TableRefExpr, ViaResolve } from "./refs.js";
import { FUNCTIONS } from "../algebra/functions.js";

export type BinaryOp = "+" | "-" | "*" | "/" | "%";

export interface LiteralExpr { kind: "literal"; type: ExprType; value: Scalar; }
export interface LocalColumnExpr { kind: "local-column"; type: ExprType; columnName: string; }
export interface AggExpr { kind: "agg"; type: ExprType; op: AggOp; ref: TableRefExpr; }
export interface LayoutOutputExpr { kind: "layout-output"; type: ExprType; layout: LayoutId; output: string; }
export interface BinaryExpr { kind: "binary"; type: ExprType; op: BinaryOp; left: Expr; right: Expr; }
export interface CallExpr { kind: "call"; type: ExprType; fn: string; args: Expr[]; }
export type VarCellRole = Extract<CellRole, "extent" | "demand" | "param" | "range" | "domain">;

export interface VarExpr {
  kind: "var";
  type: ExprType;
  role: VarCellRole;
  cell: CellRef;
}

export type Expr =
  | LiteralExpr
  | LocalColumnExpr
  | BoundRefExpr
  | TableRefExpr
  | AggExpr
  | LayoutOutputExpr
  | BinaryExpr
  | CallExpr
  | VarExpr;

export type Resolution = "literal" | "data" | "solver";

// ---- constructors ----
export const literal = (value: Scalar, space: Space = dataSpace, arity: "scalar" | "per-row" = "scalar"): LiteralExpr => ({ kind: "literal", type: { space, arity }, value });
export const col = (columnName: string, space: Space = dataSpace): LocalColumnExpr => ({ kind: "local-column", type: { space, arity: "per-row" }, columnName });
export const layoutOutput = (layout: LayoutId, output: string, type: ExprType): LayoutOutputExpr => ({ kind: "layout-output", type, layout, output });
export const agg = (op: AggOp, ref: TableRefExpr, space: Space = dataSpace): AggExpr => ({ kind: "agg", type: { space, arity: "scalar" }, op, ref });
export const boundRef = (tableName: string, columnName: string, viaSpec: Path, type: ExprType, resolve?: ViaResolve): BoundRefExpr => ({ kind: "bound-ref", type, tableName, columnName, viaSpec, ...(resolve !== undefined && { resolve }) });
export const tableRef = (plotId: LayoutId, attrName: string, viaSpec: Path, type: ExprType, resolve?: ViaResolve): TableRefExpr => ({ kind: "table-ref", type, plotId, attrName, viaSpec, ...(resolve !== undefined && { resolve }) });
export const variable = (space: Space, role: VarCellRole, cell: CellRef): VarExpr => ({ kind: "var", type: { space, arity: "scalar" }, role, cell });
export const binary = (op: BinaryOp, left: Expr, right: Expr): BinaryExpr => ({ kind: "binary", type: binaryType(op, left.type, right.type), op, left, right });
// A registered function call (algebra/functions.ts) over channel Expr args — DATA space by
// construction (functions produce values, never geometry; a scale re-spaces if it consumes one).
export const callExpr = (fn: string, args: Expr[]): CallExpr => ({ kind: "call", type: { space: dataSpace, arity: args.some((a) => a.type.arity === "per-row") ? "per-row" : "scalar" }, fn, args });

// ---- derivation ----
/** O(1): every node stores its type (binary computed at construction). */
export function typeOf(e: Expr): ExprType {
  return e.type;
}

/** Visit every node; `binary` and `call` are composite, so recurse their operands/args. */
export function walk(e: Expr, visit: (e: Expr) => void): void {
  visit(e);
  if (e.kind === "binary") {
    walk(e.left, visit);
    walk(e.right, visit);
  } else if (e.kind === "call") {
    for (const a of e.args) walk(a, visit);
  }
}

const RANK: Record<Resolution, number> = { literal: 0, data: 1, solver: 2 };

/** Max over leaves: solver > data > literal (WUNOUNS §Channel spec). */
export function resolutionOf(e: Expr): Resolution {
  let r: Resolution = "literal";
  walk(e, (n) => {
    const lr: Resolution = n.kind === "var" ? "solver" : n.kind === "literal" || n.kind === "binary" || n.kind === "call" ? "literal" : "data";
    if (RANK[lr] > RANK[r]) r = lr;
  });
  return r;
}

/** Dependency-extraction surface for C5: data leaves → producer edges; solver leaves → fixpoint cells. */
export function leaves(e: Expr): { data: Expr[]; solver: VarExpr[] } {
  const data: Expr[] = [];
  const solver: VarExpr[] = [];
  walk(e, (n) => {
    if (n.kind === "var") solver.push(n);
    else if (n.kind !== "literal" && n.kind !== "binary" && n.kind !== "call") data.push(n);
  });
  return { data, solver };
}

// ---- affine dimensional analysis (delegates to spaceArith; the static check) ----
export function binaryType(op: BinaryOp, l: ExprType, r: ExprType): ExprType {
  const arity: "scalar" | "per-row" = l.arity === "per-row" || r.arity === "per-row" ? "per-row" : "scalar";
  // Modulo is not a spatial operation — same-space passthrough when both match, else data.
  if (op === "%") {
    const space = l.space.space === r.space.space ? l.space : dataSpace;
    return { space, arity };
  }
  const space = spaceArith(op as ArithOp, l.space, r.space);
  if (space === null) throw new Error(`ill-typed: ${showSpace(l.space)} ${op} ${showSpace(r.space)}`);
  return { space, arity };
}

// ---- cexpr: a tagged template for channel `Expr` arithmetic ----------------------------------
// The channel-value twin of algebra/expr-template's `expr` (which builds ScalarExpr). Same infix
// grammar, different tree: every leaf is a channel `Expr`, so a cexpr result is HOMOGENEOUS by
// construction and never mixes with the ScalarExpr world. Bare identifiers are COLUMN reads
// (`col`), bare numbers are `literal`s, and `${…}` splices any channel `Expr` leaf:
//
//   cexpr`x + dx`                       // binary("+", col("x"), col("dx"))
//   cexpr`${col("x")} + ${col("dx")}`   // the same tree, explicit leaves
//   x(cexpr`x + dx`)                     // feed the sum through a scale
//
// Operators `+ - * / %` with standard precedence (`* / %` bind tighter than `+ -`); parentheses
// group. Identifiers are COLUMN reads unless immediately applied — `sqrt(body_mass_g)` is a
// registered function CALL (algebra/functions.ts), validated (existence + arity) at parse.
const CPREC: Record<string, number> = { "+": 1, "-": 1, "*": 2, "/": 2, "%": 2 };

type CToken = { kind: "expr"; value: Expr } | { kind: "word"; name: string } | { kind: "op"; value: BinaryOp } | { kind: "(" } | { kind: ")" } | { kind: "," };

function cTokenize(strings: TemplateStringsArray, exprs: Expr[]): CToken[] {
  const tokens: CToken[] = [];
  const isDigit = (c: string) => (c >= "0" && c <= "9") || c === ".";
  const isWordStart = (c: string) => (c >= "a" && c <= "z") || (c >= "A" && c <= "Z") || c === "_";
  const isWord = (c: string) => isWordStart(c) || (c >= "0" && c <= "9");
  for (let i = 0; i < strings.length; i++) {
    const s = strings[i];
    let j = 0;
    while (j < s.length) {
      const ch = s[j];
      if (ch === " " || ch === "\t" || ch === "\n") { j++; continue; }
      if (ch === "(") { tokens.push({ kind: "(" }); j++; continue; }
      if (ch === ")") { tokens.push({ kind: ")" }); j++; continue; }
      if (ch === ",") { tokens.push({ kind: "," }); j++; continue; }
      if (ch === "+" || ch === "-" || ch === "*" || ch === "/" || ch === "%") {
        // unary minus → a negative number literal, only at the start of an operand position
        if (ch === "-" && (tokens.length === 0 || tokens[tokens.length - 1].kind === "(" || tokens[tokens.length - 1].kind === "op" || tokens[tokens.length - 1].kind === ",")) {
          let end = j + 1;
          while (end < s.length && isDigit(s[end])) end++;
          if (end > j + 1) { tokens.push({ kind: "expr", value: literal(parseFloat(s.slice(j, end))) }); j = end; continue; }
        }
        tokens.push({ kind: "op", value: ch as BinaryOp }); j++; continue;
      }
      if (isDigit(ch)) {
        let end = j;
        while (end < s.length && isDigit(s[end])) end++;
        tokens.push({ kind: "expr", value: literal(parseFloat(s.slice(j, end))) }); j = end; continue;
      }
      if (isWordStart(ch)) {
        // a bare identifier: the PARSER decides column vs function call (by the following token)
        let end = j;
        while (end < s.length && isWord(s[end])) end++;
        tokens.push({ kind: "word", name: s.slice(j, end) }); j = end; continue;
      }
      throw new Error(`cexpr: unexpected char '${ch}'`);
    }
    if (i < exprs.length) tokens.push({ kind: "expr", value: exprs[i] });
  }
  return tokens;
}

function cParse(tokens: CToken[]): Expr {
  let pos = 0;
  const peek = (): CToken | undefined => tokens[pos];
  const advance = (): CToken => tokens[pos++];
  const atom = (): Expr => {
    const t = peek();
    if (!t) throw new Error("cexpr: unexpected end of expression");
    if (t.kind === "expr") { advance(); return t.value; }
    if (t.kind === "word") {
      advance();
      if (peek()?.kind === "(") { // a function CALL: name(arg, …)
        advance();
        const args: Expr[] = [];
        if (peek()?.kind !== ")") {
          args.push(parseExpr(0));
          while (peek()?.kind === ",") { advance(); args.push(parseExpr(0)); }
        }
        const cl = advance();
        if (!cl || cl.kind !== ")") throw new Error(`cexpr: expected ')' after ${t.name}(…`);
        const def = FUNCTIONS[t.name];
        if (def === undefined) throw new Error(`cexpr: unknown function "${t.name}" (see algebra/functions.ts for the registry)`);
        if (def.arity !== args.length) throw new Error(`cexpr: "${t.name}" takes ${def.arity} argument(s), got ${args.length}`);
        return callExpr(t.name, args);
      }
      return col(t.name); // a bare identifier is a column read
    }
    if (t.kind === "(") {
      advance();
      const inner = parseExpr(0);
      const cl = advance();
      if (!cl || cl.kind !== ")") throw new Error("cexpr: expected ')'");
      return inner;
    }
    throw new Error(`cexpr: unexpected token ${JSON.stringify(t)}`);
  };
  function parseExpr(minPrec: number): Expr {
    let left = atom();
    for (let t = peek(); t && t.kind === "op" && CPREC[t.value] > minPrec; t = peek()) {
      advance();
      left = binary(t.value, left, parseExpr(CPREC[t.value]));
    }
    return left;
  }
  const result = parseExpr(0);
  if (pos < tokens.length) throw new Error(`cexpr: unexpected tokens after expression at position ${pos}`);
  return result;
}

/** Tagged template building a channel `Expr` arithmetic tree — the channel-value twin of the
 *  ScalarExpr `expr` template. Bare identifiers → `col`, bare numbers → `literal`, `${…}` splices
 *  a channel `Expr`; `+ - * / %` with standard precedence and parentheses. Every leaf is a channel
 *  `Expr`, so the tree never mixes with the ScalarExpr world. `binary()` types each node as it is
 *  built, so an ill-typed space combination throws here, at authoring time. */
export function cexpr(strings: TemplateStringsArray, ...values: Expr[]): Expr {
  return cParse(cTokenize(strings, values));
}
