// --- scale factories (descriptors + algorithms live in components/scales) ---

const SCALE_KINDS = ["linear", "log", "sqrt", "pow", "symlog", "ordinal", "point", "color", "quantize", "threshold"] as const;
export type ScaleKind = (typeof SCALE_KINDS)[number];

/** A pending scale binding — finalized (Scale instance + contextual-dim output) when bound to a channel. */
export interface ScaleSpec {
  readonly __scale: "scale";
  descriptor: string;
  arg: unknown; // the column(s) — parseInputs against the scale descriptor
  params: Record<string, Expr>;
  shared?: boolean; // facet: global vs per-cell domain
  side?: "top" | "right" | "bottom" | "left"; // positional: PIN the axis side (else assignSides places it)
  treatment?: DomainTreatment; // the domain treatment (modeling choice — recorded API intent, §12 S6)
  axis?: AxisOptions | false; // VL-style axis config on the encoding (WUAXIS §1b); false hides the axis
  expand?: number | [number, number] | false; // containment slack (scale-expansion §4): 0/false opts out; number/[lo,hi] pins (relative fractions); unset = solved
}

/** A deferred-column binding: pairs a ScaleSpec identity with a per-channel column. */
export interface ColumnBinding {
  readonly __columnBinding: "column-binding";
  readonly scale: ScaleSpec;
  readonly column: string;
}
export const isColumnBinding = (v: unknown): v is ColumnBinding =>
  typeof v === "object" && v !== null && (v as any).__columnBinding === "column-binding";

/** A datum binding: a LITERAL in the scale's DOMAIN — `y(4000)` places the data value 4000
 *  through S. It IS a 1-row, 1-column values relation bound as an ordinary column member (§A2),
 *  so it TRAINS the domain like any member (a no-op when interior; keeps an exterior annotation
 *  visible) and applies through the standard member path. Opt out of training with apply-only. */
export interface DatumBinding {
  readonly __datumBinding: "datum-binding";
  readonly scale: ScaleSpec;
  readonly datum: number | string | boolean;
}
export const isDatumBinding = (v: unknown): v is DatumBinding =>
  typeof v === "object" && v !== null && (v as any).__datumBinding === "datum-binding";

/** An EXPRESSION binding: a scale applied to a data-space per-row expression — `x(col("a") +
 *  col("b"))`. The general form of a column binding (a bare column IS the degenerate expr, kept as a
 *  ColumnBinding for efficiency). The scale trains + applies over the derived quantity: the expression
 *  is materialized as a base projection (Plot.baseProjections) and the scale binds the minted column,
 *  so nothing downstream special-cases it. A datum (`x(4000)`) is a LITERAL, not this. */
export interface ExprBinding {
  readonly __exprBinding: "expr-binding";
  readonly scale: ScaleSpec;
  readonly expr: Expr;
}
export const isExprBinding = (v: unknown): v is ExprBinding =>
  typeof v === "object" && v !== null && (v as any).__exprBinding === "expr-binding";
/** A built channel Expr (col / binary / …): an object carrying `kind` + `type`. */
const isChannelExpr = (v: unknown): v is Expr => typeof v === "object" && v !== null && "kind" in v && "type" in v;
// --- the two value wrappers (triage §5b): the ONLY meanings a bare value can take -----------
// A marker carries only its argument and NO type — it is typed at bindChannel, the single place
// a bare value acquires a space, because the axis/direction come from the channel it lands on.
// Expression algebra type-checks at construction (before any channel exists), so a marker may
// not appear inside an expression; for expression positions use the space-explicit column form
// (`col(name, pixelSpace(...))`, the px.x/px.y/px.w/px.h readers below).

/** Pixel wrapper: `px(12)` = 12 screen pixels on whichever channel it lands on; `px("col")` =
 *  read the column as pixels (skips the scale and the frame placement). */
export interface PxMarker { readonly __px: "px-marker"; readonly value: number | string; }
export const isPxMarker = (v: unknown): v is PxMarker =>
  typeof v === "object" && v !== null && (v as PxMarker).__px === "px-marker";

/** Data wrapper: `lit(0)` = the data value 0 — placed through the channel's axis scale, and the
 *  scale's domain grows to include it (the explicit spelling of what a bare position number
 *  means). Requires a scale on that axis; there is never a silent pixel fallback. */
export interface LitMarker { readonly __lit: "lit-marker"; readonly value: number | string | boolean; }
export const isLitMarker = (v: unknown): v is LitMarker =>
  typeof v === "object" && v !== null && (v as LitMarker).__lit === "lit-marker";

export const lit = (value: number | string | boolean): LitMarker => ({ __lit: "lit-marker", value });

/** `px` is callable (the marker) and carries the axis-explicit COLUMN readers as properties —
 *  the form expression algebra needs, since it types eagerly with no channel in sight. These
 *  replace the hand-built per-callsite `px.x/px.y/px.w/px.h` helper objects. */
export const px = Object.assign(
  (value: number | string): PxMarker => ({ __px: "px-marker", value }),
  {
    x: (c: string): Expr => col(c, pixelSpace(coord("x"))),
    y: (c: string): Expr => col(c, pixelSpace(coord("y"))),
    w: (c: string): Expr => col(c, pixelSpace(len("xy"))),
    h: (c: string): Expr => col(c, pixelSpace(len("xy"))),
  },
);

/** Per-scale options. `expand`: containment slack (scale-expansion §4) — default AUTO (solved
 *  from mark extents); `0`/`false` opts out; a number or [lo, hi] pins it (relative span fractions). */
type ScaleOpts = { shared?: boolean; side?: "top" | "right" | "bottom" | "left"; domain?: DomainTreatment; params?: Record<string, Expr>; axis?: AxisOptions | false; expand?: number | [number, number] | false };
export type DeferredScale = ScaleSpec & ((colDatumOrExpr: string | number | boolean | Expr) => ColumnBinding | DatumBinding | ExprBinding);

/** A scale factory: `kind()` (no data column) is DEFERRED — callable for per-channel columns
 *  (`S('col')`) and domain literals (`S(4000)`); `kind('col')` fits its domain to that column now. */
export interface ScaleCtor {
  (arg?: undefined, opts?: ScaleOpts): DeferredScale;
  (arg: string, opts?: ScaleOpts): ScaleSpec;
}

const scaleFactory =
  (kind: ScaleKind): ScaleCtor =>
  ((arg?: unknown, opts: ScaleOpts = {}): ScaleSpec | DeferredScale => {
    // a scale fitted to a literal has no data to train on — the datum form is `const S = kind(); S(v)`
    if (typeof arg === "number" || typeof arg === "boolean")
      throw new Error(`${kind}(${arg}): a scale cannot be fitted to a literal — bind a deferred scale to data (const S = ${kind}(); …{ y: S('col') }…), then S(${arg}) is a datum in its domain`);
    const spec: ScaleSpec = {
      __scale: "scale",
      descriptor: kind,
      arg,
      params: opts.params ?? {},
      shared: opts.shared,
      side: opts.side,
      treatment: opts.domain,
      axis: opts.axis,
      expand: opts.expand,
    };
    if (arg === undefined) {
      const deferred: DeferredScale = Object.assign(
        // string → a per-channel COLUMN; an Expr → a per-row DATA EXPRESSION (a bare `col` is just the
        // column); a bare number/string literal → a DATUM in the scale's domain.
        (colDatumOrExpr: string | number | boolean | Expr): ColumnBinding | DatumBinding | ExprBinding => {
          if (typeof colDatumOrExpr === "string") return { __columnBinding: "column-binding", scale: deferred, column: colDatumOrExpr };
          if (isChannelExpr(colDatumOrExpr)) {
            return colDatumOrExpr.kind === "local-column"
              ? { __columnBinding: "column-binding", scale: deferred, column: colDatumOrExpr.columnName } // x(col("a")) == x("a")
              : { __exprBinding: "expr-binding", scale: deferred, expr: colDatumOrExpr };
          }
          return { __datumBinding: "datum-binding", scale: deferred, datum: colDatumOrExpr };
        },
        spec,
      ) as DeferredScale;
      return deferred;
    }
    return spec;
  }) as ScaleCtor;
export const linear = scaleFactory("linear");
export const log = scaleFactory("log");
export const sqrt = scaleFactory("sqrt");
export const pow = scaleFactory("pow");
export const symlog = scaleFactory("symlog");
export const ordinal = scaleFactory("ordinal");
export const point = scaleFactory("point");
export const color = scaleFactory("color");
export const quantize = scaleFactory("quantize");
export const threshold = scaleFactory("threshold");

// --- layout factories (descriptors live in components/layouts) ---

/** A pending layout binding — finalized to ONE LayoutInstance when its outputs bind to a plot.
 *  `options` is static component config (padding, align, …) — the factory's 2nd arg; it rides onto
 *  the instance and into the apply/train binding (like a scale's `range`). */
export interface LayoutProducer {
  readonly __layout: "pending";
  descriptor: string;
  arg: unknown;
  params: Record<string, Expr>;
  options: Record<string, unknown>;
  out(name: string): PendingOutput;
  /** Spread the chosen outputs into a channels object. Forms:
   *   `.pick("x", "w")` — those outputs, each under its own name;
   *   `.pick({ x1: "x", y1: "y" })` — outputs under renamed channels;
   *   `.pick("*")` or `.pick()` — the layout's FULL declared output set (in TS use this form).
   *     Spreading the producer directly (`{ ...band("cat") }`) does the same at runtime — handy in the
   *     untyped playground — but TS sees the producer's methods, so `.pick("*")`/`.pick()` is the typed
   *     spelling. The wildcard is expanded to the real outputs at bind time (explicit channels win). */
  pick(first?: "*" | string | Record<string, string>, ...rest: string[]): Record<string, PendingOutput | PendingAll>;
}
export interface PendingOutput {
  readonly __out: "pending";
  producer: LayoutProducer;
  output: string;
}
/** A wildcard: "bind ALL of this layout's declared outputs". Emitted by `.pick("*")`/`.pick()` and by
 *  spreading a producer directly; `expandLayoutOutputs` (bind time) replaces it with the real outputs. */
export interface PendingAll {
  readonly __out: "pending-all";
  producer: LayoutProducer;
}

let layoutUid = 0;
const layoutFactory = (descriptor: string) => (arg: unknown, options: Record<string, unknown> = {}): LayoutProducer => {
  const wildKey = `__all:${++layoutUid}`; // unique per producer, so spreading two producers never collides
  const p = { __layout: "pending", descriptor, arg, params: {}, options } as unknown as LayoutProducer;
  const out = (name: string): PendingOutput => ({ __out: "pending", producer: p, output: name });
  const all: PendingAll = { __out: "pending-all", producer: p };
  const pick = (first?: "*" | string | Record<string, string>, ...rest: string[]): Record<string, PendingOutput | PendingAll> => {
    if (first === undefined || first === "*") return { [wildKey]: all }; // full output schema
    const r: Record<string, PendingOutput> = {};
    if (typeof first === "object") for (const [ch, src] of Object.entries(first)) r[ch] = out(src);
    else for (const name of [first, ...rest]) r[name] = out(name);
    return r;
  };
  Object.assign(p, { out, pick });
  // Make internals non-enumerable so `{ ...producer }` spreads ONLY the wildcard sentinel — i.e.
  // a bare spread == `.pick("*")` == the full output schema.
  for (const k of ["__layout", "descriptor", "arg", "params", "options", "out", "pick"]) Object.defineProperty(p, k, { enumerable: false });
  Object.defineProperty(p, wildKey, { value: all, enumerable: true });
  return p;
};
// Directional layouts use the <family><Axis> convention: X → {x,w}, Y → {y,h}.
/** grouped stacked segments (normalized): stackY → {y,h}, stackX → {x,w}; pick the two outputs. */
export const stackX = layoutFactory("stackX");
export const stackY = layoutFactory("stackY");
/** fixed-pitch bands (legend/list items): pitchY("cat", { pitch }).pick("y","h"); pitchX → {x,w}. */
export const pitchX = layoutFactory("pitchX");
export const pitchY = layoutFactory("pitchY");
/** equal split (facet driver): eqX → {x,w}, eqY → {y,h}. */
export const eqX = layoutFactory("eqX");
export const eqY = layoutFactory("eqY");
/** numeric → x + w proportional to value; pick("x","w"). */
export const proportionalX = layoutFactory("proportionalX");
/** numeric → y + h proportional to value; pick("y","h"). */
export const proportionalY = layoutFactory("proportionalY");
/** numeric → x + y + w + h via squarified treemap; pick("x","y","w","h"). */
export const treemap = layoutFactory("treemap");
/** Fit text to bounding box → fontSize + rotate + lines; pick("fontSize","rotate","lines").
 *  A REFINE layout consumes the mark's placed CHANNELS, so its inputs default to the same-named
 *  channel columns: `fitText()` sizes exactly the string the mark draws (the `text` channel —
 *  literal or column) against its `w`/`h` box. Name an input only to OVERRIDE (`{ text: 'label' }`).
 *  One bag: input keys (text/w/h) and option keys (maxFontSize/minFontSize/shared/rotate/wrap/
 *  padding) are disjoint, so `fitText({ rotate: true, maxFontSize: Infinity })` reads naturally;
 *  the two-arg `fitText({ text: 'label' }, { rotate: true })` form still works. */
const FIT_TEXT_INPUTS = new Set(["text", "w", "h"]);
export const fitText = (bag: Record<string, unknown> = {}, options: Record<string, unknown> = {}): LayoutProducer => {
  const inputs: Record<string, unknown> = {};
  const opts: Record<string, unknown> = { ...options };
  for (const [k, v] of Object.entries(bag)) (FIT_TEXT_INPUTS.has(k) ? inputs : opts)[k] = v;
  return layoutFactory("fitText")(Object.keys(inputs).length > 0 ? inputs : undefined, opts);
};
/** Edge routing (box-model §5 rev.): boundary attach for endpoint marks — a post-affine REFINE
 *  layout. `route({ src, dst })` takes the two endpoint via HANDLES (`nodes.via(eq(...))`); at
 *  bind, each expands into hidden borrow channels (the endpoint anchor + the referent's box
 *  edges riding the same join), and the layout's outputs ARE the final endpoints —
 *  `.pick("x1", "y1", "x2", "y2")`. A boxless referent degrades that endpoint to its anchor
 *  (center attachment); no route bound = today's center semantics. Options: `pad` (px standoff
 *  past the boundary — arrowhead gap), `shape`/`shape1`/`shape2` (boundary metric override;
 *  default = the referent mark's declared boundaryShape: ellipse for dots, box for rects). */
const ROUTE_INPUTS = new Set(["src", "dst"]);
export const route = (bag: Record<string, unknown>, options: Record<string, unknown> = {}): LayoutProducer => {
  const inputs: Record<string, unknown> = {};
  const opts: Record<string, unknown> = { ...options };
  for (const [k, v] of Object.entries(bag ?? {})) (ROUTE_INPUTS.has(k) ? inputs : opts)[k] = v;
  return layoutFactory("route")(inputs, opts);
};
/** categorical → evenly spaced bands: bandX → {x,w} (a bar's x), bandY → {y,h} (a horizontal bar's y).
 *  Options (D3/VL band): `paddingInner` (gap between bands, fraction of step [0,1)), `paddingOuter`
 *  (space before first / after last band), `padding` (sets both), `align` (outer-padding [0,1], default 0.5). */
export const bandX = layoutFactory("bandX");
export const bandY = layoutFactory("bandY");
/** value → bar from the baseline: barY → {y,h} (vertical bar top+height), barX → {x,w} (horizontal
 *  bar far-edge+width). Option `zero: true` anchors the domain at the baseline. */
export const barX = layoutFactory("barX");
export const barY = layoutFactory("barY");
export const force = layoutFactory("force");
/** layered DAG placement (Sugiyama-lite: longest-path layers, barycenter order, centered rows):
 *  dag(edges).pick("x","y") — edges is an aux relation with src/dst FKs onto the marks' id. */
export const dag = layoutFactory("dag");

export type ChannelValue = ScaleSpec | ColumnBinding | DatumBinding | ExprBinding | PendingOutput | PendingAll | Expr | PxMarker | LitMarker | number | string | boolean | null;

/** The builder context threaded through the DSL + the instantiation engine. */
export interface Ctx {
  spec: Spec;
  registries: Registries;
  width: number;
  height: number;
  /** ScaleSpec OBJECT → its equivalence class (§C6): reusing one spec object across binds is the
   *  authored "same quantity" — the explicit surface where name identity deliberately stops. */
  scaleEquiv?: Map<ScaleSpec, string>;
}

// --- handles ---

/** Every authorable form of a join path: a single predicate/FK hop, or a step array
 *  (eq/on/fk/path compose freely — `path()` returns PathStep[]). */
export type PathInput = PathStep | PathStep[];

export interface MarkOpts {
  key?: string;
  params?: PlotParams;
  on?: PathInput; // nest join (parent↔child): a predicate, an fk() hop, or a multi-hop path
  /** The FRAME ASSIGNMENT (owner semantics, perCell explainer §7d): which reference names the
   *  row's panel. NOT a boolean — the value is the via HANDLE (canonical: reuses the exact
   *  declared join) or the predicate/path itself (sugar: the referent is found at resolve).
   *  Top-level layers only — a nested layer's σ already assigns. */
  frame?: ViaHandle | PathInput;
  /** σ extension at a multi-path relation (NESTED layers only, §7d): 'panel' (default —
   *  conjoin the FK paths; a row belongs where ALL its paths land) or 'union' (any path
   *  admits; a row appears in every panel it touches). */
  scope?: "panel" | "union";
}

const isViaHandle = (v: unknown): v is ViaHandle => typeof v === "object" && v !== null && "via" in v && typeof (v as { via?: { plot?: unknown } }).via?.plot === "string";

const asPath = (on: PathInput): PathStep[] => (Array.isArray(on) ? on : [on]);

export class NodeBuilder {
  constructor(
    protected ctx: Ctx,
    readonly nodeId: NodeId,
  ) {}

  /** The built IR (read by tests / the scheduler). */
  get spec(): Spec {
    return this.ctx.spec;
  }
  get registries(): Registries {
    return this.ctx.registries;
  }
  get width(): number {
    return this.ctx.width;
  }
  get height(): number {
    return this.ctx.height;
  }
  validate(report?: Report): void {
    validate(this.ctx.spec, this.ctx.registries, report);
  }

  mark(markType: string, source: TableRef, channels: Record<string, ChannelValue>, opts?: MarkOpts): PlotBuilder {
    const desc = this.ctx.registries.marks.get(markType);
    const plotId = this.ctx.spec.ids.plot(this.nodeId, opts?.key);
    channels = expandLayoutOutputs(this.ctx, channels); // `.pick("*")` / bare-spread producer → all outputs
    desugarDataLiterals(desc, channels); // §5b: bare/lit() positional values → ExprBinding over the sibling axis scale
    desugarRouteInputs(this.ctx, channels); // box-model §5 rev.: route({src,dst}) via handles → hidden endpoint/box borrow channels
    // DATUM annotation (§A2 / README "the type system enumerates the cases"): a channel bound to
    // `S(datum)` makes this a standalone annotation whose data IS the literals. Back the plot with a
    // synthesized 1-row `values` source (one column per datum channel, named by the channel), so each
    // datum binds as an ORDINARY column over it — training + apply reuse the `S(attr)` path verbatim
    // and the datum trains the shared domain like any 1-row relation.
    // UNIT source: a single-row, single-column (`value`) table — rewrite to a synthesized `values`
    // producer (value 1 by default, or the scalar UNIT(v) carried). It anchors a mark that has no
    // table of its own (a `via(on("*"))` cross-product hull, a one-off annotation).
    let src: TableRef = isUnitSource(source) ? this.#unitSource(plotId, source.value) : source;
    const datumRow: Record<string, unknown> = {};
    for (const [ch, val] of Object.entries(channels)) if (isDatumBinding(val)) datumRow[ch] = val.datum;
    if (Object.keys(datumRow).length > 0) {
      const valuesId = this.ctx.spec.ids.layout(plotId, "datum-src");
      this.ctx.spec.layouts.set(valuesId, { id: valuesId, descriptor: "values", inputs: {}, params: {}, options: { rows: [datumRow] } });
      src = { producer: valuesId };
    }
    // pass 1: finalize each distinct layout producer once (shared across its picked outputs)
    const producerIds = new Map<LayoutProducer, LayoutId>();
    for (const val of Object.values(channels)) {
      if (isPendingOutput(val) && !producerIds.has(val.producer)) {
        producerIds.set(val.producer, finalizeLayout(this.ctx, plotId, src, val.producer));
      }
    }
    // pass 2: bind channels. `baseProj` collects any scale-over-expression's derived DATA columns
    // (`x(col("a")+col("b"))`), materialized on the plot's base so train + apply both see them.
    const bound: Record<string, Expr> = {};
    const baseProj: Record<string, Expr> = {};
    for (const [ch, val] of Object.entries(channels)) bound[ch] = bindChannel(this.ctx, this.nodeId, plotId, src, desc, ch, val, producerIds, baseProj);
    const plot: Plot = {
      id: plotId,
      node: this.nodeId,
      source: src,
      markType,
      channels: bound,
      ...(Object.keys(baseProj).length > 0 ? { baseProjections: baseProj } : {}),
      params: opts?.params ?? {},
      nest: opts?.on !== undefined ? { on: asPath(opts.on) } : undefined,
      frame: opts?.frame !== undefined ? (isViaHandle(opts.frame) ? { plot: opts.frame.via.plot as PlotId, on: opts.frame.via.on } : { on: asPath(opts.frame) }) : undefined,
      scope: opts?.scope,
    };
    this.ctx.spec.plots.set(plotId, plot);
    this.ctx.spec.nodes.get(this.nodeId)!.plots.push(plotId);
    return new PlotBuilder(this.ctx, this.nodeId, plotId);
  }

  /** SUGAR (WULAYOUT_IMPL §C6 subplot model): each call APPENDS ONE ROW `{ i: k }` to this node's
   *  VIRTUAL panels table (a `values` producer with one shared container plot of rect marks — created
   *  lazily) and hosts a new child node in row k's mark — the implicit FK (`hostRow`): virtual row k ↔
   *  all rows of the child's data. Strictly node → plot → marks → child, nothing new. With no layout
   *  bound (see `subplots`) the container has no box channels, so the children's extents are HOLES and
   *  the compile stage allocates solver coverage (siblings partition the content). */
  subplot(): NodeBuilder {
    const { rows, plotId } = this.#panels();
    const k = rows.length;
    rows.push({ i: k }); // the virtual table grows by one row
    return new PlotBuilder(this.ctx, this.nodeId, plotId).child(); // child() records hostRow = k
  }

  /** Choose the panels' LAYOUT exactly as any data plot chooses one — channel bindings over the
   *  virtual table (WULAYOUT_IMPL §C6): `v.subplots({ x: eqx("i") })`. Unbound channels stay holes. */
  subplots(channels: Record<string, ChannelValue>): this {
    const { plotId, source } = this.#panels();
    const plot = this.ctx.spec.plots.get(plotId)!;
    const desc = this.ctx.registries.marks.get(plot.markType);
    channels = expandLayoutOutputs(this.ctx, channels); // `.pick("*")` / bare-spread producer → all outputs
    desugarDataLiterals(desc, channels); // §5b: same rewrite as mark()
    const producerIds = new Map<LayoutProducer, LayoutId>();
    for (const val of Object.values(channels)) {
      if (isPendingOutput(val) && !producerIds.has(val.producer)) {
        producerIds.set(val.producer, finalizeLayout(this.ctx, plotId, source, val.producer));
      }
    }
    for (const [ch, val] of Object.entries(channels)) plot.channels[ch] = bindChannel(this.ctx, this.nodeId, plotId, source, desc, ch, val, producerIds);
    return this;
  }

  /** Title each subplot/panel with a text STRIP — one label per panel, centered in the panel's step,
   *  sized by fitText, in a reserved gutter band (default: a strip ABOVE the panels, `top`).
   *  `arg`: an ARRAY of labels (one per panel, injected as the `strip_label` column) or a COLUMN name
   *  already on the panels table; default = the subplots key column `i`. Compare `.axis()`/`.legend()`:
   *  a strip is the same adornment shape (reserve a band + place text in it) over the panels producer. */
  strip(arg?: string | string[], opts: { placement?: Side; height?: number; fontSize?: number; place?: "inside" | "outside"; gap?: number; pad?: number | { top?: number; right?: number; bottom?: number; left?: number } } = {}): this {
    const { rows } = this.#panels(); // ensure the panels table exists
    let labelCol: string;
    if (Array.isArray(arg)) {
      labelCol = "strip_label";
      rows.forEach((r, k) => { r[labelCol] = arg[k] ?? String(k); });
    } else {
      labelCol = arg ?? "i"; // the subplots key column (subplot()/subplots({x:eqx("i")}))
    }
    this.ctx.spec.nodes.get(this.nodeId)!.adornments.push({ kind: "strip", labelCol, ...opts });
    return this;
  }

  /** This node's panels: the virtual `values` table + its ONE shared container plot (lazy). */
  #panels(): { rows: Record<string, unknown>[]; plotId: PlotId; source: TableRef } {
    const panelsId = `${this.nodeId}/panels`;
    let inst = this.ctx.spec.layouts.get(panelsId);
    if (inst === undefined) {
      inst = { id: panelsId, descriptor: "values", inputs: {}, params: {}, options: { rows: [] as Record<string, unknown>[] } };
      this.ctx.spec.layouts.set(panelsId, inst);
      const plotId = this.ctx.spec.ids.plot(this.nodeId, "panels");
      this.ctx.spec.plots.set(plotId, { id: plotId, node: this.nodeId, source: { producer: panelsId }, markType: "rect", channels: {}, params: {} });
      this.ctx.spec.nodes.get(this.nodeId)!.plots.push(plotId);
    }
    return { rows: inst.options!.rows as Record<string, unknown>[], plotId: `${this.nodeId}/panels`, source: { producer: panelsId } };
  }

  /** Synthesize the `values` producer backing a `UNIT` source: a single row, single `value`
   *  column. The row carries its own mark identity (`dvl_mark: 0`, the `unit` leaf's shape) — a
   *  `values` leaf mints no identity, and a via reduction joins on `dvl_mark`. Keyed per plot so
   *  two UNIT marks never collide. */
  #unitSource(plotId: PlotId, value: number | string | boolean): TableRef {
    const id = this.ctx.spec.ids.layout(plotId, "unit-src");
    this.ctx.spec.layouts.set(id, { id, descriptor: "values", inputs: {}, params: {}, options: { rows: [{ dvl_mark: 0, value }] } });
    return { producer: id };
  }

  dot(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("dot", s, c, o); }
  rect(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("rect", s, c, o); }
  bar(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("bar", s, c, o); }
  line(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("line", s, c, o); }
  /** the aggregate PRIMITIVE (SEQUENCE_MARKS §3): an ordered point set → ONE open polyline. */
  path(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("path", s, c, o); }
  /** the pair sibling (§4): each point connects to its successor (order by `order`, else x). */
  connect(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("connect", s, c, o); }
  area(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("area", s, c, o); }
  text(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("text", s, c, o); }
  tick(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("tick", s, c, o); }
  rule(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("rule", s, c, o); }
  link(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("link", s, c, o); }
  /** link's curved sibling: one cubic Bézier per row between borrowed endpoints — `curvature`
   *  bends it (fraction of the chord), or bind cx1/cy1/cx2/cy2 for explicit control points. */
  bezier(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("bezier", s, c, o); }
  arrow(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("arrow", s, c, o); }
  /** a polygon around a matched point set — bind `path` to a geometry via reduction
   *  (`pts.via(on('k'), { resolve: { path: { js: 'convex' } } }).pick('path')`). */
  hull(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("hull", s, c, o); }
  vector(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("vector", s, c, o); }
  cell(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("cell", s, c, o); }
  image(s: TableRef, c: Record<string, ChannelValue>, o?: MarkOpts) { return this.mark("image", s, c, o); }
}

export class PlotBuilder extends NodeBuilder {
  constructor(
    ctx: Ctx,
    nodeId: NodeId,
    readonly plotId: PlotId,
  ) {
    super(ctx, nodeId);
  }

  #childNodeId?: NodeId;

  /** Nesting: a plot's mark() creates a NESTED plot in a child node hosted by this plot. With `on`
   *  (a nest join) the child is a DATA-DRIVEN TEMPLATE (§C8 flow 2 — `rects.dot("pts", …, { on })`):
   *  one plot spanning all host rows, keyed by dvl_cell; without, a STATIC hostRow child. */
  override mark(markType: string, source: TableRef, channels: Record<string, ChannelValue>, opts?: MarkOpts): PlotBuilder {
    const childId = this.#ensureChildNode(opts?.on !== undefined ? { on: asPath(opts.on) } : undefined);
    return new NodeBuilder(this.ctx, childId).mark(markType, source, channels, opts);
  }

  /** §C8 flow 1: create the nested TEMPLATE explicitly, then add layers to it — each layer is ONE
   *  more keyed pipeline in the same template node (its own cell key, defaulting to this nest's
   *  join), sharing the template's frame. `nest()` itself adds NO plot. The key is a Path
   *  (CELL_KEY_VIA §3): `eq`/`on('col')`/`fk('host')`/`path(...)`, or OMITTED — the resolver
   *  infers the unique child⇄host FK from the catalog. */
  nest(source: TableRef, opts?: { on?: PathInput }): NestBuilder {
    const childId = this.#ensureChildNode(opts?.on !== undefined ? { on: asPath(opts.on) } : { on: null });
    return new NestBuilder(this.ctx, childId, source);
  }

  /** A NEW child node hosted by this plot's marks (strict node → plot → marks → child hierarchy,
   *  WULAYOUT_IMPL §C6). Each call binds the next host row — the implicit FK (`hostRow`): row k's mark
   *  box becomes the child's outer extent (`host-extent`). So a plot over a constant N-row relation,
   *  placed by an ordinary layout (eqx → equal split; literal box channels → an inset), hosts N
   *  "subplots" — no subplot noun. */
  child(): NodeBuilder {
    const childId = this.#newChildNode(null);
    return new NodeBuilder(this.ctx, childId);
  }

  #ensureChildNode(nest?: { on: Path }): NodeId {
    if (this.#childNodeId !== undefined) return this.#childNodeId;
    this.#childNodeId = this.#newChildNode(nest ?? null);
    return this.#childNodeId;
  }

  #newChildNode(nest: { on: Path } | null): NodeId {
    const parent = this.ctx.spec.nodes.get(this.nodeId)!;
    // STATIC child (no nest join): the FK key is the next host row. DATA-DRIVEN (§C8, nest join
    // present): NO hostRow — the child is a TEMPLATE spanning all host rows, keyed by dvl_cell.
    const hostRow = nest === null ? parent.children.filter((c) => c.hostPlot === this.plotId).length : undefined;
    const childId = this.ctx.spec.ids.child(this.plotId);
    this.ctx.spec.nodes.set(childId, {
      id: childId,
      plots: [],
      groups: [],
      adornments: [],
      constraints: [],
      children: [],
      extent: unboundExtent(this.ctx.spec.cells),
      frame: { scales: [] },
    });
    parent.children.push({ node: childId, hostPlot: this.plotId, nest, hostRow });
    this.ctx.spec.nodes.get(childId)!.parent = parent.id;
    return childId;
  }

  /** Record an axis directive on this plot's node (lowering to plots is C7). Accepts the same
   *  options as the scale-level `axis:` config (title, ticks, tickLength, fontSize, place, gap,
   *  pad) plus `placement` to pin the side; lowerAxes merges them onto the frame scale
   *  (directive wins over the scale-level config). */
  axis(dim: "x" | "y", opts?: { placement?: Side } & AxisOptions): this {
    this.ctx.spec.nodes.get(this.nodeId)!.adornments.push({ kind: "axis", axis: dim, ...opts });
    return this;
  }

  /** Record a legend directive for a channel (lowering is C7). `position` is an accepted alias
   *  for `placement`; an unknown placement value throws (silent typos cost a debugging session —
   *  AUTOLEGEND_IMPL §8). Extra keys (swatchSize, fontSize, …) ride through to LegendOpts. */
  legend(channel: string, opts: { placement?: LegendPlacement; position?: LegendPlacement; [k: string]: unknown } = {}): this {
    const { position, ...rest } = opts;
    const placement = (rest.placement ?? position) as LegendPlacement | undefined;
    if (placement !== undefined && !["left", "right", "top", "bottom", "inside"].includes(placement)) {
      throw new Error(`legend(${channel}): unknown placement "${String(placement)}" — use left | right | top | bottom | inside`);
    }
    this.ctx.spec.nodes.get(this.nodeId)!.adornments.push({ kind: "legend", channel, ...rest, ...(placement !== undefined && { placement }) });
    return this;
  }

  /** The scale bound to a channel (used by axis/legend lowering in C7). */
  scaleOf(channel: string): Scale | undefined {
    const expr = this.ctx.spec.plots.get(this.plotId)!.channels[channel];
    if (expr?.kind === "layout-output") return this.ctx.spec.layouts.get(expr.layout) as Scale;
    return undefined;
  }

  /** A cross-mark reference producer into this plot's solved channels (post-solve). The steps
   *  form a Path (§3a): predicates and fk() hops compose freely — a multi-hop via chains its
   *  intermediate joins exactly like a multi-hop nest key.
   *  `dvl_cell` is always borrowable: picking it as `cell` is the Level-2 frame borrow
   *  (CELL_KEY_VIA) — the consumer's cell key becomes this FK join, read early.
   *  A trailing `{ resolve }` option declares the reduction of a MULTI-MATCH join (§3b/§3c):
   *  an AggFn name, `{ fn, arg }` with an expression over the (m, f) row, a `{ js }` opaque
   *  reduce, or a per-channel map — required when the path can match several referent rows. */
  via(...args: ViaArgs): ViaHandle {
    const plot = this.ctx.spec.plots.get(this.plotId)!;
    const plotId = this.plotId;
    // BARE-STRING resolver shorthand (#2): `resolve: "convex"` names a resolver that DECLARES a
    // defaultOutput — expand to the map form `{ <defaultOutput>: { js: "convex" } }` so it mints
    // that output (the single computed form is otherwise rejected — no name to pick by). A scalar
    // reducer (no defaultOutput, e.g. "mode") or an AggFn ("avg", not in the registry) is left as
    // the whole-borrow reduction it already means.
    const last = args[args.length - 1];
    if (last !== undefined && typeof last !== "string" && "resolve" in last && typeof last.resolve === "string" && this.ctx.registries.reducers.has(last.resolve)) {
      const spec = this.ctx.registries.reducers.get(last.resolve);
      if (spec.defaultOutput !== undefined) args = [...args.slice(0, -1), { resolve: { [spec.defaultOutput]: { js: last.resolve } } }] as ViaArgs;
    }
    const v = parseViaArgs(`via(${plotId})`, args);
    const outFor = (name: string): Expr => {
      if (name === "dvl_cell") {
        // aggregating a cell id is meaningless; other picks on the same via may still resolve
        // (§5 — positional borrows are unaffected by the frame borrow riding along).
        if (v.resolveFor(name) !== undefined) throw new Error(`via(${plotId}): the cell borrow needs a single-match join — an aggregated cell id is meaningless (drop \`resolve\` for the cell pick)`);
        return tableRef(plotId, "dvl_cell", v.steps, { space: dataSpace, arity: "per-row" });
      }
      // a DECLARED computed output: the name is the resolution's, not a referent column's —
      // its space is the resolution's declared one (a pixel distance says pixel). Undeclared is
      // data BY DEFINITION (a reduction over data values is data unless said otherwise) — a
      // semantic default, not a silent fallback, hence the explicit branch.
      if (v.computedNames.includes(name)) {
        const declared = v.declaredSpace(name);
        const space: Space = declared !== undefined ? declared : dataSpace;
        return tableRef(plotId, name, v.steps, { space, arity: "per-row" }, v.resolveFor(name));
      }
      const channelSpace = plot.channels[name]?.type.space;
      if (channelSpace === undefined) spaceFallbacks.note(`via:${plotId}.${name}`);
      // §3.3 B2: a plot borrow arrives PLACED — a relative channel is borrowed post-affine as
      // pixel (the runtime truth spaceOfChan always applied at emission; the static type agrees).
      // Pixel arithmetic on borrows is well-typed at construction: out("y") + literal(5, pixel len).
      const refSpace: Space = channelSpace === undefined ? dataSpace : channelSpace.space === "relative" ? pixelSpace(channelSpace.geom) : channelSpace;
      return tableRef(plotId, name, v.steps, { space: refSpace, arity: "per-row" }, v.resolveFor(name));
    };
    // "*"/bare pick borrows the referent's CHANNELS + computed outputs, but NOT the internal
    // dvl_cell frame borrow (an explicit `.pick("dvl_cell")` still resolves it via outFor).
    const wildcard = [...Object.keys(plot.channels), ...v.computedNames];
    const base = producer([...Object.keys(plot.channels), "dvl_cell", ...v.computedNames], outFor, wildcard);
    // The handle SPREADS to all borrowed channels — a bare `...plot.via(...)` == `.pick("*")` (#4).
    // Its methods + the `via` declaration ride along NON-ENUMERABLE, so the spread carries only the
    // channel Exprs; `frame:`/isViaHandle read `.via` (present, just not enumerated).
    const handle = Object.defineProperties({ ...base.pick("*") }, {
      outputs: { value: base.outputs, enumerable: false },
      out: { value: base.out, enumerable: false },
      pick: { value: base.pick, enumerable: false },
      via: { value: { plot: plotId, on: v.steps }, enumerable: false },
    });
    // just-defined the exact ViaHandle shape; inference can't see defineProperties' additions.
    return handle as unknown as ViaHandle;
  }
}

/** The nested-TEMPLATE handle (§C8 flow 1): remembers the nest's table so layers bind CHANNELS only
 *  — `inner.dot({ x: linear("u") })`. Each mark call adds ONE more keyed pipeline to the template
 *  node (a per-layer `on` in opts overrides the nest's default join, recorded on the plot). */
export class NestBuilder {
  #inner: NodeBuilder;
  constructor(
    ctx: Ctx,
    readonly nodeId: NodeId,
    readonly source: TableRef,
  ) {
    this.#inner = new NodeBuilder(ctx, nodeId);
  }
  get spec(): Spec {
    return this.#inner.spec;
  }
  layer(markType: string, channels: Record<string, ChannelValue>, opts?: MarkOpts): PlotBuilder {
    // GUARD (the string footgun): a NestBuilder layer takes a CHANNEL MAP — its source is the
    // nest's. Passing a source name here (`nest(...).link('fedges', {…})`) would silently
    // spread the string into bogus per-character literal channels; fail loudly instead.
    if (typeof channels !== "object" || channels === null || Array.isArray(channels)) {
      const src = typeof this.source === "string" ? `"${this.source}"` : "the nested relation";
      throw new Error(
        `nest().${markType}(...): a nest layer takes a CHANNEL MAP — its source is always the nest's (${src}). ` +
          `To layer a DIFFERENT source, use the container plot's own handle: panel.${markType}(${JSON.stringify(channels)}, { … })`,
      );
    }
    return this.#inner.mark(markType, this.source, channels, opts);
  }
  dot(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("dot", c, o); }
  rect(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("rect", c, o); }
  bar(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("bar", c, o); }
  line(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("line", c, o); }
  path(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("path", c, o); }
  connect(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("connect", c, o); }
  area(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("area", c, o); }
  text(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("text", c, o); }
  tick(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("tick", c, o); }
  rule(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("rule", c, o); }
  link(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("link", c, o); }
  bezier(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("bezier", c, o); }
  hull(c: Record<string, ChannelValue>, o?: MarkOpts) { return this.layer("hull", c, o); }
}

// --- entry point ---

/** Options for `canvas(...)`: the data `db`/branch plus canvas-level chart options (Observable
 *  Plot analogues — margin/inset/background/aspectRatio). */
export type CanvasOptsArg = { db?: Database } & CanvasOpts;

/** The root: a fixed-size canvas node. Plots/scales attach to it; `.spec` is the built IR.
 *  Pass `db` to give the resolver the FK catalog (inferred nest keys, fk() hops), and any
 *  Observable-Plot-style chart options (margin, inset, background, aspectRatio). */
export function canvas(width: number, height: number, opts?: CanvasOptsArg): NodeBuilder {
  const registries = defaultRegistries();
  const { db, ...canvasOpts } = opts ?? {};
  const spec = newSpec(db, canvasOpts);
  const ctx: Ctx = { spec, registries, width, height };

  const rootId = spec.ids.node();
  spec.root = rootId;
  const root: Node = {
    id: rootId,
    plots: [],
    groups: [],
    adornments: [],
    constraints: [],
    children: [],
    extent: makeExtent(spec.cells, 0, 0, width, height),
    frame: { scales: [] },
  };
  spec.nodes.set(rootId, root);
  return new NodeBuilder(ctx, rootId);
}

/** A single-row, single-column (`value`) table — the anchor for a mark that has no table of its
 *  own: one row to place, one row to reduce a whole referent onto (`v.hull(UNIT, { ...pts.via(on("*"),
 *  { resolve: "convex" }).pick("path") })`). Bare `UNIT` carries `value` 1; `UNIT(v)` carries `v`.
 *  Use it wherever a mark source is expected. */
export type UnitFactory = UnitSource & ((value: number | string | boolean) => UnitSource);
export const UNIT: UnitFactory = Object.assign(
  (value: number | string | boolean): UnitSource => ({ __unit: "unit-source", value }),
  { __unit: "unit-source", value: 1 } as const,
);
