// Cross-relation column survival — the single authority (design/VIA_HARDENING.md §2.4).
//
// PROBLEM (gap #4): a mark table SELECTs only the columns its OWN plot's channels/layouts read.
// When another op JOINS against a plot's marks — a via borrowing the referent's key, a cell-key,
// a σ agreement, a via-agg — the joined-on column must exist on the producing mark table, but the
// mark table has no idea a foreign op joins on it. The column is projected away and the join emits
// SQL naming a column that does not exist. Silent at compile, "column does not exist" at run.
//
// DESIGN: in relational algebra the ONLY way an op references a column it does not itself produce
// is ACROSS A JOIN. So every cross-relation column demand is spelled on a multi-input op's
// `on`/`join.on`. This pass, run once over the emitted graph:
//   1. EXTRACTS, from every join-carrying op, [cell, column] requirements (both sides of each join).
//   2. TRACES each requirement backward through the (column-preserving 1:1 augment) chain to the
//      mark table that must carry it — stopping early at the first ancestor that PRODUCES it
//      (a minted hop column, a borrowed via column), else landing on the mark table root.
//   3. AUGMENTS that mark table op's payload with the required column set.
// It is COMPLETE by the relational-algebra argument, not by enumerating op kinds: a new
// join-carrying op that reuses the `on`/`join.on` shape is covered without editing this pass.
// Because it reads the truth from the emitted ops, `marktable.referencedColumns` owns only a
// plot's OWN data reads — no nest/σ/frame/via heuristics re-derive cross-relation keys.
import type { OpSpec } from "../opspec.js";
import type { CellRef } from "../../ir/cell.js";

/** A column that starts with the reserved `dvl_` prefix is never a source column — it is an
 *  identity column (dvl_plot/dvl_mark/dvl_cell) or a minted intermediate (dvl_h_*, dvl_v_*, …).
 *  Identity columns the mark table computes; minted columns an intermediate op produces. Neither
 *  is ever required FROM a source table, so they never enter the backward trace. */
const isSourceColumn = (c: string): boolean => !c.startsWith("dvl_");

/** The columns an op ADDS to its output (relative to its primary input). A required column is
 *  SATISFIED at the first ancestor that adds it — the trace stops there. */
function columnsAdded(op: OpSpec): readonly string[] {
  const p = op.payload as { kind: string; add?: Record<string, unknown>; adds?: Record<string, unknown> };
  if (p.kind === "relop") return p.add !== undefined ? Object.keys(p.add) : [];
  if (p.kind === "reduce" || p.kind === "via-agg") return p.adds !== undefined ? Object.keys(p.adds) : [];
  return [];
}

/** [cell, column] — `column` must exist on the relation carried by `cell`. */
interface Requirement {
  readonly cell: CellRef;
  readonly column: string;
}

/** Extract every cross-relation column demand from the emitted ops. Each entry pins the column to
 *  the read-edge it must arrive on (reads index follows the emitter's documented convention). */
function extract(specs: readonly OpSpec[]): Requirement[] {
  const reqs: Requirement[] = [];
  const need = (cell: CellRef | undefined, column: string): void => {
    if (cell !== undefined && isSourceColumn(column)) reqs.push({ cell, column });
  };
  for (const op of specs) {
    const p = op.payload as {
      kind: string;
      join?: { on: ReadonlyArray<readonly [string, string, ...unknown[]]> };
      on?: ReadonlyArray<readonly [string, string, ...unknown[]]>;
      by?: string | readonly string[];
    };
    switch (p.kind) {
      case "relop":
        // join-derive (via / cell-key / frame / via-stage): left ← reads[0] (pipeline), right ←
        // reads[1] (the joined input). An empty `on` is a broadcast cross join — no demand.
        if (p.join !== undefined) {
          for (const [l, r] of p.join.on) {
            need(op.reads[0], l);
            need(op.reads[1], r);
          }
        }
        break;
      case "via-agg":
        // reads: [attach target, joinBase, referent]. The final-hop join is joinBase ⋈ referent.
        if (p.on !== undefined) {
          for (const [m, r] of p.on) {
            need(op.reads[1], m);
            need(op.reads[2], r);
          }
        }
        break;
      case "sigma-verify":
        // reads: [walked marks, host base]; on = agreement pairs [left, right].
        if (p.on !== undefined) {
          for (const [l, r] of p.on) {
            need(op.reads[0], l);
            need(op.reads[1], r);
          }
        }
        break;
      case "reduce": {
        // the group key must survive on the input relation.
        const by = p.by === undefined ? [] : Array.isArray(p.by) ? p.by : [p.by];
        for (const k of by) need(op.reads[0], k);
        break;
      }
      default:
        break;
    }
  }
  return reqs;
}

/** Trace one requirement back to the mark table(s) that must carry the column, recording it in
 *  `demand` (plotId → columns). */
function trace(req: Requirement, producer: ReadonlyMap<CellRef, OpSpec>, demand: Map<string, Set<string>>): void {
  const seen = new Set<CellRef>();
  const stack: CellRef[] = [req.cell];
  while (stack.length > 0) {
    const cell = stack.pop()!;
    if (seen.has(cell)) continue;
    seen.add(cell);
    const op = producer.get(cell);
    if (op === undefined) continue; // a raw base-table leaf — it carries all its own columns.
    const p = op.payload as { kind: string; plotId?: string; source?: unknown };
    if (p.kind === "marktable") {
      const plotId = p.plotId!;
      (demand.get(plotId) ?? demand.set(plotId, new Set()).get(plotId)!).add(req.column);
      continue;
    }
    if (columnsAdded(op).includes(req.column)) continue; // minted / borrowed here — satisfied.
    // a relop with a `source` is a base/constant relation leaf (a `table` ⇒ SELECT * FROM t; a
    // `values`/`unit` ⇒ its literal columns). It has no relation parent to walk into, so it
    // terminates the trace. We treat it as carrying the column rather than raising a build error:
    // proving a column is genuinely ABSENT needs the source's column set, and sources are
    // heterogeneous — a DB table's schema is introspected (async, off the Database), while JS
    // rows / columnar / literal `values` infer theirs from content. A uniform static column-oracle
    // across all source kinds is a separate design; until it exists, a genuinely absent column
    // surfaces as the (pre-existing) runtime "column does not exist" — this pass does not make it
    // worse, and fixes every recoverable case.
    if (p.kind === "relop" && p.source !== undefined) continue;
    // pass-through augment: the identity + accumulated columns flow through the PRIMARY input
    // (reads[0]); union-all requires the column on EVERY branch.
    const parents = p.kind === "union-all" ? op.reads : op.reads.slice(0, 1);
    for (const parent of parents) if (parent !== undefined && !seen.has(parent)) stack.push(parent);
  }
}

/** The pass: collect cross-relation column demands and stamp each mark table op's payload with
 *  the columns it must additionally SELECT. Mutates `specs` in place (replaces stamped ops). */
export function propagateRequiredColumns(specs: OpSpec[]): void {
  const producer = new Map<CellRef, OpSpec>();
  for (const op of specs) for (const w of op.writes) producer.set(w, op);

  const demand = new Map<string, Set<string>>(); // marktable plotId → required source columns
  for (const req of extract(specs)) trace(req, producer, demand);
  if (demand.size === 0) return;

  for (let i = 0; i < specs.length; i++) {
    const op = specs[i];
    const p = op.payload as { kind: string; plotId?: string };
    if (p.kind !== "marktable") continue;
    const cols = demand.get(p.plotId!);
    if (cols === undefined || cols.size === 0) continue;
    specs[i] = { ...op, payload: { ...op.payload, requiredColumns: [...cols] } };
  }
}
