// Legend lowering (C7, AUTOLEGEND §0 G0): a legend is ORDINARY PLOTS over V — a swatch (dot) + text
// — binding the channel's scale APPLY-ONLY. Wired in compileSpec right after lowerAxes; the
// returned controllers (k-controller shrink) thread to the scheduler. Each legend directive
// becomes: a vtable (domain → V), an apply-only (V.value → the swatch's varying attribute), a
// grid-stack (item boxes), swatch + text plots, and a gutter reservation.
import type { Spec } from "../../ir/spec.js";
import type { Registries } from "../../operator/registry.js";
import type { Node, Side, AdornmentDirective, PlotRect } from "../../ir/node.js";
import { dock } from "./layout-api.js";
import { placeToOrder } from "../../layout/sidestack.js";
import { hostBindingMode } from "./binding-mode.js";
import type { Scale } from "../../ir/layout.js";
import type { Expr } from "../../ir/expr.js";
import type { Plot } from "../../ir/plot.js";
import type { Controller } from "../../ir/controller.js";
import { col, layoutOutput, literal } from "../../ir/expr.js";
import { coord, dataSpace, len, pixelSpace, styleSpace, type Space } from "../../types/attr.js";
import type { GridStackOpts } from "../../components/layouts/grid-stack.js";
import { mkKController } from "../../components/layouts/k-controller.js";

const SWATCH_D = 10;
const TEXT_GAP = 4;
const ITEM_PAD = 4;
const ITEM_GAP = 4;
const FONT_SIZE = 10;
const EST_CHAR_W = 6;

// AUTOLEGEND §G1: which dot attribute the legend's channel maps to. Most are identity (fill→fill,
// stroke→stroke, r→r, shape→shape); `size`/`opacity` are the mark's `r`/`fillOpacity`.
const SWATCH_ATTR: Record<string, string> = { size: "r", opacity: "fillOpacity" };
const NEUTRAL_FILL = "#888"; // non-varying swatch fill for size/opacity/shape legends

export interface LegendOpts {
  placement?: Side | "inside";
  swatchSize?: number;
  textGap?: number;
  fontSize?: number;
  pad?: number;
  itemGap?: number;
  cols?: number;
  major?: "column" | "row";
  maxLabelChars?: number;
  /** Side-stack ORDER override (Step 4): `inside` hugs the plot, `outside` sits outermost among
   *  co-located adornments. Distinct from `placement` (which side). Default: role rank (legend = 40). */
  place?: "inside" | "outside";
  /** Gap (px) before the legend band along the stack normal (Step 4). Default 2·pad. */
  gap?: number;
}

export interface LowerLegendsResult {
  controllers: Controller[];
}

export function lowerLegends(spec: Spec, registries: Registries): LowerLegendsResult {
  const controllers: Controller[] = [];
  for (const node of spec.nodes.values()) {
    for (const dir of node.adornments) {
      if (dir.kind !== "legend") continue;
      const scales = resolveChannelScales(spec, node, dir.channel);
      for (const { scale, space } of scales) {
        const ctrl = createLegend(spec, registries, node, scale, space, dir);
        if (ctrl) controllers.push(ctrl);
      }
    }
  }
  return { controllers };
}

/** Find the DISTINCT scales producing `channel` across the node's plots, each with the SPACE the
 *  channel is bound at — that space drives the swatch's varying attribute (binding-polymorphic:
 *  a colour scale emits a colour, a len/number scale a number). */
function resolveChannelScales(spec: Spec, node: Node, channel: string): { scale: Scale; space: Space }[] {
  const seen = new Set<string>();
  const out: { scale: Scale; space: Space }[] = [];
  for (const pid of node.plots) {
    const plot = spec.plots.get(pid);
    if (!plot) continue;
    const e = plot.channels[channel];
    if (e?.kind !== "layout-output") continue;
    if (seen.has(e.layout)) continue;
    seen.add(e.layout);
    const inst = spec.layouts.get(e.layout);
    if (inst?.domain) out.push({ scale: inst as Scale, space: e.type.space });
  }
  return out;
}

// ── G2: the RAMP idiom — a continuous colour legend is a band stack + axis-style labels ──
const RAMP_BANDS = 64; // uniform colour samples, one thin rect band each
const RAMP_LEN = 96; // the ramp bar's long dimension (px)
const RAMP_LABELS = 3; // min / mid / max — same `uniform` algo as the bands, aligned by construction

type LegendKind = "swatches" | "ramp";

/** THE legend-type derivation — the single inference site for "what kind of legend does this
 *  scale get" (one phase, not scattered heuristics). An operator SELF-DECLARES its idiom
 *  (`Operator.legend`, the same pattern as its `scheme` default): ramp ⟺ the channel is a
 *  colour AND the scale declares "ramp" (the interpolable continuous family). Ordinal →
 *  swatches; quantize/threshold deliberately don't declare ramp (a smooth gradient would lie
 *  about a binned encoding); size/opacity legends stay discrete (graduated symbols). */
function legendKind(scale: Scale, space: Space, registries: Registries): LegendKind {
  const isColor = space.space === "style" && space.channel === "color";
  const wop = registries.operators.has(scale.descriptor) ? registries.operators.get(scale.descriptor) : undefined;
  return isColor && wop?.legend === "ramp" ? "ramp" : "swatches";
}

function createLegend(
  spec: Spec, registries: Registries, node: Node, scale: Scale, space: Space, directive: AdornmentDirective & { kind: "legend" },
): Controller | undefined {
  const { channel } = directive;
  const userOpts = directive as unknown as LegendOpts;
  const swatchSize = userOpts.swatchSize ?? SWATCH_D;
  const textGap = userOpts.textGap ?? TEXT_GAP;
  const fontSize = userOpts.fontSize ?? FONT_SIZE;
  const pad = userOpts.pad ?? ITEM_PAD;
  const itemGap = userOpts.itemGap ?? ITEM_GAP;
  const placement = userOpts.placement ?? "right";
  const side: Side | undefined = placement === "inside" ? undefined : placement;

  const itemW = swatchSize + textGap + 8 * EST_CHAR_W;
  const itemH = Math.max(swatchSize, fontSize) + itemGap;
  const cc = node.extent.content;
  const oo = node.extent.outer; // fixed edges — a docked RAMP legend's own-axis anchor hugs these, not
  // the shrinking content box (else it chases its own reserved gutter and the fixpoint never converges).
  const pxCoordSpace = (axis: "x" | "y") => pixelSpace(coord(axis));
  const kind = legendKind(scale, space, registries);

  // Step 3: a scalar, non-hoisted, DISCRETE (swatch) legend registers as a side-stack BAND (co-located
  // with any axis on its side, they SUM; the grid-stack anchors to the band's solved corner, outside
  // the axis). Hoisted (shared template) and ramp legends keep the dock path. Compute the decision +
  // the position cells UP FRONT so the discrete grid-stack can point its bandAnchor at them.
  const isTemplate = node.insets !== undefined;
  const sideAxisEarly: "x" | "y" = (side === "left" || side === "right") ? "x" : "y";
  const hostModeEarly = hostBindingMode(spec, registries, node, sideAxisEarly);
  const hoistedEarly = isTemplate && scale.shared !== false && hostModeEarly !== null && hostModeEarly !== "pixel";
  const asBand = kind === "swatches" && side !== undefined && !isTemplate && !hoistedEarly;
  const legendX = spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("x")));
  const legendY = spec.cells.alloc("param", 0, "scalar", pixelSpace(coord("y")));
  const bandAnchor = asBand ? { x: legendX, y: legendY } : undefined;

  let legendPlots: readonly [string, string];
  let controller: Controller | undefined;
  let seedW: number;
  let seedH: number;

  if (kind === "ramp") {
    // ── the ramp: RAMP_BANDS uniform samples of the scale, each a thin rect (vertical for a
    //    left/right dock, horizontal for top/bottom), plus min/mid/max labels placed like an
    //    axis with no ticks and no rule, on the AWAY side of the bar. Both Vs use the `uniform`
    //    tick algo, so bands and labels align by construction (uniform in t).
    const horiz = side === "top" || side === "bottom";
    const bandStep = RAMP_LEN / RAMP_BANDS;
    const bandsV = `${scale.id}/legend-rampV`;
    spec.layouts.set(bandsV, {
      id: bandsV, descriptor: "vtable", inputs: {}, params: {},
      domain: scale.domain,
      options: { tickAlgo: "uniform", column: "value", count: RAMP_BANDS },
    });
    // apply-only over the samples: value → colour. The palette is the WRAPPED scale's resolved
    // scheme (resolveSpec's single scheme site follows options.wrapped) — the legend pictures
    // the live scale, palette included.
    const aoId = `${scale.id}/legend-ao`;
    spec.layouts.set(aoId, {
      id: aoId, descriptor: "apply-only",
      inputs: { marks: { relation: { producer: bandsV }, project: { value: "value" } } },
      params: {}, domain: scale.domain,
      options: { wrapped: scale.descriptor, ...scale.options },
    });
    const bandsGs = `${scale.id}/legend-gs`;
    spec.layouts.set(bandsGs, {
      id: bandsGs, descriptor: "grid-stack",
      inputs: { marks: { relation: { producer: bandsV }, project: { value: "idx" } } },
      params: {},
      options: {
        contentEdges: cc, ...(side !== undefined && { outerEdges: oo }), pad, side: side ?? "right", ...(side === undefined && { inside: "top-right" }),
        itemW: horiz ? bandStep : swatchSize, itemH: horiz ? swatchSize : bandStep,
        major: horiz ? "row" : "column",
      } as unknown as Record<string, unknown>,
    });
    const bandId = addPlot(spec, node, `legend-${channel}-band`, "rect", { producer: bandsV }, {
      x: layoutOutput(bandsGs, "x", { space: pxCoordSpace("x"), arity: "per-row" }),
      y: layoutOutput(bandsGs, "y", { space: pxCoordSpace("y"), arity: "per-row" }),
      w: literal(horiz ? bandStep : swatchSize),
      h: literal(horiz ? swatchSize : bandStep),
      fill: layoutOutput(aoId, "value", { space, arity: "per-row" }),
    });
    // labels: the same uniform algo at count 3 → the true domain min/mid/max, at t = 0/.5/1 —
    // exactly the band positions (idx 0 = min at the anchor: top for vertical, left for horiz).
    const ticksV = `${scale.id}/legend-ticksV`;
    spec.layouts.set(ticksV, {
      id: ticksV, descriptor: "vtable", inputs: {}, params: {},
      domain: scale.domain,
      options: { tickAlgo: "uniform", column: "value", count: RAMP_LABELS },
    });
    const ticksGs = `${scale.id}/legend-ticks-gs`;
    const tickPitch = RAMP_LEN / (RAMP_LABELS - 1);
    spec.layouts.set(ticksGs, {
      id: ticksGs, descriptor: "grid-stack",
      inputs: { marks: { relation: { producer: ticksV }, project: { value: "idx" } } },
      params: {},
      options: {
        contentEdges: cc, ...(side !== undefined && { outerEdges: oo }), pad, side: side ?? "right", ...(side === undefined && { inside: "top-right" }),
        itemW: horiz ? tickPitch : swatchSize, itemH: horiz ? swatchSize : tickPitch,
        major: horiz ? "row" : "column",
      } as unknown as Record<string, unknown>,
    });
    // label placement: the AWAY side of the bar per dock side — "an axis with no ticks and rule"
    const L = side === "left" ? { dx: -textGap, dy: 0, anchor: "end", baseline: "middle" }
      : side === "top" ? { dx: 0, dy: -textGap, anchor: "middle", baseline: "bottom" }
      : side === "bottom" ? { dx: 0, dy: swatchSize + textGap, anchor: "middle", baseline: "top" }
      : { dx: swatchSize + textGap, dy: 0, anchor: "start", baseline: "middle" };
    const tickTextId = addPlot(spec, node, `legend-${channel}-ramp-text`, "text", { producer: ticksV }, {
      x: layoutOutput(ticksGs, "x", { space: pxCoordSpace("x"), arity: "per-row" }),
      dx: literal(L.dx),
      y: layoutOutput(ticksGs, "y", { space: pxCoordSpace("y"), arity: "per-row" }),
      dy: literal(L.dy),
      anchor: literal(L.anchor),
      baseline: literal(L.baseline),
      text: col("label", styleSpace("text")),
      fill: literal("#333"),
      fontSize: literal(fontSize),
    });
    legendPlots = [bandId, tickTextId];
    seedW = horiz ? RAMP_LEN + 2 * pad : swatchSize + textGap + 5 * EST_CHAR_W + 2 * pad;
    seedH = horiz ? swatchSize + textGap + fontSize + 2 * pad : RAMP_LEN + 2 * pad;
  } else {
    // ── discrete swatches (categorical; binned; any non-colour channel) ──
    // 1. K cell (label prefix length; -1 = all chars)
    const initK = userOpts.maxLabelChars ?? -1;
    const kCell = spec.cells.alloc("param", initK, "scalar", dataSpace);

    // 2. V producer — domain → V(idx, value, label) via the scale's tick algo
    const tickAlgo = resolveTickAlgo(scale, registries);
    const vId = `${scale.id}/legend-V`;
    spec.layouts.set(vId, {
      id: vId, descriptor: "vtable", inputs: {}, params: {},
      domain: scale.domain,
      // ponytail: ordinal ignores count (emits all categories); continuous uses it as sample count
      options: { tickAlgo, column: "value", count: 5 },
    });

    // 3. Truncate layout — a channel-level transform on the text plot's label.
    const truncId = `${scale.id}/legend-trunc`;
    spec.layouts.set(truncId, {
      id: truncId, descriptor: "truncate",
      inputs: { marks: { relation: { producer: vId }, project: { value: "label" } } },
      params: {},
      options: { k: initK },
    });

    const baseSource = { producer: vId };

    // 4. Apply-only wrapper — map V.value through the scale (palette = the wrapped scale's
    //    resolved scheme; resolveSpec's single scheme site follows options.wrapped).
    const aoId = `${scale.id}/legend-ao`;
    spec.layouts.set(aoId, {
      id: aoId, descriptor: "apply-only",
      inputs: { marks: { relation: baseSource, project: { value: "value" } } },
      params: {}, domain: scale.domain,
      options: { wrapped: scale.descriptor, ...scale.options },
    });

    // 5. Grid-stack layout — produces item boxes (x, y, w, h). G4: the item PITCH is measured from
    //    the real (truncated) label extents at execution — `itemW` (the 8-char estimate) is only the
    //    seed / no-measure fallback.
    const gsId = `${scale.id}/legend-gs`;
    const gsOpts: GridStackOpts = {
      contentEdges: cc,
      // a BAND legend anchors its own-axis to the solved band corner (Step 3); a non-band docked
      // discrete legend (template/hoisted) keeps the fixed-outer-edge anchor.
      ...(bandAnchor !== undefined ? { bandAnchor } : side !== undefined ? { outerEdges: oo } : {}),
      itemW, itemH, pad,
      major: userOpts.major,
      side: side ?? "right",
      // G3: no side = `placement:"inside"` — an OVERLAY anchored in the content box's top-right
      // corner by grid-stack itself; no gutter is reserved and no constraints are emitted.
      ...(side === undefined && { inside: "top-right" as const }),
      label: { column: "label", fontSize, base: swatchSize + textGap + itemGap, k: initK },
      // glyph anchor inside the box (AUTOLEGEND_IMPL §8): circle centered, text middle-baselined.
      inset: { x: swatchSize / 2, y: itemH / 2 },
    };
    spec.layouts.set(gsId, {
      id: gsId, descriptor: "grid-stack",
      inputs: { marks: { relation: baseSource, project: { value: "idx" } } },
      params: {},
      options: gsOpts as unknown as Record<string, unknown>,
    });

    // 6. Swatch plot — AUTOLEGEND §G1: the legend's CHANNEL is the attribute that VARIES (via
    //    apply-only), bound at the SAME space it has in the real plot; the rest neutral constants.
    const swatchAttr = SWATCH_ATTR[channel] ?? channel;
    const swatchChannels: Record<string, Expr> = {
      x: layoutOutput(gsId, "x", { space: pxCoordSpace("x"), arity: "per-row" }),
      y: layoutOutput(gsId, "y", { space: pxCoordSpace("y"), arity: "per-row" }),
      [swatchAttr]: layoutOutput(aoId, "value", { space, arity: "per-row" }),
    };
    if (swatchAttr !== "r") swatchChannels.r = literal(swatchSize / 2);
    if (swatchAttr !== "fill") swatchChannels.fill = literal(NEUTRAL_FILL);
    const swatchId = addPlot(spec, node, `legend-${channel}-swatch`, "dot", baseSource, swatchChannels);

    // 7. Text plot — same grid-stack position as swatch, offset by dx; truncate feeds `text`.
    const textPlotId = addPlot(spec, node, `legend-${channel}-text`, "text", baseSource, {
      x: layoutOutput(gsId, "x", { space: pxCoordSpace("x"), arity: "per-row" }),
      dx: literal(swatchSize / 2 + textGap),
      y: layoutOutput(gsId, "y", { space: pxCoordSpace("y"), arity: "per-row" }),
      baseline: literal("middle"),
      text: layoutOutput(truncId, "value", { space: styleSpace("text"), arity: "per-row" }),
      anchor: literal("start"),
      fill: literal("#333"),
      fontSize: literal(fontSize),
    });
    legendPlots = [swatchId, textPlotId];
    seedW = itemW + pad * 2;
    seedH = 3 * itemH + pad * 2;

    // K-controller — only if not author-pinned (swatch labels truncate; ramp labels are numbers)
    if (side && userOpts.maxLabelChars === undefined) {
      controller = mkKController({
        kCell,
        contentTop: cc.top,
        contentBottom: cc.bottom,
        n: 0, // ponytail: unknown at lowering; the controller reads V's row count at runtime
        itemH, pad,
        minK: 3,
      });
    }
  }

  // 8. PlotRect + constraint API (measurement + positioning) — shared by both kinds. The band
  // decision + position cells were computed up front (Step 3); reuse them (legendX/legendY are the
  // band's solved corner that the discrete grid-stack anchors to).
  const hoisted = hoistedEarly;
  const legendW = spec.cells.alloc("demand", seedW, "scalar", pixelSpace(len("x")));
  const legendH = spec.cells.alloc("demand", seedH, "scalar", pixelSpace(len("y")));
  const legendRect: PlotRect = { id: `legend-${channel}`, plots: [...legendPlots], x: legendX, y: legendY, w: legendW, h: legendH };
  node.plotRects ??= [];
  node.plotRects.push(legendRect);
  if (hoisted) {
    // Shared legend (§12a): dock constraint on parent. Legend marks DON'T use affineMode:"host"
    // (they're pixel-mode from grid-stack, not affine-placed). The grid-stack anchors its own-axis
    // to the fixed OUTER extent (outerEdges above), so it no longer chases the shrinking content box.
    const parentNode = spec.nodes.get(node.parent!)!;
    parentNode.constraints.push(...dock(legendRect, { extent: parentNode.extent }, side ?? "right", pad * 2));
  } else if (asBand) {
    // Step 3: register as a side-stack BAND (role "legend", rank 40 → outside the axis at rank 10).
    // gap = 2·pad (AUTOLEGEND_IMPL §8): the grid anchors pad past its band corner. Co-located with an
    // axis on this side, the two reservations now SUM (the overlap fix); the grid-stack's bandAnchor
    // reads legendRect's solved corner, which sits outside the axis.
    (node.sideBands ??= []).push({ id: `legend-${channel}`, side: side!, role: "legend", rect: legendRect, gap: userOpts.gap ?? pad * 2, order: placeToOrder(userOpts.place) });
  } else if (side) {
    // Ramp legend (or any non-band docked case): keep the single dock reservation + outerEdges anchor.
    node.constraints.push(...dock(legendRect, { extent: node.extent }, side, pad * 2));
  }
  // G3: `placement:"inside"` emits NO arrange constraints — the legend is an overlay placed by
  // grid-stack's `inside` anchor, consuming no layout space. float() is NOT usable here: the
  // PlotRect's x/y/w/h cells are store-valued, not solver-owned, so Cassowary folds them to
  // constants and float's containment becomes a bound on the CONTENT box (the G3 infeasibility);
  // softened, it would silently squeeze the plot instead. See layout-api.ts float()'s precondition.

  // 9. Group (for styling/selection/debug)
  const groupId = spec.ids.group(node.id, `legend-${channel}`);
  node.groups.push({
    id: groupId, role: "legend",
    plots: [legendPlots[0]],
    annotates: { layout: scale.id, channel },
  });

  return controller;
}

function resolveTickAlgo(scale: Scale, registries: Registries): string {
  if (scale.ticks?.algorithm) return scale.ticks.algorithm;
  // operator-level ticks keeps first priority; then the domain's declared tick algo; then the
  // ordinal fallback for domain-less operators (spike-verified outcome-equal with the old
  // algo.ticks → domainSpec.ticks → domainKind chain).
  const desc = registries.operators.has(scale.descriptor) ? registries.operators.get(scale.descriptor) : undefined;
  return desc?.ticks ?? desc?.domain?.ticks ?? "ordinal";
}


function addPlot(spec: Spec, node: Node, key: string, markType: string, source: Plot["source"], channels: Record<string, Expr>): string {
  const id = spec.ids.plot(node.id, key);
  spec.plots.set(id, { id, node: node.id, source, markType, channels, params: {}, origin: "legend" });
  node.plots.push(id);
  return id;
}
