// Spec instantiation — turns DSL bindings (scale / layout / channel / extent) into IR
// instances + their cells. Split out of api/builder (WUMODULES Phase 2) so the builder is
// just the fluent surface. Imports the DSL value-types from builder as TYPES only (erased at
// runtime), so there is no import cycle: builder → instantiate (values), instantiate ⇢ builder (types).
import { staticOutSpace } from "../operator/operator.js";
import type { Scalar } from "../data/schema.js";
import type { LayoutId, NodeId, PlotId } from "../types/ids.js";
import type { Node, Extent } from "../ir/node.js";
import { boxEdgesOf, sourceKey, type Plot, type TableRef } from "../ir/plot.js";
import type { DomainTreatment, Scale } from "../ir/layout.js";
import type { CellRole, CellStore } from "../ir/cell.js";
import type { ChannelKind, MarkDescriptor } from "../ir/mark.js";
import { wrapOf } from "../ir/mark.js";
import { binary, col, layoutOutput, literal, tableRef, type Expr } from "../ir/expr.js";
import { coord, dataSpace, pixelSpace, relativeSpace, type Space } from "../types/attr.js";
import { parseInputs, type ViaHandle } from "./refs.js";
import { isColumnBinding, isDatumBinding, isExprBinding, isLitMarker, isPxMarker, type ChannelValue, type ColumnBinding, type Ctx, type LayoutProducer, type LitMarker, type PendingAll, type PendingOutput, type ScaleSpec } from "./builder.js";

const EXTENT: CellRole = "extent";
const DOMAIN: CellRole = "domain";
const SCALE_ABBREV: Record<string, string> = { linear: "lin", log: "log", ordinal: "ord", bandX: "band", bandY: "band", point: "pt", color: "clr" }; // id cosmetics, keyed by descriptor

export const isScaleSpec = (v: unknown): v is ScaleSpec => typeof v === "object" && v !== null && (v as { __scale?: unknown }).__scale === "scale";
export const isPendingOutput = (v: unknown): v is PendingOutput => typeof v === "object" && v !== null && (v as { __out?: unknown }).__out === "pending";
export const isPendingAll = (v: unknown): v is PendingAll => typeof v === "object" && v !== null && (v as { __out?: unknown }).__out === "pending-all";

/** route (box-model §5 rev.): expand each endpoint's via HANDLE (`route({ src, dst })`) into the
 *  HIDDEN borrow channels the layout's declared inputs bind by name — the endpoint anchor
 *  (dvl_a<k>_x/y = the referent's placed x/y) plus, when the referent can produce a FULL box,
 *  the four box edges (dvl_b<k>_* — the box RIDES the borrow: the same via join reads the
 *  referent's BOXED relation). Picking a box sets `referent.needsBox` here, at bind time — the
 *  need is authored, never sniffed — and stamps the referent's boundaryShape into the producer's
 *  options (shape<k>), so the exec clips dots in L2 without the author saying so. A partial or
 *  absent box degrades that endpoint to center attachment (anchor borrows only). Runs in mark()
 *  before the producer-finalize pass; after it, `p.arg` is cleared so finalizeLayout's
 *  natural-join default binds every declared input by its own (hidden-channel) name. */
export function desugarRouteInputs(ctx: Ctx, channels: Record<string, ChannelValue>): void {
  const done = new Set<LayoutProducer>();
  for (const val of Object.values(channels)) {
    if (!isPendingOutput(val) || val.producer.descriptor !== "route" || done.has(val.producer)) continue;
    const p = val.producer;
    done.add(p);
    const bag = (p.arg ?? {}) as Record<string, unknown>;
    for (const [role, k] of [["src", 1], ["dst", 2]] as const) {
      const h = bag[role] as ViaHandle | undefined;
      if (h === undefined || typeof h !== "object" || typeof h.via?.plot !== "string" || typeof h.out !== "function") {
        throw new Error(`route: "${role}" must be a plot via handle — route({ src: nodes.via(eq(...)), dst: nodes.via(eq(...)) })`);
      }
      const refPlot: Plot | undefined = ctx.spec.plots.get(h.via.plot as PlotId);
      if (refPlot === undefined) throw new Error(`route: "${role}" references unknown plot "${h.via.plot}"`);
      if (refPlot.channels["x"] === undefined || refPlot.channels["y"] === undefined) {
        throw new Error(`route: referent "${refPlot.id}" must bind x and y — route borrows the placed position as the endpoint anchor`);
      }
      channels[`dvl_a${k}_x`] = h.out("x");
      channels[`dvl_a${k}_y`] = h.out("y");
      // Box borrows: only when the referent's descriptor yields a FULL symbolic box under its
      // bound channels (a dot's default r counts; a rect missing its y-axis does not — that
      // endpoint degrades to center, the old partial-box rule).
      const desc = ctx.registries.marks.has(refPlot.markType) ? ctx.registries.marks.get(refPlot.markType) : undefined;
      const boxable = refPlot.origin === undefined && desc !== undefined && (desc.cardinality ?? "per-row") === "per-row";
      const edges = boxable ? boxEdgesOf(refPlot, desc) : undefined;
      if (edges?.left !== undefined && edges.right !== undefined && edges.top !== undefined && edges.bottom !== undefined) {
        refPlot.needsBox = true;
        for (const [suffix, attr, axis] of [["x0", "dvl_x0", "x"], ["y0", "dvl_y0", "y"], ["x1", "dvl_x1", "x"], ["y1", "dvl_y1", "y"]] as const) {
          channels[`dvl_b${k}_${suffix}`] = tableRef(refPlot.id, attr, h.via.on, { space: pixelSpace(coord(axis)), arity: "per-row" });
        }
        if (p.options[`shape${k}`] === undefined) p.options[`shape${k}`] = desc!.boundaryShape ?? "box";
      }
    }
    p.arg = undefined; // natural-join default: every declared input binds by its own name
  }
}

/** Expand every wildcard binding (`.pick("*")` / a bare-spread producer) into the layout's FULL
 *  declared output set — one channel per `output.add` column, bound to that output. Explicit channels
 *  already present WIN (a wildcard never overwrites them), so `{ ...band("c").pick("*"), x: 12 }` keeps
 *  the literal x. A no-op when no wildcard is present. Run before the mark's producer/bind passes. */
export function expandLayoutOutputs(ctx: Ctx, channels: Record<string, ChannelValue>): Record<string, ChannelValue> {
  if (!Object.values(channels).some(isPendingAll)) return channels;
  const out: Record<string, ChannelValue> = {};
  const wildcards: PendingAll[] = [];
  for (const [ch, v] of Object.entries(channels)) (isPendingAll(v) ? wildcards.push(v) : (out[ch] = v));
  for (const w of wildcards) {
    const o = ctx.registries.operators.get(w.producer.descriptor).output; // augment ({add}) or replace ({columns})
    const names = "add" in o ? o.add.map((c) => c.name) : o.columns.map((c) => c.name);
    for (const name of names) if (!(name in out)) out[name] = w.producer.out(name);
  }
  return out;
}
/** §5b channel-set preprocessing (mark()/subplots(), before per-channel binding). Two rewrites,
 *  both on the bag because they need two channels at once (bindChannel sees one):
 *  1. POSITIONS — a bare value whose channel defaults to "lit", or an explicit lit() marker,
 *     desugars to ExprBinding(sibling axis spec, literal(v)): the constant trains the axis's
 *     domain and places per-row, exactly `x(col("a") + k)`'s machinery. No sibling scale →
 *     left alone; bindChannel raises the loud no-scale error (the single error site).
 *  2. LENGTHS (§5b step 4, unlocked by §4's interval drawBox) — `w: lit(30)` on a mark whose
 *     channel table puts w on the x axis (pixelAxes) AND declares the interval partner x2
 *     desugars to an x2 binding: x's own expression plus 30, through the SAME scale instance.
 *     Well-defined under ANY monotone scale — under log each box gets the width of ITS 30-unit
 *     interval — and the domain grows to include x+30. Runs AFTER the position pass so a bare
 *     x has already been rewritten to its ExprBinding. */
export function desugarDataLiterals(mark: MarkDescriptor, channels: Record<string, ChannelValue>): void {
  const lengthLits: Array<[string, LitMarker]> = [];
  for (const [ch, val] of Object.entries(channels)) {
    const kind = mark.channels[ch];
    if (kind === undefined) continue;
    const bare = (typeof val === "number" || typeof val === "string" || typeof val === "boolean") && wrapOf(mark, ch) === "lit";
    if (!bare && !isLitMarker(val)) continue;
    const axis = kind === "positional-x" ? "x" : kind === "positional-y" ? "y" : null;
    if (axis === null) {
      if (isLitMarker(val) && kind === "pixel") lengthLits.push([ch, val]);
      continue; // non-desugarable lit → bindChannel reports
    }
    const spec = axisSpecOf(mark, channels, axis);
    if (spec === undefined) continue;
    const v = isLitMarker(val) ? val.value : (val as number | string | boolean);
    channels[ch] = { __exprBinding: "expr-binding", scale: spec, expr: literal(v as Scalar) };
  }
  for (const [ch, val] of lengthLits) {
    const axis = mark.pixelAxes?.[ch];
    if (axis !== "x" && axis !== "y") continue; // no single axis (strokeWidth's "xy") — bindChannel reports
    const partner = `${axis}2`;
    if (mark.channels[partner] !== (axis === "x" ? "positional-x" : "positional-y")) continue; // no interval partner (dot's r) — bindChannel reports
    if (channels[partner] !== undefined) {
      throw new Error(`"${ch}: lit(${String(val.value)})" conflicts with an explicit ${partner} binding — the length desugars INTO ${partner}; bind one or the other`);
    }
    if (typeof val.value !== "number") throw new Error(`"${ch}: lit(${String(val.value)})": a data-unit length must be a number`);
    const primary = mark.spatial[axis][0];
    const pv = channels[primary];
    const base = isColumnBinding(pv) ? { scale: pv.scale, expr: col(pv.column) }
      : isExprBinding(pv) ? { scale: pv.scale, expr: pv.expr }
      : isScaleSpec(pv) && typeof pv.arg === "string" ? { scale: pv, expr: col(pv.arg) }
      : undefined;
    if (base === undefined) {
      throw new Error(`"${ch}: lit(${val.value})" needs "${primary}" bound through a scale over a column or expression — a pixel ${primary} has nothing to add ${val.value} data units to`);
    }
    channels[partner] = { __exprBinding: "expr-binding", scale: base.scale, expr: binary("+", base.expr, literal(val.value)) };
    delete channels[ch];
  }
}

/** The ScaleSpec bound to any positional channel on `axis` in this bag (a binding's .scale or a
 *  bare fitted spec). First hit wins — frame-scale sharing unifies duplicates anyway. */
function axisSpecOf(mark: MarkDescriptor, channels: Record<string, ChannelValue>, axis: "x" | "y"): ScaleSpec | undefined {
  const want: ChannelKind = axis === "x" ? "positional-x" : "positional-y";
  for (const [ch, val] of Object.entries(channels)) {
    if (mark.channels[ch] !== want) continue;
    if (isScaleSpec(val)) return val;
    if (isColumnBinding(val) || isDatumBinding(val) || isExprBinding(val)) return val.scale;
  }
  return undefined;
}

/** The §5b no-silent-fallback errors: a data value with nothing to place through, and the
 *  not-yet-wired data-unit length. */
function litError(plotId: PlotId, channel: string, kind: ChannelKind | undefined, value: unknown): Error {
  const axis = kind === "positional-x" ? "x" : kind === "positional-y" ? "y" : undefined;
  if (axis !== undefined) {
    return new Error(`${plotId}: "${channel}: ${String(value)}" is a data value but no ${axis} scale is bound on this mark — bind one on the ${axis} axis (e.g. ${axis}: linear("col")) or write px(${String(value)}) for a pixel coordinate`);
  }
  return new Error(`${plotId}: "${channel}: lit(${String(value)})" is a data-unit length, but "${channel}" has no single axis or no interval partner channel to desugar into — use a pixel size (${channel}: ${String(value)}) or bind the interval channel yourself`);
}
const isExpr = (v: unknown): v is Expr => typeof v === "object" && v !== null && "kind" in v && "type" in v;

const columnOf = (arg: unknown, fallback: string): string => (typeof arg === "string" ? arg : fallback);

export function bindChannel(ctx: Ctx, nodeId: NodeId, plotId: PlotId, source: TableRef, mark: MarkDescriptor, channel: string, value: ChannelValue, producerIds: Map<LayoutProducer, LayoutId>, baseProj?: Record<string, Expr>): Expr {
  const kind = mark.channels[channel];
  const space: Space = kind ? mark.expectedType(channel).space : dataSpace;
  if (isColumnBinding(value)) return finalizeScale(ctx, nodeId, plotId, source, mark, channel, space, value.scale, value.column);
  // A datum `S(v)` is a 1-row relation reused through the SAME scale path (§A2): `source` is the
  // synthesized `values` producer (builder.mark), the datum lives in a column named by the channel,
  // and it binds exactly like a column — so it joins/shares S by identity, trains the domain as a
  // 1-row member, and applies through S. No special member kind, no apply-only, no lowering.
  if (isDatumBinding(value)) return finalizeScale(ctx, nodeId, plotId, source, mark, channel, space, value.scale, channel);
  // `x(col("a") + col("b"))` — a scale over a per-row DATA expression. Materialize the arithmetic as a
  // base projection (computed on the plot's base, so both TRAIN and APPLY see it) and bind the scale to
  // the minted column, exactly as a plain column binds. The space checker still governs the OUTPUT (a
  // scale emits a coordinate); the input is any data-space value, a column being the common case.
  if (isExprBinding(value)) {
    if (baseProj === undefined) throw new Error(`bindChannel: a scale-over-expression on "${channel}" needs a base-projection accumulator (bind through mark())`);
    const colName = `dvl_se_${channel}`;
    baseProj[colName] = value.expr;
    return finalizeScale(ctx, nodeId, plotId, source, mark, channel, space, value.scale, colName);
  }
  if (isScaleSpec(value)) return finalizeScale(ctx, nodeId, plotId, source, mark, channel, space, value);
  if (isPendingOutput(value)) {
    const desc = ctx.registries.operators.get(value.producer.descriptor);
    // The operator's DECLARED output space IS the expression's type — the channel never overwrites
    // it. Every operator now declares (registration error, §12.2); a "binding" declaration is the
    // sanctioned polymorphic case: the INSTANCE's space — read from the frame channel it serves.
    const declaredSpace: Space = staticOutSpace(desc.outSpaces?.[value.output]) ?? space;
    return layoutOutput(producerIds.get(value.producer)!, value.output, { space: declaredSpace, arity: "per-row" });
  }
  if (isExpr(value)) return value; // a built Expr (col/binary, or a cross-mark via-ref from pick)
  // ── §5b: the ONE place a bare value acquires a space. A bare value takes its channel's
  // DECLARED default wrapper (ir/mark.ts WRAP_OF_KIND); an explicit wrapper always wins. The
  // positional "lit" cases were desugared on the channel bag (desugarDataLiterals) when a
  // sibling scale exists — one reaching here has nothing to place through, so it errors loudly.
  // There is NO silent pixel fallback; that was the bug class this section removes.
  if (isPxMarker(value)) {
    const pxSpace: Space = space.space === "relative" ? pixelSpace(space.geom) : space;
    return typeof value.value === "string" ? col(value.value, pxSpace) : literal(value.value, pxSpace, "scalar");
  }
  if (isLitMarker(value)) throw litError(plotId, channel, kind, value.value);
  if (wrapOf(mark, channel) === "lit") throw litError(plotId, channel, kind, value);
  // default wrapper "px" (pixel sizes) and "value" (color/text/…): the stamp both take today —
  // pixel with the channel's geometry when the channel expects a placed value, else the
  // channel's own space.
  const litSpace: Space = space.space === "relative" ? pixelSpace(space.geom) : space;
  return literal(value as Scalar, litSpace, "scalar");
}

function makeScale(ctx: Ctx, id: LayoutId, spec: ScaleSpec, source: TableRef, columnOverride?: string): Scale {
  const desc = ctx.registries.operators.get(spec.descriptor);
  const holes = desc.holes?.() ?? {}; // the component declares which cells it owns — just the domain now
  const effectiveArg = columnOverride ?? spec.arg;
  return {
    id,
    descriptor: spec.descriptor,
    inputs: parseInputs(desc, effectiveArg, source),
    params: spec.params,
    shared: spec.shared,
    // authored containment slack (scale-expansion §4) → instance options; allocScaleExpansion reads it
    options: spec.expand !== undefined ? { expand: spec.expand } : undefined,
    // derived default (ex-defaultDomain): a niceable domain ⇒ "nice", else "data" — recorded API
    // intent only (§12 S6: no execution consumer yet).
    treatment: spec.treatment ?? (desc.domain !== undefined && "nice" in desc.domain && desc.domain.nice !== undefined ? "nice" : "data"),
    domain: ctx.spec.cells.alloc(DOMAIN, undefined, holes.domain ?? "relation"), // resolved domain set ({lo,hi} / categories)
  };
}

function finalizeScale(ctx: Ctx, nodeId: NodeId, plotId: PlotId, source: TableRef, mark: MarkDescriptor, channel: string, space: Space, spec: ScaleSpec, explicitColumn?: string): Expr {
  // Positional scales are FRAME-scoped — induced from domain identities, shared by
  // (axis, side); §reflection principle. Non-positional encodings are per-channel.
  if (space.space === "relative" && space.geom.kind === "coord") return bindFrameScale(ctx, nodeId, plotId, source, mark, channel, space.geom.axis, spec, explicitColumn);
  const id = ctx.spec.ids.layout(plotId, `${SCALE_ABBREV[spec.descriptor] ?? spec.descriptor}-${channel}`);
  // Forward the deferred-form column: `const s = color(); fill: s("mass")` binds its column here
  // (explicitColumn), exactly as the positional path does — without it a non-positional scale over a
  // deferred spec has no source column and compiles to an empty layout.
  ctx.spec.layouts.set(id, makeScale(ctx, id, spec, source, explicitColumn)); // non-positional (color/size/etc.)
  return layoutOutput(id, "value", { space, arity: "per-row" });
}

/** Bind a positional channel to the node's frame (WUAXIS §1). Sharing is by scale IDENTITY —
 *  `(dim, descriptor, TABLE, column)`, the QUANTITY — so two layers on `x: linear("mass")` over ONE
 *  table share one scale (domain unions their data, one axis) while the same column name on a
 *  DIFFERENT table is a different quantity. Reusing the SAME ScaleSpec OBJECT is the authored
 *  equivalence: within a node it joins the instance (members may then span tables); across nodes it
 *  tags the instances with one `equiv` class (planDomainGroups unions them). Placement is NOT
 *  decided here: an author `side` is recorded as a PIN; `assignSides` resolves sides at lowering. */
function bindFrameScale(ctx: Ctx, nodeId: NodeId, plotId: PlotId, source: TableRef, mark: MarkDescriptor, channel: string, axis: "x" | "y", spec: ScaleSpec, explicitColumn?: string): Expr {
  const node = ctx.spec.nodes.get(nodeId)!;
  const column = explicitColumn ?? columnOf(spec.arg, channel);
  const member = { plot: plotId, source, column };
  const equivTag = ctx.scaleEquiv?.get(spec); // this spec OBJECT was bound before ⇒ authored equivalence
  // same QUANTITY on the same CHANNEL ⇒ same frame scale: the same authored OBJECT (the class
  // leader's id IS the tag), or the same (table, column) identity. Identity is PER-CHANNEL: layers
  // sharing `x` share the instance; a mark's coupled x2 (even the same object/column) is its OWN
  // instance — the coupling pass below unions the domains instead (one apply per channel, no column
  // fan-out).
  const existing = node.frame.scales
    .map((sid) => ctx.spec.layouts.get(sid) as Scale)
    .find(
      (s) =>
        s.dim === axis &&
        (s.channel ?? channel) === channel &&
        ((equivTag !== undefined && (s.id === equivTag || s.equiv === equivTag)) ||
          (s.descriptor === spec.descriptor && s.members?.[0]?.column === column && sourceKey(s.members![0].source) === sourceKey(source))),
    );
  const out = (id: LayoutId): Expr => layoutOutput(id, "value", { space: relativeSpace(coord(axis)), arity: "per-row" });
  if (existing) {
    existing.members!.push(member);
    mergeAxisConfig(existing, spec, ctx);
    coupleChannels(ctx, nodeId, plotId, mark, axis);
    return out(existing.id);
  }
  const nth = node.frame.scales.filter((sid) => (ctx.spec.layouts.get(sid) as Scale).dim === axis).length;
  const id = `${nodeId}/${axis}${nth === 0 ? "" : nth + 1}`; // n0/x, n0/x2, …
  const scale = makeScale(ctx, id, spec, source, explicitColumn); // frame scale ⇒ positional; owns only its domain (NORMALIZED)
  scale.dim = axis;
  scale.channel = channel;
  scale.side = spec.side; // an author side is a PIN; undefined = assignSides places it (primary side preferred)
  scale.axis = spec.axis;
  scale.members = [member];
  // the authored-equivalence class: instances bound from ONE ScaleSpec object share a tag. Set only
  // on actual reuse (the tag = the first instance's id, backfilled onto it) — `equiv` present ⇔
  // the author declared these the same quantity.
  ctx.scaleEquiv ??= new Map();
  if (equivTag !== undefined) {
    scale.equiv = equivTag;
    const first = ctx.spec.layouts.get(equivTag);
    if (first !== undefined) first.equiv = equivTag;
  } else {
    ctx.scaleEquiv.set(spec, id);
  }
  // Suppress axis for secondary channels (mark-structural, not domain-related).
  const primary = mark.spatial[axis]?.[0];
  if (primary !== undefined && channel !== primary) scale.axis ??= false;
  ctx.spec.layouts.set(id, scale);
  node.frame.scales.push(id);
  coupleChannels(ctx, nodeId, plotId, mark, axis);
  // NORMALIZED: a frame scale emits a relative [0,1] coordinate; the frame affine (graph) places it.
  return out(id);
}

/** Mark-coupled channels (§C6, restored — deleted at ba085ca with its tests left in place):
 *  every channel the mark declares positional on `axis` is ONE quantity-axis (x/x2, x1/x2) —
 *  `mark.spatial[axis]` IS the registration. Bound instances of the group get one `equiv`
 *  class, so their domains UNION through the ordinary gather-scatter (planDomainGroups) while
 *  each instance keeps its own apply/output. Authored equiv tags are ADOPTED (never displaced);
 *  distinct pre-existing tags merge. Axis suppression for secondaries is handled structurally
 *  at bind (the mark.spatial primary check above). */
function coupleChannels(ctx: Ctx, nodeId: NodeId, plotId: PlotId, mark: MarkDescriptor, axis: "x" | "y"): void {
  const group = mark.spatial[axis];
  if (group === undefined || group.length < 2) return;
  const node = ctx.spec.nodes.get(nodeId)!;
  const insts = node.frame.scales
    .map((sid) => ctx.spec.layouts.get(sid) as Scale)
    .filter((s) => s.dim === axis && s.channel !== undefined && group.includes(s.channel) && s.members?.some((m) => m.plot === plotId));
  if (insts.length < 2) return;
  const tags = [...new Set(insts.map((i) => i.equiv).filter((t): t is string => t !== undefined))];
  const target = tags[0] ?? `cpl:${plotId}:${axis}`;
  if (tags.length > 1) for (const inst of ctx.spec.layouts.values()) if (inst.equiv !== undefined && tags.includes(inst.equiv)) inst.equiv = target;
  for (const i of insts) i.equiv = target;
}


/** First-wins axis config across shared bindings; a differing later config warns (one axis, one config). */
function mergeAxisConfig(scale: Scale, spec: ScaleSpec, _ctx: Ctx): void {
  if (spec.axis !== undefined && scale.axis !== undefined && JSON.stringify(spec.axis) !== JSON.stringify(scale.axis)) {
    console.warn(`dvl: axis config on "${scale.id}" differs across bindings — keeping the first`);
  }
  if (scale.axis === undefined) scale.axis = spec.axis;
  if (scale.side === undefined) scale.side = spec.side; // a later PIN on a shared scale still pins it
}

/** Finalize a pending layout into one LayoutInstance (shared across its picked outputs). */
export function finalizeLayout(ctx: Ctx, plotId: PlotId, source: TableRef, p: LayoutProducer): LayoutId {
  const desc = ctx.registries.operators.get(p.descriptor);
  const id = ctx.spec.ids.layout(plotId, p.descriptor);
  const inputs = parseInputs(desc, p.arg, source);
  // NATURAL-JOIN default: a marks input the author left unprojected (force("edges") names only the
  // aux) binds each declared input by its OWN name — recorded on the instance, so the mark table
  // projects it and every reader (inputBinding, compilePlot) sees one resolved binding.
  // A REFINE op (requiresPixelInputs — it consumes the mark's PLACED channels) extends this to
  // PARTIAL projects: unnamed inputs keep their channel-name default (fitText({ text: 'label' })
  // still reads the w/h channels), and the project is rebuilt in DECLARED order so the primary
  // input is always first, regardless of the author's key order.
  if (inputs.marks !== undefined && (desc.inputs.marks ?? []).length > 0) {
    const given = inputs.marks.project;
    if (given === undefined) {
      inputs.marks = { ...inputs.marks, project: Object.fromEntries((desc.inputs.marks ?? []).map((c) => [c.name, c.name])) };
    } else if (desc.requiresPixelInputs === true) {
      inputs.marks = { ...inputs.marks, project: Object.fromEntries((desc.inputs.marks ?? []).map((c) => [c.name, given[c.name] ?? c.name])) };
    }
  }
  const holes = desc.holes?.() ?? {}; // a positional layout owns its holes, like a scale — just the domain
  ctx.spec.layouts.set(id, {
    id,
    descriptor: p.descriptor,
    inputs,
    params: p.params,
    options: Object.keys(p.options).length > 0 ? p.options : undefined, // static config → binding.options (band padding, …)
    // an authored { shared } on a layout call is the per-cell pin: a perCell operator (force,
    // treemap) with shared:true runs ONCE globally inside a template; shared:false forces
    // per-cell even for operators that don't declare it.
    shared: typeof p.options.shared === "boolean" ? p.options.shared : undefined,
    domain: holes.domain !== undefined ? ctx.spec.cells.alloc(DOMAIN, undefined, holes.domain) : undefined, // the box comes from the node extent (graph)
  });
  return id;
}

/** A child-node extent with unbound cells (sized by the arrange solver, C6). */
export function unboundExtent(cells: CellStore): Extent {
  const px = pixelSpace(coord("x")), py = pixelSpace(coord("y"));
  return {
    outer: { left: cells.alloc(EXTENT, undefined, "scalar", px), right: cells.alloc(EXTENT, undefined, "scalar", px), top: cells.alloc(EXTENT, undefined, "scalar", py), bottom: cells.alloc(EXTENT, undefined, "scalar", py) },
    content: { left: cells.alloc(EXTENT, undefined, "scalar", px), right: cells.alloc(EXTENT, undefined, "scalar", px), top: cells.alloc(EXTENT, undefined, "scalar", py), bottom: cells.alloc(EXTENT, undefined, "scalar", py) },
  };
}

export function makeExtent(cells: CellStore, left: number, top: number, right: number, bottom: number): Extent {
  const px = pixelSpace(coord("x")), py = pixelSpace(coord("y"));
  const seal = (v: number, space: Space) => {
    const c = cells.alloc(EXTENT, v, "scalar", space);
    cells.write(c, v, "sealed");
    return c;
  };
  const hole = (space: Space) => cells.alloc(EXTENT, undefined, "scalar", space);
  return {
    outer: { left: seal(left, px), right: seal(right, px), top: seal(top, py), bottom: seal(bottom, py) },
    content: { left: hole(px), right: hole(px), top: hole(py), bottom: hole(py) },
  };
}
