// Dead-code elimination: remove ops whose output cells have no consumers.
// Protected: ops with no writes (pure side-effects) and ops writing SINK-role cells — outputs
// consumed EXTERNALLY by the caller, not by another op (the render SVG, verify's diagnostics;
// §11.2 F8: the spike's only wiring regression was DCE pruning verify).
import type { OptRule, RuleCtx, RuleMatch } from "../rule.js";
import type { OpSpec } from "../../plan/opspec.js";

export const deadCodeElim: OptRule = {
  name: "dead-code-elim",

  match(op: OpSpec, ctx: RuleCtx): RuleMatch | null {
    if (op.writes.length === 0) return null;
    if (op.writes.some((w) => ctx.cellRole(w) === "sink")) return null; // externally consumed
    const allDead = op.writes.every(w => ctx.graph.consumers(w).length === 0);
    return allDead ? { anchor: op } : null;
  },

  apply(m: RuleMatch, ctx: RuleCtx): void {
    ctx.graph.splice(m.anchor, 1);
  },
};
