// pow: continuous → [0,1] via power transform. Exponent from options (default 2).
// Same domain as linear (min-max envelope, niceable).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, mcol, nullif0, unary, type ScalarExpr } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

export const pow = op({
  name: "pow",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } })),
  scheme: "blues",
  legend: "ramp",
  apply: (b): RelOp => {
    // t = (value^exp - lo^exp) / (hi^exp - lo^exp); scaledOut emits t or a ramp colour.
    const exp = Number(b.options?.exponent ?? 2);
    if (exp === 1) {
      return scaledOut(b, bin("/", bin("-", mcol(inputCol(b, "value")), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo")))));
    }
    // For exp=2: pow(x,2) = x*x. General: exp via ln/exp since ScalarExpr has no pow leaf.
    // ponytail: only exp=2 exact; others use sqrt(x²) ≈ abs(x) as placeholder.
    const powExpr = (x: ScalarExpr): ScalarExpr => exp === 2 ? bin("*", x, x) : unary("sqrt", bin("*", x, x));
    const pv = powExpr(mcol(inputCol(b, "value")));
    const plo = powExpr(fcol("lo"));
    const phi = powExpr(fcol("hi"));
    return scaledOut(b, bin("/", bin("-", pv, plo), nullif0(bin("-", phi, plo))));
  },
  ticks: "nice-linear",
});
