// Pure fitText algorithm — no DVL dependencies. Solves font size, rotation, and line wrapping
// for text labels constrained to bounding boxes.

export interface FitTextInput {
  text: string;
  box: { w: number; h: number };
}

export interface FitTextOptions {
  maxFontSize?: number;
  minFontSize?: number;
  shared?: boolean;
  rotate?: boolean;
  wrap?: boolean;
  padding?: number;
  measure: (text: string, fontSize: number) => number;
}

export interface FitTextResult {
  fontSize: number;
  rotate: number;
  lines: string[];
  truncated: boolean;
}

// DEFAULTS: each label solves against ITS OWN box (shared: true opts into one uniform size),
// rotation is tried (rotate: false pins horizontal), and the size is UNCAPPED — the box bounds
// the solve ("as big as fits"; a finite maxFontSize is the opt-in ceiling).
export function fitText(items: FitTextInput[], opts: FitTextOptions): FitTextResult[] {
  const maxFS = opts.maxFontSize ?? Infinity;
  const minFS = opts.minFontSize ?? 6;
  const pad = opts.padding ?? 2;
  const { measure } = opts;

  const results = items.map(item => solveOne(item, maxFS, minFS, pad, measure, opts));

  if (opts.shared === true) {
    const sharedFS = Math.min(...results.map(r => r.fontSize));
    if (sharedFS < maxFS) return items.map(item => solveOne(item, sharedFS, minFS, pad, measure, opts));
  }
  return results;
}

function solveOne(item: FitTextInput, maxFS: number, minFS: number, pad: number,
  measure: (t: string, fs: number) => number, opts: FitTextOptions): FitTextResult {
  const availW = item.box.w - 2 * pad;
  const availH = item.box.h - 2 * pad;
  if (item.text.length === 0) return { fontSize: Math.min(maxFS, Math.max(minFS, availH / 1.2)), rotate: 0, lines: [""], truncated: false };
  if (availW <= 0 || availH <= 0) return { fontSize: minFS, rotate: 0, lines: [""], truncated: true };

  const hResult = tryFit(item.text, availW, availH, maxFS, minFS, measure, opts.wrap ?? false);
  if (opts.rotate === false) return hResult;
  const vResult = tryFit(item.text, availH, availW, maxFS, minFS, measure, opts.wrap ?? false);
  if (vResult.fontSize > hResult.fontSize) return { ...vResult, rotate: -90 };
  return hResult;
}

function tryFit(text: string, availW: number, availH: number, maxCap: number, minFS: number,
  measure: (t: string, fs: number) => number, wrap: boolean): FitTextResult {
  // An UNCAPPED (or huge) maxFontSize is bounded by the box itself: a single line can never be
  // taller than availH (fs·1.2 ≤ availH), so the search stays finite — maxFontSize: Infinity
  // means "as big as fits", not a runaway.
  const maxFS = Math.max(minFS, Math.min(maxCap, availH / 1.2));
  const lines = wrap ? wrapLines(text, availW, s => measure(s, maxFS)) : [text];
  const lineH = maxFS * 1.2;
  const textW = Math.max(...lines.map(l => measure(l, maxFS)));

  if (textW <= availW && lines.length * lineH <= availH) {
    return { fontSize: maxFS, rotate: 0, lines, truncated: false };
  }

  // Binary search for largest fontSize that fits
  let lo = minFS, hi = maxFS, bestLines = lines;
  for (let iter = 0; iter < 20 && hi - lo > 0.5; iter++) {
    const mid = (lo + hi) / 2;
    const ls = wrap ? wrapLines(text, availW, s => measure(s, mid)) : [text];
    const w = Math.max(...ls.map(l => measure(l, mid)));
    if (w <= availW && ls.length * mid * 1.2 <= availH) { lo = mid; bestLines = ls; }
    else { hi = mid; }
  }

  const fontSize = Math.max(Math.round(lo * 2) / 2, minFS); // round to 0.5
  bestLines = wrap ? wrapLines(text, availW, s => measure(s, fontSize)) : [text];

  const finalW = Math.max(...bestLines.map(l => measure(l, fontSize)));
  if (finalW > availW || bestLines.length * fontSize * 1.2 > availH) {
    const maxLines = Math.max(1, Math.floor(availH / (fontSize * 1.2)));
    bestLines = bestLines.slice(0, maxLines);
    bestLines[bestLines.length - 1] = truncateLine(bestLines[bestLines.length - 1], availW, fontSize, measure);
    return { fontSize, rotate: 0, lines: bestLines, truncated: true };
  }
  return { fontSize, rotate: 0, lines: bestLines, truncated: false };
}

export function wrapLines(text: string, availW: number, measure: (s: string) => number): string[] {
  const words = text.split(/\s+/).filter(w => w.length > 0);
  if (words.length === 0) return [""];
  const lines: string[] = [];
  let current = words[0];
  for (let i = 1; i < words.length; i++) {
    const candidate = current + " " + words[i];
    if (measure(candidate) <= availW) { current = candidate; }
    else { lines.push(current); current = words[i]; }
  }
  lines.push(current);
  return lines;
}

function truncateLine(line: string, availW: number, fontSize: number, measure: (t: string, fs: number) => number): string {
  if (measure(line, fontSize) <= availW) return line;
  for (let i = line.length - 1; i >= 0; i--) {
    const candidate = line.slice(0, i) + "…";
    if (measure(candidate, fontSize) <= availW) return candidate;
  }
  return "…";
}
