// Relation — the unit every layout/scale reads and writes (WULAYOUT_IMPL, C4 refactor).
// A relation is SQL (a foldable `SqlFragment`) or JS (materialized rows + schema). A
// COLUMN is a 1-column relation; a scalar fit is a 1-row relation; force's positions are
// an N-row relation — all the same kind. SQL composition goes through the data layer's
// `SqlFragment` → `fold` → `emit`, never string concatenation.
import type { Database } from "../data/database.js";
import { defaultDialect } from "../data/dialect.js";
import { emit, type CellEnv } from "../data/emit.js";
import { fold } from "../data/fold.js";
import type { RelationRef, SqlFragment } from "../data/fragment.js";
import type { CellId } from "../data/ids.js";
import type { OutSchema, RawRow, Row, Scalar, Schema } from "../data/schema.js";
import { sqlLiteral } from "../data/dialect.js";

export type Substrate = "sql" | "js";
export type JsRel = { readonly rows: readonly Row[]; readonly schema: Schema };
export type Relation =
  | { readonly substrate: "sql"; readonly frag: SqlFragment }
  | { readonly substrate: "js"; readonly rows: readonly Row[]; readonly schema: Schema };

export const sqlRel = (frag: SqlFragment): Relation => ({ substrate: "sql", frag });
export const jsRel = (rows: readonly Row[], schema: Schema): Relation => ({ substrate: "js", rows, schema });

/** Sanitize a logical key into a valid SQL identifier (fold names CTEs `op__cte`). */
export const sanitizeOp = (key: string): string => key.replace(/[^A-Za-z0-9_]/g, "_");

/** Build a single-CTE fragment. `key` is its stable identity (dedup in fold) + the
 *  uniquification prefix (sanitized). Bodies reference relations as `@name`, cells as `{name}`. */
export function mkFrag(key: string, body: string, inputs: Readonly<Record<string, RelationRef>>, outputs: OutSchema, cells: readonly CellId[] = []): SqlFragment {
  return { id: key, op: sanitizeOp(key), ctes: [{ name: "r", body }], result: "r", inputs, outputs, cells };
}

// `apply` attaches a layout's trained fit to the marks one of two ways, differing only in
// how the fit's CARDINALITY relates to the marks (both add columns key-preservingly, m.*):
//   • augmentBroadcast — the fit is ONE row shared by EVERY mark (a scale's {min,max}
//     domain), CROSS-JOINed so all marks read the same `f."…"`; or there is NO fit and the
//     expressions are self-contained (ordinal's window function).
//   • augmentKeyed — the fit has ONE ROW PER MARK, matched on a key; each mark JOINs its
//     OWN fit row (force positions by dvl_mark, a cross-mark FK). The fit is NOT shared.

/** Collect the column names a fragment declares (walking the passthrough chain). */
export function fragColumns(frag: SqlFragment): ReadonlySet<string> {
  const cols = new Set<string>();
  const walk = (f: SqlFragment): void => {
    const o = f.outputs;
    if ("columns" in o) { for (const c of o.columns) cols.add(c.name); return; }
    for (const c of o.add) cols.add(c.name);
    const src = f.inputs[o.passthrough];
    if (src !== undefined && "fragment" in src) walk(src.fragment);
  };
  walk(frag);
  return cols;
}

/** The augment SELECT head: splits added columns into those that REPLACE existing input
 *  columns (DuckDB * REPLACE) and those that append (new columns). When `replace` is
 *  explicitly true, all adds use REPLACE unconditionally (the affine relop path). */
const augmentHead = (adds: Readonly<Record<string, string>>, replace: boolean, inputCols?: ReadonlySet<string>): string => {
  if (replace) {
    const addList = Object.entries(adds).map(([c, e]) => `${e} AS "${c}"`).join(", ");
    return `m.* REPLACE (${addList})`;
  }
  if (inputCols === undefined) {
    const addList = Object.entries(adds).map(([c, e]) => `${e} AS "${c}"`).join(", ");
    return `m.*, ${addList}`;
  }
  const replacing: string[] = [];
  const appending: string[] = [];
  for (const [c, e] of Object.entries(adds)) {
    if (inputCols.has(c)) replacing.push(`${e} AS "${c}"`);
    else appending.push(`${e} AS "${c}"`);
  }
  const base = replacing.length > 0 ? `m.* REPLACE (${replacing.join(", ")})` : `m.*`;
  return appending.length > 0 ? `${base}, ${appending.join(", ")}` : base;
};

/** Add `adds` (exprs over mark alias `m`) to every mark. A 1-row `fit`, if given, is
 *  CROSS-JOINed so the SAME `f."…"` values are visible to all marks (e.g. a domain
 *  `{lo,hi}`). Pass `null` when the exprs reference only `m` — a self-contained apply
 *  (e.g. a window function), no join at all. Contrast `augmentKeyed` (per-mark fit).
 *  `cells` = the {ref} holes the add exprs read (bound by emit per iteration); `replace`
 *  = the adds OVERWRITE same-named mark columns (SELECT * REPLACE — declared, never inferred). */
export function augmentBroadcast(key: string, marks: SqlFragment, adds: Readonly<Record<string, string>>, addSchema: Schema, fit?: SqlFragment | null, cells: readonly CellId[] = [], replace = false): SqlFragment {
  const inputs: Record<string, RelationRef> = { marks: { fragment: marks } };
  let from = "FROM @marks AS m";
  if (fit != null) {
    inputs.fit = { fragment: fit };
    from += " CROSS JOIN @fit AS f";
  }
  const inputCols = replace ? undefined : fragColumns(marks);
  return mkFrag(key, `SELECT ${augmentHead(adds, replace, inputCols)} ${from}`, inputs, { passthrough: "marks", add: addSchema }, cells);
}

/** Add `adds` to each mark from its OWN row of a PER-MARK `fit`, matched on `on` pairs
 *  `[markCol, fitCol]` (e.g. `[["dvl_mark","dvl_mark"]]` for force, `[["src","id"]]` for a
 *  cross-mark link). Unlike `augmentBroadcast`, the fit is NOT shared — every mark joins a
 *  distinct fit row, so an N-row fit stays 1:1 instead of cross-multiplying. `kind:
 *  "LEFT JOIN"` keeps marks with no matching fit row. */
const KEYED_OP: Record<string, string> = { eq: "=", lt: "<", le: "<=", gt: ">", ge: ">=", neq: "<>" };

export function augmentKeyed(
  key: string,
  marks: SqlFragment,
  fit: SqlFragment,
  on: ReadonlyArray<readonly [string, string] | readonly [string, string, string]>,
  adds: Readonly<Record<string, string>>,
  addSchema: Schema,
  kind: "JOIN" | "LEFT JOIN" = "JOIN",
  cells: readonly CellId[] = [],
  replace = false,
): SqlFragment {
  // an optional per-pair op (default eq) — a multi-match via's STAGE join (§3b) joins on ranges
  const cond = on.map(([m, f, op]) => `m."${m}" ${KEYED_OP[op ?? "eq"] ?? "="} f."${f}"`).join(" AND ");
  const inputCols = replace ? undefined : fragColumns(marks);
  return mkFrag(key, `SELECT ${augmentHead(adds, replace, inputCols)} FROM @marks AS m ${kind} @fit AS f ON ${cond}`, { marks: { fragment: marks }, fit: { fragment: fit } }, { passthrough: "marks", add: addSchema }, cells);
}

const NO_CELLS = { get: () => undefined };

/** Fold + emit a fragment and run it through the database's backend. `cells` binds the fragment's
 *  {ref} holes at emit time — the fixpoint contract: structure folds once, values re-bind per
 *  iteration (a cell-leaf expression never bakes a literal into the folded SQL). Callers without
 *  holes omit it (NO_CELLS); an unbound hole is a loud emit error, never a silent NULL. */
export async function runRelation(db: Database, top: SqlFragment, cells: CellEnv = NO_CELLS): Promise<readonly RawRow[]> {
  for (const base of baseInputs(top)) {
    await db.ensureRegistered(base); // create the table in the backend (ensureSchema skips this when fromRows pre-cached the schema)
    await db.ensureSchema(base); // schema for fold
  }
  const folded = fold(top, (n) => db.schemaOf(n), db.backend.dialect);
  const { sql, params } = emit(folded, cells, db.backend.dialect);
  return db.backend.run(sql, params.length > 0 ? params : undefined);
}

function baseInputs(f: SqlFragment, acc = new Set<string>()): Set<string> {
  for (const ref of Object.values(f.inputs)) {
    if ("base" in ref) acc.add(ref.base);
    else baseInputs(ref.fragment, acc);
  }
  return acc;
}

/** Fold + emit a fragment to a SQL string (no Database — for fits/V that reference no base
 *  relation, or whose base schema isn't needed for composition). */
export function emitSql(top: SqlFragment, schemaOf: (n: string) => Schema = () => [], dialect = defaultDialect): string {
  return emit(fold(top, schemaOf, dialect), NO_CELLS, dialect).sql;
}

/** JS rows → a SQL relation fragment (the JS→SQL crossing; also serializes a JS `V`). */
export function valuesFrag(key: string, rows: readonly Row[], schema: Schema): SqlFragment {
  if (rows.length === 0) return mkFrag(key, "SELECT NULL WHERE 1 = 0", {}, { columns: schema });
  const cols = schema.map((c) => c.name);
  const tuples = rows.map((r) => `(${cols.map((c) => sqlLiteral(r[c] as Scalar)).join(", ")})`).join(", ");
  return mkFrag(key, `SELECT * FROM (VALUES ${tuples}) AS _v(${cols.map((c) => `"${c}"`).join(", ")})`, {}, { columns: schema });
}

/** A fragment runner: fold + emit + execute a fragment (e.g. `(f) => runRelation(db, f)`).
 *  Routing execution through this — not a raw SQL-string runner — keeps `schemaOf`/dialect
 *  in the data layer, so there is no stub schema in the hot path. */
export type RunFrag = (frag: SqlFragment) => Promise<readonly RawRow[]>;

/** Bring a relation into JS: run a SQL fragment, or return the rows as-is. */
export async function materialize(rel: Relation, run: RunFrag): Promise<JsRel> {
  if (rel.substrate === "js") return { rows: rel.rows, schema: rel.schema };
  const rows = (await run(rel.frag)) as readonly Row[];
  const cols = "columns" in rel.frag.outputs ? rel.frag.outputs.columns : schemaFromRows(rows);
  return { rows, schema: cols };
}

function schemaFromRows(rows: readonly Row[]): Schema {
  return rows.length > 0 ? Object.keys(rows[0]).map((name) => ({ name, type: "unknown" as const })) : [];
}
