// eqx (equi-width): distribute the distinct keys evenly across the range → x + width.
// Same shape as the band scale (rank → step), promoted to a layout.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, rank } from "../../algebra/relop.js";
import { continuous } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const eqX = op({
  name: "eqX",
  // The fit is {n} (a countDistinct) — a 1-row broadcast fit, hence a CONTINUOUS-shaped domain,
  // but a COUNT is not a category table, so there is no defined union (two counts don't union
  // into a shared domain) → union: null, unshareable, unionFn dropped. Not niceable (nice:
  // undefined → treatment "data"). ticks "ordinal" matches lower-legends' old fallback for
  // kindless descriptors; ordered stays true (rank order is positional).
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { n: { fn: "countDistinct", col: inputCol(b, "value") } } }), { union: null, unionFn: undefined, nice: undefined, ticks: "ordinal", interpolable: false }),
  inputs: { marks: [{ name: "key", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), w: relativeSpace(len("x")) },
  inputSpaces: { key: dataSpace },
  apply: (b): RelOp => {
    // NORMALIZED: emit relative t ∈ [0,1] — x = rank/n (left edge), w = 1/n (step). The frame affine
    // places them. eqx is a pure BOX producer: it emits the box, and a consumer that wants a POINT of
    // it (a strip label's centre) derives it — `x + w·½` (explainer §12.3), NOT a producer anchor option.
    const [xo, wo] = b.outputs;
    const invN = bin("/", lit(1), fcol("n")); // 1/n — normalized step
    return { kind: "derive", add: { [xo]: bin("*", rank(inputCol(b, "value")), invN), [wo]: invN }, outTypes: { [xo]: "double", [wo]: "double" } };
  },
});
