// band: categorical → x + width — the bar's x layout (VL's band scale, as a DVL multi-output
// layout). It binds via pick('x','w'), like `eqx`/`col`, because a bar needs TWO positional
// outputs and a single channel binding carries one.
//
// THE FIT IS THE DOMAIN (the invariant that makes the axis work — WUAXIS §apply-only): train
// produces the KEYED category table (value, idx, n) — each distinct value with its dense rank and
// the count — and apply is a keyed JOIN against it: x = idx/n (band left edge), w = 1/n. Because
// that same table IS the materialized domain, the axis's apply-only wrapper (which hands the
// DOMAIN over as the fit) re-runs this apply over the tick table V and it just works — the same
// reason `col` has a labelled axis ({lo,hi} fit = {lo,hi} domain), where the old {n}-aggregate
// band could not (its fit was not its domain).
//
// Ticks: `ordinal` — one tick per category, from the domain's rows. The axis anchors ticks at the
// CENTER of each band (binding.options.anchor === "center", set by the apply-only wrapper): the
// same apply emits x = (idx + 0.5)/n there, so tick placement still goes through the scale — no
// tick math lives outside the component.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, nullif0 } from "../../algebra/relop.js";
import { categorical } from "../scales/types.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const bandX = op({
  name: "bandX",
  // categorical defaults (set-union, ordinal ticks, keyed shape) + ordered: true — band
  // categories have positional meaning.
  domain: categorical((b): RelOp => ({ kind: "unique", col: inputCol(b, "value"), as: "value", indexed: true }), { ordered: true }),
  inputs: { marks: [{ name: "value", type: "unknown" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), w: relativeSpace(len("x")) },
  inputSpaces: { value: dataSpace },
  apply: (b): RelOp => {
    // NORMALIZED: emit relative t ∈ [0,1]; the frame affine places them. Keyed fit: marks join the
    // (value, idx, n) table on the bound column — over data marks AND over the axis's V alike.
    const [xo, wo] = b.outputs;
    // D3/VL band geometry (options are STATIC, baked at plan time; n is the runtime fit column):
    //   step = 1/(n − pi + 2·po),  bandwidth = (1 − pi)·step,  outer offset = 2·po·align
    //   left(i)   = (2·po·align + i) / (n − pi + 2·po)
    //   center(i) = left(i) + bandwidth/2  (the extra (1−pi)/2 in the numerator; ticks use this)
    const opt = (name: string, dflt: number): number => (b.options?.[name] !== undefined ? Number(b.options[name]) : b.options?.padding !== undefined ? Number(b.options.padding) : dflt);
    const pi = opt("paddingInner", 0); // gap between bands (fraction of step)
    const po = opt("paddingOuter", 0); // space before first / after last band
    const align = b.options?.align !== undefined ? Number(b.options.align) : 0.5;
    const center = b.options?.anchor === "center"; // axis ticks sit at band centers
    const denom = nullif0(bin("+", bin("-", fcol("n"), lit(pi)), lit(2 * po))); // n − pi + 2·po
    const off = 2 * po * align + (center ? (1 - pi) / 2 : 0); // compile-time constant numerator offset
    // NO fit field: the keyed join on the bound value column is the framework's decision,
    // derived from domain.shape "keyed" (exec.ts fitMode).
    return {
      kind: "derive",
      add: { [xo]: bin("/", bin("+", lit(off), fcol("idx")), denom), [wo]: bin("/", lit(1 - pi), denom) },
      outTypes: { [xo]: "double", [wo]: "double" },
    };
  },
  ticks: "ordinal",
});
