// emit() — render a folded query to dialect SQL + bound params (WUDATA §3, IMPL §9).
//
// Structure is folded once; emit fills the {cell} holes per fixpoint iteration:
//   sealed   -> constant literal      (no param)
//   param    -> bound parameter       (prepared once, re-bound per iteration)
//   subquery -> scalar subquery       (query-backed cell, kept in-database)

import type { FoldedQuery } from "./fold.js";
import { rewriteSql } from "./fragment.js";
import type { Dialect } from "./dialect.js";
import type { Scalar, SqlType } from "./schema.js";
import type { CellId } from "./ids.js";

export type CellBinding =
  | { readonly kind: "literal"; readonly value: Scalar; readonly type?: SqlType }
  | { readonly kind: "param"; readonly value: Scalar }
  | { readonly kind: "subquery"; readonly sql: string };

export interface CellEnv {
  get(id: CellId): CellBinding | undefined;
}

export interface EmitResult {
  readonly sql: string;
  readonly params: readonly Scalar[];
}

export function emit(q: FoldedQuery, env: CellEnv, d: Dialect): EmitResult {
  const params: Scalar[] = [];
  const paramIndex = new Map<string, number>(); // one placeholder per distinct cell

  const renderCell = (name: string): string => {
    const b = env.get(name);
    if (b === undefined) throw new Error(`unbound cell {${name}} at emit`);
    if (b.kind === "literal") return d.literal(b.value, b.type);
    if (b.kind === "subquery") return `(${b.sql})`;
    let idx = paramIndex.get(name);
    if (idx === undefined) {
      params.push(b.value);
      idx = params.length;
      paramIndex.set(name, idx);
    }
    return d.paramPlaceholder(idx);
  };

  const cteSql = q.ctes
    .map((c) => {
      const cols = c.columns !== undefined ? `(${c.columns.join(", ")})` : "";
      const key = c.usingKey !== undefined ? ` USING KEY (${c.usingKey.join(", ")})` : "";
      return `${c.name}${cols}${key} AS (${rewriteSql(c.body, { cell: renderCell })})`;
    })
    .join(", ");
  const recursive = q.ctes.some((c) => c.recursive === true);
  const head = q.ctes.length > 0 ? `${d.withClause(recursive)} ${cteSql} ` : "";
  return { sql: `${head}SELECT * FROM ${q.result}`, params };
}
