// Structural validation (WUIR_IMPL §2.5, the synchronous checks). FK/schema
// resolvability (#3) is deferred to C0 `autoPath`; the full dimensional checker is C6.
// Routed through `report`: strict throws, non-strict warns (default strict).
import type { Spec } from "../ir/spec.js";
import type { Registries } from "../operator/registry.js";
import type { Scale } from "../ir/layout.js";
import { typeOf } from "../ir/expr.js";
import { fits, showSpace } from "../types/attr.js";

export type Report = (w: { message: string }) => void;
const strict: Report = (w) => {
  throw new Error(w.message);
};

export function validate(spec: Spec, registries: Registries, report: Report = strict): void {
  for (const plot of spec.plots.values()) {
    // Framework-minted plots (axis/legend/strip marks, origin-tagged) are never held to author
    // rules — matters when compileSpec re-runs on an already-lowered spec (it is idempotent).
    if (plot.origin !== undefined) continue;
    if (!registries.marks.has(plot.markType)) {
      report({ message: `unknown mark type: "${plot.markType}"` });
      continue;
    }
    const mark = registries.marks.get(plot.markType);

    // Channels a bound LAYOUT consumes (a refine op's inputs default to same-named channels:
    // fitText reads `text`/`w`/`h` off the mark's bag) — legitimate on any mark, drawn or not.
    // Instance ids are plot-scoped (`${plotId}/fitText`), so membership is a prefix test.
    const layoutInputs = new Set<string>();
    for (const [lid, inst] of spec.layouts) {
      if (!lid.startsWith(`${plot.id}/`)) continue;
      for (const v of Object.values(inst.inputs.marks?.project ?? {})) if (typeof v === "string") layoutInputs.add(v);
    }

    for (const [ch, expr] of Object.entries(plot.channels)) {
      // the Level-2 frame borrow (`pick({ cell: 'dvl_cell' })`) is compiler plumbing, not a
      // channel value — the cell-key stage consumes it (plot.ts), the mark never sees it.
      if (ch === "cell" && expr.kind === "table-ref" && expr.attrName === "dvl_cell") continue;
      // 1a. channel must be declared by the mark descriptor — except a layout's own traffic:
      // a picked layout OUTPUT may land on an undeclared name (fitText's fontSize on a rect),
      // and a layout INPUT channel exists for the layout, not the draw.
      if (!(ch in mark.channels)) {
        if (expr.kind === "layout-output" || layoutInputs.has(ch)) continue;
        report({ message: `mark "${plot.markType}" has no channel "${ch}"` });
        continue;
      }
      // 1b. the data-pixel boundary check — only where the space is KNOWABLE pre-resolve:
      // literals and raw columns. Via borrows (table-ref/bound-ref/agg) settle their space at
      // resolve (a plot borrow arrives pixel; a table borrow is data through whatever consumes
      // it), and binary/call results are data-by-construction, legitimately drawn raw today
      // (§10.1) — checking those here would flag working specs. Full dimensional checker = C6.
      if (expr.kind !== "literal" && expr.kind !== "local-column") continue;
      const actual = typeOf(expr).space;
      const expected = mark.expectedType(ch).space;
      if (!fits(actual, expected)) {
        report({ message: `channel "${ch}" of "${plot.markType}": ${showSpace(actual)} does not fit ${showSpace(expected)} (use a scale?)` });
      }
    }

    // 1c. a style key shadowing a declared channel => warning (use the channel)
    for (const k of Object.keys(plot.params.style ?? {})) {
      if (k in mark.channels) report({ message: `style "${k}" shadows declared channel "${k}"; bind the channel instead` });
    }
  }

  // 5. registry: every layout descriptor name resolves; + structural domain checks.
  // (Data-dependent satisfaction -- domain contains the data, log needs positive data -- is C4.)
  for (const layout of spec.layouts.values()) {
    if (!registries.operators.has(layout.descriptor)) {
      report({ message: `unknown layout descriptor: "${layout.descriptor}"` });
      continue;
    }
    const ds = (layout as Scale).treatment;
    if (ds !== undefined && typeof ds === "object" && "explicit" in ds && !(ds.explicit[0] < ds.explicit[1])) {
      report({ message: `scale "${layout.id}": explicit domain [${ds.explicit[0]}, ${ds.explicit[1]}] must be increasing` });
    }
  }
}

