// arrange op: solve one node's box via the registered solver.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";

export function arrange(op: OpSpec, store: CellStore, ctx: RunCtx): void {
  const p = op.payload as { kind: string; nodeId: string };
  if (p.kind !== "arrange") return;
  const inst = ctx.spec.nodes.get(p.nodeId)?.arrange;
  if (inst === undefined) throw new Error(`run: node "${p.nodeId}" has no ArrangeInstance`);
  // resolve-once: the solver function was bound at CREATION (arrangeNode) — no registry.
  if (inst.resolvedSolver === undefined) throw new Error(`arrange: node "${p.nodeId}" has no resolved solver — the instance predates arrangeNode's SOLVERS binding`);
  inst.resolvedSolver(inst.constraints, store, op.writes);
}
