// The ONE join-pair extractor (CELL_KEY_VIA §3a rule 3): a resolved hop's JoinConditions →
// (left, right, op) column pairs + their qualifying relations. Replaces the split
// predicatePairs/viaPairs — consumers differ in POLICY (the nest key gates to eq; a via admits
// any op), never in the extraction.
import { isFKRef, normalizeStep, type JoinCondition, type JoinOp, type Path, type ResolvedPath } from "../../ir/refs.js";

export interface HopPair {
  left: string; // column on the current (marks/child) side
  right: string; // column on the next (host/referent) side
  op: JoinOp;
  leftRel: string | null; // qualifying relation, when the resolver attr-qualified the operand
  rightRel: string | null;
}

const col = (a: JoinCondition["left"]): string => {
  if (a.kind === "local-column") return a.columnName;
  if (a.kind === "attr") return a.column;
  throw new Error("join path: a predicate operand must be a column");
};

const rel = (a: JoinCondition["left"]): string | null => (a.kind === "attr" ? a.relation.relation : null);

/** A path site's resolved hops, with the pre-resolve fallback: a hand-built spec that never ran
 *  resolveSpec still works when the path is all-explicit (one hop, today's shape) — string
 *  shorthand steps included (normalized here, exactly as resolveSpec would); FK/null forms
 *  return null — the caller errors with its own site message. */
export function resolvedOf(site: { on: Path; resolved?: ResolvedPath } | null | undefined): ResolvedPath | null {
  if (site == null) return null;
  if (site.resolved !== undefined) return site.resolved;
  if (site.on !== null && site.on.every((s) => !isFKRef(s))) return [site.on.map(normalizeStep) as JoinCondition[]];
  return null;
}

/** Extract one hop's join pairs. `eqOnly` is the nest key's gatekeeper — dvl_cell is a
 *  partition key, so a nest hop must be all-eq; every other consumer admits any op. */
export function pairs(hop: readonly JoinCondition[], opts?: { eqOnly?: string }): HopPair[] {
  // a CROSS condition (on("*")) carries no key columns — it drops out, leaving the hop with
  // zero pairs (the emitter reads that as `ON TRUE`). eqOnly consumers (the nest key) never see
  // one: a partition key cannot be a cross product.
  return hop
    .filter((pr) => pr.cross !== true)
    .map((pr) => {
      if (opts?.eqOnly !== undefined && pr.op !== "eq") {
        throw new Error(`${opts.eqOnly}: only eq predicates are supported here (got ${pr.op})`);
      }
      return { left: col(pr.left), right: col(pr.right), op: pr.op, leftRel: rel(pr.left), rightRel: rel(pr.right) };
    });
}
