// Lift relational leaves (layout-output / bound-ref / table-ref / agg) out of binary channel
// expressions into their own BARE channels (VIA_HARDENING §3.3 B1), and normalize a bare agg channel
// to its referent via with a declared reduction (§3.3 Phase C).
//
// THE LIFTING RULE (explainer §12.3): a channel expr is lowered to a per-row SCALAR computation by
// toScalar, which inlines only leaves already materialized in the current relation — literal, var (a
// solver cell), local-column (an upstream step's column). Every OTHER leaf's value is produced by a
// RELATIONAL operator that must run first — apply a scale/layout (layout-output), reduce (agg), or
// join/borrow (via: bound-ref/table-ref) — so it cannot appear mid-scalar-expression and is LIFTED
// into its own bare channel (its own producer step); the arithmetic then reads the minted column as a
// local-column. The rule keys on the leaf's KIND (relational vs in-scope), uniformly for every
// operator; a BARE relational channel is already its own step, so only a NESTED one lifts.
//
// Runs BEFORE resolveSpec (a spec normalization, like lowerAxes): the minted channels are bare, so
// resolvePaths stamps them and assertResolvedPaths passes. Naturally idempotent — a rewritten binary
// contains no relational leaves, and a minted channel is bare (never nested).
//
// ORDER MATTERS: the minted channel is inserted BEFORE its consumer, so the producer step emits
// before the expr step that reads the minted column (steps consume the pipeline sequentially).
import type { Expr } from "../../ir/expr.js";
import type { Spec } from "../../ir/spec.js";
import type { TableRefExpr, BoundRefExpr, ViaResolve } from "../../ir/refs.js";
import type { LayoutOutputExpr } from "../../ir/expr.js";

const isRelationalLeaf = (e: Expr): e is TableRefExpr | BoundRefExpr | LayoutOutputExpr | (Expr & { kind: "agg" }) =>
  e.kind === "bound-ref" || e.kind === "table-ref" || e.kind === "agg" || e.kind === "layout-output";

/** agg(op, ref) ≡ the ref borrowed under a declared reduction (§3.3 Phase C — an aggregate is
 *  only ever the 1→N via's reduction; there is no per-row aggregate). */
const aggToVia = (e: Expr & { kind: "agg" }): TableRefExpr => ({ ...e.ref, type: e.type, resolve: { fn: e.op } as ViaResolve });

export function liftViaExprs(spec: Spec): void {
  for (const plot of spec.plots.values()) {
    let n = 0;
    const out: Record<string, Expr> = {};
    let changed = false;
    const lift = (e: Expr): Expr => {
      if (e.kind === "binary") {
        const left = lift(e.left);
        const right = lift(e.right);
        return left === e.left && right === e.right ? e : { ...e, left, right };
      }
      if (e.kind === "call") {
        const args = e.args.map(lift);
        return args.every((a, i) => a === e.args[i]) ? e : { ...e, args };
      }
      if (!isRelationalLeaf(e)) return e;
      changed = true;
      const name = `dvl_lift_${n++}`;
      out[name] = e.kind === "agg" ? aggToVia(e) : e;
      // the minted column carries the LEAF's space (a plot borrow arrives placed — pixel — per
      // the .out() typing; a table borrow is data): the consuming binary's type is unchanged.
      return { kind: "local-column", type: e.type, columnName: name };
    };
    for (const [ch, expr] of Object.entries(plot.channels)) {
      if (expr.kind === "binary" || expr.kind === "call") out[ch] = lift(expr);
      else if (expr.kind === "agg") { out[ch] = aggToVia(expr); changed = true; }
      else out[ch] = expr;
    }
    if (changed) plot.channels = out;
  }
}
