// InsertCrossings: at substrate boundaries, insert materialize/inject ops.
import type { CellRef } from "../../ir/cell.js";
import type { OptRule, RuleCtx, RuleMatch } from "../rule.js";
import type { OpSpec } from "../../plan/opspec.js";

export const insertCrossings: OptRule = {
  name: "insert-crossings",

  match(op: OpSpec, ctx: RuleCtx): RuleMatch | null {
    const cap = ctx.opCapability(op);
    if (cap.canConsume.length === 0) return null; // scalar-only op, no relation inputs

    const mismatched: CellRef[] = [];
    for (const r of op.reads) {
      const fmt = ctx.cellFormat(r);
      if (fmt && !cap.canConsume.includes(fmt.substrate)) {
        mismatched.push(r);
      }
    }
    return mismatched.length > 0 ? { anchor: op, bindings: { mismatched } } : null;
  },

  apply(m: RuleMatch, ctx: RuleCtx): void {
    const op = m.anchor;
    const mismatched = m.bindings!.mismatched as CellRef[];

    const newOps: OpSpec[] = [];
    let rewiredReads = [...op.reads];

    for (const oldCell of mismatched) {
      const fmt = ctx.cellFormat(oldCell)!;
      const newCell = ctx.allocCell("marks", "relation");

      if (fmt.substrate === "sql") {
        // Need JS but have SQL → materialize
        ctx.setCellFormat(newCell, { substrate: "js" });
        newOps.push({
          id: `${op.id}:mat:${oldCell}`,
          reads: [oldCell],
          writes: [newCell],
          payload: { kind: "materialize", key: `${op.id}:mat` },
        });
      } else {
        // Need SQL but have JS → inject
        ctx.setCellFormat(newCell, { substrate: "sql" });
        newOps.push({
          id: `${op.id}:inj:${oldCell}`,
          reads: [oldCell],
          writes: [newCell],
          payload: { kind: "inject", key: `${op.id}:inj` },
        });
      }

      rewiredReads = rewiredReads.map(r => r === oldCell ? newCell : r);
    }

    const rewired: OpSpec = { ...op, reads: rewiredReads };
    ctx.graph.splice(op, 1, ...newOps, rewired);
  },
};
