// BboxPen — a Pen that captures the bounding box of everything drawn.
// Shapes are exact geometry. Text uses a heuristic (the no-DOM fallback).
// When a DOM is available, the plot-measure op uses offscreen SVG + getBBox instead.
import type { Pen, Point, Style } from "../ir/pen.js";

export class BboxPen implements Pen {
  #minX = Infinity;
  #maxX = -Infinity;
  #minY = Infinity;
  #maxY = -Infinity;

  circle(cx: number, cy: number, r: number, _s: Style): void {
    this.#extend(cx - r, cy - r, cx + r, cy + r);
  }
  ellipse(cx: number, cy: number, rx: number, ry: number, _s: Style): void {
    this.#extend(cx - rx, cy - ry, cx + rx, cy + ry);
  }
  rect(x: number, y: number, w: number, h: number, _s: Style): void {
    this.#extend(x, y, x + w, y + h);
  }
  line(x1: number, y1: number, x2: number, y2: number, _s: Style): void {
    this.#extend(Math.min(x1, x2), Math.min(y1, y2), Math.max(x1, x2), Math.max(y1, y2));
  }
  polyline(points: readonly Point[], _s: Style): void {
    for (const [x, y] of points) this.#extend(x, y, x, y);
  }
  polygon(points: readonly Point[], _s: Style): void {
    for (const [x, y] of points) this.#extend(x, y, x, y);
  }
  path(_d: string, _s: Style): void {
    // ponytail: path bbox requires parsing bezier curves — deferred
  }
  text(s: string, x: number, y: number, style: Style): void {
    const fontSize = style.fontSize ?? 10;
    const w = 0.6 * fontSize * s.length;
    const h = fontSize;
    const anchor = style.textAnchor ?? "start";
    const x0 = anchor === "middle" ? x - w / 2 : anchor === "end" ? x - w : x;
    this.#extend(x0, y - h, x0 + w, y);
  }
  textMultiline(lines: string[], x: number, y: number, style: Style): void {
    const fontSize = style.fontSize ?? 10;
    const lineH = fontSize * 1.2;
    const maxW = Math.max(...lines.map(l => 0.6 * fontSize * l.length));
    const anchor = style.textAnchor ?? "start";
    const x0 = anchor === "middle" ? x - maxW / 2 : anchor === "end" ? x - maxW : x;
    this.#extend(x0, y - fontSize, x0 + maxW, y - fontSize + lines.length * lineH);
  }
  image(x: number, y: number, w: number, h: number, _href: string, _s: Style): void {
    this.#extend(x, y, x + w, y + h);
  }

  bbox(): { x: number; y: number; w: number; h: number } | null {
    if (this.#minX === Infinity) return null;
    return { x: this.#minX, y: this.#minY, w: this.#maxX - this.#minX, h: this.#maxY - this.#minY };
  }

  #extend(x0: number, y0: number, x1: number, y1: number): void {
    if (x0 < this.#minX) this.#minX = x0;
    if (x1 > this.#maxX) this.#maxX = x1;
    if (y0 < this.#minY) this.#minY = y0;
    if (y1 > this.#maxY) this.#maxY = y1;
  }
}
