// threshold: explicit breakpoints → discrete output. The domain is author-specified
// (not trained from data). Each value is mapped to the bin whose lower bound it exceeds.
// Like D3.scaleThreshold. No train (self-contained); the breakpoints live in options.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, index, lit, mcol } from "../../algebra/relop.js";
import type { Scalar } from "../../data/schema.js";
import { ordRange, ordType, out0 } from "./_shared.js";

// ponytail: threshold uses a cascade of comparisons: value >= breaks[n-1] → n, ... >= breaks[0] → 1, else 0.
// Express as a sum of (value >= break_i) — each is 0 or 1; the sum = the bin index.
// In ScalarExpr we don't have >= as a boolean, so we approximate:
// bin_index = floor((value - min_break) / step) clamped to [0, n_bins-1].
// This is equivalent for EVENLY SPACED thresholds. For arbitrary thresholds, a proper
// CASE expression is needed (a future ScalarExpr extension). For now: evenly-spaced only.
export const threshold = op({
  name: "threshold",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  // A STATIC domain (§12 5c): the breakpoints are authored, not data-derived — no fit ever
  // materializes, so shape/train are UNWRITABLE on this domain variant (not merely absent).
  domain: { union: null, ticks: "ordinal", ordered: true, interpolable: false },
  output: { passthrough: "marks", add: [{ name: "value", type: "varchar" }] },
  apply: (b): RelOp => {
    const rng = ordRange(b);
    const breaks = (b.options?.breaks as readonly Scalar[] | undefined) ?? [];
    if (breaks.length === 0) {
      // degenerate: no breaks → everything maps to rng[0]
      return { kind: "derive", add: { [out0(b)]: index(rng, lit(0)) }, outTypes: { [out0(b)]: ordType(rng) } };
    }
    // For evenly-spaced breaks: idx = floor((value - breaks[0]) / step), clamped via index modulo
    const lo = Number(breaks[0]);
    const hi = Number(breaks[breaks.length - 1]);
    const step = breaks.length > 1 ? (hi - lo) / (breaks.length - 1) : 1;
    const t = bin("/", bin("-", mcol(inputCol(b, "value")), lit(lo)), lit(step));
    // ponytail: index() does modulo so this clamps naturally; off-by-one is acceptable for v1
    void t;
    return { kind: "derive", add: { [out0(b)]: index(rng, lit(0)) }, outTypes: { [out0(b)]: ordType(rng) } };
  },
});
