// Shared context types + small helpers of the node compiler (ex dataflow/graph.ts).
// PlotBuild/TemplateCtx/NodeBuild are the per-plot / per-node build products compileNode
// threads through compilePlot; opOf/stampAlgo resolve + label a component's emitted subgraph.
import type { Scalar, SqlType } from "../../data/schema.js";
import type { Expr } from "../../ir/expr.js";
import type { LayoutInstance } from "../../ir/layout.js";
import type { ResolvedPath } from "../../ir/refs.js";
import type { Operator } from "../../operator/operator.js";
import type { CellRef } from "../../ir/cell.js";
import type { OpSpec } from "../opspec.js";
import type { AnyOperatorPayload } from "../payloads.js";
import type { LayoutId, NodeId, PlotId } from "../../types/ids.js";
import type { DebugSink } from "../../debug/sink.js";

export interface RenderOpts {
  margin?: { left: number; right: number; top: number; bottom: number };
  inset?: { left: number; right: number; top: number; bottom: number }; // inner data inset (px) — pulls marks off the frame edge (frame-level literal; mark-extent slack is per-scale expansion)
  background?: string;
  tickCount?: number; // default axis tick count (lowerAxes)
  strict?: boolean; // unplaceable axis → error instead of warn+skip (lowerAxes)
  debug?: DebugSink; // profiling/debug sink (explainer §2) — absent ⇒ NULL_SINK, zero overhead
  strictMultiplicity?: boolean; // §4.3: UNKNOWN-multiplicity via without a resolution → build error (resolveSpec)
}

/** One compiled plot: the END of its pipeline (`marks` — the render sink's read) and the cell holding
 *  its RELATIVE placements (`relMarks`, pre-affine) — there is no "final placed marks" notion, only
 *  sealed cells; relative placements are what the down pass reads to derive child extents. */
export interface PlotBuild {
  pid: PlotId;
  marks: CellRef; // pipeline end (pixel space) — the render sink materializes this
  relMarks: CellRef; // pre-affine (relative placements) — host-extent reads this; = marks when no affine ran
  base: CellRef; // the resolved BASE relation (marktable/producer output) — a cell-key joins the host's
  keyed?: CellRef; // post-cell-key marks (dvl_cell assigned) — what a sibling's cell BORROW reads (CELL_KEY_VIA Level 2)
  boxed?: CellRef; // C6 box columns forked off the placed marks (dvl_x0/x1/y0/y1) — the overhang op's read (scale-expansion §4); absent unless a live expansion enrolled the plot
}

/** A TEMPLATE node's nesting context, passed by compileSpec when visiting a data-driven
 *  child: the HOST plot's cells (base for the cell-key join; placed marks = the box relation the
 *  keyed affine reads) + the nest's RESOLVED join path (one entry per hop — multi-hop keys emit
 *  one join relop per hop, CELL_KEY_VIA Level 1). */
export interface TemplateCtx {
  hostBase: CellRef;
  hostMarks: CellRef;
  resolved: ResolvedPath;
}

/** `compileNode`'s output: the node's op descriptions + each plot's cells. */
export interface NodeBuild {
  nodeId: NodeId;
  specs: OpSpec[];
  plots: PlotBuild[];
}

export const num = (v: unknown): number => (typeof v === "number" ? v : 0);

// The compiler reads the RESOLVED Operator off the spec — never a registry. An unresolved
// instance is a pipeline bug: resolveSpec must run after the lowerings.
export function opOf(inst: LayoutInstance): Operator {
  if (inst.resolved === undefined) throw new Error(`compile: instance "${inst.id}" is unresolved — call resolveSpec(spec, registries) after the lowerings`);
  return inst.resolved.operator;
}

/** Stamp the INSTANCE-resolved algo onto the plan's apply/domain payloads that don't already
 *  carry one — the executor reads payload.algo, never a registry. Stamped here (not closed over
 *  inside the component's plan) so a re-registered wrapper of an existing operator (a renamed /
 *  dekeyed external) carries the object the instance actually resolved to, whatever name its
 *  inherited plan closure baked into algoName. The rule for plans that reference ANOTHER
 *  operator: embed it yourself (apply-only embeds its wrapped algo), and stamping skips you. */
export function stampAlgo(algo: Operator, specs: OpSpec[]): OpSpec[] {
  return specs.map((sp) => {
    const pl = sp.payload as unknown as AnyOperatorPayload;
    const stampable = (pl.kind === "apply" || pl.kind === "domain") && pl.algo === undefined;
    return stampable ? { ...sp, payload: { ...sp.payload, algo } } : sp;
  });
}

/** A container mark's box channels: present-or-not, and RELATIVE (a layout output — lerps the parent
 *  content) vs PIXEL (an authored literal — passes through). Derived from the channel spaces. */
export function boxModes(channels: Record<string, Expr>): { x?: "relative" | "pixel"; y?: "relative" | "pixel"; w?: "relative" | "pixel"; h?: "relative" | "pixel" } {
  const mode = (ch: string): "relative" | "pixel" | undefined => {
    const sp = channels[ch]?.type.space;
    if (sp === undefined) return undefined;
    if (sp.space === "relative") return "relative";
    if (sp.space === "pixel") return "pixel";
    return undefined;
  };
  return { x: mode("x"), y: mode("y"), w: mode("w"), h: mode("h") };
}
export const litType = (v: Scalar): SqlType => (typeof v === "number" ? "double" : typeof v === "boolean" ? "bool" : typeof v === "string" ? "varchar" : "unknown");
