// treemap: squarified 2D space partitioning, DUAL-substrate (same pattern as force):
// js runs d3-hierarchy; sql runs the squarify state machine as ONE recursive DuckDB query
// (treemap-sql.ts — the greedy scan is a plain WITH RECURSIVE, no USING KEY needed). Plan
// emits "apply" either way; both produce x, y, w, h normalized to [0,1] (the affine places
// them). Squarify is deterministic, so the substrates agree up to float error and the
// tie-ordering of equal weights (d3 preserves input order; SQL breaks ties by row ordinal —
// the same order).
import { hierarchy, treemap as d3Treemap } from "d3-hierarchy";
import { inputCol, type OpBinding } from "../../algebra/impl.js";
import { type PlanIO } from "../../operator/binding.js";
import { jsImpl, sqlImpl, type ExecCtx } from "../../algebra/impl.js";
import { treemapSql } from "./treemap-sql.js";
import { op } from "../../operator/operator.js";
import type { JsRel } from "../../algebra/relation.js";
import type { OpSpec } from "../../plan/opspec.js";
import { coord, len, relativeSpace } from "../../types/attr.js";

export const treemap = op({
  name: "treemap",
  // No domain: no train — space partitioning (same class as force). The squarified boxes
  // tile [0,1]² by relative value; positions carry no data-space meaning, nothing tickable.
  inputs: { marks: [{ name: "value", type: "double" }] },
  output: { passthrough: "marks", add: [
    { name: "x", type: "double" }, { name: "y", type: "double" },
    { name: "w", type: "double" }, { name: "h", type: "double" },
  ]},
  outSpaces: {
    x: relativeSpace(coord("x")),
    y: relativeSpace(coord("y")),
    w: relativeSpace(len("x")),
    h: relativeSpace(len("y")),
  },
  // In a template, treemap tiles PER CELL by default: each panel is its own unit square.
  perCell: true,
  plan: (io: PlanIO): OpSpec[] => {
    if (io.marksIn === undefined) throw new Error("treemap: applies over input marks (PlanIO.marksIn)");
    return [{ id: `${io.id}:apply`, reads: [io.marksIn], writes: [io.marksOut], payload: { kind: "apply", algoName: "treemap", binding: io.binding, ...(io.key !== undefined && { by: io.key }) } }];
  },
  exec: { sql: sqlImpl(treemapSql), js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, _ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    const valCol = inputCol(b, "value");
    const [xo, yo, wo, ho] = b.outputs;

    // Build a flat hierarchy: one root with N leaves (one per mark row).
    const data = marks.rows.map((r, i) => ({ i, v: Math.max(0, Number((r as Record<string, unknown>)[valCol] ?? 0)) }));
    const root = hierarchy({ children: data } as any).sum((d: any) => d.v ?? 0);

    // Run squarified treemap, normalized to [0,1]×[0,1].
    d3Treemap<any>().size([1, 1]).padding(0).round(false)(root);

    // Map leaves back to mark rows (preserving input order via index).
    const leaves = root.leaves();
    const byIndex = new Map<number, any>();
    for (const leaf of leaves) byIndex.set(leaf.data.i, leaf);

    const rows = marks.rows.map((r, i) => {
      const leaf = byIndex.get(i);
      return {
        ...r,
        [xo]: leaf ? leaf.x0 : 0,
        // d3 tiles in SCREEN space (y0 = top, y grows DOWN); the frame affine is y-UP (like `col`),
        // so emit the top edge as `1 − y0` — otherwise the flip drives tiles off the bottom of the
        // frame. The box then spans relative [y − h, y] (mirrored in treemap-sql + the parity test).
        [yo]: leaf ? (1 - leaf.y0) : 0,
        [wo]: leaf ? (leaf.x1 - leaf.x0) : 0,
        [ho]: leaf ? (leaf.y1 - leaf.y0) : 0,
      };
    });

    return {
      rows,
      schema: [...marks.schema,
        { name: xo, type: "double" as const },
        { name: yo, type: "double" as const },
        { name: wo, type: "double" as const },
        { name: ho, type: "double" as const },
      ],
    };
  }) },
});
