// SubstrateChooser: propagate substrate format through the graph.
// Strategy: keep with previous operator's representation. Bias SQL for sources.
import type { CellRef } from "../../ir/cell.js";
import type { OptRule, RuleCtx, RuleMatch } from "../rule.js";
import type { OpSpec } from "../../plan/opspec.js";

function cellIsRelation(ref: CellRef, ctx: RuleCtx): boolean {
  // A cell is a relation if it's written by an op that can produce relations,
  // or if it's read by an op in a relation slot. We use a heuristic: if the
  // producer's canProduce is non-empty, it's a relation cell.
  const prod = ctx.graph.producer(ref);
  if (prod) {
    const cap = ctx.opCapability(prod);
    return cap.canProduce.length > 0;
  }
  // No producer (external/seeded cell) — check if any consumer treats it as relation
  const cons = ctx.graph.consumers(ref);
  for (const c of cons) {
    const cap = ctx.opCapability(c);
    if (cap.canConsume.length > 0) return true;
  }
  return false;
}

export const substrateChooser: OptRule = {
  name: "substrate-chooser",

  match(op: OpSpec, ctx: RuleCtx): RuleMatch | null {
    const hasUnassigned = op.writes.some(w => ctx.cellFormat(w) === undefined && cellIsRelation(w, ctx));
    return hasUnassigned ? { anchor: op } : null;
  },

  apply(m: RuleMatch, ctx: RuleCtx): void {
    const op = m.anchor;
    const cap = ctx.opCapability(op);

    // No relation outputs (scalar-only ops like arrange, allocate)
    if (cap.canProduce.length === 0) return;

    // 1. Fixed output wins unconditionally
    if (cap.fixedOutput) {
      for (const w of op.writes) if (cellIsRelation(w, ctx)) ctx.setCellFormat(w, { substrate: cap.fixedOutput });
      return;
    }

    // 2. Keep with input: propagate predecessor's substrate
    let inputSub: "sql" | "js" | undefined;
    for (const r of op.reads) {
      const fmt = ctx.cellFormat(r);
      if (fmt) { inputSub = fmt.substrate; break; }
    }

    let outputSub: "sql" | "js";
    if (inputSub && cap.canProduce.includes(inputSub)) {
      outputSub = inputSub;
    } else {
      // 3. Source or input unknown: bias SQL
      outputSub = cap.canProduce.includes("sql") ? "sql" : "js";
    }

    for (const w of op.writes) {
      if (cellIsRelation(w, ctx)) ctx.setCellFormat(w, { substrate: outputSub });
    }
  },
};
