// relop op: a serializable relational-algebra node executed by the SHARED lowering (lower.ts).
// Absorbs the trivial-derive kinds (literal, local-column, multi-augment) AND the trivial source
// leaves (values, unit) — the optimizer used to have one hand-rolled SQL body per kind plus a
// fusion rule; now every "add column(s) from an expression over the marks" transform, and every
// constant-leaf source, is ONE payload. New framework derives/sources are relop DATA, not new
// kinds. (Non-source path dispatches to lowerApply{Sql,Js}, the same code path apply uses.)
// A `join` payload attaches a SECOND input (op.reads[1]) keyed — the via/cell-key shape; an
// empty `on` is the declared cross join (broadcast).
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { RelopPayload, RelopSource } from "../../../plan/payloads.js";
import type { Scalar } from "../../../data/schema.js";
import { cellsOf, type ApplyOp, type FitMode } from "../../../algebra/relop.js";
import type { OpBinding } from "../../../algebra/impl.js";
import { fragColumns, jsRel, mkFrag, sqlRel, type Relation } from "../../../algebra/relation.js";
import { warnOnce } from "../../../config.js";
import { lowerApplyJs, lowerApplySql } from "../../../algebra/lower.js";
/** The constant-leaf branch: `values` (a non-empty VALUES table) and `unit` (one `dvl_mark=0` row,
 *  gated to zero rows when its indicator reads 0). Emits byte-identical SQL to the former
 *  valuesOp/unitOp so the leaf fragments stay parity-stable. An empty `rows` IS the unit leaf. */
function emitSource(op: OpSpec, store: CellStore, key: string, src: RelopSource): void {
  // table: a base-relation leaf — the multi-hop nest key's intermediate hop reads the raw
  // table (fold resolves its schema from the database, exactly like a marktable's source).
  if (src.table !== undefined) {
    store.write(op.writes[0], sqlRel(mkFrag(key, `SELECT * FROM @src`, { src: { base: src.table } }, { columns: [] })), "assigned");
    return;
  }
  const rows = src.rows;
  if (rows.length === 0) {
    // unit: one 0-mark row, gated off (zero rows) when the indicator cell reads 0.
    const off = src.gate !== undefined && Number(store.read(src.gate)) === 0;
    store.write(op.writes[0], sqlRel(mkFrag(off ? `${key}:off` : key, `SELECT 0 AS dvl_mark${off ? " WHERE FALSE" : ""}`, {}, { columns: [{ name: "dvl_mark", type: "int" }] })), "assigned");
    return;
  }
  // values: a constant table literal, columns typed by the first row's JS types.
  const cols = Object.keys(rows[0]);
  const lit = (v: unknown): string => (typeof v === "number" ? String(v) : `'${String(v).replace(/'/g, "''")}'`);
  const body = `SELECT * FROM (VALUES ${rows.map((r) => `(${cols.map((c) => lit(r[c])).join(", ")})`).join(", ")}) AS _v(${cols.map((c) => `"${c}"`).join(", ")})`;
  store.write(op.writes[0], sqlRel(mkFrag(key, body, {}, { columns: cols.map((c) => ({ name: c, type: typeof rows[0][c] === "number" ? ("double" as const) : ("varchar" as const) })) })), "assigned");
}

/** Snapshot the store values of every cell the add exprs read — the JS evaluator's `cells` arg
 *  (the SQL path never needs this: exprSql emits {ref} holes that emit() binds per iteration). */
function cellValues(p: RelopPayload, store: CellStore): Readonly<Record<string, Scalar>> | undefined {
  const refs = [...new Set(Object.values(p.add).flatMap(cellsOf))];
  if (refs.length === 0) return undefined;
  const out: Record<string, Scalar> = {};
  for (const ref of refs) out[ref] = store.read(ref) as Scalar;
  return out;
}

export function relopOp(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload as unknown as RelopPayload;
  if (p.source !== undefined) return emitSource(op, store, p.key, p.source);
  const rel = store.read(op.reads[0]) as Relation;
  // the shared lowering wants a binding only for its error text / keyed path (unused here).
  const b = { key: p.key, inputs: {}, outputs: Object.keys(p.add) } as unknown as OpBinding;
  // JOIN-DERIVE (via / cell-key): attach the SECOND input (op.reads[1]) on the declared
  // equalities; an empty `on` is the declared cross join (a producer's V broadcast across host
  // cells — genuinely N×M, so it has no JS "broadcast one row" analogue: SQL substrate only,
  // the same constraint the hand-rolled via/cell-key handlers enforced).
  if (p.join !== undefined) {
    const second = store.read(op.reads[1]) as Relation;
    if (rel.substrate !== "sql" || second.substrate !== "sql") {
      throw new Error(`relop "${p.key}": join-derive needs SQL inputs (marks=${rel.substrate}, ${p.join.input}=${second.substrate}) — the planner must keep this edge in the database`);
    }
    // UNDECLARED shadowing: a join-derive whose added name collides with an existing mark
    // column, without `replace: true`. The joined side's value wins (augmentHead lowers the
    // colliding add as SELECT * REPLACE — for a via borrow that IS the point), but say so ONCE
    // per site — the shadowing may be unintended. A DECLARED replace (the affine) is silent.
    if (p.replace !== true) {
      const existing = fragColumns(rel.frag);
      const shadowed = Object.keys(p.add).filter((c) => existing.has(c));
      if (shadowed.length > 0) {
        warnOnce(p.key, `join-derive borrow shadows mark column(s) ${shadowed.map((c) => `"${c}"`).join(", ")} — the joined (f) side's value wins; rename the output to keep both, or declare replace`);
      }
    }
    const fit: FitMode = p.join.on.length === 0 ? "broadcast" : { keyed: p.join.on, kind: p.join.kind };
    const applyOp: ApplyOp = { kind: "augment", add: p.add, fit, outTypes: p.outTypes, replace: p.replace };
    store.write(op.writes[0], sqlRel(lowerApplySql(applyOp, rel.frag, second.frag, b, p.key)), "assigned");
    return;
  }
  // broadcast-only augment (no fit) — the shared lowering's `fit: "none"` path.
  const applyOp: ApplyOp = { kind: "augment", add: p.add, fit: "none", outTypes: p.outTypes, replace: p.replace };
  if (rel.substrate === "js") {
    const out = lowerApplyJs(applyOp, { rows: rel.rows, schema: rel.schema }, null, b, cellValues(p, store));
    store.write(op.writes[0], jsRel(out.rows, out.schema), "assigned");
  } else {
    store.write(op.writes[0], sqlRel(lowerApplySql(applyOp, rel.frag, null, b, p.key)), "assigned");
  }
}
