// path-agg: N placed rows → path row(s) for aggregate marks (line/area).
// There is ONE reduce (P4f): this op is the shared reduce wearing a render-side name — the same
// lowerTrainSql that fits a scale domain, here with stringAgg (ordered point concatenation) and
// anyValue (grouped passthrough) aggregations, grouped by the series columns. No hand-rolled SQL:
// the pipeline is derive (per-row point strings) → reduce → derive (assemble `d`, number marks).
// ponytail: lives here for now; will move to MarkDescriptor.aggregate when the
// mark-aggregate kind ships (step 8 of the run.ts refactor).
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import type { SqlFragment } from "../../../data/fragment.js";
import type { SqlType } from "../../../data/schema.js";
import type { OpBinding } from "../../../algebra/impl.js";
import { concat, lit, mcol, round, rownum, type Agg, type ApplyOp, type ScalarExpr } from "../../../algebra/relop.js";
import { lowerApplySql, lowerTrainSql } from "../../../algebra/lower.js";
import { sqlRel, type Relation } from "../../../algebra/relation.js";
const sqlFrag = (rel: Relation): SqlFragment => {
  if (rel.substrate !== "sql") throw new Error("path-agg: marks left the SQL substrate");
  return rel.frag;
};

const derive = (add: Record<string, ScalarExpr>, outTypes: Record<string, SqlType>): ApplyOp => ({ kind: "augment", add, fit: "none", outTypes });

export function pathAgg(op: OpSpec, store: CellStore, _ctx: RunCtx): void {
  const p = op.payload as { kind: string; key: string; shape: string; carry: readonly string[]; group: readonly string[]; order?: string };
  if (p.kind !== "path-agg") return;
  const marks = sqlFrag(store.read(op.reads[0]) as Relation);
  const b = { key: p.key, inputs: {}, outputs: [] } as unknown as OpBinding;
  const area = p.shape === "area";

  // 1 · the reduce — one row per series (GROUP BY the group columns; none = one row for the plot).
  // The point string is the aggregate's ARGUMENT (an expression, no staging column): "x,y" at
  // fixed precision, ordered by the SEQUENCE column (the bound `order` channel, else x —
  // SEQUENCE_MARKS §3.1) — and the y2 return leg walked backwards for area.
  const ord = p.order ?? "x";
  const pt = (yc: string): ScalarExpr => concat(round(mcol("x"), 2), lit(","), round(mcol(yc), 2));
  const aggs: Record<string, Agg> = {
    dvl_fwd: { fn: "stringAgg", arg: pt("y"), order: ord, sep: " L " },
    ...(area ? { dvl_rev: { fn: "stringAgg" as const, arg: pt("y2"), order: ord, desc: true, sep: " L " } } : {}),
    ...Object.fromEntries(p.carry.map((c) => [c, { fn: "anyValue" as const, col: c }])),
    dvl_plot: { fn: "anyValue", col: "dvl_plot" },
  };
  const reduced = lowerTrainSql({ kind: "aggregate", aggs }, marks, b, p.group, `${p.key}:agg`);

  // 2 · assemble the SVG path + number the path marks. (The dvl_fwd/dvl_rev staging columns ride
  // along in the output relation — render reads by channel name, so they are inert.)
  const d = area
    ? concat(lit("M "), mcol("dvl_fwd"), lit(" L "), mcol("dvl_rev"), lit(" Z"))
    : concat(lit("M "), mcol("dvl_fwd"));
  const out = lowerApplySql(derive({ d, dvl_mark: rownum() }, { d: "varchar", dvl_mark: "int" }), reduced, null, b, p.key);
  store.write(op.writes[0], sqlRel(out), "assigned");
}
