// force (force-directed): a SELF-CONTAINED iterative algorithm, DUAL-substrate.
// js: wraps d3-force synchronously (stop the simulation, tick N times) — the
// wrap-an-existing-algorithm pattern; seeded (d3's randomSource) so runs are deterministic.
// sql: ONE recursive DuckDB query (force-sql.ts — WITH RECURSIVE … USING KEY) running the
// attraction/repulsion/gravity iteration in-database; the dataflow sees ONE ordinary apply op
// either way, no iteration machinery. Both adapt relations in (marks + an aux `edges` relation
// riding the binding) and NORMALIZED relative positions out (min-max → [pad, 1−pad]; the frame
// affine places them). The two substrates are DIFFERENT simulations — same contract (normalized
// positions, deterministic per substrate), different exact coordinates; the substrate choice is
// the optimizer's (chooseImpl: SQL marks stay in SQL).
import { forceCenter, forceLink, forceManyBody, forceSimulation } from "d3-force";
import { inputCol, type OpBinding } from "../../algebra/impl.js";
import { type PlanIO } from "../../operator/binding.js";
import { jsImpl, sqlImpl, type ExecCtx } from "../../algebra/impl.js";
import { forceSql } from "./force-sql.js";
import { op } from "../../operator/operator.js";
import { mkFrag, type JsRel } from "../../algebra/relation.js";
import type { OpSpec } from "../../plan/opspec.js";
import { coord, dataSpace, relativeSpace } from "../../types/attr.js";

/** mulberry32 — a tiny seeded PRNG for d3's randomSource (deterministic layouts/tests). */
const mulberry32 = (seed: number) => (): number => {
  seed = (seed + 0x6d2b79f5) | 0;
  let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
  t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};

interface FNode {
  id: string;
  x?: number;
  y?: number;
}

export const force = op({
  name: "force",
  // No domain: no train — self-contained placement. x/y come from a physics simulation
  // min-max normalized to [pad, 1−pad]; the positions carry no data-space meaning, so there
  // is no domain to share/union and nothing an axis or legend could tick.
  inputs: { marks: [{ name: "id", type: "int" }], edges: [{ name: "src", type: "int" }, { name: "dst", type: "int" }] },
  refs: [{ from: "edges.src", to: "marks.id" }, { from: "edges.dst", to: "marks.id" }],
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "y", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), y: relativeSpace(coord("y")) },
  inputSpaces: { id: dataSpace },
  // In a template, force runs PER CELL by default: one simulation per panel, each normalized to
  // its own [pad, 1−pad] — a global sim squeezed into panels is never "force inside the facets".
  perCell: true,
  // ONE ordinary apply op (custom plan, like apply-only/vtable): reads the marks, writes the
  // augmented marks. The edges aux relation rides binding.inputs (a table name), not a cell —
  // base tables are not cells anywhere (marktable reads its source the same way). io.key (the
  // cell key when templated) rides payload.by — dispatch iterates the sim per group.
  plan: (io: PlanIO): OpSpec[] => {
    if (io.marksIn === undefined) throw new Error("force: applies over input marks (PlanIO.marksIn)");
    return [{ id: `${io.id}:apply`, reads: [io.marksIn], writes: [io.marksOut], payload: { kind: "apply", algoName: "force", binding: io.binding, ...(io.key !== undefined && { by: io.key }) } }];
  },
  // OPAQUE Exec, dual-substrate: sql = the recursive in-database simulation (force-sql.ts);
  // js = d3-force over the materialized marks (ctx.run executes the aux edges SQL).
  exec: { sql: sqlImpl(forceSql), js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    const run = ctx.run;
    const [xo, yo] = b.outputs;
    const idCol = inputCol(b, "value"); // the marks id column (the primary input)
    const edgesRef = b.inputs.edges;

    // the endpoint columns come from the binding's RESOLVED refs (an instance `on` override or
    // this operator's declared refs — §8 Stage 1b), never a name convention. The fallback below
    // mirrors the declaration for hand-built bindings that skipped the compiler.
    const refPairs = b.refs?.edges ?? [{ from: "src", to: "id" }, { from: "dst", to: "id" }];
    if (refPairs.length < 2) throw new Error(`force "${b.key}": needs two edge endpoint refs (got ${refPairs.length})`);
    const [srcCol, dstCol] = [refPairs[0].from, refPairs[1].from];

    // materialize the aux edges relation (a base table today; empty ⇒ pure repulsion).
    const edges: readonly Record<string, unknown>[] =
      typeof edgesRef === "string" ? await run(mkFrag(`${b.key}:edges`, "SELECT * FROM @e AS m", { e: { base: edgesRef } }, { columns: [{ name: srcCol, type: "unknown" }, { name: dstCol, type: "unknown" }] })) : [];

    // normalize ids to STRINGS on both sides — DuckDB integer columns arrive as BigInt on the raw
    // path and as Number after materialize; d3's node lookup needs one key space (the adapter's job).
    // Links to ABSENT nodes are dropped (a per-cell run sees only its panel's nodes; a
    // cross-panel edge exerts no force — d3 would throw "node not found" otherwise).
    const nodes: FNode[] = marks.rows.map((r) => ({ id: String(r[idCol]) }));
    const present = new Set(nodes.map((n) => n.id));
    const links = edges
      .map((e) => ({ source: String(e[srcCol]), target: String(e[dstCol]) }))
      .filter((l) => present.has(l.source) && present.has(l.target));

    // d3 runs SYNCHRONOUSLY to convergence: stop the internal timer, tick the default schedule
    // (~300 ticks takes alpha to alphaMin). Seeded → deterministic.
    const sim = forceSimulation(nodes as never[])
      .randomSource(mulberry32(0x5eed))
      .force("link", forceLink(links as never[]).id((d) => (d as FNode).id as never).distance(30))
      .force("charge", forceManyBody())
      .force("center", forceCenter(0, 0));
    sim.stop();
    for (let i = 0; i < 300; i++) sim.tick();

    // NORMALIZED: min-max the free-space positions into [pad, 1−pad] per axis (the frame affine
    // owns pixels). A degenerate span (one node) centers at 0.5.
    const pad = 0.05;
    const norm = (vs: readonly number[]): number[] => {
      const lo = Math.min(...vs);
      const hi = Math.max(...vs);
      const span = hi - lo;
      return vs.map((v) => (span === 0 ? 0.5 : pad + (1 - 2 * pad) * ((v - lo) / span)));
    };
    const nx = norm(nodes.map((n) => n.x ?? 0));
    const ny = norm(nodes.map((n) => n.y ?? 0));

    return {
      rows: marks.rows.map((r, i) => ({ ...r, [xo]: nx[i], [yo]: ny[i] })),
      schema: [...marks.schema, { name: xo, type: "double" }, { name: yo, type: "double" }],
    };
  }) },
});
