// Constraint API — pure functions returning Constraint[].
// Each positions or relates PlotRects without side effects.
import type { CellRef } from "../../ir/cell.js";
import type { Constraint } from "../../ir/layout.js";
import type { Extent } from "../../ir/node.js";
import type { PlotRect, Side } from "../../ir/node.js";

type Strength = Constraint["strength"];
interface Opts { strength?: Strength }

/** Target for dock(): scalar node (extent) or template node (inset cells). */
export type DockTarget =
  | { extent: Extent }
  | { insets: Record<Side, CellRef> };

/** Dock a rect on a side. Scalar: reservation + placement + overflow. Template: inset >= demand. */
export function dock(rect: PlotRect, target: DockTarget, side: Side, gap = 0, opts?: Opts): Constraint[] {
  const s = opts?.strength;
  const isH = side === "left" || side === "right";
  const demand = isH ? rect.w : rect.h;

  // Template node: simple 1-term inset constraint (panels sized externally)
  if ("insets" in target) {
    return [{
      terms: [{ coef: 1, edge: target.insets[side] }, { coef: -1, edge: demand }],
      op: ">=", constant: gap, strength: s ?? "strong", label: `dock:${side}:${rect.id}`,
    }];
  }

  const { extent } = target;
  const o = extent.outer;
  const c = extent.content;

  // Reservation: inset >= demand + gap [strong]
  const [hi, lo]: [CellRef, CellRef] = side === "left" ? [c.left, o.left]
    : side === "right" ? [o.right, c.right]
    : side === "top" ? [c.top, o.top]
    : [o.bottom, c.bottom];
  const reservation: Constraint = {
    terms: [{ coef: 1, edge: hi }, { coef: -1, edge: lo }, { coef: -1, edge: demand }],
    op: ">=", constant: gap, strength: s ?? "strong", label: `dock:${side}:${rect.id}`,
  };

  // ponytail: overflow constraint (medium) deferred — emitting it triggers Cassowary for all
  // nodes with axes, but Cassowary isn't fully regression-tested yet. Add when Cassowary is stable.
  return [reservation];
}

/** Float a rect inside the content box at an anchor corner. No space consumed.
 *
 *  PRECONDITION (G3): the rect's x/y/w/h cells must be SOLVER-OWNED (in the arrange op's writes).
 *  Cassowary folds non-owned cells to store CONSTANTS, so with a seeded-0 rect.x the containment
 *  becomes a bound on the CONTENT box — required, it was infeasible against the axis gutters (the
 *  G3 crash); softened, it silently squeezes the plot. No caller satisfies the precondition today
 *  — lowerLegends places inside legends via grid-stack's `inside` anchor instead. Strengths are
 *  soft (strong anchors/containment, weak overflow) so a future owned-rect caller degrades
 *  gracefully rather than throwing. */
export function float(rect: PlotRect, extent: Extent, anchor: "top-left" | "top-right" | "bottom-left" | "bottom-right" = "top-right", pad = 0, opts?: Opts): Constraint[] {
  const c = extent.content;
  const s = opts?.strength ?? "strong";
  const out: Constraint[] = [];

  // Anchor positioning
  if (anchor.includes("right")) {
    out.push({ terms: [{ coef: 1, edge: rect.x }, { coef: 1, edge: rect.w }, { coef: -1, edge: c.right }], op: "=", constant: -pad, strength: s, label: `float-x:${rect.id}` });
  } else {
    out.push({ terms: [{ coef: 1, edge: rect.x }, { coef: -1, edge: c.left }], op: "=", constant: pad, strength: s, label: `float-x:${rect.id}` });
  }
  if (anchor.includes("top")) {
    out.push({ terms: [{ coef: 1, edge: rect.y }, { coef: -1, edge: c.top }], op: "=", constant: pad, strength: s, label: `float-y:${rect.id}` });
  } else {
    out.push({ terms: [{ coef: 1, edge: rect.y }, { coef: 1, edge: rect.h }, { coef: -1, edge: c.bottom }], op: "=", constant: -pad, strength: s, label: `float-y:${rect.id}` });
  }

  // Containment [strong — NEVER required: with a non-owned rect these fold to content-box bounds]
  out.push({ terms: [{ coef: 1, edge: rect.x }, { coef: -1, edge: c.left }], op: ">=", constant: 0, strength: "strong", label: `contain-l:${rect.id}` });
  out.push({ terms: [{ coef: 1, edge: c.right }, { coef: -1, edge: rect.x }, { coef: -1, edge: rect.w }], op: ">=", constant: 0, strength: "strong", label: `contain-r:${rect.id}` });

  // Overflow [weak]
  out.push({ terms: [{ coef: 1, edge: c.bottom }, { coef: -1, edge: rect.y }, { coef: -1, edge: rect.h }], op: ">=", constant: 0, strength: "weak", label: `overflow:${rect.id}` });

  return out;
}

/** Place a adjacent to b (a sits to the right or below b). */
export function adjacentTo(a: PlotRect, b: PlotRect, edge: "right" | "below", gap = 0, opts?: Opts): Constraint[] {
  const s = opts?.strength ?? "required";
  if (edge === "right") {
    return [{ terms: [{ coef: 1, edge: a.x }, { coef: -1, edge: b.x }, { coef: -1, edge: b.w }], op: "=", constant: gap, strength: s, label: `adjacent:${a.id}→${b.id}` }];
  }
  return [{ terms: [{ coef: 1, edge: a.y }, { coef: -1, edge: b.y }, { coef: -1, edge: b.h }], op: "=", constant: gap, strength: s, label: `adjacent:${a.id}↓${b.id}` }];
}

/** Align two rects on an edge or center. */
export function align(a: PlotRect, b: PlotRect, how: "top" | "bottom" | "left" | "right" | "centerX" | "centerY" | "stretchX" | "stretchY", opts?: Opts): Constraint[] {
  const s = opts?.strength ?? "medium";
  switch (how) {
    case "top": return [{ terms: [{ coef: 1, edge: a.y }, { coef: -1, edge: b.y }], op: "=", constant: 0, strength: s, label: `align-top:${a.id}=${b.id}` }];
    case "bottom": return [{ terms: [{ coef: 1, edge: a.y }, { coef: 1, edge: a.h }, { coef: -1, edge: b.y }, { coef: -1, edge: b.h }], op: "=", constant: 0, strength: s, label: `align-bot:${a.id}=${b.id}` }];
    case "left": return [{ terms: [{ coef: 1, edge: a.x }, { coef: -1, edge: b.x }], op: "=", constant: 0, strength: s, label: `align-left:${a.id}=${b.id}` }];
    case "right": return [{ terms: [{ coef: 1, edge: a.x }, { coef: 1, edge: a.w }, { coef: -1, edge: b.x }, { coef: -1, edge: b.w }], op: "=", constant: 0, strength: s, label: `align-right:${a.id}=${b.id}` }];
    case "centerX": return [{ terms: [{ coef: 2, edge: a.x }, { coef: 1, edge: a.w }, { coef: -2, edge: b.x }, { coef: -1, edge: b.w }], op: "=", constant: 0, strength: s, label: `align-cx:${a.id}=${b.id}` }];
    case "centerY": return [{ terms: [{ coef: 2, edge: a.y }, { coef: 1, edge: a.h }, { coef: -2, edge: b.y }, { coef: -1, edge: b.h }], op: "=", constant: 0, strength: s, label: `align-cy:${a.id}=${b.id}` }];
    case "stretchX": return [...align(a, b, "left", opts), ...align(a, b, "right", opts)];
    case "stretchY": return [...align(a, b, "top", opts), ...align(a, b, "bottom", opts)];
  }
}

/** Force two rects to have the same width or height (without position coupling). */
export function sameSize(a: PlotRect, b: PlotRect, dim: "w" | "h", opts?: Opts): Constraint[] {
  const s = opts?.strength ?? "medium";
  const edge = dim === "w" ? "w" : "h";
  return [{ terms: [{ coef: 1, edge: a[edge] }, { coef: -1, edge: b[edge] }], op: "=", constant: 0, strength: s, label: `same-${dim}:${a.id}=${b.id}` }];
}

/** Sugar: equalize the inset (content-edge distance from outer-edge) on a side across nodes.
 *  Reduces to sameSize on the docked rects' relevant dimension. */
export function sameInset(rects: PlotRect[], dim: "w" | "h", opts?: Opts): Constraint[] {
  const out: Constraint[] = [];
  for (let i = 1; i < rects.length; i++) out.push(...sameSize(rects[i - 1], rects[i], dim, opts));
  return out;
}
