// The scale operators + their registration. One registration point (WUMODULES), ONE registry
// (§12 Phase 5): each scale is a single Operator carrying its Execs AND its declarative surface.
import type { Registries } from "../../operator/registry.js";
import type { Operator } from "../../operator/operator.js";
import { applyOnly } from "../internal/apply-only.js";
import { color } from "./color.js";
import { linear } from "./linear.js";
import { log } from "./log.js";
import { ordinal } from "./ordinal.js";
import { point } from "./point.js";
import { pow } from "./pow.js";
import { quantize } from "./quantize.js";
import { sqrt } from "./sqrt.js";
import { symlog } from "./symlog.js";
import { threshold } from "./threshold.js";

export { CATEGORICAL_PALETTE } from "./_shared.js";
export { categorical, continuous } from "./types.js";

export const scaleComponents: readonly Operator[] = [linear, log, sqrt, pow, symlog, ordinal, point, color, quantize, threshold];

/** Register every scale operator into `registries`. */
export function registerScales(registries: Registries): void {
  for (const s of scaleComponents) registries.operators.register(s.name, s);
  registries.operators.register(applyOnly.name, applyOnly);
}
