// point: categorical → a single evenly-spaced POSITION (VL/D3 scalePoint — like band with zero
// bandwidth). Positions sit at band CENTERS: pos(i) = (idx + 0.5)/n, so a categorical dot/line
// plot centers each category. Single-output (a position, no width), so it binds like linear —
// `x: point('cat')`, no pick.
//
// THE FIT IS THE DOMAIN (WUAXIS §apply-only, as band): train is the KEYED category table
// (value, idx, n) and apply is a keyed join, so the axis re-applies point over V and labels each
// category at its own position.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, nullif0 } from "../../algebra/relop.js";
import { categorical } from "./types.js";
import { out0 } from "./_shared.js";

export const point = op({
  name: "point",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  // discrete + ordered (categories have positional meaning)
  domain: categorical((b): RelOp => ({ kind: "unique", col: inputCol(b, "value"), as: "value", indexed: true }), { ordered: true }),
  apply: (b): RelOp => {
    // pos = (idx + 0.5)/n — the band center; data points AND axis ticks sit here (no anchor split).
    const pos = bin("/", bin("+", fcol("idx"), lit(0.5)), nullif0(fcol("n")));
    return { kind: "derive", add: { [out0(b)]: pos }, outTypes: { [out0(b)]: "double" } };
  },
  ticks: "ordinal",
});
