// symlog: symmetric log — handles zero and negative values. Uses the "bi-symmetric log"
// transform: sign(x) * log(1 + |x|/c) where c is a tuning constant (default 1).
// Same domain shape as linear (min-max envelope, niceable).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, lit, mcol, nullif0, ln, unary } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

// ponytail: symlog(x) = sign(x) * ln(1 + |x|/c). In ScalarExpr we don't have sign(),
// so we express it as: x / abs(x) * ln(1 + abs(x) / c). For x=0: ln(1+0)=0, and 0/0
// is caught by nullif0 → null → the formula short-circuits. Good enough for v1.
const symlogExpr = (x: ReturnType<typeof mcol>, c: number) => {
  const ax = unary("abs", x);
  const transformed = ln(bin("+", lit(1), bin("/", ax, lit(c))));
  // sign(x) * transformed: x / nullif0(abs(x)) * transformed
  return bin("*", bin("/", x, nullif0(ax)), transformed);
};

export const symlog = op({
  name: "symlog",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } })),
  scheme: "blues",
  legend: "ramp",
  apply: (b): RelOp => {
    const c = Number(b.options?.constant ?? 1);
    const sv = symlogExpr(mcol(inputCol(b, "value")), c);
    const slo = symlogExpr(fcol("lo"), c);
    const shi = symlogExpr(fcol("hi"), c);
    return scaledOut(b, bin("/", bin("-", sv, slo), nullif0(bin("-", shi, slo))));
  },
  ticks: "nice-linear",
});
