// Arrow Table → plain DVL rows. Shared by the node + browser DuckDB adapters. Coerces
// BIGINT → number and DECIMAL → number (applying the scale divisor from the Arrow schema).
//
// DECIMAL policy (see dialect.ts numberLiteral, the write-side half): DVL never SENDS decimals
// into the database — but it cannot control data already IN the database, so the read side
// compensates here. Arrow surfaces a DECIMAL as its scaled integer packed as number, bigint, or
// a DecimalBigNum object depending on width; the divisor applies on EVERY branch (skipping one
// returns 10^scale-inflated values — SELECT 0.5 once arrived as 5).
import { dvlSettings } from "../config.js";
import type { RawRow } from "./schema.js";

interface ArrowField {
  name: string;
  type: { typeId?: number; scale?: number; precision?: number };
}
interface ArrowSchema {
  fields: ArrowField[];
}
interface ArrowRow {
  toJSON(): Record<string, unknown>;
}
interface ArrowTable {
  schema: ArrowSchema;
  toArray(): readonly ArrowRow[];
}

export function arrowToRows(table: ArrowTable): RawRow[] {
  // Pre-compute scale divisors for DECIMAL columns (Arrow typeId 7 = Decimal).
  const divisors = new Map<string, number>();
  for (const f of table.schema.fields) {
    if (f.type.scale !== undefined && f.type.scale > 0) {
      divisors.set(f.name, 10 ** f.type.scale);
    }
  }
  const rows = table.toArray();
  // Fast path: no DECIMAL columns ⇒ only the bigint coercion can apply, no divisor lookups.
  if (divisors.size === 0) {
    return rows.map((row) => {
      const out: Record<string, unknown> = {};
      for (const [k, v] of Object.entries(row.toJSON())) {
        out[k] = typeof v === "bigint" ? Number(v) : coerceNonDecimal(k, v);
      }
      return out;
    });
  }
  return rows.map((row) => {
    const out: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(row.toJSON())) {
      if (v === null || v === undefined) { out[k] = v; continue; }
      const div = divisors.get(k);
      if (div === undefined) { out[k] = typeof v === "bigint" ? Number(v) : coerceNonDecimal(k, v); continue; }
      // DECIMAL column: unscale whatever representation Arrow chose.
      if (typeof v === "number") { out[k] = v / div; continue; }
      if (typeof v === "bigint") { out[k] = Number(v) / div; continue; }
      const n = Number((v as { valueOf(): unknown }).valueOf?.() ?? NaN);
      if (Number.isFinite(n)) { out[k] = n / div; continue; }
      if (dvlSettings.strict) throw new Error(`arrowToRows: DECIMAL column "${k}" holds an unconvertible value (${String(v)}) — cannot unscale`);
      out[k] = 0;
    }
    return out;
  });
}

/** Non-DECIMAL object values (nested structs, intervals): pass primitives through; anything else
 *  is an error in strict mode rather than a silent 0. */
function coerceNonDecimal(k: string, v: unknown): unknown {
  if (v === null || v === undefined || typeof v === "number" || typeof v === "string" || typeof v === "boolean") return v;
  const n = Number((v as { valueOf(): unknown }).valueOf?.() ?? NaN);
  if (Number.isFinite(n)) return n;
  if (dvlSettings.strict) throw new Error(`arrowToRows: column "${k}" holds an unconvertible value (${String(v)})`);
  return 0;
}
