// Squarified treemap as a single recursive DuckDB SQL query — the treemap operator's SQL
// impl (treemap.ts: `sql: sqlImpl(treemapSql)`).
//
// Squarify is a linear greedy state machine (Bruls et al.), which SQL expresses directly:
//   1. sort items by decreasing area;
//   2. try adding the next item to the current strip;
//   3. if the strip's worst aspect ratio improves (or stays equal), accept it;
//   4. otherwise finalize the strip, shrink the remaining rectangle, and RECONSIDER
//      the same item against the fresh strip.
// The recursive state is small — (next item i, strip id, strip sum/min/max, remaining
// rect x/y/w/h) — and the scan makes at most ~2n transitions (each step either accepts
// an item or finalizes a strip; a finalize is always followed by an accept since an
// empty strip accepts unconditionally). No pair generation, no USING KEY needed: this
// is a plain WITH RECURSIVE ... UNION ALL whose column names come from the seed branch.
//
// The `worst` aspect-ratio test depends only on the strip's total/min/max area and the
// short side of the remaining rectangle:
//   worst(sum, min, max, s) = max(s²·max/sum², sum²/(s²·min))
// and the accept decision is worst(with candidate) <= worst(without).
//
// Placement mirrors the JS impl's contract (treemap.ts): boxes are NORMALIZED to
// [0,1]×[0,1] — x/y/w/h are relative; the frame affine places them. Non-positive
// weights are excluded from the state machine and land as zero-size boxes at the
// origin (matching the d3 path, where such leaves resolve to 0s).
//
// Identity: marks rows carry no guaranteed key, so the fragment mints a row ordinal
// (__tm_rn) on the marks, sorts by (weight DESC, __tm_rn) for determinism, and joins
// placements back by that ordinal. The ordinal is EXCLUDEd from the output so the
// passthrough schema stays exactly marks + {x, y, w, h}.
import type { OpBinding } from "../../algebra/impl.js";
import { inputCol } from "../../algebra/impl.js";
import type { ExecCtx } from "../../algebra/impl.js";
import { sanitizeOp } from "../../algebra/relation.js";
import type { SqlFragment } from "../../data/fragment.js";

export function treemapSql(inputs: readonly SqlFragment[], b: OpBinding, _ctx: ExecCtx): SqlFragment {
  const marks = inputs[0];
  const [xo, yo, wo, ho] = b.outputs;
  const valCol = inputCol(b, "value");
  const key = `${b.key}:treemap-sql`;
  const op = sanitizeOp(key);

  // The unit square: outputs are relative [0,1]; the affine owns pixels.
  const W = "1.0";
  const H = "1.0";

  // All local CTE names are @-prefixed so the fold rewrites them on uniquification;
  // the recursive self-reference (@st) is rewritten to the same uniquified name.

  // Marks with a minted row ordinal — the join-back identity.
  const marksRnBody = `SELECT m.*, row_number() OVER () AS __tm_rn FROM @marks AS m`;

  // Sorted, normalized items: idx is the squarify visiting order; area sums to W·H.
  const itemsBody = `SELECT
      row_number() OVER (ORDER BY greatest(0, m."${valCol}"::DOUBLE) DESC, m.__tm_rn) AS idx,
      m.__tm_rn,
      greatest(0, m."${valCol}"::DOUBLE) * ${W} * ${H}
        / nullif(sum(greatest(0, m."${valCol}"::DOUBLE)) OVER (), 0) AS area
    FROM @marks_rn AS m
    WHERE greatest(0, m."${valCol}"::DOUBLE) > 0`;

  // One row per state transition. Seed: empty strip 1, full rectangle, item 1 next.
  // Recursive branch: joins the NEXT item (stops when i exceeds the item count),
  // computes the candidate strip stats laterally, and either accepts (advance i,
  // record accepted_idx) or finalizes (shrink the rect along its SHORT side by the
  // strip's thickness row_sum/longside; the same item is retried next step).
  const stateBody = `SELECT
      0 AS step, 1 AS i, 1 AS row_id,
      0.0::DOUBLE AS row_sum, NULL::DOUBLE AS row_min, NULL::DOUBLE AS row_max,
      0.0::DOUBLE AS rx, 0.0::DOUBLE AS ry, ${W}::DOUBLE AS rw, ${H}::DOUBLE AS rh,
      NULL::INTEGER AS accepted_idx
    UNION ALL
    SELECT
      s.step + 1,
      CASE WHEN decision.take THEN s.i + 1 ELSE s.i END,
      CASE WHEN decision.take THEN s.row_id ELSE s.row_id + 1 END,
      CASE WHEN decision.take THEN candidate.new_sum ELSE 0.0 END,
      CASE WHEN decision.take THEN candidate.new_min ELSE NULL END,
      CASE WHEN decision.take THEN candidate.new_max ELSE NULL END,
      CASE WHEN decision.take THEN s.rx
           WHEN s.rw >= s.rh THEN s.rx + s.row_sum / s.rh
           ELSE s.rx END,
      CASE WHEN decision.take THEN s.ry
           WHEN s.rw >= s.rh THEN s.ry
           ELSE s.ry + s.row_sum / s.rw END,
      CASE WHEN decision.take THEN s.rw
           WHEN s.rw >= s.rh THEN s.rw - s.row_sum / s.rh
           ELSE s.rw END,
      CASE WHEN decision.take THEN s.rh
           WHEN s.rw >= s.rh THEN s.rh
           ELSE s.rh - s.row_sum / s.rw END,
      CASE WHEN decision.take THEN s.i ELSE NULL END
    FROM @st AS s
    JOIN @items AS item ON item.idx = s.i
    CROSS JOIN LATERAL (
      SELECT
        s.row_sum + item.area AS new_sum,
        CASE WHEN s.row_sum = 0 THEN item.area ELSE least(s.row_min, item.area) END AS new_min,
        CASE WHEN s.row_sum = 0 THEN item.area ELSE greatest(s.row_max, item.area) END AS new_max
    ) AS candidate
    CROSS JOIN LATERAL (
      SELECT
        CASE
          WHEN s.row_sum = 0 THEN TRUE
          ELSE greatest(
                 power(least(s.rw, s.rh), 2) * candidate.new_max / power(candidate.new_sum, 2),
                 power(candidate.new_sum, 2) / (power(least(s.rw, s.rh), 2) * candidate.new_min)
               )
               <=
               greatest(
                 power(least(s.rw, s.rh), 2) * s.row_max / power(s.row_sum, 2),
                 power(s.row_sum, 2) / (power(least(s.rw, s.rh), 2) * s.row_min)
               )
        END AS take
    ) AS decision`;

  // Each accepted transition pins its item to a strip, with the remaining rect AS OF
  // acceptance (the rect only shrinks on finalize, so all items of one strip share it).
  const assignedBody = `SELECT accepted_idx AS idx, row_id, rx, ry, rw, rh
    FROM @st WHERE accepted_idx IS NOT NULL`;

  // Prefix area within each strip orders items along the strip's long side;
  // row_area fixes the strip thickness.
  const rowItemsBody = `SELECT
      a.idx, a.row_id, a.rx, a.ry, a.rw, a.rh, i.__tm_rn, i.area,
      coalesce(sum(i.area) OVER (
        PARTITION BY a.row_id ORDER BY a.idx
        ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING), 0) AS area_before,
      sum(i.area) OVER (PARTITION BY a.row_id) AS row_area
    FROM @assigned AS a
    JOIN @items AS i USING (idx)`;

  // Boxes: a horizontal strip (rw >= rh) lays items left-to-right with shared height
  // row_area/rh; a vertical strip lays them top-to-bottom with shared width row_area/rw.
  const placedBody = `SELECT
      __tm_rn,
      CASE WHEN rw >= rh THEN rx ELSE rx + area_before / (row_area / rw) END AS bx,
      CASE WHEN rw >= rh THEN ry + area_before / (row_area / rh) ELSE ry END AS by,
      CASE WHEN rw >= rh THEN row_area / rh ELSE area / (row_area / rw) END AS bw,
      CASE WHEN rw >= rh THEN area / (row_area / rh) ELSE row_area / rw END AS bh
    FROM @row_items`;

  // Join back onto ALL marks (zero/negative weights get zero-size boxes at the origin,
  // matching the JS impl); drop the minted ordinal so passthrough stays exact.
  const resultBody = `SELECT
      m.* EXCLUDE (__tm_rn),
      coalesce(p.bx, 0)::DOUBLE AS "${xo}",
      coalesce(1 - p.by, 0)::DOUBLE AS "${yo}", -- top edge y-UP (1 − screen y0); see treemap.ts
      coalesce(p.bw, 0)::DOUBLE AS "${wo}",
      coalesce(p.bh, 0)::DOUBLE AS "${ho}"
    FROM @marks_rn AS m
    LEFT JOIN @placed AS p USING (__tm_rn)`;

  return {
    id: key,
    op,
    ctes: [
      { name: "marks_rn", body: marksRnBody },
      { name: "items", body: itemsBody },
      { name: "st", body: stateBody, recursive: true },
      { name: "assigned", body: assignedBody },
      { name: "row_items", body: rowItemsBody },
      { name: "placed", body: placedBody },
      { name: "r", body: resultBody },
    ],
    result: "r",
    inputs: { marks: { fragment: marks } },
    outputs: {
      passthrough: "marks",
      add: [
        { name: xo, type: "double" },
        { name: yo, type: "double" },
        { name: wo, type: "double" },
        { name: ho, type: "double" },
      ],
    },
    cells: [],
  };
}
