// compileNode: ONE node — all its plots — into operator descriptions (ex dataflow/graph.ts).
// Shares node-local state (frame scales' cells, the extent box) across compilePlot calls;
// compileSpec (executor/) walks the node tree. The box model is separate: arrange writes the
// content-edge cells; compileNode just READS them.
import type { Spec } from "../../ir/spec.js";
import type { CellRef, CellStore } from "../../ir/cell.js";
import type { OpSpec } from "../opspec.js";
import type { LayoutId, NodeId } from "../../types/ids.js";
import { isProducerSource, isRelationSource, sourceKey, type Plot } from "../../ir/plot.js";
import { arrangeNode, arrangeTemplate, DEFAULT_MARGIN, NESTED_MARGIN } from "../../layout/arrange.js";
import { boxModes, num, opOf, type NodeBuild, type PlotBuild, type RenderOpts, type TemplateCtx } from "./context.js";
import { emitGatherScatter, planDomainGroups, type DomainGroups } from "./domains.js";
import { compilePlot } from "./plot.js";

/** Compile ONE node: every plot (data marks and — post-lowering — axis marks) through the same
 *  pipeline, sharing node-local state. Does NOT recurse children (compileSpec walks the tree).
 *  `domains` is compileSpec's cross-node collector; standalone (tests) it plans + emits locally. */
export function compileNode(spec: Spec, nodeId: NodeId, opts: RenderOpts, domains?: DomainGroups, template?: TemplateCtx): NodeBuild {
  const node = spec.nodes.get(nodeId);
  if (node === undefined) throw new Error(`compileNode: no node "${nodeId}"`);
  const specs: OpSpec[] = [];
  const plots: PlotBuild[] = [];
  const producers = new Map<LayoutId, CellRef>(); // node-local: each producer's plan emitted ONCE, shared by its readers
  const standalone = domains === undefined;
  const dom = domains ?? planDomainGroups(spec);
  // a TEMPLATE node solves INSETS, not scalar extents — allocate them BEFORE the plot loop
  // (the keyed affine reads them); the op itself is pushed with the others below.
  const templateArrange = template !== undefined ? arrangeTemplate(spec, nodeId, NESTED_MARGIN) : undefined;
  for (const plotId of node.plots) plots.push(compilePlot(spec, nodeId, plotId, specs, producers, dom.contributions, opts, template, plots));
  if (standalone) emitGatherScatter(spec, dom, specs);

  // Plot bounding-box measurement: for each PlotRect with seeded w/h,
  // emit a plot-measure op that fills those cells from the rendered bbox of its plots.
  if (node.plotRects !== undefined && node.plotRects.length > 0) {
    for (const pr of node.plotRects) {
      const marksCells = pr.plots.map((pid) => {
        const pb = plots.find((b) => b.pid === pid);
        if (pb === undefined) throw new Error(`plot-measure: plot "${pid}" not compiled in node "${nodeId}"`);
        return pb.marks;
      });
      specs.push({
        id: `${nodeId}:plot-measure:${pr.plots.join("+")}`,
        reads: marksCells,
        writes: [pr.w, pr.h],
        payload: { kind: "plot-measure", plots: pr.plots },
      });
    }
  }

  // Children (containers are marks): a child's OUTER extent extracts from its host MARK's RELATIVE
  // box — one `host-extent` op per child, reading the host plot's relative marks (+ this node's
  // content edges, which relative values lerp). It writes ONLY the edges the mark determines;
  // a missing box channel leaves a HOLE for the solver stage (fillChildExtentHoles).
  // Row pairing keys on the recorded FK (`hostRow` — the subplot model).
  for (const childRef of node.children) {
    if (childRef.hostRow === undefined) continue; // a TEMPLATE child: no scalar extents — the keyed affine reads the box RELATION
    const host = plots.find((p) => p.pid === childRef.hostPlot);
    if (host === undefined) throw new Error(`compileNode: child "${childRef.node}" hosted by unknown plot "${childRef.hostPlot}"`);
    const child = spec.nodes.get(childRef.node);
    if (child === undefined) continue;
    const row = childRef.hostRow;
    const hostPlot = spec.plots.get(childRef.hostPlot)!;
    const box = boxModes(hostPlot.channels); // which box channels exist, and relative vs pixel
    if (box.x === undefined && box.y === undefined) continue; // no box at all → all four edges are holes
    const co = child.extent.outer;
    const cc = node.extent.content;
    // writes pair positionally with the DETERMINED edges, in [left, right, top, bottom] order.
    const writes: CellRef[] = [];
    if (box.x !== undefined) writes.push(co.left);
    if (box.x !== undefined && box.w !== undefined) writes.push(co.right);
    if (box.y !== undefined) writes.push(co.top);
    if (box.y !== undefined && box.h !== undefined) writes.push(co.bottom);
    specs.push({
      id: `${childRef.node}:host-extent`,
      reads: [host.relMarks, cc.left, cc.right, cc.top, cc.bottom],
      writes,
      payload: { kind: "host-extent", parent: nodeId, child: childRef.node, row, ...box },
    });
  }
  // The node's box is an OPERATOR like everything else: one arrange op per node (reads outer +
  // the demand cells its constraints reference, writes content + child outers); the scheduler orders
  // measure → arrange → affine purely off the declared cells.
  specs.push(templateArrange ?? arrangeNode(spec, nodeId, nodeId === spec.root ? (opts.margin ?? DEFAULT_MARGIN) : NESTED_MARGIN));
  return { nodeId, specs, plots };
}

