// quantize: continuous → discrete bins. Divides the [lo, hi] domain into N equal-width
// bins and maps each value to the bin's output (from a palette/range). Like D3.scaleQuantize.
// Domain: min-max (trains lo/hi). Output: discrete (index into range).
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, floor, index, lit, mcol, nullif0 } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { ordRange, ordType, out0 } from "./_shared.js";

export const quantize = op({
  name: "quantize",
  // binding-polymorphic (§12.2): the output space is the frame channel the INSTANCE serves
  // (relative coord⟨x|y⟩ positional, style⟨…⟩ palette) — stamped at bind, declared here as such.
  outSpaces: { value: "binding" },
  // quantize is continuous (trains min-max) but output is discrete. Not niceable (bins are fixed).
  // union: null — each quantize computes its own bins from its own data range (unionFn dropped
  // with it); ticks stay the constructor's nice-linear.
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } }), { union: null, unionFn: undefined, nice: undefined }),
  apply: (b): RelOp => {
    const rng = ordRange(b);
    const n = rng.length;
    // bin index = floor(t * n), clamped by index()'s modulo
    const t = bin("/", bin("-", mcol(inputCol(b, "value")), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo"))));
    return { kind: "derive", add: { [out0(b)]: index(rng, floor(bin("*", t, lit(n)))) }, outTypes: { [out0(b)]: ordType(rng) } };
  },
});
