// color: an explicit CONTINUOUS colour scale — a numeric value → a position on a colour ramp.
// After AUTOLEGEND §6 this is just `linear` with a sequential-scheme default: the SAME train
// (min/max) and the SAME normalized t, emitted through the shared `scaledOut` helper, which indexes
// the resolved 256-step ramp when the channel is style⟨color⟩ (smooth, dual-substrate — no
// colour-interp primitive). The old 9-step `index(RAMP, floor(t·8))` banding is gone. `color` is
// kept as an explicit-intent factory ("I want a continuous colour scale"); `linear` on a colour
// channel is now identical.
import { inputCol } from "../../algebra/impl.js";
import { type RelOp } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import { bin, fcol, mcol, nullif0 } from "../../algebra/relop.js";
import { continuous } from "./types.js";
import { scaledOut } from "./_shared.js";

export const color = op({
  name: "color",
  outSpaces: { value: "binding" },
  // continuous, sequential-by-default; the ramp is a fixed palette so not niceable.
  domain: continuous((b): RelOp => ({ kind: "reduce", aggs: { lo: { fn: "min", col: inputCol(b, "value") }, hi: { fn: "max", col: inputCol(b, "value") } } }), { nice: undefined }),
  scheme: "blues",
  legend: "ramp",
  apply: (b): RelOp => {
    // t = (value − lo) / NULLIF(hi − lo, 0) ∈ [0,1]; scaledOut indexes the resolved ramp.
    const t = bin("/", bin("-", mcol(inputCol(b, "value")), fcol("lo")), nullif0(bin("-", fcol("hi"), fcol("lo"))));
    return scaledOut(b, t);
  },
});
