// Dialect emitter — the backend-specific rendering of a folded query (WUDATA §1).
// The fragment representation is dialect-agnostic; the adapter supplies a Dialect.

import type { Scalar, SqlType } from "./schema.js";

export interface Dialect {
  /** Render a scalar as a typed SQL literal (quoted/escaped). */
  literal(v: Scalar, t?: SqlType): string;
  /** Quote an identifier. */
  ident(name: string): string;
  /** A 1-based bound-parameter placeholder. */
  paramPlaceholder(index1: number): string;
  /** `WITH` or `WITH RECURSIVE`. */
  withClause(recursive: boolean): string;
}

/** THE number→SQL rule (single source): anything DVL sends INTO the database must never become
 *  a DECIMAL. DuckDB parses a bare decimal literal (`0.9500000000000001`) as fixed-point DECIMAL
 *  first — rounding at DECIMAL precision AND poisoning downstream arithmetic to DECIMAL — while
 *  the EXPONENT form (`0.95e0`) parses directly as DOUBLE and round-trips every JS double exactly.
 *  Integers stay bare (INT context); non-finite values are NULL. Every literal-rendering site
 *  (dialect.literal → emit/registerRows; sqlLiteral → fragment bodies/valuesFrag) routes here.
 *  (Data already IN the database may still be DECIMAL — the READ side compensates: duckdb-rows.) */
export function numberLiteral(v: number): string {
  if (!Number.isFinite(v)) return "NULL";
  if (Number.isInteger(v)) return String(v);
  const s = String(v);
  return s.includes("e") ? s : `${s}e0`; // 0.95 → 0.95e0; 1e-7 already exponent-form
}

/** A DuckDB-flavored default dialect; portable enough for the fold/emit core. */
export const defaultDialect: Dialect = {
  literal(v: Scalar): string {
    if (v === null) return "NULL";
    if (typeof v === "number") return numberLiteral(v);
    if (typeof v === "boolean") return v ? "TRUE" : "FALSE";
    return `'${v.replace(/'/g, "''")}'`;
  },
  ident(name: string): string {
    return `"${name.replace(/"/g, '""')}"`;
  },
  paramPlaceholder(index1: number): string {
    return `$${index1}`;
  },
  withClause(recursive: boolean): string {
    return recursive ? "WITH RECURSIVE" : "WITH";
  },
};

/** A portable inline SQL literal (numbers/bools/null; single-quoted strings).
 *  Numbers route through numberLiteral (this module) — the ONE place that guarantees nothing DVL
 *  writes into the database ever parses as DECIMAL. */
export function sqlLiteral(v: Scalar): string {
  if (v === null) return "NULL";
  if (typeof v === "number") return numberLiteral(v);
  if (typeof v === "boolean") return v ? "TRUE" : "FALSE";
  return `'${v.replace(/'/g, "''")}'`;
}
