// vtable op: resolved domain → V (tick relation) via a registered tick algo.
import type { Scalar } from "../../../data/schema.js";
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellRef, CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { genTicks } from "../../../operator/ticks.js";
import type { VtablePayload } from "../../../plan/payloads.js";
import { jsRel, mkFrag, sqlRel, valuesFrag, type JsRel, type Relation } from "../../../algebra/relation.js";
const clampCount = (len: number): number => (Number.isFinite(len) ? Math.max(2, Math.min(10, Math.round(Math.abs(len) / 60))) : 5);

function tickCountFor(store: CellStore, extent: readonly [CellRef, CellRef]): number {
  const lo = Number(store.read(extent[0]));
  const hi = Number(store.read(extent[1]));
  return clampCount(hi - lo);
}

export async function vtableOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const p = op.payload as unknown as VtablePayload;
  if (p.kind !== "vtable") return;
  if (p.indicator !== undefined && Number(store.read(p.indicator)) === 0) {
    store.write(op.writes[0], sqlRel(mkFrag(`${op.id}:off`, `SELECT * FROM (VALUES (0, 0.0, '')) AS _v(idx, "value", label) WHERE FALSE`, {}, { columns: [{ name: "idx", type: "int" }, { name: "value", type: "double" }, { name: "label", type: "varchar" }] })), "assigned");
    return;
  }
  const domain = store.read(op.reads[0]) as JsRel;
  const paramsFor = (rows: readonly Record<string, unknown>[]): Readonly<Record<string, Scalar | readonly Scalar[]>> => {
    const first = rows[0] as Record<string, unknown> | undefined;
    return first !== undefined && !("lo" in first)
      ? { categories: [...rows].sort((a, b) => Number((a as Record<string, unknown>).idx ?? 0) - Number((b as Record<string, unknown>).idx ?? 0)).map((r) => (r as Record<string, Scalar>).value ?? (r as Record<string, Scalar>).category) }
      : { min: Number(first?.lo), max: Number(first?.hi) };
  };
  if (p.by !== undefined) {
    const algo = p.algo;
    const keyedDomain = domain.rows[0] !== undefined && (domain.rows[0] as Record<string, unknown>)[p.by] !== undefined;
    const groups = new Map<number, Record<string, unknown>[]>();
    if (keyedDomain) {
      for (const r of domain.rows) {
        const k = Number((r as Record<string, unknown>)[p.by]);
        const g = groups.get(k);
        if (g === undefined) groups.set(k, [r as Record<string, unknown>]);
        else g.push(r as Record<string, unknown>);
      }
    }
    let cells: { k: number; count: number }[];
    if (p.countFrom !== undefined) {
      const boxRel = store.read(p.boxes!) as Relation;
      const boxRows = boxRel.substrate === "js" ? boxRel.rows : await ctx.run(boxRel.frag);
      const iLo = Number(store.read(p.insetLo!));
      const iHi = Number(store.read(p.insetHi!));
      cells = boxRows.map((b) => {
        const r = b as Record<string, unknown>;
        const len = Number(p.countFrom === "x" ? r.w : r.h) - iLo - iHi;
        return { k: Number(r.dvl_mark), count: p.count ?? clampCount(len) };
      });
    } else {
      const cnt = p.count ?? 5;
      cells = [...groups.keys()].map((k) => ({ k, count: cnt }));
    }
    cells.sort((a, b) => a.k - b.k);
    const rows: Record<string, Scalar>[] = [];
    let schema: JsRel["schema"] = [];
    for (const cell of cells) {
      const drows = keyedDomain ? groups.get(cell.k) : (domain.rows as readonly Record<string, unknown>[]);
      if (drows === undefined || drows.length === 0) continue;
      const one = (await genTicks(algo, paramsFor(drows), { column: p.column, count: cell.count }, jsRel([], []), "js", ctx.run)) as JsRel;
      schema = one.schema;
      for (const t of one.rows) rows.push({ [p.by]: cell.k, ...t } as Record<string, Scalar>);
    }
    if (rows.length === 0) {
      store.write(op.writes[0], sqlRel(mkFrag(`${op.id}:off`, `SELECT * FROM (VALUES (0, 0, 0.0, '')) AS _v("${p.by}", idx, "${p.column}", label) WHERE FALSE`, {}, { columns: [{ name: p.by, type: "int" }, { name: "idx", type: "int" }, { name: p.column, type: "double" }, { name: "label", type: "varchar" }] })), "assigned");
      return;
    }
    store.write(op.writes[0], sqlRel(valuesFrag(`${op.id}:V`, rows, [{ name: p.by, type: "int" }, ...schema])), "assigned");
    return;
  }
  const count = p.count ?? tickCountFor(store, p.extent!);
  const V = await genTicks(p.algo, paramsFor(domain.rows), { column: p.column, count }, jsRel([], []), "sql", ctx.run);
  store.write(op.writes[0], V, "assigned");
}
