// Color schemes (AUTOLEGEND §6) — the ONE registry of named palettes, replacing the two hardcoded
// arrays that used to live in scales/_shared.ts and scales/color.ts. Two families:
//   - CATEGORICAL: a fixed list of distinct hues, indexed by category (ordinal color).
//   - SEQUENTIAL / DIVERGING: a colour RAMP given as a few control stops, pre-sampled to 256 steps
//     so a continuous colour scale is `index(ramp, floor(t·255))` — visually smooth, dual-substrate
//     (index lowers to SQL and JS today), no colour-interpolation primitive needed (§6.3 option a).
// Resolve-once (principle #8): the IR holds the scheme NAME; resolveSpec stamps the resolved array.
import type { Registries } from "../operator/registry.js";

const RAMP_STEPS = 256;

const hex2rgb = (h: string): [number, number, number] => [parseInt(h.slice(1, 3), 16), parseInt(h.slice(3, 5), 16), parseInt(h.slice(5, 7), 16)];
const rgb2hex = (c: readonly number[]): string => "#" + c.map((v) => Math.max(0, Math.min(255, Math.round(v))).toString(16).padStart(2, "0")).join("");

/** Piecewise-linear RGB interpolation of `stops` sampled to `n` colours. */
export function sampleRamp(stops: readonly string[], n = RAMP_STEPS): string[] {
  const rgb = stops.map(hex2rgb);
  const out: string[] = [];
  for (let i = 0; i < n; i++) {
    const t = n === 1 ? 0 : i / (n - 1);
    const x = t * (rgb.length - 1);
    const lo = Math.floor(x);
    const hi = Math.min(lo + 1, rgb.length - 1);
    const f = x - lo;
    out.push(rgb2hex([0, 1, 2].map((k) => rgb[lo][k] + (rgb[hi][k] - rgb[lo][k]) * f)));
  }
  return out;
}

// ── categorical palettes (distinct hues; indexed by category rank mod n) ──
const CATEGORICAL: Record<string, readonly string[]> = {
  tableau10: ["#4e79a7", "#f28e2b", "#e15759", "#76b7b2", "#59a14f", "#edc949", "#af7aa1", "#ff9da7", "#9c755f", "#bab0ab"],
  observable10: ["#4269d0", "#efb118", "#ff725c", "#6cc5b0", "#3ca951", "#ff8ab7", "#a463f2", "#97bbf5", "#9c6b4e", "#9498a0"],
  category10: ["#1f77b4", "#ff7f0e", "#2ca02c", "#d62728", "#9467bd", "#8c564b", "#e377c2", "#7f7f7f", "#bcbd22", "#17becf"],
};

// ── ramp control stops (sampled to 256 below) ──
const RAMP_STOPS: Record<string, readonly string[]> = {
  // sequential
  blues: ["#f7fbff", "#deebf7", "#c6dbef", "#9ecae1", "#6baed6", "#4292c6", "#2171b5", "#08519c", "#08306b"],
  viridis: ["#440154", "#482878", "#3e4a89", "#31688e", "#26828e", "#1f9e89", "#35b779", "#6ece58", "#b5de2b", "#fde725"],
  turbo: ["#30123b", "#4145ab", "#4675ed", "#39a2fc", "#1bcfd4", "#24eca6", "#61fc6c", "#a4fc3b", "#d1e834", "#f3c63a", "#fe9b2d", "#f36315", "#cb2a04", "#7a0403"],
  // diverging (pivot is the middle stop)
  rdbu: ["#67001f", "#b2182b", "#d6604d", "#f4a582", "#fddbc7", "#f7f7f7", "#d1e5f0", "#92c5de", "#4393c3", "#2166ac", "#053061"],
  blueorange: ["#134b85", "#4a90c4", "#8fc0dc", "#d5e5ef", "#f7f7f7", "#fce0c8", "#f9b168", "#e57e28", "#a95213"],
};

/** Every built-in scheme resolved to its palette array (categorical as-is; ramps sampled to 256). */
export const builtinSchemes: Record<string, readonly string[]> = {
  ...CATEGORICAL,
  ...Object.fromEntries(Object.entries(RAMP_STOPS).map(([name, stops]) => [name, sampleRamp(stops)])),
};

export function registerSchemes(r: Registries): void {
  for (const [name, palette] of Object.entries(builtinSchemes)) r.schemes.register(name, palette);
}
