// Operations on TypedSchema — the Attr-level analog of data/schema.ts's
// composeSchema / reconcile (reorg §4.3 "signature checking is schema
// composition, not tag comparison"; §8.3 "attrs live on columns, never on
// relations").
//
// An operator's signature is stated per-column: it REQUIRES certain spaces in its
// inputs, ADDS some attrs (replacing same-named ones in place), and passes the
// rest through untouched (row polymorphism — ρ is "the rest of the columns").
// This is OutSchema's passthrough+add generalized from (name, carrier) to
// (name, carrier, space).
import type { Attr, Space, TypedSchema } from "./attr.js";
import { fits, isData, showSpace } from "./attr.js";

// ─────────────────────────────────────────────────────────────────────────────
// Composition — passthrough + add, replacing in place (mirrors composeSchema, but
// carrying the full Attr). This is what a `derive`/`apply` produces: the input
// attrs, with added columns overwriting same-named ones and the rest appended.
export function composeAttrs(base: TypedSchema, add: TypedSchema): TypedSchema {
  const result: Attr[] = base.map((a) => ({ ...a }));
  for (const a of add) {
    const idx = result.findIndex((c) => c.name === a.name);
    if (idx >= 0) result[idx] = { ...a }; // REPLACE in place (SELECT * REPLACE)
    else result.push({ ...a });
  }
  return result;
}

export function lookup(schema: TypedSchema, name: string): Attr | undefined {
  return schema.find((a) => a.name === name);
}

// ─────────────────────────────────────────────────────────────────────────────
// Signature satisfaction — the row-polymorphic operator contract. A Requirement
// names a column and the space it must be in; `ρ` (the rest) always passes. This
// is the check the planner runs at plan time — the dimensional checker validate.ts
// has deferred since C6, with a place to stand.
export interface Requirement {
  readonly name: string;
  readonly space: Space;
}

/** Requirements with ROLE names resolved to the instance's bound COLUMN names (W4a).
 *  A role the binding doesn't bind resolves to itself (aux relations are read elsewhere). */
export function requirementsOf(inputSpaces: Record<string, Space>, resolveCol: (role: string) => string | undefined): Requirement[] {
  return Object.entries(inputSpaces).map(([role, space]) => ({ name: resolveCol(role) ?? role, space }));
}

export type SatisfyResult =
  | { readonly ok: true }
  | { readonly ok: false; readonly reason: string };

/** Does `schema` provide every required (name, space)? */
export function satisfies(schema: TypedSchema, required: readonly Requirement[]): SatisfyResult {
  for (const req of required) {
    const a = lookup(schema, req.name);
    if (a === undefined) return { ok: false, reason: `missing column "${req.name}"` };
    if (!fits(a.type, req.space)) {
      return {
        ok: false,
        reason: `column "${req.name}" is ${showSpace(a.type)}, required ${showSpace(req.space)}`,
      };
    }
  }
  return { ok: true };
}

// ─────────────────────────────────────────────────────────────────────────────
// Space census — the structural questions that replace binding-mode's name list
// and CellRole reads. "Does this relation carry a relative spatial column?" =
// "is it a produce-layout output that still needs the affine?"
export function spacesPresent(schema: TypedSchema): ReadonlySet<Space["space"]> {
  return new Set(schema.map((a) => a.type.space));
}

export function hasSpace(schema: TypedSchema, tag: Space["space"]): boolean {
  return schema.some((a) => a.type.space === tag);
}

/** A produce-layout's output is "derived" iff it adds relative spatial columns —
 *  the structural replacement for SYSTEM_LAYOUTS membership (reorg §8.5). */
export function isDerived(schema: TypedSchema): boolean {
  return hasSpace(schema, "relative");
}

/** All non-terminal, non-data columns still awaiting placement (relative geoms). */
export function unplacedSpatial(schema: TypedSchema): readonly Attr[] {
  return schema.filter((a) => a.type.space === "relative");
}

// ─────────────────────────────────────────────────────────────────────────────
// Debug: the whole schema as an aligned attr dump (for plan tables / self-vis).
export function showSchema(schema: TypedSchema): string {
  return schema.map((a) => `${a.name}:${a.carrier}@${showSpace(a.type)}`).join(", ");
}

/** All-data schemas are the common uninteresting case; flag when a schema is pure
 *  data (nothing to type-direct) so callers can skip space-aware paths cheaply. */
export function allData(schema: TypedSchema): boolean {
  return schema.every((a) => isData(a.type));
}
