// Layout/scale/arrange/constraint instance types (WUIR_IMPL §2.2). The operator's
// declarative surface (inputs/output/outSpaces/domain/holes) lives on Operator
// (dataflow/exec.ts) — LayoutDescriptor/DomainDescriptor are gone (reorg §P0).
// Algorithms (`impl`, domain/V, solving) are C4/C6 slots.
import type { LayoutId, NodeId } from "../types/ids.js";
import type { Operator } from "../operator/operator.js"; // type-only: erases at runtime, ir stays a leaf
import type { Path, ResolvedPath } from "./refs.js";
import type { CellKind, CellRef, CellStore } from "./cell.js";
import type { Expr } from "./expr.js";
import type { TableRef } from "./plot.js";

/** Which under-defined cells a layout instance owns — the component declares its own holes
 *  (WUSCHED §cell ownership); the builder allocates them. NORMALIZED: a producer owns no pixel range
 *  — it emits relative [0,1] and the frame affine reads the host node's extent — so `domain` (the
 *  trained fit) is the only hole a component declares. */
export interface LayoutHoles {
  domain?: CellKind; // a resolved-domain cell of this kind (omit: no domain hole)
}

/** Axis config on a frame scale (WUAXIS §1, VL style: `linear("mass", { axis: {…} })`), or `false`
 *  to suppress the auto axis. Parity set — `format`/`label`/`grid`/`base` are addable per §API. */
export interface AxisOptions {
  ticks?: number | { count?: number; algorithm?: string }; // count, or count + a registered tick algo
  side?: "top" | "right" | "bottom" | "left"; // PIN placement (else assignSides prefers the primary side)
  tickLength?: number; // default 5 — tick mark length; label nudges and the gutter pad derive from it
  fontSize?: number; // default 10 — label font size; measurement and label nudges derive from it
  /** Axis TITLE (WUAXIS §title): a centered text mark naming the axis's quantity. `true` derives the
   *  text (first member's column, or the authored expression); a string is the text; the object form
   *  adds the text mark's normal styling options. Absent = no title. */
  title?: boolean | string | AxisTitleOptions;
  /** Side-stack ORDER override (Step 4): where this band sits among co-located adornments on its side.
   *  `inside` → hug the plot (innermost); `outside` → outermost. Default: the role's SIDE_ORDER rank. */
  place?: "inside" | "outside";
  /** Gap (px) before this band along the stack normal (Step 4). Default 0. */
  gap?: number;
  /** Inner padding (§12.4): space inside the band, between its edges and the ticks/labels — inflates
   *  the reserved thickness and insets the cross-axis span. Number or absolute per-side. Default 0. */
  pad?: number | { top?: number; right?: number; bottom?: number; left?: number };
}

/** Title styling — the text mark's own channels (fontSize, fill, opacity, dx/dy nudge, rotate,
 *  anchor, baseline) plus the text itself. Unset text derives from the scale's first member. */
export interface AxisTitleOptions {
  text?: string;
  fontSize?: number; // default 11
  fill?: string; // default #333333 (alias: color)
  color?: string;
  opacity?: number;
  dx?: number; // EXTRA pixel nudge on top of the side's computed offset
  dy?: number;
  rotate?: number; // override the side default (left: -90, right: 90, top/bottom: 0)
  anchor?: "start" | "middle" | "end"; // default "middle"
  baseline?: string;
}

export interface LayoutInstance {
  id: LayoutId;
  descriptor: string; // registry KEY → Registries.operators.get()
  /** Resolve-once (simplification §2.3): attached by resolveSpec(spec, registries) AFTER all
   *  spec-mutating lowerings. Downstream (compiler, executor) reads THIS — never the registry. */
  resolved?: { operator: Operator };
  inputs: Record<string, { relation: TableRef; project?: Record<string, string | Expr>; on?: Path; resolvedOn?: ResolvedPath }>;
  params: Record<string, Expr>;
  options?: Record<string, unknown>; // static binding context (values, not Exprs) → flows to OpBinding.options (e.g. apply-only's `wrapped`)
  // HOLES the instance owns — present iff its component declares them (holes()).
  domain?: CellRef; // trained-domain hole (any producer whose algo trains)
  /** Expansion hole (design/2026-07-21-scale-expansion.html §4): the scale's containment slack as
   *  two RELATIVE-denominated demand cells — the frame affine lerps this scale's outputs into
   *  [lo + span·e₀, hi − span·e₁], the overhang op writes them from measured mark-box bleed, and
   *  the scheduler fixpoints the cycle. Authored `expand` options alloc these SEALED (constants,
   *  no loop). Present only on positional scales serving extent-bearing author marks. */
  expand?: { lo: CellRef; hi: CellRef };
  /** Axis PRESENCE as a cell (WULAYOUT_IMPL §C6): 1 = drawn, 0 = merged away. Seeded 1 (drawn); the
   *  axis-merge decision op recomputes it from solved sibling alignment. The axis's V/unit producers
   *  READ it (0 ⇒ empty relations ⇒ no marks AND zero demand) — suppression flows through ordinary
   *  dataflow, nothing is unwired. Set by createAxis on ticked, placed axes only. */
  indicator?: CellRef;
  // The "SCALE" role — a frame-scoped, ticked producer sets these; a plain layout leaves them unset.
  /** The domain TREATMENT the author chose (or the derived component default). EXECUTED (§5a):
   *  an ACTIVE treatment (explicit/zero) transforms the domain cell at its two write sites —
   *  the unshared train (ops/domain.ts, via the apply-only emission so marks and ticks read one
   *  treated envelope) and the shared union (gather-scatter, post-union, first declarer wins).
   *  data/nice are identity here — nice lives in the tick algorithm. */
  treatment?: DomainTreatment;
  ticks?: { table?: TableRef; algorithm: string }; // V synthesis = C4
  /** Authored sharing PIN (§C6 precedence): `false` = never share (own domain, whatever identity
   *  says); `true` = share (documentation today — derived sharing already applies in scope; it pins
   *  the choice once a solver could decide otherwise). Unset = the solver/heuristic decides. */
  shared?: boolean;
  /** Authored EQUIVALENCE class (§C6): instances bound from ONE ScaleSpec object share this tag —
   *  the explicit "these are the same quantity" surface (works across tables and across sibling
   *  nodes, where name identity deliberately does NOT reach). Future semantic-equivalence
   *  declarations feed the same field. */
  equiv?: string;
  /** The frame CHANNEL this scale serves ("x" / "x2" / "y" …) — frame-scale identity is
   *  per-channel: layers sharing `x` share an instance; a mark's coupled x2 is its OWN instance
   *  whose domain UNIONS with x's via the coupling equivalence (WULAYOUT_IMPL §C6). */
  channel?: string;
  dim?: "x" | "y"; // the frame dimension this scale drives (identity-keyed sharing; side no longer implies it)
  side?: "top" | "right" | "bottom" | "left"; // author PIN at bind; else FILLED by assignSides at lowering (WUAXIS §5)
  axis?: AxisOptions | false; // recorded axis config (first-wins across shared bindings); false = suppress
  members?: { plot: string; source: TableRef; column: string }[]; // plots a frame scale serves; union domain = C4
  // A datum binding `S(v)` needs NO field here: it is a 1-row `values`-backed source (builder.mark)
  // bound as an ordinary column member, so it trains + applies through the standard member path (§A2).
}

/** How the rendered domain is chosen from the data — a modeling choice, not a fact
 * (WUDESIGN §The reflection principle); C4 resolves `domain` from it and checks satisfaction. */
export type DomainTreatment = "data" | "nice" | "zero" | "unbounded" | { explicit: [number, number] };

/** "Scale" is a ROLE, not a subtype: a single-output, frame-scoped, ticked LayoutInstance. Kept
 *  as an alias so call sites read intent; `isScale` narrows to it (via `treatment` presence). */
export type Scale = LayoutInstance;

/** A layout/scale's DECLARED input binding for a plot: each input role → its bound source
 *  column(s). A frame scale records them per-plot in `members`; others use the input's `project`.
 *  The compiler reads THIS (the declared input), never the storage — WUMODULES §public interface. */
export function inputBinding(layout: LayoutInstance, plotId: string): Record<string, string[]> {
  const sc = layout as Scale;
  if (sc.members) return { marks: sc.members.filter((m) => m.plot === plotId).map((m) => m.column) };
  const out: Record<string, string[]> = {};
  for (const [role, input] of Object.entries(layout.inputs)) {
    out[role] = Object.values(input.project ?? {}).filter((v): v is string => typeof v === "string");
  }
  return out;
}

export interface ArrangeInstance {
  id: LayoutId;
  scope: NodeId;
  constraints: Constraint[];
  objective: string; // registry key
  solver: string; // registry key
  /** Resolve-once: the solver FUNCTION, attached by resolveSpec — the arrange op stops looking
   *  the name up at run time. */
  resolvedSolver?: ArrangeSolver;
  /** The node's margin DEFAULTS (recorded by arrangeNode) — the strong inset equalities' constants.
   *  The measure op floors each side's demand by them, so `Node.demand` is the node's TRUE minimum
   *  footprint (§C6 demand-weighted sizing): actual insets are max(default, measured gutter). */
  margin?: { left: number; right: number; top: number; bottom: number };
}

/** A constraint PARAMETER — a literal, or a CELL read at solve time (WULAYOUT_IMPL §C6). A cell
 *  parameter must be a solver INPUT (produced upstream, or seeded if cyclic) — never one of the
 *  referencing solver's own unknowns (`unknown × unknown` is nonlinear). Cell coefficients make each
 *  solve linear PER SWEEP even when the global problem is nonlinear (demand-weighted sizing); the
 *  fixpoint closes the loop. Cell constants are convenience — subsumed by a `±1` term. */
export type Param = number | CellRef;

/** Cassowary-form linear relation over cells (WUNOUNS G3) — extent edges, demand cells alike:
 *  `sum(coef·edge) op const`, where coef/const may be cells (read-only inputs). */
export interface Constraint {
  terms: { coef: Param; edge: CellRef }[];
  op: "=" | "<=" | ">=";
  constant: Param;
  strength: "required" | "strong" | "medium" | "weak";
  /** Diagnostic provenance ("min-w:n0/panels/c0", "gutter:left") — the verify op reports violations
   *  by label; solvers ignore it. */
  label?: string;
}

/** A component-registered measurement need (WULAYOUT_IMPL §C6 demand loop): the node's `measure` op
 *  materializes `source`'s output relation, asks the MeasurementProvider for the max label extent
 *  (width for a y-axis, height for x), and writes `demand = pad + measured`. Registered on
 *  `Node.measures` by lowering (an axis), like `Node.constraints`. */
export interface MeasureRequest {
  source: LayoutId; // the producer whose output relation holds the labels (an axis's V)
  demand: CellRef; // the demand cell to fill (seeded with an estimate — the future cycle's bootstrap)
  dim: "x" | "y"; // measure height (x-axis labels stack below) or width (y-axis labels sit beside)
  side: "top" | "right" | "bottom" | "left"; // which gutter the demand occupies (per-side floors, §C6)
  provider: string; // MeasurementProvider registry key ("estimate" = the naive tier; a DOM measurer swaps in by name)
  fontSize: number;
  pad: number; // the non-label part of the footprint (tick length + label nudge)
}

/** A registered arrange solver (C6, WULAYOUT_IMPL §C6): reads the constraints + already-known cells,
 *  writes the rest. `owned` = the calling op's WRITE cells: the solver RECOMPUTES them from current
 *  inputs each call (their stale values are ignored) — the Operator contract, and what lets the SCC
 *  fixpoint iterate (a fill-holes-only solver would freeze on its first sweep). Omitted ⇒ fill holes.
 *  `propagation` (built-in) resolves required equalities; Cassowary (later) adds strong/weak +
 *  inequalities. Registered in `Registries.arrangeSolvers`. */
export type ArrangeSolver = (constraints: readonly Constraint[], cells: CellStore, owned?: readonly CellRef[]) => void;

export interface Objective {
  name: string;
}
