import type { LayoutId, NodeId, PlotId } from "../../types/ids.js";
import { walk, type Expr } from "../../ir/expr.js";
import { inputBinding, type LayoutInstance } from "../../ir/layout.js";
import type { JoinCondition, JoinOp, ResolvedPath, ViaReduceFn } from "../../ir/refs.js";
import type { Spec } from "../../ir/spec.js";
import { isProducerSource, isRelationSource, sourceKey, type Plot } from "../../ir/plot.js";
import { staticOutSpace, type Operator } from "../../operator/operator.js";
