/** The box-fork columns a via pick may borrow (box-model §5 rev.) — their presence among a via
 *  step's attrs routes the join to the referent's BOXED relation instead of its bare marks. */
const BOX_ATTRS: ReadonlySet<string> = new Set(["dvl_x0", "dvl_x1", "dvl_y0", "dvl_y1"]);

/** Chain the INTERMEDIATE hops of a resolved path onto `marksIn` (CELL_KEY_VIA Level 1, shared
 *  by the nest key and multi-hop vias): each hop reads its raw relation (a table-leaf relop) and
 *  borrows exactly the columns the NEXT hop's left side joins on — the hopped key survives the
 *  chain. The FINAL hop is the caller's (cell-key lands on the host base; a via lands on the
 *  referent's marks). `eqOnly` gates nest-key hops; a via admits any op — a non-eq intermediate
 *  can fan the rows out, which is exactly what a declared resolution (§3b) reduces at the end. */
function emitIntermediateHops(resolved: ResolvedPath, idPrefix: string, marksIn: CellRef, specs: OpSpec[], store: CellStore, eqOnly?: string): { marks: CellRef; finalOn: (readonly [string, string])[] } {
  // HOP-BORROWED key columns get FRAMEWORK-MINTED names derived from the (already unique)
  // emission-site id — the same principle as fragment scoping (dispatch.ts scopeFragments,
  // identity ladder Level 3): they are chain-internal plumbing, never user-facing, so
  // cross-chain shadowing (σ's agreement paths sharing intermediates with path 1) is
  // UNWRITABLE by construction rather than avoided by a caller-chosen alias.
  // Hop 0's LEFT side is the source table's own columns (never renamed); later hops' left
  // side reads the previous hop's minted borrow.
  const mint = (c: string): string => `dvl_h_${sanitizeOp(idPrefix)}_${c}`;
  let marks = marksIn;
  for (let h = 0; h < resolved.length - 1; h++) {
    const ps = pairs(resolved[h], eqOnly !== undefined ? { eqOnly } : undefined);
    const rel = [...new Set(ps.map((p) => p.rightRel).filter((r): r is string => r !== null))];
    if (rel.length !== 1) throw new Error(`compileNode: hop ${h} of "${idPrefix}" does not name one intermediate relation — resolveSpec must qualify multi-hop paths`);
    const tCell = store.alloc("marks", undefined, "relation");
    specs.push({ id: `${idPrefix}:hop${h}:table`, reads: [], writes: [tCell], payload: { kind: "relop", key: `${idPrefix}:hop${h}:table`, add: {}, outTypes: {}, source: { rows: [], table: rel[0] } } });
    const nextLeft = pairs(resolved[h + 1]).map((p) => p.left);
    const keyed = store.alloc("marks", undefined, "relation");
    specs.push({
      id: `${idPrefix}:hop${h}`,
      reads: [marks, tCell],
      writes: [keyed],
      payload: {
        kind: "relop",
        key: `${idPrefix}:hop${h}`,
        add: Object.fromEntries(nextLeft.map((c) => [mint(c), fcol(c)])),
        outTypes: Object.fromEntries(nextLeft.map((c) => [mint(c), "unknown" as const])),
        outSpaces: Object.fromEntries(nextLeft.map((c) => [mint(c), dataSpace])),
        join: { input: "hop", on: ps.map((p) => [h === 0 ? p.left : mint(p.left), p.right] as const) },
        tag: "path-hop",
      },
    });
    marks = keyed;
  }
  // the FINAL hop's join pairs: left side is minted when the path walked intermediates
  // (its left columns were borrowed by the last hop), the source's own column otherwise.
  const last = pairs(resolved[resolved.length - 1], eqOnly !== undefined ? { eqOnly } : undefined);
  const finalOn = last.map((p) => [resolved.length > 1 ? mint(p.left) : p.left, p.right] as const);
  return { marks, finalOn };
}

/** Per aux role, the RESOLVED join pairs (aux column ⇢ marks column) an impl reads off its
 *  binding (§8 Stage 1b): the instance's resolved `on` override wins; the operator's declared
 *  `refs` (dotted "role.col" strings) are the default. */
function auxRefs(desc: Operator, inst: LayoutInstance): Record<string, { from: string; to: string }[]> | undefined {
  const out: Record<string, { from: string; to: string }[]> = {};
  for (const [role, input] of Object.entries(inst.inputs ?? {})) {
    if (role === "marks" || input.resolvedOn === undefined || input.resolvedOn.length === 0) continue;
    out[role] = pairs(input.resolvedOn[input.resolvedOn.length - 1]).map((p) => ({ from: p.left, to: p.right }));
  }
  const defaults: Record<string, { from: string; to: string }[]> = {};
  for (const r of desc.refs ?? []) {
    const dot = r.from.indexOf(".");
    if (dot < 0) continue;
    (defaults[r.from.slice(0, dot)] ??= []).push({ from: r.from.slice(dot + 1), to: r.to.slice(r.to.indexOf(".") + 1) });
  }
  for (const [role, ps] of Object.entries(defaults)) if (out[role] === undefined) out[role] = ps; // an override wins wholesale
  return Object.keys(out).length > 0 ? out : undefined;
}

/** One plot's pipeline: base → channel steps (one per layout-output instance + literal/local-column)
 *  → per-axis affine → the final placed-marks cell. Appends its ops to `specs`. */
export function compilePlot(spec: Spec, nodeId: NodeId, plotId: PlotId, specs: OpSpec[], producers: Map<LayoutId, CellRef>, contributions: Map<LayoutId, CellRef[]>, opts: RenderOpts, template: TemplateCtx | undefined, built: readonly PlotBuild[]): PlotBuild {
  const plot = spec.plots.get(plotId);
  if (plot === undefined) throw new Error(`compileNode: no plot "${plotId}"`);
  const node = spec.nodes.get(nodeId)!;
  const cc = node.extent.content;
  const store: CellStore = spec.cells;

  // The base relation: marktable / an already-produced cell / a producer's output (emit-once).
  const base: CellRef = resolveBase(spec, plot, producers, specs, store);
  let marks: CellRef = base;

  // Cell key: a TEMPLATE plot's rows partition across the host's marks — join child-on-host on
  // the nest's RESOLVED path (this plot's own `on` overrides the nest's default) and carry the
  // host row as `dvl_cell`. A multi-hop path emits ONE JOIN RELOP PER HOP (CELL_KEY_VIA Level 1):
  // intermediates read the raw table and borrow the columns the next hop joins on; the last hop
  // lands on the host base. A via pick named `cell` short-circuits the whole chain (Level 2): the
  // referent already computed its dvl_cell, so the key is a single borrow join. Everything
  // downstream is then a KEYED variant of the ordinary pipeline.
  let keyedCell: CellRef | undefined;
  if (template !== undefined) {
    // a PRODUCER base (an axis's V / unit) has no data columns to join: it BROADCASTS
    // across the cells (empty predicates ⇒ CROSS JOIN with the host marks) — every panel gets every
    // tick, placed per cell by the keyed affine below. A DATA base joins on the nest predicates.
    // EXCEPT a producer that is ALREADY keyed (a per-cell scale's V, options.by): its rows carry
    // dvl_cell from generation — broadcasting it again would cross every panel's ticks into every
    // other panel. It skips the cell-key entirely.
    const alreadyKeyed = isProducerSource(plot.source) && spec.layouts.get(plot.source.producer)?.options?.by !== undefined;
    const broadcast = isProducerSource(plot.source) && !alreadyKeyed;
    const borrowExpr = plot.channels["cell"];
    if (alreadyKeyed) {
      // no cell-key: the pipeline proceeds on the keyed producer output as-is.
    } else if (!broadcast && borrowExpr !== undefined && borrowExpr.kind === "table-ref" && borrowExpr.attrName === "dvl_cell") {
      // LEVEL 2 — the cell BORROW: `np.via(fkPreds).pick({ cell: 'dvl_cell' })`. The referent is
      // co-nested and already keyed, so this plot's frame assignment is one FK join reading the
      // referent's dvl_cell — no denormalized key column, no host re-join. Resolved EARLY (the FK
      // join stands in for the cell-key relop, before layout), while the same via's position picks
      // stay post-affine — one declared FK, read twice.
      const ref = built.find((pb) => pb.pid === borrowExpr.plotId);
      if (ref?.keyed === undefined) throw new Error(`compileNode: cell borrow on "${plotId}" — referent "${borrowExpr.plotId}" is not co-nested under this template (no cell key to borrow)`);
      const resolvedVia = resolvedOf({ on: borrowExpr.viaSpec, resolved: borrowExpr.resolvedVia });
      if (resolvedVia === null || resolvedVia.length === 0) throw new Error(`compileNode: cell borrow on "${plotId}" has no join predicates`);
      // a MULTI-HOP borrow chains its intermediates like any nest key (§8 Stage 6) — eq-gated,
      // because the whole path feeds a partition key. resolveSpec already required the path to
      // be provably single-match end to end.
      const borrowWalk = emitIntermediateHops(resolvedVia, `${plotId}:cell-borrow`, marks, specs, store, `cell borrow "${plotId}"`);
      marks = borrowWalk.marks;
      const ps = borrowWalk.finalOn;
      if (ps.length === 0) throw new Error(`compileNode: cell borrow on "${plotId}" has no join predicates`);
      const keyed = store.alloc("marks", undefined, "relation");
      specs.push({
        id: `${plotId}:cell-borrow`,
        reads: [marks, ref.keyed],
        writes: [keyed],
        payload: { kind: "relop", key: `${plotId}:cell-borrow`, add: { dvl_cell: fcol("dvl_cell") }, outTypes: { dvl_cell: "int" }, outSpaces: { dvl_cell: dataSpace }, join: { input: "ref", on: ps }, tag: "cell-key" },
      });
      marks = keyed;
    } else if (!broadcast && plot.sigma !== undefined) {
      // σ (§7e S2/S3): the layer's partition is DERIVED — one FK route per path. 'panel'
      // conjoins (path 1 assigns dvl_cell; every further path must land on the SAME host mark);
      // 'union' admits any route (one row per touching panel, deduped by identity).
      const eqSite = `sigma "${plotId}"`;
      const { paths, mode } = plot.sigma;
      if (mode === "panel") {
        const walk0 = emitIntermediateHops(paths[0], `${plotId}:cell-key`, marks, specs, store, eqSite);
        marks = walk0.marks;
        const ps0 = walk0.finalOn;
        const keyed0 = store.alloc("marks", undefined, "relation");
        specs.push({
          id: `${plotId}:cell-key`,
          reads: [marks, template.hostBase],
          writes: [keyed0],
          payload: { kind: "relop", key: `${plotId}:cell-key`, add: { dvl_cell: fcol("dvl_mark") }, outTypes: { dvl_cell: "int" }, outSpaces: { dvl_cell: dataSpace }, join: { input: "host", on: ps0 }, tag: "cell-key" },
        });
        marks = keyed0;
        for (let k = 1; k < paths.length; k++) {
          const walkK = emitIntermediateHops(paths[k], `${plotId}:sigma${k}`, marks, specs, store, eqSite);
          marks = walkK.marks;
          const psk = walkK.finalOn;
          // the diagnostics TWIN (§7e S4): the rows this agreement will drop, as data — the
          // LEFT-JOIN null-matches over the same pairs, BEFORE the inner join filters them.
          const dropped = store.alloc("sink", undefined, "relation");
          plot.sigmaDropped = dropped;
          specs.push({
            id: `${plotId}:sigma${k}:verify`,
            reads: [marks, template.hostBase],
            writes: [dropped],
            payload: { kind: "sigma-verify", key: `${plotId}:sigma${k}:verify`, on: [...psk, ["dvl_cell", "dvl_mark"] as const] },
          });
          const agreed = store.alloc("marks", undefined, "relation");
          specs.push({
            id: `${plotId}:sigma${k}:agree`,
            reads: [marks, template.hostBase],
            writes: [agreed],
            payload: { kind: "relop", key: `${plotId}:sigma${k}:agree`, add: {}, outTypes: {}, outSpaces: {}, join: { input: "host", on: [...psk, ["dvl_cell", "dvl_mark"] as const] }, tag: "sigma-agree" },
          });
          marks = agreed;
        }
      } else {
        // union: K INDEPENDENT chains from the SAME pre-σ base — never threaded through each
        // other; each branch is "the rows as seen from path k", then one row per (row, panel).
        const base = marks;
        const outs: CellRef[] = paths.map((path, k) => {
          const walked = emitIntermediateHops(path, `${plotId}:sigmaU${k}`, base, specs, store, eqSite);
          const ps = walked.finalOn;
          const out = store.alloc("marks", undefined, "relation");
          specs.push({
            id: `${plotId}:sigmaU${k}`,
            reads: [walked.marks, template.hostBase],
            writes: [out],
            payload: { kind: "relop", key: `${plotId}:sigmaU${k}`, add: { dvl_cell: fcol("dvl_mark") }, outTypes: { dvl_cell: "int" }, outSpaces: { dvl_cell: dataSpace }, join: { input: "host", on: ps }, tag: "cell-key" },
          });
          return out;
        });
        const keyed = store.alloc("marks", undefined, "relation");
        specs.push({ id: `${plotId}:sigma-union`, reads: outs, writes: [keyed], payload: { kind: "union-all", key: `${plotId}:sigma-union`, dedupBy: ["dvl_mark", "dvl_cell"] } });
        marks = keyed;
      }
    } else {
      const resolved = broadcast ? [[]] : resolvedOf(plot.nest) ?? (template.resolved.length > 0 ? template.resolved : null);
      if (resolved === null || (!broadcast && resolved.every((h) => h.length === 0))) throw new Error(`compileNode: template plot "${plotId}" has no nest predicates`);
      // cell-key IS a join relop (P4d) — one per hop. Empty predicates = the declared cross join
      // (a producer's V broadcast across every cell) — the join relop's empty-`on` broadcast
      // shape, not a special kind.
      const nestWalk = emitIntermediateHops(resolved, `${plotId}:cell-key`, marks, specs, store, `cell-key "${plotId}"`);
      marks = nestWalk.marks;
      const ps = nestWalk.finalOn;
      const keyed = store.alloc("marks", undefined, "relation");
      specs.push({
        id: `${plotId}:cell-key`,
        reads: [marks, template.hostBase],
        writes: [keyed],
        payload: { kind: "relop", key: `${plotId}:cell-key`, add: { dvl_cell: fcol("dvl_mark") }, outTypes: { dvl_cell: "int" }, outSpaces: { dvl_cell: dataSpace }, join: { input: "host", on: ps }, tag: "cell-key" },
      });
      marks = keyed;
    }
    keyedCell = marks;
  }

  // FRAME assignment on a TOP-LEVEL layer (§7e F2): owner semantics — borrow the referent's
  // dvl_cell over the resolved frame path, EARLY (before layout), so every cell-keyed consumer
  // downstream (per-cell fits, clip, counts) sees the layer's panel. The referent may live in a
  // LATER-compiled node: the placeholder read is patched by compileSpec after the full walk.
  if (template === undefined && plot.frame?.resolved !== undefined) {
    const fr = plot.frame;
    const site = `frame "${plotId}"`;
    const frameWalk = emitIntermediateHops(fr.resolved!, `${plotId}:frame`, marks, specs, store, site);
    marks = frameWalk.marks;
    const ps = frameWalk.finalOn;
    const refKeyed: CellRef = built.find((pb) => pb.pid === fr.plot)?.keyed ?? `$plot-keyed:${fr.plot}`;
    const keyed = store.alloc("marks", undefined, "relation");
    specs.push({
      id: `${plotId}:frame-borrow`,
      reads: [marks, refKeyed],
      writes: [keyed],
      payload: { kind: "relop", key: `${plotId}:frame-borrow`, add: { dvl_cell: fcol("dvl_cell") }, outTypes: { dvl_cell: "int" }, outSpaces: { dvl_cell: dataSpace }, join: { input: "ref", on: ps }, tag: "cell-key" },
    });
    marks = keyed;
    keyedCell = marks;
  }

  // Group channels into dataflow STEPS: one per layout-output INSTANCE (fed by ≥1 channels — a
  // scale by 1, a multi-output layout like eqx by x,w via pick), plus literal/local-column channels.
  // Grouping is what makes pick() general: ONE apply per instance produces ALL its declared outputs.
  type LayoutStep = { kind: "layout"; layoutId: LayoutId; chans: { ch: string; output: string }[] };
  type ExprStep = { kind: "expr"; ch: string; expr: Expr };
  type ChanResolve = { fn?: string; arg?: unknown; order?: string; desc?: boolean; js?: ViaReduceFn | string; jsResolved?: ViaReduceFn; sqlResolved?: (xCol: string, yCol: string) => string; requires?: readonly string[]; cols?: readonly string[] };
  type ViaStep = { kind: "via"; refPlot?: PlotId; refTable?: string; resolved: ResolvedPath; chans: { ch: string; attr: string; space: Expr["type"]["space"]; resolve?: ChanResolve }[] };
  const steps: (LayoutStep | ExprStep | ViaStep)[] = [];
  const seen = new Map<LayoutId, LayoutStep>();
  const seenVia = new Map<string, ViaStep>(); // (refPlot, predicates) → ONE join adding all its channels
  for (const [ch, expr] of Object.entries(plot.channels)) {
    if (expr.kind === "layout-output") {
      let s = seen.get(expr.layout);
      if (s === undefined) {
        s = { kind: "layout", layoutId: expr.layout, chans: [] };
        seen.set(expr.layout, s);
        steps.push(s);
      }
      s.chans.push({ ch, output: expr.output });
    } else if (expr.kind === "table-ref") {
      // the `cell` pick is the Level-2 frame borrow, consumed by the cell-key stage above —
      // it is not a channel value and never joins post-affine.
      if (ch === "cell" && expr.attrName === "dvl_cell") continue;
      // a cross-mark via reference: borrow a channel of another plot, joined on the resolved
      // path (multi-hop = chained intermediate joins, exactly the nest key's emission).
      // Group by (referent, path) — one join chain per distinct via() call.
      const resolvedVia = resolvedOf({ on: expr.viaSpec, resolved: expr.resolvedVia });
      if (resolvedVia === null || resolvedVia.length === 0 || resolvedVia.some((h) => h.length === 0)) throw new Error(`compileNode: via reference on "${plotId}:${ch}" needs join predicates`);
      const k = `${expr.plotId}|${JSON.stringify(resolvedVia)}`;
      let vs = seenVia.get(k);
      if (vs === undefined) {
        vs = { kind: "via", refPlot: expr.plotId as PlotId, resolved: resolvedVia, chans: [] };
        seenVia.set(k, vs);
        steps.push(vs);
      }
      const resolve = typeof expr.resolve === "string" ? { fn: expr.resolve } : (expr.resolve as ChanResolve | undefined);
      vs.chans.push({ ch, attr: expr.attrName, space: expr.type.space, resolve });
    } else if (expr.kind === "bound-ref") {
      // a cross-TABLE via (§8 Stage 2): the same join chain, but the referent is a raw table —
      // borrowed values are DATA (pre-affine), so this step joins in the pipeline, not post-affine.
      const resolvedVia = resolvedOf({ on: expr.viaSpec, resolved: expr.resolvedVia });
      if (resolvedVia === null || resolvedVia.length === 0 || resolvedVia.some((h) => h.length === 0)) throw new Error(`compileNode: table via on "${plotId}:${ch}" needs join predicates`);
      const k = `t:${expr.tableName}|${JSON.stringify(resolvedVia)}`;
      let vs = seenVia.get(k);
      if (vs === undefined) {
        vs = { kind: "via", refTable: expr.tableName, resolved: resolvedVia, chans: [] };
        seenVia.set(k, vs);
        steps.push(vs);
      }
      const resolve = typeof expr.resolve === "string" ? { fn: expr.resolve } : (expr.resolve as ChanResolve | undefined);
      vs.chans.push({ ch, attr: expr.columnName, space: expr.type.space, resolve });
    } else {
      steps.push({ kind: "expr", ch, expr });
    }
  }

  // ONE via-join emission for both referent kinds (§8 Stage 2): a plot referent joins its
  // PlotBuild's marks (post-affine — pixel borrows); a table referent joins a table-leaf relation
  // (pre-affine — data borrows). Identical chain: intermediates, then the final hop as a plain
  // join relop (single-match channels) and/or a via-agg (declared resolutions, §3b).
  const emitViaJoins = (step: ViaStep, refCell: CellRef, marksIn: CellRef, idBase: string): CellRef => {
    let cur = marksIn;
    const lastHop = pairs(step.resolved[step.resolved.length - 1]).map((pr) => [pr.left, pr.right, pr.op] as const);
    // borrowed columns: a relative referent space arrives PLACED (pixel, same geom — post-affine
    // plot referent); every other space passes through unchanged (a table referent's data stays data).
    const spaceOfChan = (c: (typeof step.chans)[number]): Space => (c.space.space === "relative" ? pixelSpace(c.space.geom) : c.space);
    const carrier = step.refTable !== undefined ? ("unknown" as const) : ("double" as const); // placed values are doubles; raw table columns are whatever they are
    // §3b: channels with a DECLARED reduction lower as via-agg (keyed reduce + keyed attach —
    // one value per mark by construction); the rest stay the single-match join relop (P4d).
    const plain = step.chans.filter((c) => c.resolve === undefined);
    const resolved = step.chans.filter((c) => c.resolve !== undefined);
    if (plain.length > 0) {
      // a MULTI-HOP plain via chains its intermediates IN PLACE — every hop is single-match
      // (the multiplicity judgment demanded a resolution otherwise), so cardinality holds.
      const viaWalk = emitIntermediateHops(step.resolved, `${idBase}:via`, cur, specs, store);
      const prev = viaWalk.marks;
      const next = store.alloc("marks", undefined, "relation");
      // via IS a join relop (P4d): borrow the referent's columns onto these marks over the
      // declared ON pairs. The borrowed columns are fcol reads of the joined alias.
      specs.push({
        id: `${idBase}:via:${plain.map((c) => c.ch).join(",")}`,
        reads: [prev, refCell],
        writes: [next],
        payload: {
          kind: "relop",
          key: `${idBase}:via:${plain[0].ch}`,
          add: Object.fromEntries(plain.map((c) => [c.ch, fcol(c.attr)])),
          outTypes: Object.fromEntries(plain.map((c) => [c.ch, carrier])),
          outSpaces: Object.fromEntries(plain.map((c) => [c.ch, spaceOfChan(c)])),
          join: { input: "ref", on: viaWalk.finalOn },
          tag: `via:${plain[0].ch}`,
        },
      });
      cur = next;
    }
    if (resolved.length > 0) {
      // the reduce's JOIN BASE: the marks walked through the intermediate hops — a SIDE chain,
      // never the pipeline (a multi-match intermediate may fan out; only the reduced 1-row-per-
      // mark result rejoins the pipeline, so mark cardinality is preserved by construction).
      const aggWalk = step.resolved.length > 1 ? emitIntermediateHops(step.resolved, `${idBase}:via-agg`, cur, specs, store) : null;
      const joinBase = aggWalk !== null ? aggWalk.marks : cur;
      // the final hop's pairs with their PREDICATE OPS (a range join stays a range join); left
      // side minted when the walk borrowed it
      const stageOn = lastHop.map(([l, r, op], i) => [aggWalk !== null ? aggWalk.finalOn[i][0] : l, r, op] as const);
      // DECLARATIVE resolutions decompose into THREE ops the optimizer can see (§8 Stage 3):
      // stage (a join relop projecting the mark identity + per-match staged values — the only
      // scope where both m and f exist), the ONE reduce (by dvl_mark), and the keyed LEFT-JOIN
      // attach. The OPAQUE js form keeps the via-agg op: its (matches, mark) contract needs
      // two-sided rows a single-input reduce cannot carry.
      const declarative = resolved.filter((c) => c.resolve!.js === undefined);
      const opaque = resolved.filter((c) => c.resolve!.js !== undefined);
      if (declarative.length > 0) {
        const stageAdd: Record<string, ScalarExpr> = {};
        const stageSpaces: Record<string, Space> = {};
        const reduceAdds: Record<string, { fn?: string; col: string; order?: string; desc?: boolean }> = {};
        for (const c of declarative) {
          stageAdd[`dvl_v_${c.ch}`] = (c.resolve!.arg as ScalarExpr | undefined) ?? fcol(c.attr);
          stageSpaces[`dvl_v_${c.ch}`] = dataSpace; // staging values — internal, pre-reduce
          if (c.resolve!.order !== undefined) {
            stageAdd[`dvl_o_${c.ch}`] = fcol(c.resolve!.order);
            stageSpaces[`dvl_o_${c.ch}`] = dataSpace;
          }
          reduceAdds[c.ch] = { fn: c.resolve!.fn, col: `dvl_v_${c.ch}`, ...(c.resolve!.order !== undefined && { order: `dvl_o_${c.ch}`, desc: c.resolve!.desc }) };
        }
        const stageCell = store.alloc("marks", undefined, "relation");
        specs.push({
          id: `${idBase}:via-stage:${declarative.map((c) => c.ch).join(",")}`,
          reads: [joinBase, refCell],
          writes: [stageCell],
          payload: {
            kind: "relop",
            key: `${idBase}:via-stage:${declarative[0].ch}`,
            add: stageAdd,
            outTypes: Object.fromEntries(Object.keys(stageAdd).map((c) => [c, "unknown" as const])),
            outSpaces: stageSpaces,
            join: { input: "ref", on: stageOn },
            tag: `via-stage:${declarative[0].ch}`,
          },
        });
        const reducedCell = store.alloc("marks", undefined, "relation");
        specs.push({
          id: `${idBase}:via-reduce:${declarative.map((c) => c.ch).join(",")}`,
          reads: [stageCell],
          writes: [reducedCell],
          payload: { kind: "reduce", key: `${idBase}:via-reduce:${declarative[0].ch}`, by: "dvl_mark", adds: reduceAdds, outSpaces: Object.fromEntries(declarative.map((c) => [c.ch, spaceOfChan(c)])) },
        });
        const prev = cur;
        const next = store.alloc("marks", undefined, "relation");
        specs.push({
          id: `${idBase}:via-attach:${declarative.map((c) => c.ch).join(",")}`,
          reads: [prev, reducedCell],
          writes: [next],
          payload: {
            kind: "relop",
            key: `${idBase}:via-attach:${declarative[0].ch}`,
            add: Object.fromEntries(declarative.map((c) => [c.ch, fcol(c.ch)])),
            outTypes: Object.fromEntries(declarative.map((c) => [c.ch, "double" as const])),
            outSpaces: Object.fromEntries(declarative.map((c) => [c.ch, spaceOfChan(c)])),
            join: { input: "fit", on: [["dvl_mark", "dvl_mark"]], kind: "LEFT JOIN" }, // no match ⇒ NULL, never a dropped mark
            tag: `via-attach:${declarative[0].ch}`,
          },
        });
        cur = next;
      }
      if (opaque.length > 0) {
        const prev = cur;
        const next = store.alloc("marks", undefined, "relation");
        specs.push({
          id: `${idBase}:via-agg:${opaque.map((c) => c.ch).join(",")}`,
          reads: [prev, joinBase, refCell],
          writes: [next],
          payload: {
            kind: "via-agg",
            key: `${idBase}:via-agg:${opaque[0].ch}`,
            on: stageOn,
            adds: Object.fromEntries(opaque.map((c) => [c.ch, { attr: c.attr, ...c.resolve! }])),
            outSpaces: Object.fromEntries(opaque.map((c) => [c.ch, spaceOfChan(c)])),
          },
        });
        cur = next;
      }
    }
    return cur;
  };

  // relative coord/len columns to place, grouped by axis; the frame affine is one pass per axis below.
  // Each column carries its producing scale's EXPANSION cells (if any) — the affine lerps that
  // column into the scale's slack-compressed box (scale-expansion §4: t′ = e₀ + t·(1−e₀−e₁)).
  const relByAxis = new Map<"x" | "y", { coords: PlacedCol[]; lens: PlacedCol[] }>();
  const rel = (axis: "x" | "y"): { coords: PlacedCol[]; lens: PlacedCol[] } => {
    let g = relByAxis.get(axis);
    if (g === undefined) relByAxis.set(axis, (g = { coords: [], lens: [] }));
    return g;
  };
  // The base scale behind a channel expr: a layout-output's instance, unwrapping apply-only
  // (an axis tick binds apply-only(x) — its positions MUST move with x's marks, so it inherits
  // the wrapped scale's expansion cells; the ONE shared unwrap, LOUD on a dangling reference).
  // Literals/vias have no producer ⇒ no expansion ⇒ they lerp the frame box — which is exactly
  // why axis furniture stays anchored (§4b).
  const expOf = (expr: Expr | undefined): { lo: CellRef; hi: CellRef } | undefined =>
    expr === undefined || expr.kind !== "layout-output" ? undefined : baseInstanceOf(spec, expr.layout)?.expand;

  // BASE PROJECTIONS: data-space columns a scale-over-expression (`x(col("a")+col("b"))`) needs on the
  // base, so both the scale's TRAIN (reads the base) and its APPLY see the derived quantity. Emitted
  // here — BEFORE pipelineBase is captured — as one derive over the base; the arithmetic lowers with the
  // ordinary scalar machinery (data leaves inline, no lift).
  if (plot.baseProjections !== undefined && Object.keys(plot.baseProjections).length > 0) {
    const prev = marks;
    marks = store.alloc("marks", undefined, "relation");
    const add: Record<string, ScalarExpr> = {};
    const outTypes: Record<string, string> = {};
    const outSpaces: Record<string, import("../../types/attr.js").Space> = {};
    for (const [col, e] of Object.entries(plot.baseProjections)) { add[col] = toScalar(e); outTypes[col] = "double"; outSpaces[col] = e.type.space; }
    specs.push({ id: `${plotId}:base-proj`, reads: [prev], writes: [marks], payload: { kind: "relop", key: `${plotId}:base-proj`, add, outTypes, outSpaces, tag: "base-proj" } });
  }

  const pipelineBase = marks; // what TRAINS read (source columns; dvl_cell after a cell-key) — never the augment chain
  const postAffineSteps: typeof steps = []; // deferred post-affine layout steps
  for (const step of steps) {
    if (step.kind === "layout") {
      const instCheck = spec.layouts.get(step.layoutId);
      const descCheck = instCheck && opOf(instCheck);
      if (descCheck?.requiresPixelInputs) { postAffineSteps.push(step); continue; }
    }
    const prev = marks;
    let next = store.alloc("marks", undefined, "relation");
    if (step.kind === "layout") {
      // Every producer is a LayoutInstance handled the SAME way — compileNode never branches on "is it
      // a scale". `descriptor` (which component) and `domain` (its trained-domain hole, if it owns one)
      // are generic instance fields, read identically for a positional scale and for eqx.
      const inst = spec.layouts.get(step.layoutId);
      if (inst === undefined) throw new Error(`compileNode: no layout instance "${step.layoutId}"`);
      const desc = opOf(inst); // the operator carries the (ex-descriptor) declarative fields
      const column = inputBinding(inst, plotId).marks?.[0];
      if (column === undefined) throw new Error(`compileNode: layout "${step.layoutId}" has no source column`);
      const algo = desc; // one object — plan and declarative surface alike

      // outputs ordered by the component's DECLARED outputs (outSpaces, else the added columns), each
      // mapped to the channel(s) that picked it — so eqx.pick('x','w') binds x,w in the algo's order.
      // MULTIPLE channels may pick ONE output (x AND x2 on the same positional scale — a rule/interval
      // sharing a domain): the apply writes the PRIMARY channel's column, and a copy (below) fans it to
      // the siblings; all are placed by the affine.
      const declared = desc.outSpaces !== undefined ? Object.keys(desc.outSpaces) : "add" in desc.output ? desc.output.add.map((a) => a.name) : [];
      const out2chs = new Map<string, string[]>();
      for (const c of step.chans) out2chs.set(c.output, [...(out2chs.get(c.output) ?? []), c.ch]);
      const outputs = declared.map((o) => out2chs.get(o)?.[0]).filter((c): c is string => c !== undefined);

      // NORMALIZED: the operator binding carries no pixel range — apply emits relative [0,1] and the
      // frame affine (below) owns the box. An instance's static `options` flow to the binding (generic;
      // apply-only carries its `wrapped` scale this way).
      // MULTI-INPUT layouts (stack: weight + group + order) — the primary marks column binds role
      // "value" (every apply's convention); further declared marks inputs bind under their own role
      // names, from the instance's project. OpBinding.inputs is already multi-input.
      const marksInputs = (desc.inputs.marks ?? []).map((c) => c.name);
      const proj = inst.inputs.marks?.project;
      const extraInputs: Record<string, string> = {};
      for (let mi = 1; mi < marksInputs.length; mi++) {
        const col = proj?.[marksInputs[mi]];
        if (typeof col === "string") extraInputs[marksInputs[mi]] = col;
      }
      // AUX relations (force's edges): a non-marks input role rides the binding under its role name
      // — RelInput's "aux relation" arm. A bare table NAME today; cell/producer-backed aux later.
      for (const [role, input] of Object.entries(inst.inputs)) {
        if (role === "marks" || typeof input.relation !== "string") continue;
        extraInputs[role] = input.relation;
      }
      const binding: OpBinding = { key: `${plotId}:${step.layoutId}`, inputs: { value: column, ...extraInputs }, outputs, options: inst.options, refs: auxRefs(desc, inst), outSpace: plot.channels[outputs[0]]?.type.space };

      const domainCell = inst.domain; // the trained-domain hole — present iff the component declared it

      // The component emits its OWN operator subgraph via `plan`; compileNode calls it and nothing else
      // (it sees only the base contract — no train/apply, no default-plan synthesis). It supplies only
      // the IO cells; whether to train is the component's own local decision (normalized frame).
      // a member of a SHARED scale trains into a fresh CONTRIBUTION hole; the framework's
      // gather-scatter op unions contributions into the effective domain the member's apply reads
      // — shared within a node (layers) or across nodes (sibling subplots).
      const holes: Record<string, CellRef> = domainCell !== undefined ? { domain: domainCell } : {};
      const contribs = contributions.get(step.layoutId);
      if (contribs !== undefined && domainCell !== undefined) {
        const contribution = store.alloc("domain", undefined, "relation");
        contribs.push(contribution);
        holes.contribution = contribution;
      }
      // Per-cell execution in a TEMPLATE: an authored `shared: false` partitions a scale's
      // train/apply by the cell key (one domain per host mark), and a `perCell` operator
      // (force, treemap — whole-set arrangements) partitions BY DEFAULT (one run per panel;
      // `shared: true` opts back into a single global run).
      const key = template !== undefined && inst.shared !== true && (inst.shared === false || desc.perCell === true) ? "dvl_cell" : undefined;
      const io: PlanIO = { id: `${plotId}:${step.layoutId}`, binding, marksIn: prev, trainIn: pipelineBase, marksOut: next, holes, key, treatment: inst.treatment, alloc: (role, kind) => store.alloc(role, undefined, kind) };
      specs.push(...stampAlgo(algo, algo.plan(io)));

      // fan a shared output out to its SIBLING channels: a copy `sib := primary` (both hold the same
      // relative value; the affine then places each into its own column).
      for (const o of declared) {
        const chs = out2chs.get(o);
        if (chs === undefined || chs.length < 2) continue;
        for (const sib of chs.slice(1)) {
          const src = next;
          next = store.alloc("marks", undefined, "relation");
          const copySpace = staticOutSpace(desc.outSpaces?.[o]) ?? plot.channels[chs[0]].type.space;
          specs.push({ id: `${plotId}:copy:${sib}`, reads: [src], writes: [next], payload: { kind: "relop", key: `${plotId}:${sib}`, add: { [sib]: mcol(chs[0]) }, outTypes: { [sib]: "unknown" }, outSpaces: { [sib]: copySpace }, tag: `col:${sib}` } });
        }
      }

    } else if (step.kind === "via") {
      if (step.refTable !== undefined) {
        // TABLE-referent via (§8 Stage 2): joins IN the pre-affine chain — the borrowed values
        // are data, free to be scaled/placed downstream. The referent is a table-leaf relation.
        const tCell = store.alloc("marks", undefined, "relation");
        specs.push({ id: `${plotId}:tvia:${step.chans[0].ch}:table`, reads: [], writes: [tCell], payload: { kind: "relop", key: `${plotId}:tvia:${step.chans[0].ch}:table`, add: {}, outTypes: {}, source: { rows: [], table: step.refTable } } });
        next = emitViaJoins(step, tCell, prev, `${plotId}:t`);
      } else {
        // Plot-referent via: defer to post-affine — reads the referent's final marks (pixel
        // space). The consumer's affine must NOT re-transform borrowed pixel channels.
        postAffineSteps.push(step);
        next = prev; // no cell consumed in the pre-affine chain for this step
      }
    } else if (step.expr.kind === "literal") {
      specs.push({ id: `${plotId}:lit:${step.ch}`, reads: [prev], writes: [next], payload: { kind: "relop", key: `${plotId}:${step.ch}`, add: { [step.ch]: lit(step.expr.value, step.expr.type.space) }, outTypes: { [step.ch]: litType(step.expr.value) }, outSpaces: { [step.ch]: step.expr.type.space }, tag: `lit:${step.ch}` } });
    } else if (step.expr.kind === "local-column") {
      specs.push({ id: `${plotId}:col:${step.ch}`, reads: [prev], writes: [next], payload: { kind: "relop", key: `${plotId}:${step.ch}`, add: { [step.ch]: mcol(step.expr.columnName) }, outTypes: { [step.ch]: "unknown" }, outSpaces: { [step.ch]: step.expr.type.space }, tag: `col:${step.ch}` } });
    } else if (step.expr.kind === "binary" || step.expr.kind === "call") {
      // §3.3 A3: a binary channel lowers as a relop add over the data-leaf subset.
      // A binary consuming a lifted column produced by a PLOT-referent via must emit post-affine:
      // plot-referent joins always defer (they read the referent's placed marks — plot.ts:543),
      // so the dvl_lift_* column does not exist in the pre-affine chain. The value's space is NOT
      // the discriminator (E14: a data-space reduce over a plot referent still joins post-affine)
      // — the minted channel's expr kind is: table-ref ⇒ plot referent ⇒ defer.
      let plotLift = false;
      walk(step.expr, (n) => { if (n.kind === "local-column" && n.columnName.startsWith("dvl_lift_") && plot.channels[n.columnName]?.kind === "table-ref") plotLift = true; });
      if (plotLift) { postAffineSteps.push(step); next = prev; }
      else specs.push({ id: `${plotId}:expr:${step.ch}`, reads: [prev], writes: [next], payload: { kind: "relop", key: `${plotId}:${step.ch}`, add: { [step.ch]: toScalar(step.expr) }, outTypes: { [step.ch]: "double" }, outSpaces: { [step.ch]: step.expr.type.space }, tag: `expr:${step.ch}` } });
    } else {
      throw new Error(`compileNode: channel "${step.ch}" (${step.expr.kind}) is unsupported`);
    }
    marks = next;
  }
  // PAIRS marks (connect — SEQUENCE_MARKS §4): each point borrows its SUCCESSOR's coords via a
  // LEAD window (1:1 augment; the partition tail's successor is NULL → a degenerate, invisible
  // segment, so N points draw N−1 segments with no filter). Runs PRE-affine on the relative
  // coords: x2 = LEAD(x) is the successor's relative t, and the frame affine places all four
  // endpoints exactly as it does for a link mark — the minted columns register below.
  if (plot.resolvedMark?.cardinality === "pairs") {
    const kinds = plot.resolvedMark.channels;
    const pBound = Object.keys(plot.channels);
    if (plot.channels["x"] === undefined || plot.channels["y"] === undefined) throw new Error(`compilePlot: connect "${plotId}" needs both x and y channels`);
    const pGroup = pBound.filter((ch) => kinds[ch] === "color" || kinds[ch] === "shape"); // series partition
    if (pGroup.length > 1) throw new Error(`compilePlot: connect "${plotId}" supports ONE series channel for now (got ${pGroup.join(", ")})`);
    const w = { partition: pGroup[0], order: plot.channels["order"] !== undefined ? "order" : "x" };
    const prev = marks;
    const next = store.alloc("marks", undefined, "relation");
    const sx = plot.channels["x"].type.space;
    const sy = plot.channels["y"].type.space;
    specs.push({
      id: `${plotId}:pairs`,
      reads: [prev],
      writes: [next],
      payload: {
        kind: "relop",
        key: `${plotId}:pairs`,
        add: { x1: mcol("x"), y1: mcol("y"), x2: lead("x", w), y2: lead("y", w) },
        outTypes: { x1: "double", y1: "double", x2: "double", y2: "double" },
        outSpaces: { x1: sx, y1: sy, x2: sx, y2: sy },
        tag: "pairs",
      },
    });
    marks = next;
    // the minted endpoints place through the frame affine like link's channels (x1/x2 on the x
    // axis, y1/y2 on y) — pixel-bound channels need no placement, matching the walk below.
    if (sx.space === "relative" && sx.geom.kind === "coord") rel(sx.geom.axis).coords.push({ name: "x1", exp: expOf(plot.channels["x"]) }, { name: "x2", exp: expOf(plot.channels["x"]) });
    if (sy.space === "relative" && sy.geom.kind === "coord") rel(sy.geom.axis).coords.push({ name: "y1", exp: expOf(plot.channels["y"]) }, { name: "y2", exp: expOf(plot.channels["y"]) });
  }

  // THE AFFINE IS AN INSERTED CROSSING (decision §12.1): the planner walks each channel's bound
  // expression and inserts the affine exactly where the expression's OWN space is `relative geom`
  // — the render sink consumes pixels, so a surviving relative column IS the space mismatch on
  // the channel→sink edge (the same shape as insert-crossings on the sql⇄js axis). This replaces
  // the per-branch accumulation: producers, literals, and fanned-out sibling copies all carry
  // their space on the expression (stamped from the producer's declaration, never the channel —
  // the demo-blank rule made structural), so ONE typed walk decides placement. A via/table-ref
  // channel is excluded: it borrows the referent's POST-affine (already-pixel) values.
  for (const [ch, expr] of Object.entries(plot.channels)) {
    if (expr.kind === "table-ref") continue; // borrowed placed columns (via) — never re-placed
    const sp = expr.type.space;
    if (sp.space !== "relative") continue; // pixel literal / style / data — no crossing to insert
    if (sp.geom.kind === "coord") rel(sp.geom.axis).coords.push({ name: ch, exp: expOf(expr) });
    else if (sp.geom.kind === "len") {
      if (sp.geom.axis === "xy") throw new Error(`compilePlot: channel "${ch}" is a relative len⟨xy⟩ — an isotropic relative length has no frame axis to place into (declare len⟨x⟩ or len⟨y⟩, or bind a pixel value)`);
      rel(sp.geom.axis).lens.push({ name: ch, exp: expOf(expr) });
    }
  }

  const relMarks = marks; // the RELATIVE placements — what host-extent reads (pre-affine)

  // The frame affine emission lives in layout/frame.ts — THE relative→pixel coercion's home
  // (§9). One inserted crossing per (plot, axis) over the collected mismatch columns.
  // Data inset (Plot's `inset`, canvas option): pull marks off the frame edge by shrinking the
  // relative→pixel range. Root-level only — a nested/template plot's box is the host cell.
  // Mark-extent containment does NOT live here — it is per-scale expansion on the columns above.
  const dataInset = nodeId === spec.root ? opts.inset : undefined;
  marks = emitFrameAffines({ plotId, relByAxis, template, insets: node.insets, cc, store, specs, marks, dataInset });

  // Post-affine steps: via (plot referent, pixel-space) + post-affine layouts. Vias and deferred
  // exprs run FIRST regardless of bag order — a refine layout (fitText, route) reads columns the
  // via joins mint, so the joins must precede every post-affine apply.
  const postAffineOrdered = [...postAffineSteps.filter((s) => s.kind !== "layout"), ...postAffineSteps.filter((s) => s.kind === "layout")];
  for (const step of postAffineOrdered) {
    if (step.kind === "expr") {
      // a pixel-lifted binary (deferred above): the via join(s) before it in postAffineSteps
      // have produced its dvl_lift_* columns on the placed marks.
      const next = store.alloc("marks", undefined, "relation");
      specs.push({ id: `${plotId}:expr:${step.ch}`, reads: [marks], writes: [next], payload: { kind: "relop", key: `${plotId}:${step.ch}`, add: { [step.ch]: toScalar(step.expr) }, outTypes: { [step.ch]: "double" }, outSpaces: { [step.ch]: step.expr.type.space }, tag: `expr:${step.ch}` } });
      marks = next;
      continue;
    }
    if (step.kind === "via") {
      // Plot-referent via: read the referent's post-affine marks (pixel space). The borrowed
      // channels are already placed — the consumer's affine has already run and does not touch them.
      // Cross-node via works because all pixel coordinates are in a single global SVG space.
      // If a future change introduces per-node viewBoxes, nested <svg> elements, or per-frame
      // coordinate transforms, cross-node via will need a coordinate reconciliation step here.
      const ref = built.find((pb) => pb.pid === step.refPlot);
      // Box borrows (box-model §5 rev.): a via step whose picks include the referent's box-edge
      // attrs (the route desugar's dvl_b<k>_* channels) reads the referent's BOXED relation — a
      // superset of its marks (same rows, four extra pixel columns). The desugar set needsBox on
      // the referent at bind time, so the fork exists whether the referent compiled before or
      // after this plot ($plot-boxed patches the late case).
      const wantsBox = step.refPlot !== undefined && step.chans.some((c) => BOX_ATTRS.has(c.attr));
      let refCell: CellRef;
      if (wantsBox) {
        if (ref !== undefined && ref.boxed === undefined) throw new Error(`compilePlot: via on "${plotId}" borrows box edges of "${step.refPlot}" but its box fork was never emitted — desugarRouteInputs must set needsBox at bind (compiler bug)`);
        refCell = ref !== undefined ? ref.boxed! : `$plot-boxed:${step.refPlot}`;
      } else {
        refCell = ref !== undefined ? ref.marks : `$ref:${step.refPlot}`;
      }
      marks = emitViaJoins(step, refCell, marks, plotId);
    }
    if (step.kind !== "layout") continue;
    const prev = marks;
    const next = store.alloc("marks", undefined, "relation");
    const inst = spec.layouts.get(step.layoutId)!;
    const desc = opOf(inst);
    const algo = desc;
    const marksInputs = (desc.inputs.marks ?? []).map((c) => c.name);
    const proj = inst.inputs.marks?.project;
    const extraInputs: Record<string, string> = {};
    for (let mi = 1; mi < marksInputs.length; mi++) {
      const col = proj?.[marksInputs[mi]];
      if (typeof col === "string") extraInputs[marksInputs[mi]] = col;
    }
    const column = inputBinding(inst, plotId).marks?.[0];
    if (column === undefined) throw new Error(`compileNode: post-affine layout "${step.layoutId}" has no source column`);
    const declared = desc.outSpaces !== undefined ? Object.keys(desc.outSpaces) : "add" in desc.output ? desc.output.add.map((a: { name: string }) => a.name) : [];
    const out2chs = new Map<string, string[]>();
    for (const c of step.chans) out2chs.set(c.output, [...(out2chs.get(c.output) ?? []), c.ch]);
    const outputs = declared.map((o: string) => out2chs.get(o)?.[0]).filter((c): c is string => c !== undefined);
    const binding: OpBinding = { key: `${plotId}:${step.layoutId}`, inputs: { value: column, ...extraInputs }, outputs, options: inst.options, refs: auxRefs(desc, inst), outSpace: plot.channels[outputs[0]]?.type.space };
    const key = template !== undefined && inst.shared !== true && (inst.shared === false || desc.perCell === true) ? "dvl_cell" : undefined;
    const holes: Record<string, CellRef> = {};
    const io: PlanIO = { id: `${plotId}:${step.layoutId}`, binding, marksIn: prev, trainIn: prev, marksOut: next, holes, key, alloc: (role, kind) => store.alloc(role, undefined, kind) };
    specs.push(...stampAlgo(algo, algo.plan(io)));
    marks = next;
  }

  // AGGREGATE marks (line/path/area): the placed rows collapse to path row(s) — one per series
  // (a `group` channel: an ordinal/keyed non-positional channel that partitions the line), else one
  // for the whole plot. Positional channels feed the path `d`; the rest are carried. `order` is the
  // SEQUENCE channel (SEQUENCE_MARKS §3.1): the column the points sort by — bound explicitly for a
  // trajectory (x non-monotone), else path-agg defaults to x.
  const markDesc = plot.resolvedMark;
  if (markDesc === undefined) throw new Error(`compile: plot "${plotId}" has an unresolved mark — call resolveSpec(spec, registries) after the lowerings`);
  if (markDesc.cardinality === "aggregate") {
    const positional = (ch: string): boolean => { const k = markDesc.channels[ch]; return k === "positional-x" || k === "positional-y"; };
    const bound = Object.keys(plot.channels);
    const group = bound.filter((ch) => markDesc.channels[ch] === "color" || markDesc.channels[ch] === "shape"); // series partition
    const orderCh = plot.channels["order"] !== undefined ? "order" : undefined;
    const carry = bound.filter((ch) => !positional(ch) && !group.includes(ch) && ch !== "order");
    const placed = store.alloc("marks", undefined, "relation");
    specs.push({ id: `${plotId}:path`, reads: [marks], writes: [placed], payload: { kind: "path-agg", key: `${plotId}:path`, shape: plot.markType === "area" ? "area" : "line", carry, group, ...(orderCh !== undefined && { order: orderCh }) } });
    marks = placed;
  }



  // C6 box columns (scale-expansion §4): FORK a `box:` relop off the placed marks — four derived
  // pixel edges (dvl_x0/x1/y0/y1) from the mark's symbolic extentOf. A side product, not a
  // pipeline stage: the render sink still reads `marks`; only the overhang op reads `boxed`.
  // Emitted when a live expansion loop wants the measurement OR a route endpoint borrows this
  // plot's box (needsBox — §5 rev., set at bind); adornment plots (origin-tagged) never participate.
  let boxed: CellRef | undefined;
  const liveExpansion = Object.values(plot.channels).some((e) => {
    const exp = expOf(e);
    return exp !== undefined && store.get(exp.lo).status !== "sealed";
  });
  if ((liveExpansion && participates(plot)) || plot.needsBox === true) {
    const edges = boxEdgesOf(plot) ?? {};
    const add: Record<string, ScalarExpr> = {};
    const outTypes: Record<string, SqlType> = {};
    const outSpaces: Record<string, Space> = {};
    const put = (col: string, e: ScalarExpr | undefined, axis: "x" | "y"): void => { if (e !== undefined) { add[col] = e; outTypes[col] = "double"; outSpaces[col] = pixelSpace(coord(axis)); } };
    put("dvl_x0", edges.left, "x"); put("dvl_x1", edges.right, "x");
    put("dvl_y0", edges.top, "y"); put("dvl_y1", edges.bottom, "y");
    if (Object.keys(add).length > 0) {
      boxed = store.alloc("marks", undefined, "relation");
      specs.push({ id: `${plotId}:box`, reads: [marks], writes: [boxed], payload: { kind: "relop", key: `${plotId}:box`, add, outTypes, outSpaces, tag: "box" } });
    }
  }

  return { pid: plotId, marks, relMarks, base, keyed: keyedCell, boxed };
}

/** A plot's base relation: a table name → a `marktable` op; `{ relation }` → the cell itself;
 *  `{ producer }` → run the SOURCE instance's `plan` once (emit-once via the node-local cache — the
 *  axis's tick/text/rule plots share one V), the base is its output cell. */
function resolveBase(spec: Spec, plot: Plot, producers: Map<LayoutId, CellRef>, specs: OpSpec[], store: CellStore): CellRef {
  if (isProducerSource(plot.source)) {
    const pid = plot.source.producer;
    let cell = producers.get(pid);
    if (cell === undefined) {
      const inst = spec.layouts.get(pid);
      if (inst === undefined) throw new Error(`compileNode: no producer instance "${pid}"`);
      cell = store.alloc("marks", undefined, "relation"); // the compiler allocates the output cell — uniform with every op
      const algo = opOf(inst);
      const io: PlanIO = { id: `${pid}:prod`, binding: { key: `${pid}:prod`, inputs: {}, outputs: [], options: inst.options }, marksOut: cell, holes: inst.domain !== undefined ? { domain: inst.domain } : {}, alloc: (role, kind) => store.alloc(role, undefined, kind) };
      specs.push(...stampAlgo(algo, algo.plan(io))); // no marksIn — a source reads its holes, not input marks
      producers.set(pid, cell);
    }
    return cell;
  }
  if (isRelationSource(plot.source)) return plot.source.relation;
  const marks = store.alloc("marks", undefined, "relation");
  specs.push({ id: `${plot.id}:marktable`, reads: [], writes: [marks], payload: { kind: "marktable", plotId: plot.id } });
  return marks;
}
