// materialize op: sql→js crossing. Run the SQL fragment, produce JS rows.
import type { OpSpec } from "../../../plan/opspec.js";
import type { CellStore } from "../../../ir/cell.js";
import type { RunCtx } from "../../../executor/run.js";
import { jsRel, materialize, type Relation } from "../../../algebra/relation.js";
export async function materializeOp(op: OpSpec, store: CellStore, ctx: RunCtx): Promise<void> {
  const rel = store.read(op.reads[0]) as Relation;
  if (rel.substrate === "js") {
    store.write(op.writes[0], rel, "assigned");
    return;
  }
  const { rows, schema } = await materialize(rel, ctx.run);
  store.write(op.writes[0], jsRel(rows, schema), "assigned");
}
