// proportionalX: items sized proportionally to a value column along x-axis.
// x = cumsum(preceding) / total, w = value / total. Normalized [0,1].
// Opaque js-only Exec (same pattern as force/treemap).
import { inputCol, type OpBinding } from "../../algebra/impl.js";
import { type PlanIO } from "../../operator/binding.js";
import { jsImpl, type ExecCtx } from "../../algebra/impl.js";
import { op } from "../../operator/operator.js";
import type { JsRel } from "../../algebra/relation.js";
import type { OpSpec } from "../../plan/opspec.js";
import { coord, dataSpace, len, relativeSpace } from "../../types/attr.js";

export const proportionalX = op({
  name: "proportionalX",
  // No domain: no trained fit — outputs are cumulative shares in [0,1] (same rationale as
  // stack). A percent axis over the unit interval would be a future unit-domain feature.
  inputs: { marks: [{ name: "value", type: "double" }] },
  output: { passthrough: "marks", add: [{ name: "x", type: "double" }, { name: "w", type: "double" }] },
  outSpaces: { x: relativeSpace(coord("x")), w: relativeSpace(len("x")) },
  inputSpaces: { value: dataSpace },
  plan: (io: PlanIO): OpSpec[] => {
    if (io.marksIn === undefined) throw new Error("proportionalX: applies over input marks");
    return [{ id: `${io.id}:apply`, reads: [io.marksIn], writes: [io.marksOut], payload: { kind: "apply", algoName: "proportionalX", binding: io.binding } }];
  },
  exec: { js: jsImpl(async (inputs: readonly JsRel[], b: OpBinding, _ctx: ExecCtx): Promise<JsRel> => {
    const marks = inputs[0];
    const valCol = inputCol(b, "value");
    const [xo, wo] = b.outputs;
    let total = 0;
    for (const r of marks.rows) total += Math.max(0, Number((r as Record<string, unknown>)[valCol] ?? 0));
    if (total === 0) {
      const n = marks.rows.length || 1;
      return { rows: marks.rows.map((r, i) => ({ ...r, [xo]: i / n, [wo]: 1 / n })), schema: [...marks.schema, { name: xo, type: "double" as const }, { name: wo, type: "double" as const }] };
    }
    let cumX = 0;
    const rows = marks.rows.map((r) => {
      const v = Math.max(0, Number((r as Record<string, unknown>)[valCol] ?? 0));
      const x = cumX / total;
      const w = v / total;
      cumX += v;
      return { ...r, [xo]: x, [wo]: w };
    });
    return { rows, schema: [...marks.schema, { name: xo, type: "double" as const }, { name: wo, type: "double" as const }] };
  }) },
});
