// The pen — the abstract drawing surface a mark's `draw` emits onto. Per-primitive
// calls take canonical-carrier styles; a concrete pen (e.g. render/SvgPen) is the SOLE
// place the target encoding is chosen. Lives in ir/ (not render/) so MarkDescriptor.draw
// can reference it without an ir↔render cycle (WUDESIGN §Scene Graph: draw is mark-side,
// the pen impl is target-side).
import type { Row } from "../data/schema.js";

export interface Style {
  fill?: string;
  stroke?: string;
  strokeWidth?: number;
  opacity?: number;
  fillOpacity?: number;
  strokeOpacity?: number;
  strokeDasharray?: string;
  fontSize?: number;
  fontFamily?: string; // text marks: the resolved font stack. Emitted EXPLICITLY (never inherited)
  // so an offscreen measurement (plot-measure's getBBox) and the final render — both SvgPen — agree
  // on glyph metrics regardless of the DOM context each is inserted into. See DEFAULT_FONT_FAMILY.
  textAnchor?: string; // "start" | "middle" | "end" (text marks)
  dominantBaseline?: string; // "hanging" | "middle" | "alphabetic"
  rotate?: number;
  title?: string; // hover tooltip — a target-native accessible name (SVG: a <title> child), not a drawn attribute
}

export type Point = readonly [number, number];

export interface Pen {
  circle(cx: number, cy: number, r: number, style: Style): void;
  ellipse(cx: number, cy: number, rx: number, ry: number, style: Style): void;
  rect(x: number, y: number, w: number, h: number, style: Style): void;
  line(x1: number, y1: number, x2: number, y2: number, style: Style): void;
  polyline(points: readonly Point[], style: Style): void;
  polygon(points: readonly Point[], style: Style): void;
  path(d: string, style: Style): void;
  text(s: string, x: number, y: number, style: Style): void;
  textMultiline?(lines: string[], x: number, y: number, style: Style): void;
  image(x: number, y: number, w: number, h: number, href: string, style: Style): void;
}

// --- helpers for `draw` bodies: read resolved row values defensively ---
export function num(row: Row, key: string, fallback = 0): number {
  const v = row[key];
  return typeof v === "number" ? v : fallback;
}

export function numOpt(row: Row, key: string): number | undefined {
  const v = row[key];
  return typeof v === "number" ? v : undefined;
}

export function str(row: Row, key: string): string | undefined {
  const v = row[key];
  return v === null || v === undefined ? undefined : String(v);
}


/** The ONE canonical font for rendered SVG text. Emitted on the root <svg> (self-contained
 *  output) AND used by every measuring context (offscreen getBBox, canvas measureText,
 *  grid-stack item sizing). Measurement and display MUST resolve the same font or every
 *  measured gutter lies — the web demo measured in the page-body font (Times) and displayed
 *  in the app font (system-ui), under-reserving every text gutter (AUTOLEGEND_IMPL §8). */
export const DVL_FONT_FAMILY = "ui-sans-serif, system-ui, sans-serif";
const BASELINE_MAP: Record<string, string> = { top: "hanging", middle: "middle", bottom: "alphabetic" };

/** The default text font stack. Pinned EXPLICITLY on every text mark (not left to CSS inheritance)
 *  so text geometry is deterministic: `plot-measure`'s offscreen getBBox measures the same font the
 *  final SVG renders, closing the measure↔render gap that let axis-label gutters be mis-reserved.
 *  Matches the demo shell's `.app` stack, so pinning it is a no-op on the rendered appearance. */
export const DEFAULT_FONT_FAMILY = "ui-sans-serif, system-ui, sans-serif";

/** Pull the modeled paint channels off a row into a Style. */
export function styleOf(row: Row): Style {
  const bl = str(row, "baseline");
  return {
    fill: str(row, "fill"),
    stroke: str(row, "stroke"),
    strokeWidth: numOpt(row, "strokeWidth"),
    opacity: numOpt(row, "opacity"),
    fillOpacity: numOpt(row, "fillOpacity"),
    strokeOpacity: numOpt(row, "strokeOpacity"),
    strokeDasharray: str(row, "strokeDasharray"),
    fontSize: numOpt(row, "fontSize"),
    fontFamily: str(row, "fontFamily"),
    textAnchor: str(row, "anchor"),
    dominantBaseline: bl !== undefined ? BASELINE_MAP[bl] : undefined,
    rotate: numOpt(row, "rotate"),
    title: str(row, "title"),
  };
}
